    public function __construct()
    {
        parent::__construct();
        $this->load->model('leads_model');

        $this->token = get_option("tokenBearer_contactcenter");
        $this->tokenOpenai = get_option("tokenopenai_contactcenter");
        $this->tokenAsstOpenai = get_option("tokeasst_contactcenter");
        $this->tokenElevenlabsi = get_option("token_elevenlabs_contactcenter");
        $this->UrlApi = "https://gateway.api_brasil.io/api/v2/";
        $this->load->library("contactcenter/api_brasil");
        $this->load->library("contactcenter/axiom_evolution");
        $this->load->library("contactcenter/chatbot");
