    }


    /**
     * Cria a fila de mensagens
     */
    public function msg_queue($data)
    {

        // tira o html tags do msg
        $data['msg'] = strip_tags($data['msg']);
        if (empty($data['msg'])) {
            return false; // Se a mensagem estiver vazia, não adiciona à fila
        }

        $data = array(
            'number' => $data['number'],
            'msg' => $data['msg'],
            'staffid' => $data['staffid'],
            'type' => $data['type'],
            'reply_id' => $data['reply_id'],
            'edit_id' => $data['edit_id'],
            'file_name' => $data['file_name'],
            'url' => $data['url'],
        );

        $result =  $this->db->insert(db_prefix() . 'contactcenter_message_queue', $data);
        if ($result) {
            return $this->db->insert_id();
        } else {
            return false;
        }
    }

    /**
     * Processa a fila de mensagens
     */
    public function process_contactcenter_queue()
    {

        // Verifica se a fila já está sendo processada
        $this->db->where('status', 'pending');
        $this->db->limit(1);
        $pending = $this->db->get_where(db_prefix() . 'contactcenter_message_queue')->result();
        foreach ($pending as $msg) {
            // troca o status para processando
            $this->db->where('id', $msg->id);
            $this->db->update(db_prefix() . 'contactcenter_message_queue', array('status' => 'PROCESSING'));

            if ($msg->type == "text") {

                $enviado = $this->send_text($msg->number, $msg->msg, $msg->staffid, $msg->reply_id, $msg->edit_id, $queue = false, $type_source = 'crm');
            } else if ($msg->type == "audio") {
                $enviado = $this->send_audio($msg->number, $msg->url, $msg->staffid, false);
            } else {
                $enviado = $this->send_file($msg->number, $msg->msg, $msg->url, $msg->type, $msg->staffid, $fileName = null, $msg->reply_id, false);
            }


            if ($enviado['status'] == "PENDING") {
                // Deleta o arquivo se for tipo "audio"
                if ($msg->type == "audio" && !empty($msg->url)) {
                    // Extrai apenas o caminho relativo após "uploads/"
                    $relativePath = strstr($msg->url, 'uploads/'); // retorna tudo a partir de "uploads/"
                    if ($relativePath) {
                        $path = FCPATH . $relativePath;
                        if (file_exists($path)) {
                            unlink($path);
                        }
                    }
                }

                $this->db->where('id', $msg->id);
                $this->db->delete(db_prefix() . 'contactcenter_message_queue');
            } else {
                // Se deu erro, troca o status para pending
                $this->db->where('id', $msg->id);
                $this->db->update(db_prefix() . 'contactcenter_message_queue', array('status' => 'pending'));
            }
        }
    }


    /**
     * Dispara mensagem para o whats pode passar o numero ou ID do grupo
     * @param type $number
     * @param type $msg
     * @param type $staffid
     * @return type
     */
    public function send_text($number, $msg, $staffid = null, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'crm')
    {

        $telefone_limpo = preg_replace('/\D/', '', $number);
        $number = $telefone_limpo;

        if (empty($edit_id)) {
            $this->update_lead_lastcontact_by_phone($number);
        }

        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        } else {
            $this->db->where('dev_type', 1);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        }

        // Log device status for debugging
        log_activity("send_file: Device status check - Status: " . ($tokenStaff->status ?? 'null') . ", Staff ID: " . ($staffid ?? 'null') . ", Number: {$number}");

        if ($tokenStaff->status == "inChat" || $tokenStaff->status == "CONNECTED" || $tokenStaff->status == "open" || $tokenStaff->status == "connecting") {

            $text = str_replace("<br />", "", $msg);
            $text = str_replace("<strong>", "**", $text);
            $text = str_replace("</strong>", "**", $text);

            // Verifica se envia para o app local ou crm
            if ($apiLocal) {
                $this->load->model('notification_websocket_model');
                $data = [
                    'to' => $number,
                    'type' => 'text',
                    'body' => $text,
                    'token' => $tokenDevice,
                    'replyTo' => $reply_id,
                    'editId' => $edit_id,
                    'source' => $type_source,
                ];

                return $this->notification_websocket_model->send("whatsapp:sent", $data);
            }


            // busco servidor do device
            $server = $this->get_server($tokenStaff->server_id);


            if ($tokenStaff->dev_type == 3) {
                $staff_name = (get_staff_user_id() ? get_staff_full_name(get_staff_user_id()) . ": " : "");
                $text = "{$staff_name} {$text}";
            }

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {

                $prefixUrl = "{$server->url}message/sendText/{$tokenStaff->dev_instance_name}";

                if ($reply_id) {
                    $data = array(
                        'number' => $number,
                        'options' => array(
                            'delay' => 2000,
                            'presence' => 'composing',
                            'linkPreview' => true,
                            'quoted' => array(
                                'key' => array(
                                    'id' => $reply_id
                                )
                            )
                        ),
                        'textMessage' => array(
                            'text' => $text
                        )
                    );
                } elseif ($edit_id) {

                    $this->db->where('msg_send_id', $edit_id);
                    $msg = $this->db->get(db_prefix() . 'contactcenter_message')->row();
                    if (!$msg) {
                        return false;
                    }

                    $prefixUrl = "{$server->url}chat/updateMessage/{$tokenStaff->dev_instance_name}";


                    $data = [
                        "number" => $number,
                        "key" => [
                            "remoteJid" => $msg->remoteJid,
                            "fromMe" => true,
                            "id" => $edit_id
                        ],
                        "text" => $text
                    ];

                    log_activity("Message edit: {$msg->msg_content} para {$text} Phone: {$number} ", get_staff_user_id());
                } else {
                    $data = array(
                        'number' => $number,
                        'options' => array(
                            'delay' => 2000,
                            'presence' => 'composing',
                            'linkPreview' => false
                        ),
                        'textMessage' => array(
                            'text' => $text
                        )
                    );
                }


                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);

                if ($send['status'] == "PENDING") {
                    return $send;
                } else {

                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'msg' => $msg,
                            'staffid' => $staffid,
                            'type' => 'text',
                            'reply_id' => $reply_id,
                            'edit_id' => $edit_id
                        );

                        $this->msg_queue($fila);
                    }

                    return $send;
                }



                //return $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);



            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {

                $prefixUrl = "{$server->url}message/sendText/{$tokenStaff->dev_instance_name}";
                if ($reply_id) {

                    $data = array(
                        'number' => $number,
                        'text' => $text,
                        'delay' => 2000,
                        'quoted' => array(
                            'key' => array(
                                'id' => $reply_id
                            )
                        ),
                        'linkPreview' => true,
                    );
                } elseif ($edit_id) {

                    $this->db->where('msg_send_id', $edit_id);
                    $msg = $this->db->get(db_prefix() . 'contactcenter_message')->row();
                    if (!$msg) {
                        return false;
                    }

                    $prefixUrl = "{$server->url}chat/updateMessage/{$tokenStaff->dev_instance_name}";


                    $data = [
                        "number" => $number,
                        "key" => [
                            "remoteJid" => $msg->remoteJid,
                            "fromMe" => true,
                            "id" => $edit_id
                        ],
                        "text" => $text
                    ];

                    log_activity("Message edit: {$msg->msg_content} para {$text} Phone: {$number} ", get_staff_user_id());
                } else {

                    $data = array(
                        'number' => $number,
                        'text' => $text,
                        'options' => array(
                            'delay' => 2000,
                            'presence' => 'composing',
                            'linkPreview' => false
                        )
                    );
                }


                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);

                if ($send['status'] == "PENDING") {
                    return $send;
                } else {
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'msg' => $msg,
                            'staffid' => $staffid,
                            'type' => 'text',
                            'reply_id' => $reply_id,
                            'edit_id' => $edit_id
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                }
            }
        } else {
            if ($queue) {
                $fila = array(
                    'number' => $number,
                    'msg' => $msg,
                    'staffid' => $staffid,
                    'type' => 'text',
                    'reply_id' => $reply_id,
                    'edit_id' => $edit_id
                );

                $this->msg_queue($fila);
            }
        }
    }

    public function send_list($phonenumber, $list, $staffid = null, $type_source = 'crm')
    {
        $telefone_limpo = preg_replace('/\D/', '', $phonenumber);
        $phonenumber = $telefone_limpo;

        $this->update_lead_lastcontact_by_phone($phonenumber);

        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        } else {
            $this->db->where('dev_type', 1);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        }




        if ($tokenStaff->status == "inChat" || $tokenStaff->status == "open") {

            // Verifica se envia para o app local ou crm
            if ($apiLocal) {
                $this->load->model('notification_websocket_model');
                $data = [
                    'to' => $phonenumber,
                    'type' => 'list',
                    'token' => $tokenDevice,
                    'list' => $list,
                    'source' => $type_source,
                ];

                return $this->notification_websocket_model->send("whatsapp:sent", $data);
            }

            $server = $this->get_server($tokenStaff->server_id);

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {

                $data = array(
                    'number' => $phonenumber,
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'composing',
                    ),
                    'listMessage' =>  $list
                );

                $prefixUrl = "{$server->url}message/sendList/{$tokenStaff->dev_instance_name}";

                return $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {
                // For v2, API requires buttonText and footerText fields
                // Ensure they exist (even if empty strings) to satisfy API requirements
                $listData = $list;
                
                // Ensure required fields exist with at least empty strings
                if (!isset($listData['buttonText'])) {
                    $listData['buttonText'] = "";
                }
                if (!isset($listData['footerText'])) {
                    $listData['footerText'] = "";
                }
                
                // Try v2 format first (flat merge with number)
                $data = array_merge(['number' => $phonenumber], $listData);

                $prefixUrl = "{$server->url}message/sendList/{$tokenStaff->dev_instance_name}";

                $result = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                
                // If v2 format fails with specific error about missing properties in listMessage,
                // try v1 format (wrapped in listMessage) but ensure all required fields are present
                if ($result && isset($result['error']) && 
                    (isset($result['response']['message']) && 
                     (is_array($result['response']['message']) && 
                      (in_array('instance requires property "buttonText"', $result['response']['message'][0] ?? []) ||
                       in_array('instance requires property "footerText"', $result['response']['message'][0] ?? []))))) {
                    
                    log_activity("send_list v2 format failed with missing property error, trying v1 format - Error: " . json_encode($result), get_staff_user_id());
                    
                    // Ensure all required fields are in listMessage for v1 format
                    $listMessage = $listData;
                    if (!isset($listMessage['buttonText'])) {
                        $listMessage['buttonText'] = "";
                    }
                    if (!isset($listMessage['footerText'])) {
                        $listMessage['footerText'] = "";
                    }
                    
                    $data_v1 = [
                        'number' => $phonenumber,
                        'options' => [
                            'delay' => 2000,
                            'presence' => 'composing',
                        ],
                        'listMessage' => $listMessage
                    ];
                    
                    return $this->axiom_evolution->send($data_v1, $prefixUrl, $tokenDevice);
                }
                
                return $result;
            }
        }
    }


