    /**
     * Send vCard (Contact Card)
     * @param string $number Phone number
     * @param string $name Contact name
     * @param string $phone Contact phone (with country code)
     * @param int $staffid Staff ID
     * @param string $text Optional text message to send with vCard
     */
    public function send_vcard($number, $name, $phone, $staffid = null, $text = null)
    {
        $telefone_limpo = preg_replace('/\D/', '', $number);
        $number = $telefone_limpo;
        $phone_clean = preg_replace('/\D/', '', $phone);

        $this->update_lead_lastcontact_by_phone($number);

        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        } else {
            $this->db->where('dev_type', 1);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        }

        if ($tokenStaff->status == "inChat" || $tokenStaff->status == "CONNECTED" || $tokenStaff->status == "open" || $tokenStaff->status == "connecting") {
            $server = $this->get_server($tokenStaff->server_id);

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {
                $prefixUrl = "{$server->url}message/sendContact/{$tokenStaff->dev_instance_name}";
                
                $data = array(
                    'number' => $number,
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'composing',
                    ),
                    'contactMessage' => array(
                        'fullName' => $name,
                        'displayName' => $name,
                        'organization' => '',
                        'phoneNumber' => $phone_clean
                    )
                );

                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                
                // If text is provided, send it after vCard
                if ($text && $send['status'] == "PENDING") {
                    sleep(2); // Small delay between vCard and text
                    $this->send_text($number, $text, $staffid, null, null, true, 'crm');
                }
                
                return $send;
            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {
                $prefixUrl = "{$server->url}message/sendContact/{$tokenStaff->dev_instance_name}";
                
                $data = array(
                    'number' => $number,
                    'fullName' => $name,
                    'displayName' => $name,
                    'phoneNumber' => $phone_clean,
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'composing',
                    )
                );

                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                
                // If text is provided, send it after vCard
                if ($text && $send['status'] == "PENDING") {
                    sleep(2);
                    $this->send_text($number, $text, $staffid, null, null, true, 'crm');
                }
                
                return $send;
            }
        }
        return false;
    }

    public function send_file($number, $msg, $url, $media_type = "image", $staffid = null, $fileName = null, $reply_id = null, $queue = true, $type_source = 'crm')
    {
        // Validate URL parameter - must be a non-empty string
        if (!is_string($url) || empty($url)) {
            log_activity("send_file error: Invalid URL parameter. Type: " . gettype($url) . ", Value: " . var_export($url, true));
            return array('error' => true, 'response' => array('message' => array('Invalid media URL - must be a non-empty string')));
        }

        $telefone_limpo = preg_replace('/\D/', '', $number);
        $number = $telefone_limpo;

        $this->update_lead_lastcontact_by_phone($number);

        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if (!$tokenStaff) {
                return array('error' => true, 'response' => array('message' => array('Device not found for staff ID: ' . $staffid)));
            }
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        } else {
            $this->db->where('dev_type', 1);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if (!$tokenStaff) {
                return array('error' => true, 'response' => array('message' => array('No default device found')));
            }
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        }




        if ($tokenStaff->status == "inChat" || $tokenStaff->status == "CONNECTED" || $tokenStaff->status == "open" || $tokenStaff->status == "connecting") {

            // Verifica se envia para o app local ou crm
            if ($apiLocal) {
                $this->load->model('notification_websocket_model');
                $data = [
                    'to' => $number,
                    'type' => $media_type,
                    'body' => $msg,
                    'token' => $tokenDevice,
                    'replyTo' => $reply_id,
                    'editId' => null,
                    'source' => $type_source,
                    'url' => $url,
                ];

                return $this->notification_websocket_model->send("whatsapp:sent", $data);
            }

            // busco o server
            $server = $this->get_server($tokenStaff->server_id);

            $text = str_replace("<br />", "", $msg);
            $text = str_replace("<strong>", "**", $text);
            $text = str_replace("</strong>", "**", $text);

            if ($tokenStaff->dev_type == 3) {
                $staff_name = get_staff_full_name(get_staff_user_id()) . ": ";
                $text = "{$staff_name} {$text}";
            }

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {

                $data = array(
                    'number' => $number,
                    'options' => array(
                        'delay' => 1200,
                        'presence' => 'composing',
                    ),
                    'mediaMessage' => array(
                        'mediatype' => $media_type,
                        'fileName' => $fileName,
                        'caption' => $text,
                        'media' => $url,
                    )
                );

                if ($reply_id) {
                    $data['linkPreview'] = true;
                    $data['options']['quoted'] = array(
                        'key' => array(
                            'id' => $reply_id
                        )
                    );
                }

                $prefixUrl = "{$server->url}message/sendMedia/{$tokenStaff->dev_instance_name}";

                //$ApiUrl = $this->UrlApi . 'whatsapp/sendText';

                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                if ($send['status'] == "PENDING") {
                    // Even when PENDING, queue as backup to ensure message is sent if AI run expires
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'msg' => $msg,
                            'staffid' => $staffid,
                            'url' => $url,
                            'type' => $media_type,
                            'reply_id' => $reply_id,
                            'file_name' => $fileName,
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                } else {
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'msg' => $msg,
                            'staffid' => $staffid,
                            'url' => $url,
                            'type' => $media_type,
                            'reply_id' => $reply_id,
                            'file_name' => $fileName,
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                }
            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {
                $data = array(
                    'number' => $number,
                    'mediatype' => $media_type,
                    'caption' => $text,
                    'media' => $url,
                    'options' => array(
                        'delay' => 0,
                        'presence' => 'composing',
                    )
                );

                if ($reply_id) {
                    $data['linkPreview'] = true;
                    $data['quoted'] = array(
                        'key' => array(
                            'id' => $reply_id
                        )
                    );
                }

                $prefixUrl = "{$server->url}message/sendMedia/{$tokenStaff->dev_instance_name}";

                //$ApiUrl = $this->UrlApi . 'whatsapp/sendText';

                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                if ($send['status'] == "PENDING") {
                    // Even when PENDING, queue as backup to ensure message is sent if AI run expires
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'msg' => $msg,
                            'staffid' => $staffid,
                            'type' => $media_type,
                            'reply_id' => $reply_id,
                            'file_name' => $fileName,
                            'url' => $url
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                } else {
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'msg' => $msg,
                            'staffid' => $staffid,
                            'type' => $media_type,
                            'reply_id' => $reply_id,
                            'file_name' => $fileName,
                            'url' => $url
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                }
            }
        } else {
            // Device status check failed - log for debugging
            log_activity("send_file: Device status check failed - Status: " . ($tokenStaff->status ?? 'null') . " is not in allowed states (inChat, CONNECTED, open, connecting). Staff ID: " . ($staffid ?? 'null'));
            return null; // Explicitly return null instead of implicit
        }
    }

    /**
     * Envia audio mp3
     * @param type $number
     * @param type $url
     * @param type $staffid
     * @return type
     */
    public function send_audio($number, $url, $staffid = null, $queue = true, $type_source = 'crm')
    {

        $telefone_limpo = preg_replace('/\D/', '', $number);
        $number = $telefone_limpo;

        $this->update_lead_lastcontact_by_phone($number);

        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if (!$tokenStaff) {
                log_activity("send_audio: Device not found for staff ID: " . ($staffid ?? 'null'));
                return null;
            }
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        } else {
            $this->db->where('dev_type', 1);
            $tokenStaff = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if (!$tokenStaff) {
                log_activity("send_audio: No default device found");
                return null;
            }
            $tokenDevice = $tokenStaff->dev_token;
            $apiLocal = $tokenStaff->api_local;
        }

        if (!$tokenStaff) {
            log_activity("send_audio: Device lookup failed - Staff ID: " . ($staffid ?? 'null'));
            return null;
        }

        if ($tokenStaff->status == "inChat" || $tokenStaff->status == "CONNECTED" || $tokenStaff->status == "open" || $tokenStaff->status == "connecting") {

            // Verifica se envia para o app local ou crm
            if ($apiLocal) {
                $this->load->model('notification_websocket_model');
                $data = [
                    'to' => $number,
                    'type' => 'media',
                    'body' => null,
                    'token' => $tokenDevice,
                    'replyTo' => null,
                    'editId' => null,
                    'source' => $type_source,
                    'url' => $url,
                ];

                return $this->notification_websocket_model->send("whatsapp:sent", $data);
            }

            // busco o server            
            $server = $this->get_server($tokenStaff->server_id);

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {
                $data = array(
                    'number' => $number,
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'recording',
                        'encoding' => true,
                    ),
                    'audioMessage' => array(
                        'audio' => $url,
                    )
                );

                $prefixUrl = "{$server->url}message/sendWhatsAppAudio/{$tokenStaff->dev_instance_name}";

                //$ApiUrl = $this->UrlApi . 'whatsapp/sendText';

                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                if ($send['status'] == "PENDING") {
                    // Even when PENDING, queue as backup to ensure message is sent if AI run expires
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'staffid' => $staffid,
                            'type' => 'audio',
                            'url' => $url
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                } else {
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'staffid' => $staffid,
                            'type' => 'audio',
                            'url' => $url
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                }
            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {
                $data = array(
                    'number' => $number,
                    'audio' => $url,
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'recording',
                        'encoding' => true,
                    )
                );

                $prefixUrl = "{$server->url}message/sendWhatsAppAudio/{$tokenStaff->dev_instance_name}";

                $send = $this->axiom_evolution->send($data, $prefixUrl, $tokenDevice);
                if ($send['status'] == "PENDING") {
                    // Even when PENDING, queue as backup to ensure message is sent if AI run expires
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'staffid' => $staffid,
                            'type' => 'audio',
                            'url' => $url
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                } else {
                    if ($queue) {
                        $fila = array(
                            'number' => $number,
                            'staffid' => $staffid,
                            'type' => 'audio',
                            'url' => $url
                        );

                        $this->msg_queue($fila);
                    }
                    return $send;
                }
            }
        } else {
            // Device status check failed - log for debugging
            log_activity("send_audio: Device status check failed - Status: " . ($tokenStaff->status ?? 'null') . " is not in allowed states (inChat, CONNECTED, open, connecting). Staff ID: " . ($staffid ?? 'null'));
            return null; // Explicitly return null instead of implicit
        }
    }

   


 

    /**
     * Desconecta da API, não do Whats
     * @param type $tokenDevice
     * @return type
     */
    public function disconnect_device($device)
    {

        // busco o server        
        $server = $this->get_server($device->server_id);


        // valido que se for axiom_evolution chama um discontect, senao chama da api brasil
        if ($server->api_type == "axiom_evolution") {
            $ApiUrl = $server->url . 'instance/logout/' . $device->dev_instance_name;

            return $this->axiom_evolution->logout($ApiUrl, $device->dev_token);
        } else {
            $curl = curl_init();

            curl_setopt_array($curl, array(
                CURLOPT_URL => 'https://cluster.apigratis.com/api/v2/whatsapp/disconnect',
                CURLOPT_RETURNTRANSFER => true,
                CURLOPT_ENCODING => '',
                CURLOPT_MAXREDIRS => 10,
                CURLOPT_TIMEOUT => 30,
                CURLOPT_FOLLOWLOCATION => true,
                CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
                CURLOPT_CUSTOMREQUEST => 'POST',
                CURLOPT_HTTPHEADER => array(
                    "Content-Type: application/json",
                    "Authorization: Bearer {$this->token}",
                    "DeviceToken: {$device->dev_token}"
                ),
            ));

            $response = curl_exec($curl);

            curl_close($curl);
            return json_decode($response, true);
        }
    }

    /**
     * Pega o status de conexão do device  
     * @param type $tokenDevice
     * @return type
     */
    public function getConnectionStatus($dev_id)
    {

        $device = $this->get_device($dev_id);
        if ($device) {


            // busco o server          
            $server = $this->get_server($device->server_id);


            if ($server->api_type == "wpp") {
                $ApiUrl = $this->UrlApi . 'whatsapp/getConnectionStatus';
                $TYPE = "POST";

                return $this->api_brasil->getConnectionStatus('whatsapp/getConnectionStatus', $device->dev_token, $TYPE);
            } else if ($server->api_type == "evolution") {
                $ApiUrl = $this->UrlApi . 'evolution/instance/connectionState';
                $TYPE = "GET";

                return $this->api_brasil->getConnectionStatus('whatsapp/getConnectionStatus', $device->dev_token, $TYPE);
            } else if ($server->api_type == "axiom_evolution") {
                $ApiUrl = $server->url . 'instance/connectionState/' . $device->dev_instance_name;
                $TYPE = "GET";

                return $this->axiom_evolution->getConnectionStatus($ApiUrl, $device->dev_token);
            }
        }
    }


