    /**
     * Verica de numero do contato está no whatsapp
     * @param type $data
     * @return bool
     */
    public function verify_Number_Whatsapp($data)
    {
        $curl = curl_init();

        $tokenDevice = $data["token"];
        if ($tokenDevice) {
            $this->db->where('dev_token', $tokenDevice);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($device) {

                // busco o server                
                $server = $this->get_server($device->server_id);

                if ($device->api_local != 1) {

                    $ApiUrl = $server->url . 'chat/whatsappNumbers/' . $device->dev_instance_name;
                    $phoneNumber = ["numbers" => [$data["phonenumber"]]];

                    $result = $this->axiom_evolution->verify_Number_Whatsapp($ApiUrl, $tokenDevice, $phoneNumber);
                    return [
                        'status' => "success",
                        'type' => "sistema",
                        'exists' => ($result ? true : false),
                    ];
                } else {

                    $this->load->model('notification_websocket_model');
                    $data = [
                        'to' => $data["phonenumber"],
                        'apikey' => $device->dev_token,
                    ];

                    $result = $this->notification_websocket_model->send("whatsapp:verifyNumber", $data);
                    if ($result) {
                        return [
                            'status' => "success",
                            'type' => "local",
                            'id' => $result['id'],
                        ];
                    }
                }
            }
        }
    }

    /**
     * pega os Device no banco 
     * @param type $device_id
     * @return type
     */
    public function get_device($device_id = null, $staffid = null, $active_only = false)
    {

        if ($device_id) {
            if ($staffid) {
                $this->db->where('staffid', $staffid);
            }
            $this->db->where('dev_id', $device_id);
            return $this->db->get(db_prefix() . 'contactcenter_device')->row();
        } else {
            if ($staffid) {
                $this->db->where('staffid', $staffid);
            }
            // Filter by active status when requested (e.g., for chat dropdowns)
            if ($active_only) {
                $this->db->where('is_active', 1);
            }
            return $this->db->get(db_prefix() . 'contactcenter_device')->result();
        }
    }

