    /**
     * Pega os chat no banco 
     * @param type $data
     * @param type $isRead
     * @return type
     */
    public function get_messages_chat($data, $isRead = false)
    {
        $tokenDevice = $data["token"];
        $phoneNumber = $data["phonenumber"];
        $isGroup = isset($data["group"]) ? intval($data["group"]) : 0;
        $paginadorId = isset($data["paginadorId"]) ? $data["paginadorId"] : null;
        $showAllDevices = !empty($data["show_messages_all_devices"]) || (!empty($data["show_all_devices"]) && $data["show_all_devices"] == 1);
        if ($phoneNumber) {

            $this->db->select('
                m.msg_id,
                m.staffid,
                m.msg_wook,
                m.msg_type,
                m.msg_fromMe,
                m.msg_send_id,
                m.msg_session,
                m.msg_isGroupMsg,
                m.msg_name,
                m.msg_to,
                m.msg_from,
                m.msg_title,
                m.msg_content,
                m.msg_url,
                m.msg_status,
                m.msg_isread,
                m.msg_date,
                m.msg_date_update,
                m.msg_conversation_number,
                m.reply_participant,
                m.reply_msg,
                m.reply_id,
                m.sent_source,
                m.remoteJid,
                m.msg_reaction,
                d.dev_name as device_dev_name,
                d.dev_number as device_dev_number
            ');
            $this->db->from(db_prefix() . 'contactcenter_message m');
            $this->db->join(db_prefix() . 'contactcenter_device d', 'd.dev_token = m.msg_session', 'left');

            if ($paginadorId) {
                $this->db->where('m.msg_date <', $paginadorId);
            }
            $this->db->where('m.msg_isGroupMsg', $isGroup);

            // Flexible phone number matching: DB may store 5516898375259, 16898375259, or 16898375259@s.whatsapp.net
            $phoneClean = preg_replace('/\D/', '', $phoneNumber);
            if ($isGroup == 1) {
                $this->db->where('m.msg_conversation_number', $phoneNumber);
            } else {
                $this->db->group_start();
                $this->db->where('m.msg_conversation_number', $phoneNumber);
                $this->db->or_where('m.msg_conversation_number', $phoneClean);
                $this->db->or_where('m.msg_conversation_number', $phoneClean . '@s.whatsapp.net');
                if (strlen($phoneClean) >= 10 && strlen($phoneClean) <= 11 && substr($phoneClean, 0, 2) !== '55') {
                    $this->db->or_where('msg_conversation_number', '55' . $phoneClean);
                }
                if (strlen($phoneClean) >= 12 && substr($phoneClean, 0, 2) === '55') {
                    $this->db->or_where('msg_conversation_number', substr($phoneClean, 2));
                }
                $this->db->group_end();
            }

            if ($isGroup == 1) {
                // For groups, use DISTINCT or group by msg_id to avoid duplicates
                // Instead of GROUP BY which causes SQL errors, use DISTINCT ON columns
                // Or better: group by msg_id which is unique, but filter duplicates differently
                // For now, let's just order by msg_id and let the application handle deduplication
                // Or we can use a subquery approach - but simpler: just don't group by non-key columns
                // Remove the problematic GROUP BY - if deduplication is needed, it should be done in PHP
                // $this->db->group_by(['msg_content', 'msg_date', 'msg_url']);
            } else {
                if (!$showAllDevices) {
                    $this->db->where('m.msg_session', $tokenDevice);
                }
            }

            if ($paginadorId) {
                $this->db->order_by("m.msg_date", "DESC");
            } else {
                $this->db->order_by("m.msg_id", "DESC");
            }
            $this->db->limit(25);

            $query = $this->db->get();
            if ($query === false) {
                log_activity("get_messages_chat SQL ERROR - Query failed. Last query: " . $this->db->last_query(), get_staff_user_id());
                return array();
            }
            $Result = $query->result();

            // Local env fallback: if no messages and session filter may not match (device reconnected, api_local), try without session
            if (empty($Result) && $isGroup != 1 && !$showAllDevices && isset($_SERVER['HTTP_HOST']) && (strpos($_SERVER['HTTP_HOST'], 'localhost') !== false || strpos($_SERVER['HTTP_HOST'], '127.0.0.1') !== false)) {
                $this->db->select('m.msg_id, m.staffid, m.msg_wook, m.msg_type, m.msg_fromMe, m.msg_send_id, m.msg_session, m.msg_isGroupMsg, m.msg_name, m.msg_to, m.msg_from, m.msg_title, m.msg_content, m.msg_url, m.msg_status, m.msg_isread, m.msg_date, m.msg_date_update, m.msg_conversation_number, m.reply_participant, m.reply_msg, m.reply_id, m.sent_source, m.remoteJid, m.msg_reaction, d.dev_name as device_dev_name, d.dev_number as device_dev_number');
                $this->db->from(db_prefix() . 'contactcenter_message m');
                $this->db->join(db_prefix() . 'contactcenter_device d', 'd.dev_token = m.msg_session', 'left');
                if ($paginadorId) {
                    $this->db->where('m.msg_date <', $paginadorId);
                }
                $this->db->where('m.msg_isGroupMsg', 0);
                $this->db->group_start();
                $this->db->where('m.msg_conversation_number', $phoneNumber);
                $this->db->or_where('m.msg_conversation_number', $phoneClean);
                $this->db->or_where('m.msg_conversation_number', $phoneClean . '@s.whatsapp.net');
                if (strlen($phoneClean) >= 10 && strlen($phoneClean) <= 11 && substr($phoneClean, 0, 2) !== '55') {
                    $this->db->or_where('m.msg_conversation_number', '55' . $phoneClean);
                }
                if (strlen($phoneClean) >= 12 && substr($phoneClean, 0, 2) === '55') {
                    $this->db->or_where('m.msg_conversation_number', substr($phoneClean, 2));
                }
                $this->db->group_end();
                if ($paginadorId) {
                    $this->db->order_by("m.msg_date", "DESC");
                } else {
                    $this->db->order_by("m.msg_id", "DESC");
                }
                $this->db->limit(25);
                $query2 = $this->db->get();
                if ($query2 && $query2->num_rows() > 0) {
                    $Result = $query2->result();
                }
            }

            if ($isRead && $Result && $isGroup != 1) {
                // Use actual msg_conversation_number from results for correct contact match
                $actualNumber = $Result[0]->msg_conversation_number ?? $phoneNumber;
                $read = [
                    "isread" => 0
                ];
                $this->db->where('session', $tokenDevice);
                $this->db->where('phonenumber', $actualNumber);
                $this->db->update(db_prefix() . 'contactcenter_contact', $read);
            }
            return array_reverse($Result);
        }
    }


    /**
     * Pega os contatos no banco 
     * @param int $staffid Staff ID - when 0, use $device_token (session) to fetch by device
     * @param string $msg_fromMe
     * @param mixed $paginadorDate
     * @param mixed $status
     * @param mixed $assignLead
     * @param mixed $chat_marked_read
     * @param string $chat_sort
     * @param bool $include_last_message
     * @param string|null $device_token Device token (session) - used when staffid is 0 (e.g. local/dev environment, department devices)
     * @return array|false
     */
    public function get_contact_chat($staffid, $msg_fromMe = "", $paginadorDate = null, $status = null, $assignLead = null, $chat_marked_read = null, $chat_sort = "newest_first", $include_last_message = false, $device_token = null)
    {
        log_activity("get_contact_chat CALLED - Staff ID: " . ($staffid ?? 'null') . ", Device token: " . ($device_token ? 'yes' : 'no'), get_staff_user_id());
        
        // When staffid is 0/null, use device_token (session) to fetch - for local env, department devices (dev_type 3), api_local
        $use_session_filter = (!$staffid && !empty($device_token));
        if (!$staffid && !$use_session_filter) {
            log_activity("get_contact_chat ABORTED - No staff ID and no device token provided", get_staff_user_id());
            return false;
        }

        $limit = 25;

        // Check if chat_marked_read field exists
        $has_chat_marked_read = $this->db->field_exists('chat_marked_read', db_prefix() . 'contactcenter_contact');
        
        $select_fields = '
            c.*, 
            c.transferid, 
            c.session, 
            c.isread, 
            c.staffid, 
            c.leadid, 
            c.assigned, 
            c.client_id, 
            c.rel_type, 
            c.rel_type, 
            c.phonenumber, 
            c.name as contactname, 
            c.thumb as contactthumb, 
            c.isGroup, c.date, 
            l.status,
            l.name as leadname,
            l.assigned                    
        ';
        
        if ($has_chat_marked_read) {
            $select_fields = str_replace('c.isread,', 'c.isread, c.chat_marked_read,', $select_fields);
        }
        
        // For by_unread_date, we need to join with messages table
        if ($chat_sort == "by_unread_date") {
            $select_fields .= ', MIN(CASE WHEN m.msg_fromMe = 0 THEN m.msg_date END) as first_unread_date';
        }
        
        // Add group_api_name to select if it's a group
        $select_fields .= ', g.group_api_name as group_name';
        
        // Add last message fields only if requested (to avoid performance issues on initial load)
        if ($include_last_message) {
            $select_fields .= ', 
                lm.msg_content as last_msg_content,
                lm.msg_fromMe as last_msg_fromMe,
                lm.msg_date as last_msg_date,
                lm.msg_name as last_msg_name,
                lm.msg_type as last_msg_type
            ';
        } else {
            // Don't add last message fields to avoid expensive query
            // Helper function will handle empty values gracefully
        }
        
        $this->db->select($select_fields);
        $this->db->from(db_prefix() . 'contactcenter_contact c');
        $this->db->join(db_prefix() . 'leads l', 'l.id = c.leadid', 'left');
        // Join with group_api table to get group name (only for groups)
        $this->db->join(db_prefix() . 'contactcenter_group_api g', 'g.group_api_id = c.phonenumber', 'left');
        
        // Only join with last message if requested (this is expensive)
        if ($include_last_message) {
            // Optimized: use msg_id instead of msg_date for faster lookup
            $last_message_subquery = '
                SELECT 
                    m1.msg_conversation_number,
                    m1.msg_session,
                    m1.msg_content,
                    m1.msg_fromMe,
                    m1.msg_date,
                    m1.msg_name,
                    m1.msg_type
                FROM ' . db_prefix() . 'contactcenter_message m1
                INNER JOIN (
                    SELECT 
                        msg_conversation_number,
                        msg_session,
                        MAX(msg_id) as max_msg_id
                    FROM ' . db_prefix() . 'contactcenter_message
                    GROUP BY msg_conversation_number, msg_session
                ) m2 ON m1.msg_conversation_number = m2.msg_conversation_number 
                     AND m1.msg_session = m2.msg_session 
                     AND m1.msg_id = m2.max_msg_id
            ';
            
            $this->db->join('(' . $last_message_subquery . ') lm', 
                'lm.msg_conversation_number = c.phonenumber AND lm.msg_session = c.session', 
                'left');
        }
        
        // Join with messages table for by_unread_date sort (use different alias to avoid conflict)
        if ($chat_sort == "by_unread_date") {
            $this->db->join(db_prefix() . 'contactcenter_message m', 'm.msg_conversation_number = c.phonenumber AND m.msg_session = c.session', 'left');
        }
        
        if ($use_session_filter) {
            $this->db->where('c.session', $device_token);
        } else {
            $this->db->where('c.staffid', $staffid);
        }
        $this->db->where('c.active', 1);

        if ($status) {
            $this->db->where('l.status', $status);
        }
        if ($paginadorDate) {
            $this->db->where('c.id <', $paginadorDate);
        }
        if ($assignLead) {
            $this->db->where('l.assigned', $assignLead);
        }
        if ($msg_fromMe !== "") {
            $this->db->where('c.msg_fromMe', 0);
        }
        if ($chat_marked_read !== null && $chat_marked_read !== "" && $has_chat_marked_read) {
            $this->db->where('c.chat_marked_read', $chat_marked_read);
        }

        // Group by for by_unread_date to handle the MIN() aggregate function
        if ($chat_sort == "by_unread_date") {
            $this->db->group_by('c.id');
        }

        // Apply sorting based on chat_sort parameter
        switch ($chat_sort) {
            case "oldest_first":
                // Order by date ascending (oldest first)
                $this->db->order_by('c.date', 'asc');
                break;
            case "unread_first":
                // Order by unread status first (unread = 0 or chat_marked_read = 0), then by date descending
                if ($has_chat_marked_read) {
                    $this->db->order_by('c.chat_marked_read', 'asc'); // 0 = unread comes first
                    $this->db->order_by('c.date', 'desc');
                } else {
                    // If chat_marked_read doesn't exist, fall back to isread
                    $this->db->order_by('c.isread', 'asc'); // Lower isread = more unread
                    $this->db->order_by('c.date', 'desc');
                }
                break;
            case "read_first":
                // Order by read status first (read = 1 or chat_marked_read = 1), then by date descending
                if ($has_chat_marked_read) {
                    $this->db->order_by('c.chat_marked_read', 'desc'); // 1 = read comes first
                    $this->db->order_by('c.date', 'desc');
                } else {
                    // If chat_marked_read doesn't exist, fall back to isread
                    $this->db->order_by('c.isread', 'desc'); // Higher isread = more read
                    $this->db->order_by('c.date', 'desc');
                }
                break;
            case "by_unread_date":
                // Order by date of first unread message (oldest unread first)
                $this->db->order_by('first_unread_date', 'asc');
                $this->db->order_by('c.date', 'desc');
                break;
            case "newest_first":
            default:
                // Default: Order by ID descending (newest first)
                $this->db->order_by('c.id', 'desc');
                break;
        }
        
        $this->db->limit($limit);

        $query = $this->db->get()->result();

        if ($query) {
            // Removed synchronous API calls from loop - these were causing severe performance issues
            // Group names are now fetched asynchronously when a group chat is opened (in ajax_get_messages_chat)
            // This allows the contact list to load quickly, and group names update when needed
            log_activity("get_contact_chat START - Total contacts: " . count($query) . ", Staff ID: " . ($staffid ?? 'null'), get_staff_user_id());
            
            $lastDate = end($query)->id;
            $paginador_key = $use_session_filter ? "dev_{$device_token}" : $staffid;
            $this->session->set_userdata("contacenter_paginadorContact_{$paginador_key}", $lastDate);
        }

        return $query;
    }



    public function get_contact_chat_open($staffid)
    {
        $this->db->where('c.staffid', $staffid);
        $this->db->where('c.active', 1);
        $this->db->order_by('c.id', 'desc');
        $this->db->limit(25);
        $query = $this->db->get(db_prefix() . 'contactcenter_contact c')->result();

        if ($query) {
            $lastDate = end($query)->id;
            $this->session->set_userdata("contacenter_paginadorContact_{$staffid}", $lastDate);
        }

        return $query;
    }


    /**
     * Pega os contatos no banco 
     * @param type $token
     * @return type
     */
    public function get_contact_messenger($data)
    {

        if ($data) {
            $limit = 25;
            $status = $data['status'];
            $paginadorDate = $data['paginadorDate'];

            // Consulta 1: Contato + Leads
            $this->db->select('c.id,c.lead_id,c.date,c.count, c.source,c.page_id,c.sender_id,l.id as leadid, l.name, l.contactcenter_thumb, l.status');
            $this->db->from(db_prefix() . 'facebookleadsintegration_messenger_contact c');
            $this->db->join(db_prefix() . 'leads l', 'l.id = c.lead_id', 'inner');
            $this->db->where('c.page_id', $data['page_id']);
            if ($status) {
                $this->db->where('l.status', $status);
            }
            if ($paginadorDate) {
                $this->db->where('c.date <', $paginadorDate);
            }
            $this->db->order_by('c.date', 'desc');
            $this->db->limit($limit);
            $results = $this->db->get()->result();

            if ($results) {
                // Pegar a data da última posição do array após a ordenação
                $lastDate = end($results)->date;
                $this->session->set_userdata("contacenter_paginadorContact_{$data['page_id']}", $lastDate);
                return $results;
            } else {
                return false;
            }
        } else {
            return false;
        }
    }

    public function get_contact_messenger_pusher($data)
    {

        if ($data) {
            $this->db->select('c.id,c.lead_id,c.date,c.source,c.page_id,c.sender_id,l.id as leadid, l.name, l.contactcenter_thumb, l.status');
            $this->db->from(db_prefix() . 'facebookleadsintegration_messenger_contact c');
            $this->db->join(db_prefix() . 'leads l', 'l.id = c.lead_id', 'inner');
            $this->db->where('c.page_id', $data['page_id']);
            $this->db->where('c.sender_id', $data['sender_id']);
            $results = $this->db->get()->result();
            if ($results) {
                return $results;
            } else {
                return false;
            }
        }
    }



    /**
     * Pega os Os Group no banco 
     * @param type $staffid
     * @return type
     */
    public function get_group_chat($token)
    {
        if ($token) {
            $this->db->select(" *, SUBSTRING_INDEX(SUBSTRING_INDEX(msg_send_id, '_', 2), '_', -1) as phone_number");
            $this->db->select('SUM(CASE WHEN msg_isread = 0 THEN 1 ELSE 0 END) AS unread_count');
            $this->db->select('MAX(msg_date) as msg_date');
            $this->db->where('msg_session', $token);
            $this->db->where('msg_isGroupMsg', 1);
            $this->db->group_by("phone_number");
            $this->db->order_by('msg_date', 'DESC');
            $this->db->limit(100);
            return $this->db->get(db_prefix() . 'contactcenter_message')->result();
        }
    }

    /**
     * pega as ordem da conversas
     * @param type $con_id
     * @return type
     */
    public function get_conversation_engine($con_id = null, $staffid = null, $filters = [])
    {
        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $staff =  $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($staff) {
                $this->db->where('device_id', $staff->dev_id);
            }
        }

        if ($con_id) {
            $this->db->where('con_id', $con_id);
            return $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();
        } else {
            // Apply filters
            $show_inactive = isset($filters['show_inactive']) ? $filters['show_inactive'] : false;
            if (!$show_inactive) {
                // By default, show only active campaigns
                $this->db->where('con_status', 1);
            }
            
            // Order by ID DESC (newest first) by default
            $this->db->order_by('con_id', 'DESC');
            
            return $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->result();
        }
    }

    /**
     * Salva o device no banco 
     * @param array $data
     * @return bool
     */
    public function add_device($data)
    {
        $data['dev_date'] = date("Y-m-d H:i:s");
        if ($data['dev_openai'] == 1) {
            $data['dev_openai_date'] = date("Y-m-d H:i:s");
        }

        $data['dev_number'] = preg_replace('/[^0-9]/', '', $data['dev_number']);


        $data['api_type'] = "axiom_evolution";
        // AXIOM: URL do servidor definida pelo usuário nas configurações, não hardcoded
        if (empty($data['server_url'])) {
            $data['server_url'] = "";
        }



        $result = $this->db->get(db_prefix() . 'contactcenter_device')->result();
        if ($result) {
            foreach ($result as  $device) {

                //validação do device do sistema para ter somente um device
                if ($data['dev_type'] == 1 && $device->dev_type == 1 && $device->dev_token != $data['dev_token']) {
                    if ($data['dev_id'] != "" && $device->dev_id != $data['dev_id']) {
                        $result = [
                            "sucesso" => false,
                            "aviso" => "Você só pode ter um device tipo sistema",
                        ];
                        return $result;
                    }
                } elseif ($data['staffid'] == $device->staffid && $device->dev_token != $data['dev_token'] && $data['dev_id'] != $device->dev_id) {
                    $result = [
                        "sucesso" => false,
                        "aviso" => "Você só pode ter um device por Colaborador",
                    ];
                    return $result;
                }
            }
        }

        $server_id_old = 0;
        $token_old = 0;
        if ($data['dev_id'] != "") {

            // get the device
            $device = $this->get_device($data["dev_id"]);
            $server_id_old = $device->server_id;

            $token_old = $device->dev_token;

            //faz update do device na tabela de contato caso troque de fluxo, limpa o chatbot
            $this->db->where('dev_id', $data['dev_id']);
            $Fluxo = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($Fluxo) {
                if ($Fluxo->chatbot_id != $data['chatbot_id']) {
                    $this->db->where('session', $data['dev_token']);
                    $this->db->update(db_prefix() . 'contactcenter_contact', ["chatbot_group_id" => null, "chatbot_agenda" => null]);
                }
            }


            $id = $data['dev_id'];
            unset($data['dev_id']);
            
            // Check if sales_knowledge column exists before trying to save it
            if (isset($data['sales_knowledge']) && !$this->db->field_exists('sales_knowledge', db_prefix() . 'contactcenter_device')) {
                // Column doesn't exist, remove from data to avoid error
                unset($data['sales_knowledge']);
                log_activity('Device update: sales_knowledge column not found, skipping field. Please run migration 174.');
            }
            
            $this->db->where('dev_id', $id);
            $this->db->update(db_prefix() . 'contactcenter_device', $data);

            if ($this->db->affected_rows() > 0) {
                $result = [
                    "sucesso" => true,
                    "aviso" => _l('contac_save'),
                ];
            }
        } else {
            //verifica se o plano tem limite de device
            $plan = $this->get_plan();
            $this->db->select('count(dev_id) as total');
            $this->db->where('dev_type !=', 1);
            $countDevice = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($countDevice->total >= $plan->qtd_device) {
                $result = [
                    "sucesso" => false,
                    "limit" => true,
                    "aviso" => _l('contac_assistent_aviso_limit_device'),
                ];
                return $result;
            }



            //faz a validação do token
            $this->db->where('dev_token', $data['dev_token']);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($device) {
                $result = [
                    "sucesso" => false,
                    "aviso" => "Você só pode ter um device por token",
                ];
                return $result;
            }

            // Check if sales_knowledge column exists before trying to insert it
            if (isset($data['sales_knowledge']) && !$this->db->field_exists('sales_knowledge', db_prefix() . 'contactcenter_device')) {
                // Column doesn't exist, remove from data to avoid error
                unset($data['sales_knowledge']);
                log_activity('Device insert: sales_knowledge column not found, skipping field. Please run migration 174.');
            }

            $this->db->insert(db_prefix() . 'contactcenter_device', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                $result = [
                    "sucesso" => true,
                    "aviso" => _l('contac_save'),
                ];


                if ($data['api_local'] == 1) {
                    log_activity("api_local  1");

                    return $result;
                }
            }
        }


        try {

       
            $server_old = null;
            if ($server_id_old > 0) {
                $server_old = $this->get_server($server_id_old);
            }

            if ($server_old != null && $server_old->id == $data['server_id']) {
                return $result;
            }

            // get host
            $host = site_url();

            // get server
            $server = $this->get_server($data['server_id']);


            if ($server_old != null) {

                // logout first
                $ApiUrl = $server_old->url . 'instance/logout/' .  $data['dev_instance_name'];
                $this->axiom_evolution->logout($ApiUrl, $data['dev_token']);

                $this->axiom_evolution->delete_instance($server_old, $host, $data['dev_instance_name']);
            }


            // create and delete instance
            if ($server->version == 1) {
                $this->axiom_evolution->create_instance_v1($server, $host, $data);
            } else {
                $this->axiom_evolution->create_instance_v2($server, $host, $data);
                log_activity("pedido de criação da instância {$data['dev_instance_name']} no servidor {$server->name}");
            }
        } catch (Exception $e) {
            log_activity("Erro ao criar ou deletar instância: " . $e->getMessage());
        }

        return $result;
    }

    /**
     * Deleta o device
     *
     * @param [int] $dev_id
     * @return void
     */
    public function delete_device($dev_id)
    {
        if ($dev_id) {
            $this->db->where('dev_id', $dev_id);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($device) {
                $this->db->where('dev_id', $device->dev_id);
                $this->db->delete(db_prefix() . 'contactcenter_device');
                if ($this->db->affected_rows() > 0) {
                    //deleta as mensagens
                    $this->db->where('msg_session', $device->dev_token);
                    $this->db->delete(db_prefix() . 'contactcenter_message');

                    //deleta os contatos
                    $this->db->where('session', $device->dev_token);
                    $this->db->delete(db_prefix() . 'contactcenter_contact');

                    // delete a instancia
                    $server = $this->get_server($device->server_id);
                    $host = site_url();
                    $this->axiom_evolution->delete_instance($server, $host, $device->dev_instance_name);

                    return true;
                }
            }
        }
    }

    /**
     * Transferir Lead para o staff
     *
     * @param [type] $data
     * @return void
     */
    public function transferir_leads($data)
    {
        if ($data) {
            unset($data['dev_id']);


            $this->db->where('staffid_to', $data["staffid_to"]);
            $this->db->where('dev_token', $data["dev_token"]);
            $this->db->where('phonenumber', $data["phonenumber"]);
            $result = $this->db->get(db_prefix() . 'contactcenter_atendimento_trans')->row();
            if ($result) {
                set_alert('danger', _l("contact_transfer_error_duplicidade"));
                return false;
            }

            if ($data["trans_id"] != "") {
                $this->db->where('trans_id', $data["trans_id"]);
                $this->db->update(db_prefix() . 'contactcenter_atendimento_trans', $data);
                if ($this->db->affected_rows() > 0) {
                    if ($data['lead_id']) {
                        $this->leads_model->log_lead_activity($data['lead_id'], _l('contact_transfer_log') . ' ' . get_staff_full_name($data['staffid_to']), "", json_encode($data));
                    }

                    $notified = add_notification([
                        'description'     => "Contatado {$data['lead_id']} foi transferido para você, acesse o link para ver mais detalhes.",
                        'touserid'        => $data['staffid_to'],
                        'link'            => 'contactcenter/chattransfer',
                    ]);
                    return true;
                }
            } else {
                $data['trans_date'] = date("Y-m-d H:i:s");
                $this->db->insert(db_prefix() . 'contactcenter_atendimento_trans', $data);
                $insert_id = $this->db->insert_id();
                if ($insert_id) {
                    if ($data['lead_id']) {
                        $this->leads_model->log_lead_activity($data['lead_id'], _l('contact_transfer_log') . ' ' . get_staff_full_name($data['staffid_to']), "", json_encode($data));
                    }
                    $notified = add_notification([
                        'description'     => "Contatado {$data['lead_id']} foi transferido para você, acesse o link para ver mais detalhes.",
                        'touserid'        => $data['staffid_to'],
                        'link'            => 'contactcenter/chattransfer',
                    ]);
                    return true;
                }
            }
            set_alert('danger', _l("contact_transfer_error"));
            return false;
        } else {
            set_alert('danger', _l("contact_transfer_error"));
            return false;
        }
    }

    /**
     * Retorna as transferencias de contatos
     * 
     */
    public function ajax_accept_contact($data)
    {
        if ($data) {
            $data["trans_accepted"] = 1;
            $leadid = $data['leadid'];
            $staffid_from = $data['datafrom'];
            $phoneNumber = $data['phonenumber'];
            $token = $data['token'];

            unset($data['phonenumber']);
            unset($data['leadid']);
            unset($data['datafrom']);
            unset($data['token']);

            $this->db->where('trans_id', $data['trans_id']);
            $this->db->update(db_prefix() . 'contactcenter_atendimento_trans', $data);
            if ($this->db->affected_rows() > 0) {
                $this->leads_model->log_lead_activity($leadid, _l('contact_transfer_accept'));
                $notified = add_notification([
                    'description'     => get_staff_full_name(get_staff_user_id()) . " " . _l("contact_transfer_accept_from") . " {$leadid}",
                    'touserid'        => $staffid_from,
                    'link'            => '',
                ]);

                //da o upadate na tabela de contatos
                $this->db->where("trans_id", $data['trans_id']);
                $transfer = $this->db->get(db_prefix() . 'contactcenter_atendimento_trans')->row();

                $transfer_contact = [
                    "staffid" => $transfer->staffid_to,
                    "transferid" => $transfer->trans_id,
                    "leadid" => $transfer->lead_id,
                ];

                $this->db->where("phonenumber", $phoneNumber);
                $this->db->where("session", $token);
                $this->db->update(db_prefix() . 'contactcenter_contact', $transfer_contact);

                $text = "Olá sou o(a) agente " . get_staff_full_name(get_staff_user_id()) . " estou assumindo o seu atendimento, no que posso ajudar?";
                $this->send_text($phoneNumber, $text, $staffid_from);

                return true;
            }
        }
    }
    /**
     * Retorna as transferencias de leads     *
     * @param [int] $staffid
     * @return void
     */
    public function get_transfer_leads($staffid = null, $accepted = 0)
    {
        if ($staffid) {
