            $this->db->order_by('trans_date', 'DESC');
            $this->db->where('trans_accepted', $accepted);
            $result = $this->db->get(db_prefix() . 'contactcenter_atendimento_trans')->result();
            if ($result) {
                return monta_html_contact_transferido($result);
            } else {
                return false;
            }
        }
    }

    /**
     * Salva motor de conversa 
     * @param array $data
     * @return bool
     */
    public function add_conversation_engine($data)
    {
        $data['con_date'] = date("Y-m-d H:i:s");
        $data['staffid'] = get_staff_user_id();

        // Ensure backup_phone_field is preserved (can be null)
        $backup_phone_field = isset($data['backup_phone_field']) ? $data['backup_phone_field'] : null;

        if ($data['tags'] != "" && $data['tags'] != null && count($data['tags']) > 0) {
            $data['tags'] = implode(",", $data['tags']);
        } else {
            $data['tags'] = "";
        }
        
        // Re-add backup_phone_field after tags processing to ensure it's not lost
        if ($backup_phone_field !== null) {
            $data['backup_phone_field'] = $backup_phone_field;
        } else {
            $data['backup_phone_field'] = null;
        }

        if ($data['con_id'] != "") {
            $id = $data['con_id'];
            unset($data['con_id']);

            // Log the data being updated, especially backup_phone_field
            log_message('debug', 'Updating conversation engine ID: ' . $id);
            log_message('debug', 'Backup phone field in update data: ' . var_export(isset($data['backup_phone_field']) ? $data['backup_phone_field'] : 'NOT SET', true));
            log_message('debug', 'All data keys: ' . implode(', ', array_keys($data)));

            $this->db->where('con_id', $id);
            $this->db->update(db_prefix() . 'contactcenter_conversation_engine', $data);
            
            // Log the SQL query to see what's actually being executed
            log_message('debug', 'Update SQL: ' . $this->db->last_query());
            log_message('debug', 'Affected rows: ' . $this->db->affected_rows());
            
            if ($this->db->affected_rows() > 0) {
                return true;
            } else {
                // Even if no rows were affected (same value), return true if update was successful
                // Check if the record exists and update was attempted
                $this->db->where('con_id', $id);
                $exists = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();
                if ($exists) {
                    return true; // Record exists, update was attempted (might be same value)
                }
            }
        } else {
            // Log the data being inserted
            log_message('debug', 'Inserting new conversation engine');
            log_message('debug', 'Backup phone field in insert data: ' . var_export(isset($data['backup_phone_field']) ? $data['backup_phone_field'] : 'NOT SET', true));
            
            $this->db->insert(db_prefix() . 'contactcenter_conversation_engine', $data);
            $insert_id = $this->db->insert_id();
            
            // Log the SQL query
            log_message('debug', 'Insert SQL: ' . $this->db->last_query());
            
            if ($insert_id) {
                return true;
            }
        }
    }

    /**
     * salva a lista de conversas
     * @param type $data
     * @return bool
     */
    public function add_conversation_engine_list($data)
    {
        if ($data) {
            // Verifica se $data["list_text"] está em branco
            if (empty($data["list_text"])) {
                // Verifica se o $_FILES["file"] não existe
                if (!isset($_FILES["file"]) || empty($_FILES["file"]["name"])) {
                    return false;
                }
            }

            if ($_FILES["file"] && $_FILES['file']['name']) {
                $file_extension = pathinfo($_FILES['file']['name'], PATHINFO_EXTENSION);

                // Define o tipo de mídia com base na extensão do arquivo
                $image_extensions = ['gif', 'jpg', 'jpeg', 'png'];
                $video_extensions = ['mp4', 'avi', 'mov', 'wmv'];
                $audio_extensions = ['mp3', 'wav', 'ogg'];

                if (in_array(strtolower($file_extension), $image_extensions)) {
                    $mediaType = 'image';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'image';
                } elseif (in_array(strtolower($file_extension), $video_extensions)) {
                    $mediaType = 'video';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'video';
                } elseif (in_array(strtolower($file_extension), $audio_extensions)) {
                    $mediaType = 'audio';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'audio';
                } else {
                    // Tipo de arquivo não suportado
                    return false;
                }

                if ($mediaType == 'audio') {
                    $media =  $this->uploads_media_php("contactcenter/{$mediaType}", $maxSize);
                } else {
                    $media = $this->uploads_media("contactcenter/{$mediaType}", $maxSize, $mediaType);
                }

                if ($media) {
                    $data["list_image"] = $media;
                } else {
                    return false;
                }
            }

            $this->db->insert(db_prefix() . 'contactcenter_conversation_engine_list', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                return $insert_id;
            }
        }
        return false;
    }

    public function update_conversation_engine_list($list_id, $data)
    {
        if ($list_id && $data) {
            // Verifica se $data["list_text"] está em branco
            if (empty($data["list_text"])) {
                // Verifica se o $_FILES["file"] não existe
                if (!isset($_FILES["file"]) || empty($_FILES["file"]["name"])) {
                    // Se não tem texto nem arquivo novo, verifica se já existe mídia
                    $this->db->where('list_id', $list_id);
                    $existing = $this->db->get(db_prefix() . 'contactcenter_conversation_engine_list')->row();
                    if (!$existing || (!$existing->list_text && !$existing->list_image)) {
                        return false;
                    }
                }
            }

            if ($_FILES["file"] && $_FILES['file']['name']) {
                $file_extension = pathinfo($_FILES['file']['name'], PATHINFO_EXTENSION);

                // Define o tipo de mídia com base na extensão do arquivo
                $image_extensions = ['gif', 'jpg', 'jpeg', 'png'];
                $video_extensions = ['mp4', 'avi', 'mov', 'wmv'];
                $audio_extensions = ['mp3', 'wav', 'ogg'];

                if (in_array(strtolower($file_extension), $image_extensions)) {
                    $mediaType = 'image';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'image';
                } elseif (in_array(strtolower($file_extension), $video_extensions)) {
                    $mediaType = 'video';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'video';
                } elseif (in_array(strtolower($file_extension), $audio_extensions)) {
                    $mediaType = 'audio';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'audio';
                } else {
                    // Tipo de arquivo não suportado
                    return false;
                }

                if ($mediaType == 'audio') {
                    $media =  $this->uploads_media_php("contactcenter/{$mediaType}", $maxSize);
                } else {
                    $media = $this->uploads_media("contactcenter/{$mediaType}", $maxSize, $mediaType);
                }

                if ($media) {
                    // Delete old media file if exists
                    $this->db->where('list_id', $list_id);
                    $old_list = $this->db->get(db_prefix() . 'contactcenter_conversation_engine_list')->row();
                    if ($old_list && $old_list->list_image) {
                        if (file_exists("uploads/{$old_list->list_image}")) {
                            unlink("uploads/{$old_list->list_image}");
                        }
                    }
                    $data["list_image"] = $media;
                } else {
                    return false;
                }
            }

            $this->db->where('list_id', $list_id);
            $this->db->update(db_prefix() . 'contactcenter_conversation_engine_list', $data);
            return $this->db->affected_rows() > 0;
        }
        return false;
    }


    /**
     * deleta a lsita dos engine
     * @param type $id
     * @return bool
     */
    public function delete_conversation_list($id)
    {

        if ($id) {

            $this->db->where('list_id', $id);
            $list = $this->db->get(db_prefix() . 'contactcenter_conversation_engine_list')->row();
            if ($list->list_image) {
                if (file_exists("uploads/{$list->list_image}")) {
                    unlink("uploads/{$list->list_image}");
                }
            }

            $this->db->where('list_id', $id);
            $deleted = $this->db->delete(db_prefix() . 'contactcenter_conversation_engine_list');
            if ($deleted) {
                log_activity('Deleted conversa list [' . $id . ']', get_staff_user_id());
                return true;
            }
        }
    }

    /**
     * deleta o engine
     * @param type $data
     * @return bool
     */
    public function delete_engine($data)
    {

        if ($data) {
            $this->db->where('con_id', $data["id"]);
            $this->db->delete(db_prefix() . 'contactcenter_conversation_engine_list');

            $this->db->where('con_id', $data["id"]);
            $deleted = $this->db->delete(db_prefix() . 'contactcenter_conversation_engine');
            if ($deleted) {
                log_activity('Deleted conversa list [' . $id . ']', get_staff_user_id());
                return true;
            }
        }
    }

    public function ajax_send_audio($data)
    {

        if ($data["phonenumber"]) {
            $base64 = $data["audio"];

            //$audio = $this->convert_base64_webm($base64, $ReturnUrl = false);

            $audio = $this->upload_audio("contactcenter/audio");
            log_activity('Send audio [' . $audio . ']');
            $audioUrl = site_url("/uploads/" . $audio);
            $send = $this->send_audio($data["phonenumber"], $audioUrl, $data["staffid"], $queue = true, $type_source = 'crm_user');
            $result = json_decode($send);
            log_message('error', 'Send audio response: ' . $result);
            $log = json_encode($result);
