            if ($result->error == false) {
                if (file_exists(FCPATH . "/uploads/" . $audio)) {
                    unlink(FCPATH . "/uploads/" . $audio);
                }
            }
            if ($send) {
                return true;
            }
        }
    }

    /**
     * salva o status publicado engine
     * @param type $data
     * @return bool
     */
    public function update_status_engine($data)
    {
        $id = $data['id'];

        // busco as mensagens
        $canSave = false;
        $mensagens = $this->get_engine_conversation_list_by_engine_id($id);
        if ($mensagens) {
            foreach ($mensagens as $mensagem) {

                if ($mensagem->list_text != null || $mensagem->list_image != null) {
                    $canSave = true;
                    break;
                }
            }
        }

        if (!$canSave) {
            return false;
        }


        unset($data['id']);
        $this->db->where('con_id', $id);
        $this->db->update(db_prefix() . 'contactcenter_conversation_engine', $data);
        if ($this->db->affected_rows() > 0) {
            return true;
        }
    }

