        }
    }

    /**
     * Faz upload de audio
     * @param type $path
     * @param type $maxSize
     * @return bool
     */
    public function upload_audio($path)
    {
        if ($_SERVER["REQUEST_METHOD"] == "POST" && isset($_FILES["audio"])) {
            // Verifica se houve algum erro durante o upload
            if ($_FILES["audio"]["error"] != UPLOAD_ERR_OK) {
                log_message('error', 'Erro durante o upload do arquivo de áudio: ' . $_FILES["audio"]["error"]);
                return "Erro durante o upload do arquivo de áudio.";
            }

            // Define o caminho completo do diretório de upload
            $upload_path = FCPATH . "uploads/{$path}/" . date("m-Y");

            // Se o diretório não existir, cria-o recursivamente com permissões 0777
            if (!is_dir($upload_path)) {
                mkdir($upload_path, 0777, true);
            }

            // Gera um nome único para o arquivo de áudio (com extensão .mp3)
            $filename = uniqid() . ".mp3";
            $target_file = "{$upload_path}/{$filename}";

            // Move o arquivo temporário para o diretório de upload
            if (move_uploaded_file($_FILES["audio"]["tmp_name"], $target_file)) {
                // Upload bem-sucedido, retorna o caminho relativo do arquivo
                return "{$path}/" . date("m-Y") . "/{$filename}";
            } else {
                log_message('error', 'Erro ao mover o arquivo temporário para o diretório de upload.');
                // Erro ao mover o arquivo temporário
                return "Erro ao enviar o arquivo de áudio.";
            }
        } else {
            log_message('error', 'Requisição inválida ou arquivo não enviado.');
            // Requisição inválida ou arquivo não enviado
            return "Nenhum arquivo de áudio enviado.";
        }
    }

    /**
     * uploads_image
     * @param string $path caminho para imagem sem a pasta uploads
     * @param int $maxSize O Tamanho maximo em MB que pode subir a imagem 1024 a cada 1MB
     * @return string Caminho da imagem
     */
    public function uploads_image($path, $maxSize = null)
    {
        // Define o caminho do diretório de upload
        $upload_path = FCPATH . "uploads/{$path}/" . date("m-Y");
        $return_path = "{$path}/" . date("m-Y");
        // Se o diretório não existir, cria-o
        if (!is_dir($upload_path)) {
            // Permissões 0777 dão permissões máximas, ajuste conforme necessário
            mkdir($upload_path, 0777, true);
        }

        // Manipulação do upload da imagem
        $config['upload_path'] = $upload_path;
        $config['allowed_types'] = 'gif|jpg|jpeg|png';
        $config['max_size'] = $maxSize; // Tamanho máximo em kilobytes (2MB)
        $config['file_name'] = uniqid(); // Nome do arquivo

        $this->load->library('upload', $config);

        if ($this->upload->do_upload("file")) {
            $upload_data = $this->upload->data();
            return $return_path . "/" . $upload_data['file_name'];
        } else {
            $error = $this->upload->display_errors();
            return false;
        }
    }

    /**
     * uploads_media
     *
     * @param [type] $path
     * @param [type] $maxSize
     * @param string $mediaType
     * @return void
     */
    public function uploads_media($path, $maxSize = null, $mediaType = 'image')
    {
        // Define o caminho do diretório de upload
        $upload_path = FCPATH . "uploads/{$path}/" . date("m-Y");
        $return_path = "{$path}/" . date("m-Y");

        // Se o diretório não existir, cria-o
        if (!is_dir($upload_path)) {
            mkdir($upload_path, 0777, true); // Permissões 0777
        }

        // Configuração para tipos de mídia
        $config['upload_path'] = $upload_path;
        $config['file_name'] = uniqid(); // Nome do arquivo

        // Definindo tipos de mídia permitidos
        if ($mediaType == 'image') {
            $config['allowed_types'] = 'gif|jpg|jpeg|png';
            $config['max_size'] = $maxSize; // Tamanho máximo em kilobytes
        } elseif ($mediaType == 'video') {
            $config['allowed_types'] = 'mp4|avi|mov|wmv';
            $config['max_size'] = $maxSize;
        } elseif ($mediaType == 'document') {
            $config['allowed_types'] = 'pdf|xlsx|doc|docx';
            $config['max_size'] = $maxSize;
        } elseif ($mediaType == 'zip') {
            $config['allowed_types'] = 'zip';
            $config['max_size'] = $maxSize;
        } elseif ($mediaType == 'audio') { // Suporte para áudio
            $config['allowed_types'] = 'mp3|wav|ogg';
            $config['max_size'] = $maxSize;
        } else {
            return false; // Tipo de mídia não suportado
        }

        $this->load->library('upload', $config);

        if ($this->upload->do_upload("file")) {
            $upload_data = $this->upload->data();
            return $return_path . "/" . $upload_data['file_name'];
        } else {
            $error = $this->upload->display_errors();
            print_r($error);
            return false;
        }
    }



    public function uploads_media_php($path, $maxSize = null)
    {
        // Define o caminho do diretório de upload
        $upload_path = FCPATH . "uploads/{$path}/" . date("m-Y");
        $return_path = "{$path}/" . date("m-Y");

        // Se o diretório não existir, cria-o
        if (!is_dir($upload_path)) {
            mkdir($upload_path, 0777, true);
        }

        // Verifica se o arquivo foi enviado
        if (isset($_FILES['file']) && $_FILES['file']['error'] == UPLOAD_ERR_OK) {
            $fileTmpPath = $_FILES['file']['tmp_name'];
            $fileName = $_FILES['file']['name'];
            $fileSize = $_FILES['file']['size'];
            $fileType = $_FILES['file']['type'];

            // Remove espaços do nome do arquivo
            $fileName = str_replace(' ', '_', $fileName);

            // Verifica o tamanho do arquivo
            if ($maxSize && $fileSize > $maxSize * 1024) { // Convertendo para bytes
                echo "O arquivo é muito grande.";
                return false;
            }

            // Gera um nome único para o arquivo
            $fileName = uniqid() . '_' . $fileName;
            $dest_path = $upload_path . '/' . $fileName;

            // Move o arquivo para o diretório de destino
            if (move_uploaded_file($fileTmpPath, $dest_path)) {
                return $return_path . "/" . $fileName; // Retorna o caminho do arquivo
            } else {
                echo "Erro ao mover o arquivo.";
                return false;
            }
        } else {
            echo "Nenhum arquivo enviado ou erro no upload.";
            return false;
        }
    }



    /**
     * atualiza a AI do leads
     * @param type $data
     * @return bool
     */
    public function off_ai_user_single($data)
    {
        if ($data) {
            $id = $data["id"];
            $new_status = $data["status"];
            $crear["gpt_status"] = $new_status;
            $this->db->where('id', $id);
            $this->db->update(db_prefix() . 'leads', $crear);
            
            // Verify the update was successful
            $this->db->where('id', $id);
            $lead_after = $this->db->get(db_prefix() . 'leads')->row();
            
            if ($this->db->affected_rows() > 0) {
                log_message('debug', "off_ai_user_single - Lead ID: {$id}, gpt_status updated to: {$new_status}, verified: " . ($lead_after->gpt_status ?? 'null'));
                log_activity("off_ai_user_single - Lead ID: {$id}, gpt_status updated to: {$new_status}, verified: " . ($lead_after->gpt_status ?? 'null'), get_staff_user_id());
                return true;
            } else {
                log_message('error', "off_ai_user_single FAILED - Lead ID: {$id}, attempted status: {$new_status}");
                log_activity("off_ai_user_single FAILED - Lead ID: {$id}, attempted status: {$new_status}", get_staff_user_id());
            }
        }
        return false;
    }

    /**
     * Liga e desliga a AI do device 
     * @param type $data
     * @return bool
     */
    public function ajax_off_ai_all($data)
    {
        if ($data) {
            $device = $this->get_device_token($data["id"]);
            if ($device) {
                $old_status = $device->dev_openai;
                $new_status = ($device->dev_openai == 1) ? 0 : 1;
                
                // Enhanced logging to track device-level AI toggles
                $caller_trace = debug_backtrace(DEBUG_BACKTRACE_IGNORE_ARGS, 5);
                $caller_info = '';
                foreach ($caller_trace as $i => $trace) {
                    if ($i > 0 && $i <= 3) {
                        $caller_info .= ($caller_info ? ' -> ' : '') . ($trace['function'] ?? 'unknown') . '()';
                    }
                }
                
                log_activity("DEVICE AI TOGGLE CALLED - Device ID: {$device->dev_id}, Old Status: {$old_status}, New Status: {$new_status}, Caller: {$caller_info}, Staff ID: " . get_staff_user_id(), get_staff_user_id());
                
                if ($device->dev_openai == 1) {
                    $crear["dev_openai"] = 0;
                    log_activity("Desligou a IA do Device: {$device->dev_id} (Device-level toggle)", get_staff_user_id());
                } else {
                    $crear["dev_openai"] = 1;
                    log_activity("Ligou a IA do Device: {$device->dev_id} (Device-level toggle)", get_staff_user_id());
                }

                $this->db->where('dev_id', $device->dev_id);
                $this->db->update(db_prefix() . 'contactcenter_device', $crear);
                
                if ($this->db->affected_rows() > 0) {
                    // Verify the update
                    $this->db->where('dev_id', $device->dev_id);
                    $device_after = $this->db->get(db_prefix() . 'contactcenter_device')->row();
                    log_activity("DEVICE AI TOGGLE VERIFICATION - Device ID: {$device->dev_id}, Status after update: " . ($device_after->dev_openai ?? 'null'), get_staff_user_id());
                    return true;
                }
            }
        }
    }

