            if ($device->api_local == 1) {
                $this->db->where('dev_token',  $device->dev_token);
                $this->db->update(db_prefix() . 'contactcenter_device', ["api_web_status" => "close"]);
            } else {
                $this->db->where('dev_token',  $device->dev_token);
                $this->db->update(db_prefix() . 'contactcenter_device', ["api_web_status" => "close", "status" => "close"]);
            }


            // renicia o dispositivo antes de pedir o qrcode
            $url = "{$server->url}instance/restart/{$device->dev_instance_name}";
            $this->axiom_evolution->restart_instance_evolution($url, $device->dev_token);
            sleep(2);

            // crio url 
            $url = "{$server->url}instance/create";

            $start = $this->axiom_evolution->start_isntance_evolution($url, $device->dev_token, $device->dev_instance_name);
            if ($start["status"] != 200) {

                $url = "{$server->url}instance/connect/{$device->dev_instance_name}";

                $qrcode = $this->axiom_evolution->connect_isntance_evolution($url, $device->dev_token);

                if ($qrcode["instance"] && $qrcode["instance"]["state"] && $qrcode["instance"]["state"] == "open") {
                    $result["message"] = "Conectado...";
                    $result["instance"]["status"] = "Conectado";
                    $result['message'] = "Dispositivo conectado";
                } else {

                    $result["response"]["qrcode"]["base64"] = $qrcode["base64"];
                    $result["response"]["qrcode"]["pairingCode"] = $qrcode["pairingCode"];
                    $result["message"] = "Conectando...";
                    $result['error'] = false;
                }


                return $result;
            } else {
                return $start;
            }
        }
        return false;
    }

    public function cron_status_device()
    {
        $devices = $this->get_device();
        if ($devices) {
            foreach ($devices as $device) {

                sleep(1);
                if ($device->dev_type != 1) {

                    if ($device->api_local == 1) {

                        $last_status = strtotime($device->last_status);
                        $current_time = time();

                        if (!$last_status || ($current_time - $last_status) > 180) { // mais de 3 min sem atualizar
                            $data = [
                                "status" => "close",
                                "api_local" => 0, // Desativa o api local   
                                "api_local_status"  => "close",
                            ];

                            //verifica se o device está ativo do backup
                            $result = $this->getConnectionStatus($device->dev_id);
                            if ($result) {
                                $status = $result["instance"]["state"];
                                $data["status"] = $status;
                            }
                        } else {
                            $data = [
                                "status" => "open",
                                "api_local_status"  => "open",
                            ];
                        }
                    } else {

                        $result = $this->getConnectionStatus($device->dev_id);
                        if ($result) {

                            $status = $result["instance"]["state"];
                            $data = [
                                "status" => $status,
                                "api_web_status"  => $status,
                            ];
                        }
                    }

                    $this->db->where('dev_id', $device->dev_id);
                    $this->db->update(db_prefix() . 'contactcenter_device', $data);
                }
            }
        }
    }

    /**
     * Pegas a notificação em tempo real e envia para whats 
     */
    public function cron_notification_staff()
    {

        $dateThreeDaysAgo = date('Y-m-d H:i:s', strtotime('-1 days'));

        $this->db->where('isread', 0);
        $this->db->where('isread_whats', 0);
        $this->db->where('date >=', $dateThreeDaysAgo);
        $notification = $this->db->get(db_prefix() . 'notifications')->result();
        if ($notification) {

            foreach ($notification as $notific) {

                $data["isread_whats"] = 1;
                $this->db->where('id', $notific->id);
                $this->db->update(db_prefix() . 'notifications', $data);

                //Pega os dados do staff(Telefone)
                $staff = get_staff($notific->touserid);

                $msg = "{$notific->from_fullname} " . _l("not_task_added_someone_as_follower");
                $additional_data = '';
                $additional_data = unserialize($notific->additional_data);
                $description = _l($notific->description, $additional_data) . " \n" . time_ago($notific->date);
                $description = $notific->from_fullname . ' - ' . str_replace("<br />", "", $description) . " \n" . admin_url("{$notific->link}");

                if ($staff->phonenumber) {
                    $result = $this->send_text($staff->phonenumber, $description, $staffid = null);
                } else {
                    echo "sem PhoneNumber";
                }


                //salva msg no banco 
                //  $this->insert_send_chat($result);

                echo $staff->phonenumber . "<br>";
                echo $result;
            }
        }
    }

    /**
     * dispara a conversa automatica pela IA
     */
    public function cron_engine_converstion()
    {
        echo "<pre>";
        log_activity("Campaign cron started - conversation_engine");

        // pego as conversas do motor
        $resultsMotorConversas = $this->get_engine_by_status_leads();
        log_activity("Campaign cron - Found " . count($resultsMotorConversas) . " active campaigns");
        
        foreach ($resultsMotorConversas as $motorConversa) {
            log_activity("Campaign cron - Processing engine ID: {$motorConversa->con_id}, Title: {$motorConversa->con_title}");

            if ($motorConversa->device_id == null) {
                log_activity("Campaign cron - Skipping engine {$motorConversa->con_id}, no device_id");
                continue;
            }

            // busco o agente pelo device_id (primary device for lead ownership)
            $agente = $this->get_device($motorConversa->device_id);
            if (!$agente) {
                log_activity("Campaign cron - Skipping engine {$motorConversa->con_id}, device not found");
                continue;
            }
            if (!$agente->staffid || $agente->dev_engine != 1) {
                log_activity("Campaign cron - Skipping engine {$motorConversa->con_id}, device not configured");
                continue;
            }
            if (!in_array($agente->status, ["inChat", "CONNECTED", "open", "connecting"])) {
                log_activity("Campaign cron - Skipping engine {$motorConversa->con_id}, device status: {$agente->status}");
                continue;
            }
            
            if ($agente && $agente->staffid && $agente->dev_engine == 1 && ($agente->status == "inChat" || $agente->status == "CONNECTED" || $agente->status == "open" || $agente->status == "connecting")) {
                log_activity("Campaign cron - Engine {$motorConversa->con_id} device OK, proceeding");
                
                // Build device list for rotation (primary + spare devices)
                $device_list = array();
                $device_list[] = $motorConversa->device_id; // Primary device first
                
                // Add spare devices if configured
                if (!empty($motorConversa->spare_devices)) {
                    $spare_devices = explode(',', $motorConversa->spare_devices);
                    foreach ($spare_devices as $spare_device_id) {
                        $spare_device_id = trim($spare_device_id);
                        if (!empty($spare_device_id) && $spare_device_id != $motorConversa->device_id) {
                            $spare_device = $this->get_device($spare_device_id);
                            // Only add if device is valid and connected
                            if ($spare_device && $spare_device->dev_engine == 1 && ($spare_device->status == "inChat" || $spare_device->status == "CONNECTED" || $spare_device->status == "open" || $spare_device->status == "connecting")) {
                                $device_list[] = $spare_device_id;
                            }
                        }
                    }
                }
                
                // Get current rotation index
                $rotation_index = isset($motorConversa->device_rotation_index) ? intval($motorConversa->device_rotation_index) : 0;
                $total_devices = count($device_list);
                
                if ($total_devices == 0) {
                    continue; // No valid devices
                }


                $start_time = strtotime($motorConversa->start_time);
                $end_time = strtotime($motorConversa->end_time);

                $current_time = strtotime(date("H:i:s"));

                if ($current_time < $start_time || $current_time > $end_time) {
                    log_activity("Campaign cron - Skipping engine {$motorConversa->con_id}, outside time window (current: " . date("H:i:s", $current_time) . ", start: " . date("H:i:s", $start_time) . ", end: " . date("H:i:s", $end_time) . ")");
                    continue;
                }

                $leads_day = intval($motorConversa->leads_day);
                if ($leads_day > 0) {
                    $leadsEnviadosHoje = $this->get_leads_enviados_hoje($motorConversa->con_id);
                    if ($leadsEnviadosHoje >= $leads_day) {
                        log_activity("Campaign cron - Skipping engine {$motorConversa->con_id}, daily limit reached ({$leadsEnviadosHoje}/{$leads_day})");
                        continue;
                    }
                }
                
                log_activity("Campaign cron - Engine {$motorConversa->con_id} passed time window and daily limit checks, proceeding to cadence check");

                // Get cadence settings (intervals are stored in minutes, convert to seconds)
                // CHECK CADENCE BEFORE PROCESSING LEADS to avoid updating leads if we can't send
                $batch_size = isset($motorConversa->batch_size) ? (int)$motorConversa->batch_size : 1;
                $batch_cooldown = isset($motorConversa->batch_cooldown) ? (int)$motorConversa->batch_cooldown : 3; // Already in minutes
                $interval_min_minutes = isset($motorConversa->message_interval_min) ? (int)$motorConversa->message_interval_min : 1; // Stored as minutes
                $interval_max_minutes = isset($motorConversa->message_interval_max) ? (int)$motorConversa->message_interval_max : 3; // Stored as minutes
                
                log_activity("Campaign cadence - Engine {$motorConversa->con_id} settings: batch_size={$batch_size}, cooldown={$batch_cooldown}min, interval={$interval_min_minutes}-{$interval_max_minutes}min");
                
                // Convert minutes to seconds for interval checking
                $interval_min = $interval_min_minutes * 60;
                $interval_max = $interval_max_minutes * 60;
                
                // Get last send time for this campaign
                // Check messages sent to leads that are part of this campaign
                log_activity("Campaign cadence - Engine {$motorConversa->con_id} checking last send time...");
                
                $last_send = null;
                // Use query builder instead of raw query for better error handling
                $this->db->select('MAX(m.msg_date) as last_send_time', false);
                $this->db->from(db_prefix() . 'contactcenter_message m');
                $this->db->join(db_prefix() . 'leads l', 'm.msg_conversation_number  = l.phonenumber', 'inner');
                $this->db->where('l.conversation_engine_id', $motorConversa->con_id);
                $this->db->where('m.msg_fromMe', 1);
                $last_send_query = $this->db->get();
                
                if ($last_send_query && $last_send_query->num_rows() > 0) {
                    $last_send = $last_send_query->row();
                    $last_send_time_str = ($last_send && isset($last_send->last_send_time) && $last_send->last_send_time) ? $last_send->last_send_time : "none";
                    log_activity("Campaign cadence - Engine {$motorConversa->con_id} last send query result: {$last_send_time_str}");
                } else {
                    log_activity("Campaign cadence - Engine {$motorConversa->con_id} no previous messages found, treating as first message");
                }
                
                // Check if enough time has passed since last message
                if ($last_send && isset($last_send->last_send_time) && $last_send->last_send_time && !empty($last_send->last_send_time)) {
                    $last_send_time = strtotime($last_send->last_send_time);
                    $current_time = time();
                    $time_since_last = $current_time - $last_send_time;
                    
                    // Get random interval (in seconds)
                    $required_interval = $this->get_random_interval($interval_min, $interval_max);
                    
                    log_activity("Campaign cadence check - Engine ID: {$motorConversa->con_id}, Last send: " . date('Y-m-d H:i:s', $last_send_time) . ", Time since: {$time_since_last}s, Required: {$required_interval}s");
                    
                    // If not enough time has passed, skip this cron run
                    if ($time_since_last < $required_interval) {
                        log_activity("Campaign cadence - Skipping engine {$motorConversa->con_id}, waiting {$required_interval}s, only {$time_since_last}s passed");
                        continue; // Skip this campaign, wait for next cron
                    }
                } else {
                    // No previous message, allow sending (first message)
                    log_activity("Campaign cadence - First message for engine {$motorConversa->con_id}, allowing send");
                }
                
                // Get batch tracking from campaign (refresh from DB to get latest values)
                $this->db->where('con_id', $motorConversa->con_id);
                $campaign_refresh = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();
                $current_batch_count = isset($campaign_refresh->current_batch_count) ? (int)$campaign_refresh->current_batch_count : 0;
                $last_batch_time = isset($campaign_refresh->last_batch_time) && $campaign_refresh->last_batch_time ? strtotime($campaign_refresh->last_batch_time) : 0;
                
                // Check if we're in cooldown period after a batch
                if ($current_batch_count >= $batch_size) {
                    $cooldown_seconds = $batch_cooldown * 60;
                    $time_since_batch = time() - $last_batch_time;
                    
                    if ($time_since_batch < $cooldown_seconds) {
                        log_activity("Campaign cadence - Skipping engine {$motorConversa->con_id}, batch cooldown active");
                        continue; // Still in cooldown, skip this cron run
                    } else {
                        // Cooldown finished, reset batch count
                        $current_batch_count = 0;
                        $this->db->where('con_id', $motorConversa->con_id);
                        $this->db->update(db_prefix() . 'contactcenter_conversation_engine', [
                            'current_batch_count' => 0,
                            'last_batch_time' => null
                        ]);
                    }
                }

                // Pega os leads - ONLY AFTER CADENCE CHECK PASSES
                $date_filter_type = isset($motorConversa->date_filter_type) ? $motorConversa->date_filter_type : 'creation_date';
                $date = ($date_filter_type == 'last_contact' && isset($motorConversa->leads_last_contact_data)) ? $motorConversa->leads_last_contact_data : $motorConversa->leads_create_data;
                $date_final = ($date_filter_type == 'last_contact' && isset($motorConversa->leads_last_contact_data_final)) ? $motorConversa->leads_last_contact_data_final : $motorConversa->leads_create_data_final;
                $birthday_field = isset($motorConversa->birthday_field) ? $motorConversa->birthday_field : null;
                if ($date_filter_type == 'birthday' && empty($birthday_field)) {
                    continue; // Skip birthday campaigns without birthday field configured
                }
                $Resultleads = $this->get_leads_status_cadastrado_staff($agente->staffid, $motorConversa->leads_status, $date, $date_final, $motorConversa->con_id, $motorConversa->tags, $date_filter_type, isset($motorConversa->filter_source) ? $motorConversa->filter_source : null, isset($motorConversa->filter_city) ? $motorConversa->filter_city : null, isset($motorConversa->filter_state) ? $motorConversa->filter_state : null, $birthday_field);
                
                log_activity("Campaign cron - Engine {$motorConversa->con_id} found " . count($Resultleads) . " leads to process");

                // Limit to one lead per cron run to respect intervals
                if (!empty($Resultleads)) {
                    $original_count = count($Resultleads);
                    $Resultleads = array_slice($Resultleads, 0, 1);
                    log_activity("Campaign cadence - Processing 1 lead for engine {$motorConversa->con_id}, Total available: {$original_count}");
                } else {
                    log_activity("Campaign cadence - No leads available for engine {$motorConversa->con_id}");
                    continue; // No leads, skip
                }

                // coloco o lead no fim da fila
                foreach ($Resultleads as $lead) {
                    if ($agente->api_local == 1) {
                        if ($lead->is_whatsapp == "pending") {
                            continue; // verifica e pula esperando a webhook confirmar
                        }
                    }

                    $this->db->where('id', $lead->id);
                    $this->db->update(db_prefix() . 'leads', ['date_whats' => date("Y-m-d H:i:s")]);
                }


                // salvo o total de leads
                $date_filter_type = isset($motorConversa->date_filter_type) ? $motorConversa->date_filter_type : 'creation_date';
                $date = ($date_filter_type == 'last_contact' && isset($motorConversa->leads_last_contact_data)) ? $motorConversa->leads_last_contact_data : $motorConversa->leads_create_data;
                $date_final = ($date_filter_type == 'last_contact' && isset($motorConversa->leads_last_contact_data_final)) ? $motorConversa->leads_last_contact_data_final : $motorConversa->leads_create_data_final;
                $birthday_field = isset($motorConversa->birthday_field) ? $motorConversa->birthday_field : null;
                $countLeads = $this->get_count_leads_status_cadastrado_staff($agente->staffid, $motorConversa->leads_status, $date, $date_final, $motorConversa->con_id, $date_filter_type, isset($motorConversa->filter_source) ? $motorConversa->filter_source : null, isset($motorConversa->filter_city) ? $motorConversa->filter_city : null, isset($motorConversa->filter_state) ? $motorConversa->filter_state : null, $birthday_field);
                $enCount["leads_count"] = $countLeads;
                $this->db->where('con_id', $motorConversa->con_id);
                $this->db->update(db_prefix() . 'contactcenter_conversation_engine', $enCount);

                // atualizo o status do lead para null enquanto nao envia a msg
                foreach ($Resultleads as $lead) {

                    //verifica se o lead tem o whatsapp e verifica se é API local ou API externa
                    if ($agente->api_local == 1) {
                        if ($lead->is_whatsapp == "pending") {
                            //verifica e pula esperando a webhook confirmar
                            $this->load->model('notification_websocket_model');
                            $data = [
                                'to' => [$lead->phonenumber],
                                'apikey' => $agente->dev_token,
                            ];

                            $result = $this->notification_websocket_model->send("campanha:verifyNumber", $data);
                            continue; // verifica e pula esperando a webhook confirmar
                        }
                    }

                    //grava o id da conversa no lead
                    $UpdadeLead = [
                        "con_id" => $motorConversa->con_id,
                        "lead_id" => $lead->id,
                        "send" => true,
                        "date_whats" => date("Y-m-d H:i:s"),
                        "campaign_tag_id" => isset($motorConversa->campaign_tag_id) ? $motorConversa->campaign_tag_id : null
                    ];
                    $this->updade_lead($UpdadeLead);
                }
                
                $ResultConversas = $this->get_engine_conversation_list_by_engine_id($motorConversa->con_id);
                $countConversas = count($ResultConversas);
                $counterror = 0;
                $leads_processed_this_run = 0;
                
                foreach ($Resultleads as $lead) {
                    // Stop if batch size reached
                    if ($current_batch_count >= $batch_size) {
                        break;
                    }
                    $messages_sent_count = 0; // Track messages sent for this lead for rotation

                    //verifica se o lead tem o whatsapp e verifica se é API local ou API externa
                    if ($agente->api_local == 1) {
                        if ($lead->is_whatsapp == "pending") {
                            continue;
                        } elseif ($lead->is_whatsapp == "not_registered") {
                            $isValidNumber = false;
                        } elseif ($lead->is_whatsapp == "registered") {
                            $isValidNumber = true;
                        }
                    } else {
                        //API externa
                        $data = [
                            "token" => $agente->dev_token,
                            "phonenumber" => $lead->phonenumber
                        ];

                        $isValidNumber = $this->verify_Number_Whatsapp($data);
                        if ($isValidNumber["exists"]) {
                            //atualiza o lead para whatsapp
                            $this->db->where('id', $lead->id);
                            $this->db->update(db_prefix() . 'leads', ['is_whatsapp' => 'registered']);
                            $isValidNumber = true;
                        } else {
                            $isValidNumber = false;
                        }
                    }



                    if ($isValidNumber == false) {
                        // Try backup phone if configured
                        $backup_tried = false;
                        $backup_success = false;
                        
                        if (!empty($motorConversa->backup_phone_field)) {
                            $campaign_name = isset($motorConversa->con_title) ? $motorConversa->con_title : "ID: {$motorConversa->con_id}";
                            $campaign_id = $motorConversa->con_id;
                            
                            log_activity("Campaign backup phone VALIDATION ATTEMPT - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Lead: {$lead->name}, Primary phone invalid: {$lead->phonenumber}, Trying backup field ID: {$motorConversa->backup_phone_field}", get_staff_user_id());
                            
                            // Get backup phone number from custom field
                            $backup_phone = get_custom_field_value($lead->id, $motorConversa->backup_phone_field, 'leads', false);
                            
                            if (!empty($backup_phone)) {
                                $backup_tried = true;
                                
                                // Get country code for formatting (default to Brazil/55 if not set)
                                $country_code = isset($motorConversa->backup_phone_country_code) ? $motorConversa->backup_phone_country_code : '55';
                                
                                // Format phone number according to country code
                                $this->load->helper('contactcenter');
                                $backup_phone_clean = formatPhoneNumber($backup_phone, false, $country_code);
                                
                                if (!empty($backup_phone_clean)) {
                                    log_activity("Campaign backup phone VALIDATION FOUND - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Backup number found: {$backup_phone_clean} (original: {$backup_phone}, country code: {$country_code})", get_staff_user_id());
                                    
                                    // Validate backup phone number
                                    if ($agente->api_local == 1) {
                                        // For local API, check if backup number is registered
                                        $this->db->where('id', $lead->id);
                                        $backup_lead_check = $this->db->get(db_prefix() . 'leads')->row();
                                        if ($backup_lead_check && $backup_lead_check->is_whatsapp == "registered") {
                                            $backup_success = true;
                                        } else {
                                            // Check backup number directly
                                            $temp_lead = clone $lead;
                                            $temp_lead->phonenumber = $backup_phone_clean;
                                            $temp_lead->is_whatsapp = "pending";
                                            // We'll validate during send, so assume it might work
                                            $backup_success = true;
                                        }
                                    } else {
                                        // For external API, verify backup number
                                        $backup_data = [
                                            "token" => $agente->dev_token,
                                            "phonenumber" => $backup_phone_clean
                                        ];
                                        
                                        $backup_isValidNumber = $this->verify_Number_Whatsapp($backup_data);
                                        if ($backup_isValidNumber["exists"]) {
                                            $backup_success = true;
                                            // Update lead phonenumber and is_whatsapp
                                            $old_phone = $lead->phonenumber;
                                            $this->db->where('id', $lead->id);
                                            $this->db->update(db_prefix() . 'leads', [
                                                'phonenumber' => $backup_phone_clean,
                                                'is_whatsapp' => 'registered'
                                            ]);
                                            
                                            // Add note to lead with detailed information
                                            $this->load->model('misc_model');
                                            $timestamp = date('d/m/Y H:i:s');
                                            $campaign_name = isset($motorConversa->con_title) ? $motorConversa->con_title : "ID: {$motorConversa->con_id}";
                                            $note_text = "Número de telefone atualizado automaticamente pela campanha durante validação.\n\n";
                                            $note_text .= "Campanha: {$campaign_name}\n";
                                            $note_text .= "Data/Hora: {$timestamp}\n";
                                            $note_text .= "Número anterior: {$old_phone}\n";
                                            $note_text .= "Novo número: {$backup_phone_clean}\n";
                                            $note_text .= "\nO número anterior não era válido para WhatsApp, então o sistema utilizou o número de backup configurado na campanha.";
                                            
                                            // Get a valid staff ID (use device staffid if available, otherwise get first admin or system user)
                                            $note_staffid = get_staff_user_id();
                                            if (empty($note_staffid) || $note_staffid == 0) {
                                                // Try to get staff ID from the device/agent
                                                if (isset($agente) && !empty($agente->staffid)) {
                                                    $note_staffid = $agente->staffid;
                                                } else {
                                                    // Get first admin staff ID as fallback
                                                    $this->db->select('staffid');
                                                    $this->db->where('admin', 1);
                                                    $this->db->where('active', 1);
                                                    $this->db->limit(1);
                                                    $admin_staff = $this->db->get(db_prefix() . 'staff')->row();
                                                    $note_staffid = $admin_staff ? $admin_staff->staffid : 1;
                                                }
                                            }
                                            
                                            try {
                                                // Manually insert note to ensure valid staff ID
                                                $note_data = [
                                                    'description' => nl2br($note_text),
                                                    'dateadded' => date('Y-m-d H:i:s'),
                                                    'addedfrom' => $note_staffid,
                                                    'rel_type' => 'lead',
                                                    'rel_id' => $lead->id
                                                ];
                                                
                                                $note_data = hooks()->apply_filters('create_note_data', $note_data, 'lead', $lead->id);
                                                
                                                $this->db->insert(db_prefix() . 'notes', $note_data);
                                                $note_id = $this->db->insert_id();
                                                
                                                if ($note_id) {
                                                    hooks()->do_action('note_created', $note_id, $note_data);
                                                    log_activity("Campaign backup phone NOTE ADDED ✓ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Note ID: {$note_id}, Staff ID: {$note_staffid}", $note_staffid);
                                                } else {
                                                    log_activity("Campaign backup phone NOTE FAILED ✗ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Failed to add note", $note_staffid);
                                                }
                                            } catch (Exception $e) {
                                                log_activity("Campaign backup phone NOTE ERROR ✗ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Error: " . $e->getMessage(), $note_staffid);
                                            }
                                            
                                            log_activity("Campaign backup phone VALIDATION SUCCESS ✓ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Lead: {$lead->name}, Phone updated from {$old_phone} to {$backup_phone_clean}, Backup number is valid", get_staff_user_id());
                                            
                                            // Update lead object for subsequent processing
                                            $lead->phonenumber = $backup_phone_clean;
                                            $lead->is_whatsapp = 'registered';
                                            $isValidNumber = true; // Set to true so processing continues
                                        } else {
                                            log_activity("Campaign backup phone VALIDATION FAILED ✗ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Lead: {$lead->name}, Backup number also invalid: {$backup_phone_clean}", get_staff_user_id());
                                        }
                                    }
                                } else {
                                    log_activity("Campaign backup phone VALIDATION INVALID - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Backup field value is empty or invalid after cleaning (original: {$backup_phone})", get_staff_user_id());
                                }
                            } else {
                                log_activity("Campaign backup phone VALIDATION NOT FOUND - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, No backup phone found in custom field ID: {$motorConversa->backup_phone_field}", get_staff_user_id());
                            }
                        } else {
                            $primary_error = "Número do lead não é valido para o whatsapp";
                            log_activity("Campaign backup phone VALIDATION NOT CONFIGURED - Campaign: {$motorConversa->con_id}, Lead ID: {$lead->id}, Primary phone invalid: {$lead->phonenumber}, No backup field configured", get_staff_user_id());
                        }
                        
                        // If backup didn't work or wasn't tried, mark as error
                        if (!$backup_success) {
                            $UpdadeLead = [
                                "lead_id" => $lead->id,
                                "status_final" => $motorConversa->leads_status,
                                "date_whats" => date("Y-m-d H:i:s")
                            ];
                            $this->rollback_lead($UpdadeLead);

                            $message = "Número do lead não é valido para o whatsapp";
                            if ($backup_tried) {
                                $message .= " (backup também inválido)";
                            }

                            // coloca o lead na tabela de erro
                            $this->save_contactcenter_error($lead, $motorConversa, $message, true);

                            continue;
                        }
                        // If backup succeeded, $isValidNumber is now true and processing continues
                    }

                    $message = "";
                    foreach ($ResultConversas as $Conversas) {
                        sleep(2);

                        // Select device for this message using round-robin
                        $device_index = $rotation_index % $total_devices;
                        $selected_device_id = $device_list[$device_index];
                        $selected_device = $this->get_device($selected_device_id);
                        
                        // Verify selected device is still valid
                        if (!$selected_device || $selected_device->dev_engine != 1 || !in_array($selected_device->status, ["inChat", "CONNECTED", "open", "connecting"])) {
                            // Fallback to primary device if selected device is invalid
                            $selected_device = $agente;
                            $selected_device_id = $motorConversa->device_id;
                        }
                        
                        // Use selected device's staffid for sending, but lead ownership stays with primary device
                        $sending_staffid = $selected_device->staffid;
                        
                        // Log device rotation for debugging (only log first message per lead to avoid spam)
                        if ($Conversas === reset($ResultConversas)) {
                            log_activity("Device rotation - Engine ID: {$motorConversa->con_id}, Lead ID: {$lead->id}, Using device: {$selected_device_id} (Index: {$device_index}/{$total_devices}), Primary device: {$motorConversa->device_id}", get_staff_user_id());
                        }

                        if ($Conversas->list_image != null) {

                            $texto = "";
                            if ($Conversas->list_text != null && $Conversas->list_text != "") {

                                $textArray = array_filter(explode('|', $Conversas->list_text), function ($value) {
                                    return trim($value) !== '';
                                });
                                $text = $textArray[array_rand($textArray)];

                                // Load merge fields library
                                if (!class_exists('Leads_merge_fields', false)) {
                                    $this->load->library('merge_fields/leads_merge_fields');
                                }
                                
                                // Store original text for logging
                                $original_texto = $texto;
                                
                                // Get all merge fields for this lead
                                $merge_fields = $this->leads_merge_fields->format($lead->id);
                                
                                // Add custom variables for backward compatibility
                                $firstName = explode(' ', $lead->name)[0];
                                $merge_fields['{FirstName}'] = $firstName;
                                $merge_fields['{Lead}'] = $lead->name;
                                $merge_fields['{Agente}'] = get_contactcenter_staff_name($agente->staffid);
                                
                                // Replace all merge fields (case-insensitive)
                                $replaced_fields = [];
                                $unreplaced_fields = [];
                                
                                foreach ($merge_fields as $key => $val) {
                                    if (stripos($texto, $key) !== false) {
                                        $texto = str_ireplace($key, $val, $texto);
                                        $replaced_fields[$key] = $val;
                                    }
                                }
                                
                                // Check for unreplaced fields
                                preg_match_all('/\{[^}]+\}/', $texto, $matches);
                                if (!empty($matches[0])) {
                                    $unreplaced_fields = array_unique($matches[0]);
                                }
                                
                                // Parse spintax if needed
                                $texto_before_spintax = $texto;
                                $texto = parse_spintax($texto);
                                
                                // Log merge field replacement
                                $log_message = "Conversation Message Sent - Lead ID: {$lead->id}, Conversation ID: {$Conversas->id}\n";
                                $log_message .= "Original Text: " . substr($original_texto, 0, 200) . (strlen($original_texto) > 200 ? '...' : '') . "\n";
                                $log_message .= "After Merge Fields: " . substr($texto_before_spintax, 0, 200) . (strlen($texto_before_spintax) > 200 ? '...' : '') . "\n";
                                $log_message .= "Final Text: " . substr($texto, 0, 200) . (strlen($texto) > 200 ? '...' : '') . "\n";
                                $log_message .= "Replaced Fields (" . count($replaced_fields) . "): " . implode(', ', array_keys($replaced_fields)) . "\n";
                                if (!empty($unreplaced_fields)) {
                                    $log_message .= "WARNING - Unreplaced Fields (" . count($unreplaced_fields) . "): " . implode(', ', $unreplaced_fields) . "\n";
                                }
                                
                                log_activity($log_message, $agente->staffid);
                            }

                            $img = site_url("uploads/{$Conversas->list_image}");

                            if ($Conversas->media_type == "audio") {
                                $response = $this->try_send_with_backup(
                                    $lead, 
                                    $motorConversa, 
                                    $lead->phonenumber, 
                                    $texto, 
                                    $sending_staffid, 
                                    'audio', 
                                    ['url' => $img]
                                );
                            } else {
                                $name = explode('/', $Conversas->list_image);
                                $fileName = end($name);
                                $response = $this->try_send_with_backup(
                                    $lead, 
                                    $motorConversa, 
                                    $lead->phonenumber, 
                                    $texto, 
                                    $sending_staffid, 
                                    'file', 
                                    ['url' => $img, 'media_type' => $Conversas->media_type, 'file_name' => $fileName, 'caption' => $texto]
                                );
                            }

                            if ($response["error"] == true) {
                                $counterror++;
                                $message .= $response["message"];
                            } else {
                                // Increment rotation index only on successful send
                                $rotation_index++;
                                $messages_sent_count++;
                            }
                        } else {

                            if ($Conversas->list_text == null) {
                                continue;
                            }

                            $textArray = array_filter(explode('|', $Conversas->list_text), function ($value) {
                                return trim($value) !== '';
                            });
                            $text = $textArray[array_rand($textArray)];

                            $firstName = explode(' ', $lead->name)[0];
                            $texto = str_replace('{FirstName}', $firstName, $text);
                            $texto = str_replace('{Lead}', $lead->name, $texto);
                            $texto = str_replace('{Agente}', get_contactcenter_staff_name($agente->staffid), $texto);

                            $response = $this->try_send_with_backup(
                                $lead, 
                                $motorConversa, 
                                $lead->phonenumber, 
                                $texto, 
                                $sending_staffid, 
                                'text'
                            );
                            if ($response["error"] == true) {
                                $counterror++;
                                $message .= $response["message"] . " \n";
                            } else {
                                // Increment rotation index only on successful send
                                $rotation_index++;
                                $messages_sent_count++;
                            }
                        }
                    }
                    
                    // Update rotation index and batch count in database after processing all messages for this lead
                    if ($messages_sent_count > 0) {
                        $current_batch_count++;
                        $leads_processed_this_run++;
                        
                        $update_data = [
                            'device_rotation_index' => $rotation_index,
                            'current_batch_count' => $current_batch_count
                        ];
                        
                        // If batch is complete, set last_batch_time
                        if ($current_batch_count >= $batch_size) {
                            $update_data['last_batch_time'] = date('Y-m-d H:i:s');
                        }
                        
                        $this->db->where('con_id', $motorConversa->con_id);
                        $this->db->update(db_prefix() . 'contactcenter_conversation_engine', $update_data);
                    }

                    if ($counterror == $countConversas) {
                        $UpdadeLead = [
                            "lead_id" => $lead->id,
                            "status_final" => $motorConversa->leads_status,
                            "status_whats" => 1,
                            "date_whats" => date("Y-m-d H:i:s")
                        ];
                        $this->rollback_lead($UpdadeLead);


                        // coloca o lead na tabela de erro
                        $this->save_contactcenter_error($lead, $motorConversa, $message);
                    } else {

                        // deleta o lead da tabela de erro baseado no lead_id e motor_id
                        $this->db->where('lead_id', $lead->id);
                        $this->db->where('con_id', $motorConversa->con_id);
                        $this->db->delete(db_prefix() . 'contactcenter_conversation_engine_error');

                        // Lead ownership stays with primary device (agente->staffid), not the sending device
                        $UpdadeLead = [
                            "lead_id" => $lead->id,
                            "send" => true,
                            "con_id" => $motorConversa->con_id,
                            "status_final" => $motorConversa->leads_status_final,
                            "status_whats" => 1,
                            "date_whats" => date("Y-m-d H:i:s")
                        ];
                        $this->updade_lead($UpdadeLead);

                        $this->update_conversation_engine($motorConversa);
                    }
                }
            }
        }
    }

    /**
     * Tries to send message with primary phone, then backup field if configured
     * @param object $lead Lead object
     * @param object $motorConversa Campaign object
     * @param string $phone_number Phone number to try
     * @param string $message_text Message text
     * @param int $sending_staffid Staff ID
     * @param string $type Message type (text, audio, file)
     * @param array $extra_params Extra parameters for send_file/send_audio
     * @return array Response array with 'error' and 'message' keys
     */
    private function try_send_with_backup($lead, $motorConversa, $phone_number, $message_text, $sending_staffid, $type = 'text', $extra_params = [])
    {
        $campaign_name = isset($motorConversa->con_title) ? $motorConversa->con_title : "ID: {$motorConversa->con_id}";
        $campaign_id = $motorConversa->con_id;
        
        // Try primary phone number first
        $response = $this->send_message_by_type($phone_number, $message_text, $sending_staffid, $type, $extra_params);
        
        // If primary failed and backup field is configured, try backup
        if ($response["error"] == true && !empty($motorConversa->backup_phone_field)) {
            $primary_error = isset($response["message"]) ? $response["message"] : "Unknown error";
            log_activity("Campaign backup phone ATTEMPT - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Lead: {$lead->name}, Primary phone failed: {$phone_number}, Error: {$primary_error}, Trying backup field ID: {$motorConversa->backup_phone_field}", get_staff_user_id());
            
            // Get backup phone number from custom field
            $backup_phone = get_custom_field_value($lead->id, $motorConversa->backup_phone_field, 'leads', false);
            
            if (!empty($backup_phone)) {
                // Get country code for formatting (default to Brazil/55 if not set)
                $country_code = isset($motorConversa->backup_phone_country_code) ? $motorConversa->backup_phone_country_code : '55';
                
                // Format phone number according to country code
                $this->load->helper('contactcenter');
                $backup_phone_clean = formatPhoneNumber($backup_phone, false, $country_code);
                
                if (!empty($backup_phone_clean)) {
                    log_activity("Campaign backup phone FOUND - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Backup number found: {$backup_phone_clean} (original: {$backup_phone}, country code: {$country_code})", get_staff_user_id());
                    
                    // Try sending with backup number
                    $backup_response = $this->send_message_by_type($backup_phone_clean, $message_text, $sending_staffid, $type, $extra_params);
                    
                    if ($backup_response["error"] == false) {
                        // Backup succeeded! Update lead phonenumber and add note
                        $old_phone = $lead->phonenumber;
                        
                        // Update lead phonenumber
                        $this->db->where('id', $lead->id);
                        $this->db->update(db_prefix() . 'leads', ['phonenumber' => $backup_phone_clean]);
                        
                        // Add note to lead with detailed information
                        $this->load->model('misc_model');
                        $timestamp = date('d/m/Y H:i:s');
                        $note_text = "Número de telefone atualizado automaticamente pela campanha.\n\n";
                        $note_text .= "Campanha: {$campaign_name}\n";
                        $note_text .= "Data/Hora: {$timestamp}\n";
                        $note_text .= "Número anterior: {$old_phone}\n";
                        $note_text .= "Novo número: {$backup_phone_clean}\n";
                        $note_text .= "\nO envio da mensagem falhou com o número anterior, então o sistema utilizou o número de backup configurado na campanha e a mensagem foi enviada com sucesso.";
                        
                        // Ensure we have a valid staff ID
                        $note_staffid = $sending_staffid;
                        if (empty($note_staffid) || $note_staffid == 0) {
                            $note_staffid = get_staff_user_id();
                            if (empty($note_staffid) || $note_staffid == 0) {
                                // Get first admin staff ID as fallback
                                $this->db->select('staffid');
                                $this->db->where('admin', 1);
                                $this->db->where('active', 1);
                                $this->db->limit(1);
                                $admin_staff = $this->db->get(db_prefix() . 'staff')->row();
                                $note_staffid = $admin_staff ? $admin_staff->staffid : 1;
                            }
                        }
                        
                        try {
                            // Manually insert note to ensure valid staff ID
                            $note_data = [
                                'description' => nl2br($note_text),
                                'dateadded' => date('Y-m-d H:i:s'),
                                'addedfrom' => $note_staffid,
                                'rel_type' => 'lead',
                                'rel_id' => $lead->id
                            ];
                            
                            $note_data = hooks()->apply_filters('create_note_data', $note_data, 'lead', $lead->id);
                            
                            $this->db->insert(db_prefix() . 'notes', $note_data);
                            $note_id = $this->db->insert_id();
                            
                            if ($note_id) {
                                hooks()->do_action('note_created', $note_id, $note_data);
                                log_activity("Campaign backup phone NOTE ADDED ✓ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Note ID: {$note_id}, Staff ID: {$note_staffid}", $note_staffid);
                            } else {
                                log_activity("Campaign backup phone NOTE FAILED ✗ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Failed to add note", $note_staffid);
                            }
                        } catch (Exception $e) {
                            log_activity("Campaign backup phone NOTE ERROR ✗ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Error: " . $e->getMessage(), $note_staffid);
                        }
                        
                        log_activity("Campaign backup phone SUCCESS ✓ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Lead: {$lead->name}, Phone updated from {$old_phone} to {$backup_phone_clean}, Message sent successfully", $note_staffid);
                        
                        // Update lead object for subsequent messages
                        $lead->phonenumber = $backup_phone_clean;
                        $phone_changed = true;
                        
                        // Add message sent note (second note after phone change note)
                        $this->add_campaign_message_note($lead, $motorConversa, $message_text, $type, $note_staffid, $backup_phone_clean);
                        
                        // Update last contact
                        $this->update_lead_last_contact($lead->id);
                        
                        $backup_response['phone_changed'] = true;
                        return $backup_response;
                    } else {
                        $backup_error = isset($backup_response["message"]) ? $backup_response["message"] : "Unknown error";
                        log_activity("Campaign backup phone FAILED ✗ - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Lead: {$lead->name}, Backup number also failed: {$backup_phone_clean}, Error: {$backup_error}", get_staff_user_id());
                    }
                } else {
                    log_activity("Campaign backup phone INVALID - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Backup field value is empty or invalid after cleaning (original: {$backup_phone})", get_staff_user_id());
                }
            } else {
                log_activity("Campaign backup phone NOT FOUND - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, No backup phone found in custom field ID: {$motorConversa->backup_phone_field}", get_staff_user_id());
            }
        } elseif ($response["error"] == true && empty($motorConversa->backup_phone_field)) {
            // Log when primary fails but no backup is configured (for debugging)
            $primary_error = isset($response["message"]) ? $response["message"] : "Unknown error";
            log_activity("Campaign backup phone NOT CONFIGURED - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Primary phone failed: {$phone_number}, Error: {$primary_error}, No backup field configured", get_staff_user_id());
        }
        
        // If primary succeeded, add message note and update last contact
        if ($response["error"] == false) {
            // Get valid staff ID for note
            $note_staffid = $sending_staffid;
            if (empty($note_staffid) || $note_staffid == 0) {
                $note_staffid = get_staff_user_id();
                if (empty($note_staffid) || $note_staffid == 0) {
                    $this->db->select('staffid');
                    $this->db->where('admin', 1);
                    $this->db->where('active', 1);
                    $this->db->limit(1);
                    $admin_staff = $this->db->get(db_prefix() . 'staff')->row();
                    $note_staffid = $admin_staff ? $admin_staff->staffid : 1;
                }
            }
            
            // Add message sent note
            $this->add_campaign_message_note($lead, $motorConversa, $message_text, $type, $note_staffid, $phone_number);
            
            // Update last contact
            $this->update_lead_last_contact($lead->id);
        }
        
        // Return original response (either primary failed or backup also failed)
        return $response;
    }
    
    /**
     * Add a note to lead when a campaign message is sent
     * @param object $lead Lead object
     * @param object $motorConversa Campaign object
     * @param string $message_text Message content
     * @param string $type Message type
     * @param int $staffid Staff ID
     * @param string $phone_used Phone number used to send
     */
    private function add_campaign_message_note($lead, $motorConversa, $message_text, $type, $staffid, $phone_used)
    {
        $campaign_name = isset($motorConversa->con_title) ? $motorConversa->con_title : "ID: {$motorConversa->con_id}";
        $campaign_id = $motorConversa->con_id;
        $timestamp = date('d/m/Y H:i:s');
        
        // Truncate message for note (first 200 chars)
        $message_preview = mb_substr($message_text, 0, 200);
        if (mb_strlen($message_text) > 200) {
            $message_preview .= '...';
        }
        
        // Determine message type label
        $type_label = 'Texto';
        if ($type == 'audio') {
            $type_label = 'Áudio';
        } elseif ($type == 'file') {
            $type_label = 'Arquivo';
        }
        
        $note_text = "Mensagem enviada pela campanha.\n\n";
        $note_text .= "Campanha: {$campaign_name}\n";
        $note_text .= "Data/Hora: {$timestamp}\n";
        $note_text .= "Tipo: {$type_label}\n";
        $note_text .= "Telefone: {$phone_used}\n";
        $note_text .= "\nMensagem:\n{$message_preview}";
        
        try {
            $note_data = [
                'description' => nl2br($note_text),
                'dateadded' => date('Y-m-d H:i:s'),
                'addedfrom' => $staffid,
                'rel_type' => 'lead',
                'rel_id' => $lead->id
            ];
            
            $note_data = hooks()->apply_filters('create_note_data', $note_data, 'lead', $lead->id);
            
            $this->db->insert(db_prefix() . 'notes', $note_data);
            $note_id = $this->db->insert_id();
            
            if ($note_id) {
                hooks()->do_action('note_created', $note_id, $note_data);
                log_activity("Campaign message note added - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Note ID: {$note_id}", $staffid);
            }
        } catch (Exception $e) {
            log_activity("Campaign message note error - Campaign: {$campaign_name} (ID: {$campaign_id}), Lead ID: {$lead->id}, Error: " . $e->getMessage(), $staffid);
        }
    }
    
    /**
     * Update lead's last contact date/time
     * @param int $lead_id Lead ID
     */
    private function update_lead_last_contact($lead_id)
    {
        $this->db->where('id', $lead_id);
        $this->db->update(db_prefix() . 'leads', [
            'lastcontact' => date('Y-m-d H:i:s')
        ]);
    }

    /**
     * Update lastcontact on the lead matching a phone number.
     * Tries exact match first, then digits-only match for performance.
     */
    public function update_lead_lastcontact_by_phone($phone)
    {
        $phone_clean = preg_replace('/\D/', '', $phone);
        if (empty($phone_clean)) return;

        $esc = $this->db->escape($phone_clean);
        $lead_table = db_prefix() . 'leads';

        $lead = $this->db->query(
            "SELECT id FROM {$lead_table}
             WHERE phonenumber = {$esc} OR phonenumber = " . $this->db->escape($phone) . "
             LIMIT 1"
        )->row();

        if (!$lead) {
            $lead = $this->db->query(
                "SELECT id FROM {$lead_table}
                 WHERE REPLACE(REPLACE(REPLACE(REPLACE(phonenumber, ' ', ''), '-', ''), '(', ''), ')', '') = {$esc}
                 LIMIT 1"
            )->row();
        }

        if ($lead) {
            $this->db->where('id', $lead->id);
            $this->db->update($lead_table, [
                'lastcontact' => date('Y-m-d H:i:s')
            ]);
        }
    }
    
    /**
     * Helper to send message by type
     */
    private function send_message_by_type($phone_number, $message_text, $sending_staffid, $type = 'text', $extra_params = [])
    {
        if ($type == 'audio') {
            return $this->send_audio(strval($phone_number), $extra_params['url'] ?? '', $sending_staffid);
        } elseif ($type == 'file') {
            return $this->send_file(
                strval($phone_number), 
                $extra_params['caption'] ?? '', 
                $extra_params['url'] ?? '', 
                $extra_params['media_type'] ?? 'image', 
                $sending_staffid, 
                $extra_params['file_name'] ?? null
            );
        } else {
            return $this->send_text(strval($phone_number), $message_text, $sending_staffid, null, null, true, 'crm');
        }
    }

    public function save_contactcenter_error($lead, $motorConversa, $message, $invalid_number = false)
    {

        $this->db->where('lead_id', $lead->id);
        $this->db->where('con_id', $motorConversa->con_id);
        $error = $this->db->get(db_prefix() . 'contactcenter_conversation_engine_error')->row();
        if ($error) {

            if ($invalid_number) {
                $error->invalid_number = 1;
            }

            $error->error_message = $message;
            $error->error_date = date("Y-m-d H:i:s");
            $this->db->where('error_id', $error->error_id);
            $this->db->update(db_prefix() . 'contactcenter_conversation_engine_error', $error);
        } else {
            $error["lead_id"] = $lead->id;
            $error["lead_name"] = $lead->name;
            $error["lead_phonumber"] = $lead->phonenumber;
            $error["con_id"] = $motorConversa->con_id;
            $error["error_message"] = $message;
            $error["error_date"] = date("Y-m-d H:i:s");
            $error["invalid_number"] = ($invalid_number ? 1 : 0);

            $this->db->insert(db_prefix() . 'contactcenter_conversation_engine_error', $error);
        }
    }

    public function get_leads_enviados_hoje($con_id)
    {
        $this->db->where('conversation_engine_id', $con_id);
        $this->db->where('conversation_engine_send >=', date("Y-m-d"));
        $this->db->where('status !=', 0);

        return $this->db->get(db_prefix() . 'leads')->num_rows();
    }

    public function updade_lead($data)
    {
        if ($data) {
            $id = $data["lead_id"];
            if ($id && $data["send"]) {
                $up["conversation_engine_send"] = date("Y-m-d H:i:s");
                $up["conversation_engine_id"] = $data["con_id"];
                $up["status"] = $data["status_final"];

                if ($data["status_whats"]) {
                    $up["status_whats"] = $data["status_whats"];
                }

                if ($data["date_whats"]) {
                    $up["date_whats"] = $data["date_whats"];
                }
                
                // Add campaign tag to lead if configured
                if (isset($data["campaign_tag_id"]) && !empty($data["campaign_tag_id"])) {
                    $campaign_tag_id = intval($data["campaign_tag_id"]);
                    if ($campaign_tag_id > 0) {
                        // Check if tag exists
                        $this->db->where('id', $campaign_tag_id);
                        $tag = $this->db->get(db_prefix() . 'tags')->row();
                        
                        if ($tag) {
                            // Check if tag is already assigned to this lead
                            $this->db->where('tag_id', $campaign_tag_id);
                            $this->db->where('rel_id', $id);
                            $this->db->where('rel_type', 'lead');
                            $existing = $this->db->get(db_prefix() . 'taggables')->row();
                            
                            if (!$existing) {
                                // Get max order for this lead
                                $this->db->select_max('tag_order');
                                $this->db->where('rel_id', $id);
                                $this->db->where('rel_type', 'lead');
                                $max_order_result = $this->db->get(db_prefix() . 'taggables')->row();
                                $max_order = $max_order_result && $max_order_result->tag_order ? ($max_order_result->tag_order + 1) : 1;
                                
                                // Insert tag relationship
                                $this->db->insert(db_prefix() . 'taggables', [
                                    'tag_id' => $campaign_tag_id,
                                    'rel_id' => $id,
                                    'rel_type' => 'lead',
                                    'tag_order' => $max_order
                                ]);
                                
                                log_activity("Campaign tag added - Campaign ID: {$data["con_id"]}, Lead ID: {$id}, Tag ID: {$campaign_tag_id}, Tag Name: {$tag->name}", get_staff_user_id());
                            }
                        }
                    }
                }
            }

            if ($data["reply"] && $data["con_id"]) {
                $up["conversation_engine_send_reply"] = date("Y-m-d H:i:s");
                //atualiza o count reply no engine
                $EngineReply = $this->get_conversation_engine($data["con_id"]);
                if ($EngineReply) {
                    $enReply["con_count_reply"] = $EngineReply->con_count_reply + 1;
                    $this->db->where('con_id', $EngineReply->con_id);
                    $this->db->update(db_prefix() . 'contactcenter_conversation_engine', $enReply);
                }
            }
            $this->db->where('id', $id);
            $this->db->update(db_prefix() . 'leads', $up);
        }
    }

    public function rollback_lead($data)
    {
        if ($data) {
            $id = $data["lead_id"];
            if ($id) {
                $up["conversation_engine_send"] = null;
                $up["conversation_engine_id"] = null;
                $up["status"] = $data["status_final"];

                if ($data["status_whats"]) {
                    $up["status_whats"] = $data["status_whats"];
                }

                if ($data["date_whats"]) {
                    $up["date_whats"] = $data["date_whats"];
                }

                $this->db->where('id', $id);
                $this->db->update(db_prefix() . 'leads', $up);
            }
        }
    }

    /**
     * Pega dos leads na fase castral e para enviar msg automatica 
     * @param type $staffid
     * @return type
     */
    public function get_leads_status_cadastrado_staff($staffid, $status, $date, $date_final, $conversation_engine_id, $taggables, $date_filter_type = 'creation_date', $filter_source = null, $filter_city = null, $filter_state = null, $birthday_field = null)
    {
        if (!$staffid) {
            return null;
        }

        // Birthday campaigns: filter leads where custom field day/month matches today
        if ($date_filter_type == 'birthday' && !empty($birthday_field)) {
            $cf_table = db_prefix() . 'customfieldsvalues';
            $cf_field_id = (int) $birthday_field;
            $cf_fieldto = $this->db->escape('leads');
            $sql = "SELECT leads.* 
                FROM " . db_prefix() . "leads as leads
                INNER JOIN {$cf_table} cfv ON cfv.relid = leads.id AND cfv.fieldid = {$cf_field_id} AND cfv.fieldto = {$cf_fieldto}
                WHERE leads.status = {$status} 
                  AND leads.assigned = {$staffid}
                  AND leads.phonenumber != '' 
                  AND cfv.value IS NOT NULL 
                  AND cfv.value != ''
                  AND MONTH(STR_TO_DATE(cfv.value, '%Y-%m-%d')) = MONTH(CURDATE())
                  AND DAY(STR_TO_DATE(cfv.value, '%Y-%m-%d')) = DAY(CURDATE())
                  AND (leads.conversation_engine_id IS NULL OR leads.conversation_engine_id != {$conversation_engine_id})
                  AND (leads.gpt_thread IS NULL OR leads.gpt_thread = '')
                  AND (leads.status_whats IS NULL OR leads.status_whats != 2)";

            // Add source filter
            if ($filter_source && !empty($filter_source)) {
                $sources = explode(',', $filter_source);
                $sources_clean = array_map('intval', $sources);
                $sources_str = implode(',', $sources_clean);
                $sql .= " AND leads.source IN ({$sources_str})";
            }
            if ($filter_city && !empty($filter_city)) {
                $cities = explode(',', $filter_city);
                $cities_escaped = array_map(function($c) { return $this->db->escape(trim($c)); }, $cities);
                $sql .= " AND leads.city IN (" . implode(',', $cities_escaped) . ")";
            }
            if ($filter_state && !empty($filter_state)) {
                $states = explode(',', $filter_state);
                $states_escaped = array_map(function($s) { return $this->db->escape(trim($s)); }, $states);
                $sql .= " AND leads.state IN (" . implode(',', $states_escaped) . ")";
            }
            if ($taggables != null && !empty($taggables)) {
                $sql .= " AND EXISTS (
                    SELECT 1 FROM " . db_prefix() . "taggables AS taggables
                    WHERE taggables.rel_id = leads.id AND taggables.tag_id IN ({$taggables})
                )";
            }
            $sql .= " ORDER BY leads.date_whats ASC LIMIT 1";
            $query = $this->db->query($sql);
            return $query->result();
        }

        // Determine which date field to use
        $date_field = ($date_filter_type == 'last_contact') ? 'lastcontact' : 'dateadded';

        // Consulta SQL base
        $sql = "SELECT * 
            FROM " . db_prefix() . "leads as leads
            WHERE status = {$status} 
              AND assigned = {$staffid}
              AND phonenumber != '' 
              AND {$date_field} >= '{$date}' 
              AND {$date_field} <= '{$date_final}'
              AND (conversation_engine_id IS NULL OR conversation_engine_id != {$conversation_engine_id})
              AND (gpt_thread IS NULL OR gpt_thread = '')
              AND (status_whats IS NULL OR status_whats != 2)";

        // Add source filter
        if ($filter_source && !empty($filter_source)) {
            $sources = explode(',', $filter_source);
            $sources_clean = array_map('intval', $sources);
            $sources_str = implode(',', $sources_clean);
            $sql .= " AND source IN ({$sources_str})";
        }

        // Add city filter
        if ($filter_city && !empty($filter_city)) {
            $cities = explode(',', $filter_city);
            $cities_escaped = array_map(function($city) {
                return $this->db->escape(trim($city));
            }, $cities);
            $cities_str = implode(',', $cities_escaped);
            $sql .= " AND city IN ({$cities_str})";
        }

        // Add state filter
        if ($filter_state && !empty($filter_state)) {
            $states = explode(',', $filter_state);
            $states_escaped = array_map(function($state) {
                return $this->db->escape(trim($state));
            }, $states);
            $states_str = implode(',', $states_escaped);
            $sql .= " AND state IN ({$states_str})";
        }

        // Adiciona a condição de tags se taggables for fornecido
        if ($taggables != null && !empty($taggables)) {
            $sql .= " AND EXISTS (
                    SELECT 1
                    FROM " . db_prefix() . "taggables AS taggables
                    WHERE taggables.rel_id = leads.id
                      AND taggables.tag_id IN ({$taggables})
                  )";
        }

        // Ordenação e Limite
        $sql .= " ORDER BY date_whats ASC LIMIT 1";

        // Executa a consulta SQL
        $query = $this->db->query($sql);

        // Retorna o resultado
        return $query->result();
    }


    public function get_leads_status_cadastrado_staff_taggables($taggables, $leadid)
    {

        //$this->load->database();



        // Monta a consulta SQL
        //$status = get_option("leads_cadastro_engine_contactcenter");
        $sql = "SELECT count(rel_id) as tags_count FROM " . db_prefix() . "taggables 
                WHERE rel_id = {$leadid} 
                AND tag_id IN ({$taggables})";

        // Executa a consulta SQL com os parâmetros
        $query = $this->db->query($sql);
        $result = $query->row(); // Obter a primeira linha do resultado

        if ($result) {
            return $result->tags_count; // Retornar o valor de count(*)
        } else {
            return 0; // Se não houver resultados, retornar 0
        }
    }

    public function filter_leads_by_taggables($Resultleads, $motorConversa)
    {
        if ($motorConversa->tags != null && $motorConversa->tags != "") {
            $filteredLeads = [];

            foreach ($Resultleads as $lead) {
                $count = 0;

                $count = $this->get_leads_status_cadastrado_staff_taggables($motorConversa->tags, $lead->id);
                if ($count > 0) {
                    $filteredLeads[] = $lead;
                }
            }
            return $filteredLeads;
        }
        return $Resultleads;
    }

