   public function extrairNumero($decodedData)
    {
        $key = $decodedData["data"]["key"];

        // 1️⃣ PRIMEIRO: procurar @s.whatsapp.net em remoteJid ou remoteJidAlt (prioridade igual)
        $camposPrincipais = [
            $key["remoteJid"]     ?? null,
            $key["remoteJidAlt"]  ?? null,
        ];

        foreach ($camposPrincipais as $campo) {
            if (!empty($campo) && str_ends_with($campo, "@s.whatsapp.net")) {
                if (preg_match('/(\d{6,})/', $campo, $m)) {
                    return $m[0];
                }
            }
        }

        // 2️⃣ SEGUNDO: procurar @s.whatsapp.net em outros campos
        $outrosCampos = [
            $key["participant"]   ?? null,
            $key["senderPn"]      ?? null,
        ];

        foreach ($outrosCampos as $campo) {
            if (!empty($campo) && str_ends_with($campo, "@s.whatsapp.net")) {
                if (preg_match('/(\d{6,})/', $campo, $m)) {
                    return $m[0];
                }
            }
        }

        // 3️⃣ TERCEIRO: se não tiver @s.whatsapp.net, verificar @g.us (grupos)
        if (!empty($key["remoteJid"]) && str_ends_with($key["remoteJid"], "@g.us")) {
            if (preg_match('/(\d{6,})/', $key["remoteJid"], $m)) {
                return $m[0];
            }
        }

        // 4️⃣ ÚLTIMO: pegar o primeiro número válido de qualquer campo (exceto @lid)
        $todosCampos = [
            $key["remoteJid"]     ?? null,
            $key["remoteJidAlt"]  ?? null,
            $key["participant"]   ?? null,
            $key["senderPn"]      ?? null,
        ];

        foreach ($todosCampos as $campo) {
            if (!empty($campo) && !str_ends_with($campo, "@lid")) {
                if (preg_match('/(\d{6,})/', $campo, $m)) {
                    return $m[0];
                }
            }
        }

        return null;
    }


    /**
     * Insert do dando que vem do socket e webhook
     * @param type $data
     * @return bool
     */
    public function insert_webhook($data)
    {

        $decodedData = json_decode($data, true);
        if ($decodedData) {
            $this->get_webhook_evolution_axiom($decodedData);
        }
    }



    public function get_webhook_evolution_axiom($decodedData)
    {
        //msg enviada
        if ($decodedData["event"] == "messages.upsert" || $decodedData["event"] == "send.message" || $decodedData["event"] == "messages.set") {

            $msg_date = date('Y-m-d H:i:s', ($decodedData["data"]["messageTimestamp"]["low"] ? $decodedData["data"]["messageTimestamp"]["low"] : $decodedData["data"]["messageTimestamp"]));

            preg_match('/(\d+)/', $decodedData["sender"], $matches);
            $numero_sender = $matches[0];

            //verifica se é grupo ou individual
            if (str_ends_with($decodedData["data"]["key"]["remoteJid"], '@g.us')) {
                $isGroupMsg = true;
                $groupId = str_replace('@g.us', '', $decodedData["data"]["key"]["remoteJid"]);

                if ($decodedData["data"]["key"]["fromMe"] == true) {
                    $numero_telefone = $numero_sender;
                } else {
                    //limpa o numero do telefone
                    preg_match('/(\d+)/', $decodedData["data"]["key"]["participant"], $matches);
                    $numero_telefone = $matches[0];
                }
            } else if (str_ends_with($decodedData["data"]["key"]["remoteJid"], '@lid')) {
                $isGroupMsg = false;
                $groupId = null;

                
                //limpa o numero do telefone
               // preg_match('/(\d+)/', $decodedData["data"]["key"]["senderPn"], $matches);
                $numero_telefone =$this->extrairNumero($decodedData);
            } else {
                $isGroupMsg = false;
                $groupId = null;

                //limpa o numero do telefone
                //preg_match('/(\d+)/', $decodedData["data"]["key"]["remoteJid"], $matches);
                $numero_telefone = $this->extrairNumero($decodedData);;
            }





            $fromMe =  $decodedData["data"]["key"]["id"];
            // Normalize fromMe to integer (0 or 1) for consistent comparison
            $msg_fromMe = isset($decodedData["data"]["key"]["fromMe"]) ? (intval($decodedData["data"]["key"]["fromMe"]) ? 1 : 0) : 0;
            $data = array(
                "msg_wook" => $decodedData["event"],
                "msg_fromMe" => $msg_fromMe,
                "msg_send_id" => $fromMe,
                "msg_session" => $decodedData["apikey"],
                "msg_isGroupMsg" => ($isGroupMsg ? 1 : 0),
                "msg_name" => $decodedData["data"]["pushName"],
                "msg_to" => ($decodedData["data"]["key"]["fromMe"] ? $numero_telefone : $numero_sender),
                "msg_from" => ($decodedData["data"]["key"]["fromMe"] ? $numero_sender : $numero_telefone),
                "msg_content" => ($decodedData["data"]["message"]["conversation"] ? $decodedData["data"]["message"]["conversation"] : $decodedData["data"]["message"]["extendedTextMessage"]["text"]),
                "msg_date" => $msg_date,
                "msg_status" =>  $decodedData["data"]["status"],
                "remoteJid" =>  $decodedData["data"]["key"]["remoteJid"]
            );

            $data["msg_conversation_number"] = $data["msg_from"];
            if ($data["msg_fromMe"] == 1) {
                $data["msg_conversation_number"] = $data["msg_to"];
            }

            //se for grupo adiciona o grupo ao numero de contato
            if ($isGroupMsg && $groupId) {
                $data["msg_conversation_number"] = $groupId;
            } else {
                // Se não for grupo, valida se é um número de telefone válido (10 a 15 dígitos numéricos)
                if (preg_match('/^\d{10,15}$/', $data["msg_conversation_number"])) {
                    // ok, número válido, mantém
                } else {
                    // Número inválido, retorna false
                    return false;
                }
            }


            //pega as mensagem marcadas 
            if ($decodedData["data"]["contextInfo"]) {

                //pega os dados do contatos no banco
                preg_match('/(\d+)/', $decodedData["data"]["contextInfo"]["participant"], $matches);
                $numero_participant = $matches[0];

                $this->db->where('phonenumber', $numero_participant);
                $registro = $this->db->get(db_prefix() . 'contactcenter_contact')->row();
                if ($registro && $registro->name) {
                    $data["reply_participant"] = $registro->name;
                } else {
                    $data["reply_participant"] = $numero_participant;
                }

                //limita a contidade de caracteres              
                $data["reply_msg"] = ($decodedData["data"]["contextInfo"]["quotedMessage"]["conversation"] ? substr($decodedData["data"]["contextInfo"]["quotedMessage"]["conversation"], 0, 100) : substr($decodedData["data"]["contextInfo"]["quotedMessage"]["extendedTextMessage"]["text"], 0, 100));
                $data["reply_id"] = $decodedData["data"]["contextInfo"]["stanzaId"];
            }



            //lista de mensagens
            if ($decodedData["data"]["message"]["listMessage"]) {
                $data["msg_content"] = $decodedData["data"]["message"]["listMessage"]["title"] . " - " . $decodedData["data"]["message"]["listMessage"]["description"];
                $data["msg_type"] = "text";
            }
            if ($decodedData["data"]["message"]["listResponseMessage"]) {
                $data["msg_content"] = $decodedData["data"]["message"]["listResponseMessage"]["title"];
                $data["msg_type"] = "text";
            }

            if ($decodedData["data"]["messageType"] == "audioMessage") {

                // busco device pelo token
                $device = $this->get_device_token($decodedData["apikey"]);
                // busco server
                $server = $this->get_server($device->server_id);
                // monto a url
                $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;
                //pega a media
                $media = $this->axiom_evolution->get_media_evolution_base64($url, $decodedData["data"]["key"]["id"], $decodedData["apikey"]);

                // convertendo para audio
                $audio = $this->convert_base64_audio_webhook($media["base64"]);

                // convertendo para mp3
                $convertMp3 = $this->api_convert_type_audio(site_url("{$audio}"));

                if ($convertMp3["url"]) {
                    //excluindo o audio convertido
                    unlink(FCPATH . $audio);
                    //faz o download do audio
                    $data["msg_base64"] = $this->save_audio_from_url($convertMp3["url"]);
                } else {
                    log_activity('Erro ao converter audio api axiom (get_webhook_evolution_axiom)');
                }
                $data["msg_type"] = "ptt";
                // $data["msg_base64"] = "data:audio/ogg; codecs=opus;base64," . $media["base64"];
            }
            if ($decodedData["data"]["messageType"] == "imageMessage") {

                if ($decodedData["data"]["message"]["base64"] != null) {
                    $data["msg_base64"] = "data:image/jpeg;base64," . $decodedData["data"]["message"]["base64"];
                    $data["msg_type"] = "image";
                    $data["msg_url"] = contactcenter_base64ToFile($data["msg_base64"], "contactcenter/messages");
                } else {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);

                    // busco server
                    $server = $this->get_server($device->server_id);


                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $decodedData["data"]["key"]["id"], $decodedData["apikey"]);
                    $data["msg_base64"] = "data:image/jpeg;base64," . $media["base64"];
                    $data["msg_type"] = "image";
                }

                if ($decodedData["data"]["message"]["imageMessage"]["caption"]) {
                    $data["msg_content"] = $decodedData["data"]["message"]["imageMessage"]["caption"];
                }

                if ($decodedData["data"]["message"]["imageMessage"]["jpegThumbnail"]) {
                    $data["msg_thumb"] = "data:image/jpeg;base64," . $decodedData["data"]["message"]["imageMessage"]["jpegThumbnail"];
                }
            }
            if ($decodedData["data"]["messageType"] == "documentMessage") {

                if ($decodedData["data"]["message"]["documentMessage"]["mimetype"] == "application/pdf") {

                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);

                    // busco server
                    $server = $this->get_server($device->server_id);

                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $decodedData["data"]["key"]["id"], $decodedData["apikey"]);
                    $data["msg_base64"] = "data:application/pdf;base64," . $media["base64"];

                    if ($decodedData["data"]["message"]["documentMessage"]["jpegThumbnail"]) {
                        $data["msg_thumb"] = "data:image/jpeg;base64," . $decodedData["data"]["message"]["documentMessage"]["jpegThumbnail"];
                    }

                    $data["msg_type"] = "documentPDF";
                    $data["msg_content"] = ($decodedData["data"]["message"]["documentMessage"]["caption"] ? $decodedData["data"]["message"]["documentMessage"]["caption"] : $decodedData["data"]["message"]["documentMessage"]["title"]);
                } else if ($decodedData["data"]["message"]["documentMessage"]["mimetype"] == "application/zip") {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $decodedData["data"]["key"]["id"], $decodedData["apikey"]);
                    $data["msg_base64"] = "data:application/zip;base64," . $media["base64"];
                    $data["msg_type"] = "documentZIP";
                    $data["msg_content"] = ($decodedData["data"]["message"]["documentMessage"]["caption"] ? $decodedData["data"]["message"]["documentMessage"]["caption"] : "Arquivo ZIP");
                } else if ($decodedData["data"]["message"]["documentMessage"]["mimetype"] == "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $decodedData["data"]["key"]["id"], $decodedData["apikey"]);
                    $data["msg_base64"] = "data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64," . $media["base64"];
                    $data["msg_type"] = "documentXLSX";
                    $data["msg_content"] = ($decodedData["data"]["message"]["documentMessage"]["caption"] ? $decodedData["data"]["message"]["documentMessage"]["caption"] : "Arquivo XLSX");
                } else if ($decodedData["data"]["message"]["documentMessage"]["mimetype"] == "application/vnd.openxmlformats-officedocument.wordprocessingml.document") {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $decodedData["data"]["key"]["id"], $decodedData["apikey"]);
                    $data["msg_base64"] = "data:application/vnd.openxmlformats-officedocument.wordprocessingml.document;base64," . $media["base64"];
                    $data["msg_type"] = "documentDOCX";
                    $data["msg_content"] = ($decodedData["data"]["message"]["documentMessage"]["caption"] ? $decodedData["data"]["message"]["documentMessage"]["caption"] : "Arquivo DOCX");
                }


                //transforma o base64 em arquivo
                if ($data["msg_base64"] && $data["msg_type"] != "ptt") {
                    $data["msg_url"] = contactcenter_base64ToFile($data["msg_base64"], "contactcenter/messages");
                }
            }
            if ($decodedData["data"]["messageType"] == "videoMessage") {
                $data["msg_type"] = "video";
            }
            if ($decodedData["data"]["messageType"] == "conversation" || $decodedData["data"]["messageType"] == "extendedTextMessage") {
                $data["msg_type"] = "text";
            }


            //verifica se é mgs editada troca o id para o id da msg original
            if ($decodedData["data"]["message"]["editedMessage"]["message"]["protocolMessage"]["key"]["id"]) {
                $fromMe = $decodedData["data"]["message"]["editedMessage"]["message"]["protocolMessage"]["key"]["id"];
                $data["msg_type"] = "text";
            }


            // se msgtype for null ou vazio, nao salva
            if ($data["msg_type"] == null || $data["msg_type"] == "") {
                return false;
            }

            //verifica se já tem o registo
            $this->db->where('msg_send_id', $fromMe);
            $registro = $this->db->get(db_prefix() . 'contactcenter_message')->row();
            if (!$registro) {
                $this->db->insert(db_prefix() . 'contactcenter_message', $data);
                $insert_id = $this->db->insert_id();
                if ($insert_id) {
                    $data["msg_id"] = $insert_id;

                    $this->update_lead_lastcontact_by_phone($data['msg_conversation_number'] ?? '');

                    //Pega o staffid do da session
                    $device = $this->get_device_token($decodedData["apikey"]);
                    if ($device->staffid) {
                        $data["staffid"] = $device->staffid;
                    } else {
                        $data["staffid"] = 0;
                    }

                    $data["campanha"] = $device->dev_number;

                    //Faz o isert do lead
                    $lead = $this->insert_leads_whatsapp($data);
                    
                    // Kill Switch: If message is from lead (not fromMe), exclude from active campaigns
                    if ($data["msg_fromMe"] == 0 && $lead && isset($lead->id) && isset($device->dev_id)) {
                        // Find all active campaigns for this device that have stop_on_reply enabled
                        $this->db->where('status', 1);
                        $this->db->where('device_id', $device->dev_id);
                        $this->db->where('stop_on_reply', 1);
                        $active_campaigns = $this->db->get(db_prefix() . 'contactcenter_leads_engine')->result();
                        
                        foreach ($active_campaigns as $campaign) {
                            // Exclude lead from campaign
                            $this->exclude_lead_from_campaign($campaign->id, $lead->id, 'reply_received');
                        }
                    }

                    if ($lead) {
                        $data["leadid"] = $lead->id;
                        $data["client_id"] = $lead->client_id;
                        $data["assigned"] = $lead->assigned;                       
                        
                        
                        // Check and execute message triggers if message has content
                        if (!empty($data["msg_content"])) {
                            // Normalize msg_fromMe to integer for consistent comparison (0 = contact, 1 = staff)
                            $msg_fromMe_normalized = isset($data["msg_fromMe"]) ? intval($data["msg_fromMe"]) : 0;
                            $is_from_staff = $msg_fromMe_normalized == 1;
                            
                            log_activity("TRIGGER CALL - Lead ID: {$lead->id}, Message from staff: " . ($is_from_staff ? 'yes' : 'no') . ", msg_fromMe (raw): " . var_export($data["msg_fromMe"], true) . ", msg_fromMe (normalized): {$msg_fromMe_normalized}, Content: " . substr($data["msg_content"], 0, 50), get_staff_user_id());
                            
                            // Check if this is the first message from this lead (only for contact messages)
                            $is_first_message = false;
                            if (!$is_from_staff) {
                                $is_first_message = $this->is_first_message_from_lead($lead->id, $data["msg_from"]);
                                log_activity("TRIGGER CALL - Is first message: " . ($is_first_message ? 'yes' : 'no'), get_staff_user_id());
                            }
                            
                            // Execute triggers (will filter by message_sender_type internally)
                            $this->check_and_execute_triggers($lead->id, $data["msg_content"], $is_first_message, $is_from_staff);
                        } else {
                            log_activity("TRIGGER SKIP - Lead ID: {$lead->id}, Reason: Empty message content", get_staff_user_id());
                        }


                        if ($device->dev_openai == 1 || $device->dev_openai == 2) {
                            // Refresh lead data to get latest gpt_status (in case it was updated by toggle)
                            // Use flush_cache to ensure we get fresh data from database (no caching)
                            $this->db->flush_cache();
                            $this->db->where('id', $lead->id);
                            $leadFresh = $this->db->get(db_prefix() . 'leads')->row();
                            
                            // Log for debugging - check what gpt_status we have
                            if ($leadFresh) {
                                log_message('debug', "Webhook AI Check - Lead ID: {$leadFresh->id}, Phone: " . ($data['msg_from'] ?? 'N/A') . ", gpt_status: {$leadFresh->gpt_status}, will process: " . ($leadFresh->gpt_status == 0 ? 'YES' : 'NO'));
                                log_activity("Webhook AI Check - Lead ID: {$leadFresh->id}, Phone: " . ($data['msg_from'] ?? 'N/A') . ", gpt_status: {$leadFresh->gpt_status}, will process: " . ($leadFresh->gpt_status == 0 ? 'YES' : 'NO'), get_staff_user_id());
                            } else {
                                log_message('error', "Webhook AI Check ERROR - Lead not found! Lead ID: {$lead->id}");
                                log_activity("Webhook AI Check ERROR - Lead not found! Lead ID: {$lead->id}", get_staff_user_id());
                            }
                            
                            // Only process AI if gpt_status == 0 (AI is ON)
                            // gpt_status == 1 means AI is OFF, so skip processing
                            if ($leadFresh && $leadFresh->gpt_status == 0) {
                                $data["leadid"] = $leadFresh->id;
                                $data["lead_name"] = $leadFresh->name;
                                $data["lead_status"] = $leadFresh->status;


                                if ($data["msg_type"] == "ptt") {
                                    //$Urlaudio = $this->convert_base64_audio($data["msg_base64"]);
                                    $texto = $this->create_transcription($data["msg_base64"]);
                                    $data["msg_content"] = $texto;
                                    $data["ia_type"] = 1;
                                } elseif ($data["msg_type"] == "image") {
                                    $data["ia_type"] = 2;
                                } else {
                                    $data["ia_type"] = 0;
                                }

                                $block = $this->block_chatboot($data);

                                // Pega o dia atual (0 para domingo, 6 para sábado)
                                $day = date('w', strtotime($data["msg_date"]));

                                // Obtém a data atual no formato Y-m-d (para garantir que usamos a mesma data para todas as comparações)
                                $dataAtual = date("Y-m-d");

                                // Pega o horário atual como timestamp, incluindo a data
                                $horaAtual = strtotime($dataAtual . ' ' . date("H:i"));

                                // Pega os horários de atendimento
                                $timerDevice = json_decode($device->timer_ia);
                                $startValue = isset($timerDevice->$day->start) ? $timerDevice->$day->start : '';
                                $endValue = isset($timerDevice->$day->end) ? $timerDevice->$day->end : '';

                                if ($startValue != '' && $endValue != '') {
                                    // Converte os horários de atendimento para timestamps, incluindo a data atual
                                    $startTimestamp = strtotime($dataAtual . ' ' . $startValue);
                                    $endTimestamp = strtotime($dataAtual . ' ' . $endValue);

                                    // Verifica se está dentro do horário de atendimento
                                    if ($horaAtual >= $startTimestamp && $horaAtual <= $endTimestamp) {
                                        $block = false;
                                    } else {
                                        // Se estiver fora do horário de atendimento, bloqueia
                                        $block = true;
                                    }
                                }


                                if (!$block) {
                                    if ($device->dev_openai == 1) {
                                        if (get_option('openai_speed_send')) {
                                            $this->speed_send_msg_openai($data);
                                        } else {
                                            $this->insert_msg_cron_ia($data);
                                        }
                                    } elseif ($device->dev_openai == 2) {
                                        $this->chatbot->get_chatbot($data, $device->chatbot_id);
                                    }
                                }
                            }
                        }

                        //confirmação de agendamento de atendimento
                        if ($decodedData["data"]["message"]["listResponseMessage"]) {
                            $data["selectedRowId"] = $decodedData["data"]["message"]["listResponseMessage"]["singleSelectReply"]["selectedRowId"];
                            $this->confirm_agendamento($data);
                        }
                        
                        // Handle text message responses for meeting confirmations (fallback when list message fails)
                        // Check if message content matches confirmation/cancellation keywords
                        if (isset($data["msg_content"]) && !empty($data["msg_content"])) {
                            $msg_content_clean = trim(strtolower($data["msg_content"]));
                            
                            // Keywords for confirmation
                            $confirm_keywords = ['sim', 'yes', 'confirmo', 'confirmar', 'ok', 'confirmado', 'aceito', 'aceitar'];
                            // Keywords for cancellation
                            $cancel_keywords = ['cancelar', 'cancel', 'cancelado', 'não', 'nao', 'no', 'desmarcar', 'desmarcado'];
                            
                            $is_confirm = false;
                            $is_cancel = false;
                            
                            // Check if message matches confirmation keywords
                            foreach ($confirm_keywords as $keyword) {
                                if (strpos($msg_content_clean, $keyword) !== false) {
                                    $is_confirm = true;
                                    break;
                                }
                            }
                            
                            // Check if message matches cancellation keywords
                            if (!$is_confirm) {
                                foreach ($cancel_keywords as $keyword) {
                                    if (strpos($msg_content_clean, $keyword) !== false) {
                                        $is_cancel = true;
                                        break;
                                    }
                                }
                            }
                            
                            // If message matches confirmation or cancellation keywords, try to find the event
                            if ($is_confirm || $is_cancel) {
                                // IMPORTANT: Only process if a confirmation message was recently sent to this phone number
                                // This prevents false positives when keywords are sent before confirmation
                                $phone_clean = preg_replace('/\D/', '', $data["msg_conversation_number"]);
                                
                                // Check if a confirmation message was sent to this number recently (within last 6 hours)
                                $confirmation_title = _l("contac_notification_title_whats_list"); // "Confirmação de agendamento"
                                $confirmation_desc_keyword = _l("contac_notification_description_whats_list"); // "Lembramos que você possui um agendamento"
                                
                                // Try to match by conversation number (exact match)
                                $this->db->select('msg_id, msg_date, msg_content');
                                $this->db->from(db_prefix() . 'contactcenter_message');
                                $this->db->where('msg_fromMe', 1); // Sent FROM system
                                $this->db->where('msg_conversation_number', $data["msg_conversation_number"]);
                                $this->db->group_start();
                                $this->db->like('msg_content', $confirmation_title); // Contains "Confirmação de agendamento"
                                if (!empty($confirmation_desc_keyword) && $confirmation_desc_keyword != "contac_notification_description_whats_list") {
                                    $this->db->or_like('msg_content', $confirmation_desc_keyword); // Contains "Lembramos que você possui um agendamento"
                                }
                                // Also check for text fallback keywords
                                $this->db->or_like('msg_content', 'Evento começa hoje'); // Text fallback keyword
                                $this->db->or_like('msg_content', 'agendamento'); // Generic keyword
                                $this->db->group_end();
                                $this->db->where('msg_date >=', date('Y-m-d H:i:s', strtotime('-6 hours')));
                                $this->db->order_by('msg_date', 'DESC');
                                $this->db->limit(1);
                                
                                $recent_confirmation = $this->db->get()->row();
                                
                                // Log the check result for debugging
                                if (!$recent_confirmation) {
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE CHECK - No recent confirmation found for phone: {$phone_clean}, conversation_number: {$data['msg_conversation_number']}, searching last 6 hours", get_staff_user_id());
                                } else {
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE CHECK - Recent confirmation found - msg_id: {$recent_confirmation->msg_id}, date: {$recent_confirmation->msg_date}", get_staff_user_id());
                                }
                                
                                // Only proceed if a confirmation was sent recently (within last 6 hours)
                                if (!$recent_confirmation) {
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE IGNORED - No recent confirmation sent - Phone: {$phone_clean}, Response: " . ($is_confirm ? 'confirm' : 'cancel') . " - Message will be processed normally", get_staff_user_id());
                                    // Don't process keywords as confirmation - message will be handled by AI/normal flow
                                    // Continue execution to allow normal message processing
                                    $is_confirm = false;
                                    $is_cancel = false;
                                }
                                
                                // Try to find event by checking events for leads/customers with this phone number
                                // Check for events that are starting soon (within next few hours) - most likely the one they're confirming
                                // Don't require notifyWhatsapp=1 because text fallback might not have updated it
                                $this->db->select('e.eventid, e.rel_type, e.rel_id, e.userid, e.start, e.notifyWhatsapp');
                                $this->db->from(db_prefix() . 'events e');
                                $this->db->join(
                                    db_prefix() . 'leads l',
                                    'l.id = e.rel_id AND e.rel_type = "lead"',
                                    'left'
                                );

                                $this->db->where(
                                    'REPLACE(REPLACE(REPLACE(REPLACE(COALESCE(l.phonenumber, ""), " ", ""), "-", ""), "(", ""), ")", "") =',
                                    $phone_clean,
                                    false
                                );

                                $this->db->where('e.status', 1);
                                $this->db->where('e.start >=', date('Y-m-d H:i:s', strtotime('-1 hour')));
                                $this->db->where('e.start <=', date('Y-m-d H:i:s', strtotime('+6 hours')));
                                $this->db->order_by('e.start', 'ASC');
                                $this->db->limit(1);

                                
                                $event = $this->db->get()->row();
                                
                                // If not found in leads, try customers
                                if (!$event) {
                                $this->db->select('e.eventid, e.rel_type, e.rel_id, e.userid, e.start, e.notifyWhatsapp');
                                $this->db->from(db_prefix() . 'events e');
                                $this->db->join(
                                    db_prefix() . 'clients c',
                                    'c.userid = e.rel_id AND e.rel_type = "customer"',
                                    'left'
                                );

                                $this->db->where(
                                    'REPLACE(REPLACE(REPLACE(REPLACE(COALESCE(c.phonenumber, ""), " ", ""), "-", ""), "(", ""), ")", "") =',
                                    $phone_clean,
                                    false
                                );

                                $this->db->where('e.status', 1);
                                $this->db->where('e.start >=', date('Y-m-d H:i:s', strtotime('-1 hour')));
                                $this->db->where('e.start <=', date('Y-m-d H:i:s', strtotime('+6 hours')));
                                $this->db->order_by('e.start', 'ASC');
                                $this->db->limit(1);

                                $event = $this->db->get()->row();

                                }
                                
                                // Process if a confirmation was recently sent, OR if we found an event that was recently notified
                                // This handles cases where the message wasn't stored in DB yet or format mismatch
                                $should_process = false;
                                if (isset($recent_confirmation) && $recent_confirmation) {
                                    $should_process = true;
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE - Recent confirmation message found, proceeding", get_staff_user_id());
                                } elseif (isset($event) && $event) {
                                    // Even if we didn't find the confirmation message, if we found a recently notified event,
                                    // it's likely a response to that confirmation (message might not be in DB yet or format mismatch)
                                    $should_process = true;
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE - No confirmation message found but event found with notifyWhatsapp=1, proceeding anyway - Event ID: {$event->eventid}", get_staff_user_id());
                                }
                                
                                if ($should_process && isset($event) && $event) {
                                    // Construct selectedRowId in the same format as list message responses
                                    $resposta = $is_confirm ? 'yes' : 'cancel';
                                    $data["selectedRowId"] = "{$resposta}-{$event->eventid}-agendamento";
                                    $data["msg_conversation_number"] = $data["msg_conversation_number"]; // Keep original phone number
                                    
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE DETECTED - Event ID: {$event->eventid}, Phone: {$phone_clean}, Response: " . ($is_confirm ? 'confirm' : 'cancel'), get_staff_user_id());
                                    
                                    // Process the confirmation using the existing function
                                    $this->confirm_agendamento($data);
                                } elseif (!$should_process) {
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE IGNORED - No recent confirmation and no event found - Phone: {$phone_clean}, Response: " . ($is_confirm ? 'confirm' : 'cancel'), get_staff_user_id());
                                } elseif (!isset($event) || !$event) {
                                    log_activity("cron_confirm_agendamento TEXT RESPONSE NO EVENT FOUND - Phone: {$phone_clean}, Response: " . ($is_confirm ? 'confirm' : 'cancel'), get_staff_user_id());
                                }
                            }
                        }

                        //faz o Analytics do meta facebook/instagram
                        if ($decodedData["data"]["contextInfo"]) {
                            $this->insert_analytics_meta($data, $decodedData["data"]);
                        }
                    }

                    // faz i insert do contact
                    $contact = $this->insert_contact($data);

                    return true;
                }
                return true;
            } else {
                //atuliza a msg editada

                if ($decodedData["data"]["message"]["editedMessage"]) {
                    $updateData = array(
                        "msg_content" => $decodedData["data"]["message"]["editedMessage"]["message"]["protocolMessage"]["editedMessage"]["conversation"],
                        "msg_status" => "MESSAGE_EDIT",
                    );

                    $this->db->where('msg_send_id', $decodedData["data"]["message"]["editedMessage"]["message"]["protocolMessage"]["key"]["id"]);
                    $this->db->update(db_prefix() . 'contactcenter_message', $updateData);
                }
            }

            return ["sucess" => 200];
        } else if ($decodedData["event"] == "qrcode.updated") {

            // $Qrcode = $decodedData["data"]["qrcode"]["base64"];

            // $CI = &get_instance();
            // $CI->load->library('app_pusher');

            // $tamanho_chunk = 6000;
            // $chunks = str_split($Qrcode, $tamanho_chunk);

            // $count = count($chunks);
            // foreach ($chunks as $index => $chunk) {
            //     $is_last = ($index == $count - 1); // Verifica se este é o último chunk
            //     $qr = array('message' => $chunk, 'is_last' => $is_last);
            //     $CI->app_pusher->trigger($decodedData["apikey"], 'qrcode', $qr);
            // }           

            return ["sucess" => 200];
        } else if ($decodedData["event"] == "connection.update") {
            $session = $decodedData["apikey"];
            $status = $decodedData["data"]["state"];

            // valido se existe device com essa session
            $device = $this->get_device_token($session);
            if ($device) {
                $data = [];
                if ($device->api_local != 1) {
                    $data["api_web_status"] = $status;
                    $data["status"] = $status;
                    $data["last_status"] = date("Y-m-d H:i:s");
                    $this->db->where('dev_token', $session);
                    $this->db->update(db_prefix() . 'contactcenter_device', $data);
                }
            }

            return ["success" => 200];
        } else if ($decodedData["event"] == "contacts.update") {
            //limpa o numero do telefone
            preg_match('/(\d+)/', $decodedData["data"]["remoteJid"], $matches);
            $numero_telefone = $matches[0];


            $UpdadeLead = [
                "thumb" => ($decodedData["data"]["profilePicUrl"] ? $decodedData["data"]["profilePicUrl"] : null),
            ];
            $this->db->where('phonenumber', $numero_telefone);
            $this->db->update(db_prefix() . 'contactcenter_contact', $UpdadeLead);
        } else if ($decodedData["event"] == "messages_delete") {


            //pega a mensagem
            $this->db->where('msg_send_id', $decodedData["data"]["id"]);
            $registro = $this->db->get(db_prefix() . 'contactcenter_message')->row();
            if ($registro) {


                $msg_date = date('Y-m-d H:i:s', $decodedData["data"]["messageTimestamp"]);
                $UpdadeMsg = [
                    "msg_status" => " DELIVERY_DELETE",
                    "msg_date_update" => $msg_date,
                ];
                $this->db->where('msg_send_id', $registro->msg_send_id);
                $this->db->update(db_prefix() . 'contactcenter_message', $UpdadeMsg);
            }
        } else if ($decodedData["event"] == "messages.update") {
            $UpdadeMsg = [
                "msg_status" => $decodedData["data"]["status"],
            ];
            $this->db->where('msg_send_id', $decodedData["data"]["keyId"]);
            $this->db->update(db_prefix() . 'contactcenter_message', $UpdadeMsg);
        }
    }



    public function speed_send_msg_openai($data)
    {

        if ($data["msg_fromMe"] == 0 && $data["msg_isGroupMsg"] == 0) {
            $device = $this->get_device_token($data["msg_session"]);

            // recupero o token do assistente             
            $assistant = $this->get_assistants_ai($device->assistant_ai_id);
            if ($assistant) {
                $assistant_token = $assistant->ai_token;
            }
            $model_assitente = $this->get_assistente_model_openai($assistant_token);

            //pega o dados do cadastro do Lead
            $lead = $this->get_leads($data["leadid"]);
            
            // Refresh lead data to ensure we have latest gpt_status
            if ($lead && isset($lead->id)) {
                $this->db->flush_cache();
                $this->db->where('id', $lead->id);
                $lead = $this->db->get(db_prefix() . 'leads')->row();
            }
            
            // Check gpt_status - if AI is disabled for this lead, don't process
            // gpt_status == 1 means AI is OFF, gpt_status == 0 means AI is ON
            if (!$lead || $lead->gpt_status == 1) {
                log_message('debug', "speed_send_msg_openai SKIP - AI disabled for lead ID: " . ($data["leadid"] ?? 'unknown') . ", gpt_status: " . ($lead->gpt_status ?? 'null'));
                log_activity("speed_send_msg_openai SKIP - AI disabled for lead ID: " . ($data["leadid"] ?? 'unknown') . ", gpt_status: " . ($lead->gpt_status ?? 'null'), get_staff_user_id());
                return false;
            }

            if ($data["ia_type"] == 2) {

                if ($model_assitente["model"] == "gpt-3.5-turbo" || $model_assitente["model"] == "gpt-3.5-turbo-1106") {

                    $dataError = [
                        "device_id" => $device->dev_id,
                        "lead_id" => ($lead ? $lead->id : null),
                        "device_token" => $device->dev_token,
                        "model" => $model_assitente["model"],
                        "error" => "Modelo não suporta imagens"
                    ];

                    // salvo o erro na activity log
                    log_activity("Erro na requisição send_msg_openai image: " . json_encode($dataError), get_staff_user_id());
                    return false;
                }
                $dateTime = date("Y-m-d H:i:s");

                $this->db->where("msg_id", $data["msg_id"]);
                $image = $this->db->get(db_prefix() . 'contactcenter_message')->row();
                if ($image->msg_base64) {
                    $path = $this->convert_base64_image($image->msg_base64);
                    $url = site_url($path);

                    $contents[] = [
                        "type" => "image_url",
                        "image_url" => [
                            "url" => $url
                        ],

                    ];

                    // Adiciona o conteúdo de texto, se existir
                    if ($data["msg_content"] != null && $data["msg_content"] != "") {

                        $contents[] = [
                            "type" => "text",
                            "text" => $data["msg_content"]
                        ];
                    }
                }
            }

            if ($data["ia_type"]  == 0 || $data["ia_type"]  == 1) {
                if ($data["msg_content"] != null && $data["msg_content"] != "") {

                    $contents[] = [
                        "type" => "text",
                        "text" => $data["msg_content"]
                    ];
                }
            }
            $typeAudio = $data["ia_type"];

            $contentsMSG = $contents;


            if ($lead) {
                //Inicia a conversa com a OpenAI
                if ($device->dev_openai == 1 || $device->dev_openai == 2) {
                    // Refresh lead data to get latest gpt_status (in case it was updated by toggle)
                    $this->db->where('id', $lead->id);
                    $leadFresh = $this->db->get(db_prefix() . 'leads')->row();
                    
                    if ($leadFresh && $leadFresh->gpt_status == 0) {
                        //Verifica se tem historico se não tiver cria 
                        $thread = $this->thread_lead($leadFresh->id, $assistant_token, $model_assitente["model"]);


                        // chucnk de $contentsMSG to maximo 10
                        $finalContent = array_chunk($contentsMSG, 10);
                        $sends = [];
                        foreach ($finalContent as $contents) {

                            $send = $this->send_msg_openai($thread, $contents, $device->dev_id, $leadFresh->id, $device->dev_token, $model_assitente["model"]);

                            // sleep(3);
                            $sends[] = $send;
                        }



                        // se algum $sends for false nao entra
                        if (!in_array(false, $sends)) {
                            // Apaga as imagens geradas   
                            if (isset($path) && file_exists($path)) {
                                unlink(FCPATH . $path);
                            }

                            //Pega a mgs e envia para o lead
                            $result = $this->reply_send_openai($thread, $leadFresh->phonenumber, $data["staffid"], $assistant_token, $typeAudio, $device->dev_id, $leadFresh->id, $device->dev_token, $model_assitente["model"]);
                        }
                    } elseif ($leadFresh && $leadFresh->gpt_status == 1) {
                        // Apaga as imagens geradas                        
                        if (isset($path) && file_exists($path)) {
                            unlink(FCPATH . $path);
                        }
                    }
                }
            } else {
                // Apaga as imagens geradas               
                if (isset($path) && file_exists($path)) {
                    unlink(FCPATH . $path);
                }
            }
        }
    }



    /**
     * Sincroniza os dados do webhook do whatsapp para o historico
     */
    public function insert_historico_webhook($json)
    {
        $decodedData = json_decode($json, true);

        if ($decodedData["event"] == "messages.set") {

            foreach ($decodedData["data"] as $historic) {
                $msg_date = date('Y-m-d H:i:s', $historic['messageTimestamp']);

                //verifica se é grupo ou individual
                if (str_ends_with($historic["key"]["remoteJid"], '@g.us')) {
                    $isGroupMsg = true;
                } else {
                    $isGroupMsg = false;
                }

                //se for grupo pula
                if ($isGroupMsg) {
                    continue;
                }

                //limpa o numero do telefone
                preg_match('/(\d+)/', $historic["key"]["remoteJid"], $matches);
                $numero_telefone = $matches[0];

                preg_match('/(\d+)/', $decodedData["sender"], $matches);
                $numero_sender = $matches[0];





                $data = array(
                    "msg_wook" => $decodedData["event"],
                    "msg_fromMe" => $historic["key"]["fromMe"],
                    "msg_send_id" => $historic["key"]["id"],
                    "msg_session" => $decodedData["apikey"],
                    "msg_isGroupMsg" => $isGroupMsg,
                    "msg_name" => $historic["pushName"],
                    "msg_to" => ($historic["key"]["fromMe"] ? $numero_telefone : $numero_sender),
                    "msg_from" => ($historic["key"]["fromMe"] ? $numero_sender : $numero_telefone),
                    "msg_content" => ($historic["message"]["conversation"] ? $historic["message"]["conversation"] : $historic["message"]["extendedTextMessage"]["text"]),
                    "msg_date" => $msg_date,
                    "msg_status" =>  $historic["status"],
                    "sent_source" => "historic",
                );

                if ($historic["messageType"] == "conversation") {
                    $data["msg_type"] = "text";
                }

                //se mensagem for editada
                if ($historic["messageType"] == "editedMessage") {
                    $data["msg_type"] = "message_edit";
                    $data["msg_content"] = $historic["message"]["editedMessage"]["message"]["protocolMessage"]["editedMessage"]["conversation"];
                    $data["msg_send_id"] = $historic["message"]["editedMessage"]["message"]["protocolMessage"]["key"]["id"];
                }

                if ($data["msg_fromMe"] == 1) {
                    $data["msg_conversation_number"] = $data["msg_to"];
                } else {
                    $data["msg_conversation_number"] = $data["msg_from"];
                }

                //verifica se já tem o registo no banco se tiver pula
                $this->db->where('msg_send_id', $historic["key"]["id"]);
                $registro = $this->db->get(db_prefix() . 'contactcenter_message')->row();
                if ($registro) {

                    $this->db->where('phonenumber', $data["msg_conversation_number"]);
                    $this->db->where('session', $decodedData["apikey"]);
                    $this->db->update(db_prefix() . 'contactcenter_contact', ["active" => 1]);
                    continue;
                }


                //lista de mensagens
                if ($historic["message"]["listMessage"]) {
                    $data["msg_content"] = $historic["message"]["listMessage"]["title"] . " - " . $historic["message"]["listMessage"]["description"];
                    $data["msg_type"] = "text";
                }
                if ($historic["message"]["listResponseMessage"]) {
                    $data["msg_content"] = $historic["message"]["listResponseMessage"]["title"];
                    $data["msg_type"] = "text";
                }

                //salva o audio
                if ($historic["messageType"] == "audioMessage") {

                    // busco device pelo token
                    $device = $this->get_device_token($historic["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;
                    //pega a media
                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $historic["apikey"]);
                    if ($media["error"]) {
                        $data["msg_content"] = "Audio não disponível";
                    } else {
                        // convertendo para audio
                        $audio = $this->convert_base64_audio_webhook($media["base64"]);

                        // convertendo para mp3
                        $convertMp3 = $this->api_convert_type_audio(site_url("{$audio}"));

                        if ($convertMp3["url"]) {
                            //excluindo o audio convertido
                            unlink(FCPATH . $audio);
                            //faz o download do audio
                            $data["msg_base64"] = $this->save_audio_from_url($convertMp3["url"]);
                        } else {
                            log_activity('Erro ao converter audio api axiom (insert_historico_webhook)');
                        }
                    }

                    $data["msg_type"] = "ptt";
                }

                //salva a imagem
                if ($historic["messageType"] == "imageMessage") {

                    if ($historic["message"]["base64"] != null) {
                        $data["msg_base64"] = "data:image/jpeg;base64," . $historic["message"]["base64"];
                        $data["msg_type"] = "image";
                    } else {
                        // busco device pelo token
                        $device = $this->get_device_token($data["msg_session"]);

                        // busco server
                        $server = $this->get_server($device->server_id);


                        // monto a url
                        $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                        $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $historic["apikey"]);
                        if ($media["error"]) {
                            $data["msg_content"] = "Imagem não disponível";
                        } else {
                            $data["msg_base64"] = "data:image/jpeg;base64," . $media["base64"];
                        }


                        $data["msg_type"] = "image";
                    }
                }


                if ($historic["messageType"] == "documentMessage") {

                    if ($historic["message"]["documentMessage"]["mimetype"] == "application/pdf") {

                        // busco device pelo token
                        $device = $this->get_device_token($historic["apikey"]);

                        // busco server
                        $server = $this->get_server($device->server_id);

                        // monto a url
                        $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                        $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $historic["apikey"]);
                        if ($media["error"]) {
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo PDF não disponível");
                        } else {
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo PDF disponível");
                            $data["msg_base64"] = "data:application/pdf;base64," . $media["base64"];
                        }
                        $data["msg_type"] = "documentPDF";
                    } else if ($historic["message"]["documentMessage"]["mimetype"] == "application/zip") {
                        // busco device pelo token
                        $device = $this->get_device_token($historic["apikey"]);
                        // busco server
                        $server = $this->get_server($device->server_id);
                        // monto a url
                        $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                        $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $historic["apikey"]);
                        if ($media["error"]) {
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo ZIP nao disponível");
                        } else {
                            $data["msg_base64"] = "data:application/zip;base64," . $media["base64"];
                        }

                        $data["msg_type"] = "documentZIP";
                    } else if ($historic["message"]["documentMessage"]["mimetype"] == "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") {
                        // busco device pelo token
                        $device = $this->get_device_token($historic["apikey"]);
                        // busco server
                        $server = $this->get_server($device->server_id);
                        // monto a url
                        $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                        $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $historic["apikey"]);
                        if ($media["error"]) {
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo XLSX nao disponível");
                        } else {
                            $data["msg_base64"] = "data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64," . $media["base64"];
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo XLSX disponível");
                        }
                        $data["msg_type"] = "documentXLSX";
                    } else if ($historic["message"]["documentMessage"]["mimetype"] == "application/vnd.openxmlformats-officedocument.wordprocessingml.document") {
                        // busco device pelo token
                        $device = $this->get_device_token($historic["apikey"]);
                        // busco server
                        $server = $this->get_server($device->server_id);
                        // monto a url
                        $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                        $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $historic["apikey"]);
                        if ($media["error"]) {
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo DOCX nao disponível");
                        } else {
                            $data["msg_base64"] = "data:application/vnd.openxmlformats-officedocument.wordprocessingml.document;base64," . $media["base64"];
                            $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo DOCX");
                        }
                        $data["msg_type"] = "documentDOCX";
                    }
                }


                if ($historic["messageType"] == "videoMessage") {
                    $data["msg_type"] = "video";
                }
                if ($historic["messageType"] == "conversation" || $historic["messageType"] == "extendedTextMessage") {
                    $data["msg_type"] = "text";
                }


                // se msgtype for null ou vazio, pula para o proximo
                if ($data["msg_type"] == null || $data["msg_type"] == "") {
                    continue;
                }

                $device = $this->get_device_token($historic["apikey"]);

                //Pega o staffid do da session
                if ($device->staffid) {
                    $data["staffid"] = $device->staffid;
                } else {
                    $data["staffid"] = 0;
                }

                // salva as mensagens
                if (!$registro && $isGroupMsg == false) {
                    //verifica se já tem o registo
                    $this->db->where('msg_send_id', $data["msg_send_id"]);
                    $registro = $this->db->get(db_prefix() . 'contactcenter_message')->row();
                    if ($registro) {
                        $this->db->where('msg_send_id', $data["msg_send_id"]);
                        $this->db->update(db_prefix() . 'contactcenter_message', $data);
                        continue;
                    }

                    $this->db->insert(db_prefix() . 'contactcenter_message', $data);
                    $insert_id = $this->db->insert_id();
                    if ($insert_id) {
                        $data["msg_id"] = $insert_id;

                        //Faz o isert do lead
                        if (get_option("contac_settings_sincronizacao_whatsapp_leads") == 1) {
                            $lead = $this->insert_leads_whatsapp($data);
                        }
                    }
                }
            } //fim do foreach

        } //fim do if


    }

    public function sincronize_historico_cron()
    {
        $this->db->where("status_sinc", 1);
        $this->db->where("is_processing", 0); // Apenas dispositivos não em processamento
        $this->db->where("status", "open");
        $devices = $this->db->get(db_prefix() . 'contactcenter_device')->result();

        if ($devices) {
            foreach ($devices as $device) {

                if ($device->dev_type == 1 || $device->api_local == 1) {
                    continue;
                }

                $server = $this->get_server($device->server_id);
                if ($server->version == 1) {
                    continue;
                }

                // Marcar o dispositivo como em processamento
                $this->db->where('dev_id', $device->dev_id);
                $this->db->update(db_prefix() . 'contactcenter_device', ['is_processing' => 1]);



                try {
                    $this->process_device($device);
                } catch (Exception $e) {
                    log_activity('Erro ao processar dispositivo [' . $device->dev_id . ']: ' . $e->getMessage());
                }

                // Finalizar o processamento
                $this->db->where('dev_id', $device->dev_id);
                $this->db->update(db_prefix() . 'contactcenter_device', [
                    'is_processing' => 0,
                    "totalPages" => 0,
                    "currentPage" => 0,
                    "status_sinc" => 0,
                ]);
            }
        }
    }

