    public function cron_sincroniza_contact_whatsapp()
    {
        $this->load->database();
        $this->load->helper('url');

        $limit = 20; // Limite de contatos a serem sincronizados por execução

        //pega os contatos que precisam ser sincronizados
        $this->db->where('sincronizar', 0);
        $this->db->where("remoteJid IS NOT NULL", null, false);
        $this->db->where("remoteJid !=", '');
        $this->db->limit($limit);
        $contacts = $this->db->get(db_prefix() . 'contactcenter_contact')->result();

        if (!$contacts) return;



        $client = new Client();
        $concurrency = $limit;

        $requests = [];
        $jidMap = []; // Mapear JID por índice
        $deviceToken = null;

        foreach ($contacts as $index => $c) {
            $device = $this->get_device_token($c->session);
            if ($device->api_local == 1) {
                // Se o dispositivo for local, não faz a requisição
                continue;
            }



            $server = $this->get_server($device->server_id);

            if ($device->status === "open" && $server->version == 2) {
                $url = $server->url . "chat/findMessages/" . $device->dev_instance_name;
                $jid = $c->remoteJid ?? ($c->telefone . "@s.whatsapp.net");

                $jidMap[$index] = [
                    'jid' => $jid,
                    'device_token' => $device->dev_token
                ];

                $requests[] = function () use ($client, $url, $jid) {
                    return $client->postAsync($url, [
                        'headers' => [
                            'apikey' => get_option('contactcenter_api_key'),
                        ],
                        'json' => [
                            'where' => ['key' => ['remoteJid' => $jid]],
                            'page' => 1,
                            'offset' => 50,
                        ],
                        'timeout' => 5,
                    ]);
                };
            }
        }

        $pool = new Pool($client, $requests, [
            'concurrency' => $concurrency,
            'fulfilled' => function (Response $response, $index) use ($jidMap) {
                $body = $response->getBody()->getContents();
                $data = json_decode($body, true);

                if (!isset($data['messages']['records']) || count($data['messages']['records']) === 0) {
                    return;
                }

                // Ordena do mais recente para o mais antigo pelo campo 'messageTimestamp'
                usort($data['messages']['records'], function ($a, $b) {
                    return $a['messageTimestamp'] <=> $b['messageTimestamp'];
                });

                $jidInfo = $jidMap[$index];

                $this->insert_historico_cron($data, $jidInfo['device_token']);
            },
            'rejected' => function ($reason, $index) {
                log_message('error', "Erro ao sincronizar contato #$index: " . $reason->getMessage());
            },
        ]);

        $promise = $pool->promise();
        $promise->wait();
    }




    public function insert_contact_cron($data)
    {
        if ($data) {

            $this->db->where('phonenumber', $data["msg_conversation_number"]);
            $this->db->where('session', $data["msg_session"]);
            $contact = $this->db->get(db_prefix() . 'contactcenter_contact')->row();
            if ($contact) {
                $isread = $contact->isread + 1;
                $crear = [
                    "date" => $data["msg_date"],
                    "isread" => $isread,
                    "msg_fromMe" => $data["msg_fromMe"],
                    "isGroup" => $data["msg_isGroupMsg"],
                    "active" => 1,
                ];
                $this->db->where('id', $contact->id);
                $this->db->update(db_prefix() . 'contactcenter_contact', $crear);
            } else {
                $crear = [
                    "staffid" => $data["staffid"],
                    "phonenumber" => $data["msg_conversation_number"],
                    "session" => $data["msg_session"],
                    "date" => $data["msg_date"],
                    "isGroup" => $data["msg_isGroupMsg"],
                    "isread" => 1,
                    "active" => 1,
                    "date" => $data["msg_date"],
                    "msg_fromMe" => $data["msg_fromMe"],
                ];
                $insert =   $this->db->insert(db_prefix() . 'contactcenter_contact', $crear);
            }
        }
    }




    public function insert_historico_cron($decodedData, $dev_token)
    {


        foreach ($decodedData["messages"]["records"] as $historic) {
            $msg_date = date('Y-m-d H:i:s', $historic['messageTimestamp']);


            //verifica se é grupo ou individual
            if (str_ends_with($historic["key"]["remoteJid"], '@g.us')) {
                $isGroupMsg = true;
            } else {
                $isGroupMsg = false;
            }

            // //se for grupo pula
            // if ($isGroupMsg) {
            //     continue;
            // }

            if (str_ends_with($historic["key"]["remoteJid"], '@broadcast')) {
                continue;
            }


            $decodedData["apikey"] = $dev_token;

            //limpa o numero do telefone
            preg_match('/(\d+)/', $historic["key"]["remoteJid"], $matches);
            $numero_telefone = $matches[0];

            preg_match('/(\d+)/', $decodedData["sender"], $matches);
            $numero_sender = $matches[0];



            $data = array(
                "msg_wook" => $decodedData["event"],
                "msg_fromMe" => $historic["key"]["fromMe"],
                "msg_send_id" => $historic["key"]["id"],
                "msg_session" => $decodedData["apikey"],
                "msg_isGroupMsg" => $isGroupMsg,
                "msg_name" => $historic["pushName"],
                "msg_to" => ($historic["key"]["fromMe"] ? $numero_telefone : $numero_sender),
                "msg_from" => ($historic["key"]["fromMe"] ? $numero_sender : $numero_telefone),
                "msg_content" => ($historic["message"]["conversation"] ? $historic["message"]["conversation"] : $historic["message"]["extendedTextMessage"]["text"]),
                "msg_date" => $msg_date,
                "msg_status" =>  $historic["status"],
                "remoteJid" => $historic["key"]["remoteJid"],
                "sent_source" => "historic_cron",
            );



            if ($historic["messageType"] == "conversation") {
                $data["msg_type"] = "text";
            }

            //se mensagem for editada
            if ($historic["messageType"] == "editedMessage") {
                $data["msg_type"] = "message_edit";
                $data["msg_content"] = $historic["message"]["editedMessage"]["message"]["protocolMessage"]["editedMessage"]["conversation"];
                $data["msg_send_id"] = $historic["message"]["editedMessage"]["message"]["protocolMessage"]["key"]["id"];
            }

            if ($data["msg_fromMe"] == 1) {
                $data["msg_conversation_number"] = $data["msg_to"];
            } else {
                $data["msg_conversation_number"] = $data["msg_from"];
            }


            //verifica se já tem o registo no banco se tiver pula
            $this->db->where('msg_send_id', $data["msg_send_id"]);
            $registro = $this->db->get(db_prefix() . 'contactcenter_message')->row();
            if ($registro) {

                $this->db->where('phonenumber', $data["msg_conversation_number"]);
                $this->db->where('session', $decodedData["apikey"]);
                $this->db->update(db_prefix() . 'contactcenter_contact', ["active" => 1]);
                continue;
            }

            if (!$data["msg_conversation_number"]) {
                continue;
            }


            //lista de mensagens
            if ($historic["message"]["listMessage"]) {
                $data["msg_content"] = $historic["message"]["listMessage"]["title"] . " - " . $historic["message"]["listMessage"]["description"];
                $data["msg_type"] = "text";
            }
            if ($historic["message"]["listResponseMessage"]) {
                $data["msg_content"] = $historic["message"]["listResponseMessage"]["title"];
                $data["msg_type"] = "text";
            }

            //salva o audio
            if ($historic["messageType"] == "audioMessage") {

                // busco device pelo token
                $device = $this->get_device_token($decodedData["apikey"]);
                // busco server
                $server = $this->get_server($device->server_id);
                // monto a url
                $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;
                //pega a media
                $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $decodedData["apikey"]);
                if ($media["error"]) {
                    $data["msg_content"] = "Audio não disponível";
                } else {
                    // convertendo para audio
                    $audio = $this->convert_base64_audio_webhook($media["base64"]);

                    // convertendo para mp3
                    $convertMp3 = $this->api_convert_type_audio(site_url("{$audio}"));

                    if ($convertMp3["url"]) {
                        //excluindo o audio convertido
                        unlink(FCPATH . $audio);
                        //faz o download do audio
                        $data["msg_base64"] = $this->save_audio_from_url($convertMp3["url"]);
                    } else {
                        log_activity('Erro ao converter audio api axiom (insert_historico_cron)');
                    }
                }

                $data["msg_type"] = "ptt";
            }

            //salva a imagem
            if ($historic["messageType"] == "imageMessage") {

                if ($historic["message"]["base64"] != null) {
                    $data["msg_base64"] = "data:image/jpeg;base64," . $historic["message"]["base64"];
                    $data["msg_type"] = "image";
                } else {
                    // busco device pelo token
                    $device = $this->get_device_token($data["msg_session"]);

                    // busco server
                    $server = $this->get_server($device->server_id);


                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $decodedData["apikey"]);
                    if ($media["error"]) {
                        $data["msg_content"] = "Imagem não disponível";
                    } else {
                        $data["msg_base64"] = "data:image/jpeg;base64," . $media["base64"];
                    }


                    $data["msg_type"] = "image";
                }
            }


            if ($historic["messageType"] == "documentMessage") {

                if ($historic["message"]["documentMessage"]["mimetype"] == "application/pdf") {

                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);

                    // busco server
                    $server = $this->get_server($device->server_id);

                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $decodedData["apikey"]);
                    if ($media["error"]) {
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo PDF não disponível");
                    } else {
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo PDF disponível");
                        $data["msg_base64"] = "data:application/pdf;base64," . $media["base64"];
                    }
                    $data["msg_type"] = "documentPDF";
                } else if ($historic["message"]["documentMessage"]["mimetype"] == "application/zip") {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $decodedData["apikey"]);
                    if ($media["error"]) {
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo ZIP nao disponível");
                    } else {
                        $data["msg_base64"] = "data:application/zip;base64," . $media["base64"];
                    }

                    $data["msg_type"] = "documentZIP";
                } else if ($historic["message"]["documentMessage"]["mimetype"] == "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $decodedData["apikey"]);
                    if ($media["error"]) {
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo XLSX nao disponível");
                    } else {
                        $data["msg_base64"] = "data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64," . $media["base64"];
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo XLSX disponível");
                    }
                    $data["msg_type"] = "documentXLSX";
                } else if ($historic["message"]["documentMessage"]["mimetype"] == "application/vnd.openxmlformats-officedocument.wordprocessingml.document") {
                    // busco device pelo token
                    $device = $this->get_device_token($decodedData["apikey"]);
                    // busco server
                    $server = $this->get_server($device->server_id);
                    // monto a url
                    $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

                    $media = $this->axiom_evolution->get_media_evolution_base64($url, $historic["key"]["id"], $decodedData["apikey"]);
                    if ($media["error"]) {
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo DOCX nao disponível");
                    } else {
                        $data["msg_base64"] = "data:application/vnd.openxmlformats-officedocument.wordprocessingml.document;base64," . $media["base64"];
                        $data["msg_content"] = ($historic["message"]["documentMessage"]["caption"] ? $historic["message"]["documentMessage"]["caption"] : "Arquivo DOCX");
                    }
                    $data["msg_type"] = "documentDOCX";
                }
            }


            if ($historic["messageType"] == "videoMessage") {
                $data["msg_type"] = "video";
            }
            if ($historic["messageType"] == "conversation" || $historic["messageType"] == "extendedTextMessage") {
                $data["msg_type"] = "text";
            }


            // se msgtype for null ou vazio, pula para o proximo
            if ($data["msg_type"] == null || $data["msg_type"] == "") {
                continue;
            }

            //Pega o staffid do da session
            $device = $this->get_device_token($decodedData["apikey"]);
            if ($device->staffid) {
                $data["staffid"] = $device->staffid;
            } else {
                $data["staffid"] = 0;
            }



            // salva as mensagens
            if (!$registro && $isGroupMsg == false) {
                $this->db->insert(db_prefix() . 'contactcenter_message', $data);
                $insert_id = $this->db->insert_id();
                if ($insert_id) {
                    $data["msg_id"] = $insert_id;

                    $contact = $this->insert_contact_cron($data);

                    // //Faz o isert do lead
                    if (get_option("contac_settings_sincronizacao_whatsapp_leads") == 1) {
                        $lead = $this->insert_leads_whatsapp($data);
                    }
                }
            } else {
                $this->db->where('msg_send_id', $data["msg_send_id"]);
                $this->db->update(db_prefix() . 'contactcenter_message', $data);
            }
        } //fim do foreach




    }


    /**
     * pega todas as mensagens de um device na API 
     */
    public function get_chat_all_api($device_id, $pages = 1, $offset = 50)
    {

        $device =  $this->get_device();
        $server = $this->get_server($device->server_id);
        if ($device->status == "open" && $server->version == 2) {

            $data = [
                "where" => [
                    "remoteJid" => $remoteJid,
                ],
                "page" => $pages,
                "offset" => $offset
            ];

            $data_json = json_encode($data);

            if ($server) {
                $url = "{$server->url}chat/findMessages/{$device->dev_instance_name}";
                $curl = curl_init();
                curl_setopt_array($curl, array(
                    CURLOPT_URL => $url,
                    CURLOPT_RETURNTRANSFER => true,
                    CURLOPT_ENCODING => '',
                    CURLOPT_MAXREDIRS => 10,
                    CURLOPT_TIMEOUT => 30,
                    CURLOPT_FOLLOWLOCATION => true,
                    CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
                    CURLOPT_CUSTOMREQUEST => 'POST',
                    CURLOPT_POSTFIELDS => $data_json,
                    CURLOPT_HTTPHEADER => array(
                        'Content-Type: application/json',
                        'ApiKey: ' . $device->dev_token . ' '
                    ),
                ));

                $response = curl_exec($curl);
                curl_close($curl);
                $response = json_decode($response, true);
                if ($response) {
                    return $response;
                } else {
                    return false;
                }
            }
        }
    }



    public function sincroniza_contact_whatsapp($device_id)
    {
        $device =  $this->get_device($device_id);

        if ($device->status == "inChat" || $device->status == "CONNECTED" || $device->status == "open" || $device->status == "connecting") {

            $server = $this->get_server($device->server_id);
            if ($server && $server->version == 2) {
                $url = "{$server->url}chat/findContacts/{$device->dev_instance_name}";
                $curl = curl_init();
                curl_setopt_array($curl, array(
                    CURLOPT_URL => $url,
                    CURLOPT_RETURNTRANSFER => true,
                    CURLOPT_ENCODING => '',
                    CURLOPT_MAXREDIRS => 10,
                    CURLOPT_TIMEOUT => 30,
                    CURLOPT_FOLLOWLOCATION => true,
                    CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
                    CURLOPT_CUSTOMREQUEST => 'POST',
                    CURLOPT_HTTPHEADER => array(
                        'Content-Type: application/json',
                        'ApiKey: ' . $device->dev_token . ' '
                    ),
                ));

                $response = curl_exec($curl);
                curl_close($curl);
                $response = json_decode($response, true);

                if ($response[0]["id"] != null) {
                    $i = 1;
                    foreach ($response as $key => $contact) {

                        //pula lista de transmisão
                        if (str_ends_with($contact["remoteJid"], '@lid')) {
                            continue;
                        }

                        //verifica se é grupo ou individual
                        if (str_ends_with($contact["remoteJid"], '@g.us')) {
                            $isGroupMsg = true;
                        } else {
                            $isGroupMsg = false;
                        }

                        preg_match('/(\d+)/', $contact["remoteJid"], $matches);
                        $contact_phone = $matches[0];

                        $updateContact = [
                            "phonenumber " => $contact_phone,
                            "thumb" => ($contact["profilePicUrl"] ? $contact["profilePicUrl"] : null),
                            "name" => $contact["pushName"],
                            "session" => $device->dev_token,
                            "staffid" => $device->staffid,
                            "isGroup" => $isGroupMsg,
                            "remoteJid" => $contact["remoteJid"],
                            "sincronizar" => 1,
                        ];

                        if (!$contact_phone) {
                            continue;
                        }

                        //verifica se já tem o registo
                        $this->db->where('phonenumber', $contact_phone);
                        $this->db->where('session', $device->dev_token);
                        $registro = $this->db->get(db_prefix() . 'contactcenter_contact')->row();
                        if (!$registro) {
                            //se não tem a data coloca a data atual mais 1 segundo para cada contato
                            $updateContact["date"] = date('Y-m-d H:i:s', strtotime("+{$i} second"));
                            $updateContact["active"] = ($isGroupMsg ? 1 : 0);
                            $this->db->insert(db_prefix() . 'contactcenter_contact', $updateContact);
                            $i++;
                        } else {
                            if ($isGroupMsg) {
                                $updateContact["active"] = 1;
                                $updateContact["sincronizar"] = 1;
                            }
                            $this->db->where('phonenumber', $contact_phone);
                            $this->db->where('session', $device->dev_token);
                            $this->db->update(db_prefix() . 'contactcenter_contact', $updateContact);
                        }
                    }
                }
            }
        }
    }




    /**
     * Envia uma lista de opções para o confirmar agendamento
     */
    public function cron_confirm_agendamento()
    {
        //Verifica se esta habilitado
        if (get_option('contac_active_confirm_agendamento') == 0) {
            log_activity("cron_confirm_agendamento DISABLED - Meeting confirmation is disabled in settings", get_staff_user_id());
            return false;
        }

        $quantHoras = get_option('contactcenter_notify_whatsapp_agendamento');
        if (empty($quantHoras) || $quantHoras <= 0) {
            log_activity("cron_confirm_agendamento INVALID HOURS - Configured hours is invalid: {$quantHoras}", get_staff_user_id());
            return false;
        }

        log_activity("cron_confirm_agendamento START - Checking for events to notify. Hours before: {$quantHoras}", get_staff_user_id());

        // Query events that:
        // 1. Are active (status = 1)
        // 2. Haven't been notified yet (notifyWhatsapp = 0)
        // 3. Are for leads or customers
        // 4. Are in the future (start >= now) or within the last day (to catch any missed ones)
        // 5. The notification time should have arrived (start - configured hours <= now)
        $current_time = date('Y-m-d H:i:s');
        $notification_time_limit = date('Y-m-d H:i:s', strtotime("+{$quantHoras} hours"));
        $min_start_time = date('Y-m-d H:i:s', strtotime("-1 day")); // Check past 24 hours for missed notifications
        $max_start_time = date('Y-m-d H:i:s', strtotime('+30 days')); // Check up to 30 days in the future
        
        // Get all events in the time range first (for debugging)
        $this->db->select('eventid, start, status, notifyWhatsapp, rel_type, rel_id');
        $this->db->from(db_prefix() . 'events');
        $this->db->where('start >=', $min_start_time);
        $this->db->where('start <=', $max_start_time);
        $all_events_in_range = $this->db->get()->result();
        log_activity("cron_confirm_agendamento DEBUG - Total events in time range (2026-01-16 to +30 days): " . count($all_events_in_range) . " - Event IDs: " . implode(', ', array_column($all_events_in_range, 'eventid')), get_staff_user_id());
        
        // Now apply filters for events that should be checked
        $this->db->where('status', 1);
        $this->db->where('notifyWhatsapp', 0);
        $this->db->where_in('rel_type', ['lead', 'customer']);
        // Get events that are in the future or within the notification window (past 24 hours to catch missed ones)
        $this->db->where('start >=', $min_start_time);
        $this->db->where('start <=', $max_start_time);
        $this->db->order_by('start', 'ASC'); // Process earliest events first
        $events = $this->db->get(db_prefix() . 'events')->result();

        log_activity("cron_confirm_agendamento EVENTS FOUND - Found " . count($events) . " events to check (status=1, notifyWhatsapp=0, rel_type in [lead,customer])", get_staff_user_id());
        
        // Log any events that were excluded
        if (count($all_events_in_range) > count($events)) {
            $event_ids_checked = array_column($events, 'eventid');
            $excluded_events = array_filter($all_events_in_range, function($e) use ($event_ids_checked) {
                return !in_array($e->eventid, $event_ids_checked);
            });
            foreach ($excluded_events as $excluded) {
                $exclusion_reasons = [];
                if ($excluded->status != 1) $exclusion_reasons[] = "status={$excluded->status}";
                if ($excluded->notifyWhatsapp != 0) $exclusion_reasons[] = "notifyWhatsapp={$excluded->notifyWhatsapp}";
                if (!in_array($excluded->rel_type, ['lead', 'customer'])) $exclusion_reasons[] = "rel_type={$excluded->rel_type}";
                log_activity("cron_confirm_agendamento EVENT EXCLUDED - Event ID: {$excluded->eventid}, Start: {$excluded->start}, Reasons: " . implode(', ', $exclusion_reasons), get_staff_user_id());
            }
        }

        $notifications_sent = 0;
        foreach ($events as $event) {
            // Initialize variables
            $phone = null;
            $name = null;
            
            // Calculate when the notification should be sent (event start - configured hours)
            $notification_time = date('Y-m-d H:i:s', strtotime($event->start . " -{$quantHoras} hours"));
            
            // Get timestamps for comparison
            $event_start_timestamp = strtotime($event->start);
            $current_timestamp = strtotime($current_time);
            $notification_timestamp = strtotime($notification_time);
            
            // Check if event has already started
            $event_has_started = $current_timestamp > $event_start_timestamp;
            
            // Check if notification time has passed
            $notification_time_passed = $current_timestamp >= $notification_timestamp;
            
            // We should send if notification time has passed AND event hasn't started yet
            // Or if notification time passed but event just started (within last hour) - catch missed ones
            $time_to_send = false;
            if ($notification_time_passed && !$event_has_started) {
                // Normal case: notification time passed, event hasn't started yet
                $time_to_send = true;
            } elseif ($notification_time_passed && $event_has_started && (($current_timestamp - $event_start_timestamp) < 3600)) {
                // Edge case: notification time passed, event just started (within last hour) - try to catch missed notification
                $time_to_send = true;
            }
            
            log_activity("cron_confirm_agendamento CHECKING EVENT - Event ID: {$event->eventid}, Start: {$event->start}, Notification Time: {$notification_time}, Current Time: {$current_time}, Notification Passed: " . ($notification_time_passed ? 'yes' : 'no') . ", Event Started: " . ($event_has_started ? 'yes' : 'no') . ", Time To Send: " . ($time_to_send ? 'yes' : 'no'), get_staff_user_id());
            
            // Check if it's time to send the notification
            if ($time_to_send) {
                log_activity("cron_confirm_agendamento TIME TO SEND - Event ID: {$event->eventid}, Sending notification now", get_staff_user_id());
                
                // Mark as notified BEFORE sending to avoid duplicate sends if cron runs multiple times
                $this->db->where('eventid', $event->eventid);
                $this->db->update(db_prefix() . 'events', ["notifyWhatsapp" => 1]);
                
                log_activity("cron_confirm_agendamento TIME TO SEND - Event ID: {$event->eventid}, Sending notification now. Is Past Event: " . ($is_past_event ? 'yes' : 'no'), get_staff_user_id());

                //pega o telefone do lead
                if ($event->rel_type == 'lead') {
                    $this->db->where('id', $event->rel_id);
                    $lead = $this->db->get(db_prefix() . 'leads')->row();
                    if ($lead) {
                        $phone = $lead->phonenumber;
                        $name = $lead->name;
                    }
                }

                //pega o telefone do cliente
                if ($event->rel_type == 'customer') {
                    $this->db->where('userid', $event->rel_id);
                    $customer = $this->db->get(db_prefix() . 'clients')->row();
                    if ($customer) {
                        $phone = $customer->phonenumber;
                        $name = $customer->company;
                    }
                }

                // pega o device do usuario, caso não tenha sai pelo do sistema 
                $this->db->where('staffid', $event->userid);
                $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
                if ($device) {
                    $staffid = $event->userid;
                } else {
                    $staffid = null;
                }


                if ($phone) {
                    $token = $this->create_confirmation_token($event->eventid, $phone);
                    $confirm_link = site_url('contactcenter/appointment_confirm_public/index/' . $token);

                    $custom_template = get_option('contac_confirm_msg_template');
                    if (!empty($custom_template)) {
                        $text_message = str_replace(
                            ['{name}', '{date}', '{link}'],
                            [$name, _dt($event->start), $confirm_link],
                            $custom_template
                        );
                    } else {
                        $title = _l("contac_notification_title_whats_list");
                        $greeting = _l("contac_notification_description_whats_saudacao_list");
                        $desc = _l("contac_notification_description_whats_list");

                        $text_message  = "*{$title}*\n\n";
                        $text_message .= "{$greeting} {$name}, {$desc} " . _dt($event->start) . "\n\n";
                        $text_message .= _l('contac_confirm_link_label') . " {$confirm_link}\n\n";
                        $text_message .= _l('contac_confirm_keyword_instructions');
                    }

                    $send_result = $this->send_text($phone, $text_message, $staffid, null, null, true, 'crm');

                    $send_success = false;
                    if ($send_result) {
                        if (isset($send_result['error']) || (isset($send_result['status']) && $send_result['status'] >= 400)) {
                            $error_msg = isset($send_result['error']) ? $send_result['error'] : 'HTTP ' . ($send_result['status'] ?? 'unknown');
                            log_activity("cron_confirm_agendamento NOTIFICATION FAILED - Event ID: {$event->eventid}, Phone: {$phone}, Error: {$error_msg}", get_staff_user_id());
                        } elseif (isset($send_result['key']) || isset($send_result['id']) || isset($send_result['message'])) {
                            $send_success = true;
                            $notifications_sent++;
                            log_activity("cron_confirm_agendamento NOTIFICATION SENT - Event ID: {$event->eventid}, Phone: {$phone}, Name: {$name}", get_staff_user_id());
                        } else {
                            log_activity("cron_confirm_agendamento NOTIFICATION UNKNOWN RESPONSE - Event ID: {$event->eventid}, Phone: {$phone}, Response: " . json_encode($send_result), get_staff_user_id());
                        }
                    } else {
                        log_activity("cron_confirm_agendamento NOTIFICATION FAILED - Event ID: {$event->eventid}, Phone: {$phone}, send_text returned false/null", get_staff_user_id());
                    }

                    if (!$send_success) {
                        $this->db->where('eventid', $event->eventid);
                        $this->db->update(db_prefix() . 'events', ["notifyWhatsapp" => 0]);
                        log_activity("cron_confirm_agendamento RESET NOTIFY STATUS - Event ID: {$event->eventid}, Setting notifyWhatsapp back to 0 for retry", get_staff_user_id());
                    }
                } else {
                    log_activity("cron_confirm_agendamento NO PHONE - Event ID: {$event->eventid}, No phone number found for rel_type: {$event->rel_type}, rel_id: {$event->rel_id}", get_staff_user_id());
                }
            } else {
                log_activity("cron_confirm_agendamento NOT YET TIME - Event ID: {$event->eventid}, Notification time: {$notification_time}, Current time: {$current_time}", get_staff_user_id());
            }
        }
        
        log_activity("cron_confirm_agendamento COMPLETE - Total notifications sent: {$notifications_sent} out of " . count($events) . " events checked", get_staff_user_id());
    }

    /**
     * confirma o agendamento
     */
    public function confirm_agendamento($data)
    {

        $selectedRowId = explode("-", $data["selectedRowId"]);
        $resposta = $selectedRowId[0];
        $eventid = $selectedRowId[1];
        $type = $selectedRowId[2];

        if ($type == "agendamento") {

            if ($resposta == "yes") {
                $status = 2;
                $custom_success = get_option('contac_confirm_msg_success');
                $notificacao = !empty($custom_success) ? $custom_success : _l("contac_notification_agendamento_success");
            } else if ($resposta == "cancel") {
                $status = 4;
                $custom_cancel = get_option('contac_confirm_msg_cancel');
                $notificacao = !empty($custom_cancel) ? $custom_cancel : _l("contac_notification_agendamento_cancel");
            } else if ($resposta == "reschedule") {
                $status = 3;
            }

            $this->db->where('eventid', $eventid);
            $events = $this->db->get(db_prefix() . 'events')->row();
            if ($events) {
                $this->db->where('eventid', $eventid);
                $this->db->update(db_prefix() . 'events', ["status" => $status]);

                if ($events->rel_type == "lead") {
                    $relType = _l("contac_lead");
                    $this->leads_model->log_lead_activity($events->rel_id, _l('contac_notification_agendamento_success'));
                } else if ($events->rel_type == "customer") {
                    $relType = _l("contac_customer");
                }

                if (!empty($events->userid)) {
                    add_notification([
                        'description'     => "{$notificacao} {$relType} {$events->rel_id}.",
                        'touserid'        => (int) $events->userid,
                        'link'            => "agenda_axiom/agenda",
                    ]);
                } else {
                    log_activity('contactcenter: skipped appointment notification because events.userid is empty. eventid=' . (int) $eventid . ', rel_type=' . (string) $events->rel_type . ', rel_id=' . (int) $events->rel_id, get_staff_user_id());
                }

                if ($data["staffid"] == $events->userid) {
                    $staffid = $data["staffid"];
                } else {
                    $staffid = null;
                }
                $this->send_text($data["msg_conversation_number"], $notificacao, $staffid);
                return true;
            }
        }
    }

    public function create_confirmation_token($event_id, $phone)
    {
        $table = db_prefix() . 'contactcenter_confirmation_tokens';
        if (!$this->db->table_exists($table)) {
            return false;
        }

        $token = bin2hex(random_bytes(32));

        $this->db->insert($table, [
            'token'      => $token,
            'event_id'   => $event_id,
            'phone'      => $phone,
            'status'     => 'pending',
            'created_at' => date('Y-m-d H:i:s'),
        ]);

        return $this->db->insert_id() ? $token : false;
    }

    public function get_confirmation_by_token($token)
    {
        $table = db_prefix() . 'contactcenter_confirmation_tokens';
        if (!$this->db->table_exists($table)) {
            return null;
        }

        $this->db->select('ct.*, e.start, e.title, e.rel_type, e.rel_id, e.userid, e.status as event_status');
        $this->db->from($table . ' ct');
        $this->db->join(db_prefix() . 'events e', 'e.eventid = ct.event_id', 'left');
        $this->db->where('ct.token', $token);

        return $this->db->get()->row();
    }

    public function process_confirmation_token($token, $action)
    {
        $table = db_prefix() . 'contactcenter_confirmation_tokens';
        if (!$this->db->table_exists($table)) {
            return ['success' => false, 'message' => 'Table not found'];
        }

        $record = $this->get_confirmation_by_token($token);
        if (!$record) {
            return ['success' => false, 'message' => 'invalid'];
        }

        if ($record->status !== 'pending') {
            return ['success' => false, 'message' => 'already_used', 'previous_status' => $record->status];
        }

        $new_status = ($action === 'confirm') ? 'confirmed' : 'cancelled';
        $this->db->where('token', $token);
        $this->db->update($table, [
            'status'   => $new_status,
            'acted_at' => date('Y-m-d H:i:s'),
        ]);

        $event_status = ($action === 'confirm') ? 2 : 4;
        $this->db->where('eventid', $record->event_id);
        $this->db->update(db_prefix() . 'events', ['status' => $event_status]);

        if ($action === 'confirm') {
            $custom_msg = get_option('contac_confirm_msg_success');
            $notificacao = !empty($custom_msg) ? $custom_msg : _l('contac_notification_agendamento_success');
        } else {
            $custom_msg = get_option('contac_confirm_msg_cancel');
            $notificacao = !empty($custom_msg) ? $custom_msg : _l('contac_notification_agendamento_cancel');
        }

        if ($record->rel_type == 'lead') {
            $relType = _l('contac_lead');
            $this->load->model('leads_model');
            $this->leads_model->log_lead_activity($record->rel_id, $notificacao);
        } else {
            $relType = _l('contac_customer');
        }

        if (!empty($record->userid)) {
            add_notification([
                'description' => "{$notificacao} {$relType} {$record->rel_id}.",
                'touserid'    => (int) $record->userid,
                'link'        => 'agenda_axiom/agenda',
            ]);
        } else {
            log_activity('contactcenter: skipped token notification because record.userid is empty. event_id=' . (int) $record->event_id . ', rel_type=' . (string) $record->rel_type . ', rel_id=' . (int) $record->rel_id, get_staff_user_id());
        }

        if ($record->phone) {
            $this->send_text($record->phone, $notificacao, null);
        }

        return ['success' => true, 'status' => $new_status, 'notification' => $notificacao];
    }


    /**
     * faz o download do audio e salva no servidor
     */
    function save_audio_from_url($url)
    {

        $audioContent = file_get_contents($url);

        if ($audioContent === false) {
            return false;
        }

        $path = FCPATH . "uploads/contactcenter/audio/";

        if (!is_dir($path)) {
            mkdir($path, 0777, true);
        }

        $fileName = uniqid() . '_output.mp3';
        $savePath = $path . $fileName;

        $saveStatus = file_put_contents($savePath, $audioContent);
        if ($saveStatus === false) {
            log_activity('Error save audio function save_audio_from_url()');
            return false;
        } else {
            return "uploads/contactcenter/audio/{$fileName}";
        }
    }


    /**
     * Converte audio para mp3 na api axiom
     */
    public function api_convert_type_audio($url_audio, $inputFormat = "ogg", $outputFormat = "mp3")
    {

        $curl = curl_init();
        // AXIOM: serviço de áudio externo removido — configure um serviço local
        $url = '';

        $data = array(
            "audioUrl" => $url_audio,
            "inputFormat" => $inputFormat,
            "outputFormat" => $outputFormat,
        );
        $data_json = json_encode($data);

        curl_setopt_array($curl, array(
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_ENCODING => '',
            CURLOPT_MAXREDIRS => 10,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
            CURLOPT_CUSTOMREQUEST => 'POST',
            CURLOPT_POSTFIELDS => $data_json,
            CURLOPT_HTTPHEADER => array(
                'Content-Type: application/json'
            ),
        ));

        $response = curl_exec($curl);

        curl_close($curl);
        return json_decode($response, true);
    }

