    public function insert_analytics_meta($data, $decodedData)
    {

        if ($data["msg_fromMe"] == 1) {
            return; // Não processa mensagens enviadas pelo próprio usuário
        }


        // ✅ Normaliza o formato novo ou antigo de $decodedData
        if (isset($decodedData['_data']['ctwaContext'])) {
            $ctwa = $decodedData['_data']['ctwaContext'];
            $FB = [
                'externalAdReply' => [
                    'title' => $ctwa['title'] ?? '',
                    'body' => $ctwa['description'] ?? '',
                    'mediaType' => $ctwa['mediaType'] ?? '',
                    'thumbnailUrl' => $ctwa['thumbnailUrl'] ?? '',
                    'sourceUrl' => $ctwa['sourceUrl'] ?? '',
                    'sourceId' => $ctwa['sourceId'] ?? null,
                ],
                'conversionSource' => $ctwa['conversionSource'] ?? 'FB_Post',
                'entryPointConversionApp' => $ctwa['sourceApp'] ?? '',
            ];
        } else {
            $FB = $decodedData['contextInfo'] ?? [];
        }


        //verificar se title body sourceUrl sourceId se estão vazios se tiver retorna false
        if (empty($FB['externalAdReply']['sourceUrl']) || empty($FB['externalAdReply']['sourceId'])) {
            return false; // Não processa se os campos essenciais estiverem vazios
        }



        // Verifica se o sourceUrl é link custom e extrai inxid
        if (!empty($FB['externalAdReply']['sourceUrl'])) {
            $sourceUrl = $FB['externalAdReply']['sourceUrl'];
            $urlComponents = parse_url($sourceUrl);
            if (isset($urlComponents['query'])) {
                parse_str($urlComponents['query'], $queryParams);
            }
        }

        $conversionSource = $FB['conversionSource'] ?? 'FB_Post';
        $sourceId = $FB['externalAdReply']['sourceId'] ?? null;

        // Se 'inxid' estiver presente na query string
        if (isset($queryParams['inxid'])) {
            $axiomId = $queryParams['inxid'];
        } elseif (preg_match('/^[a-f0-9]{32}$/i', $conversionSource)) {
            $axiomId = $conversionSource;
        }

        // Se houver axiomId, atualiza count na tabela de links
        if (isset($axiomId)) {
            $this->db->where('hash', $axiomId);
            $linkCustom = $this->db->get(db_prefix() . 'contactcenter_links_custom')->row();
            if ($linkCustom) {
                $conversionSource = "ORGANIC";
                $sourceId = $linkCustom->hash;
                $this->db->where('link_id', $linkCustom->link_id);
                $this->db->update(db_prefix() . 'contactcenter_links_custom', [
                    "count" => $linkCustom->count + 1
                ]);
            }
        }

        // Verifica se já existe um registro com mesma sessão e lead_id
        $this->db->where('session', $data["msg_session"]);
        $this->db->where('lead_id', $data["leadid"]);
        $this->db->where('sourceId', $sourceId);
        $meta = $this->db->get(db_prefix() . 'contactcenter_meta')->row();

        if (!$meta) {
            // Verifica se já existe meta_head
            $this->db->where('sourceId', $sourceId);
            $metaHead = $this->db->get(db_prefix() . 'contactcenter_meta_head')->row();

            if (!$metaHead && !empty($FB['externalAdReply']['thumbnailUrl'])) {
                $outputFile = uniqid() . ".jpg";
                $upload_path = FCPATH . "uploads/contactcenter/thumbnailsMeta/" . date("m-Y");
                $pathImage = "uploads/contactcenter/thumbnailsMeta/" . date("m-Y");

                if (!is_dir($upload_path)) mkdir($upload_path, 0777, true);

                $target_file = "{$upload_path}/{$outputFile}";
                $imageContent = @file_get_contents($FB['externalAdReply']['thumbnailUrl']);

                if ($imageContent !== false && file_put_contents($target_file, $imageContent) !== false) {
                    $FB['externalAdReply']['thumbnailUrl'] = "{$pathImage}/{$outputFile}";
                } else {
                    log_activity("Erro ao baixar o conteúdo da imagem para o servidor contactcenter_meta.");
                }

                $this->db->insert(db_prefix() . 'contactcenter_meta_head', [
                    "title" => $FB['externalAdReply']['title'],
                    "body" => $FB['externalAdReply']['body'],
                    "sourceId" => $sourceId,
                    "dev_session" => $data["msg_session"],
                    "thumbnailUrl" => $FB['externalAdReply']['thumbnailUrl'],
                    "sourceUrl" => $FB['externalAdReply']['sourceUrl'],
                    "date" => $data["msg_date"]
                ]);
            }

            // Insere registro na tabela contactcenter_meta
            $this->db->insert(db_prefix() . 'contactcenter_meta', [
                "lead_id" => $data["leadid"],
                "session" => $data["msg_session"],
                "conversionSource" => $conversionSource,
                "title" => $FB['externalAdReply']['title'],
                "body" => $FB['externalAdReply']['body'],
                "mediaType" => $FB['externalAdReply']['mediaType'],
                "thumbnailUrl" => $metaHead->thumbnailUrl ?? $FB['externalAdReply']['thumbnailUrl'],
                "sourceId" => $sourceId,
                "sourceUrl" => $FB['externalAdReply']['sourceUrl'],
                "date" => $data["msg_date"],
                "source" => ($decodedData['_data']['ctwaContext']["sourceApp"] ? $decodedData['_data']['ctwaContext']["sourceApp"] :  $decodedData["source"]),
                "entryPointConversionApp" => $FB['entryPointConversionApp']
            ]);
        }
    }




