    public function insert_contact($data)
    {
        if (!$data) return;

        $rel_type = 'lead';

        if (!$data["client_id"]) {
            $this->db->where('phonenumber', $data["msg_conversation_number"]);
            $this->db->order_by('staffid', 'desc');
            $staff = $this->db->get(db_prefix() . 'staff')->row();
            $rel_type = $staff ? 'staff' : 'lead';
        } else {
            $rel_type = 'customer';
        }

        // Verifica se já existe contato com mesmo telefone e sessão
        $this->db->where('phonenumber', $data["msg_conversation_number"]);
        $this->db->where('session', $data["msg_session"]);
        $contact = $this->db->get(db_prefix() . 'contactcenter_contact')->row();

        $nameContact = null;
        if ($data["msg_isGroupMsg"] && $contact) {
            $nameContact = $contact->name;
        } else {
            $nameContact = ($data["lead_name"] ?  $data["lead_name"] : $data["msg_name"]);
        }

        // Define estrutura de criação
        $crear = [
            "staffid" => $data["staffid"],
            "phonenumber" => $data["msg_conversation_number"],
            "leadid" => $data["leadid"],
            "session" => $data["msg_session"],
            "date" => $data["msg_date"],
            "isGroup" => $data["msg_isGroupMsg"],
            "isread" => isset($contact->isread) ? ($contact->isread + 1) : 1,
            "active" => 1,
            "msg_fromMe" => $data["msg_fromMe"],
            "rel_type" => $rel_type,
            "assigned" => $data["assigned"],
            "name" => $nameContact,
            "client_id" => $data["client_id"],
            "lead_status" => $data["lead_status"],
            "thumb" => ($contact->thumb ? $contact->thumb : $data["profilePicUrl"]),
            "remoteJid" => $data["remoteJid"],
        ];

        // Inicia transação para garantir consistência
        $this->db->trans_start();

        // Insere o novo registro
        $this->db->insert(db_prefix() . 'contactcenter_contact', $crear);
        $insert = $this->db->insert_id();

        if ($insert) {
            // Apaga registros duplicados com ID menor (se existirem)
            $this->db->where('phonenumber', $data["msg_conversation_number"]);
            $this->db->where('session', $data["msg_session"]);
            $this->db->where('id <', $insert);
            $this->db->delete(db_prefix() . 'contactcenter_contact');
        }

        $this->db->trans_complete();

        // Log se houve falha
        if ($this->db->trans_status() === FALSE) {
            //  log_activity("ERRO na função insert_contact: " . json_encode($this->db->error()));
        }
    }








