    /**
     * Faz o block do chatboot 
     */
    public function block_chatboot($data)
    {

        if ($data["msg_from"] == $data["msg_to"]) {
            return true;
        }

        // se ele for o usuario
        if ($data["msg_fromMe"] == 0) {
            return false;
        }

        // Definindo o intervalo de tempo para os últimos 10 minutos
        $ten_minutes_ago = date('Y-m-d H:i:s', strtotime('-20 minutes'));

        $this->db->select("COUNT(msg_id) as message_count");
        $this->db->where('msg_from', $data["msg_from"]);
        $this->db->where('msg_to', $data["msg_to"]);
        $this->db->where('msg_session', $data["msg_session"]);
        $this->db->where('msg_date >=', $ten_minutes_ago);
        $result = $this->db->get(db_prefix() . 'contactcenter_message')->row();
        if ($result->message_count >= 40) {

            $block = ["gpt_status" => 1];
            $this->db->where('id', $data["leadid"]);
            $this->db->update(db_prefix() . 'leads', $block);

            log_activity("Ia bloqueado por excesso de mensagens: " . $data["msg_from"] . " e msg_to: " . $data["msg_to"] . " e session: " . $data["msg_session"] . " e leadid: " . $data["leadid"] . "");

            $this->send_text($data["msg_to"], "Atendimento transferido para um colaborador", $data["staffid"]);
            $this->send_text($data["msg_from"], "Por favor, verifique a conversa com {$data["msg_name"]} {$data["msg_to"]}");
            return true;
        }
    }

    /**
     * Transfor base64 em audio mp3, se passar $ReturnUrl como true ele retorna a url se não retorna o caminho da pasta 
     * @param type $base64
     * @param type $ReturnUrl
     * @return type
     */
    public function convert_base64_audio($base64, $ReturnUrl = false)
    {

        $dado = explode(",", $base64);

        // Decodificar o áudio base64 para dados binários
        $audioData = base64_decode($dado[1]);
        if (!$audioData) {
            $audioData = base64_decode($dado[0]);
        }

        // Verifique se a decodificação foi bem-sucedida
        if ($audioData === false) {
            die('Erro ao decodificar o áudio base64.');
        }

        // Caminho e nome do arquivo MP3 de saída
        $outputFile = uniqid() . ".mp3";
        $upload_path = FCPATH . "uploads/contactcenter/audio/" . date("m-Y");
        //retorna url se $ReturnUrl for true
        $upload_url = "/uploads/contactcenter/audio/" . date("m-Y");

        // Certifique-se de que o diretório de upload exista ou crie-o
        if (!is_dir($upload_path)) {
            mkdir($upload_path, 0777, true);
        }

        $target_file = "{$upload_path}/{$outputFile}";

        // Salvar os dados binários como um arquivo MP3
        $result = file_put_contents($target_file, $audioData);

        if ($result !== false) {
            // Upload bem-sucedido, retorna o caminho relativo do arquivo
            if ($ReturnUrl) {
                return "{$upload_url}/{$outputFile}";
            } else {
                return $target_file;
            }
        } else {
            die('Erro ao salvar o arquivo MP3.');
        }
    }

    public function convert_base64_image($base64)
    {
        // Divida a string base64 em suas partes
        $data = explode(',', $base64);

        // Decodifique a parte que contém a base64
        $imageData = base64_decode($data[1]);

        // Caminho e nome do arquivo de saída
        $outputFile = uniqid() . ".jpg"; // Alterar a extensão conforme o tipo de imagem (ex: .png, .jpeg, etc.)

        // Caminhos de upload
        $upload_url = "/uploads/contactcenter/imagesOpenai/" . date("m-Y");
        $upload_path = FCPATH . "uploads/contactcenter/imagesOpenai/" . date("m-Y");

        // Certifique-se de que o diretório de upload exista ou crie-o
        if (!is_dir($upload_path)) {
            mkdir($upload_path, 0777, true);
        }

        // Caminho completo do arquivo
        $path = "{$upload_path}/{$outputFile}";
        $target_file = "{$upload_url}/{$outputFile}";

        // Salvar os dados binários como um arquivo de imagem
        $result = file_put_contents($path, $imageData);

        if ($result !== false) {
            return $target_file;
        } else {
            die('Erro ao salvar o arquivo de imagem.');
        }
    }



