    /**
     * Faz o insert no banco das mensagem que vai para IA
     * @param type $data
     */
    public function insert_msg_cron_ia($data)
    {

        if ($data["msg_fromMe"] == 0 && $data["msg_isGroupMsg"] == 0) {
            // Check gpt_status - if AI is disabled for this lead, don't queue the message
            if (isset($data["leadid"]) && $data["leadid"]) {
                // Use fresh database query to avoid caching
                $this->db->flush_cache();
                $this->db->where('id', $data["leadid"]);
                $lead = $this->db->get(db_prefix() . 'leads')->row();
                // gpt_status == 1 means AI is OFF, gpt_status == 0 means AI is ON
                if ($lead && $lead->gpt_status == 1) {
                    log_message('debug', "insert_msg_cron_ia SKIP - AI disabled for lead ID: " . $data["leadid"] . ", gpt_status: " . $lead->gpt_status);
                    log_activity("insert_msg_cron_ia SKIP - AI disabled for lead ID: " . $data["leadid"] . ", gpt_status: " . $lead->gpt_status, get_staff_user_id());
                    return false;
                }
            }
            
            $Crear = array(
                "ia_to" => $data["msg_from"],
                "staffid" => $data["staffid"],
                "leadid" => $data["leadid"],
                "msg_id" => $data["msg_id"],
                "ia_content" => $data["msg_content"],
                "ia_session" => $data["msg_session"],
                "ia_date" => date("Y-m-d H:i:s"),
                "ia_type" => $data["ia_type"],
            );
            $this->db->insert(db_prefix() . 'contactcenter_message_ia', $Crear);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                return true;
            }
        }
    }

    /**
     * Pega os leads e agrupa todas as messagem para pegar id
     * @return type
     */
    public function get_lead_msg_openai()
    {
        $this->db->group_by('leadid');
        $result = $this->db->get(db_prefix() . 'contactcenter_message_ia')->result();
        if ($result) {
            return $result;
        }
    }

    /**
     * Pega as mensagem para enviar para IA via Cron
     * @return type
     */
    public function get_msg_openai($leadid)
    {
        // Obter a data e hora atual
        $currentDateTime = date("Y-m-d H:i:s");
        // Calcular a data e hora há menos de um minuto
        $oneMinuteAgo = date("Y-m-d H:i:s", strtotime('-1 minute', strtotime($currentDateTime)));

        // $this->db->where('ia_date <=', $oneMinuteAgo);
        $this->db->where('leadid', $leadid);
        $this->db->order_by('ia_id', "ASC");
        $result = $this->db->get(db_prefix() . 'contactcenter_message_ia')->result();
        if ($result) {
            return $result;
        }
    }

