            $this->db->where('id', $leadid);
            $result = $this->db->get(db_prefix() . 'leads')->row();
            if ($result) {
                return $result;
            }
        }
    }

    /**
     * envia as mensagem pela IA 
     */
    public function cron_send_msg_openai_historico_msg()
    {
        echo "<pre>";
        //Pega os Leads para enviar
        $Users = $this->get_lead_msg_openai();

        if ($Users) {
            foreach ($Users as $User) {
                //pega todas msg menor que 1 minuto
                // $msg = $this->get_msg_openai($User->leadid);


                $this->db->where('msg_conversation_number', $User->ia_to);
                $this->db->where('msg_session', $User->ia_session);
                $this->db->order_by('msg_id', "DESC");
                $this->db->limit(5);
                $msg = $this->db->get(db_prefix() . 'contactcenter_message')->result();

                //inverte a ordem para ficar na ordem correta
                $msg = array_reverse($msg);
                if ($msg && count($msg) > 0) {


                    // Inicializar um array para armazenar os conteúdos
                    $contents = [];

                    //Pega o staffid do da session
                    $device = $this->get_device_token($User->ia_session);

                    // recupero o token do assistente             
                    $assistant = $this->get_assistants_ai($device->assistant_ai_id);
                    if ($assistant) {
                        $assistant_token = $assistant->ai_token;
                    }

                    $model_assitente = $this->get_assistente_model_openai($assistant_token);

                    //pega o dados do cadastro do Lead
                    $lead = $this->get_leads($User->leadid);
                    
            // Check gpt_status - if AI is disabled for this lead, skip processing
            if (!$lead || $lead->gpt_status == 1) {
                // Delete queued messages for this lead since AI is disabled
                foreach ($msg as $row) {
                    $this->db->where('ia_id', $row->ia_id);
                    $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                }
                log_message('debug', "cron_send_msg_openai_historico_msg SKIP - AI disabled for lead ID: " . $User->leadid);
                log_activity("cron_send_msg_openai_historico_msg SKIP - AI disabled for lead ID: " . $User->leadid, get_staff_user_id());
                continue; // Skip to next lead
            }

                    // Inicializar array para armazenar os caminhos dos arquivos de imagem
                    $imagePaths = [];

                    $messagesToSend = []; // ← Array final para enviar no POST

                    foreach ($msg as $row) {


                        $role = $row->msg_fromMe ? "assistant"  : "user"; // ou outro campo que define o role
                        if ($row->msg_fromMe) {
                            $atualizaDataAssistente = date("Y-m-d H:i:s");
                        } else {
                            $atualizaDataAssistente = "";
                        }

                        // Conteúdo da mensagem
                        $contents = [];

                        if ($row->msg_type == "image" &&  $role != "assistant") {
                            if ($model_assitente["model"] == "gpt-3.5-turbo" || $model_assitente["model"] == "gpt-3.5-turbo-1106") {
                                $dataError = [
                                    "device_id" => $device->dev_id,
                                    "lead_id" => ($lead ? $lead->id : null),
                                    "device_token" => $device->dev_token,
                                    "model" => $model_assitente["model"],
                                    "error" => "Modelo não suporta imagens"
                                ];
                                log_activity("Erro na requisição send_msg_openai image: " . json_encode($dataError), get_staff_user_id());
                                continue;
                            }

                            $this->db->where("msg_id", $row->msg_id);
                            $image = $this->db->get(db_prefix() . 'contactcenter_message')->row();

                            if ($image && $image->msg_base64) {
                                $path = $this->convert_base64_image($image->msg_base64);
                                $url = site_url($path);
                                $imagePaths[] = $path;

                                $contents[] = [
                                    "type" => "image_url",
                                    "image_url" => [
                                        "url" => $url
                                    ]
                                ];

                                if (!empty($row->msg_content)) {
                                    $formattedMessage = $atualizaDataAssistente . " {$row->msg_content}";
                                    $contents[] = [
                                        "type" => "text",
                                        "text" => $formattedMessage
                                    ];
                                }
                            }
                        } elseif ($row->msg_type == "text" || $row->msg_type == "ptt") {
                            if (!empty($row->msg_content)) {
                                $formattedMessage =  $atualizaDataAssistente . " {$row->msg_content}";
                                $contents[] = [
                                    "type" => "text",
                                    "text" => $formattedMessage
                                ];
                            }
                        }

                        if ($row->msg_type == "ptt") {
                            $typeAudio = 1;
                        } else {
                            $typeAudio = 0;
                        }


                        // Se houver conteúdo, adiciona no array final
                        if (!empty($contents)) {
                            $messagesToSend[] = [
                                "role" => $role,
                                "content" => $contents
                            ];
                        }
                    }



                    $contentsMSG = $messagesToSend;
                    //  print_r($contentsMSG);              
                    if ($lead) {

                        //Inicia a conversa com a OpenAI
                        if ($device->dev_openai == 1 || $device->dev_openai == 2) {
                            // Refresh lead data to get latest gpt_status (in case it was updated by toggle)
                            $this->db->where('id', $lead->id);
                            $leadFresh = $this->db->get(db_prefix() . 'leads')->row();

                            if ($leadFresh && $leadFresh->gpt_status == 0) {

                                //Verifica se tem historico se não tiver cria 
                                $thread = $this->thread_lead($leadFresh->id, $assistant_token, $model_assitente["model"]);

                                // chucnk de $contentsMSG to maximo 10

                                $sends = [];
                                foreach ($messagesToSend as $contents) {
                                    // sleep(3);
                                    $send = $this->send_msg_openai_historico($thread, $contents, $device->dev_id, $leadFresh->id, $device->dev_token, $model_assitente["model"]);
                                    $sends[] = $send;
                                }

                                // se algum $sends for false nao entra
                                if (!in_array(false, $sends)) {

                                    //apaga a msg depos de enviar
                                    $this->db->where('leadid', $User->leadid);
                                    $this->db->where('ia_session', $User->ia_session);
                                    $this->db->delete(db_prefix() . 'contactcenter_message_ia');

                                    // Apaga as imagens geradas
                                    foreach ($imagePaths as $path) {
                                        unlink(FCPATH . $path);
                                    }

                                    //Pega a mgs e envia para o lead
                                    $result = $this->reply_send_openai($thread, $User->ia_to, $User->staffid, $assistant_token, $typeAudio, $device->dev_id, $leadFresh->id, $device->dev_token, $model_assitente["model"]);
                                }
                            } elseif ($leadFresh && $leadFresh->gpt_status == 1) {
                                //apaga a msg depos de enviar
                                foreach ($msg as $row) {
                                    $this->db->where('ia_id', $row->ia_id);
                                    $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                                }

                                // Apaga as imagens geradas
                                foreach ($imagePaths as $path) {
                                    unlink(FCPATH . $path);
                                }
                            }
                        }
                    } else {
                        //apaga a msg depos de enviar
                        foreach ($msg as $row) {
                            $this->db->where('ia_id', $row->ia_id);
                            $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                        }

                        // Apaga as imagens geradas
                        foreach ($imagePaths as $path) {
                            unlink(FCPATH . $path);
                        }
                    }
                }
            }
        }
    }



    /**
     * envia as mensagem pela IA 
     */
    public function cron_send_msg_openai()
    {
        //Pega os Leads para enviar
        $Users = $this->get_lead_msg_openai();

        if ($Users) {
            foreach ($Users as $User) {
                //pega todas msg menor que 1 minuto
                $msg = $this->get_msg_openai($User->leadid);
                if ($msg && count($msg) > 0) {
                    // Inicializar um array para armazenar os conteúdos
                    $contents = [];

                    //Pega o staffid do da session
                    $device = $this->get_device_token($User->ia_session);

                    // recupero o token do assistente             
                    $assistant = $this->get_assistants_ai($device->assistant_ai_id);
                    if ($assistant) {
                        $assistant_token = $assistant->ai_token;
                    }

                    $model_assitente = $this->get_assistente_model_openai($assistant_token);

                    //pega o dados do cadastro do Lead
                    $lead = $this->get_leads($User->leadid);
                    
                    // Check gpt_status - if AI is disabled for this lead, skip processing
                    if (!$lead || $lead->gpt_status == 1) {
                        // Delete queued messages for this lead since AI is disabled
                        foreach ($msg as $row) {
                            $this->db->where('ia_id', $row->ia_id);
                            $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                        }
                        log_message('debug', "cron_send_msg_openai SKIP - AI disabled for lead ID: " . $User->leadid);
                        log_activity("cron_send_msg_openai SKIP - AI disabled for lead ID: " . $User->leadid, get_staff_user_id());
                        continue; // Skip to next lead
                    }

                    // Inicializar array para armazenar os caminhos dos arquivos de imagem
                    $imagePaths = [];

                    foreach ($msg as $row) {


                        if ($row->ia_type == 2) {

                            if ($model_assitente["model"] == "gpt-3.5-turbo" || $model_assitente["model"] == "gpt-3.5-turbo-1106") {

                                $dataError = [
                                    "device_id" => $device->dev_id,
                                    "lead_id" => ($lead ? $lead->id : null),
                                    "device_token" => $device->dev_token,
                                    "model" => $model_assitente["model"],
                                    "error" => "Modelo não suporta imagens"
                                ];

                                // salvo o erro na activity log
                                log_activity("Erro na requisição send_msg_openai image: " . json_encode($dataError), get_staff_user_id());
                                continue;
                            }

                            $dateTime = date("Y-m-d H:i:s");

                            $this->db->where("msg_id", $row->msg_id);
                            $image = $this->db->get(db_prefix() . 'contactcenter_message')->row();
                            if ($image->msg_base64) {
                                $path = $this->convert_base64_image($image->msg_base64);
                                $url = site_url($path);

                                // Armazena o caminho da imagem gerada
                                $imagePaths[] = $path;

                                $contents[] = [
                                    "type" => "image_url",
                                    "image_url" => [
                                        "url" => $url
                                    ],

                                ];

                                // Adiciona o conteúdo de texto, se existir
                                if ($row->ia_content != null && $row->ia_content != "") {
                                    $contents[] = [
                                        "type" => "text",
                                        "text" => $row->ia_content
                                    ];
                                }
                            }
                        }

                        if ($row->ia_type == 0 || $row->ia_type == 1) {
                            if ($row->ia_content != null && $row->ia_content != "") {
                                $formattedMessage = $row->ia_content;
                                $row->ia_content = $formattedMessage;
                                $contents[] = [
                                    "type" => "text",
                                    "text" => $row->ia_content
                                ];
                            }
                        }
                        $typeAudio = $row->ia_type;
                    }

                    $contentsMSG = $contents;


                    if ($lead) {
                        //Inicia a conversa com a OpenAI
                        if ($device->dev_openai == 1 || $device->dev_openai == 2) {
                            // Refresh lead data to get latest gpt_status (in case it was updated by toggle)
                            // Use flush_cache to ensure we get fresh data from database (no caching)
                            $this->db->flush_cache();
                            $this->db->where('id', $lead->id);
                            $leadFresh = $this->db->get(db_prefix() . 'leads')->row();
                            
                            // Log for debugging - check what gpt_status we have
                            if ($leadFresh) {
                                log_message('debug', "Webhook AI Check - Lead ID: {$leadFresh->id}, Phone: " . ($data['msg_from'] ?? 'N/A') . ", gpt_status: {$leadFresh->gpt_status}, will process: " . ($leadFresh->gpt_status == 0 ? 'YES' : 'NO'));
                                log_activity("Webhook AI Check - Lead ID: {$leadFresh->id}, Phone: " . ($data['msg_from'] ?? 'N/A') . ", gpt_status: {$leadFresh->gpt_status}, will process: " . ($leadFresh->gpt_status == 0 ? 'YES' : 'NO'), get_staff_user_id());
                            } else {
                                log_message('error', "Webhook AI Check ERROR - Lead not found! Lead ID: {$lead->id}");
                                log_activity("Webhook AI Check ERROR - Lead not found! Lead ID: {$lead->id}", get_staff_user_id());
                            }
                            
                            // Only process AI if gpt_status == 0 (AI is ON)
                            // gpt_status == 1 means AI is OFF, so skip processing
                            if ($leadFresh && $leadFresh->gpt_status == 0) {
                                //Verifica se tem historico se não tiver cria 
                                $thread = $this->thread_lead($leadFresh->id, $assistant_token, $model_assitente["model"]);

                                // chucnk de $contentsMSG to maximo 10
                                $finalContent = array_chunk($contentsMSG, 10);
                                $sends = [];
                                foreach ($finalContent as $contents) {
                                    $send = $this->send_msg_openai($thread, $contents, $device->dev_id, $leadFresh->id, $device->dev_token, $model_assitente["model"]);
                                    // sleep(3);
                                    $sends[] = $send;
                                }

                                // se algum $sends for false nao entra
                                if (!in_array(false, $sends)) {

                                    //apaga a msg depos de enviar
                                    foreach ($msg as $row) {
                                        $this->db->where('ia_id', $row->ia_id);
                                        $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                                    }

                                    // Apaga as imagens geradas
                                    foreach ($imagePaths as $path) {
                                        unlink(FCPATH . $path);
                                    }

                                    //Pega a mgs e envia para o lead
                                    $result = $this->reply_send_openai($thread, $User->ia_to, $User->staffid, $assistant_token, $typeAudio, $device->dev_id, $leadFresh->id, $device->dev_token, $model_assitente["model"]);
                                }
                            } elseif ($leadFresh && $leadFresh->gpt_status == 1) {
                                //apaga a msg depos de enviar
                                foreach ($msg as $row) {
                                    $this->db->where('ia_id', $row->ia_id);
                                    $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                                }

                                // Apaga as imagens geradas
                                foreach ($imagePaths as $path) {
                                    unlink(FCPATH . $path);
                                }
                            }
                        }
                    } else {
                        //apaga a msg depos de enviar
                        foreach ($msg as $row) {
                            $this->db->where('ia_id', $row->ia_id);
                            $this->db->delete(db_prefix() . 'contactcenter_message_ia');
                        }

                        // Apaga as imagens geradas
                        foreach ($imagePaths as $path) {
                            unlink(FCPATH . $path);
                        }
                    }
                }
            }
        }
    }

    /**
     * Cria o Thread para o Hitorico do lead
     * 
     */

    function thread_lead($lead_id, $ai_key, $ai_model)
    {

        if ($lead_id) {
            $this->db->where("lead_id", $lead_id);
            $this->db->where("ai_key", $ai_key);
            $this->db->where("ai_model", $ai_model);
            $result = $this->db->get(db_prefix() . 'contactcenter_thread')->row();
            if ($result) {
                return $result->thread_id;
            } else {
                $thread = $this->crearThreadsOpenai();
                if ($thread) {
                    $data = [
                        "lead_id" => $lead_id,
                        "thread_id" => $thread,
                        "ai_key" => $ai_key,
                        "ai_model" => $ai_model,
                        "date" => date("Y-m-d H:i:s"),
                    ];
                    $this->db->insert(db_prefix() . 'contactcenter_thread', $data);
                    $insert_id = $this->db->insert_id();

                    return $thread;
                } else {
                    return false;
                }
            }
        }
    }

    /**
