    public function insert_send_chat($decodedData)
    {
        $decodedData = json_decode($decodedData, true);
        $data = array(
            "msg_wook" => "SEND_MESSAGE",
            "msg_isread" => 1,
            "msg_type" => $decodedData["response"]["data"][0]["type"],
            "msg_fromMe" => $decodedData["response"]["data"][0]["fromMe"],
            "msg_send_id" => $decodedData["response"]["data"][0]["id"],
            "msg_session" => $decodedData["device"]["device_token"],
            "msg_isGroupMsg" => $decodedData["response"]["data"][0]["isGroupMsg"],
            "msg_name" => $decodedData["response"]["data"][0]["sender"]["verifiedName"],
            "msg_to" => str_replace("@c.us", "", $decodedData["response"]["data"][0]["to"]),
            "msg_from" => str_replace("@c.us", "", $decodedData["response"]["data"][0]["from"]),
            "msg_content" => $decodedData["response"]["data"][0]["body"],
            "msg_status" => $decodedData["device"]["status"],
            "msg_date" => date('Y-m-d H:i:s')
