                //dados da conversa
                $chat = $this->get_chat_whats_banco($insert_id);
                if ($lead) {
                }
                return true;
            }
        }
    }

    /**
     * Atualiza o thread no leads
     * @param type $leadId
     * @param type $thread
     * @return bool
     */
    public function leads_updade_thread($leadId, $thread, $model_assitente)
    {
        $data = [
            "gpt_thread" => $thread,
            "gpt_thread_model" => $model_assitente
        ];
        $this->db->where('id', $leadId);
        $this->db->update(db_prefix() . 'leads', $data);
        if ($this->db->affected_rows() > 0) {
            return true;
        }
    }

    /**
     * Pega uma conversa no banco 
     * @param type $id
     * @return type
     */
    public function get_chat_whats_banco($id)
    {
        if ($id) {
            $this->db->like('msg_id', $id);
            return $this->db->get(db_prefix() . 'contactcenter_message')->row();
        }
    }

    /**
     * Faz vericação se leads ou cliente e da insert no banco 
     * @param type $data
     */
    public function insert_leads_whatsapp($data)
    {
        // Verificar se a msg é do sistema ou leads
        if ($data["msg_isGroupMsg"] == 0) {

            $phonenumber = ($data["msg_fromMe"] == 0 ? $data["msg_from"] : $data["msg_to"]);
            $name = ($data["msg_fromMe"] == 0 ? $data["msg_name"] : $phonenumber);

            // // Verifica se já um Cliente
            // $this->db->where('phonenumber', $phonenumber);
            // $client = $this->db->get(db_prefix() . 'clients')->row();
            // if ($client) {
            //     return false;
            // }

            // Verifica se já um Staff
            $this->db->where('phonenumber', $phonenumber);
            $staff = $this->db->get(db_prefix() . 'staff')->row();
            if ($staff) {
                return false;
            }

            // Verifica se já um leads
            //$this->db->like('phonenumber', $data["msg_from"]);
            $this->db->where('phonenumber', $phonenumber);
            $lead = $this->db->get(db_prefix() . 'leads')->row();
            if ($lead) {
                //atualiza o reply se foi a IA que começou a conversa                
                if ($lead->conversation_engine_id && $lead->conversation_engine_send_reply == "") {
                    $UpdadeLead = [
                        "reply" => true,
                        "lead_id" => $lead->id,
                        "con_id" => $lead->conversation_engine_id,
                        "lastcontact" => date("Y-m-d H:i:s"),
                    ];
                    $this->updade_lead($UpdadeLead);
                }

                if ($data["msg_fromMe"] == 0) {
                    if ($lead->name == $phonenumber) {
                        $Crear = ["name" => ($name != "" ? $name : $phonenumber)];
                    }
                    $this->leads_model->update($Crear, $lead->id);
                }

                return $lead;
            } else {
                //caso não é lead da insert e retorna o cadastro 
                $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
                $custom_id = $custom_fields[0]['id'];
                $creaLead = [
                    "name" => ($name != ""  ? $name : $phonenumber),
                    "phonenumber" => $phonenumber,
                    "status" => get_option('leads_cadastro_contactcenter'),
                    "assigned" => ($data["staffid"] ? $data["staffid"] : 1),
                    "source" => get_option("leads_source_contactcenter"),
                    "gpt_status" => 0,
                    "lastcontact" => date("Y-m-d H:i:s"),
                    "is_whatsapp" => "registered",
                    "custom_fields" => [
                        "leads" => [
                            "$custom_id" => "Whatsapp {$data["campanha"]}"
                        ]
                    ],
                ];
                $id = $this->add_lead($creaLead);

                $this->db->where('id', $id);
                $lead = $this->db->get(db_prefix() . 'leads')->row();
                return $lead;
            }
        }
    }

    /**
     * Pega a data na tabela da agenda e verifica se esta disponivel 
     * @param type $date
     * @param type $staffid
     */
    public function get_date_agenda($date, $staffid)
    {
        // Inicialmente, defina $DataNew como $date
        $DataNew = $date;

        // Inicie um loop do-while para verificar se há um agendamento existente para a data fornecida
        do {
            // Verifique no banco de dados se já existe um evento agendado para a data e o usuário fornecidos
            $this->db->where('start', $DataNew);
            $this->db->where('userid', $staffid);
            $event = $this->db->get(db_prefix() . 'events')->row();

            // Se um evento for encontrado para a data fornecida
            if ($event) {
                // Adicione 1 dia útil à data
                $DataNew = date('Y-m-d H:i:s', strtotime($DataNew . ' +1 day'));
                // Verificar se a nova data cai em um fim de semana (sábado ou domingo)
                $dia_da_semana = date('w', strtotime($DataNew));

                // Se a nova data cair em um sábado, adicionar mais 2 dias para que o agendamento seja na próxima segunda-feira
                if ($dia_da_semana == 6) { // 6 = sábado
                    $DataNew = date('Y-m-d H:i:s', strtotime($DataNew . ' +2 days'));
                }

                // Se a nova data cair em um domingo, adicionar mais 1 dia para que o agendamento seja na próxima segunda-feira
                if ($dia_da_semana == 0) { // 0 = domingo
                    $DataNew = date('Y-m-d H:i:s', strtotime($DataNew . ' +1 day'));
                }
            } else {
                $dia_da_semana = date('w', strtotime($DataNew));
                // Se a nova data cair em um sábado, adicionar mais 2 dias para que o agendamento seja na próxima segunda-feira
                if ($dia_da_semana == 6) { // 6 = sábado
                    $DataNew = date('Y-m-d H:i:s', strtotime($DataNew . ' +2 days'));
                }

                // Se a nova data cair em um domingo, adicionar mais 1 dia para que o agendamento seja na próxima segunda-feira
                if ($dia_da_semana == 0) { // 0 = domingo
                    $DataNew = date('Y-m-d H:i:s', strtotime($DataNew . ' +1 day'));
                }

                // valido se a data ja existe, se ja existe ela volta pro lopp, senao sai
                $this->db->where('start', $DataNew);
                $this->db->where('userid', $staffid);
                $event = $this->db->get(db_prefix() . 'events')->row();
                if ($event) {
                    continue;
                }

                // Se não houver evento na data fornecida, saia do loop
                break;
            }
        } while (true); // Loop até encontrar uma data sem agendamento


        return $DataNew;
    }

    public function get_agenda_current_time($current_date, $staffid)
    {
        $this->db->where('start', $current_date);
        $this->db->where('userid', $staffid);
        $event = $this->db->get(db_prefix() . 'events')->row();

        // retorna a data se existir, mas se for final de semana, nao retorna
        if ($event) {
            return $current_date;
        } else {
            return null;
        }
    }

    /**
     * Faz o agendamento na agenda do CRM 
     * @param type $date
     * @param type $phonenumber
     * @param type $staffid
     * @return bool
     */
    public function insert_time_agenda($date, $phonenumber, $staffid, $reagendamento = false, $minutes_schedule = 0)
    {

        if ($phonenumber) {
            //$this->db->like('phonenumber', $phonenumber);
            $this->db->where('phonenumber', $phonenumber);
            $lead = $this->db->get(db_prefix() . 'leads')->row();
        }
        if ($staffid) {
            $this->db->where('staffid', $staffid);
            $user = $this->db->get(db_prefix() . 'staff')->row();
        }

        //se for reagendamento apaga o registro antigo 
        if ($reagendamento) {
            $dia = date("Y-m-d H:i:s");
            $this->db->where('lead_id', $lead->id);
            $this->db->where('start >=', "{$dia}");
            $this->db->delete(db_prefix() . 'events');
        }

        // valido se ja existe um agendamento pra esse horario pra esse usuario
        $this->db->where('start', $date);
        $this->db->where('userid', $staffid);
        $event = $this->db->get(db_prefix() . 'events')->row();
        if ($event) {
            return false;
        }

        $dateTime = date("d-m-Y H:i:s", strtotime($date));

        if ($minutes_schedule > 0) {
            $hour = strtotime($date . " +{$minutes_schedule} minutes");
        } else {
            $hour = strtotime($date . " +1 hour");
        }

        $dateEnd = date("Y-m-d H:i:s", $hour);
        $text = "Call agendada via Whatsapp, Lead:#{$lead->id}, {$lead->name} - dia $dateTime";
        $data["userid"] = $staffid;
        $data["description"] = $text;
        $data["title"] = get_option("contac_title_agendamento");
        $data["start"] = $date;
        $data["end"] = $dateEnd;
        $data["color"] = "#28B8DA";
        $data["reminder_before"] = 30;
        $data["reminder_before_type"] = "minutes";
        $data["rel_id"] = $lead->id;
        $data["status"] = 1;
        $data["public"] = 1;
        $data["rel_type"] = "lead";


        $agendaAxiom = get_modules_active('agenda_axiom');
        if (version_compare($agendaAxiom->installed_version, '1.1.2', '>=')) {
            $data["end"] = date("H:i", strtotime($dateEnd));
            $data['meetLink'] = 0;
            // Verifica se o link de reunião está ativo
            if (get_option("contac_active_link_call")) {
                $data['meetLink'] = 1;
            }
            $this->load->model('agenda_axiom/agenda_axiom_model');
            $response = $this->agenda_axiom_model->event($data);
            if ($response) {
                $status = [
                    "status" =>  get_option("leads_cadastro_call_contactcenter"),
                    "leadid" => $lead->id,
                ];
                $statusRead = $this->leads_model->update_lead_status($status);
                if ($statusRead) {
                    //avisa o staff 
                    try {
                        $this->db->where('dev_type', 1);
                        $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
                        if ($device) {
                            if ($user->phonenumber) {
                                $this->send_text($user->phonenumber, $text, $staffid = null, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'crm');
                            }
                        }
                    } catch (Exception $e) {
                        log_activity("Erro ao enviar mensagem de agendamento: " . $e->getMessage(), get_staff_user_id());
                    }
                }

                return $response;
            }
            return false;
        } else {
            $data["end"] = $dateEnd;
            $this->db->insert(db_prefix() . 'events', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {

                $status = [
                    "status" =>  get_option("leads_cadastro_call_contactcenter"),
                    "leadid" => $lead->id,
                ];
                $statusRead = $this->leads_model->update_lead_status($status);
                if ($statusRead) {
                    //avisa o staff 
                    try {
                        $this->db->where('dev_type', 1);
                        $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
                        if ($device) {
                            $this->send_text($user->phonenumber, $text);
                        }
                    } catch (Exception $e) {
                        log_activity("Erro ao enviar mensagem de agendamento: " . $e->getMessage(), get_staff_user_id());
                    }

                    return true;
                }
                return true;
            } else {
                return false;
            }
        }
    }


    public function verificar_agendamento_lead($phonenumber)
    {

        if ($phonenumber) {
            //$this->db->like('phonenumber', $phonenumber);
            $this->db->where('phonenumber', $phonenumber);
            $lead = $this->db->get(db_prefix() . 'leads')->row();
            $lead_id = $lead->id;
        }

        if ($lead_id) {
            $date = date("Y-m-d H:i:s");
            $this->db->where('rel_id', $lead_id);
            $this->db->where('start >=', "{$date}");
            $result = $this->db->get(db_prefix() . 'events')->row();
            if ($result) {
                return $result->start;
            } else {
                return false;
            }
        }
    }

