    //  Script Auto-Update
    // ──────────────────────────────────────────────────

    public function get_script_update_settings($assistant_id)
    {
        $json = get_option('contactcenter_script_autoupdate_' . (int) $assistant_id);
        if (empty($json)) {
            return [
                'enabled'        => 0,
                'frequency_days' => 7,
                'lead_count'     => 50,
                'lead_status_id' => '',
                'notify_staff_id'=> '',
                'last_run_date'  => '',
            ];
        }
        return json_decode($json, true);
    }

    public function save_script_update_settings($assistant_id, $data)
    {
        $key = 'contactcenter_script_autoupdate_' . (int) $assistant_id;
        $current = $this->get_script_update_settings($assistant_id);
        $data['last_run_date'] = isset($current['last_run_date']) ? $current['last_run_date'] : '';
        update_option($key, json_encode($data));
        return true;
    }

    public function run_script_autoupdate($assistant_id, $settings = null)
    {
        if (!$settings) {
            $settings = $this->get_script_update_settings($assistant_id);
        }

        $assistant = $this->get_assistants_ai($assistant_id);
        if (!$assistant) {
            return ['error' => 'Assistant not found'];
        }

        $frequency   = isset($settings['frequency_days']) ? (int) $settings['frequency_days'] : 7;
        $lead_count  = isset($settings['lead_count']) ? (int) $settings['lead_count'] : 50;
        $status_id   = isset($settings['lead_status_id']) ? (int) $settings['lead_status_id'] : 0;
        $notify_staff = isset($settings['notify_staff_id']) ? (int) $settings['notify_staff_id'] : 0;

        $this->db->select('id, phonenumber, name');
        $this->db->from(db_prefix() . 'leads');
        $this->db->where('phonenumber IS NOT NULL', null, false);
        $this->db->where("phonenumber != ''", null, false);
        if ($status_id > 0) {
            $this->db->where('status', $status_id);
        }
        $this->db->order_by('COALESCE(lastcontact, dateadded) DESC', '', false);
        $this->db->limit($lead_count);
        $leads = $this->db->get()->result();

        log_activity('AXIOM Script AutoUpdate: Found ' . count($leads) . ' leads for assistant #' . $assistant_id . ' (status=' . $status_id . ', limit=' . $lead_count . ')');

        if (empty($leads)) {
            log_activity('AXIOM Script AutoUpdate: No leads found for assistant #' . $assistant_id);
            return ['error' => 'No leads found matching criteria'];
        }

        $interactions = [];
        foreach ($leads as $lead) {
            $history = $this->get_chat_history_for_contact($lead->id, 20);
            if (!empty($history)) {
                $interactions[] = [
                    'lead_name' => $lead->name,
                    'messages'  => $history,
                ];
            }
        }

        if (empty($interactions)) {
            log_activity('AXIOM Script AutoUpdate: No conversations found for assistant #' . $assistant_id);
            return ['error' => 'No conversations found'];
        }

        $gemini_api_key = trim(get_option('contactcenter_gemini_api_key'));
        if (empty($gemini_api_key)) {
            $gemini_api_key = trim(get_option('omniu_studio_gemini_api_key'));
        }
        if (empty($gemini_api_key)) {
            return ['error' => 'Gemini API key not configured'];
        }

        $current_instructions = $assistant->instructions ?? '';

        $prompt  = "You are an expert AI assistant optimizer. Your task is to analyze real customer conversations and compare them against the current assistant instructions to propose improvements.\n\n";
        $prompt .= "CURRENT ASSISTANT INSTRUCTIONS:\n" . $current_instructions . "\n\n";
        $prompt .= "REAL CONVERSATIONS FROM THE LAST {$frequency} DAYS (" . count($interactions) . " contacts, " . count($leads) . " leads analyzed):\n";
        $prompt .= json_encode($interactions, JSON_UNESCAPED_UNICODE) . "\n\n";
        $prompt .= "TASK:\n";
        $prompt .= "1. Analyze the real conversations and identify patterns, common questions, objections, and successful resolution strategies.\n";
        $prompt .= "2. Compare these patterns against the current instructions.\n";
        $prompt .= "3. Propose an UPDATED version of the instructions that:\n";
        $prompt .= "   - Keeps the same overall structure and formatting\n";
        $prompt .= "   - Adds new FAQ items based on frequently asked questions found in conversations\n";
        $prompt .= "   - Improves the conversation flow based on what works in real interactions\n";
        $prompt .= "   - Updates objection handling based on real objections found\n";
        $prompt .= "   - Keeps ALL existing function calls and technical integrations intact\n";
        $prompt .= "   - Maintains the same language (Portuguese pt-BR) as the original\n";
        $prompt .= "4. Provide a summary of ALL changes made and WHY (in Portuguese).\n\n";
        $prompt .= "OUTPUT FORMAT:\nReturn ONLY a raw JSON object (no markdown, no code blocks). Start with { and end with }.\n";
        $prompt .= "{\n  \"proposed_script\": \"The full updated instructions text here\",\n  \"summary\": \"Bullet-point summary of changes in Portuguese\"\n}\n";

        $result = contactcenter_call_gemini_api($gemini_api_key, $prompt, true);

        if (isset($result['error'])) {
            log_activity('AXIOM Script AutoUpdate Error: ' . $result['error'] . ' for assistant #' . $assistant_id);
            return $result;
        }

        $proposed_script = isset($result['proposed_script']) ? $result['proposed_script'] : '';
        $summary         = isset($result['summary']) ? $result['summary'] : '';

        if (empty($proposed_script)) {
            log_activity('AXIOM Script AutoUpdate: Empty proposal from Gemini for assistant #' . $assistant_id);
            return ['error' => 'Empty proposal from AI'];
        }

        $table = db_prefix() . 'contactcenter_script_updates';
        if (!$this->db->table_exists($table)) {
            return ['error' => 'Script updates table not found'];
        }

        $this->db->insert($table, [
            'assistant_id'     => $assistant_id,
            'current_script'   => $current_instructions,
            'proposed_script'  => $proposed_script,
            'summary'          => $summary,
            'contacts_analyzed'=> count($interactions),
            'status'           => 'pending',
            'created_at'       => date('Y-m-d H:i:s'),
        ]);
        $update_id = $this->db->insert_id();

        $option_key = 'contactcenter_script_autoupdate_' . $assistant_id;
        $settings['last_run_date'] = date('Y-m-d');
        update_option($option_key, json_encode($settings));

        if ($notify_staff > 0) {
            $assistant_name = $assistant->ai_name ?? 'Assistant #' . $assistant_id;
            $notified = add_notification([
                'description'     => 'contac_script_update_pending',
                'touserid'        => $notify_staff,
                'link'            => 'contactcenter/assistant_edit/' . $assistant_id . '#script-updates',
                'additional_data' => serialize([$assistant_name]),
            ]);
            if ($notified) {
                pusher_trigger_notification([$notify_staff]);
            }
        }

        log_activity('AXIOM Script AutoUpdate: Proposal #' . $update_id . ' created for assistant #' . $assistant_id . ' (' . count($interactions) . ' contacts analyzed)');

        return ['success' => true, 'update_id' => $update_id];
    }

    public function get_pending_script_updates($assistant_id)
    {
        $table = db_prefix() . 'contactcenter_script_updates';
        if (!$this->db->table_exists($table)) {
            return [];
        }
        $this->db->where('assistant_id', (int) $assistant_id);
        $this->db->where('status', 'pending');
        $this->db->order_by('created_at', 'DESC');
        return $this->db->get($table)->result();
    }

    public function get_script_update_history($assistant_id, $limit = 10)
    {
        $table = db_prefix() . 'contactcenter_script_updates';
        if (!$this->db->table_exists($table)) {
            return [];
        }
        $this->db->where('assistant_id', (int) $assistant_id);
        $this->db->where_in('status', ['approved', 'rejected']);
        $this->db->order_by('created_at', 'DESC');
        $this->db->limit($limit);
        return $this->db->get($table)->result();
    }

    public function review_script_update($update_id, $status, $staff_id)
    {
        $table = db_prefix() . 'contactcenter_script_updates';
        if (!$this->db->table_exists($table)) {
            return false;
        }

        $update = $this->db->where('id', (int) $update_id)->get($table)->row();
        if (!$update || $update->status !== 'pending') {
            return false;
        }

        $this->db->where('id', (int) $update_id);
        $this->db->update($table, [
            'status'      => $status,
            'reviewed_by' => (int) $staff_id,
            'reviewed_at' => date('Y-m-d H:i:s'),
        ]);

        if ($status === 'approved') {
            $this->db->where('id', $update->assistant_id);
            $this->db->update(db_prefix() . 'contactcenter_assistants_ai', [
                'instructions'   => $update->proposed_script,
                'last_update'    => date('Y-m-d H:i:s'),
                'staffid_update' => (int) $staff_id,
            ]);

            log_activity('AXIOM Script Update #' . $update_id . ' APPROVED for assistant #' . $update->assistant_id . ' by staff #' . $staff_id);
        } else {
            log_activity('AXIOM Script Update #' . $update_id . ' REJECTED for assistant #' . $update->assistant_id . ' by staff #' . $staff_id);
        }

        return true;
    }

    /**
     * Add or update assistant template
     * @param array $data
     * @return array
     */
    public function save_assistant_template($data)
    {
        $id = isset($data['id']) ? (int) $data['id'] : 0;
        unset($data['id']);
        $data['staffid'] = get_staff_user_id();
        $data['updated_at'] = date('Y-m-d H:i:s');
        if (isset($data['functions']) && is_array($data['functions'])) {
            $data['functions'] = json_encode($data['functions']);
        }
        if ($id) {
            $this->db->where('id', $id);
            $this->db->where('is_system', 0);
            $this->db->update(db_prefix() . 'contactcenter_assistant_templates', $data);
            return ['success' => true, 'id' => $id];
        }
        $data['created_at'] = date('Y-m-d H:i:s');
        $data['is_system'] = 0;
        $this->db->insert(db_prefix() . 'contactcenter_assistant_templates', $data);
        return ['success' => true, 'id' => $this->db->insert_id()];
    }

