    /**
     * Add library media to assistant
     * @param int $assistant_id
     * @param int $media_id
     * @return bool|int
     */
    public function add_library_media_to_assistant($assistant_id, $media_id)
    {
        // Get the library media
        $this->db->where('id', $media_id);
        $this->db->where('is_library', 1);
        $library_media = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->row();
        
        if (!$library_media) {
            return false;
        }
        
        // Check if already added to this assistant
        $this->db->where('assist_id', $assistant_id);
        $this->db->where('file_path', $library_media->file_path);
        $this->db->where('is_library', 0);
        $existing = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->row();
        
        if ($existing) {
            return $existing->id; // Already added
        }
        
        // Create a copy for this assistant (not library)
        $data = [
            'assist_id' => $assistant_id,
            'file_name' => $library_media->file_name,
            'file_path' => $library_media->file_path,
            'file_type' => $library_media->file_type,
            'file_size' => $library_media->file_size,
            'variable_name' => $library_media->variable_name,
            'staffid' => get_staff_user_id(),
            'is_library' => 0,
            'date' => date('Y-m-d H:i:s')
        ];
        
        $this->db->insert(db_prefix() . 'contactcenter_assistants_media', $data);
        $insert_id = $this->db->insert_id();
        
        if ($insert_id) {
            log_activity('Added library media [' . $library_media->file_name . '] to assistant [' . $assistant_id . ']', get_staff_user_id());
            return $insert_id;
        }
        
        return false;
    }

    /**
     * Add assistant media file
     * @param array $data
     * @return int|bool
     */
    public function add_assistant_media($data)
    {
        $data['staffid'] = get_staff_user_id();
        $data['date'] = date('Y-m-d H:i:s');
        // Default to not library (assistant-specific) unless specified
        if (!isset($data['is_library'])) {
            $data['is_library'] = 0;
        }
        $this->db->insert(db_prefix() . 'contactcenter_assistants_media', $data);
        $insert_id = $this->db->insert_id();
        if ($insert_id) {
            $media_type = $data['is_library'] ? 'library' : 'assistant';
            log_activity('Added media file [' . $data['file_name'] . '] to ' . $media_type . ($data['is_library'] ? '' : ' [' . $data['assist_id'] . ']'), get_staff_user_id());
            return $insert_id;
        }
        return false;
    }

    /**
     * Delete assistant media file
     * @param int $media_id
     * @return bool
     */
    public function delete_assistant_media($media_id)
    {
        $this->db->where('id', $media_id);
        $media = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->row();
        
        if ($media) {
            // If it's library media, check if other assistants are using it
            if ($media->is_library == 1) {
                // Check if other assistants are using this file
                $this->db->where('file_path', $media->file_path);
                $this->db->where('id !=', $media_id);
                $other_uses = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->num_rows();
                
                // Only delete physical file if no other assistants are using it
                if ($other_uses == 0) {
                    $file_path = FCPATH . 'uploads/' . $media->file_path;
                    if (file_exists($file_path)) {
                        @unlink($file_path);
                    }
                }
            } else {
                // Assistant-specific media - check if it's used by library or other assistants
                $this->db->where('file_path', $media->file_path);
                $this->db->where('id !=', $media_id);
                $other_uses = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->num_rows();
                
                // Only delete physical file if not used elsewhere
                if ($other_uses == 0) {
                    $file_path = FCPATH . 'uploads/' . $media->file_path;
                    if (file_exists($file_path)) {
                        @unlink($file_path);
                    }
                }
            }
            
            // Delete database record
            $this->db->where('id', $media_id);
            $this->db->delete(db_prefix() . 'contactcenter_assistants_media');
            
            if ($this->db->affected_rows() > 0) {
                $media_type = $media->is_library ? 'library' : 'assistant [' . $media->assist_id . ']';
                log_activity('Deleted media file [' . $media->file_name . '] from ' . $media_type, get_staff_user_id());
                return true;
            }
        }
        return false;
    }

    /**
     * Upload assistant media file with all formats support
     * @param string $path
     * @param int $maxSize
     * @param string $field_name
     * @return array|bool
     */
    public function upload_assistant_media_file($path, $maxSize = null, $field_name = 'media_file')
    {
        // Check if file exists
        if (!isset($_FILES[$field_name]) || $_FILES[$field_name]['error'] !== UPLOAD_ERR_OK) {
            return array('success' => false, 'error' => 'No file uploaded or upload error occurred');
        }

        // Define o caminho do diretório de upload
        $upload_path = FCPATH . "uploads/{$path}/" . date("m-Y");
        $return_path = "{$path}/" . date("m-Y");

        // Se o diretório não existir, cria-o
        if (!is_dir($upload_path)) {
            if (!mkdir($upload_path, 0777, true)) {
                return array('success' => false, 'error' => 'Failed to create upload directory');
            }
        }

        // Verifica se o diretório é gravável
        if (!is_writable($upload_path)) {
            return array('success' => false, 'error' => 'Upload directory is not writable');
        }

        // Configuração para upload com todos os formatos suportados
        $config['upload_path'] = $upload_path;
        $config['file_name'] = uniqid();
        // Permite todos os formatos de mídia
        $config['allowed_types'] = 'jpg|jpeg|png|gif|webp|mp3|wav|ogg|m4a|aac|mp4|avi|mov|wmv|flv|webm|mkv|pdf|doc|docx';
        $config['max_size'] = $maxSize ? $maxSize : (50 * 1024); // Default 50MB
        $config['overwrite'] = false;

        $this->load->library('upload', $config);

        if ($this->upload->do_upload($field_name)) {
            $upload_data = $this->upload->data();
            return array(
                'success' => true,
                'file_path' => $return_path . "/" . $upload_data['file_name']
            );
        } else {
            $error = $this->upload->display_errors('', '');
            return array('success' => false, 'error' => $error);
        }
    }

    /**
     * Upload onboarding knowledge materials (PDF, TXT, DOCX, CSV, JSON, MD)
     * @param int $assistant_id
     * @param int $max_size_bytes Default 10MB
     * @return array ['paths' => [], 'errors' => []]
     */
    public function upload_onboarding_materials($assistant_id, $max_size_bytes = 10485760)
    {
        $allowed_ext = ['txt', 'pdf', 'docx', 'csv', 'json', 'md'];
        $paths = [];
        $errors = [];

        if (!isset($_FILES['materials_files']) || empty($_FILES['materials_files']['name'])) {
            return ['paths' => [], 'errors' => []];
        }

        $files = $_FILES['materials_files'];
        $names = is_array($files['name']) ? $files['name'] : [$files['name']];
        $tmp_names = is_array($files['tmp_name']) ? $files['tmp_name'] : [$files['tmp_name']];
        $errors_arr = is_array($files['error']) ? $files['error'] : [$files['error']];
        $sizes = is_array($files['size']) ? $files['size'] : [$files['size']];

        $upload_path = FCPATH . 'uploads/contactcenter/onboarding_materials/' . $assistant_id . '/' . date('Y-m');
        $return_base = 'contactcenter/onboarding_materials/' . $assistant_id . '/' . date('Y-m');
        if (!is_dir($upload_path)) {
            if (!mkdir($upload_path, 0755, true)) {
                return ['paths' => [], 'errors' => ['Failed to create upload directory']];
            }
        }

        for ($i = 0; $i < count($names); $i++) {
            if ($errors_arr[$i] !== UPLOAD_ERR_OK) {
                $errors[] = ($names[$i] ?? 'file') . ': Upload error';
                continue;
            }
            if ($sizes[$i] > $max_size_bytes) {
                $errors[] = ($names[$i] ?? 'file') . ': File too large (max 10MB)';
                continue;
            }
            $ext = strtolower(pathinfo($names[$i], PATHINFO_EXTENSION));
            if (!in_array($ext, $allowed_ext)) {
                $errors[] = ($names[$i] ?? 'file') . ': Invalid type (allowed: ' . implode(', ', $allowed_ext) . ')';
                continue;
            }
            $safe_name = preg_replace('/[^a-zA-Z0-9._-]/', '_', pathinfo($names[$i], PATHINFO_FILENAME));
            $dest_name = $safe_name . '_' . uniqid() . '.' . $ext;
            $dest_path = $upload_path . '/' . $dest_name;
            if (move_uploaded_file($tmp_names[$i], $dest_path)) {
                $paths[] = $return_base . '/' . $dest_name;
            } else {
                $errors[] = ($names[$i] ?? 'file') . ': Failed to save';
            }
        }

        return ['paths' => $paths, 'errors' => $errors];
    }

    /**
     * Salva o assistente no banco 
     * @param array $data
     * @return bool
     */
    public function get_chat_history_for_contact($contact_id, $limit = 10)
    {
        // This assumes a 'contactcenter_message' table structure. Adjust as needed.
        // We want messages from both sides (fromMe = 0 and 1)
        
        // First, we need to find the phone number associated with this contact/lead ID to query messages
        // Assuming $contact_id is a Lead ID for now based on the controller logic
        $this->db->select('phonenumber');
        $this->db->where('id', $contact_id);
        $lead = $this->db->get(db_prefix() . 'leads')->row();
        
        if (!$lead || empty($lead->phonenumber)) {
            return [];
        }
        
        $phone = $lead->phonenumber;
        
        // Now fetch messages for this phone number
        $this->db->select('msg_content, msg_fromMe');
        // Check if 'date' column exists
        if ($this->db->field_exists('date', db_prefix() . 'contactcenter_message')) {
             $this->db->select('date');
             $this->db->order_by('date', 'DESC');
        } else {
             // Fallback to 'id' if no date column found
             $this->db->order_by('msg_send_id', 'DESC');
        }

        $this->db->from(db_prefix() . 'contactcenter_message');
        $this->db->where('remoteJid', $phone . '@s.whatsapp.net'); // Adjust JID format if needed
        $this->db->or_where('remoteJid', $phone); // Fallback
        
        $this->db->limit($limit);
        
        $query = $this->db->get();
        
        if ($query->num_rows() > 0) {
            $results = $query->result_array();
            // Reverse to chronological order
            return array_reverse($results);
        }
        
        return [];
    }

    public function add_assistant($data)
    {

        if ($data['id'] != "") {
            $id = $data['id'];
            unset($data['id']);

            // Save version history before updating
            $this->save_assistant_version($id, $data);

            $data["last_update"] = date("Y-m-d H:i:s");
            $data["staffid_update"] = get_staff_user_id();


            $assistent = $this->updateOpenAIAssistant($data);
            if ($assistent["id"]) {
                $data["ai_token"] = $assistent["id"];
                $data["model"] = $assistent["model"];
            } else {
                log_activity("Erro ao atualizar assistente: " . json_encode($data), get_staff_user_id());
                set_alert('danger', _l('contac_assistent_error_update'));
                return false;
            }

            if ($data["functions"]) {
                $data["functions"] = json_encode($data["functions"]);
            } else {
                $data["functions"] = null;
            }


            if ($_FILES["file"]["name"]) {

                if (!$data["vector_id"]) {
                    $VectorId =  $this->createVectorStore($data["ai_name"]);
                    $data["vector_id"] = $VectorId["id"];
                }

                $data["vector_id"] =  trim($data["vector_id"]);
                if (!$data["vector_id"]) {
                    log_activity("Erro ao criar o vector: " . json_encode($data), get_staff_user_id());
                    set_alert('danger', _l('contac_assistent_error_vector'));
                    return false;
                }

                //verifica o tipo do arquivo
                $file = $_FILES["file"]["name"];
                $file_type = pathinfo($file, PATHINFO_EXTENSION);
                $file_type = strtolower($file_type);
                $allowed_types = ['txt', 'pdf', 'docx', 'csv', 'json', 'md'];
                if (!in_array($file_type, $allowed_types)) {
                    log_activity("Tipo de arquivo não permitido: {$file_type}" . json_encode($data), get_staff_user_id());
                    set_alert('danger', _l('contac_assistent_error_type_file'));
                    return false;
                }

                $path = FCPATH . "/uploads/" . $this->uploads_media_php("contactcenter/assistants/");
                if ($path) {
                    $fileResponse = $this->uploadFileToOpenAI($path);
                    if (!empty($fileResponse["id"])) {
                        $attachResponse = $this->addFileToVectorStore($data["vector_id"], $fileResponse["id"]);
                        if ($attachResponse["id"]) {
                            $attachResponseVector = $this->attachVectorStoreToAssistant($data["ai_token"], $data["vector_id"]);
                            if ($attachResponseVector["id"]) {
                                //salva o arquivo no banco
                                $saveFile = [
                                    "files_id" => $fileResponse["id"],
                                    "files" => $file,
                                    "assist_id" => $data["ai_token"],
                                    "vector_id" => $data["vector_id"],
                                    "staffid" => get_staff_user_id(),
                                ];
                                $this->db->insert(db_prefix() . 'contactcenter_assistants_files', $saveFile);
                                $insert_id = $this->db->insert_id();
                                if (!$insert_id) {
                                    set_alert('danger', _l('contac_assistent_error_file'));
                                    return false;
                                } else {
                                    set_alert('success', _l('contac_save'));
                                }
                            }
                        }
                    }
                    unlink($path);
                }
            }


            unset($data["file"]);
            $this->db->where('id', $id);
            $this->db->update(db_prefix() . 'contactcenter_assistants_ai', $data);
            if ($this->db->affected_rows() > 0) {
                $result = [
                    "sucesso" => true,
                    "id" => $id,
                ];
                return $result;
            }
        } else {

            //verifica se o plano tem limite de device
            $plan = $this->get_plan();
            $this->db->select('count(id) as total');
            $countAssit = $this->db->get(db_prefix() . 'contactcenter_assistants_ai')->row();
            if ($countAssit->total >= $plan->qtd_assistant) {
                $result = [
                    "sucesso" => false,
                    "limit" => true,
                    "aviso" => _l('contac_assistent_aviso_limit_device'),
                ];
                return $result;
            }


            $template_id = isset($data['template_id']) ? (int) $data['template_id'] : 0;
            unset($data['template_id']);
            if ($template_id) {
                $template = $this->get_assistant_templates($template_id);
                if ($template) {
                    $data["instructions"] = $template->instructions;
                    $data["model"] = $template->model ?: "gpt-4o-mini";
                    if ($template->functions) {
                        $data["functions"] = is_string($template->functions) ? json_decode($template->functions, true) : $template->functions;
                    }
                }
            }
            if (empty($data["instructions"])) {
                $data["instructions"] = "instructions";
            }
            if (empty($data["model"])) {
                $data["model"] = "gpt-4o-mini";
            }
            $data["staffid"] = get_staff_user_id();
            $data["create_date"] = date("Y-m-d H:i:s");
            $data["last_update"] = date("Y-m-d H:i:s");
            $data["staffid_update"] = get_staff_user_id();
            $assistent = $this->createOpenAIAssistant($data);
            if ($assistent["id"]) {
                $data["ai_token"] = $assistent["id"];
                $data["model"] = isset($assistent["model"]) ? $assistent["model"] : $data["model"];
            } else {
                return false;
            }
            if (isset($data["functions"]) && is_array($data["functions"])) {
                $data["functions"] = json_encode($data["functions"]);
            } elseif (empty($data["functions"])) {
                $data["functions"] = null;
            }

            $this->db->insert(db_prefix() . 'contactcenter_assistants_ai', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                $result = [
                    "sucesso" => true,
                    "id" => $insert_id,
                ];
                return $result;
            } else {
                return false;
            }
        }
    }

    /**
     * Save assistant version history before update
     * @param int $assistant_id
     * @param array $new_data New data being saved
     * @return bool
     */
    public function save_assistant_version($assistant_id, $new_data = [])
    {
        // Ensure language is loaded - use current language from globals or session
        $current_lang = isset($GLOBALS['language']) ? $GLOBALS['language'] : (is_staff_logged_in() ? get_staff_default_language() : get_option('active_language'));
        if (!$current_lang) {
            $current_lang = 'english';
        }
        
        // Load language file directly from module path
        $lang_file = module_dir_path('contactcenter') . 'language/' . $current_lang . '/contactcenter_lang.php';
        if (file_exists($lang_file) && !isset($this->lang->language['contac_assistant_change_instructions'])) {
            include($lang_file);
            if (isset($lang) && is_array($lang)) {
                $this->lang->language = array_merge($this->lang->language, $lang);
            }
        }
        
        // Get current assistant data
        $current_assistant = $this->get_assistants_ai($assistant_id);
        if (!$current_assistant) {
            return false;
        }

        // Get next version number
        $this->db->where('assistant_id', $assistant_id);
        $this->db->select_max('version_number');
        $max_version = $this->db->get(db_prefix() . 'contactcenter_assistants_ai_versions')->row();
        $next_version = ($max_version && $max_version->version_number) ? $max_version->version_number + 1 : 1;

        // Calculate changes summary - use lang->line() directly for better compatibility
        $changes = [];
        if (!empty($new_data)) {
            if (isset($new_data['ai_name']) && $new_data['ai_name'] != $current_assistant->ai_name) {
                $lang_name = $this->lang->line('contac_assistant_change_name', false) ?: 'Name';
                $lang_arrow = $this->lang->line('contac_assistant_change_arrow', false) ?: '→';
                $changes[] = $lang_name . ": '{$current_assistant->ai_name}' " . $lang_arrow . " '{$new_data['ai_name']}'";
            }
            if (isset($new_data['model']) && $new_data['model'] != $current_assistant->model) {
                // Map GPT model names to AXIOM version names
                $model_map = [
                    'gpt-4o-mini' => 'Standard',
                    'gpt-4o' => 'Advanced',
                    'gpt-4.1' => 'Pro',
                    'gpt-4.1-mini' => 'Lite',
                    'gpt-4.1-nano' => 'Nano',
                    'gpt-5.1' => 'Next',
                    'gpt-5-pro' => 'Ultra'
                ];
                $old_model_name = isset($model_map[$current_assistant->model]) ? $model_map[$current_assistant->model] : $current_assistant->model;
                $new_model_name = isset($model_map[$new_data['model']]) ? $model_map[$new_data['model']] : $new_data['model'];
                
                $lang_model = $this->lang->line('contac_assistant_change_model', false) ?: 'Model';
                $lang_arrow = $this->lang->line('contac_assistant_change_arrow', false) ?: '→';
                $changes[] = $lang_model . ": '{$old_model_name}' " . $lang_arrow . " '{$new_model_name}'";
            }
            if (isset($new_data['instructions']) && $new_data['instructions'] != $current_assistant->instructions) {
                $lang_instructions = $this->lang->line('contac_assistant_change_instructions', false) ?: 'Instructions updated';
                $changes[] = $lang_instructions;
            }
            if (isset($new_data['functions'])) {
                $old_functions = json_decode($current_assistant->functions ?? '[]', true);
                $new_functions = is_array($new_data['functions']) ? $new_data['functions'] : json_decode($new_data['functions'] ?? '[]', true);
                if (json_encode($old_functions) != json_encode($new_functions)) {
                    $added = array_diff($new_functions, $old_functions);
                    $removed = array_diff($old_functions, $new_functions);
                    if (!empty($added)) {
                        $lang_added = $this->lang->line('contac_assistant_change_functions_added', false) ?: 'Functions added';
                        $changes[] = $lang_added . ": " . implode(', ', $added);
                    }
                    if (!empty($removed)) {
                        $lang_removed = $this->lang->line('contac_assistant_change_functions_removed', false) ?: 'Functions removed';
                        $changes[] = $lang_removed . ": " . implode(', ', $removed);
                    }
                }
            }
            if (isset($new_data['vector_id']) && $new_data['vector_id'] != $current_assistant->vector_id) {
                $lang_vector = $this->lang->line('contac_assistant_change_vector_store', false) ?: 'Vector store updated';
                $changes[] = $lang_vector;
            }
        }

        $lang_no_changes = $this->lang->line('contac_assistant_no_changes', false) ?: 'No changes detected';
        $change_summary = !empty($changes) ? implode('; ', $changes) : $lang_no_changes;

        // Save version snapshot
        $version_data = [
            'assistant_id' => $assistant_id,
            'version_number' => $next_version,
            'ai_name' => $current_assistant->ai_name,
            'ai_token' => $current_assistant->ai_token,
            'model' => $current_assistant->model,
            'instructions' => $current_assistant->instructions,
            'functions' => $current_assistant->functions,
            'vector_id' => $current_assistant->vector_id,
            'active' => 0, // Old version, not active
            'created_by' => get_staff_user_id(),
            'created_at' => date('Y-m-d H:i:s'),
            'change_summary' => $change_summary
        ];

        $this->db->insert(db_prefix() . 'contactcenter_assistants_ai_versions', $version_data);
        return $this->db->insert_id();
    }

    /**
     * Get assistant version history
     * @param int $assistant_id
     * @return array
     */
    public function get_assistant_versions($assistant_id)
    {
        $this->db->where('assistant_id', $assistant_id);
        $this->db->order_by('version_number', 'DESC');
        return $this->db->get(db_prefix() . 'contactcenter_assistants_ai_versions')->result();
    }

    /**
     * Get specific assistant version
     * @param int $version_id
     * @return object|null
     */
    public function get_assistant_version($version_id)
    {
        $this->db->where('id', $version_id);
        return $this->db->get(db_prefix() . 'contactcenter_assistants_ai_versions')->row();
    }

    /**
     * Restore assistant to a previous version
     * @param int $assistant_id
     * @param int $version_id
     * @return bool
     */
    public function restore_assistant_version($assistant_id, $version_id)
    {
        // Get the version to restore
        $version = $this->get_assistant_version($version_id);
        if (!$version || $version->assistant_id != $assistant_id) {
            return false;
        }

        // Get current assistant
        $current_assistant = $this->get_assistants_ai($assistant_id);
        if (!$current_assistant) {
            return false;
        }

        // Save current version before restoring
        $this->save_assistant_version($assistant_id, []);

        // Restore data from version
        $restore_data = [
            'ai_name' => $version->ai_name,
            'model' => $version->model,
            'instructions' => $version->instructions,
            'functions' => $version->functions,
            'vector_id' => $version->vector_id,
            'last_update' => date('Y-m-d H:i:s'),
            'staffid_update' => get_staff_user_id()
        ];

        // Update assistant
        $this->db->where('id', $assistant_id);
        $this->db->update(db_prefix() . 'contactcenter_assistants_ai', $restore_data);

        // Update OpenAI assistant if needed
        if ($current_assistant->ai_token) {
            $update_data = [
                'ai_token' => $current_assistant->ai_token,
                'instructions' => $version->instructions,
                'ai_name' => $version->ai_name,
                'model' => $version->model,
                'functions' => $version->functions ? json_decode($version->functions, true) : []
            ];
            $this->updateOpenAIAssistant($update_data);
        }

        log_activity("Restored assistant [ID: {$assistant_id}] to version {$version->version_number}", get_staff_user_id());
        return true;
    }

    /**
     * Cria um assistente OpenAI
     */
    public function createOpenAIAssistant($data)
    {
        $url = "https://api.openai.com/v1/assistants";

        $data = [
            "instructions" => $data["instructions"],
            "name" => $data["ai_name"],
            "tools" => [["type" => "file_search"]],
            "model" => $data["model"],
        ];

        $headers = [
            "Content-Type: application/json",
            "Authorization: Bearer $this->tokenOpenai",
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }


