    /**
     * Faz o upload de um arquivo para o assistente OpenAI
     */
    public function uploadFileToOpenAI($filePath)
    {
        $url = "https://api.openai.com/v1/files";

        $headers = [
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $postFields = [
            "purpose" => "assistants",
            "file" => new CURLFile($filePath, mime_content_type($filePath), basename($filePath))
        ];

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, $postFields);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }

    /**
     * Deleta um arquivo enviado para a OpenAI
     */
    public function deleteUploadFileToOpenAI($fileId)
    {
        $url = "https://api.openai.com/v1/files/{$fileId}";

        $headers = [
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "DELETE");
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }

    /**
     * Deleta um arquivo do Vector Store e do banco de dados
     */
    public function delete_File_VectorStore($data)
    {
        if ($data) {
            //verifica se existe o registro no banco
            $this->db->where('id', $data["id"]);
            $file = $this->db->get(db_prefix() . 'contactcenter_assistants_files')->row();
            if (!$file) {
                return false;
            }

            $fileOpenai = $this->removeFileFromVectorStore($file->vector_id, $file->files_id);
            if ($fileOpenai["deleted"] == true) {
                $deleteFile = $this->deleteUploadFileToOpenAI($file->files_id);
                if ($deleteFile["deleted"] == true) {
                    //deleta o arquivo no banco
                    $this->db->where('id', $file->id);
                    $this->db->delete(db_prefix() . 'contactcenter_assistants_files');
                    if ($this->db->affected_rows() > 0) {
                        log_activity('Deleted file [' . $file->id . '] Assist [ ' . $file->assist_id . ' ]', get_staff_user_id());
                        return true;
                    }
                }
            }
            return false;
        }
    }

    /**
     * Remove um arquivo do Vector Store
     */
    public function removeFileFromVectorStore($vectorStoreId, $fileId)
    {
        $url = "https://api.openai.com/v1/vector_stores/{$vectorStoreId}/files/{$fileId}";

        $headers = [
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "DELETE");
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }



    /**
     * Anexa um arquivo a um assistente OpenAI
     */
    public function addFileToVectorStore($vectorStoreId, $fileId)
    {
        $url = "https://api.openai.com/v1/vector_stores/{$vectorStoreId}/files";

        $payload = [
            "file_id" => $fileId
        ];

        $headers = [
            "Content-Type: application/json",
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "POST");
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($payload));
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }

    /**
     * Cria um Vector Store na OpenAI
     */
    public function createVectorStore($name)
    {
        $url = "https://api.openai.com/v1/vector_stores";

        $payload = [
            "name" => $name // Nome do Vector Store
        ];

        $headers = [
            "Content-Type: application/json",
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($payload));
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }

    /**
     * Anexa um Vector Store a um assistente OpenAI
     */
    public function attachVectorStoreToAssistant($assistantId, $vectorStoreId)
    {
        $url = "https://api.openai.com/v1/assistants/{$assistantId}";

        $payload = [
            "tool_resources" => [
                "file_search" => [
                    "vector_store_ids" => [$vectorStoreId]
                ]
            ]
        ];

        $headers = [
            "Content-Type: application/json",
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "POST");
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($payload));
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }



    /**
     * Deleta um assistente OpenAI
     */
    public function deleteOpenAIAssistant($assistantId)
    {
        $url = "https://api.openai.com/v1/assistants/" . $assistantId;

        $headers = [
            "Content-Type: application/json",
            "Authorization: Bearer " . $this->tokenOpenai,
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "DELETE");
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true);
    }

    /**
     * deleta o assistant
     * @param type $data
     * @return bool
     */
    public function delete_assistant($data)
    {

        if ($data) {

            // valida se existe assistent em algum device
            $this->db->where('assistant_ai_id', $data["id"]);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            if ($device) {
                return false;
            }

            //pega o assistente
            $this->db->where('id', $data["id"]);
            $assist = $this->db->get(db_prefix() . 'contactcenter_assistants_ai')->row();
            if ($assist) {
                // deleta o assistente na openai
                $response = $this->deleteOpenAIAssistant($assist->ai_token);
                if ($response["deleted"] == true) {
                    $this->db->where('id', $data["id"]);
                    $deleted = $this->db->delete(db_prefix() . 'contactcenter_assistants_ai');
                    if ($deleted) {
                        log_activity('Deleted conversa list [' . $data["id"] . ']', get_staff_user_id());

                        //deleta os arquivos do assistente
                        $this->db->where('assist_id', $data["id"]);
                        $files = $this->db->get(db_prefix() . 'contactcenter_assistants_files')->result();
                        if ($files) {
                            foreach ($files as $file) {
                                $this->deleteUploadFileToOpenAI($file->files_id);
                                $this->db->where('id', $file->id);
                                $this->db->delete(db_prefix() . 'contactcenter_assistants_files');
                            }
                        }

                        return true;
                    }
                }
            }
        }
    }

    /**
