    public function add_group($data)
    {
        if ($data['id'] != "") {
            $id = $data['id'];
            unset($data['id']);
            $this->db->where('id', $id);
            $this->db->update(db_prefix() . 'contactcenter_assistants_ai', $data);
            if ($this->db->affected_rows() > 0) {
                return true;
            }
        } else {
            $this->db->insert(db_prefix() . 'contactcenter_group_api', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {

                // busco o token pelo device
                $device = $this->get_device($data["device_id"]);

                if ($device) {
                    // Get server information
                    $server = $this->get_server($device->server_id);
                    
                    // Check if server uses Evolution API
                    if ($server && $server->api_type == "axiom_evolution") {
                        // Use Evolution API to create group
                        $participants = is_string($data["numbers"]) ? array_map('trim', explode(',', $data["numbers"])) : $data["numbers"];
                        
                        $response = $this->axiom_evolution->create_group_evolution(
                            $server->url,
                            $device->dev_instance_name,
                            $device->dev_token,
                            $data["group_api_name"],
                            $participants
                        );
                        
                        // Evolution API returns group ID in different format
                        if (isset($response['group']['id']) || isset($response['groupId'])) {
                            $group_id = isset($response['group']['id']) ? $response['group']['id'] : $response['groupId'];
                            
                            // Update group ID in database
                            $this->db->where('id', $insert_id);
                            $this->db->update(db_prefix() . 'contactcenter_group_api', ["group_api_id" => $group_id]);
                            
                            // Set group description if provided
                            if (!empty($data["group_api_description"])) {
                                $this->axiom_evolution->set_group_description_evolution(
                                    $server->url,
                                    $device->dev_instance_name,
                                    $device->dev_token,
                                    $group_id,
                                    $data["group_api_description"]
                                );
                            }
                        } else {
                            log_activity("Error creating group with Evolution API: " . json_encode($response));
                        }
                    } else {
                        // Use old API (apigratis) for backward compatibility
                        $response = $this->create_group_api($device->dev_token, $data["group_api_name"], $data["numbers"]);

                        if ($response["response"]["result"]["gid"]["user"]) {
                            // atualizo o id do grupo na tabela
                            $this->db->where('id', $insert_id);
                            $this->db->update(db_prefix() . 'contactcenter_group_api', ["group_api_id" => $response["response"]["result"]["gid"]["user"]]);

                            // crio a descriçao na api
                            $this->create_group_description_api($device->dev_token, $response["response"]["result"]["gid"]["user"], $data["group_api_description"]);
                        }
                    }
                }

                return true;
            }
        }
    }

    public function get_groups($group_id = null)
    {

        if ($group_id) {
            $this->db->where('id', $group_id);
            return $this->db->get(db_prefix() . 'contactcenter_group_api')->row();
        } else {
            return $this->db->get(db_prefix() . 'contactcenter_group_api')->result();
        }
    }

    public function delete_group($data)
    {

        if ($data) {
            $id = $data["id"];
            // valida se existe assistent em algum device
            $this->db->where('id', $data["id"]);
            $group = $this->db->get(db_prefix() . 'contactcenter_group_api')->row();
            if ($group) {

                // busco o token pelo device
                $device = $this->get_device($group->device_id);

                if ($device) {

                    // deleta o grupo no whatsapp
                    $response = $this->leave_group($device->dev_token, $group->group_api_id);

                    if ($response["response"]["messages"] == "SUCCESS") {
                        $this->db->where('id', $data["id"]);
                        $deleted = $this->db->delete(db_prefix() . 'contactcenter_group_api');
                        if ($deleted) {
                            log_activity('Deleted conversa list [' . $id . ']', get_staff_user_id());
                            return true;
                        }
                    }
                }
            }

            return false;
        }
    }

    public function delete_participant_group($data)
    {

        if ($data) {
            $id = $data["id"];
            // valida se existe assistent em algum device
            $this->db->where('id', $data["id"]);
            $group = $this->db->get(db_prefix() . 'contactcenter_group_api')->row();
            if ($group) {

                // busco o token pelo device
                $device = $this->get_device($group->device_id);

                if ($device) {

                    // deleta o grupo no whatsapp
                    $response = $this->delete_participant($device->dev_token, $group->group_api_id, $data["number"]);

                    if ($response["response"]["messages"] == "SUCCESS") {


                        // remove number to string numbers
                        $numbers = explode(",", $group->numbers);
                        $key = array_search($data["number"], $numbers);
                        unset($numbers[$key]);
                        $numbers = implode(",", $numbers);

                        // update column
                        $this->db->where('id', $data["id"]);
                        $this->db->update(db_prefix() . 'contactcenter_group_api', ["numbers" => $numbers]);

                        return true;
                    }
                }
            }

            return false;
        }
    }

    public function get_media_evolution($id)
    {
        if ($id) {
            $this->db->where('msg_send_id', $id);
            $msg = $this->db->get(db_prefix() . 'contactcenter_message')->row();

            $device = $this->get_device_token($msg->msg_session);
            // busco o servidor           
            $server = $this->get_server($device->server_id);

            if ($msg->msg_base64) {

                if (strpos($msg->msg_base64, 'data:audio') === 0) {
                    $src = $msg->msg_base64;
                } else if (strpos($msg->msg_base64, 'data:image') === 0) {
                    $src = $msg->msg_base64;
                } else if (strpos($msg->msg_base64, 'data:video') === 0) {
                    $src = $msg->msg_base64;
                } else if (strpos($msg->msg_base64, 'data:application') === 0) {
                    $src = $msg->msg_base64;
                } else {
                    $src = site_url("{$msg->msg_base64}");
                }

                return [
                    "thumb" => $msg->msg_thumb,
                    "base64" => $src,
                    "type" => $msg->msg_type,
                ];
            }

            // crio a url
            $url = $server->url . "chat/getBase64FromMediaMessage/" . $device->dev_instance_name;

            $response = $this->axiom_evolution->get_media_evolution_base64($url, $msg->msg_send_id, $msg->msg_session);
            if ($response) {

                if ($response["mediaType"] == "audioMessage") {
                    $audio = $this->convert_base64_audio_webhook($response["base64"]);
                    // convertendo para mp3
                    $convertMp3 = $this->api_convert_type_audio(site_url("{$audio}"));
                    if ($convertMp3["url"]) {
                        //excluindo o audio convertido
                        unlink(FCPATH . $audio);
                        //faz o download do audio
                        $data["msg_base64"] = $this->save_audio_from_url($convertMp3["url"]);
                    } else {
                        log_activity('Erro ao converter audio api axiom get_media_evolution_base64()');
                    }
                } else {
                    $data["msg_base64"] = "data:{$response["mimetype"]};base64," . $response["base64"];
                }



                if ($data["msg_base64"]) {
                    $this->db->where('msg_send_id', $id);
                    $this->db->update(db_prefix() . 'contactcenter_message', $data);
                    if ($this->db->affected_rows() > 0) {
                        return [
                            "thumb" => $msg->msg_thumb,
                            "base64" => $data["msg_base64"],
                            "type" => $msg->msg_type,
                        ];
                    }
                } else {
                    return false;
                }
            }
        }
    }


    /*     * ******************************************************************* */
    /*     * *************** Parte do assitente Openai ************************ */

    public function reply_send_openai($thread, $phonenumber, $staffid, $assistant_token, $typeAudio, $device_id, $leadid, $device_token, $model)
    {
        // Check if there's already an active/failed run before starting a new one
        $active_run = $this->check_active_run($thread, $device_id, $leadid, $device_token, $model);
        if ($active_run) {
            $existing_status = isset($active_run["status"]) ? $active_run["status"] : null;
            $existing_run_id = isset($active_run["id"]) ? $active_run["id"] : null;
            
            // If run is already in a terminal state, don't start a new one - exit early
            if (in_array($existing_status, ["completed", "failed", "cancelled", "expired"])) {
                log_activity("reply_send_openai SKIP - Run already in terminal state: {$existing_status}. Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$existing_run_id}", get_staff_user_id());
                return false; // Exit early, don't process failed runs
            }
            
            // If run is active (queued, in_progress, requires_action), use existing run
            if (in_array($existing_status, ["queued", "in_progress", "requires_action"])) {
                log_activity("reply_send_openai USING EXISTING - Run already active: {$existing_status}. Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$existing_run_id}", get_staff_user_id());
                $Runsid = $existing_run_id;
            } else {
                // Start new run
                $Runsid = $this->runsAssistOpenai($thread, $assistant_token, $device_id, $leadid, $device_token, $model);
            }
        } else {
            // No active run, start new one
            $Runsid = $this->runsAssistOpenai($thread, $assistant_token, $device_id, $leadid, $device_token, $model);
        }

        if ($Runsid) {
            $max_iterations = 60; // Maximum 60 iterations (2 minutes with 2 second sleep)
            $iteration = 0;

            do {
                $result = $this->getStatusMsgOpenai($Runsid, $thread, $device_id, $leadid, $device_token, $model);

                // Only process requires_action when status is actually "requires_action"
                if (isset($result["status"]) && $result["status"] == "requires_action") {
                    log_activity("reply_send_openai PROCESSING REQUIRES_ACTION - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Iteration: {$iteration}", get_staff_user_id());
                    $this->requires_action($result, $thread, $Runsid, $phonenumber, $staffid, $device_id, $leadid, $device_token, $model);
                    // After submitting tool outputs, wait a bit longer for the run to process
                    sleep(3);
                }

                sleep(2);
                $iteration++;
                
                // Break loop for terminal states (completed, failed, cancelled, expired)
                $status = isset($result["status"]) ? $result["status"] : null;
                if (in_array($status, ["completed", "failed", "cancelled", "expired"])) {
                    log_activity("reply_send_openai COMPLETED - Run finished with status: {$status}. Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Iterations: {$iteration}", get_staff_user_id());
                    break;
                }
                
                // Safety: Break if too many iterations to prevent infinite loops
                if ($iteration >= $max_iterations) {
                    log_activity("reply_send_openai TIMEOUT - Maximum iterations reached. Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Status: " . ($status ?? "unknown"), get_staff_user_id());
                    break;
                }
            } while (true);

            // Get the assistant's response after the run completes
            log_activity("reply_send_openai FETCHING RESPONSE - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, About to call getMessagesOpenai", get_staff_user_id());
            
            try {
                $RespotaOpenai = $this->getMessagesOpenai($thread, $Runsid, $device_id, $leadid, $device_token, $model);
                $original_response = $RespotaOpenai; // Keep original for logging
                
                log_activity("reply_send_openai GETMESSAGES RESULT - Thread: {$thread}, Lead ID: {$leadid}, getMessagesOpenai returned: " . (is_string($RespotaOpenai) ? 'string, length: ' . strlen($RespotaOpenai) : gettype($RespotaOpenai)), get_staff_user_id());
                
                if ($RespotaOpenai === false || empty($RespotaOpenai)) {
                    log_activity("reply_send_openai NO RESPONSE FROM API - Thread: {$thread}, Lead ID: {$leadid}, getMessagesOpenai returned false or empty", get_staff_user_id());
                    return false;
                }
                
                $RespotaOpenai = strip_tags($RespotaOpenai);
                
                // Log the assistant's response and check if any tool calls were made
                log_activity("reply_send_openai ASSISTANT RESPONSE RAW - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Original Length: " . strlen($original_response ?? '') . " chars, After strip_tags: " . strlen($RespotaOpenai ?? '') . " chars, Status: {$status}", get_staff_user_id());
                log_activity("reply_send_openai RESPONSE CONTENT - Thread: {$thread}, Lead ID: {$leadid}, Content: " . substr($RespotaOpenai ?? '', 0, 500), get_staff_user_id());
                log_activity("reply_send_openai RESPONSE CHECK - Thread: {$thread}, Lead ID: {$leadid}, RespotaOpenai exists: " . (isset($RespotaOpenai) ? 'yes' : 'no') . ", Is empty: " . (empty($RespotaOpenai) ? 'yes' : 'no') . ", Is truthy: " . ($RespotaOpenai ? 'yes' : 'no'), get_staff_user_id());
            } catch (Exception $e) {
                log_activity("reply_send_openai EXCEPTION GETTING RESPONSE - Thread: {$thread}, Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                return false;
            }
            
            log_activity("reply_send_openai AFTER TRY-CATCH - Thread: {$thread}, Lead ID: {$leadid}, RespotaOpenai still exists: " . (isset($RespotaOpenai) ? 'yes, length: ' . strlen($RespotaOpenai) : 'no'), get_staff_user_id());
            
            // Get the last few messages from database to see what the assistant saw
            try {
                $lead = $this->get_leads($leadid);
                if ($lead && $lead->phonenumber) {
                    $phoneClean = preg_replace('/[^0-9]/', '', $lead->phonenumber);
                    // Query messages directly using msg_conversation_number (same as get_messages_chat)
                    $this->db->select('m.msg_content, m.msg_fromMe, m.msg_date, m.staffid');
                    $this->db->from(db_prefix() . 'contactcenter_message m');
                    $this->db->where('m.msg_conversation_number', $phoneClean);
                    $this->db->where('m.msg_isGroupMsg', 0); // Only individual conversations
                    $this->db->order_by('m.msg_date', 'DESC');
                    $this->db->limit(5);
                    $recent_msgs = $this->db->get()->result_array();
                    if ($recent_msgs) {
                        log_activity("reply_send_openai RECENT MESSAGES - Thread: {$thread}, Lead ID: {$leadid}, Last 5 messages from DB: " . json_encode($recent_msgs), get_staff_user_id());
                        
                        // Get the last user message (msg_fromMe = 0 or false)
                        $last_user_message = null;
                        foreach ($recent_msgs as $msg) {
                            if (isset($msg['msg_fromMe']) && ($msg['msg_fromMe'] == 0 || $msg['msg_fromMe'] === false)) {
                                $last_user_message = $msg['msg_content'];
                                break;
                            }
                        }
                        // Store for later use
                        $GLOBALS['last_user_message_for_ai'] = $last_user_message;
                    }
                }
            } catch (Exception $e) {
                log_activity("reply_send_openai EXCEPTION IN LOGGING - Thread: {$thread}, Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                // Ignore errors in logging, continue execution
            }
            
            log_activity("reply_send_openai AFTER RECENT MESSAGES QUERY - Thread: {$thread}, Lead ID: {$leadid}, Continuing to tool calls check", get_staff_user_id());
            
            // Check if this run had any tool calls (function calls) - use last $result from loop
            $last_result = $result ?? null;
            if (isset($last_result["required_action"]) && isset($last_result["required_action"]["submit_tool_outputs"])) {
                $tool_calls = $last_result["required_action"]["submit_tool_outputs"]["tool_calls"] ?? [];
                log_activity("reply_send_openai TOOL CALLS DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Tool Calls Count: " . count($tool_calls), get_staff_user_id());
            } else {
                log_activity("reply_send_openai NO TOOL CALLS - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Status: {$status} - Assistant completed without calling any functions. This may indicate the assistant didn't recognize a response that should be saved.", get_staff_user_id());
            }

            log_activity("reply_send_openai AFTER TOOL CALLS CHECK - Thread: {$thread}, Lead ID: {$leadid}, About to validate response", get_staff_user_id());

            // Check if response exists and is not empty before attempting to send
            // Use trim to ensure we're not sending empty/whitespace-only responses
            if (!isset($RespotaOpenai) || $RespotaOpenai === false) {
                log_activity("reply_send_openai NO RESPONSE VARIABLE - Thread: {$thread}, Lead ID: {$leadid}, RespotaOpenai is not set or is false", get_staff_user_id());
                return false;
            }
            
            log_activity("reply_send_openai BEFORE TRIM - Thread: {$thread}, Lead ID: {$leadid}, RespotaOpenai length before trim: " . strlen($RespotaOpenai ?? ''), get_staff_user_id());
            
            $RespotaOpenai = trim($RespotaOpenai);
            
            log_activity("reply_send_openai AFTER TRIM - Thread: {$thread}, Lead ID: {$leadid}, RespotaOpenai length after trim: " . strlen($RespotaOpenai) . ", Is empty: " . (empty($RespotaOpenai) ? 'yes' : 'no'), get_staff_user_id());
            
            // Check if AI response contains instructions to send files (e.g., "1. Enviar o primeiro áudio", "2. Enviar o segundo áudio")
            // If so, try to detect and send the files automatically
            if (!empty($RespotaOpenai) && !empty($leadid) && !empty($device_id)) {
                $device = $this->get_device($device_id);
                if ($device && $device->assistant_ai_id) {
                    // Pattern to detect file sending instructions (e.g., "1. Enviar...", "2. Enviar...", "Enviar o primeiro áudio", etc.)
                    $file_send_patterns = [
                        '/\d+\.\s*(Enviar|enviar)\s+(o|a|os|as)?\s*(primeiro|segundo|terceiro|primeira|segunda|terceira)?\s*(áudio|audio|arquivo|file|mídia|media)/i',
                        '/(Enviar|enviar)\s+(o|a|os|as)?\s*(primeiro|segundo|terceiro|primeira|segunda|terceira)?\s*(áudio|audio|arquivo|file|mídia|media)/i',
                        '/\[Envio dos áudios\]/i',
                        '/\[Enviar\s+(Áudios|áudios|Áudio|áudio|Audios|audios|Audio|audio)\]/i',
                        '/\[Enviar\s+(os|as)?\s*(Áudios|áudios|Áudio|áudio|Audios|audios|Audio|audio)\]/i',
                        '/\[Enviar\s+(arquivo|arquivos|Arquivo|Arquivos|file|files|File|Files)\]/i',
                        '/\[Enviar\s+(mídia|mídias|midia|midias|Mídia|Mídias|Midia|Midias)\]/i',
                        // Patterns for "Vou enviar agora os áudios" / "Vou enviar os áudios"
                        '/(Vou|vou)\s+(enviar|enviar)\s+(agora|now)?\s*(os|as|o|a)?\s*(áudios|áudio|audios|audio|arquivos|arquivo|files|file)/i',
                        '/(Vou|vou)\s+(enviar|enviar)\s+(os|as|o|a)?\s*(áudios|áudio|audios|audio|arquivos|arquivo|files|file)/i',
                        // Patterns for numbered audio references like "1. Primeiro Áudio" or "1. Primeiro Áudio (sobre o sistema)."
                        '/\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio)/i',
                        '/\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio)\s*\(/i',
                        // Pattern for "Vou enviar agora" followed by anything about audio/files
                        '/(Vou|vou)\s+(enviar|enviar)\s+(agora|now).*?(áudio|audio|arquivo|file|mídia|media)/i'
                    ];
                    
                    $has_file_instructions = false;
                    foreach ($file_send_patterns as $pattern) {
                        if (preg_match($pattern, $RespotaOpenai)) {
                            $has_file_instructions = true;
                            break;
                        }
                    }
                    
                    if ($has_file_instructions) {
                        log_activity("reply_send_openai FILE SEND PATTERN DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Response contains file sending instructions, attempting to extract and send media", get_staff_user_id());
                        
                        // Try to get all available media variables from the assistant
                        $this->db->where('assist_id', $device->assistant_ai_id);
                        $available_media = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->result();
                        
                        if ($available_media && count($available_media) > 0) {
                            log_activity("reply_send_openai AVAILABLE MEDIA FOUND - Thread: {$thread}, Lead ID: {$leadid}, Found " . count($available_media) . " media items in assistant", get_staff_user_id());
                            
                            // Sort media by ID to maintain consistent order
                            usort($available_media, function($a, $b) {
                                return $a->id <=> $b->id;
                            });
                            
                            // Check for generic "[Enviar Áudios]" (plural) or "[Enviar Áudio]" (singular) patterns
                            $is_plural_audio_pattern = preg_match('/\[Enviar\s+(Áudios|áudios|Audios|audios)\]/i', $RespotaOpenai);
                            $is_singular_audio_pattern = preg_match('/\[Enviar\s+(Áudio|áudio|Audio|audio)\]/i', $RespotaOpenai);
                            
                            // Also check for "Vou enviar agora os áudios" patterns (plural)
                            if (!$is_plural_audio_pattern) {
                                $is_plural_audio_pattern = preg_match('/(Vou|vou)\s+(enviar|enviar)\s+(agora|now)?\s*(os|as)\s*(áudios|audios)/i', $RespotaOpenai);
                            }
                            
                            // Check for numbered audio references like "1. Primeiro Áudio" - these indicate multiple audios
                            if (!$is_plural_audio_pattern && preg_match('/\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro)\s+(Áudio|áudio|Audio|audio)/i', $RespotaOpenai)) {
                                // Count how many numbered audio references exist
                                preg_match_all('/\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio)/i', $RespotaOpenai, $matches);
                                if (count($matches[0]) > 1) {
                                    $is_plural_audio_pattern = true; // Multiple audios mentioned
                                }
                            }
                            
                            $media_sent = false;
                            
                            // Get lead phone number once
                            $lead = $this->get_leads($leadid);
                            $phonenumber = null;
                            if ($lead && $lead->phonenumber) {
                                $phonenumber = preg_replace('/[^0-9]/', '', $lead->phonenumber);
                            }
                            
                            // If pattern is "[Enviar Áudios]" (plural), send ALL audio files
                            if ($is_plural_audio_pattern && $phonenumber) {
                                log_activity("reply_send_openai PLURAL AUDIO PATTERN DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Sending all audio files", get_staff_user_id());
                                
                                foreach ($available_media as $media) {
                                    $file_ext = strtolower(pathinfo($media->file_path, PATHINFO_EXTENSION));
                                    if (in_array($file_ext, ['mp3', 'wav', 'ogg', 'm4a', 'aac'])) {
                                        $final_url = site_url("uploads/{$media->file_path}");
                                        
                                        log_activity("reply_send_openai SENDING AUDIO - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Variable: {$media->variable_name}", get_staff_user_id());
                                        
                                        $response = $this->send_audio($phonenumber, $final_url, $device->staffid, true, 'AI');
                                        
                                        if ($response && (is_array($response) ? (!isset($response['error']) || !$response['error']) : true)) {
                                            log_activity("reply_send_openai AUTO SEND AUDIO SUCCESS - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}", get_staff_user_id());
                                            $media_sent = true;
                                        } else {
                                            log_activity("reply_send_openai AUTO SEND AUDIO FAILED - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Response: " . json_encode($response), get_staff_user_id());
                                        }
                                        
                                        // Small delay between sending multiple audios
                                        usleep(500000); // 0.5 seconds
                                    }
                                }
                            }
                            // If pattern is "[Enviar Áudio]" (singular), send the FIRST audio file
                            elseif ($is_singular_audio_pattern && $phonenumber) {
                                log_activity("reply_send_openai SINGULAR AUDIO PATTERN DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Sending first audio file", get_staff_user_id());
                                
                                foreach ($available_media as $media) {
                                    $file_ext = strtolower(pathinfo($media->file_path, PATHINFO_EXTENSION));
                                    if (in_array($file_ext, ['mp3', 'wav', 'ogg', 'm4a', 'aac'])) {
                                        $final_url = site_url("uploads/{$media->file_path}");
                                        
                                        log_activity("reply_send_openai SENDING FIRST AUDIO - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Variable: {$media->variable_name}", get_staff_user_id());
                                        
                                        $response = $this->send_audio($phonenumber, $final_url, $device->staffid, true, 'AI');
                                        
                                        if ($response && (is_array($response) ? (!isset($response['error']) || !$response['error']) : true)) {
                                            log_activity("reply_send_openai AUTO SEND AUDIO SUCCESS - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}", get_staff_user_id());
                                            $media_sent = true;
                                        } else {
                                            log_activity("reply_send_openai AUTO SEND AUDIO FAILED - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Response: " . json_encode($response), get_staff_user_id());
                                        }
                                        
                                        break; // Only send the first audio
                                    }
                                }
                            }
                            
                            // Try to match media variables based on order (primeiro, segundo, terceiro) or position (1, 2, 3)
                            // Also handle numbered audio references like "1. Primeiro Áudio", "2. Segundo Áudio"
                            if (!$media_sent) {
                                // First, check if there are numbered audio references (e.g., "1. Primeiro Áudio", "2. Segundo Áudio")
                                // If multiple are found, send all corresponding audios
                                preg_match_all('/\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio)/i', $RespotaOpenai, $numbered_matches);
                                
                                if (!empty($numbered_matches[0]) && count($numbered_matches[0]) > 0 && $phonenumber) {
                                    // Found numbered audio references, send all corresponding audios
                                    log_activity("reply_send_openai NUMBERED AUDIO REFERENCES DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Found " . count($numbered_matches[0]) . " numbered audio references", get_staff_user_id());
                                    
                                    $media_order_map = [
                                        1 => ['primeiro', 'primeira', 'first', '1'],
                                        2 => ['segundo', 'segunda', 'second', '2'],
                                        3 => ['terceiro', 'terceira', 'third', '3']
                                    ];
                                    
                                    // Extract the position numbers from the matches
                                    $positions_to_send = [];
                                    foreach ($numbered_matches[1] as $match) {
                                        foreach ($media_order_map as $index => $keywords) {
                                            if (in_array(strtolower($match), $keywords)) {
                                                $positions_to_send[] = $index;
                                                break;
                                            }
                                        }
                                    }
                                    
                                    // Send all audios that match the numbered references
                                    foreach ($positions_to_send as $position) {
                                        if (isset($available_media[$position - 1])) {
                                            $media = $available_media[$position - 1];
                                            $file_ext = strtolower(pathinfo($media->file_path, PATHINFO_EXTENSION));
                                            
                                            if (in_array($file_ext, ['mp3', 'wav', 'ogg', 'm4a', 'aac'])) {
                                                $final_url = site_url("uploads/{$media->file_path}");
                                                
                                                log_activity("reply_send_openai SENDING NUMBERED AUDIO - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Position: {$position}", get_staff_user_id());
                                                
                                                $response = $this->send_audio($phonenumber, $final_url, $device->staffid, true, 'AI');
                                                
                                                if ($response && (is_array($response) ? (!isset($response['error']) || !$response['error']) : true)) {
                                                    log_activity("reply_send_openai AUTO SEND AUDIO SUCCESS - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}", get_staff_user_id());
                                                    $media_sent = true;
                                                } else {
                                                    log_activity("reply_send_openai AUTO SEND AUDIO FAILED - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Response: " . json_encode($response), get_staff_user_id());
                                                }
                                                
                                                // Small delay between sending multiple audios
                                                usleep(500000); // 0.5 seconds
                                            }
                                        }
                                    }
                                }
                                
                                // If still no media sent, try the original order-based matching
                                if (!$media_sent) {
                                    $media_order_map = [
                                        1 => ['primeiro', 'primeira', 'first', '1'],
                                        2 => ['segundo', 'segunda', 'second', '2'],
                                        3 => ['terceiro', 'terceira', 'third', '3']
                                    ];
                                    
                                    foreach ($media_order_map as $index => $keywords) {
                                        // Check if response mentions this position/keyword
                                        $pattern_check = false;
                                        foreach ($keywords as $keyword) {
                                            if (preg_match('/\b' . preg_quote($keyword, '/') . '\b/i', $RespotaOpenai)) {
                                                $pattern_check = true;
                                                break;
                                            }
                                        }
                                        
                                        if ($pattern_check && isset($available_media[$index - 1]) && $phonenumber) {
                                            $media = $available_media[$index - 1];
                                            
                                            log_activity("reply_send_openai ATTEMPTING AUTO SEND MEDIA - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Variable: {$media->variable_name}, Position: {$index}", get_staff_user_id());
                                            
                                            // Determine media type from file extension
                                            $file_ext = strtolower(pathinfo($media->file_path, PATHINFO_EXTENSION));
                                            $media_type = "image";
                                            if (in_array($file_ext, ['mp4', 'avi', 'mov', 'wmv', 'flv', 'webm', 'mkv'])) {
                                                $media_type = "video";
                                            } elseif (in_array($file_ext, ['mp3', 'wav', 'ogg', 'm4a', 'aac'])) {
                                                $media_type = "audio";
                                            } elseif (in_array($file_ext, ['pdf', 'doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx'])) {
                                                $media_type = "document";
                                            }
                                            
                                            $final_url = site_url("uploads/{$media->file_path}");
                                            $name_parts = explode('/', $media->file_path);
                                            $file_name = end($name_parts);
                                            
                                            // Send the media
                                            if ($media_type == "audio") {
                                                $response = $this->send_audio($phonenumber, $final_url, $device->staffid, true, 'AI');
                                            } else {
                                                $response = $this->send_file($phonenumber, "", $final_url, $media_type, $device->staffid, $file_name);
                                            }
                                            
                                            if ($response && (is_array($response) ? (!isset($response['error']) || !$response['error']) : true)) {
                                                log_activity("reply_send_openai AUTO SEND MEDIA SUCCESS - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Type: {$media_type}", get_staff_user_id());
                                                $media_sent = true;
                                            } else {
                                                log_activity("reply_send_openai AUTO SEND MEDIA FAILED - Thread: {$thread}, Lead ID: {$leadid}, Media ID: {$media->id}, Response: " . json_encode($response), get_staff_user_id());
                                            }
                                        }
                                    }
                                }
                            }
                            
                            if ($media_sent) {
                                log_activity("reply_send_openai FILE INSTRUCTIONS HANDLED - Thread: {$thread}, Lead ID: {$leadid}, Media sent automatically, skipping text response with instructions", get_staff_user_id());
                                // Remove the file sending instructions from the response before sending text
                                // This prevents sending text like "1. Enviar o primeiro áudio" or "[Enviar Áudios]" after the file is sent
                                
                                // Remove bracket patterns like "[Enviar Áudios]" (on their own line or with surrounding text)
                                $RespotaOpenai = preg_replace('/\[Enviar\s+(Áudios|áudios|Áudio|áudio|Audios|audios|Audio|audio|arquivo|arquivos|Arquivo|Arquivos|mídia|mídias|midia|midias|Mídia|Mídias|Midia|Midias)\].*?(\n|$)/i', '', $RespotaOpenai);
                                
                                // Remove "Vou enviar agora os áudios" patterns
                                $RespotaOpenai = preg_replace('/(Vou|vou)\s+(enviar|enviar)\s+(agora|now)?\s*(os|as|o|a)?\s*(áudios|áudio|audios|audio|arquivos|arquivo|files|file).*?(\n|$)/i', '', $RespotaOpenai);
                                
                                // Remove numbered audio references like "1. Primeiro Áudio (sobre o sistema)."
                                $RespotaOpenai = preg_replace('/^\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio).*?(\n|$)/im', '', $RespotaOpenai);
                                
                                // Remove other file sending patterns
                                foreach ($file_send_patterns as $pattern) {
                                    $RespotaOpenai = preg_replace($pattern . '.*?(\n|$)', '', $RespotaOpenai);
                                }
                                // Also remove lines that match numbered list patterns for file sending
                                $RespotaOpenai = preg_replace('/^\d+\.\s*(Enviar|enviar).*?(\n|$)/im', '', $RespotaOpenai);
                                
                                // Remove any remaining standalone bracket patterns
                                $RespotaOpenai = preg_replace('/\s*\[Enviar\s+(Áudios|áudios|Áudio|áudio|Audios|audios|Audio|audio|arquivo|arquivos|Arquivo|Arquivos|mídia|mídias|midia|midias|Mídia|Mídias|Midia|Midias)\]\s*/i', '', $RespotaOpenai);
                                
                                $RespotaOpenai = trim($RespotaOpenai);
                                
                                // If after removing instructions, the response is empty or only contains punctuation/emojis, don't send it
                                if (empty($RespotaOpenai) || preg_match('/^[\s\p{P}\p{So}]*$/u', $RespotaOpenai)) {
                                    log_activity("reply_send_openai RESPONSE CLEANED - Thread: {$thread}, Lead ID: {$leadid}, Response is empty after removing file instructions, not sending text", get_staff_user_id());
                                    return true; // Return true because we sent the media successfully
                                }
                            }
                        } else {
                            log_activity("reply_send_openai NO MEDIA FOUND - Thread: {$thread}, Lead ID: {$leadid}, Response mentions sending files but no media found in assistant", get_staff_user_id());
                        }
                    }
                }
                
                // Proactive check: Remove numbered audio references even if we didn't detect recent audios
                // This catches cases where the AI mentions "1. Áudio 1", "2. Áudio 2", "1. Primeiro Áudio", etc. in the response
                // These are typically just references to files that should have been sent via send_media function
                if (preg_match('/\d+\.\s*(Áudio|áudio|Audio|audio|Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro)/i', $RespotaOpenai)) {
                    log_activity("reply_send_openai PROACTIVE CLEANUP - Thread: {$thread}, Lead ID: {$leadid}, Found numbered audio references in response, removing them", get_staff_user_id());
                    
                    // Remove numbered audio references like "1. Áudio 1", "2. Áudio 2"
                    $RespotaOpenai = preg_replace('/^\d+\.\s*<strong>?\s*(Áudio|áudio|Audio|audio)\s*\d+\s*<\/strong>?.*?(\n|$)/im', '', $RespotaOpenai);
                    $RespotaOpenai = preg_replace('/^\d+\.\s*(Áudio|áudio|Audio|audio)\s*\d+.*?(\n|$)/im', '', $RespotaOpenai);
                    $RespotaOpenai = preg_replace('/\n\s*\d+\.\s*<strong>?\s*(Áudio|áudio|Audio|audio)\s*\d+\s*<\/strong>?\s*\n?/i', "\n", $RespotaOpenai);
                    $RespotaOpenai = preg_replace('/\n\s*\d+\.\s*(Áudio|áudio|Audio|audio)\s*\d+\s*\n?/i', "\n", $RespotaOpenai);
                    $RespotaOpenai = preg_replace('/\d+\.\s*<strong>?\s*(Áudio|áudio|Audio|audio)\s*\d+\s*<\/strong>?/i', '', $RespotaOpenai);
                    $RespotaOpenai = preg_replace('/\d+\.\s*(Áudio|áudio|Audio|audio)\s*\d+/i', '', $RespotaOpenai);
                    
                    // Remove numbered audio references like "1. Primeiro Áudio (sobre o sistema)."
                    $RespotaOpenai = preg_replace('/^\d+\.\s*<strong>?\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio).*?(\n|$)/im', '', $RespotaOpenai);
                    $RespotaOpenai = preg_replace('/^\d+\.\s*(Primeiro|Segundo|Terceiro|primeiro|segundo|terceiro|Primeira|Segunda|Terceira|primeira|segunda|terceira)\s+(Áudio|áudio|Audio|audio).*?(\n|$)/im', '', $RespotaOpenai);
                    
                    // Remove "Vou enviar agora os áudios" patterns
                    $RespotaOpenai = preg_replace('/(Vou|vou)\s+(enviar|enviar)\s+(agora|now)?\s*(os|as|o|a)?\s*(áudios|áudio|audios|audio).*?(\n|$)/i', '', $RespotaOpenai);
                    
                    // Clean up multiple consecutive newlines
                    $RespotaOpenai = preg_replace('/\n{3,}/', "\n\n", $RespotaOpenai);
                    $RespotaOpenai = trim($RespotaOpenai);
                    
                    log_activity("reply_send_openai PROACTIVE CLEANUP DONE - Thread: {$thread}, Lead ID: {$leadid}, Text after removal: " . substr($RespotaOpenai, 0, 200), get_staff_user_id());
                }
                
                // Language validation: Remove non-Portuguese/English/Spanish text (like Arabic, Chinese, etc.)
                // This prevents the AI from sending messages in unexpected languages
                if (!empty($RespotaOpenai)) {
                    // Detect Arabic characters (Unicode range: \u0600-\u06FF)
                    if (preg_match('/[\x{0600}-\x{06FF}\x{0750}-\x{077F}\x{08A0}-\x{08FF}\x{FB50}-\x{FDFF}\x{FE70}-\x{FEFF}]/u', $RespotaOpenai)) {
                        log_activity("reply_send_openai ARABIC TEXT DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Removing Arabic characters from response", get_staff_user_id());
                        
                        // Remove Arabic text (keep only Portuguese/English/Spanish characters)
                        // This regex removes Arabic characters while preserving Latin characters, numbers, punctuation, and whitespace
                        $RespotaOpenai = preg_replace('/[\x{0600}-\x{06FF}\x{0750}-\x{077F}\x{08A0}-\x{08FF}\x{FB50}-\x{FDFF}\x{FE70}-\x{FEFF}]+/u', '', $RespotaOpenai);
                        $RespotaOpenai = trim($RespotaOpenai);
                        
                        log_activity("reply_send_openai ARABIC TEXT REMOVED - Thread: {$thread}, Lead ID: {$leadid}, Text after removal: " . substr($RespotaOpenai, 0, 200), get_staff_user_id());
                    }
                    
                    // Also detect and remove other non-Latin scripts (Chinese, Japanese, Korean, etc.)
                    // Keep: Latin (A-Z, a-z), Portuguese accented characters, Spanish characters, numbers, punctuation, whitespace
                    // Remove: Cyrillic, CJK (Chinese/Japanese/Korean), Arabic, Hebrew, etc.
                    if (preg_match('/[\x{0400}-\x{04FF}\x{4E00}-\x{9FFF}\x{3040}-\x{309F}\x{30A0}-\x{30FF}\x{AC00}-\x{D7AF}\x{0590}-\x{05FF}]/u', $RespotaOpenai)) {
                        log_activity("reply_send_openai NON-LATIN TEXT DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Removing non-Latin characters from response", get_staff_user_id());
                        
                        // Remove non-Latin scripts while preserving Latin characters with accents
                        $RespotaOpenai = preg_replace('/[\x{0400}-\x{04FF}\x{4E00}-\x{9FFF}\x{3040}-\x{309F}\x{30A0}-\x{30FF}\x{AC00}-\x{D7AF}\x{0590}-\x{05FF}]+/u', '', $RespotaOpenai);
                        $RespotaOpenai = trim($RespotaOpenai);
                        
                        log_activity("reply_send_openai NON-LATIN TEXT REMOVED - Thread: {$thread}, Lead ID: {$leadid}, Text after removal: " . substr($RespotaOpenai, 0, 200), get_staff_user_id());
                    }
                    
                    // Check if send_media failed and remove references to sending audio/files
                    // This prevents the AI from mentioning that it had problems sending files
                    // Check for patterns like "Parece que estou com problemas para enviar", "problemas para enviar os áudios", etc.
                    if (preg_match('/(Parece que|parece que|Estou com|estou com|Tive|tive|Houve|houve).*?(problemas?|dificuldades?|erro).*?(para|ao|ao tentar).*?(enviar|enviando).*?(áudios?|audios?|arquivos?|files?|mídias?|medias?)/i', $RespotaOpenai)) {
                        log_activity("reply_send_openai MEDIA SEND ERROR MENTION DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Removing mention of media send problems from response", get_staff_user_id());
                        
                        // Remove sentences that mention problems sending media
                        $RespotaOpenai = preg_replace('/(Parece que|parece que|Estou com|estou com|Tive|tive|Houve|houve).*?(problemas?|dificuldades?|erro).*?(para|ao|ao tentar).*?(enviar|enviando).*?(áudios?|audios?|arquivos?|files?|mídias?|medias?|explicativos?|explicative).*?[.!?]?\s*/i', '', $RespotaOpenai);
                        $RespotaOpenai = preg_replace('/(no momento|atualmente|agora).*?[.!?]?\s*/i', '', $RespotaOpenai);
                        
                        // Clean up multiple consecutive newlines and spaces
                        $RespotaOpenai = preg_replace('/\n{3,}/', "\n\n", $RespotaOpenai);
                        $RespotaOpenai = preg_replace('/\s{3,}/', ' ', $RespotaOpenai);
                        $RespotaOpenai = trim($RespotaOpenai);
                        
                        log_activity("reply_send_openai MEDIA SEND ERROR MENTION REMOVED - Thread: {$thread}, Lead ID: {$leadid}, Text after removal: " . substr($RespotaOpenai, 0, 200), get_staff_user_id());
                    }
                }
            }
            
            if (!empty($RespotaOpenai)) {
                log_activity("reply_send_openai PREPARING TO SEND - Thread: {$thread}, Lead ID: {$leadid}, Response exists, Length: " . strlen($RespotaOpenai) . " chars, typeAudio: {$typeAudio}, active_audio: " . get_option("active_audio_contactcenter"), get_staff_user_id());
                
                // Check if this message has already been sent for this run_id to prevent duplicates
                // Each run should only send one message, so we check by run_id and interaction_type
                $already_sent = false;
                if ($this->db->table_exists(db_prefix() . 'contactcenter_ai_interactions') && !empty($Runsid)) {
                    $this->db->where('run_id', $Runsid);
                    $this->db->where('interaction_type', 'message');
                    $this->db->where('lead_id', $leadid);
                    $existing = $this->db->get(db_prefix() . 'contactcenter_ai_interactions')->row();
                    if ($existing) {
                        $already_sent = true;
                        log_activity("reply_send_openai DUPLICATE DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Message already sent for this run (existing ID: {$existing->id}), skipping duplicate send", get_staff_user_id());
                    }
                }
                
                // Log AI message to structured AI interactions table
                try {
                    $last_user_msg = isset($GLOBALS['last_user_message_for_ai']) ? $GLOBALS['last_user_message_for_ai'] : null;
                    unset($GLOBALS['last_user_message_for_ai']); // Clean up
                    
                    // Only log if not already sent (to avoid duplicate logs)
                    if (!$already_sent) {
                        $this->log_ai_interaction(array(
                            'lead_id' => $leadid,
                            'device_id' => $device_id,
                            'thread_id' => $thread,
                            'run_id' => $Runsid,
                            'interaction_type' => 'message',
                            'user_message' => $last_user_msg,
                            'ai_response' => $RespotaOpenai,
                            'raw_input' => isset($recent_msgs) ? json_encode($recent_msgs) : null,
                            'raw_output' => $original_response ?? $RespotaOpenai,
                            'status' => $status ?? 'completed',
                            'context_data' => array(
                                'typeAudio' => $typeAudio,
                                'active_audio' => get_option("active_audio_contactcenter"),
                                'run_status' => $status ?? null
                            )
                        ));
                    }
                } catch (Exception $e) {
                    error_log("Failed to log AI message interaction: " . $e->getMessage());
                }
                
                // If message was already sent, return early to prevent duplicate
                if ($already_sent) {
                    log_activity("reply_send_openai SKIPPING DUPLICATE - Thread: {$thread}, Lead ID: {$leadid}, Run ID: {$Runsid}, Message already sent for this run", get_staff_user_id());
                    return true; // Return true because message was already sent successfully
                }
                
                // Check if audio files were recently sent (within last 30 seconds) and remove numbered audio references
                // This prevents sending text like "1. Áudio 1", "2. Áudio 2" after audio files have been sent
                try {
                    $lead = $this->get_leads($leadid);
                    if ($lead && $lead->phonenumber) {
                        $phoneClean = preg_replace('/[^0-9]/', '', $lead->phonenumber);
                        
                        // Check for recently sent audio/media messages (within last 30 seconds)
                        // Audio messages typically have null or empty msg_content
                        $this->db->select('msg_date, msg_content, msg_type');
                        $this->db->from(db_prefix() . 'contactcenter_message');
                        $this->db->where('msg_conversation_number', $phoneClean);
                        $this->db->where('msg_fromMe', 1);
                        $this->db->where('msg_isGroupMsg', 0);
                        $this->db->group_start();
                        $this->db->where('msg_content IS NULL', null, false);
                        $this->db->or_where('msg_content', '');
                        $this->db->or_where('msg_type', 'audio');
                        $this->db->group_end();
                        $this->db->where('msg_date >=', date('Y-m-d H:i:s', strtotime('-30 seconds')));
                        $this->db->order_by('msg_date', 'DESC');
                        $this->db->limit(5);
                        $recent_audios = $this->db->get()->result();
                        
                        if ($recent_audios && count($recent_audios) > 0) {
                            log_activity("reply_send_openai RECENT AUDIOS DETECTED - Thread: {$thread}, Lead ID: {$leadid}, Found " . count($recent_audios) . " audio messages sent in last 30 seconds, removing numbered audio references from text", get_staff_user_id());
                            
                            // Remove numbered audio references like "1. Áudio 1", "2. Áudio 2", etc.
                            // Pattern: number followed by period, optional space, then "Áudio" or "Audio" followed by number
                            // Match with or without bold tags
                            $RespotaOpenai = preg_replace('/^\d+\.\s*<strong>?\s*(Áudio|áudio|Audio|audio)\s*\d+\s*<\/strong>?.*?(\n|$)/im', '', $RespotaOpenai);
                            $RespotaOpenai = preg_replace('/^\d+\.\s*(Áudio|áudio|Audio|audio)\s*\d+.*?(\n|$)/im', '', $RespotaOpenai);
                            // Also remove standalone lines like "1. Áudio 1" or "2. Áudio 2"
                            $RespotaOpenai = preg_replace('/\n\s*\d+\.\s*<strong>?\s*(Áudio|áudio|Audio|audio)\s*\d+\s*<\/strong>?\s*\n?/i', "\n", $RespotaOpenai);
                            $RespotaOpenai = preg_replace('/\n\s*\d+\.\s*(Áudio|áudio|Audio|audio)\s*\d+\s*\n?/i', "\n", $RespotaOpenai);
                            // Remove inline patterns like "1. Áudio 1" or "2. Áudio 2" (with or without bold)
                            $RespotaOpenai = preg_replace('/\d+\.\s*<strong>?\s*(Áudio|áudio|Audio|audio)\s*\d+\s*<\/strong>?/i', '', $RespotaOpenai);
                            $RespotaOpenai = preg_replace('/\d+\.\s*(Áudio|áudio|Audio|audio)\s*\d+/i', '', $RespotaOpenai);
                            
                            // Clean up multiple consecutive newlines
                            $RespotaOpenai = preg_replace('/\n{3,}/', "\n\n", $RespotaOpenai);
                            $RespotaOpenai = trim($RespotaOpenai);
                            
                            log_activity("reply_send_openai AUDIO REFERENCES REMOVED - Thread: {$thread}, Lead ID: {$leadid}, Text after removal: " . substr($RespotaOpenai, 0, 200), get_staff_user_id());
                            
                            // If response is empty after removing audio references, don't send it
                            if (empty($RespotaOpenai) || preg_match('/^[\s\p{P}\p{So}]*$/u', $RespotaOpenai)) {
                                log_activity("reply_send_openai RESPONSE EMPTY AFTER REMOVAL - Thread: {$thread}, Lead ID: {$leadid}, Not sending empty text after removing audio references", get_staff_user_id());
                                return true; // Return true because audio files were already sent
                            }
                        }
                    }
                } catch (Exception $e) {
                    log_activity("reply_send_openai ERROR CHECKING RECENT AUDIOS - Thread: {$thread}, Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                    // Continue execution even if check fails
                }
                
                //Valida se o audio esta ativo 
                if (get_option("active_audio_contactcenter") == 1) {
                    if ($typeAudio == 1) {

                        // Expressão regular para encontrar links no texto
                        $regexLink = '/\bhttps?:\/\/\S+/i';
                        // Verifica se o texto contém um link se tiver resopnde em texto 
                        if (preg_match($regexLink, $RespotaOpenai)) {
                            //$regex = '/【[^】]*】/';
                            $regex = '/【[^】]*】/u';
                            $textoLimpo = preg_replace($regex, '', $RespotaOpenai);
                            $textoLimpo = str_replace('**', '*', $textoLimpo);
                            $send = $this->send_text($phonenumber, $textoLimpo, $staffid, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'AI');

                            if (!$send["error"]) {
                                return true;
                            }
                            return false;
                        } else {
                            if (get_option("active_audio_contactcenter_elevenlabs") == 1) {

                                $this->db->where("dev_id", $device_id);
                                $voz = $this->db->get(db_prefix() . 'contactcenter_device')->row();
                                if ($voz->dev_voz_id) {
                                    $base64 = $this->crear_audio_elevenlabs($RespotaOpenai, $voz->dev_voz_id);
                                     //log_activity("Error send audio_elevenlabs {$base64}");
                                } else {
                                    $base64 = $this->crear_audio_openai($RespotaOpenai);
                                }
                            } else {
                                $base64 = $this->crear_audio_openai($RespotaOpenai);
                            }

                            $audio = $this->convert_base64_audio_openai($base64);
                            $url = site_url("{$audio}");

                            $sendAudio = $this->send_audio($phonenumber, $url, $staffid, $queue = true, $type_source = 'AI');

                            $error = json_decode($sendAudio, true);
                            //se tiver erro de envio de audio na api brasil, manda texto 
                            if ($error["error"]) {
                                $errorSend = json_encode($error);
                                log_activity("Error send audio device  {$errorSend}");
                                $send = $this->send_text($phonenumber, $RespotaOpenai, $staffid, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'AI');
                            } else {

                                // Exclui o arquivo de audio si ele foi enviado com sucesso
                                $path = FCPATH . "{$audio}";
                                if (file_exists($path)) {
                                    unlink($path);
                                }

                                $errorSend = json_encode($error);
                                log_activity("Enviado send audio device elevenlabs {$errorSend}");
                                return true;
                            }
                        }
                    } else {

                        $regex = '/【[^】]*】/u';
                        $textoLimpo = preg_replace($regex, '', $RespotaOpenai);

                        // Divide o texto por quebra de linha ou parágrafo duplo
                        $mensagens = preg_split("/\n\s*\n|\n/", trim($textoLimpo));

                        $send = ["error" => true]; // Inicializa para evitar erro caso não haja mensagens

                        foreach ($mensagens as $mensagem) {
                            if (!empty(trim($mensagem))) {
                                log_activity("reply_send_openai SENDING TEXT MESSAGE - Thread: {$thread}, Lead ID: {$leadid}, Message: " . substr(trim($mensagem), 0, 200), get_staff_user_id());
                                $send = $this->send_text($phonenumber, trim($mensagem), $staffid, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'AI');
                                log_activity("reply_send_openai SEND RESULT - Thread: {$thread}, Lead ID: {$leadid}, Send result: " . json_encode($send), get_staff_user_id());
                                sleep(1); // Pequeno delay para evitar bloqueios por envio rápido
                            }
                        }

                        if (isset($send) && !$send["error"]) {
                            log_activity("reply_send_openai SUCCESS - Thread: {$thread}, Lead ID: {$leadid}, Message sent successfully", get_staff_user_id());
                            return true;
                        } else {
                            log_activity("reply_send_openai ERROR - Thread: {$thread}, Lead ID: {$leadid}, Failed to send message, Send result: " . json_encode($send ?? "not set"), get_staff_user_id());
                            return false;
                        }
                    }
                } else {

                    $regex = '/【[^】]*】/u';
                    $textoLimpo = preg_replace($regex, '', $RespotaOpenai);

                    // Divide o texto por quebra de linha ou parágrafo duplo
                    $mensagens = preg_split("/\n\s*\n|\n/", trim($textoLimpo));

                    $send = ["error" => true]; // Inicializa para evitar erro caso não haja mensagens
                    $messages_sent = 0;

                    foreach ($mensagens as $mensagem) {
                        if (!empty(trim($mensagem))) {
                            log_activity("reply_send_openai SENDING TEXT MESSAGE (no audio) - Thread: {$thread}, Lead ID: {$leadid}, Message: " . substr(trim($mensagem), 0, 200), get_staff_user_id());
                            $send = $this->send_text($phonenumber, trim($mensagem), $staffid, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'AI');
                            log_activity("reply_send_openai SEND RESULT (no audio) - Thread: {$thread}, Lead ID: {$leadid}, Send result: " . json_encode($send), get_staff_user_id());
                            $messages_sent++;
                            sleep(1); // Pequeno delay para evitar bloqueios por envio rápido
                        }
                    }

                    if ($messages_sent > 0 && !$send["error"]) {
                        log_activity("reply_send_openai SUCCESS (no audio) - Thread: {$thread}, Lead ID: {$leadid}, Messages sent: {$messages_sent}", get_staff_user_id());
                        return true;
                    } else {
                        log_activity("reply_send_openai ERROR (no audio) - Thread: {$thread}, Lead ID: {$leadid}, Messages sent: {$messages_sent}, Send result: " . json_encode($send), get_staff_user_id());
                        return false;
                    }
                }
            } else {
                log_activity("reply_send_openai NO RESPONSE - Thread: {$thread}, Lead ID: {$leadid}, RespotaOpenai is empty or false after trim. Original length was: " . strlen($original_response ?? ''), get_staff_user_id());
                return false;
            }
            //}
        } else {
            log_activity("reply_send_openai NO RUN ID - Thread: {$thread}, Lead ID: {$leadid}, Runsid is false or empty", get_staff_user_id());
            return false;
        }
    }

    //Passo 01
    public function crearThreadsOpenai()
    {


        // URL da API do OpenAI
        $url = "https://api.openai.com/v1/threads";

        // Cabeçalhos da requisição
        $headers = array(
            "Content-Type: application/json",
            "Authorization: Bearer $this->tokenOpenai",
            "OpenAI-Beta: assistants=v2"
        );

        // Configuração da requisição cURL
        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, '');

        // Executa a requisição e obtém a resposta
        $response = curl_exec($ch);

        // Verifica por erros
        if (curl_errno($ch)) {
            echo 'Erro na requisição cURL: ' . curl_error($ch);
        }

        // Fecha a sessão cURL
        curl_close($ch);

        // Exibe a resposta
        $responseArray = json_decode($response, true);
        // Verificar se a decodificação foi bem-sucedida
        if ($responseArray === null) {
            return 'Erro ao decodificar JSON';
        } else {
            // Acessar o campo "status"
            return $responseArray['id'];
        }
    }

    /*
     * Envia a menssagem para o Thread
     * Passo 02
     * adicionar uma mensagem a um tópico
     */



    public function send_msg_openai($THREAD_ID, $Message, $device_id, $leadid, $device_token, $model)
    {

        // valido se message é null ou array igual 0
        if ($Message == null || count($Message) == 0) {
            return false;
        }

        // Check for active runs before adding message
        $active_run = $this->check_active_run($THREAD_ID, $device_id, $leadid, $device_token, $model);
        if ($active_run) {
            $run_id = isset($active_run["id"]) ? $active_run["id"] : null;
            $run_status = isset($active_run["status"]) ? $active_run["status"] : null;
            
            // If run is in requires_action, we need to process function calls first
            if ($run_status == "requires_action" && $run_id) {
                log_activity("send_msg_openai - Run {$run_id} in requires_action status, processing function calls before adding message. Thread: {$THREAD_ID}, Lead ID: {$leadid}", get_staff_user_id());
                
                // Get the full run status to process requires_action
                $result = $this->getStatusMsgOpenai($run_id, $THREAD_ID, $device_id, $leadid, $device_token, $model);
                
                // Get device and lead info for requires_action
                $device = $this->get_device($device_id);
                $lead = $this->get_leads($leadid);
                $phonenumber = $lead ? $lead->phonenumber : null;
                $staffid = $lead ? $lead->assigned : null;
                
                // Process requires_action (this will submit tool outputs)
                if ($result && isset($result["status"]) && $result["status"] == "requires_action") {
                    $this->requires_action($result, $THREAD_ID, $run_id, $phonenumber, $staffid, $device_id, $leadid, $device_token, $model);
                    
                    // Wait for the run to complete after submitting tool outputs
                    $max_wait_after_submit = 60; // Increased wait time for requires_action processing
                    $waited_after_submit = 0;
                    while ($waited_after_submit < $max_wait_after_submit) {
                        sleep(2);
                        $waited_after_submit += 2;
                        $result = $this->getStatusMsgOpenai($run_id, $THREAD_ID, $device_id, $leadid, $device_token, $model);
                        
                        // If still requires_action, process again (in case of multiple function calls)
                        if ($result && isset($result["status"]) && $result["status"] == "requires_action") {
                            $this->requires_action($result, $THREAD_ID, $run_id, $phonenumber, $staffid, $device_id, $leadid, $device_token, $model);
                            $waited_after_submit = 0; // Reset counter when processing new requires_action
                            continue;
                        }
                        
                        // If completed or failed, break
                        if ($result && isset($result["status"]) && in_array($result["status"], ["completed", "failed", "cancelled", "expired"])) {
                            log_activity("send_msg_openai - Run {$run_id} completed with status: {$result['status']}. Thread: {$THREAD_ID}, Lead ID: {$leadid}", get_staff_user_id());
                            break;
                        }
                    }
                    
                    if ($waited_after_submit >= $max_wait_after_submit) {
                        log_activity("send_msg_openai - Run {$run_id} still active after processing requires_action for {$max_wait_after_submit}s. Thread: {$THREAD_ID}, Lead ID: {$leadid}. Proceeding anyway.", get_staff_user_id());
                    }
                }
                
                // Double-check that run is no longer active before proceeding
                $active_run = $this->check_active_run($THREAD_ID, $device_id, $leadid, $device_token, $model);
                if ($active_run) {
                    log_activity("send_msg_openai - Run still active after requires_action processing. Status: " . ($active_run["status"] ?? "unknown") . ". Thread: {$THREAD_ID}, Lead ID: {$leadid}. Waiting additional 10 seconds.", get_staff_user_id());
                    sleep(10);
                    $active_run = $this->check_active_run($THREAD_ID, $device_id, $leadid, $device_token, $model);
                }
            } else {
                // For other active states (queued, in_progress), wait normally
                $max_wait = 30;
                $waited = 0;
                while ($active_run && $waited < $max_wait) {
                    sleep(2);
                    $waited += 2;
                    $active_run = $this->check_active_run($THREAD_ID, $device_id, $leadid, $device_token, $model);
                }
                
                if ($active_run) {
                    log_activity("send_msg_openai - Active run still running after {$max_wait}s for thread {$THREAD_ID}, proceeding anyway", get_staff_user_id());
                }
            }
        }

        // URL da API do OpenAI
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/messages";



        // Cabeçalhos da requisição
        $data = array(
            "role" => "user",
            "content" => $Message
        );

        $headers = array(
            "Content-Type: application/json",
            "Authorization: Bearer $this->tokenOpenai",
            "OpenAI-Beta: assistants=v2"
        );


        // Configuração da requisição cURL
        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));

        // Executa a requisição e obtém a resposta
        $response = curl_exec($ch);

        // Verifica por erros
        if (curl_errno($ch)) {

            // monto objeto pra salvar o erro
            $dataError = [
                "device_id" => $device_id,
                "lead_id" => $leadid,
                "device_token" => $device_token,
                "request" => json_encode($data),
                "model" => $model,
                "error" => curl_error($ch)
            ];

            // salvo o erro na activity log
            log_activity("Erro na requisição send_msg_openai curl_errno linha 3830: " . json_encode($dataError), get_staff_user_id());
        }

        // Fecha a sessão cURL
        curl_close($ch);

        // valido response
        $responseArray = json_decode($response, true);

        if (isset($responseArray["error"])) {
            // Check if error is due to active run
            if (isset($responseArray["error"]["code"]) && strpos($responseArray["error"]["message"], "while a run") !== false) {
                // Active run error - check if it's requires_action and process it
                log_activity("send_msg_openai - Active run error detected, checking run status for thread {$THREAD_ID}, Lead ID: {$leadid}", get_staff_user_id());
                
                $active_run = $this->check_active_run($THREAD_ID, $device_id, $leadid, $device_token, $model);
                if ($active_run) {
                    $run_id = isset($active_run["id"]) ? $active_run["id"] : null;
                    $run_status = isset($active_run["status"]) ? $active_run["status"] : null;
                    
                    // If run is in requires_action, process it
                    if ($run_status == "requires_action" && $run_id) {
                        log_activity("send_msg_openai - Processing requires_action during error retry. Run ID: {$run_id}, Thread: {$THREAD_ID}, Lead ID: {$leadid}", get_staff_user_id());
                        
                        $result = $this->getStatusMsgOpenai($run_id, $THREAD_ID, $device_id, $leadid, $device_token, $model);
                        $device = $this->get_device($device_id);
                        $lead = $this->get_leads($leadid);
                        $phonenumber = $lead ? $lead->phonenumber : null;
                        $staffid = $lead ? $lead->assigned : null;
                        
                        if ($result && isset($result["status"]) && $result["status"] == "requires_action") {
                            $this->requires_action($result, $THREAD_ID, $run_id, $phonenumber, $staffid, $device_id, $leadid, $device_token, $model);
                            
                            // Wait for run to complete
                            sleep(5);
                        }
                    } else {
                        // For other active states, just wait
                        log_activity("send_msg_openai - Active run in status: " . ($run_status ?? "unknown") . ", waiting 5 seconds before retry", get_staff_user_id());
                        sleep(5);
                    }
                } else {
                    // No active run found, wait a bit anyway
                    log_activity("send_msg_openai - No active run found but error occurred, waiting 5 seconds before retry", get_staff_user_id());
                    sleep(5);
                }
                
                // Retry the request
                $ch = curl_init($url);
                curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
                curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
                curl_setopt($ch, CURLOPT_POST, true);
                curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
                $response = curl_exec($ch);
                curl_close($ch);
                
                $responseArray = json_decode($response, true);
                
                // If still error after retry, log and return false
                if (isset($responseArray["error"])) {
                    $dataError = [
                        "device_id" => $device_id,
                        "lead_id" => $leadid,
                        "device_token" => $device_token,
                        "model" => $model,
                        "request" => json_encode($data),
                        "error" => $responseArray["error"]
                    ];
                    log_activity("Erro na requisição send_msg_openai (after retry): " . json_encode($dataError), get_staff_user_id());
                    return false;
                } else {
                    return true; // Retry succeeded
                }
            } else {
                // Other error - log and return false
                $dataError = [
                    "device_id" => $device_id,
                    "lead_id" => $leadid,
                    "device_token" => $device_token,
                    "model" => $model,
                    "request" => json_encode($data),
                    "error" => $responseArray["error"]
                ];

                // salvo o erro na activity log
                log_activity("Erro na requisição send_msg_openai: " . json_encode($dataError), get_staff_user_id());

                return false;
            }
        } else {

            return true;
        }
    }

    public function send_msg_openai_historico($THREAD_ID, $Message, $device_id, $leadid, $device_token, $model)
    {

        // valido se message é null ou array igual 0
        if ($Message == null || count($Message) == 0) {
            return false;
        }

        // URL da API do OpenAI
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/messages";



        $headers = array(
            "Content-Type: application/json",
            "Authorization: Bearer $this->tokenOpenai",
            "OpenAI-Beta: assistants=v2"
        );


        // Configuração da requisição cURL
        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($Message));

        // Executa a requisição e obtém a resposta
        $response = curl_exec($ch);

        // Verifica por erros
        if (curl_errno($ch)) {

            // monto objeto pra salvar o erro
            $dataError = [
                "device_id" => $device_id,
                "lead_id" => $leadid,
                "device_token" => $device_token,
                "request" => json_encode($Message),
                "model" => $model,
                "error" => curl_error($ch)
            ];

            // salvo o erro na activity log
            log_activity("Erro na requisição send_msg_openai curl_errno linha 3830: " . json_encode($dataError), get_staff_user_id());
        }

        // Fecha a sessão cURL
        curl_close($ch);

        // valido response
        $responseArray = json_decode($response, true);

        if ($responseArray["error"]) {

            // pego o error e salvo no log
            $dataError = [
                "device_id" => $device_id,
                "lead_id" => $leadid,
                "device_token" => $device_token,
                "model" => $model,
                "request" => json_encode($Message),
                "error" => $responseArray["error"]
            ];

            // salvo o erro na activity log
            log_activity("Erro na requisição send_msg_openai: " . json_encode($dataError), get_staff_user_id());

            return false;
        } else {

            return true;
        }
    }

    /*
     * Passo 03
     * execute o assistante
     */
    function runsAssistOpenai($THREAD_ID, $assistant_token, $device_id, $leadid, $device_token, $model)
    {




        //pega o dados do assistente 
        $this->db->where('ai_token', $assistant_token);
        $assist = $this->db->get(db_prefix() . 'contactcenter_assistants_ai')->row();


        // URL da API do OpenAI
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/runs";

        // Dados da requisição
        $data = array(
            "assistant_id" => $assistant_token
        );


        $instructions =  date("d/m/Y") . " " . date("H:i:s") . "\n";
        $instructions .= $assist->instructions;

        if ($assist->instructions) {
            $data["instructions"] = $instructions;
        }

        $responseArray = $this->openai_api->calApiPost($url, $this->tokenOpenai, $device_id, $leadid, $device_token, $model, $data);

        // Se não houver erros, retorna o ID do run
        if (isset($responseArray['id'])) {
            return $responseArray['id'];
        } else {
            // Se a estrutura esperada não estiver presente, logue o erro e retorne falso
            $dataError = [
                "device_id" => $device_id,
                "lead_id" => $leadid,
                "device_token" => $device_token,
                "model" => $model,
                "request" => json_encode($data),
                "error" => "Estrutura de resposta inesperada: " . json_encode($responseArray)
            ];
            log_activity("Erro na requisição runAssistent: " . json_encode($dataError), get_staff_user_id());
            return false;
        }
    }

