    /** Passo 04
     * Verifica se a resposta esta pronta 
     * @param type $RunId
     * @param type $THREAD_ID
     * @return type
     */
    function getStatusMsgOpenai($RunId, $THREAD_ID, $device_id, $leadid, $device_token, $model)
    {
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/runs/{$RunId}";
        return $this->openai_api->callApi($url, $this->tokenOpenai, $device_id, $leadid, $device_token, $model);
    }
    
    /**
     * Check if there's an active run on a thread
     * @param string $THREAD_ID
     * @param int $device_id
     * @param int $leadid
     * @param string $device_token
     * @param string $model
     * @return array|null Returns run data if active, null if no active run
     */
    private function check_active_run($THREAD_ID, $device_id, $leadid, $device_token, $model)
    {
        // Get list of runs for this thread
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/runs?limit=1";
        
        $headers = array(
            "Content-Type: application/json",
            "Authorization: Bearer $this->tokenOpenai",
            "OpenAI-Beta: assistants=v2"
        );
        
        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_HEADER, true);
        
        $response = curl_exec($ch);
        curl_close($ch);
        
        $responseArray = json_decode($response, true);
        
        if (isset($responseArray["data"]) && count($responseArray["data"]) > 0) {
            $latest_run = $responseArray["data"][0];
            // Check if run is in a state that prevents adding messages
            $active_states = ["queued", "in_progress", "requires_action"];
            if (in_array($latest_run["status"], $active_states)) {
                return $latest_run;
            }
        }
        
        return null;
    }

