    function getMessagesOpenai($THREAD_ID, $device_id, $leadid, $device_token, $model)
    {
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/messages";
        $responseArray = $this->openai_api->callApi($url, $this->tokenOpenai, $device_id, $leadid, $device_token, $model);

        // Verifica se a resposta contém um erro
        if ($responseArray === false) {
            log_activity("getMessagesOpenai ERROR - Thread: {$THREAD_ID}, Lead ID: {$leadid}, API call returned false", get_staff_user_id());
            return false; // Retorna falso se houver erro
        }

        // Log the response structure for debugging
        log_activity("getMessagesOpenai RESPONSE STRUCTURE - Thread: {$THREAD_ID}, Lead ID: {$leadid}, Has data: " . (isset($responseArray['data']) ? 'yes, count: ' . count($responseArray['data']) : 'no'), get_staff_user_id());

        // Find the first assistant message (messages are returned in reverse chronological order)
        if (isset($responseArray['data']) && is_array($responseArray['data'])) {
            foreach ($responseArray['data'] as $message) {
                // Check if this message is from the assistant
                if (isset($message['role']) && $message['role'] === 'assistant') {
                    // Check if message has content
                    if (isset($message['content']) && is_array($message['content'])) {
                        // Loop through content items to find text content
                        foreach ($message['content'] as $contentItem) {
                            if (isset($contentItem['type']) && $contentItem['type'] === 'text' && isset($contentItem['text']['value'])) {
                                $assistantMessageContent = $contentItem['text']['value'];
                                // Substituir ** por tags HTML de negrito
                                $formattedContent = preg_replace('/\*\*(.*?)\*\*/', '<strong>$1</strong>', $assistantMessageContent);
                                $result = nl2br($formattedContent); // Exibir o conteúdo
                                log_activity("getMessagesOpenai SUCCESS - Thread: {$THREAD_ID}, Lead ID: {$leadid}, Found assistant message, length: " . strlen($result) . " chars", get_staff_user_id());
                                return $result;
                            }
                        }
                    }
                }
            }
            
            // If we get here, no assistant message was found
            log_activity("getMessagesOpenai NO ASSISTANT MESSAGE - Thread: {$THREAD_ID}, Lead ID: {$leadid}, No assistant message found in response", get_staff_user_id());
            
            // Log all message roles for debugging
            $messageRoles = [];
            foreach ($responseArray['data'] as $msg) {
                $messageRoles[] = isset($msg['role']) ? $msg['role'] : 'unknown';
            }
            log_activity("getMessagesOpenai MESSAGE ROLES - Thread: {$THREAD_ID}, Lead ID: {$leadid}, Roles found: " . implode(', ', $messageRoles), get_staff_user_id());
            
            return false;
        } else {
            // Se a estrutura esperada não estiver presente, logue o erro e retorne falso
            $dataError = [
                "device_id" => $device_id,
                "lead_id" => $leadid,
                "device_token" => $device_token,
                "model" => $model,
                "error" => "Estrutura de resposta inesperada: " . json_encode($responseArray),
                "response_keys" => isset($responseArray) && is_array($responseArray) ? array_keys($responseArray) : "not array",
                "data_exists" => isset($responseArray['data']),
                "data_count" => isset($responseArray['data']) && is_array($responseArray['data']) ? count($responseArray['data']) : 0
            ];
            log_activity("getMessagesOpenai ERROR - Thread: {$THREAD_ID}, Lead ID: {$leadid}, " . json_encode($dataError), get_staff_user_id());
            return false;
        }
    }





