    function send_function_openai($THREAD_ID, $RunId, $tools_outputs, $device_id, $leadid, $device_token, $model)
    {
        // URL da API do OpenAI
        $url = "https://api.openai.com/v1/threads/{$THREAD_ID}/runs/{$RunId}/submit_tool_outputs";

        // Dados da requisição
        $data = array(
            "tool_outputs" => $tools_outputs
        );

        return $this->openai_api->calApiPost($url, $this->tokenOpenai, $device_id, $leadid, $device_token, $model, $data);
    }

