    /**
     * Faz a transcrição do audio 
     * @param type $audio
     * @return type
     */
    public function create_transcription($audio)
    {

        if (!file_exists($audio)) {
            log_activity("Erro: arquivo de áudio não encontrado.");
            return null;
        }

        $audioFile = $audio;

        $url = 'https://api.openai.com/v1/audio/transcriptions';

        // Inicializa a sessão cURL
        $ch = curl_init();

        // Configuração das opções cURL
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, 1);
        curl_setopt($ch, CURLOPT_POST, 1);
        curl_setopt($ch, CURLOPT_POSTFIELDS, array(
            'file' => new CURLFile($audioFile),
            'model' => 'whisper-1'
        ));
        curl_setopt($ch, CURLOPT_HTTPHEADER, array(
            "Authorization: Bearer $this->tokenOpenai",
            'Content-Type: multipart/form-data'
        ));

        // Executa a requisição cURL, obtendo a resposta
        $response = curl_exec($ch);

        // Verifica por erros
        if (curl_errno($ch)) {
            log_activity("Erro ao realizar a transcrição do audio: Erro na requisição: " . curl_error($ch));
        }

        // Fecha a sessão cURL
        curl_close($ch);

        // Imprime a resposta da API
        $response = json_decode($response);

        return $response->text;
    }

    public function crear_audio_elevenlabs($texto, $voz_id)
    {
        $curl = curl_init();

        $postData = array(
            "model_id" => "eleven_multilingual_v2",
            "voice_settings" => array(
                "stability" => 1,
                "similarity_boost" => 1,
                "style" => 0.5,
                "use_speaker_boost" => false,
                "language_id" => "pt"
            ),
            "text" => $texto
        );

        $postFields = json_encode($postData);

        curl_setopt_array($curl, [
            CURLOPT_URL => "https://api.elevenlabs.io/v1/text-to-speech/{$voz_id}",
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_ENCODING => "",
            CURLOPT_MAXREDIRS => 10,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
            CURLOPT_CUSTOMREQUEST => "POST",
            CURLOPT_POSTFIELDS => $postFields,
            CURLOPT_HTTPHEADER => [
                "Content-Type: application/json",
                "xi-api-key: {$this->tokenElevenlabsi}"
            ],
        ]);

        $response = curl_exec($curl);
        curl_close($curl);
        return $response;
    }

    /**
     * Cria o audio pela Openai 
     * @param type $texto
     * @return type
     */
    public function crear_audio_openai($texto)
    {

        $url = 'https://api.openai.com/v1/audio/speech';

        // Configuração das opções cURL
        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);

        // Configuração dos dados da requisição
        $data = array(
            'model' => 'tts-1',
            'input' => $texto,
            'voice' => 'alloy'
        );

        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));

        // Configuração dos cabeçalhos HTTP
        $headers = array(
            'Authorization: Bearer ' . $this->tokenOpenai,
            'Content-Type: application/json'
        );

        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

        // Executa a requisição cURL e obtém a resposta
        $response = curl_exec($ch);
        curl_close($ch);

        return $response;
    }





