    public function save_status_device($data)
    {


        $decodedData = json_decode($data, true);
        if ($decodedData) {
            if ($decodedData["data"]["wook"] == "STATUS_CONNECT") {

                $session = $decodedData["data"]["session"];
                $status = $decodedData["data"]["status"];

                // valido se existe device com essa session
                $device = $this->get_device_token($session);
                if ($device) {

                    // valido se status é diferente do banco
                    if ($device->status != $status) {
                        $this->db->where('dev_token', $session);
                        $this->db->update(db_prefix() . 'contactcenter_device', ["status" => $status]);
                    }
                }

                return ["sucess" => 200];
            }
        }

        return true;
    }

    public function get_webhook_qrcode($data)
    {

        $decodedData = json_decode($data, true);
        if ($decodedData) {
            if ($decodedData["data"]["wook"] == "QRCODE") {

                $session = $decodedData["data"]["session"];
                $status = $decodedData["data"]["status"];
                $Qrcode = $decodedData["data"]["qrcode"];

                if ($status == "awaitReadQrCode") {

                    $CI = &get_instance();
                    $CI->load->library('app_pusher');

                    $tamanho_chunk = 6000;
                    $chunks = str_split($Qrcode, $tamanho_chunk);

                    $count = count($chunks);
                    foreach ($chunks as $index => $chunk) {
                        $is_last = ($index == $count - 1); // Verifica se este é o último chunk
                        $qr = array('message' => $chunk, 'is_last' => $is_last);
                        $CI->app_pusher->trigger($decodedData["data"]["session"], 'qrcode', $qr);
                    }
                }

                return ["sucess" => 200];
            }
        }

        return true;
    }

    public function import_leads($request, $file)
    {
        $totalImported = 0;

        $notImportableFields = hooks()->apply_filters('not_importable_leads_fields', [
            'id',
            'assigned',
            'dateadded',
            'last_status_change',
            'addedfrom',
            'leadorder',
            'date_converted',
            'lost',
            'junk',
            'is_imported_from_email_integration',
            'email_integration_uid',
            'is_public',
            'dateassigned',
            'client_id',
            'lastcontact',
            'last_lead_status',
            'from_form_id',
            'default_language',
            'hash',
            'lm_follow_up',
            'from_ma_form_id',
            'ma_point',
            'status',
            'source',
            'converted_by_lead_manager',
            'lead_value',
            'id_face_inst',
            'from_ma_form_id',
            'ma_point',
            'gpt_thread',
            'gpt_status',
            'conversation_engine_id',
            'conversation_engine_send',
            'conversation_engine_send_reply',
            'contactcenter_thumb',
            'tags',
            'status_whats'
        ]);

        $dbFields = $this->db->list_fields(db_prefix() . 'leads');

        $databaseFields = [];
        foreach ($dbFields as $field) {
            if (in_array($field, $notImportableFields)) {
                continue;
            }
            $databaseFields[] = $field;
        }

        $file_info = pathinfo($file['name']);
        if (strtolower($file_info['extension']) == 'xlsx' || strtolower($file_info['extension']) == 'xls') {
            // Carrega o arquivo Excel
            $inputFileName = $file['tmp_name'];
            $spreadsheet = IOFactory::load($inputFileName);

            $sheet = $spreadsheet->getActiveSheet();
            $data = $sheet->toArray();
            $columns = array_shift($data);
            $leadsData = [];

            $columnMapping = [
                "Nome" => "name",
                "Posição" => "title",
                "Empresa" => "company",
                "Descrição" => "description",
                "Pais" => "country",
                "Cep" => "zip",
                "Cidade" => "city",
                "Estado" => "state",
                "Endereço" => "address",
                "Email" => "email",
                "Website" => "website",
                "Telefone" => "phonenumber",
                "telefone" => "phonenumber",
                "website" => "website",
                "Endereco" => "address",
                "endereco" => "address",
            ];

            // Itera sobre os dados
            foreach ($data as $rowNumber => $row) {
                $insert = [];
                $extraDescriptions = [];

                foreach ($columns as $index => $columnName) {

                    if ($columnName == null) {
                        continue;
                    }

                    $columnValue = $this->checkNullValueAddedByUser($row[$index]);

                    if (array_key_exists($columnName, $columnMapping)) {
                        $mappedField = $columnMapping[$columnName];
                        $insert[$mappedField] = $columnValue;

                        if ($mappedField == 'name' && empty($columnValue)) {
                            $insert[$mappedField] = '/';
                        } elseif ($mappedField == 'country') {
                            $insert[$mappedField] = $this->countryValue($columnValue);
                        }
                    } else if (in_array(strtolower($columnName), $databaseFields)) {
                        $insert[strtolower($columnName)] = $columnValue;
                    } else {
                        $extraDescriptions[] = "$columnName: $columnValue";
                    }
                }

                // Concatena valores extras na coluna description
                if (!empty($extraDescriptions)) {
                    if (isset($insert['description'])) {
                        $insert['description'] .= " | " . implode(" | ", $extraDescriptions);
                    } else {
                        $insert['description'] = implode(" | ", $extraDescriptions);
                    }
                }

                // Preenche campos padrão
                if (!isset($insert['dateadded'])) {
                    $insert['dateadded'] = date('Y-m-d H:i:s');
                }

                if (!isset($insert['addedfrom'])) {
                    $insert['addedfrom'] = get_staff_user_id();
                }

                $insert['status'] = $request['status'];
                $insert['source'] = $request['source'];

                if ($request['gpt_status']) {
                    $insert['gpt_status'] = $request['gpt_status'];
                } else {
                    $insert['gpt_status'] = 0;
                }


                if ($request['responsible']) {
                    $insert['assigned'] = $request['responsible'];
                }

                $telefoneLimpo = preg_replace('/\D/', '', $insert['phonenumber']);
                $countryStr = (string)$request['country'];
                $numDigits = strlen($countryStr);
                $VerfTel = substr($telefoneLimpo, 0, $numDigits);
                if ($VerfTel != $request['country']) {
                    $formatNumber =  $request['country'] . $telefoneLimpo;
                    $insert['phonenumber'] = formatPhoneNumber($formatNumber);
                } else {
                    $insert['phonenumber'] = formatPhoneNumber($telefoneLimpo);
                }

                // retira os espaços em branco
                $insert['phonenumber'] = trim($insert['phonenumber']);



                // não insere se já existir lead com esse phonenumber
                $lead = $this->db->where('phonenumber', $insert['phonenumber'])->get('tblleads')->row();
                if (!$lead) {
                    $id = $this->add_lead_from_lead_model($insert);
                    if ($id) {
                        $totalImported++;
                    }
                }
            }

            return $totalImported;
        }

        return 0;
    }

    protected function checkNullValueAddedByUser($val)
    {
        if ($val === 'NULL' || $val === 'null') {
            $val = '';
        }

        return $val;
    }

    private function getCountry($search = null, $id = null)
    {
        if ($search) {
            $this->db->where('iso2', $search)
                ->or_where('short_name', $search)
                ->or_where('long_name', $search);
        } else {
            $this->db->where('country_id', $id);
        }

        return $this->db->get('countries')->row();
    }

    private function countryValue($value)
    {
        if ($value != '') {
            if (!is_numeric($value)) {
                $country = $this->getCountry($value);
                $value = $country ? $country->country_id : 0;
            }
        } else {
            $value = 0;
        }

        return $value;
    }

    protected function trimInsertValues($insert)
    {
        foreach ($insert as $key => $val) {
            $insert[$key] = !is_null($val) ? trim($val) : $val;
        }

        return $insert;
    }

    protected function findSource($sources, $id)
    {
        foreach ($sources as $source) {
            if ($source['name'] == $id || $source['id'] == $id) {
                return $source;
            }
        }
    }

    protected function findStatus($statuses, $id)
    {
        foreach ($statuses as $status) {
            if ($status['name'] == $id || $status['id'] == $id) {
                return $status;
            }
        }
    }

    protected function statusValue($statuses, $value, $data)
    {
        return $this->findStatus($statuses, $value)['id'] ?? $data['status'];
    }

    protected function sourceValue($sources, $value, $data)
    {
        return $this->findSource($sources, $value)['id'] ?? $data['source'];
    }

