    /**
     * Process stuck leads for a specific campaign immediately after assignment
     * @param string $campaign Campaign name
     * @param int $group_id Group ID
     * @return int Number of leads updated
     */
    public function process_stuck_leads_for_campaign($campaign, $group_id)
    {
        if (get_option("active_contador_contactcenter") != 1) {
            return 0;
        }
        
        $this->load->database();
        $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
        
        if (empty($custom_fields)) {
            return 0;
        }
        
        $field_id = $custom_fields[0]['id'];
        $staff = get_option("staff_contador_contactcenter");
        $status = get_option("leads_status_contador_contactcenter");
        $source = get_option("leads_source_contador_contactcenter");
        
        // Get leads with this campaign that are assigned to the initial staff
        $this->db->select('l.*, c.value');
        $this->db->from(db_prefix() . 'leads l');
        $this->db->join(db_prefix() . 'customfieldsvalues c', 'l.id = c.relid AND c.fieldid = ' . $field_id, 'left');
        $this->db->where('c.value', $campaign);
        $this->db->where('l.status', $status);
        $this->db->where('l.assigned', $staff);
        $this->db->where('l.source', $source);
        $this->db->order_by('l.id', 'ASC');
        $this->db->limit(50); // Process up to 50 leads at a time
        
        $query = $this->db->get();
        $leads = $query->result_array();
        
        if (empty($leads)) {
            return 0;
        }
        
        // Get the attendant for this group (lowest counter)
        $this->db->where('grup_id', $group_id);
        $this->db->order_by('cont_data', 'ASC');
        $this->db->order_by('cont_vezes', 'ASC');
        $atendente = $this->db->get(db_prefix() . 'leads_cont')->row_array();
        
        if (!$atendente) {
            log_activity("process_stuck_leads_for_campaign - No attendant found for group ID: {$group_id}", get_staff_user_id());
            return 0;
        }
        
        $AtendId = $atendente['user_id'];
        $quant = $atendente['cont_vezes'] + 1;
        $leads_updated = 0;
        
        foreach ($leads as $lead) {
            // Assign lead to attendant
            $this->db->where('id', $lead['id']);
            $this->db->update(db_prefix() . 'leads', ['assigned' => $AtendId]);
            
            if ($this->db->affected_rows() > 0) {
                $leads_updated++;
                
                // Send notification
                add_notification([
                    'description' => _l("not_lead_assigned_from_form") . " {$lead['id']}.",
                    'touserid' => $AtendId,
                    'link' => admin_url("#leadid={$lead['id']}"),
                ]);
                
                // Transfer events
                $date = date("Y-m-d H:i:s", strtotime("-1 day"));
                $this->db->where('userid', $staff);
                $this->db->where('rel_id', $lead['id']);
                $this->db->where('rel_type', "lead");
                $this->db->where('start >', $date);
                $leadsEvents = $this->db->get(db_prefix() . 'events')->result();
                
                if ($leadsEvents) {
                    foreach ($leadsEvents as $event) {
                        $this->db->where('id', $event->eventid);
                        $this->db->update(db_prefix() . 'events', ['userid' => $AtendId]);
                    }
                }
                
                // Update counter
                $QuantCrear = ['cont_vezes' => $quant, 'cont_data' => date('Y-m-d H:i:s')];
                $this->db->where('cont_id', $atendente['cont_id']);
                $this->db->update(db_prefix() . 'leads_cont', $QuantCrear);
                
                $quant++; // Increment for next lead
            }
        }
        
        log_activity("process_stuck_leads_for_campaign - Campaign: {$campaign}, Group ID: {$group_id}, Leads updated: {$leads_updated}", get_staff_user_id());
        
        return $leads_updated;
    }

    public function active_module($data)
    {



        $return = [
            "error" => true,
            "message" => "Erro ao criar plano"
        ];

        $data["key"] = trim($data["key"]);

        // valida se ja tem um plano com a key
        $this->db->where('plan_key', $data["key"]);
        $plano = $this->db->get(db_prefix() . 'contactcenter_saas_planos')->row();
        if ($plano) {
            if ($plano->plan_status == 1 && $plano->plan_key_status == "Validado" && !$data["update"]) {
                $return = [
                    "error" => false,
                    "message" => "Plano já esta ativado"
                ];

                return $return;
            }
        }

        if (!$plano && $data["update"]) {
            $return = [
                "error" => true,
                "message" => "Chave não Ativada ainda ou não existe"
            ];

            return $return;
        }

        // busco a api baseado na chave digitado
        $response = $this->valid_key($data);

        if ($response["error"] == true) {
            $return = [
                "error" => true,
                "message" => $response["message"]
            ];

            return $return;
        }

        if ($response["plan"]["plan_key_status"] != "Validado" && $response["plan"]["plan_url"] != site_url()  && !$data["update"]) {
            $return = [
                "error" => true,
                "message" => "Chave já foi ativada por outro dominio"
            ];

            return $return;
        }


        // crio um novo plano
        $plano = [
            "plan_id_saas" => $response["plan"]["plan_id"],
            "staffid" => get_staff_user_id(),
            "plan_desc" => $response["plan"]["plan_desc"],
            "plan_key" => $response["plan"]["plan_key"],
            "plan_url" => $response["plan"]["plan_url"],
            "plan_status" => $response["plan"]["plan_status"],
            "plan_key_status" => $response["plan"]["plan_key_status"],
            "qtd_device" => $response["qtd_device"],
            "qtd_assistant" => $response["qtd_assistant"],
            "plan_date_start" => $response["plan"]["plan_date_start"],
            "plan_date_end" => $response["plan"]["plan_date_end"],
            "plan_date_create" => date('Y-m-d H:i:s'),
        ];

        if ($data["update"]) {
            unset($plano["plan_date_create"]);
            unset($plano["plan_date_start"]);
            $this->db->where('plan_key', $data["key"]);
            $this->db->update(db_prefix() . 'contactcenter_saas_planos', $plano);
            return [
                "error" => false,
                "message" => "Chave atualizada com sucesso"
            ];
        }

        $this->db->insert(db_prefix() . 'contactcenter_saas_planos', $plano);
        $insert_id = $this->db->insert_id();
        if ($insert_id) {

            $return = [
                "error" => false,
                "message" => "Chave ativada com sucesso"
            ];

            return $return;
        } else {
            $return = [
                "error" => true,
                "message" => "Erro ao criar plano"
            ];

            return $return;
        }
    }

