    public function change_phone($data)
    {

        $response = [
            "error" => true,
            "message" => "Erro ao alterar whatsapp"
        ];

        // busco motor
        $this->db->where('con_id', $data['con_id']);
        $engine = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();

        if ($engine) {

            // busco device
            $device = $this->get_device($engine->device_id);

            if ($device) {
                $device_token = $device->dev_token;

                $request = [
                    "phonenumber" => $data['phone'],
                    "token" => $device_token
                ];
                $isValidNumber = $this->verify_Number_Whatsapp($request);

                if ($isValidNumber["exists"]) {
                    $this->update_phone($data);

                    $this->db->where('error_id', $data['id']);
                    $this->db->delete(db_prefix() . 'contactcenter_conversation_engine_error');

                    $response = [
                        "error" => false,
                        "message" => "Whatsapp alterado com sucesso"
                    ];
                } else {
                    $response = [
                        "error" => true,
                        "message" => "Whatsapp inválido"
                    ];
                }
            }
        }

        return $response;
    }

