    public function duplicate_engine($data)
    {

        $this->db->where('con_id', $data['id']);
        $engine = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();

        $engine->con_title = $engine->con_title . " - Duplicado";
        $engine->con_status = 0;
        $engine->con_date = date('Y-m-d H:i:s');
        $engine->con_id = null;
        $engine->con_count_send = 0;
        $engine->con_count_reply = 0;
        $engine->leads_sleep = 0;
        $engine->device_id = null;

        $this->db->insert(db_prefix() . 'contactcenter_conversation_engine', $engine);
        // pego id inserido
        $id = $this->db->insert_id();

        // busco os contactcenter_conversation_engine_list
        $this->db->where('con_id', $data['id']);
        $engine_list = $this->db->get(db_prefix() . 'contactcenter_conversation_engine_list')->result();

        if ($engine_list) {
            foreach ($engine_list as $list) {
                $list->con_id = $id;
                $list->list_id = null;
                $this->db->insert(db_prefix() . 'contactcenter_conversation_engine_list', $list);
            }
        }

        return true;
    }

    public function replicate_engine($engine_id, $device_ids)
    {
        try {
            // Get the original engine
            $this->db->where('con_id', $engine_id);
            $original_engine = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();
            
            if (!$original_engine) {
                return ['success' => false, 'message' => 'Engine not found', 'count' => 0];
            }
            
            // Get the engine list (messages)
            $this->db->where('con_id', $engine_id);
            $engine_list = $this->db->get(db_prefix() . 'contactcenter_conversation_engine_list')->result();
            
            $created_count = 0;
            $errors = [];
            
            foreach ($device_ids as $device_id) {
                // Verify device exists
                $device = $this->get_device($device_id);
                if (!$device) {
                    $errors[] = "Device ID {$device_id} not found";
                    continue;
                }
                
                // Convert object to array for insertion
                $new_engine = (array) $original_engine;
                
                // Remove the ID so it creates a new record
                unset($new_engine['con_id']);
                
                // Update fields for the new campaign
                $new_engine['con_title'] = $original_engine->con_title . " - " . $device->dev_name;
                $new_engine['con_status'] = 0; // Set as inactive by default
                $new_engine['con_date'] = date('Y-m-d H:i:s');
                $new_engine['con_count_send'] = 0;
                $new_engine['con_count_reply'] = 0;
                $new_engine['leads_sleep'] = 0;
                $new_engine['device_id'] = $device_id;
                $new_engine['device_rotation_index'] = 0; // Reset rotation index
                
                // Insert the new engine
                $this->db->insert(db_prefix() . 'contactcenter_conversation_engine', $new_engine);
                $new_engine_id = $this->db->insert_id();
                
                if ($new_engine_id) {
                    // Copy the engine list (messages)
                    if ($engine_list) {
                        foreach ($engine_list as $list_item) {
                            $new_list = (array) $list_item;
                            
                            // Remove the ID and update con_id
                            unset($new_list['list_id']);
                            $new_list['con_id'] = $new_engine_id;
                            
                            $this->db->insert(db_prefix() . 'contactcenter_conversation_engine_list', $new_list);
                        }
                    }
                    
                    $created_count++;
                    
                    log_activity('Campaign replicated - Original ID: ' . $engine_id . ', New ID: ' . $new_engine_id . ', Device: ' . $device->dev_name);
                } else {
                    $errors[] = "Failed to create campaign for device: {$device->dev_name}";
                }
            }
            
            if ($created_count > 0) {
                return [
                    'success' => true, 
                    'count' => $created_count,
                    'message' => count($errors) > 0 ? implode(', ', $errors) : ''
                ];
            } else {
                return [
                    'success' => false,
                    'count' => 0,
                    'message' => count($errors) > 0 ? implode(', ', $errors) : 'Failed to replicate campaign'
                ];
            }
            
        } catch (Exception $e) {
            log_activity('Error replicating campaign: ' . $e->getMessage());
            return ['success' => false, 'message' => $e->getMessage(), 'count' => 0];
        }
    }

    public function get_leads_engine($con_id)
    {
        // busco o motor
        $this->db->where('con_id', $con_id);
        $engine = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();

        if ($engine) {

            // busco o device
            $device = $this->get_device($engine->device_id);

            $date_filter_type = isset($engine->date_filter_type) ? $engine->date_filter_type : 'creation_date';
            $date = ($date_filter_type == 'last_contact' && isset($engine->leads_last_contact_data)) ? $engine->leads_last_contact_data : $engine->leads_create_data;
            $date_final = ($date_filter_type == 'last_contact' && isset($engine->leads_last_contact_data_final)) ? $engine->leads_last_contact_data_final : $engine->leads_create_data_final;
            $leads = $this->get_all_leads_status_cadastrado_staff($device->staffid, $engine->leads_status, $date, $date_final, $engine->con_id, $engine->tags, $date_filter_type, isset($engine->filter_source) ? $engine->filter_source : null, isset($engine->filter_city) ? $engine->filter_city : null, isset($engine->filter_state) ? $engine->filter_state : null);

            // valido se tem tags
            //$leads = $this->filter_leads_by_taggables($leads, $engine);

            return $leads;
        }

        return null;
    }

    public function get_all_leads_status_cadastrado_staff($staffid, $status, $date, $date_final, $conversation_engine_id, $taggables, $date_filter_type = 'creation_date', $filter_source = null, $filter_city = null, $filter_state = null)
    {
        if (!$staffid) {
            return null; // Garantir que não execute nada sem um staffid válido
        }

        // Determine which date field to use
        $date_field = ($date_filter_type == 'last_contact') ? 'lastcontact' : 'dateadded';

        // Consulta SQL base
        $sql = "SELECT * 
            FROM " . db_prefix() . "leads as leads
            WHERE status = {$status} 
              AND assigned = {$staffid}
              AND phonenumber != '' 
              AND {$date_field} >= '{$date}' 
              AND {$date_field} <= '{$date_final}'
              AND (conversation_engine_id IS NULL OR conversation_engine_id != {$conversation_engine_id})
              AND (gpt_thread IS NULL OR gpt_thread = '')
              AND (status_whats IS NULL OR status_whats != 2)";

        // Add source filter
        if ($filter_source && !empty($filter_source)) {
            $sources = explode(',', $filter_source);
            $sources_clean = array_map('intval', $sources);
            $sources_str = implode(',', $sources_clean);
            $sql .= " AND source IN ({$sources_str})";
        }

        // Add city filter
        if ($filter_city && !empty($filter_city)) {
            $cities = explode(',', $filter_city);
            $cities_escaped = array_map(function($city) {
                return $this->db->escape(trim($city));
            }, $cities);
            $cities_str = implode(',', $cities_escaped);
            $sql .= " AND city IN ({$cities_str})";
        }

        // Add state filter
        if ($filter_state && !empty($filter_state)) {
            $states = explode(',', $filter_state);
            $states_escaped = array_map(function($state) {
                return $this->db->escape(trim($state));
            }, $states);
            $states_str = implode(',', $states_escaped);
            $sql .= " AND state IN ({$states_str})";
        }

        // Adiciona a condição de tags se taggables for fornecido
        if ($taggables != null && !empty($taggables)) {
            $sql .= " AND EXISTS (
                    SELECT 1
                    FROM " . db_prefix() . "taggables AS taggables
                    WHERE taggables.rel_id = leads.id
                      AND taggables.tag_id IN ({$taggables})
                  )";
        }

        // Executa a consulta SQL
        $query = $this->db->query($sql);

        // Retorna todos os resultados
        return $query->result();
    }


    public function valid_if_engine_will_run($id)
    {

        $messages = [];

        $this->db->where('con_id', $id);
        $engine = $this->db->get(db_prefix() . 'contactcenter_conversation_engine')->row();

        if ($engine) {

            if ($engine->device_id == null) {
                $messages[] = _l("contact_valid_engine_device");
            }

            if ($engine->con_status == 0) {
                $messages[] = _l("contact_valid_engine_status");
            }

            $device = $this->get_device($engine->device_id);

            if ($device) {

                if ($device->dev_type == 1) {
                    $messages[] = _l("contact_valid_engine_device_type");
                }

                if ($device->dev_engine == 0) {
                    $messages[] = _l("contact_valid_engine_device_engine");
                }

                if ($device->staffid == 0) {
                    $messages[] = _l("contact_valid_engine_device_staff");
                }

                if ($device->status != "inChat" && $device->status != "CONNECTED" && $device->status != "open" && $device->status != "connecting") {
                    $messages[] = _l("contact_valid_engine_device_status");
                }

                $date_filter_type = isset($engine->date_filter_type) ? $engine->date_filter_type : 'creation_date';
                $date = ($date_filter_type == 'last_contact' && isset($engine->leads_last_contact_data)) ? $engine->leads_last_contact_data : $engine->leads_create_data;
                $date_final = ($date_filter_type == 'last_contact' && isset($engine->leads_last_contact_data_final)) ? $engine->leads_last_contact_data_final : $engine->leads_create_data_final;
                $leads = $this->get_count_leads_status_cadastrado_staff($device->staffid, $engine->leads_status, $date, $date_final, $engine->con_id, $date_filter_type, isset($engine->filter_source) ? $engine->filter_source : null, isset($engine->filter_city) ? $engine->filter_city : null, isset($engine->filter_state) ? $engine->filter_state : null);

                if (count($leads) == 0) {
                    $messages[] = _l("contact_valid_engine_leads");
                }
            }
        }

        return $messages;
    }


    public function requires_action($result, $thread, $Runsid, $phonenumber, $staffid, $device_id, $leadid, $device_token, $model)
    {
        // CRITICAL: Only process when status is actually "requires_action"
        // Exit early for all other statuses (failed, completed, cancelled, expired, etc.)
        // This prevents unnecessary logging and processing
        if (!is_array($result) || !isset($result["status"]) || $result["status"] !== "requires_action") {
            return; // Exit early - do not log or process
        }
        
        // Only log when we're actually processing requires_action
        log_activity("requires_action METHOD CALLED - Lead ID: {$leadid}, Device ID: {$device_id}, Status: requires_action", get_staff_user_id());
        
        if ($result["status"] == "requires_action") {
            log_activity("requires_action STATUS MATCH - Processing tool calls. Lead ID: {$leadid}, Device ID: {$device_id}", get_staff_user_id());
            $tools_outputs = [];

            log_activity("AI TOOL CALLS PROCESSING STARTED - Lead ID: {$leadid}, Device ID: {$device_id}, Tool Calls Count: " . count($result["required_action"]["submit_tool_outputs"]["tool_calls"]), get_staff_user_id());
            
            foreach ($result["required_action"]["submit_tool_outputs"]["tool_calls"] as $tool_call) {

                //pega dos dados do lead e muda o agendamento para o staff atribuido ao lead
                $lead = $this->get_leads($leadid);
                $staffid = $lead->assigned;



                $tool_callsId = $tool_call["id"];
                $function_name = isset($tool_call["function"]["name"]) ? $tool_call["function"]["name"] : "UNKNOWN";
                $function_arguments_raw = isset($tool_call["function"]["arguments"]) ? $tool_call["function"]["arguments"] : "{}";
                $function_arguments = json_decode($function_arguments_raw, true);
                
                // Ensure we have a valid staff ID for logging
                $log_staff_id = get_staff_user_id();
                if (!$log_staff_id && isset($staffid)) {
                    $log_staff_id = $staffid;
                }
                if (!$log_staff_id) {
                    $log_staff_id = null; // Will use [System] in ActivityLogger
                }
                
                try {
                    log_activity("AI FUNCTION CALLED - Function: {$function_name}, Lead ID: {$leadid}, Device ID: {$device_id}, Raw Arguments: {$function_arguments_raw}", $log_staff_id);
                    
                    // Log to structured AI interactions table
                    $this->log_ai_interaction(array(
                        'lead_id' => $leadid,
                        'device_id' => $device_id,
                        'thread_id' => $thread,
                        'run_id' => $Runsid,
                        'interaction_type' => 'function_call',
                        'function_name' => $function_name,
                        'function_arguments' => $function_arguments_raw,
                        'raw_input' => json_encode($tool_call),
                        'status' => 'calling'
                    ));
                } catch (Exception $e) {
                    error_log("Failed to log AI FUNCTION CALLED: " . $e->getMessage());
                }
                
                if (json_last_error() !== JSON_ERROR_NONE) {
                    try {
                        log_activity("AI FUNCTION ERROR - JSON decode failed. Function: {$function_name}, Lead ID: {$leadid}, JSON Error: " . json_last_error_msg() . ", Raw: {$function_arguments_raw}", $log_staff_id);
                    } catch (Exception $e) {
                        error_log("Failed to log AI FUNCTION ERROR: " . $e->getMessage());
                    }
                    $output = json_encode(["success" => "false", "error" => "Invalid JSON in function arguments"]);
                    continue;
                } else {
                    try {
                        log_activity("AI FUNCTION ARGUMENTS PARSED - Function: {$function_name}, Lead ID: {$leadid}, Arguments: " . json_encode($function_arguments), $log_staff_id);
                    } catch (Exception $e) {
                        error_log("Failed to log AI FUNCTION ARGUMENTS PARSED: " . $e->getMessage());
                    }
                }
                
                // Log which function handler will be used
                try {
                    log_activity("AI FUNCTION ROUTING - Function: {$function_name}, Lead ID: {$leadid}, Checking function handlers...", $log_staff_id);
                } catch (Exception $e) {
                    error_log("Failed to log ROUTING: " . $e->getMessage());
                }
                
                $output = "";

                if ($function_name == "get_horario_agenda") {

                    $current_time = $function_arguments["date"];

                    if ($current_time < date("Y-m-d")) {
                        $current_time = date("Y-m-d");
                    } else {
                        $current_time = $current_time;
                    }


                    $time = get_option("time_contactcenter");
                    $saturdayHours = get_option("saturdayHours");
                    $minutesToAdd = get_option("agendaMinutesToAdd");
                    //$afterSomeHour = get_option("after_some_hour");
                    $afterSomeHour = $function_arguments["after_some_hour"];
                    $explodeTime = explode(",", $time);
                    $currentDateTime = date("Y-m-d H:i:s"); // Data e hora atual
                    $content = [];



                    if ($current_time != null) {

                        // se a data for domingo, nao retorna horarios
                        if (date('N', strtotime($current_time)) == 7) {
                            $content = [];
                        }
                        // se for sabado e nao tiver horario, devolve vazio
                        else if (date('N', strtotime($current_time)) == 6 && !$saturdayHours) {
                            $content = [];
                        } else {

                            // se o dia for sabado e tiver horarios de sabado, pega os horarios de sabado
                            if (date('N', strtotime($current_time)) == 6 && $saturdayHours) {
                                $explodeTime = explode(",", $saturdayHours);
                            }

                            $specific_hour = $function_arguments["specific_hour"];
                            $period_of_day = $function_arguments["period_of_day"]; // ["morning", "afternoon"]

                            $time_hours = $function_arguments["rejected_hours"];

                            // retiro os horarios que ja foram rejeitados
                            if ($time_hours != null && count($time_hours) > 0) {
                                $explodeTime = array_diff($explodeTime, $time_hours);
                            }

                            // tiro todos os horariso menores iguais ao horario after_some_hour
                            if ($afterSomeHour != null) {
                                $explodeTime = array_filter($explodeTime, function ($time) use ($afterSomeHour) {
                                    $hour = explode(":", $time)[0];
                                    $hour = (int)$hour;
                                    return $hour > $afterSomeHour;
                                });
                            }

                            if ($period_of_day != null) {
                                $explodeTime = array_filter($explodeTime, function ($time) use ($period_of_day) {
                                    $hour = explode(":", $time)[0];
                                    $hour = (int)$hour;
                                    if ($period_of_day == "morning") {
                                        return $hour < 12;
                                    } else {
                                        return $hour >= 12;
                                    }
                                });
                            }

                            // faço randon baseado no get_option('quant_time_contactcenter')
                            /*if (count($explodeTime) >  get_option('quant_time_contactcenter')) {
                                $randomKeys = array_rand($explodeTime,  get_option('quant_time_contactcenter')); // Seleciona quantidade índices aleatórios
                                sort($randomKeys); // Ordena os índices aleatórios para preservar a sequência cronológica
                                $explodeTime = array_intersect_key($explodeTime, array_flip($randomKeys)); // Filtra os 4 horários
                            }*/


                            foreach ($explodeTime as $hora) {
                                $dataHora = date("{$current_time} {$hora}:00");

                                // se a hora for menor que hora atual, vai pra proxima hora
                                if ($dataHora < $currentDateTime) {
                                    continue;
                                }

                                $Userid = $staffid ? $staffid : 1;
                                $timeBanco = $this->get_agenda_current_time($dataHora, $Userid);

                                if ($timeBanco != null) {
                                    continue;
                                }

                                // se o horario for menor que a data atual mais os minutos, nao entra no loop. Exemplo. Se tiver horarios para as 14:30 e os minutos for 90, nao colocar esse
                                if ($minutesToAdd > 0) {
                                    if ($dataHora < date("Y-m-d H:i:s", strtotime($currentDateTime . " +{$minutesToAdd} minutes"))) {
                                        continue;
                                    }
                                }

                                $content[] = $dataHora;
                            }

                            $quant_time_contactcenter = get_option('quant_time_contactcenter');
                            if (count($content) >= $quant_time_contactcenter) {

                                if ($specific_hour != null) {
                                    $content = array_filter($content, function ($time) use ($specific_hour) {

                                        // pego a hora no formato assim HH:MM
                                        $hour = date("H:i", strtotime($time));
                                        return $hour == $specific_hour;
                                    });
                                }

                                // pego somente a quantidade de horarios que foi definido, mas pega embaralhado pranao ficar sempre os primeiros horarios
                                $content = array_slice($content, 0, $quant_time_contactcenter);
                            }
                        }
                    } else {

                        // Se houver mais de 4 horários, seleciona 4 aleatoriamente, mantendo a ordem
                        /*if (count($explodeTime) >  get_option('quant_time_contactcenter')) {
                            $randomKeys = array_rand($explodeTime,  get_option('quant_time_contactcenter')); // Seleciona quantidade índices aleatórios
                            sort($randomKeys); // Ordena os índices aleatórios para preservar a sequência cronológica
                            $explodeTime = array_intersect_key($explodeTime, array_flip($randomKeys)); // Filtra os 4 horários
                        }*/

                        foreach ($explodeTime as $hora) {
                            $dataHora = date("Y-m-d {$hora}:00"); // Concatena a data fornecida com a hora
                            if ($dataHora < $currentDateTime) {
                                $dataHora = date("Y-m-d H:i:s", strtotime($dataHora . " +1 day"));
                            }

                            $Userid = $staffid ? $staffid : 1;
                            $timeBanco = $this->get_date_agenda($dataHora, $Userid);

                            // se o horario for menor que a data atual mais os minutos, nao entra no loop. Exemplo. Se tiver horarios para as 14:30 e os minutos for 90, nao colocar esse
                            if ($minutesToAdd > 0) {
                                if ($timeBanco < date("Y-m-d H:i:s", strtotime($currentDateTime . " +{$minutesToAdd} minutes"))) {
                                    continue;
                                }
                            }

                            $content[] = $timeBanco;
                        }
                    }

                    $output = json_encode(["dates" => $content]);
                } elseif ($function_name == "set_horario_agenda" || $function_name == "set_reagendamento") {
                    
                    // Ensure we have a valid staff ID for logging
                    $log_staff_id = get_staff_user_id();
                    if (!$log_staff_id && isset($staffid)) {
                        $log_staff_id = $staffid;
                    }
                    if (!$log_staff_id) {
                        $log_staff_id = null;
                    }
                    
                    try {
                        log_activity("set_horario_agenda STARTED - Lead ID: {$leadid}, Function: {$function_name}, Arguments: " . json_encode($function_arguments), $log_staff_id);
                    } catch (Exception $e) {
                        error_log("Failed to log set_horario_agenda STARTED: " . $e->getMessage());
                    }

                    $minutes_schedule = get_option("minutes_schedule");

                    $horario = $function_arguments["date"];
                    $summary = $function_arguments["summary_conversation"];
                    
                    // Validate and parse the date
                    $currentDateTime = date('Y-m-d H:i:s');
                    $parsedDate = null;
                    
                    // Try to parse the date
                    try {
                        $parsedDate = new DateTime($horario);
                        $parsedDateString = $parsedDate->format('Y-m-d H:i:s');
                        
                        try {
                            log_activity("set_horario_agenda DATE PARSED - Lead ID: {$leadid}, Original: {$horario}, Parsed: {$parsedDateString}, Current: {$currentDateTime}", $log_staff_id);
                        } catch (Exception $e) {
                            error_log("Failed to log DATE PARSED: " . $e->getMessage());
                        }
                        
                        // Check if date is in the past
                        if ($parsedDateString < $currentDateTime) {
                            try {
                                log_activity("set_horario_agenda ERROR - Date is in the past. Lead ID: {$leadid}, Date: {$parsedDateString}, Current: {$currentDateTime}", $log_staff_id);
                            } catch (Exception $e) {
                                error_log("Failed to log date validation error: " . $e->getMessage());
                            }
                            $output = json_encode(["success" => "false", "message" => "Cannot schedule in the past. Please choose a future date."]);
                            continue;
                        }
                        
                        // Check if date is too far in the future (more than 1 year)
                        $oneYearFromNow = date('Y-m-d H:i:s', strtotime('+1 year'));
                        if ($parsedDateString > $oneYearFromNow) {
                            try {
                                log_activity("set_horario_agenda WARNING - Date is more than 1 year in the future. Lead ID: {$leadid}, Date: {$parsedDateString}", $log_staff_id);
                            } catch (Exception $e) {
                                error_log("Failed to log future date warning: " . $e->getMessage());
                            }
                        }
                        
                        // Check if date is more than 3 months in the future (likely a mistake - reject it)
                        $threeMonthsFromNow = date('Y-m-d H:i:s', strtotime('+3 months'));
                        if ($parsedDateString > $threeMonthsFromNow) {
                            // Try to detect if it's a date format misinterpretation (DD/MM vs MM/DD)
                            $dateParts = explode('-', $parsedDateString);
                            $suggestedDate = null;
                            if (count($dateParts) == 3) {
                                $year = $dateParts[0];
                                $month = $dateParts[1];
                                $day = $dateParts[2];
                                
                                // If month > 12, it's likely DD/MM format misinterpreted as MM/DD
                                // Try swapping month and day
                                if ($month > 12 && $day <= 12) {
                                    $suggestedDate = "{$year}-{$day}-{$month}";
                                    // Validate the suggested date
                                    try {
                                        $suggestedDateTime = new DateTime($suggestedDate . ' ' . (isset($dateParts[3]) ? $dateParts[3] : '10:00:00'));
                                        $suggestedDateString = $suggestedDateTime->format('Y-m-d H:i:s');
                                        // Check if suggested date is within 3 months
                                        if ($suggestedDateString <= $threeMonthsFromNow && $suggestedDateString >= $currentDateTime) {
                                            $suggestedDate = $suggestedDateString;
                                        } else {
                                            $suggestedDate = null;
                                        }
                                    } catch (Exception $e) {
                                        $suggestedDate = null;
                                    }
                                }
                            }
                            
                            try {
                                log_activity("set_horario_agenda ERROR - Date is more than 3 months in the future. Lead ID: {$leadid}, Date: {$parsedDateString}, Current: {$currentDateTime}. This is likely a date format misinterpretation (d-m-y vs m-d-y). Suggested: " . ($suggestedDate ?? 'none'), $log_staff_id);
                            } catch (Exception $e) {
                                error_log("Failed to log 3 months error: " . $e->getMessage());
                            }
                            
                            $errorMessage = "The date provided ({$parsedDateString}) is more than 3 months in the future, which is not allowed. ";
                            if ($suggestedDate) {
                                $errorMessage .= "It appears there may be a date format confusion. Did you mean {$suggestedDate}? ";
                            }
                            $errorMessage .= "IMPORTANT: Before calling set_horario_agenda, you MUST first call get_horario_agenda with the desired date to check available times. Use the dates and times returned by get_horario_agenda when calling set_horario_agenda. Please call get_horario_agenda first to get available appointment slots, then use one of those dates/times.";
                            
                            $output = json_encode(["success" => "false", "message" => $errorMessage]);
                            continue;
                        }
                        
                        // Update horario to use parsed date
                        $horario = $parsedDateString;
                        
                    } catch (Exception $e) {
                        try {
                            log_activity("set_horario_agenda ERROR - Failed to parse date. Lead ID: {$leadid}, Date: {$horario}, Error: " . $e->getMessage(), $log_staff_id);
                        } catch (Exception $logError) {
                            error_log("Failed to log parse error: " . $logError->getMessage());
                        }
                        $output = json_encode(["success" => "false", "message" => "Invalid date format. Please use YYYY-MM-DD HH:MM:SS format."]);
                        continue;
                    }

                    $canSchedule = true;
                    // se dia for domingo nao agenda
                    if (date('N', strtotime($horario)) == 7) {
                        $agenda = false;
                        $canSchedule = false;
                        try {
                            log_activity("set_horario_agenda REJECTED - Sunday. Lead ID: {$leadid}, Date: {$horario}", $log_staff_id);
                        } catch (Exception $e) {
                            error_log("Failed to log Sunday rejection: " . $e->getMessage());
                        }
                    }

                    // se dia for sabado mas nao tiver horarios, nao agenda
                    if (date('N', strtotime($horario)) == 6 && !get_option("saturdayHours")) {
                        $agenda = false;
                        $canSchedule = false;
                        try {
                            log_activity("set_horario_agenda REJECTED - Saturday without hours. Lead ID: {$leadid}, Date: {$horario}", $log_staff_id);
                        } catch (Exception $e) {
                            error_log("Failed to log Saturday rejection: " . $e->getMessage());
                        }
                    }

                    if ($canSchedule) {
                        $Userid = $staffid ? $staffid : 1;
                        $isReagendamento = ($function_name == "set_reagendamento" ? true : false);
                        
                        try {
                            log_activity("set_horario_agenda SCHEDULING - Lead ID: {$leadid}, Date: {$horario}, Staff ID: {$Userid}, Is Reagendamento: " . ($isReagendamento ? 'yes' : 'no'), $log_staff_id);
                        } catch (Exception $e) {
                            error_log("Failed to log SCHEDULING: " . $e->getMessage());
                        }
                        
                        $agenda = $this->insert_time_agenda($horario, $phonenumber, $Userid, $isReagendamento, $minutes_schedule);
                        
                        if ($agenda) {
                            try {
                                log_activity("set_horario_agenda SUCCESS - Lead ID: {$leadid}, Date: {$horario}, Agenda created successfully", $log_staff_id);
                            } catch (Exception $e) {
                                error_log("Failed to log SUCCESS: " . $e->getMessage());
                            }
                        } else {
                            try {
                                log_activity("set_horario_agenda FAILED - Lead ID: {$leadid}, Date: {$horario}, insert_time_agenda returned false", $log_staff_id);
                            } catch (Exception $e) {
                                error_log("Failed to log FAILED: " . $e->getMessage());
                            }
                        }

                        if ($summary != null && $summary != "" && $agenda) {

                            if ($phonenumber) {
                                $this->db->where('phonenumber', $phonenumber);
                                $lead = $this->db->get(db_prefix() . 'leads')->row();

                                $this->db->insert(db_prefix() . 'notes', [
                                    'rel_id'         => $lead->id,
                                    'rel_type'       => 'lead',
                                    'dateadded'      => date('Y-m-d H:i:s'),
                                    'addedfrom'      => $Userid,
                                    'description'    => $summary,
                                    'date_contacted' => date('Y-m-d H:i:s'),
                                ]);
                            }
                        }

                        // se o link_call estiver ativo, retorna o link
                        if (get_option("contac_active_link_call")) {
                            $output = json_encode([
                                "success" => !empty($agenda) ? "true" : "false",
                                "link_call" => $agenda["link_call"]
                            ]);
                        } else {
                            $output = json_encode([
                                "success" => !empty($agenda) ? "true" : "false"
                            ]);
                        }
                    } else {
                        $output = json_encode(["success" => "false"]);
                    }
                } elseif ($function_name == "verificar_agendamento_lead") {
                    $response = $this->verificar_agendamento_lead($phonenumber);
                    $output = json_encode($response ? ["date" => $response] : "false");
                } else if ($function_name == "current_datetime") {


                    $all_days = [];

                    $today = new DateTime();

                    for ($i = 0; $i < 100; $i++) {
                        $all_days[] = [
                            'date' => $today->format('Y-m-d'), // Usando um formato padrão de data
                            'dayOfWeek' => $today->format('l'), // Dia da semana por extenso
                        ];
                        $today->modify('+1 day'); // Passa para o próximo dia
                    }

                    $currentDay = [
                        'date' => (new DateTime())->format('Y-m-d'),
                        'dayOfWeek' => (new DateTime())->format('l')
                    ];

                    $output = json_encode([
                        'all_days' => $all_days,
                        'currentDay' => $currentDay
                    ]);
                } else if ($function_name == "weekday") {
                    $all_days = [];

                    $today = new DateTime();

                    for ($i = 0; $i < 100; $i++) {
                        $all_days[] = [
                            'date' => $today->format('Y-m-d'), // Usando um formato padrão de data
                            'dayOfWeek' => $today->format('l'), // Dia da semana por extenso
                        ];
                        $today->modify('+1 day'); // Passa para o próximo dia
                    }

                    $currentDay = [
                        'date' => (new DateTime())->format('Y-m-d'),
                        'dayOfWeek' => (new DateTime())->format('l')
                    ];

                    $output = json_encode([
                        'all_days' => $all_days,
                        'currentDay' => $currentDay
                    ]);
                } else if ($function_name == "get_timezone") {

                    $output = json_encode(['timezone' => date_default_timezone_get()]);
                } elseif ($function_name == "get_tabela_precos") {
                    $items = $this->db->get(db_prefix() . 'items')->result();
                    $contents = [];
                    $moeda = get_currencies_default();

                    foreach ($items as $item) {
                        $contents[] = [
                            "item" => $item->description,
                            "description" => $item->long_description,
                            "rate" => $item->rate,
                            "quant" => 1,
                            "currency" => $moeda
                        ];
                    }

                    $output = json_encode($items ? ["items" => $contents] : ["success" => "false"]);
                } elseif ($function_name == "set_proposta") {
                    $this->load->model('proposals_model');
                    $subtotal = 0;
                    $orderCounter = 1;

                    $currentDate = date('d/m/Y');
                    $openTillDate = date('d/m/Y', strtotime('+7 days'));

                    $this->db->where("phonenumber", $phonenumber);
                    $lead = $this->db->get(db_prefix() . 'leads')->row();

                    $Userid = $staffid ? $staffid : 1;

                    $proposal = [
                        'subject' => $function_arguments["proposal_data"]["subject"],
                        'rel_type' => 'lead',
                        'rel_id' => $lead->id,
                        'date' => $currentDate,
                        'open_till' => $openTillDate,
                        'currency' => 3,
                        'discount_type' => '',
                        'tags' => '',
                        'allow_comments' => 'on',
                        'status' => 4,
                        'assigned' => $Userid,
                        'proposal_to' => $lead->name,
                        'city' => $lead->city,
                        'state' => $lead->state,
                        'zip' => $lead->zip,
                        'email' => $lead->email ? $lead->email : "123456@example.com.br",
                        'phone' => $lead->phonenumber,
                        'newitems' => [],
                        'subtotal' => 0,
                        'total' => 0
                    ];

                    foreach ($function_arguments['newitems'] as $item) {
                        $proposal['newitems'][] = [
                            'order' => $orderCounter++,
                            'description' => $item['description'],
                            'long_description' => $item['long_description'],
                            'qty' => $item['qty'],
                            'unit' => $item['unit'],
                            'rate' => $item['rate']
                        ];
                        $subtotal += $item['rate'] * $item['qty'];
                    }

                    $proposal['subtotal'] = $subtotal;
                    $proposal['total'] = $subtotal;

                    $id = $this->proposals_model->add($proposal);
                    $hash = $this->db->where("id", $id)->get(db_prefix() . 'proposals')->row();

                    $output = json_encode($id ? ["link" => site_url("proposal/{$hash->id}/{$hash->hash}")] : ["success" => "false"]);
                } elseif ($function_name == "get_processes") {

                    // Formata o CPF ou CNPJ para o padrão armazenado no banco
                    $document = $this->format_cpf_cnpj($function_arguments["document"]);

                    $this->db->where('vat', $document);
                    $client = $this->db->get(db_prefix() . 'clients')->row();

                    if ($client == null) {
                        $output = json_encode(["success" => "false", "message" => "Cliente nao encontrado"]);
                    } else {

                        // busco os processos desse cliente
                        $this->db->where('userid', $client->userid);
                        $processes = $this->db->get(db_prefix() . 'juridico_process')->result();

                        if ($processes) {
                            $contents = [];
                            foreach ($processes as $process) {

                                // busco a ultima movimentaçao do processo
                                $this->db->where('process_id', $process->id);
                                $this->db->order_by('step_date', 'DESC');
                                $movimentacao = $this->db->get(db_prefix() . 'juridico_step')->row();

                                if ($movimentacao) {
                                    $contents[] = [
                                        "movimentation_description" => $movimentacao->content,
                                        "process_number" => $process->code,
                                        "step_date" => $movimentacao->step_date
                                    ];
                                } else {
                                    $contents[] = [
                                        "movimentation_description" => "",
                                        "process_number" => $process->code,
                                        "step_date" => ""
                                    ];
                                }
                            }
                            $output = json_encode(["processes" => $contents]);
                        } else {
                            $output = json_encode(["success" => "false", "message" => "Cliente nao tem processos"]);
                        }
                    }
                } elseif ($function_name == "get_faturas_sankhya") {
                    $this->load->model('sankhya/sankhya_model');

                    $document = preg_replace('/\D/', '', $function_arguments["document"]);

                    $faturas = $this->sankhya_model->get_client_by_cnpj_invoice($document);
                    if ($faturas) {
                        $output = json_encode(["success" => "true", "faturas" => $faturas]);
                    } else {
                        $output = json_encode(["success" => "false", "message" => "Cliente não tem faturas"]);
                    }
                } elseif ($function_name == "get_faturas_axiom") {

                    $faturas = $this->get_invoice_client($function_arguments["document"]);
                    if ($faturas) {
                        $output = json_encode(["success" => "true", "faturas" => $faturas]);
                    } else {
                        $output = json_encode(["success" => "false", "message" => "Cliente não tem faturas"]);
                    }
                } elseif ($function_name == "open_ticket") {

                    $this->load->model('tickets_model');

                    $message = $function_arguments["problem_description"];
                    //coloca a tag <a> para abrir o link no navegador do cliente
                    $message = "<a href='" . admin_url("contactcenter/chatsingle/{$device_id}?number={$phonenumber}") . "' target='_blank'><i class='fa-regular fa-comment'></a> -> " . $message;


                    $crear_ticket = [
                        'subject' => $function_arguments["summary"],
                        'contactid' => '',
                        'userid' => '',
                        'name' => 'Open by IA',
                        'email' => 'ia@axiom.com.br',
                        'department' => (get_option('default_status_ticket_ia') ? get_option('default_status_ticket_ia') : 1),
                        'cc' => '',
                        'tags' => '',
                        'assigned' => (get_option('default_staff_ticket_ia') ? get_option('default_staff_ticket_ia') : 1),
                        'priority' => '2',
                        'service' => '',
                        'message' => html_purify($message),
                    ];

                    $id = $this->tickets_model->add($crear_ticket, get_staff_user_id());
                    if ($id) {
                        $output = json_encode(["success" => "true", "ticket" => "Nº " . $id]);
                    } else {
                        $output = json_encode(["success" => "false", "message" => "Erro ao criar ticket"]);
                    }
                } elseif ($function_name == "create_contract") {

                    $convert_lead = $this->convert_to_customer($leadid);
                    if ($convert_lead) {
                        $contract = $this->create_contracts_clients_ia($convert_lead, $device_id);
                        if ($contract) {
                            //transfoma o phonenumber e staffid base64
                            $phonenumber = base64_encode($phonenumber);
                            $staffid = base64_encode($staffid);
                            $link = $contract . '&p=' . $phonenumber . '&s=' . $staffid;

                            $output = json_encode(["success" => "true", "contract_link" => $link]);
                        } else {
                            log_activity('Erro ao criar contrato, pela IA device_id: ' . $device_id . ' leadid: ' . $leadid);
                            $output = json_encode(["success" => "false", "message" => "Erro ao criar contrato"]);
                        }
                    } else {
                        log_activity('Erro ao converter lead para cliente, pela IA device_id: ' . $device_id . ' leadid: ' . $leadid);
                        $output = json_encode(["success" => "false", "message" => "Erro ao criar contrato"]);
                    }
                } elseif (strtolower(trim($function_name)) == "update_leads") {
                    // Log that we matched the function name
                    try {
