                    log_activity("update_leads CURRENT STATUS - Lead ID: {$leadid}, Status ID: " . ($status_atual ?? 'null') . ", Status Name: " . ($status_atual_nome ?? 'N/A'), get_staff_user_id());

                    $fields = [
                        'name',
