                    ];
                    
                    foreach ($function_arguments as $field_name => $field_value) {
                        log_activity("update_leads PROCESSING FIELD - Lead ID: {$leadid}, Field: {$field_name}, Value: " . (is_array($field_value) ? json_encode($field_value) : $field_value), get_staff_user_id());
                        
                        // Map fields with lead_ prefix to database fields
                        if (isset($field_mapping[$field_name])) {
