                    }
                    
                    log_activity("update_leads DATA FOR UPDATE - Lead ID: {$leadid}, Data: " . json_encode($data), get_staff_user_id());
                    log_activity("update_leads CUSTOM FIELDS FOR UPDATE - Lead ID: {$leadid}, Custom Fields: " . json_encode($custom_fields_with_values), get_staff_user_id());

                    // Update lead data
                    if (!empty($data)) {
                        // Check current values before update to see if they're different
                        $current_values = [];
                        foreach ($data as $key => $value) {
                            if (isset($lead_atual->$key)) {
                                $current_values[$key] = $lead_atual->$key;
                            }
                        }
                        log_activity("update_leads CURRENT VALUES - Lead ID: {$leadid}, Current: " . json_encode($current_values), get_staff_user_id());
                        
                        // Ensure email is properly trimmed if present
                        if (isset($data['email'])) {
                            $data['email'] = trim($data['email']);
                            if (empty($data['email'])) {
                                unset($data['email']); // Remove empty email
                                log_activity("update_leads EMAIL REMOVED - Lead ID: {$leadid}, Email was empty after trim", get_staff_user_id());
                            } else {
                                log_activity("update_leads EMAIL FINAL - Lead ID: {$leadid}, Email to save: {$data['email']}", get_staff_user_id());
                            }
                        }
                        
                        $this->db->where('id', $leadid);
                        $this->db->update(db_prefix() . 'leads', $data);
                        $affected_rows = $this->db->affected_rows();
                        
                        log_activity("update_leads UPDATE EXECUTED - Lead ID: {$leadid}, Affected Rows: {$affected_rows}", get_staff_user_id());
                        
                        // Verify the update by checking the database
                        $this->db->where('id', $leadid);
                        $lead_after = $this->db->get(db_prefix() . 'leads')->row();
                        
                        $update_successful = false;
                        foreach ($data as $key => $value) {
                            if (isset($lead_after->$key) && $lead_after->$key == $value) {
                                $update_successful = true;
                                log_activity("update_leads FIELD VERIFIED - Lead ID: {$leadid}, Field: {$key}, Value matches: {$value}", get_staff_user_id());
                            } elseif (isset($lead_after->$key) && $lead_after->$key != $value) {
                                log_activity("update_leads FIELD MISMATCH - Lead ID: {$leadid}, Field: {$key}, Expected: {$value}, Got: " . $lead_after->$key, get_staff_user_id());
                            }
                        }
                        
                        if ($affected_rows == 0 && !$update_successful) {
                            log_activity("update_leads WARNING - No rows affected and values don't match. Lead ID: {$leadid}, Data: " . json_encode($data) . ", Current: " . json_encode($current_values), get_staff_user_id());
                            // Still count as success if we tried to update (maybe values were already correct)
                            $affected_rows = 1; // Count as success if we attempted update
                        } elseif ($affected_rows == 0 && $update_successful) {
                            log_activity("update_leads INFO - No rows affected but values match (already updated). Lead ID: {$leadid}", get_staff_user_id());
                            $affected_rows = 1; // Count as success
                        }
                    } else {
                        log_activity("update_leads WARNING - No data to update. Lead ID: {$leadid}", get_staff_user_id());
                        $affected_rows = 0;
                    }

                    // Verify if status was actually changed
                    if ($status_alterado && $affected_rows > 0) {
                        $lead_depois = $this->get_leads($leadid);
                        $status_depois = $lead_depois ? $lead_depois->status : null;
                        $status_depois_nome = null;
                        if ($status_depois) {
                            $this->load->model('leads_model');
                            $status_obj_depois = $this->leads_model->get_status($status_depois);
                            $status_depois_nome = $status_obj_depois ? $status_obj_depois->name : 'N/A';
                        }
                        
                        log_activity("update_leads STATUS AFTER UPDATE - Lead ID: {$leadid}, Status ID: " . ($status_depois ?? 'null') . ", Status Name: " . ($status_depois_nome ?? 'N/A'), get_staff_user_id());
                        
                        if ($status_depois == $novo_status_id) {
                            log_activity("update_leads SUCCESS - Status changed successfully! Lead ID: {$leadid}, From: {$status_atual_nome} (ID: {$status_atual}) To: {$status_depois_nome} (ID: {$status_depois})", get_staff_user_id());
                        } else {
                            log_activity("update_leads ERROR - Status was NOT changed! Lead ID: {$leadid}, Expected: {$novo_status_nome} (ID: {$novo_status_id}), Current: {$status_depois_nome} (ID: {$status_depois})", get_staff_user_id());
                        }
                    } elseif ($status_alterado && $affected_rows == 0) {
                        log_activity("update_leads ERROR - Status change requested but no rows affected. Lead ID: {$leadid}, New Status ID: {$novo_status_id}", get_staff_user_id());
                    }

                    // Save custom fields if there are values
                    if (!empty($custom_fields_with_values['leads'])) {
                        log_activity("update_leads PROCESSING CUSTOM FIELDS - Lead ID: {$leadid}, Custom Fields: " . json_encode($custom_fields_with_values), get_staff_user_id());
                        try {
