                    } else {
                        log_activity("update_leads NO CUSTOM FIELDS - Lead ID: {$leadid}, No custom fields to update", get_staff_user_id());
                    }

                    // Create log with updated fields
                    $mensagem_log = 'Update performed by AXIOM';
                    if (!empty($alteracoes)) {
                        $mensagem_log .= ': ' . implode(', ', $alteracoes);
                    }

                    try {
                        $this->load->model('leads_model');
                        $this->leads_model->log_lead_activity($leadid, $mensagem_log);
