                    } catch (Exception $e) {
                        log_activity("update_leads ERROR - Failed to log lead activity. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                    }

                    log_activity("update_leads COMPLETED - Lead ID: {$leadid}, Success: true, Changes: " . count($alteracoes), get_staff_user_id());

                    $output = json_encode(["success" => "true"]);
                } elseif ($function_name == "get_lead_info") {
                    // Busca todas as informações do lead
                    $lead = $this->get_leads($leadid);
                    
                    if (!$lead) {
                        $output = json_encode([
                            "success" => "false",
                            "message" => "Lead não encontrado"
                        ]);
                    } else {
                        // Informações básicas do lead
                        $leadInfo = [
                            "id" => $lead->id ?? null,
                            "name" => $lead->name ?? null,
                            "title" => $lead->title ?? null,
                            "company" => $lead->company ?? null,
                            "email" => $lead->email ?? null,
                            "phonenumber" => $lead->phonenumber ?? null,
                            "address" => $lead->address ?? null,
                            "city" => $lead->city ?? null,
                            "state" => $lead->state ?? null,
                            "zip" => $lead->zip ?? null,
                            "country" => $lead->country ?? null,
                            "website" => $lead->website ?? null,
                            "description" => $lead->description ?? null,
                            "status" => $lead->status ?? null,
                            "source" => $lead->source ?? null,
                            "lead_value" => $lead->lead_value ?? null,
                            "assigned" => $lead->assigned ?? null,
                            "dateadded" => $lead->dateadded ?? null,
                            "lastcontact" => $lead->lastcontact ?? null,
                            "date_converted" => $lead->date_converted ?? null,
                            "last_status_change" => $lead->last_status_change ?? null,
                        ];

                        // Busca nome do status se existir
                        if ($lead->status) {
                            $this->db->where('id', $lead->status);
                            $status = $this->db->get(db_prefix() . 'leads_status')->row();
                            if ($status) {
                                $leadInfo["status_name"] = $status->name;
                            }
                        }

                        // Busca nome da fonte se existir
                        if ($lead->source) {
                            $this->db->where('id', $lead->source);
                            $source = $this->db->get(db_prefix() . 'leads_sources')->row();
                            if ($source) {
                                $leadInfo["source_name"] = $source->name;
                            }
                        }

                        // Busca todos os campos personalizados
                        $customFields = get_custom_fields('leads');
                        $leadInfo["custom_fields"] = [];
                        
                        if ($customFields) {
                            foreach ($customFields as $customField) {
                                $fieldValue = get_custom_field_value($leadid, $customField['id'], 'leads', false);
                                if ($fieldValue !== '' && $fieldValue !== null) {
                                    $leadInfo["custom_fields"][$customField['slug']] = [
                                        "name" => $customField['name'],
                                        "value" => $fieldValue,
                                        "type" => $customField['type']
                                    ];
                                }
                            }
                        }

                        // Remove campos vazios/null para não poluir a resposta
                        $leadInfo = array_filter($leadInfo, function($value) {
                            return $value !== null && $value !== '';
                        });

                        $output = json_encode([
                            "success" => "true",
                            "lead" => $leadInfo
                        ]);
                    }
                } elseif ($function_name == "get_lead_context") {
                    // Busca todo o contexto e histórico do lead
                    // Initialize output to ensure it's always set
                    $output = json_encode(["success" => "false", "message" => "Function execution started"]);
                    
                    // Set execution time limit for this function (30 seconds)
                    $start_time = microtime(true);
                    $max_execution_time = 30;
                    
                    try {
                        // Parse function arguments to determine context limits
                        $recent_only = isset($function_arguments["recent_only"]) && $function_arguments["recent_only"] === true;
                        $conversation_limit = isset($function_arguments["limit"]) ? (int)$function_arguments["limit"] : null;
                        $include_all = isset($function_arguments["include_all"]) && $function_arguments["include_all"] === true;
                        
                        // Default strategy: Start with last 50 conversations for recent context
                        // This prevents overwhelming the assistant with too much history
                        $default_limit = 50;
                        $max_limit = 200; // Maximum allowed even if requested more
                        
                        // Determine actual limit to use
                        if ($include_all) {
                            $actual_limit = 500; // Full history if explicitly requested
                            log_activity("get_lead_context MODE - Full history requested. Lead ID: {$leadid}", get_staff_user_id());
                        } elseif ($conversation_limit !== null && $conversation_limit > 0) {
                            $actual_limit = min($conversation_limit, $max_limit); // Respect requested limit but cap at max
                            log_activity("get_lead_context MODE - Custom limit requested: {$conversation_limit}, Using: {$actual_limit}. Lead ID: {$leadid}", get_staff_user_id());
                        } elseif ($recent_only) {
                            $actual_limit = $default_limit; // Use default recent limit
                            log_activity("get_lead_context MODE - Recent only mode, limit: {$actual_limit}. Lead ID: {$leadid}", get_staff_user_id());
                        } else {
                            $actual_limit = $default_limit; // Default: recent context only
                            log_activity("get_lead_context MODE - Default mode (recent context), limit: {$actual_limit}. Lead ID: {$leadid}", get_staff_user_id());
                        }
                        
                        log_activity("get_lead_context START - Lead ID: {$leadid}, Device ID: {$device_id}, Limit: {$actual_limit}", get_staff_user_id());
                        $lead = $this->get_leads($leadid);
                        
                        if (!$lead) {
                            log_activity("get_lead_context ERROR - Lead not found. Lead ID: {$leadid}", get_staff_user_id());
                            $output = json_encode([
                                "success" => "false",
                                "message" => "Lead não encontrado"
                            ]);
                        } else {
                            log_activity("get_lead_context LEAD FOUND - Lead ID: {$leadid}, Name: " . ($lead->name ?? 'N/A'), get_staff_user_id());
                            
                            // Check execution time
                            $elapsed = microtime(true) - $start_time;
                            if ($elapsed > $max_execution_time) {
                                throw new Exception("Function execution timeout after {$elapsed} seconds");
                            }
                            $context = [
                                "lead_id" => $lead->id ?? null,
                                "lead_name" => $lead->name ?? null,
                                "phonenumber" => $lead->phonenumber ?? null,
                                "context_mode" => $include_all ? "full" : ($recent_only ? "recent_only" : "recent"),
                                "conversations_limit_applied" => $actual_limit,
                            ];

                            $phoneNumber = $lead->phonenumber ?? null;
                            $phoneClean = $phoneNumber ? preg_replace('/\D/', '', $phoneNumber) : null;
                            
                            // Initialize arrays and counts
                            $conversations = [];
                            $original_conversation_count = 0;
                            
                            log_activity("get_lead_context PHONE PROCESSED - Lead ID: {$leadid}, Original: " . ($phoneNumber ?? 'null') . ", Cleaned: " . ($phoneClean ?? 'null'), get_staff_user_id());

                            // 1. Busca conversas/mensagens com o lead - limitado para contexto recente
                            if ($phoneClean) {
                                try {
                                    log_activity("get_lead_context FETCHING CONVERSATIONS - Lead ID: {$leadid}, Phone: {$phoneClean}, Limit: {$actual_limit}", get_staff_user_id());
                                    // Busca mensagens usando msg_conversation_number (mesmo campo usado pela página de chat)
                                    // Isso garante consistência com get_messages_chat e retorna apenas conversas individuais (não grupos)
                                    // Ordena por mais recente primeiro e limita conforme solicitado
                                    $this->db->select('m.*, s.firstname, s.lastname, d.dev_name')
                                             ->from(db_prefix() . 'contactcenter_message m')
                                             ->join(db_prefix() . 'staff s', 's.staffid = m.staffid', 'left')
                                             ->join(db_prefix() . 'contactcenter_device d', 'd.dev_token = m.msg_session', 'left')
                                             ->where('m.msg_conversation_number', $phoneClean)
                                             ->where('m.msg_isGroupMsg', 0) // Exclui mensagens de grupo, apenas conversas individuais
                                             ->order_by('m.msg_date', 'DESC')
                                             ->limit($actual_limit); // Limita conforme o modo escolhido (default: 50 mais recentes)
                                    
                                    $query_result = $this->db->get();
                                    
                                    // Check if query was successful
                                    if ($query_result === false) {
                                        $db_error = $this->db->error();
                                        log_activity("get_lead_context CONVERSATIONS QUERY FAILED - Lead ID: {$leadid}, DB Error: " . json_encode($db_error), get_staff_user_id());
                                        $messages = [];
                                        $original_conversation_count = 0;
                                    } else {
                                        $messages = $query_result->result_array();
                                        log_activity("get_lead_context CONVERSATIONS FETCHED - Lead ID: {$leadid}, Count: " . count($messages), get_staff_user_id());
                                        
                                        // Check total count available (for summary) - only if we got messages
                                        if (count($messages) > 0) {
                                            $this->db->select('COUNT(*) as total')
                                                     ->from(db_prefix() . 'contactcenter_message m')
                                                     ->where('m.msg_conversation_number', $phoneClean)
                                                     ->where('m.msg_isGroupMsg', 0); // Exclui mensagens de grupo
                                            $total_result = $this->db->get()->row();
                                            $original_conversation_count = $total_result ? (int)$total_result->total : count($messages);
                                            log_activity("get_lead_context TOTAL CONVERSATIONS AVAILABLE - Lead ID: {$leadid}, Total in DB: {$original_conversation_count}, Returning: " . count($messages), get_staff_user_id());
                                        } else {
                                            $original_conversation_count = 0;
                                        }
                                    }

                                    foreach ($messages as $msg) {
                                        $conversations[] = [
                                            "date" => $msg['msg_date'] ?? null,
                                            "direction" => ($msg['msg_fromMe'] == 1) ? "sent" : "received",
                                            "content" => $msg['msg_content'] ?? null,
                                            "staff_name" => !empty($msg['firstname']) ? trim($msg['firstname'] . ' ' . ($msg['lastname'] ?? '')) : null,
                                            "staff_id" => $msg['staffid'] ?? null,
                                            "device_name" => $msg['dev_name'] ?? null,
                                            "type" => "conversation"
                                        ];
                                    }
                                    
                                    log_activity("get_lead_context CONVERSATIONS PROCESSED - Lead ID: {$leadid}, Included: " . count($conversations) . ", Total available: {$original_conversation_count}", get_staff_user_id());
                                } catch (Exception $e) {
                                    log_activity("get_lead_context ERROR - Failed to fetch conversations. Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                                } catch (Throwable $e) {
                                    log_activity("get_lead_context FATAL ERROR - Failed to fetch conversations. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                                }
                            } else {
                                log_activity("get_lead_context SKIP CONVERSATIONS - Lead ID: {$leadid}, No phone number", get_staff_user_id());
                            }
                            
                            log_activity("get_lead_context AFTER CONVERSATIONS - Lead ID: {$leadid}, Continuing to campaigns...", get_staff_user_id());

                            // 2. Busca mensagens de campanhas enviadas ao lead
                            // Campaign messages are tracked in leads table via conversation_engine_id and conversation_engine_send
                            // We can also identify campaign messages in contactcenter_message by checking if they were sent
                            // by the system during campaign execution (they would have specific characteristics)
                            $campaignMessages = [];
                            try {
                                log_activity("get_lead_context FETCHING CAMPAIGNS - Lead ID: {$leadid}", get_staff_user_id());
                                
                                // Check if lead has been part of any campaigns by checking conversation_engine_id
                                if ($lead->conversation_engine_id) {
                                    $this->db->select('ce.con_id, ce.con_title as campaign_name, ce.con_date as campaign_date, l.conversation_engine_send as send_date')
                                             ->from(db_prefix() . 'contactcenter_conversation_engine ce')
                                             ->join(db_prefix() . 'leads l', 'l.conversation_engine_id = ce.con_id', 'left')
                                             ->where('l.id', $leadid)
                                             ->where('l.conversation_engine_send IS NOT NULL', null, false)
                                             ->order_by('l.conversation_engine_send', 'DESC')
                                             ->limit(50);
                                    
                                    $query_result = $this->db->get();
                                    
                                    // Check if query was successful
                                    if ($query_result === false) {
                                        $db_error = $this->db->error();
                                        log_activity("get_lead_context CAMPAIGN QUERY FAILED - Lead ID: {$leadid}, DB Error: " . json_encode($db_error), get_staff_user_id());
                                        $campaigns = [];
                                    } else {
                                        $campaigns = $query_result->result_array();
                                        log_activity("get_lead_context CAMPAIGNS FETCHED - Lead ID: {$leadid}, Count: " . count($campaigns), get_staff_user_id());
                                    }
                                    
                                    foreach ($campaigns as $camp) {
                                        $campaignMessages[] = [
                                            "date" => $camp['send_date'] ?? null,
                                            "campaign_name" => $camp['campaign_name'] ?? null,
                                            "campaign_id" => $camp['con_id'] ?? null,
                                            "type" => "campaign"
                                        ];
                                    }
                                    log_activity("get_lead_context CAMPAIGNS PROCESSED - Lead ID: {$leadid}, Total: " . count($campaignMessages), get_staff_user_id());
                                } else {
                                    log_activity("get_lead_context NO CAMPAIGNS - Lead ID: {$leadid}, Lead has no conversation_engine_id", get_staff_user_id());
                                }
                            } catch (Exception $e) {
                                log_activity("get_lead_context ERROR - Failed to fetch campaign messages. Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                            } catch (Throwable $e) {
                                log_activity("get_lead_context FATAL ERROR - Failed to fetch campaign messages. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                            }
                            
                            log_activity("get_lead_context AFTER CAMPAIGNS - Lead ID: {$leadid}, Continuing to follow-ups...", get_staff_user_id());

                            // 3. Busca follow-ups/agendamentos relacionados ao lead
                            $followUps = [];
                            if ($this->db->table_exists(db_prefix() . 'events')) {
                                try {
                                    log_activity("get_lead_context FETCHING FOLLOW-UPS - Lead ID: {$leadid}", get_staff_user_id());
                                    $this->db->select('e.*, s.firstname, s.lastname')
                                             ->from(db_prefix() . 'events e')
                                             ->join(db_prefix() . 'staff s', 's.staffid = e.userid', 'left')
                                             ->where('e.rel_type', 'lead')
                                             ->where('e.rel_id', $leadid)
                                             ->order_by('e.start', 'DESC')
                                             ->limit(50);
                                    
                                    $query_result = $this->db->get();
                                    
                                    // Check if query was successful
                                    if ($query_result === false) {
                                        $db_error = $this->db->error();
                                        log_activity("get_lead_context FOLLOW-UP QUERY FAILED - Lead ID: {$leadid}, DB Error: " . json_encode($db_error), get_staff_user_id());
                                        $events = [];
                                    } else {
                                        $events = $query_result->result_array();
                                        log_activity("get_lead_context FOLLOW-UPS FETCHED - Lead ID: {$leadid}, Count: " . count($events), get_staff_user_id());
                                    }
                                    
                                    foreach ($events as $event) {
                                        $followUps[] = [
                                            "event_id" => $event['eventid'] ?? null,
                                            "title" => $event['title'] ?? null,
                                            "start" => $event['start'] ?? null,
                                            "end" => $event['end'] ?? null,
                                            "staff_name" => !empty($event['firstname']) ? trim($event['firstname'] . ' ' . ($event['lastname'] ?? '')) : null,
                                            "status" => $event['status'] ?? null,
                                            "description" => $event['description'] ?? null,
                                            "type" => "followup"
                                        ];
                                    }
                                    log_activity("get_lead_context FOLLOW-UPS PROCESSED - Lead ID: {$leadid}, Total: " . count($followUps), get_staff_user_id());
                                } catch (Exception $e) {
                                    log_activity("get_lead_context ERROR - Failed to fetch follow-ups. Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                                } catch (Throwable $e) {
                                    log_activity("get_lead_context FATAL ERROR - Failed to fetch follow-ups. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                                }
                            } else {
                                log_activity("get_lead_context SKIP FOLLOW-UPS - Lead ID: {$leadid}, Events table does not exist", get_staff_user_id());
                            }
                            
                            log_activity("get_lead_context AFTER FOLLOW-UPS - Lead ID: {$leadid}, Continuing to manual messages...", get_staff_user_id());

                            // 4. Busca mensagens manuais (speed messages) enviadas ao lead
                            $manualMessages = [];
                            if ($phoneClean) {
                                try {
                                    log_activity("get_lead_context FETCHING MANUAL MESSAGES - Lead ID: {$leadid}, Phone: {$phoneClean}", get_staff_user_id());
                                    // Como alternativa, identificamos mensagens manuais como aquelas enviadas
                                    // por staff (msg_fromMe = 1 e staffid não nulo) que não são de campanha
                                    $this->db->select('m.*, s.firstname, s.lastname')
                                             ->from(db_prefix() . 'contactcenter_message m')
                                             ->join(db_prefix() . 'staff s', 's.staffid = m.staffid', 'left')
                                             ->where('m.msg_to', $phoneClean)
                                             ->where('m.msg_fromMe', 1)
                                             ->where('m.staffid IS NOT NULL', null, false)
                                             ->where('m.staffid >', 0)
                                             ->order_by('m.msg_date', 'DESC')
                                             ->limit(100);
                                    
                                    $query_result = $this->db->get();
                                    
                                    // Check if query was successful
                                    if ($query_result === false) {
                                        $db_error = $this->db->error();
                                        log_activity("get_lead_context MANUAL MESSAGES QUERY FAILED - Lead ID: {$leadid}, DB Error: " . json_encode($db_error), get_staff_user_id());
                                        $manual = [];
                                    } else {
                                        $manual = $query_result->result_array();
                                        log_activity("get_lead_context MANUAL MESSAGES FETCHED - Lead ID: {$leadid}, Count: " . count($manual), get_staff_user_id());
                                    }
                                    
                                    foreach ($manual as $man) {
                                        // Verifica se não é de campanha (campanhas geralmente não têm staffid específico)
                                        $manualMessages[] = [
                                            "date" => $man['msg_date'] ?? null,
                                            "content" => $man['msg_content'] ?? null,
                                            "staff_name" => !empty($man['firstname']) ? trim($man['firstname'] . ' ' . ($man['lastname'] ?? '')) : null,
                                            "staff_id" => $man['staffid'] ?? null,
                                            "type" => "manual"
                                        ];
                                    }
                                    log_activity("get_lead_context MANUAL MESSAGES PROCESSED - Lead ID: {$leadid}, Total: " . count($manualMessages), get_staff_user_id());
                                } catch (Exception $e) {
                                    log_activity("get_lead_context ERROR - Failed to fetch manual messages. Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                                } catch (Throwable $e) {
                                    log_activity("get_lead_context FATAL ERROR - Failed to fetch manual messages. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                                }
                            } else {
                                log_activity("get_lead_context SKIP MANUAL MESSAGES - Lead ID: {$leadid}, No phone number", get_staff_user_id());
                            }
                            
                            log_activity("get_lead_context AFTER MANUAL MESSAGES - Lead ID: {$leadid}, Continuing to activities...", get_staff_user_id());

                            // 5. Busca atividades do lead (log de atividades)
                            $activities = [];
                            $activityTable = db_prefix() . 'lead_activity_log';
                            if ($this->db->table_exists($activityTable)) {
                                try {
                                    log_activity("get_lead_context FETCHING ACTIVITIES - Lead ID: {$leadid}", get_staff_user_id());
                                    $this->db->select('lal.*, s.firstname, s.lastname')
                                             ->from($activityTable . ' lal')
                                             ->join(db_prefix() . 'staff s', 's.staffid = lal.staffid', 'left')
                                             ->where('lal.leadid', $leadid)
                                             ->order_by('lal.date', 'DESC')
                                             ->limit(50);
                                    
                                    $query_result = $this->db->get();
                                    
                                    // Check if query was successful
                                    if ($query_result === false) {
                                        $db_error = $this->db->error();
                                        log_activity("get_lead_context ACTIVITIES QUERY FAILED - Lead ID: {$leadid}, DB Error: " . json_encode($db_error), get_staff_user_id());
                                        $acts = [];
                                    } else {
                                        $acts = $query_result->result_array();
                                        log_activity("get_lead_context ACTIVITIES FETCHED - Lead ID: {$leadid}, Count: " . count($acts), get_staff_user_id());
                                    }
                                    
                                    foreach ($acts as $act) {
                                        $activities[] = [
                                            "date" => $act['date'] ?? null,
                                            "description" => $act['description'] ?? null,
                                            "staff_name" => !empty($act['firstname']) ? trim($act['firstname'] . ' ' . ($act['lastname'] ?? '')) : null,
                                            "type" => $act['type'] ?? null,
                                            "type_name" => "activity"
                                        ];
                                    }
                                    log_activity("get_lead_context ACTIVITIES PROCESSED - Lead ID: {$leadid}, Total: " . count($activities), get_staff_user_id());
                                } catch (Exception $e) {
                                    log_activity("get_lead_context ERROR - Failed to fetch activities. Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . substr($e->getTraceAsString(), 0, 500), get_staff_user_id());
                                } catch (Throwable $e) {
                                    log_activity("get_lead_context FATAL ERROR - Failed to fetch activities. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                                }
                            } else {
                                log_activity("get_lead_context SKIP ACTIVITIES - Lead ID: {$leadid}, Activity table does not exist", get_staff_user_id());
                            }
                            
                            log_activity("get_lead_context AFTER ACTIVITIES - Lead ID: {$leadid}, Starting to build context...", get_staff_user_id());

                        // Organiza o contexto inicial (antes da truncation)
                        // Store original counts for summary (use the total available count we fetched)
                        if (!isset($original_conversation_count)) {
                            $original_conversation_count = count($conversations);
                        }
                        $original_campaign_count = count($campaignMessages);
                        $original_followup_count = count($followUps);
                        $original_manual_count = count($manualMessages);
                        $original_activity_count = count($activities);
                        
                        log_activity("get_lead_context BUILDING CONTEXT - Lead ID: {$leadid}, Conversations included: " . count($conversations) . " of {$original_conversation_count} total, Campaigns: {$original_campaign_count}, Follow-ups: {$original_followup_count}", get_staff_user_id());
                        
                        // Store initial arrays (will be truncated later)
                        $context["conversations"] = $conversations;
                        $context["campaign_messages"] = $campaignMessages;
                        $context["follow_ups"] = $followUps;
                        $context["manual_messages"] = $manualMessages;
                        $context["activities"] = $activities;

                        log_activity("get_lead_context BEFORE JSON ENCODE - Lead ID: {$leadid}, Context keys: " . implode(', ', array_keys($context)), get_staff_user_id());
                        
                        try {
                            // PRIORITY: Always include recent conversations for context understanding
                            // Limit content length in individual conversations first to save space
                            foreach ($conversations as &$conv) {
                                if (isset($conv['content']) && strlen($conv['content']) > 500) {
                                    $conv['content'] = substr($conv['content'], 0, 500) . '... [truncated]';
                                }
                            }
                            unset($conv);
                            
                            // Limit manual messages and activities to save space (keep conversations)
                            if (count($manualMessages) > 20) {
                                $manualMessages = array_slice($manualMessages, 0, 20);
                                log_activity("get_lead_context WARNING - Truncated manual messages to 20. Lead ID: {$leadid}", get_staff_user_id());
                            }
                            
                            if (count($activities) > 20) {
                                $activities = array_slice($activities, 0, 20);
                                log_activity("get_lead_context WARNING - Truncated activities to 20. Lead ID: {$leadid}", get_staff_user_id());
                            }
                            
                            // Helper function to build summary with actual included data
                            $buildSummary = function($conv_data, $camp_data, $follow_data, $manual_data, $act_data) use ($original_conversation_count, $original_campaign_count, $original_followup_count, $original_manual_count, $original_activity_count) {
                                $last_conversation_date = null;
                                if (!empty($conv_data) && isset($conv_data[0]['date'])) {
                                    $last_conversation_date = $conv_data[0]['date'];
                                }
                                
                                $last_campaign_date = null;
                                if (!empty($camp_data) && isset($camp_data[0]['date'])) {
                                    $last_campaign_date = $camp_data[0]['date'];
                                }
                                
                                $last_follow_up_date = null;
                                if (!empty($follow_data) && isset($follow_data[0]['start'])) {
                                    $last_follow_up_date = $follow_data[0]['start'];
                                }
                                
                                $has_more = $original_conversation_count > count($conv_data);
                                
                                return [
                                    "total_conversations" => $original_conversation_count,
                                    "conversations_included" => count($conv_data),
                                    "has_more_conversations" => $has_more,
                                    "total_campaign_messages" => $original_campaign_count,
                                    "campaign_messages_included" => count($camp_data),
                                    "total_follow_ups" => $original_followup_count,
                                    "follow_ups_included" => count($follow_data),
                                    "total_manual_messages" => $original_manual_count,
                                    "manual_messages_included" => count($manual_data),
                                    "total_activities" => $original_activity_count,
                                    "activities_included" => count($act_data),
                                    "last_conversation_date" => $last_conversation_date,
                                    "last_campaign_date" => $last_campaign_date,
                                    "last_follow_up_date" => $last_follow_up_date,
                                    "note" => $has_more 
                                        ? "More conversations available. Call get_lead_context again with 'limit' parameter (e.g., limit: 100) or 'include_all': true to retrieve older messages."
                                        : "All available conversations included."
                                ];
                            };
                            
                            // Progressive truncation strategy: Always prioritize recent conversations
                            // Try with all conversations first, then reduce progressively if needed
                            $max_output_size = 95000; // ~95KB to leave some margin (OpenAI limit is ~100KB)
                            $conversation_limits = [300, 200, 150, 100, 75, 50, 30, 20, 15, 10]; // Progressive limits
                            $output = null;
                            
                            foreach ($conversation_limits as $limit) {
                                // Use most recent conversations (they're already ordered DESC)
                                $final_conversations = (count($conversations) > $limit) ? array_slice($conversations, 0, $limit) : $conversations;
                                $final_campaigns = array_slice($campaignMessages, 0, 10);
                                $final_followups = array_slice($followUps, 0, 10);
                                
                                // Build summary with actual included data
                                $summary = $buildSummary($final_conversations, $final_campaigns, $final_followups, $manualMessages, $activities);
                                
                                // Build context with truncated data and summary
                                $test_context = [
                                    "lead_id" => $context["lead_id"],
                                    "lead_name" => $context["lead_name"],
                                    "phonenumber" => $context["phonenumber"],
                                    "conversations" => $final_conversations, // Always include conversations
                                    "campaign_messages" => $final_campaigns,
                                    "follow_ups" => $final_followups,
                                    "manual_messages" => $manualMessages,
                                    "activities" => $activities,
                                    "summary" => $summary
                                ];
                                
                                $test_output = json_encode([
                                    "success" => "true",
                                    "context" => $test_context
                                ], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
                                
                                if ($test_output === false) {
                                    throw new Exception("JSON encoding failed: " . json_last_error_msg());
                                }
                                
                                $output_size = strlen($test_output);
                                
                                if ($output_size <= $max_output_size) {
                                    $output = $test_output;
                                    $context["conversations"] = $final_conversations;
                                    $context["campaign_messages"] = $final_campaigns;
                                    $context["follow_ups"] = $final_followups;
                                    $context["manual_messages"] = $manualMessages;
                                    $context["activities"] = $activities;
                                    $context["summary"] = $summary;
                                    
                                    if (count($conversations) > $limit) {
                                        log_activity("get_lead_context WARNING - Truncated conversations to {$limit} most recent (Output size: {$output_size} bytes). Lead ID: {$leadid}", get_staff_user_id());
                                    }
                                    break;
                                }
                            }
                            
                            // If still too large even with minimum conversations, at least include recent ones
                            if ($output === null) {
                                // Keep only the most recent 10 conversations as absolute minimum
                                $final_conversations = array_slice($conversations, 0, 10);
                                $summary = $buildSummary($final_conversations, [], [], [], []);
                                
                                $context["conversations"] = $final_conversations;
                                $context["campaign_messages"] = [];
                                $context["follow_ups"] = [];
                                $context["manual_messages"] = [];
                                $context["activities"] = [];
                                $context["summary"] = $summary;
                                
                                $output = json_encode([
                                    "success" => "true",
                                    "context" => $context
                                ], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
                                
                                if ($output === false) {
                                    throw new Exception("JSON encoding failed: " . json_last_error_msg());
                                }
                                
                                log_activity("get_lead_context WARNING - Using minimum context (10 most recent conversations only) due to size constraints. Lead ID: {$leadid}, Output size: " . strlen($output) . " bytes", get_staff_user_id());
                            }
                            
                            // Validate JSON encoding was successful
                            if ($output === false || !is_string($output)) {
                                throw new Exception("JSON encoding failed or output is invalid");
                            }
                            
                            log_activity("get_lead_context SUCCESS - Lead ID: {$leadid}, Output size: " . strlen($output) . " bytes, Conversations included: " . count($context["conversations"]) . " of {$original_conversation_count} total", get_staff_user_id());
                        } catch (Exception $e) {
                            log_activity("get_lead_context ERROR - JSON encoding failed. Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                            $output = json_encode([
                                "success" => "false",
                                "message" => "Erro ao processar contexto do lead: " . $e->getMessage()
                            ]);
                        }
                    }
                    } catch (Exception $e) {
                        log_activity("get_lead_context ERROR - General error. Lead ID: {$leadid}, Error: " . $e->getMessage() . " - Trace: " . $e->getTraceAsString(), get_staff_user_id());
                        $output = json_encode([
                            "success" => "false",
                            "message" => "Erro ao buscar contexto do lead: " . $e->getMessage()
                        ]);
                    }
                    
                    // Ensure output is always set (safety check)
                    if (empty($output) || !isset($output)) {
                        log_activity("get_lead_context CRITICAL - Output not set! Lead ID: {$leadid}", get_staff_user_id());
                        $output = json_encode([
                            "success" => "false",
                            "message" => "Erro inesperado ao processar contexto do lead"
                        ]);
                    }
                    
                    log_activity("get_lead_context COMPLETED - Lead ID: {$leadid}, Output length: " . strlen($output) . " bytes", get_staff_user_id());
                } elseif (strtolower(trim($function_name)) == "manage_conversation") {
                    log_activity("manage_conversation FUNCTION MATCHED - Lead ID: {$leadid}, Device ID: {$device_id}, Arguments: " . json_encode($function_arguments), get_staff_user_id());
                    log_activity("manage_conversation INICIADO - Lead ID: {$leadid}, Arguments: " . json_encode($function_arguments), get_staff_user_id());
                    
                    // Gerencia a conversa: desabilita/habilita IA, muda staff owner, notificações, etc
                    $actions_performed = [];
                    $lead = $this->get_leads($leadid);
                    
                    if (!$lead) {
                        log_activity("manage_conversation ERRO - Lead não encontrado. Lead ID: {$leadid}", get_staff_user_id());
                        $output = json_encode([
                            "success" => "false",
                            "message" => "Lead não encontrado"
                        ]);
                    } else {
                        // Busca status atual do lead
                        $status_atual = $lead->status;
                        $status_atual_nome = null;
                        if ($status_atual) {
                            $this->load->model('leads_model');
                            $status_obj_atual = $this->leads_model->get_status($status_atual);
                            $status_atual_nome = $status_obj_atual ? $status_obj_atual->name : 'N/A';
                        }
                        log_activity("manage_conversation STATUS ATUAL - Lead ID: {$leadid}, Status ID: " . ($status_atual ?? 'null') . ", Status Nome: " . ($status_atual_nome ?? 'N/A'), get_staff_user_id());
                        
                        $update_data = [];
                        
                        // Desabilitar IA
                        if (isset($function_arguments["disable_ai"]) && $function_arguments["disable_ai"] === true) {
                            // CRITICAL: Only disable AI for THIS specific lead, NOT the device
                            // Log device info to track if device-level disabling is happening
                            $device_info = $this->get_device($device_id);
                            $device_ai_status_before = $device_info ? $device_info->dev_openai : 'unknown';
                            
                            log_activity("manage_conversation DISABLE_AI CALLED - Lead ID: {$leadid}, Device ID: {$device_id}, Device AI Status: {$device_ai_status_before}, Phone: " . ($lead->phonenumber ?? 'N/A'), get_staff_user_id());
                            
                            $update_data["gpt_status"] = 1;
                            $actions_performed[] = "IA desabilitada para esta conversa (apenas este lead)";
                            
                            // Verify we're only updating the lead, not the device
                            log_activity("manage_conversation DISABLE_AI - Apenas atualizando gpt_status do lead [ID: {$leadid}], NÃO alterando dev_openai do device [ID: {$device_id}]", get_staff_user_id());
                        }
                        
                        // Habilitar IA
                        if (isset($function_arguments["enable_ai"]) && $function_arguments["enable_ai"] === true) {
                            $update_data["gpt_status"] = 0;
                            $actions_performed[] = "IA habilitada para esta conversa";
                            log_activity("manage_conversation - IA habilitada para o lead [ID: {$leadid}]", get_staff_user_id());
                        }
                        
                        // Mudar staff owner
                        if (isset($function_arguments["change_staff_owner"]) && !empty($function_arguments["change_staff_owner"])) {
                            $new_staff_id = (int)$function_arguments["change_staff_owner"];
                            
                            log_activity("manage_conversation MUDANÇA STAFF - Lead ID: {$leadid}, Novo Staff ID: {$new_staff_id}, Staff Atual: " . ($lead->assigned ?? 'null'), get_staff_user_id());
                            
                            // Verifica se o staff existe
                            $this->db->where('staffid', $new_staff_id);
                            $staff = $this->db->get(db_prefix() . 'staff')->row();
                            
                            if ($staff) {
                                $update_data["assigned"] = $new_staff_id;
                                $actions_performed[] = "Responsável alterado para: " . get_staff_full_name($new_staff_id);
                                
                                // Envia notificação para o novo responsável
                                $this->load->model('leads_model');
                                $this->leads_model->lead_assigned_member_notification($leadid, $new_staff_id, true);
                                
                                log_activity("manage_conversation STAFF ALTERADO - Lead ID: {$leadid}, Novo Staff: " . get_staff_full_name($new_staff_id) . " (ID: {$new_staff_id})", get_staff_user_id());
                            } else {
                                $actions_performed[] = "Erro: Staff ID {$new_staff_id} não encontrado";
                                log_activity("manage_conversation ERRO STAFF - Staff ID {$new_staff_id} não encontrado para Lead ID: {$leadid}", get_staff_user_id());
                            }
                        }
                        
                        // Mudar status
                        if (isset($function_arguments["change_status"]) && !empty($function_arguments["change_status"])) {
                            $new_status = (int)$function_arguments["change_status"];
                            
                            log_activity("manage_conversation MUDANÇA STATUS - Lead ID: {$leadid}, Novo Status ID: {$new_status}, Status Atual: {$status_atual} ({$status_atual_nome})", get_staff_user_id());
                            
                            // Verifica se o status existe
                            $this->db->where('id', $new_status);
                            $status = $this->db->get(db_prefix() . 'leads_status')->row();
                            
                            if ($status) {
                                $update_data["status"] = $new_status;
                                $update_data["last_status_change"] = date('Y-m-d H:i:s');
                                $actions_performed[] = "Status alterado para: " . $status->name;
                                
                                log_activity("manage_conversation STATUS VALIDADO - Lead ID: {$leadid}, Novo Status Nome: {$status->name} (ID: {$new_status})", get_staff_user_id());
                                
                                // Log de atividade
                                $this->load->model('leads_model');
                                $this->leads_model->log_lead_activity($leadid, 'not_lead_activity_status_updated', false, serialize([
                                    'Sistema (IA)',
                                    $lead->status ? $this->leads_model->get_status($lead->status)->name : 'N/A',
                                    $status->name,
                                ]));
                                
                                log_activity("manage_conversation STATUS PREPARADO PARA UPDATE - Lead ID: {$leadid}, De: {$status_atual_nome} (ID: {$status_atual}) Para: {$status->name} (ID: {$new_status})", get_staff_user_id());
                            } else {
                                $actions_performed[] = "Erro: Status ID {$new_status} não encontrado";
                                log_activity("manage_conversation ERRO STATUS - Status ID {$new_status} não encontrado para Lead ID: {$leadid}", get_staff_user_id());
                            }
                        }
                        
                        // Atualiza o lead se houver mudanças usando o método Leads_model->update
                        if (!empty($update_data)) {
                            $update_data["lastcontact"] = date('Y-m-d H:i:s');
                            
                            log_activity("manage_conversation DADOS PARA UPDATE - Lead ID: {$leadid}, Update Data: " . json_encode($update_data), get_staff_user_id());
                            
                            // Carrega o modelo Leads_model se ainda não estiver carregado
                            if (!isset($this->leads_model)) {
                                $this->load->model('leads_model');
                            }
                            
                            // Usa o método update do Leads_model para atualizar apenas este lead específico
                            // Isso garante que apenas o lead específico seja atualizado, não o dispositivo inteiro
                            
                            // CRITICAL SAFEGUARD: Verify device AI status before update to detect if device is being disabled
                            $device_before = $this->get_device($device_id);
                            $device_ai_before = $device_before ? $device_before->dev_openai : null;
                            
                            $update_success = $this->leads_model->update($update_data, $leadid);
                            
                            // CRITICAL SAFEGUARD: Verify device AI status after update to ensure device wasn't accidentally disabled
                            $device_after = $this->get_device($device_id);
                            $device_ai_after = $device_after ? $device_after->dev_openai : null;
                            
                            if ($device_ai_before !== null && $device_ai_after !== null && $device_ai_before != $device_ai_after) {
                                // ALERT: Device AI status changed during lead update - this should NOT happen!
                                log_activity("manage_conversation CRITICAL ERROR - Device AI status changed during lead update! Device ID: {$device_id}, Before: {$device_ai_before}, After: {$device_ai_after}, Lead ID: {$leadid}", get_staff_user_id());
                            }
                            
                            log_activity("manage_conversation UPDATE EXECUTADO - Lead ID: {$leadid}, Success: " . ($update_success ? 'true' : 'false') . ", Device AI Status Check: Before={$device_ai_before}, After={$device_ai_after}", get_staff_user_id());
                            
                            // Verify the update only affected the specific lead
                            if (isset($update_data["gpt_status"])) {
                                $lead_after = $this->get_leads($leadid);
                                $gpt_status_after = $lead_after ? $lead_after->gpt_status : null;
                                log_activity("manage_conversation GPT_STATUS VERIFICATION - Lead ID: {$leadid}, Expected gpt_status: {$update_data['gpt_status']}, Actual gpt_status: {$gpt_status_after}", get_staff_user_id());
                            }
                            
                            // Verifica se o status foi realmente alterado (apenas se o update foi bem-sucedido)
                            if (isset($update_data["status"]) && $update_success) {
                                $lead_depois = $this->get_leads($leadid);
                                $status_depois = $lead_depois ? $lead_depois->status : null;
                                $status_depois_nome = null;
                                if ($status_depois) {
                                    $this->load->model('leads_model');
                                    $status_obj_depois = $this->leads_model->get_status($status_depois);
                                    $status_depois_nome = $status_obj_depois ? $status_obj_depois->name : 'N/A';
                                }
                                
                                log_activity("manage_conversation STATUS DEPOIS DO UPDATE - Lead ID: {$leadid}, Status ID: " . ($status_depois ?? 'null') . ", Status Nome: " . ($status_depois_nome ?? 'N/A'), get_staff_user_id());
                                
                                if ($status_depois == $update_data["status"]) {
                                    log_activity("manage_conversation SUCESSO - Status alterado com sucesso! Lead ID: {$leadid}, De: {$status_atual_nome} (ID: {$status_atual}) Para: {$status_depois_nome} (ID: {$status_depois})", get_staff_user_id());
                                } else {
                                    $status_esperado_nome = isset($status) ? $status->name : 'N/A';
                                    log_activity("manage_conversation ERRO - Status NÃO foi alterado! Lead ID: {$leadid}, Esperado: {$status_esperado_nome} (ID: {$update_data['status']}), Atual: {$status_depois_nome} (ID: {$status_depois})", get_staff_user_id());
                                }
                            }
                        } else {
                            log_activity("manage_conversation AVISO - Nenhum dado para atualizar. Lead ID: {$leadid}", get_staff_user_id());
                        }
                        
                        // Enviar notificação personalizada
                        if (isset($function_arguments["send_notification"]) && $function_arguments["send_notification"] === true) {
                            $notification_message = isset($function_arguments["notification_message"]) 
                                ? $function_arguments["notification_message"] 
                                : "Ação realizada na conversa do lead #{$leadid}";
                            
                            // Use the new staff ID if it was changed, otherwise use current assigned or fallback
                            $notification_to = null;
                            if (isset($function_arguments["change_staff_owner"]) && !empty($function_arguments["change_staff_owner"])) {
                                $notification_to = (int)$function_arguments["change_staff_owner"];
                                log_activity("manage_conversation NOTIFICATION TARGET - Using new staff owner for notification. Lead ID: {$leadid}, Staff ID: {$notification_to}", get_staff_user_id());
                            } else {
                                // Get the current assigned staff (after update if it was changed)
                                $this->db->where('id', $leadid);
                                $current_lead = $this->db->get(db_prefix() . 'leads')->row();
                                $notification_to = $current_lead->assigned ?? $lead->assigned ?? get_staff_user_id();
                                log_activity("manage_conversation NOTIFICATION TARGET - Using current assigned staff. Lead ID: {$leadid}, Staff ID: {$notification_to}", get_staff_user_id());
                            }
                            
                            if ($notification_to) {
                                // Verify staff exists
                                $this->db->where('staffid', $notification_to);
                                $staff_exists = $this->db->get(db_prefix() . 'staff')->row();
                                
                                if ($staff_exists && $staff_exists->active == 1) {
                                    $notification_data = [
                                        'description' => $notification_message,
                                        'touserid' => $notification_to,
                                        'link' => admin_url("leads/index/{$leadid}"),
                                    ];
                                    
                                    log_activity("manage_conversation NOTIFICATION CREATING - Lead ID: {$leadid}, Staff ID: {$notification_to}, Message: {$notification_message}", get_staff_user_id());
                                    
                                    try {
                                        $notification_result = add_notification($notification_data);
                                        
                                        if ($notification_result) {
                                            log_activity("manage_conversation NOTIFICATION CREATED - Lead ID: {$leadid}, Staff ID: {$notification_to}, Notification ID: " . ($notification_result ?: 'N/A'), get_staff_user_id());
                                            
                                            // Trigger Pusher notification
                                            try {
                                                pusher_trigger_notification([$notification_to]);
                                                log_activity("manage_conversation NOTIFICATION PUSHER TRIGGERED - Lead ID: {$leadid}, Staff ID: {$notification_to}", get_staff_user_id());
                                            } catch (Exception $e) {
                                                log_activity("manage_conversation NOTIFICATION PUSHER ERROR - Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                                            }
                                            
                                            $actions_performed[] = "Notificação enviada para " . get_staff_full_name($notification_to);
                                        } else {
                                            log_activity("manage_conversation NOTIFICATION FAILED - add_notification returned false. Lead ID: {$leadid}, Staff ID: {$notification_to}", get_staff_user_id());
                                            $actions_performed[] = "Erro ao enviar notificação";
                                        }
                                    } catch (Exception $e) {
                                        log_activity("manage_conversation NOTIFICATION EXCEPTION - Lead ID: {$leadid}, Error: " . $e->getMessage(), get_staff_user_id());
                                        $actions_performed[] = "Erro ao enviar notificação: " . $e->getMessage();
                                    }
                                } else {
                                    log_activity("manage_conversation NOTIFICATION ERROR - Staff ID {$notification_to} não encontrado. Lead ID: {$leadid}", get_staff_user_id());
                                    $actions_performed[] = "Erro: Staff ID {$notification_to} não encontrado para notificação";
                                }
                            } else {
                                log_activity("manage_conversation NOTIFICATION ERROR - No staff ID available. Lead ID: {$leadid}", get_staff_user_id());
                                $actions_performed[] = "Erro: Nenhum staff disponível para receber notificação";
                            }
                        } else {
                            log_activity("manage_conversation NOTIFICATION SKIPPED - send_notification is false or not set. Lead ID: {$leadid}", get_staff_user_id());
                        }
                        
                        log_activity("manage_conversation FINALIZADO - Lead ID: {$leadid}, Actions: " . implode(', ', $actions_performed), get_staff_user_id());
                        
                        $output = json_encode([
                            "success" => "true",
                            "message" => "Ações executadas com sucesso",
                            "actions" => $actions_performed
                        ]);
                    }
                } elseif ($function_name == "send_media") {
                    // Função para enviar mídia através do assistente
                    try {
                        // Log inicial com todos os parâmetros recebidos
                        log_activity("send_media INICIADO - Arguments: " . json_encode($function_arguments) . " - Device ID: {$device_id} - Lead ID: {$leadid}", get_staff_user_id());
                        
                        $media_type = isset($function_arguments["media_type"]) ? $function_arguments["media_type"] : "image";
                        $media_variable = isset($function_arguments["media_variable"]) ? $function_arguments["media_variable"] : null;
                        $media_id = isset($function_arguments["media_id"]) ? (int)$function_arguments["media_id"] : null;
                        $media_url = isset($function_arguments["media_url"]) ? $function_arguments["media_url"] : null;
                        $caption = isset($function_arguments["caption"]) ? $function_arguments["caption"] : "";

                        log_activity("send_media PARÂMETROS - media_type: {$media_type}, media_variable: " . ($media_variable ?? 'null') . ", media_id: " . ($media_id ?? 'null') . ", media_url: " . ($media_url ?? 'null'), get_staff_user_id());

                        // Validação: deve ter media_variable OU media_id OU media_url
                        if (!$media_variable && !$media_id && !$media_url) {
                            log_activity("send_media ERRO - Nenhum parâmetro de mídia fornecido", get_staff_user_id());
                            $output = json_encode([
                                "success" => "false",
                                "message" => "É necessário fornecer media_variable, media_id ou media_url"
                            ]);
                        } else {
                            $final_url = null;
                            $file_name = null;

                            // Busca o device para obter o assistant_ai_id
                            $device = $this->get_device($device_id);
                            if (!$device) {
                                log_activity("send_media ERRO - Dispositivo não encontrado: {$device_id}", get_staff_user_id());
                                $output = json_encode([
                                    "success" => "false",
                                    "message" => "Dispositivo não encontrado"
                                ]);
                            } elseif (!$device->assistant_ai_id) {
                                log_activity("send_media ERRO - Dispositivo não possui assistant_ai_id configurado. Device ID: {$device_id}", get_staff_user_id());
                                $output = json_encode([
                                    "success" => "false",
                                    "message" => "Dispositivo não possui assistente configurado"
                                ]);
                            } else {
                                log_activity("send_media DEVICE ENCONTRADO - Device ID: {$device_id}, Assistant AI ID: {$device->assistant_ai_id}", get_staff_user_id());
                                // Se foi fornecido media_variable, busca pelo nome da variável
                                if ($media_variable) {
                                    log_activity("send_media BUSCANDO POR VARIÁVEL - Variable recebida: {$media_variable}", get_staff_user_id());
                                    
                                    // Normaliza a variável: remove espaços e garante que tenha chaves
                                    $variable_name = trim($media_variable);
                                    if (strpos($variable_name, '{') !== 0) {
                                        $variable_name = '{' . $variable_name;
                                    }
                                    if (substr($variable_name, -1) !== '}') {
                                        $variable_name = $variable_name . '}';
                                    }
                                    
                                    log_activity("send_media VARIÁVEL NORMALIZADA - Variable normalizada: {$variable_name}", get_staff_user_id());
                                    
                                    // Busca a mídia pela variável exata
                                    $this->db->where('variable_name', $variable_name);
                                    $this->db->where('assist_id', $device->assistant_ai_id);
                                    $query = $this->db->get(db_prefix() . 'contactcenter_assistants_media');
                                    $media = $query->row();
                                    
                                    log_activity("send_media QUERY 1 - SQL: " . $this->db->last_query() . " - Resultado: " . ($media ? "ENCONTRADO" : "NÃO ENCONTRADO"), get_staff_user_id());
                                    
                                    if (!$media) {
                                        // Tenta buscar sem as chaves também
                                        $variable_clean = trim($media_variable, '{}');
                                        $variable_clean_formatted = '{' . $variable_clean . '}';
                                        
                                        log_activity("send_media TENTANDO BUSCAR SEM CHAVES - Variable clean: {$variable_clean_formatted}", get_staff_user_id());
                                        
                                        $this->db->where('variable_name', $variable_clean_formatted);
                                        $this->db->where('assist_id', $device->assistant_ai_id);
                                        $query2 = $this->db->get(db_prefix() . 'contactcenter_assistants_media');
                                        $media = $query2->row();
                                        
                                        log_activity("send_media QUERY 2 - SQL: " . $this->db->last_query() . " - Resultado: " . ($media ? "ENCONTRADO" : "NÃO ENCONTRADO"), get_staff_user_id());
                                    }
                                    
                                    if (!$media) {
                                        // Lista todas as variáveis disponíveis para debug
                                        $this->db->where('assist_id', $device->assistant_ai_id);
                                        $all_media = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->result();
                                        $available_vars = [];
                                        $available_details = [];
                                        foreach ($all_media as $m) {
                                            $available_vars[] = $m->variable_name;
                                            $available_details[] = "ID: {$m->id}, Variable: {$m->variable_name}, File: {$m->file_name}, Path: {$m->file_path}";
                                        }
                                        
                                        log_activity("send_media MÍDIA NÃO ENCONTRADA - Variable buscada: {$media_variable} (normalizada: {$variable_name}) - Assistant ID: {$device->assistant_ai_id} - Total de mídias cadastradas: " . count($all_media), get_staff_user_id());
                                        log_activity("send_media MÍDIAS DISPONÍVEIS - " . implode(' | ', $available_details), get_staff_user_id());
                                        
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "Mídia não encontrada com a variável: " . $media_variable . ". Variáveis disponíveis: " . implode(', ', $available_vars)
                                        ]);
                                    } else {
                                        $final_url = site_url("uploads/{$media->file_path}");
                                        
                                        // Pega o nome completo do arquivo com extensão do file_path (igual ao conversation_engine faz)
                                        // Conversation Engine: $name = explode('/', $message_engine->image); $fileName = end($name);
                                        $name_parts = explode('/', $media->file_path);
                                        $file_name = end($name_parts); // Nome completo com extensão
                                        
                                        log_activity("send_media MÍDIA ENCONTRADA - ID: {$media->id}, Variable: {$media->variable_name}, File: {$media->file_name}, Path: {$media->file_path}, File Name completo (com extensão): {$file_name}", get_staff_user_id());
                                        
                                        // Detecta o tipo de mídia pelo arquivo se não foi especificado corretamente
                                        $file_ext = strtolower(pathinfo($media->file_path, PATHINFO_EXTENSION));
                                        log_activity("send_media EXTENSÃO DO ARQUIVO - Extensão: {$file_ext}", get_staff_user_id());
                                        
                                        if (in_array($file_ext, ['mp4', 'avi', 'mov', 'wmv', 'flv', 'webm', 'mkv'])) {
                                            $media_type = "video";
                                        } elseif (in_array($file_ext, ['mp3', 'wav', 'ogg', 'm4a', 'aac'])) {
                                            $media_type = "audio";
                                        } elseif (in_array($file_ext, ['pdf', 'doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx'])) {
                                            $media_type = "document";
                                        } elseif (in_array($file_ext, ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp'])) {
                                            $media_type = "image";
                                        }
                                        
                                        log_activity("send_media TIPO DETECTADO - Tipo final: {$media_type}, URL final: {$final_url}", get_staff_user_id());
                                        
                                        // Verifica se a URL é acessível publicamente
                                        $headers = @get_headers($final_url, 1);
                                        if ($headers && strpos($headers[0], '200') !== false) {
                                            log_activity("send_media URL ACESSÍVEL - URL retornou HTTP 200 (OK)", get_staff_user_id());
                                        } else {
                                            log_activity("send_media AVISO - URL pode não ser acessível publicamente. Headers: " . (is_array($headers) ? json_encode($headers) : 'Não retornou headers'), get_staff_user_id());
                                        }
                                    }
                                } elseif ($media_id) {
                                    // Se foi fornecido media_id, busca pelo ID
                                    $this->db->where('id', $media_id);
                                    $this->db->where('assist_id', $device->assistant_ai_id);
                                    $media = $this->db->get(db_prefix() . 'contactcenter_assistants_media')->row();
                                    
                                    if (!$media) {
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "Mídia não encontrada no assistente com ID: " . $media_id
                                        ]);
                                    } else {
                                        $final_url = site_url("uploads/{$media->file_path}");
                                        
                                        // Pega o nome completo do arquivo com extensão do file_path (igual ao conversation_engine faz)
                                        $name_parts = explode('/', $media->file_path);
                                        $file_name = end($name_parts); // Nome completo com extensão
                                    }
                                } else {
                                    // Se foi fornecido media_url, valida e usa
                                    if (filter_var($media_url, FILTER_VALIDATE_URL)) {
                                        $final_url = $media_url;
                                        // Tenta extrair o nome do arquivo da URL
                                        $parsed_url = parse_url($media_url);
                                        if (isset($parsed_url['path'])) {
                                            $file_name = basename($parsed_url['path']);
                                        }
                                    } else {
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "URL de mídia inválida"
                                        ]);
                                    }
                                }
                            }

                            // Se temos uma URL válida, envia a mídia
                            if ($final_url) {
                                log_activity("send_media PREPARANDO ENVIO - URL: {$final_url}, Tipo: {$media_type}, File Name: {$file_name}, Caption: '{$caption}', Phone: {$phonenumber}", get_staff_user_id());
                                
                                // Comparação com Conversation Engine e Follow-up
                                log_activity("send_media COMPARAÇÃO - Conversation Engine usa: send_file(strval(\$lead->phonenumber), \$texto, \$img, \$message_engine->media_type, \$device->staffid, \$fileName)", get_staff_user_id());
                                log_activity("send_media COMPARAÇÃO - Follow-up usa: send_file(strval(\$lead->phonenumber), \$texto, \$img, \$Conversas->media_type, \$agente->staffid, \$fileName)", get_staff_user_id());
                                log_activity("send_media COMPARAÇÃO - Send_media agora usa: send_file(strval(\$phonenumber), \$caption, \$final_url, \$media_type, \$staffid, \$file_name) - MESMOS PARÂMETROS que Conversation Engine e Follow-up", get_staff_user_id());
                                
                                // Valida o tipo de mídia
                                $allowed_types = ["image", "video", "document", "audio"];
                                if (!in_array($media_type, $allowed_types)) {
                                    log_activity("send_media ERRO - Tipo de mídia inválido: {$media_type}", get_staff_user_id());
                                    $output = json_encode([
                                        "success" => "false",
                                        "message" => "Tipo de mídia inválido. Use: image, video, document ou audio"
                                    ]);
                                } else {
                                    // Para áudio, usa send_audio() em vez de send_file() (igual ao follow-up e conversation_engine)
                                    if ($media_type == "audio") {
                                        // If staffid is null or lead doesn't have assigned staff, use device staffid as fallback
                                        if (empty($staffid) && $device) {
                                            $staffid = $device->staffid;
                                            log_activity("send_media STAFFID FALLBACK - Lead assigned staff is null/empty, using device staffid: {$staffid}", get_staff_user_id());
                                        }
                                        
                                        log_activity("send_media CHAMANDO send_audio - Parâmetros: number={$phonenumber}, url={$final_url}, staffid={$staffid}", get_staff_user_id());
                                        
                                        $response = $this->send_audio(
                                            $phonenumber,
                                            $final_url,
                                            $staffid,
                                            true, // queue
                                            'AI' // type_source
                                        );
                                    } else {
                                        // Para outros tipos (image, video, document), usa send_file()
                                        // Conversation Engine e Follow-up também usam send_file para image/video/document
                                        // Usa EXATAMENTE os mesmos parâmetros que conversation_engine usa (sem passar reply_id, queue e type_source)
                                        // Conversation Engine: send_file(strval($lead->phonenumber), $texto, $img, $message_engine->media_type, $device->staffid, $fileName)
                                        
                                        // If staffid is null or lead doesn't have assigned staff, use device staffid as fallback
                                        if (empty($staffid) && $device) {
                                            $staffid = $device->staffid;
                                            log_activity("send_media STAFFID FALLBACK - Lead assigned staff is null/empty, using device staffid: {$staffid}", get_staff_user_id());
                                        }
                                        
                                        log_activity("send_media CHAMANDO send_file - Usando EXATAMENTE os mesmos parâmetros do conversation_engine:", get_staff_user_id());
                                        log_activity("send_media send_file - strval(phonenumber): '" . strval($phonenumber) . "', caption: '{$caption}', url: '{$final_url}', media_type: '{$media_type}', staffid: {$staffid}, fileName: '{$file_name}' (sem reply_id, queue e type_source - usando defaults)", get_staff_user_id());
                                        
                                        $response = $this->send_file(
                                            strval($phonenumber),
                                            $caption,
                                            $final_url,
                                            $media_type,
                                            $staffid,
                                            $file_name
                                        );
                                        
                                        log_activity("send_media APÓS send_file - Response recebida, verificando estrutura...", get_staff_user_id());
                                    }

                                    log_activity("send_media RESPOSTA COMPLETA - Response: " . json_encode($response, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) . " - Response type: " . gettype($response), get_staff_user_id());
                                    
                                    if (is_array($response)) {
                                        log_activity("send_media ESTRUTURA RESPOSTA - Keys: " . implode(', ', array_keys($response)) . " - Tem 'status': " . (isset($response['status']) ? 'SIM (' . $response['status'] . ')' : 'NÃO') . " - Tem 'error': " . (isset($response['error']) ? 'SIM (' . ($response['error'] ? 'true' : 'false') . ')' : 'NÃO'), get_staff_user_id());
                                        if (isset($response['status'])) {
                                            log_activity("send_media STATUS RESPOSTA - Status: {$response['status']}", get_staff_user_id());
                                        }
                                        if (isset($response['error'])) {
                                            log_activity("send_media ERROR RESPOSTA - Error: " . ($response['error'] ? 'true' : 'false'), get_staff_user_id());
                                            if (isset($response['message'])) {
                                                log_activity("send_media ERROR MESSAGE - Message: " . $response['message'], get_staff_user_id());
                                            }
                                        }
                                        if (isset($response['key'])) {
                                            log_activity("send_media KEY RESPOSTA - Key presente: " . json_encode($response['key']), get_staff_user_id());
                                        }
                                        if (isset($response['message'])) {
                                            log_activity("send_media MESSAGE RESPOSTA - Message presente, tipo: " . gettype($response['message']), get_staff_user_id());
                                        }
                                    }

                                    if ($response === null) {
                                        log_activity("send_media ERRO - send_file retornou null. Device pode estar desconectado ou API não disponível.", get_staff_user_id());
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "Erro ao enviar mídia: Dispositivo pode estar desconectado ou API não disponível. Verifique a conexão do dispositivo."
                                        ]);
                                    } elseif (is_array($response) && isset($response["error"]) && $response["error"]) {
                                        $error_msg = isset($response["message"]) ? $response["message"] : (isset($response["error"]) ? $response["error"] : "Erro desconhecido");
                                        log_activity("send_media ERRO AO ENVIAR - Erro ao enviar mídia pelo assistente AI - Response: " . json_encode($response) . " - Error message: {$error_msg}", get_staff_user_id());
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "Erro ao enviar mídia: " . $error_msg
                                        ]);
                                    } elseif (is_array($response) && isset($response["status"])) {
                                        // Check for valid status values that indicate success
                                        $valid_statuses = ["PENDING", "SENT", "DELIVERED"];
                                        $status = $response["status"];
                                        
                                        if (in_array($status, $valid_statuses)) {
                                            // Quando status é PENDING/SENT/DELIVERED, verifica se há key e message na resposta
                                            // Isso confirma que o WhatsApp realmente recebeu a mensagem
                                            $has_key = isset($response["key"]) && !empty($response["key"]);
                                            $has_message = isset($response["message"]) && !empty($response["message"]);
                                            
                                            log_activity("send_media STATUS VALIDO - Status: {$status}, Tipo: {$media_type}, Lead: {$leadid}, Device: {$device_id}, Phone: {$phonenumber} - Has key: " . ($has_key ? 'SIM' : 'NÃO') . " - Has message: " . ($has_message ? 'SIM' : 'NÃO') . " - URL: {$final_url}", get_staff_user_id());
                                            
                                            // Para áudio, key e message são essenciais para confirmar que foi enviado
                                            // Para outros tipos, status PENDING/SENT/DELIVERED pode ser suficiente
                                            if ($media_type == "audio") {
                                                // Áudio requer key e message para confirmar envio
                                                if ($has_key && $has_message) {
                                                    log_activity("send_media AUDIO ENVIADO COM SUCESSO - Key e message presentes, confirma envio", get_staff_user_id());
                                                    $output = json_encode([
                                                        "success" => "true",
                                                        "message" => "Mídia enviada com sucesso"
                                                    ]);
                                                } else {
                                                    log_activity("send_media AUDIO FALHOU - Status {$status} mas sem key ou message, não foi enviado", get_staff_user_id());
                                                    $output = json_encode([
                                                        "success" => "false",
                                                        "message" => "Erro ao enviar mídia: Resposta incompleta do servidor. Status: {$status} mas faltam dados de confirmação (key/message)."
                                                    ]);
                                                }
                                            } else {
                                                // Para outros tipos de mídia, status válido é suficiente
                                                if ($has_key && $has_message) {
                                                    log_activity("send_media MÍDIA ENVIADA COM SUCESSO - Key e message presentes", get_staff_user_id());
                                                    $output = json_encode([
                                                        "success" => "true",
                                                        "message" => "Mídia enviada com sucesso"
                                                    ]);
                                                } elseif ($status == "PENDING") {
                                                    // PENDING sem key/message pode ser aceito para outros tipos (mas não para áudio)
                                                    log_activity("send_media MÍDIA PENDING - Status PENDING sem key/message, aceito para tipo: {$media_type}", get_staff_user_id());
                                                    $output = json_encode([
                                                        "success" => "true",
                                                        "message" => "Mídia enviada com sucesso (em processamento). Nota: Se a mensagem não chegar, verifique se a URL do arquivo está acessível publicamente."
                                                    ]);
                                                } else {
                                                    // Status SENT/DELIVERED sem key/message ainda é aceito
                                                    log_activity("send_media MÍDIA ENVIADA - Status {$status} sem key/message, mas status indica sucesso", get_staff_user_id());
                                                    $output = json_encode([
                                                        "success" => "true",
                                                        "message" => "Mídia enviada com sucesso"
                                                    ]);
                                                }
                                            }
                                        } else {
                                            // Status inválido ou desconhecido
                                            log_activity("send_media STATUS INVÁLIDO - Status: {$status} não é válido (esperado: PENDING, SENT, DELIVERED)", get_staff_user_id());
                                            $output = json_encode([
                                                "success" => "false",
                                                "message" => "Erro ao enviar mídia: Status inválido do servidor: {$status}"
                                            ]);
                                        }
                                    } elseif (!isset($response["error"])) {
                                        // Response sem error mas também sem status - pode ser um problema
                                        // Verifica se tem outros indicadores de sucesso
                                        $has_key = isset($response["key"]) && !empty($response["key"]);
                                        $has_message = isset($response["message"]) && !empty($response["message"]);
                                        
                                        if ($has_key && $has_message) {
                                            log_activity("send_media SUCESSO SEM STATUS - Key e message presentes, confirma envio", get_staff_user_id());
                                            $output = json_encode([
                                                "success" => "true",
                                                "message" => "Mídia enviada com sucesso"
                                            ]);
                                        } else {
                                            // Sem status, sem error, sem key/message - resposta ambígua, tratar como erro
                                            log_activity("send_media RESPOSTA AMBÍGUA - Sem status, sem error, sem key/message. Response: " . json_encode($response), get_staff_user_id());
                                            $output = json_encode([
                                                "success" => "false",
                                                "message" => "Erro ao enviar mídia: Resposta ambígua do servidor. Não foi possível confirmar se a mídia foi enviada."
                                            ]);
                                        }
                                    } else {
                                        $error_msg = isset($response["error"]) ? $response["error"] : "Erro desconhecido ao enviar mídia";
                                        log_activity("send_media ERRO AO ENVIAR - Erro ao enviar mídia pelo assistente AI - Response: " . json_encode($response) . " - Error message: {$error_msg}", get_staff_user_id());
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "Erro ao enviar mídia: " . $error_msg
                                        ]);
                                    }
                                }
                            } else {
                                log_activity("send_media ERRO - final_url está vazio. Media variable: " . ($media_variable ?? 'null') . ", Media ID: " . ($media_id ?? 'null') . ", Media URL: " . ($media_url ?? 'null'), get_staff_user_id());
                            }
                        }
                    } catch (Exception $e) {
                        log_activity("send_media EXCEÇÃO - Exceção ao processar send_media: " . $e->getMessage() . " - Stack trace: " . $e->getTraceAsString(), get_staff_user_id());
                        $output = json_encode([
                            "success" => "false",
                            "message" => "Erro ao processar envio de mídia: " . $e->getMessage()
                        ]);
                    }
                    
                    log_activity("send_media FINALIZADO - Output: {$output}", get_staff_user_id());
                } elseif ($function_name == "create_group_chat") {
                    // Function to create a group chat between the device/staff and the lead
                    try {
                        log_activity("create_group_chat INICIADO - Lead ID: {$leadid}, Device ID: {$device_id}, Arguments: " . json_encode($function_arguments), get_staff_user_id());
                        
                        // Get lead information
                        $lead = $this->get_leads($leadid);
                        if (!$lead) {
                            log_activity("create_group_chat ERRO - Lead não encontrado. Lead ID: {$leadid}", get_staff_user_id());
                            $output = json_encode([
                                "success" => "false",
                                "message" => "Lead not found"
                            ]);
                        } else {
                            // Get device information
                            $device = $this->get_device($device_id);
                            if (!$device) {
                                log_activity("create_group_chat ERRO - Device não encontrado. Device ID: {$device_id}", get_staff_user_id());
                                $output = json_encode([
                                    "success" => "false",
                                    "message" => "Device not found"
                                ]);
                            } else {
                                // Generate group name
                                $meeting_date = isset($function_arguments["meeting_date"]) ? $function_arguments["meeting_date"] : null;
                                $custom_name = isset($function_arguments["custom_name"]) ? $function_arguments["custom_name"] : null;
                                $group_name = $this->generate_group_chat_name($lead, $meeting_date, $custom_name);
                                
                                log_activity("create_group_chat NOME GERADO - Group Name: {$group_name}, Lead: {$lead->name}, Meeting Date: " . ($meeting_date ?? 'null'), get_staff_user_id());
                                
                                // Get lead phone number (format: 5511999999999)
                                $lead_phone = $phonenumber;
                                
                                // Start with lead phone number
                                $participants = [$lead_phone];
                                
                                // Get configured staff members to auto-add to group
                                $auto_add_staff_ids = get_option('contactcenter_group_chat_auto_add_staff');
                                log_activity("create_group_chat AUTO ADD STAFF CONFIG - Raw config value: " . ($auto_add_staff_ids ?: 'empty') . " (type: " . gettype($auto_add_staff_ids) . ")", get_staff_user_id());
                                
                                if (!empty($auto_add_staff_ids)) {
                                    // Handle both array and comma-separated string formats
                                    if (is_array($auto_add_staff_ids)) {
                                        $staff_ids_array = array_filter($auto_add_staff_ids, function($val) {
                                            return !empty(trim($val));
                                        });
                                    } else {
                                        $staff_ids_array = array_filter(explode(',', $auto_add_staff_ids), function($val) {
                                            return !empty(trim($val));
                                        });
                                    }
                                    
                                    log_activity("create_group_chat AUTO ADD STAFF - Processing " . count($staff_ids_array) . " staff IDs: " . implode(', ', $staff_ids_array), get_staff_user_id());
                                    
                                    $staff_added_count = 0;
                                    $staff_skipped_count = 0;
                                    $staff_failed_count = 0;
                                    
                                    foreach ($staff_ids_array as $staff_id) {
                                        $staff_id = trim($staff_id);
                                        if (empty($staff_id)) {
                                            log_activity("create_group_chat SKIP - Empty staff ID in array", get_staff_user_id());
                                            continue;
                                        }
                                        
                                        // Get staff member info
                                        $staff_info = $this->staff_model->get($staff_id);
                                        $staff_name = $staff_info ? ($staff_info->firstname . ' ' . $staff_info->lastname) : "Unknown (ID: {$staff_id})";
                                        
                                        log_activity("create_group_chat PROCESSING STAFF - Staff ID: {$staff_id}, Name: {$staff_name}", get_staff_user_id());
                                        
                                        // Get phone number from staff profile (phonenumber field)
                                        $staff_phone = null;
                                        if ($staff_info && !empty($staff_info->phonenumber)) {
                                            // Clean phone number (remove non-digits, ensure country code format)
                                            $staff_phone = preg_replace('/\D/', '', $staff_info->phonenumber);
                                            log_activity("create_group_chat STAFF PHONE FROM PROFILE - Staff ID: {$staff_id} ({$staff_name}), Original: {$staff_info->phonenumber}, Cleaned: {$staff_phone}", get_staff_user_id());
                                        } else {
                                            log_activity("create_group_chat STAFF PHONE MISSING - Staff ID: {$staff_id} ({$staff_name}) has no phone number in profile (phonenumber field is empty)", get_staff_user_id());
                                        }
                                        
                                        // If no phone in profile, try to get from device as fallback
                                        if (empty($staff_phone)) {
                                            log_activity("create_group_chat FALLBACK TO DEVICE - Staff ID: {$staff_id} ({$staff_name}), trying to get phone from device", get_staff_user_id());
                                            $staff_devices = $this->get_device(null, $staff_id);
                                            
                                            if (!empty($staff_devices)) {
                                                $devices_list = is_array($staff_devices) ? $staff_devices : [$staff_devices];
                                                log_activity("create_group_chat STAFF DEVICES - Staff ID: {$staff_id} ({$staff_name}) has " . count($devices_list) . " device(s)", get_staff_user_id());
                                                
                                                foreach ($devices_list as $staff_device) {
                                                    $phone_field = !empty($staff_device->dev_number) ? $staff_device->dev_number : null;
                                                    log_activity("create_group_chat DEVICE CHECK - Staff ID: {$staff_id}, Device ID: " . ($staff_device->dev_id ?? 'N/A') . ", Phone field: " . ($phone_field ?: 'empty'), get_staff_user_id());
                                                    
                                                    if ($phone_field) {
                                                        $staff_phone = preg_replace('/\D/', '', $phone_field);
                                                        log_activity("create_group_chat PHONE FROM DEVICE - Staff ID: {$staff_id} ({$staff_name}), Original: {$phone_field}, Cleaned: {$staff_phone}", get_staff_user_id());
                                                        break; // Use first device found with phone number
                                                    }
                                                }
                                            }
                                        }
                                        
                                        // Add staff phone to participants if found
                                        if (!empty($staff_phone)) {
                                            if (!in_array($staff_phone, $participants)) {
                                                $participants[] = $staff_phone;
                                                $staff_added_count++;
                                                log_activity("create_group_chat STAFF ADDED ✓ - Staff ID: {$staff_id}, Name: {$staff_name}, Phone: {$staff_phone}", get_staff_user_id());
                                            } else {
                                                $staff_skipped_count++;
                                                log_activity("create_group_chat STAFF SKIPPED ⚠ - Staff ID: {$staff_id}, Name: {$staff_name}, Phone already in participants: {$staff_phone}", get_staff_user_id());
                                            }
                                        } else {
                                            $staff_failed_count++;
                                            log_activity("create_group_chat STAFF FAILED ✗ - Staff ID: {$staff_id}, Name: {$staff_name} has no phone number in profile or device", get_staff_user_id());
                                        }
                                    }
                                    
                                    log_activity("create_group_chat STAFF SUMMARY - Total processed: " . count($staff_ids_array) . ", Added: {$staff_added_count}, Skipped (duplicate): {$staff_skipped_count}, Failed (no device/phone): {$staff_failed_count}", get_staff_user_id());
                                } else {
                                    log_activity("create_group_chat AUTO ADD STAFF - No staff configured for auto-add", get_staff_user_id());
                                }
                                
                                log_activity("create_group_chat PARTICIPANTS FINAL - Total participants: " . count($participants) . ", List: " . implode(', ', $participants), get_staff_user_id());
                                
                                // Get server information
                                $server = $this->get_server($device->server_id);
                                
                                if (!$server) {
                                    log_activity("create_group_chat ERRO - Server não encontrado. Server ID: " . ($device->server_id ?? 'null'), get_staff_user_id());
                                    $output = json_encode([
                                        "success" => "false",
                                        "message" => "Server not found"
                                    ]);
                                } else {
                                    // Create group using Evolution API
                                    if ($server->api_type == "axiom_evolution") {
                                        $response = $this->axiom_evolution->create_group_evolution(
                                            $server->url,
                                            $device->dev_instance_name,
                                            $device->dev_token,
                                            $group_name,
                                            $participants
                                        );
                                        
                                        // Evolution API returns group ID in different formats depending on version
                                        // Check for: response['id'], response['group']['id'], or response['groupId']
                                        $group_id = null;
                                        
                                        log_activity("create_group_chat RESPONSE CHECK - Full response: " . json_encode($response), get_staff_user_id());
                                        
                                        if (isset($response['id']) && !empty($response['id'])) {
                                            $group_id = $response['id'];
                                            log_activity("create_group_chat GROUP ID FOUND - Found in response['id']: {$group_id}", get_staff_user_id());
                                        } elseif (isset($response['group']['id']) && !empty($response['group']['id'])) {
                                            $group_id = $response['group']['id'];
                                            log_activity("create_group_chat GROUP ID FOUND - Found in response['group']['id']: {$group_id}", get_staff_user_id());
                                        } elseif (isset($response['groupId']) && !empty($response['groupId'])) {
                                            $group_id = $response['groupId'];
                                            log_activity("create_group_chat GROUP ID FOUND - Found in response['groupId']: {$group_id}", get_staff_user_id());
                                        } else {
                                            log_activity("create_group_chat GROUP ID NOT FOUND - Response keys: " . implode(', ', array_keys($response ?: [])), get_staff_user_id());
                                        }
                                        
                                        if ($group_id) {
                                            // Save group to database
                                            $group_data = [
                                                'group_api_name' => $group_name,
                                                'group_api_description' => '',
                                                'group_api_id' => $group_id,
                                                'device_id' => $device_id,
                                                'numbers' => $lead_phone
                                            ];
                                            // Only add date_created if column exists
                                            if ($this->db->field_exists('date_created', db_prefix() . 'contactcenter_group_api')) {
                                                $group_data['date_created'] = date('Y-m-d H:i:s');
                                            }
                                            
                                            $this->db->insert(db_prefix() . 'contactcenter_group_api', $group_data);
                                            $group_db_id = $this->db->insert_id();
                                            
                                            // Log group creation with participant details
                                            $participants_count = count($participants);
                                            $participants_list = implode(', ', $participants);
                                            log_activity("create_group_chat SUCESSO ✓ - Group criado com sucesso. Group ID (API): {$group_id}, Group DB ID: {$group_db_id}, Lead ID: {$leadid}, Total Participants: {$participants_count} ({$participants_list})", get_staff_user_id());
                                            
                                            // Verify participants in API response
                                            if (isset($response['participants']) && is_array($response['participants'])) {
                                                $api_participants = [];
                                                foreach ($response['participants'] as $p) {
                                                    if (isset($p['phoneNumber'])) {
                                                        $api_participants[] = $p['phoneNumber'];
                                                    }
                                                }
                                                log_activity("create_group_chat API VERIFICATION - Group {$group_id} has " . count($api_participants) . " participants in API response: " . implode(', ', $api_participants), get_staff_user_id());
                                            }
                                            
                                            // Set group picture if configured
                                            $default_picture = get_option('contactcenter_group_chat_default_picture');
                                            if (!empty($default_picture)) {
                                                $picture_path = FCPATH . $default_picture;
                                                if (file_exists($picture_path)) {
                                                    $picture_response = $this->axiom_evolution->set_group_picture_evolution(
                                                        $server->url,
                                                        $device->dev_instance_name,
                                                        $device->dev_token,
                                                        $group_id,
                                                        $picture_path
                                                    );
                                                    
                                                    if (isset($picture_response['error'])) {
                                                        log_activity("create_group_chat WARNING - Failed to set group picture. Error: " . json_encode($picture_response), get_staff_user_id());
                                                    } else {
                                                        log_activity("create_group_chat PICTURE SET - Group picture set successfully for Group ID: {$group_id}", get_staff_user_id());
                                                    }
                                                } else {
                                                    log_activity("create_group_chat WARNING - Default picture file not found: {$picture_path}", get_staff_user_id());
                                                }
                                            }
                                            
                                            // Send first message to group if configured
                                            $default_message = get_option('contactcenter_group_chat_default_message');
                                            log_activity("create_group_chat MESSAGE CHECK - Default message configured: " . (!empty($default_message) ? 'YES (length: ' . strlen($default_message) . ')' : 'NO'), get_staff_user_id());
                                            
                                            // Initialize final_message variable to use later for sending to lead
                                            $final_message = '';
                                            
                                            if (!empty($default_message)) {
                                                log_activity("create_group_chat MESSAGE PROCESSING START - Processing default message template for Group ID: {$group_id}, Lead ID: {$leadid}", get_staff_user_id());
                                                
                                                // Prepare merge fields
                                                $replacements = [
                                                    '{lead_name}' => $lead->name ?? '',
                                                    '{lead_email}' => $lead->email ?? '',
                                                    '{lead_phone}' => $lead->phonenumber ?? '',
                                                    '{date}' => '',
                                                    '{date_iso}' => '',
                                                    '{google_meet_link}' => ''
                                                ];
                                                
                                                log_activity("create_group_chat MERGE FIELDS - Lead Name: " . ($lead->name ?? 'empty') . ", Lead Email: " . ($lead->email ?? 'empty') . ", Lead Phone: " . ($lead->phonenumber ?? 'empty'), get_staff_user_id());
                                                
                                                // Format meeting date
                                                if (!empty($meeting_date)) {
                                                    try {
                                                        $date_obj = new DateTime($meeting_date);
                                                        $replacements['{date}'] = $date_obj->format('d/m/Y');
                                                        $replacements['{date_iso}'] = $date_obj->format('Y-m-d');
                                                        log_activity("create_group_chat DATE FORMAT - Meeting date: {$meeting_date} → Formatted: " . $replacements['{date}'] . " / ISO: " . $replacements['{date_iso}'], get_staff_user_id());
                                                    } catch (Exception $e) {
                                                        log_activity("create_group_chat WARNING - Invalid meeting_date format: {$meeting_date}. Error: " . $e->getMessage(), get_staff_user_id());
                                                    }
                                                } else {
                                                    log_activity("create_group_chat DATE - No meeting date provided, date placeholders will be empty", get_staff_user_id());
                                                }
                                                
                                                // Get Google Meet link from the last meeting/event for this lead
                                                $google_meet_link = '';
                                                
                                                // First, try to get from the last meeting in events table
                                                $this->db->where('rel_type', 'lead');
                                                $this->db->where('rel_id', $leadid);
                                                $this->db->where('meetLink IS NOT NULL');
                                                $this->db->where('meetLink !=', '');
                                                $this->db->where('meetLink !=', '0');
                                                $this->db->where('meetLink !=', '1');
                                                $this->db->order_by('start', 'DESC');
                                                $this->db->limit(1);
                                                $last_meeting = $this->db->get(db_prefix() . 'events')->row();
                                                
                                                if ($last_meeting && !empty($last_meeting->meetLink)) {
                                                    // Validate it's a URL
                                                    if (filter_var($last_meeting->meetLink, FILTER_VALIDATE_URL) || strpos($last_meeting->meetLink, 'http://') === 0 || strpos($last_meeting->meetLink, 'https://') === 0) {
                                                        $google_meet_link = $last_meeting->meetLink;
                                                        log_activity("create_group_chat GOOGLE MEET FOUND - Found in last meeting (Event ID: {$last_meeting->eventid}, Start: {$last_meeting->start}): {$google_meet_link}", get_staff_user_id());
                                                    } else {
                                                        log_activity("create_group_chat GOOGLE MEET INVALID - Last meeting has meetLink but it's not a valid URL: {$last_meeting->meetLink}", get_staff_user_id());
                                                    }
                                                } else {
                                                    log_activity("create_group_chat GOOGLE MEET NOT FOUND - No meeting with valid meetLink found for Lead ID: {$leadid}", get_staff_user_id());
                                                    
                                                    // Fallback: Check custom fields
                                                    $custom_fields = get_custom_fields('leads');
                                                    log_activity("create_group_chat GOOGLE MEET SEARCH FALLBACK - Checking " . count($custom_fields) . " custom fields for Google Meet link", get_staff_user_id());
                                                    
                                                    foreach ($custom_fields as $field) {
                                                        $field_value = get_custom_field_value($lead->id, $field['id'], 'leads');
                                                        if (!empty($field_value)) {
                                                            // Check if it looks like a Google Meet link
                                                            if (preg_match('/meet\.google\.com|meet\.google|meet\?|meet\/[a-z-]+/i', $field_value)) {
                                                                $google_meet_link = $field_value;
                                                                log_activity("create_group_chat GOOGLE MEET FOUND - Found in custom field '{$field['name']}' (ID: {$field['id']}): {$google_meet_link}", get_staff_user_id());
                                                                break;
                                                            }
                                                        }
                                                    }
                                                    
                                                    // If still not found, check lead description
                                                    if (empty($google_meet_link) && !empty($lead->description)) {
                                                        log_activity("create_group_chat GOOGLE MEET SEARCH - Checking lead description (length: " . strlen($lead->description) . ")", get_staff_user_id());
                                                        // Try to extract Google Meet link from description
                                                        if (preg_match('/(https?:\/\/meet\.google\.com\/[a-z-]+|https?:\/\/meet\.google\.com\/[a-z]+-[a-z]+-[a-z]+)/i', $lead->description, $matches)) {
                                                            $google_meet_link = $matches[1];
                                                            log_activity("create_group_chat GOOGLE MEET FOUND - Found in lead description: {$google_meet_link}", get_staff_user_id());
                                                        } else {
                                                            log_activity("create_group_chat GOOGLE MEET NOT FOUND - No Google Meet link found in lead description", get_staff_user_id());
                                                        }
                                                    } elseif (empty($google_meet_link)) {
                                                        log_activity("create_group_chat GOOGLE MEET NOT FOUND - Lead description is empty, no Google Meet link available", get_staff_user_id());
                                                    }
                                                }
                                                
                                                $replacements['{google_meet_link}'] = $google_meet_link;
                                                
                                                // Log all replacements before processing
                                                log_activity("create_group_chat REPLACEMENTS - All merge field values: " . json_encode($replacements), get_staff_user_id());
                                                
                                                // Replace placeholders in message
                                                $final_message = str_replace(array_keys($replacements), array_values($replacements), $default_message);
                                                
                                                // Clean up empty placeholders that weren't replaced
                                                $final_message = preg_replace('/\{[^}]+\}/', '', $final_message);
                                                $final_message = trim($final_message);
                                                
                                                log_activity("create_group_chat MESSAGE FINAL - Original template length: " . strlen($default_message) . ", Final message length: " . strlen($final_message), get_staff_user_id());
                                                log_activity("create_group_chat MESSAGE CONTENT - Final message content: " . substr($final_message, 0, 200) . (strlen($final_message) > 200 ? '...' : ''), get_staff_user_id());
                                                
                                                // Only send if message is not empty after replacements
                                                if (!empty($final_message)) {
                                                    log_activity("create_group_chat SENDING MESSAGE - Preparing to send first message to group: {$group_id}, Device: {$device->dev_instance_name}, Server: {$server->url}", get_staff_user_id());
                                                    
                                                    // Pass server version to use correct API format
                                                    $message_response = $this->axiom_evolution->send_group_message_evolution(
                                                        $server->url,
                                                        $device->dev_instance_name,
                                                        $device->dev_token,
                                                        $group_id,
                                                        $final_message,
                                                        $server->version ?? null // Pass version to use correct format
                                                    );
                                                    
                                                    if (isset($message_response['error'])) {
                                                        log_activity("create_group_chat MESSAGE FAILED ✗ - Failed to send first message to group. Group ID: {$group_id}, Error: " . json_encode($message_response), get_staff_user_id());
                                                    } else {
                                                        log_activity("create_group_chat MESSAGE SENT ✓ - First message sent successfully to Group ID: {$group_id}, Response: " . json_encode($message_response), get_staff_user_id());
                                                    }
                                                } else {
                                                    log_activity("create_group_chat SKIP MESSAGE ⚠ - Final message is empty after replacements, skipping message send. Original template: " . substr($default_message, 0, 100), get_staff_user_id());
                                                }
                                            } else {
                                                log_activity("create_group_chat NO MESSAGE - No default message configured in settings, skipping first message", get_staff_user_id());
                                            }
                                            
                                            // Always generate and send invite link to the lead
                                            log_activity("create_group_chat GENERATING INVITE LINK - Generating invite link for group {$group_id}", get_staff_user_id());
                                            
                                            $invite_response = $this->axiom_evolution->generate_group_invite_link_evolution(
                                                $server->url,
                                                $device->dev_instance_name,
                                                $device->dev_token,
                                                $group_id
                                            );
                                            
                                            $invite_link = null;
                                            if (isset($invite_response['inviteUrl']) && !empty($invite_response['inviteUrl'])) {
                                                // Evolution API returns full invite URL
                                                $invite_link = $invite_response['inviteUrl'];
                                                log_activity("create_group_chat INVITE LINK FOUND - InviteUrl: {$invite_link}", get_staff_user_id());
                                            } elseif (isset($invite_response['code']) && !empty($invite_response['code'])) {
                                                $invite_link = "https://chat.whatsapp.com/" . $invite_response['code'];
                                                log_activity("create_group_chat INVITE CODE FOUND - Code: {$invite_response['code']}", get_staff_user_id());
                                            } elseif (isset($invite_response['inviteCode']) && !empty($invite_response['inviteCode'])) {
                                                // Evolution API returns inviteCode, format as WhatsApp invite link
                                                $invite_link = "https://chat.whatsapp.com/" . $invite_response['inviteCode'];
                                                log_activity("create_group_chat INVITE CODE FOUND - InviteCode: {$invite_response['inviteCode']}", get_staff_user_id());
                                            } elseif (isset($invite_response['inviteLink']) && !empty($invite_response['inviteLink'])) {
                                                $invite_link = $invite_response['inviteLink'];
                                                log_activity("create_group_chat INVITE LINK FOUND - InviteLink: {$invite_link}", get_staff_user_id());
                                            } elseif (isset($invite_response['link']) && !empty($invite_response['link'])) {
                                                $invite_link = $invite_response['link'];
                                                log_activity("create_group_chat INVITE LINK FOUND - Link: {$invite_link}", get_staff_user_id());
                                            } else {
                                                log_activity("create_group_chat INVITE LINK NOT FOUND - Response: " . json_encode($invite_response), get_staff_user_id());
                                            }
                                            
                                            if ($invite_link) {
                                                log_activity("create_group_chat INVITE LINK GENERATED - Link: {$invite_link}", get_staff_user_id());
                                                
                                                // Get invite message template
                                                $invite_message_template = get_option('contactcenter_group_chat_invite_message');
                                                if (empty($invite_message_template)) {
                                                    $invite_message_template = "Olá! Você foi convidado para participar do grupo *{group_name}*.\n\nClique no link abaixo para entrar:\n{invite_link}";
                                                }
                                                
                                                // Prepare merge fields for invite message
                                                $invite_replacements = [
                                                    '{group_name}' => $group_name,
                                                    '{invite_link}' => $invite_link,
                                                    '{lead_name}' => $lead->name ?? ''
                                                ];
                                                
                                                $invite_message = str_replace(array_keys($invite_replacements), array_values($invite_replacements), $invite_message_template);
                                                
                                                // Send invite link to the lead
                                                $clean_lead_phone = preg_replace('/\D/', '', $lead_phone);
                                                if (!empty($clean_lead_phone)) {
                                                    log_activity("create_group_chat PREPARING TO SEND INVITE - Phone: {$clean_lead_phone}, Device ID: {$device_id}, Staff ID: " . ($device->staffid ?? 'null'), get_staff_user_id());
                                                    
                                                    // Verify device is connected before sending
                                                    if ($device && ($device->status == "inChat" || $device->status == "CONNECTED" || $device->status == "open" || $device->status == "connecting")) {
                                                        $send_result = $this->send_text($clean_lead_phone, $invite_message, $device->staffid, null, null, true, 'crm');
                                                        log_activity("create_group_chat INVITE SENT TO LEAD - Invite link sent to {$clean_lead_phone} for group {$group_id}. Send result: " . json_encode($send_result), get_staff_user_id());
                                                        
                                                        // Also send the meeting link message to the lead (so they get it even if not added to group)
                                                        // Check if we have a final_message prepared (from the group message)
                                                        if (isset($final_message) && !empty($final_message)) {
                                                            log_activity("create_group_chat SENDING MEETING MESSAGE TO LEAD - Sending meeting message to {$clean_lead_phone} after invite", get_staff_user_id());
                                                            $meeting_message_result = $this->send_text($clean_lead_phone, $final_message, $device->staffid, null, null, true, 'crm');
                                                            log_activity("create_group_chat MEETING MESSAGE SENT TO LEAD - Meeting message sent to {$clean_lead_phone}. Send result: " . json_encode($meeting_message_result), get_staff_user_id());
                                                        }
                                                    } else {
                                                        log_activity("create_group_chat INVITE NOT SENT - Device not connected. Device ID: {$device_id}, Status: " . ($device->status ?? 'not found'), get_staff_user_id());
                                                    }
                                                }
                                            } else {
                                                log_activity("create_group_chat INVITE LINK FAILED - Could not generate invite link. Response: " . json_encode($invite_response), get_staff_user_id());
                                            }
                                            
                                            $output = json_encode([
                                                "success" => "true",
                                                "message" => "Group chat created successfully",
                                                "group_name" => $group_name,
                                                "group_id" => $group_id
                                            ]);
                                        } else {
                                            log_activity("create_group_chat ERRO - Resposta da API não contém group ID. Response: " . json_encode($response), get_staff_user_id());
                                            $output = json_encode([
                                                "success" => "false",
                                                "message" => "Error creating group: Invalid response from API. Response: " . json_encode($response)
                                            ]);
                                        }
                                    } else {
                                        // Fallback to old API if not Evolution
                                        log_activity("create_group_chat ERRO - Server não é Evolution API. API Type: " . ($server->api_type ?? 'null'), get_staff_user_id());
                                        $output = json_encode([
                                            "success" => "false",
                                            "message" => "Group creation is only available for Evolution API servers"
                                        ]);
                                    }
                                }
                            }
                        }
                    } catch (Exception $e) {
                        log_activity("create_group_chat EXCEÇÃO - Exceção ao criar grupo: " . $e->getMessage() . " - Stack trace: " . $e->getTraceAsString(), get_staff_user_id());
                        $output = json_encode([
                            "success" => "false",
                            "message" => "Error creating group: " . $e->getMessage()
                        ]);
                    }
                    
                    log_activity("create_group_chat FINALIZADO - Output: {$output}", get_staff_user_id());
                } else {

                    $log = [
                        "function_name" => $function_name,
                        "function_arguments" => $function_arguments,
                        "thread" => $thread,
                        "Runsid" => $Runsid,
                        "device_id" => $device_id,
                        "leadid" => $leadid,
                        "description" => "Funçao nao encontrada " . $function_name,
                    ];

                    try {
                        log_activity("AI FUNCTION NOT FOUND - Function: {$function_name}, Lead ID: {$leadid}, Device ID: {$device_id}, Arguments: " . json_encode($function_arguments), $log_staff_id);
                    } catch (Exception $e) {
                        error_log("Failed to log FUNCTION NOT FOUND: " . $e->getMessage());
                    }

                    $output = json_encode(["success" => "false", "error" => "Function '{$function_name}' not found or not enabled"]);
                }

                // Log if function didn't match any handler (output is still empty)
                if (empty($output) && $function_name != "UNKNOWN") {
                    try {
                        log_activity("AI FUNCTION UNHANDLED - Function: {$function_name}, Lead ID: {$leadid}, No handler found for this function", $log_staff_id);
                    } catch (Exception $e) {
                        error_log("Failed to log UNHANDLED: " . $e->getMessage());
                    }
                    $output = json_encode(["success" => "false", "error" => "Function '{$function_name}' is not implemented or not enabled"]);
                }
                
                $tools_outputs[] = [
                    "tool_call_id" => $tool_callsId,
                    "output" => $output
                ];
                
                // Log function result to structured AI interactions table
                try {
                    $this->log_ai_interaction(array(
                        'lead_id' => $leadid,
                        'device_id' => $device_id,
                        'thread_id' => $thread,
                        'run_id' => $Runsid,
                        'interaction_type' => 'function_response',
                        'function_name' => $function_name,
                        'function_arguments' => $function_arguments_raw,
                        'function_result' => $output,
                        'raw_output' => json_encode(array(
                            'tool_call_id' => $tool_callsId,
                            'output' => $output
                        )),
                        'status' => 'completed'
                    ));
                } catch (Exception $e) {
                    error_log("Failed to log AI function result: " . $e->getMessage());
                }
            }

            // salvo log com tudo e output
            $dataLog = [
                "thread" => $thread,
                "Runsid" => $Runsid,
                "device_id" => $device_id,
                "leadid" => $leadid,
                "staffid" => $staffid,
                "device_token" => $device_token,
                "model" => $model,
                "required_action" => $result["required_action"],
                "tools_outputs" => $tools_outputs
            ];
            log_activity("requires_action: " . json_encode($dataLog));

            if ($result["required_action"]["type"] == 'submit_tool_outputs') {
                $this->send_function_openai($thread, $Runsid, $tools_outputs, $device_id, $leadid, $device_token, $model);
            }
        }
    }

    public function get_invoice_client($document)
    {
        // Remove a máscara do documento recebido
        $document = preg_replace('/\D/', '', $document);

        // Busca no banco removendo a máscara dos registros também
        $sql = "SELECT * FROM " . db_prefix() . "clients 
            WHERE REPLACE(REPLACE(REPLACE(REPLACE(vat, '.', ''), '-', ''), '/', ''), ' ', '') = ? 
            LIMIT 1";

        $client = $this->db->query($sql, [$document])->row();
        if ($client) {
            $this->db->where('clientid', $client->userid);
            $this->db->where_in('status', [1, 3, 4]);
            $invoices = $this->db->get(db_prefix() . 'invoices')->result();
            if (!$invoices) {
                log_activity('Cliente não possui faturas');
                return false;
            }
            $faturas = [];
            foreach ($invoices as $invoice) {
                $item = [];
                if ($invoice->status == Invoices_model::STATUS_UNPAID) {
                    $status = _l('invoice_status_unpaid');
                } elseif ($invoice->status == Invoices_model::STATUS_PAID) {
                    $status = _l('invoice_status_paid');
                } elseif ($invoice->status == Invoices_model::STATUS_PARTIALLY) {
                    $status = _l('invoice_status_not_paid_completely');
                } elseif ($invoice->status == Invoices_model::STATUS_OVERDUE) {
                    $status = _l('invoice_status_overdue');
                } elseif ($invoice->status == Invoices_model::STATUS_CANCELLED) {
                    $status = _l('invoice_status_cancelled');
                } else {
                    // status 6
                    $status = _l('invoice_status_draft');
                }


                $item['invoice_number'] = $invoice->number;
                $item['invoice_due_date'] = $invoice->duedate;
                $item['invoice_total'] = $invoice->total;
                $item['invoice_status'] = $status;
                $item['link_invoice'] = site_url('invoice/' . $invoice->id . '/' . $invoice->hash);


                $faturas[] = $item;
            }
            return $faturas;
        }
        log_activity('Cliente não encontrado');
        return false;
    }


    public function format_cpf_cnpj($value)
    {
        $value = preg_replace('/[^0-9]/', '', $value); // Remove qualquer máscara existente

        if (strlen($value) == 11) {
            // Formata como CPF: 000.000.000-00
            return preg_replace('/(\d{3})(\d{3})(\d{3})(\d{2})/', '$1.$2.$3-$4', $value);
        } elseif (strlen($value) == 14) {
            // Formata como CNPJ: 00.000.000/0000-00
            return preg_replace('/(\d{2})(\d{3})(\d{3})(\d{4})(\d{2})/', '$1.$2.$3/$4-$5', $value);
        }

        return $value; // Retorna o valor original caso não seja CPF ou CNPJ válido
    }



