    /**
     * atualiza_phonenumber_lead
     * atualiza o telefone do lead
     * @param [type] $id
     * @return void
     */
    public function atualiza_phonenumber_lead($id)
    {
        if ($id) {
            $this->db->where('id', $id);
            $lead = $this->db->get(db_prefix() . 'leads')->row();
            if ($lead) {
                if ($lead->phonenumber) {
                    $phone = formatPhoneNumber($lead->phonenumber);

                    $this->db->where('id', $lead->id);
                    $this->db->update(db_prefix() . 'leads', ['phonenumber' => $phone]);
                }
            }
        }
    }

