    public function delete_lead_repeated()
    {

        // recupera todos os leads com mesmo phonenumber
        $this->db->select('phonenumber, COUNT(phonenumber) as total');
        $this->db->group_by('phonenumber');
        $this->db->having('total > 1');
        $leads = $this->db->get(db_prefix() . 'leads')->result();

        // percorre os leads e deleto os mais antigos, deixando o lead mais atual
        foreach ($leads as $lead) {

            // busco os leads pelo phonenumber
            $this->db->select('id');
            $this->db->where('phonenumber', $lead->phonenumber);
            $this->db->order_by('dateadded', 'DESC');
            $ids = $this->db->get(db_prefix() . 'leads')->result();

            // mantenho id mais recente e retiro os outros
            $keepId = array_shift($ids);
            if (!empty($ids)) {
                $placeholders = implode(',', array_fill(0, count($ids), '?'));
                $deleteQuery = "DELETE FROM tblleads WHERE id IN ($placeholders)";

                $this->db->query($deleteQuery, array_map(function ($id) {
                    return $id->id;
                }, $ids));
            }
        }
    }

    /**
     * Calculate warm-up daily limit based on start date
     * Day 1: 50, Day 2: 75, Day 3: 100, then increases by 25% daily
     */
    private function calculate_warmup_limit($warmup_start_date, $target_limit)
    {
        if (empty($warmup_start_date)) {
            return $target_limit;
        }
        
        $start = new DateTime($warmup_start_date);
        $now = new DateTime();
        $days = $start->diff($now)->days;
        
        if ($days == 0) {
            return 50;
        } elseif ($days == 1) {
            return 75;
        } elseif ($days == 2) {
            return 100;
        } else {
            // Increase by 25% daily from day 3
            $limit = 100;
            for ($i = 3; $i <= $days; $i++) {
                $limit = min($limit * 1.25, $target_limit);
            }
            return (int)$limit;
        }
    }
    
    /**
     * Get messages sent today for a campaign
     */
    private function get_daily_progress($campaign_id)
    {
        $today = date('Y-m-d');
        $this->db->where('campaign_id', $campaign_id);
        $this->db->where('date', $today);
        $progress = $this->db->get(db_prefix() . 'contactcenter_campaign_daily_progress')->row();
        
        return $progress ? (int)$progress->messages_sent : 0;
    }
    
    /**
     * Increment daily progress for a campaign
     */
    private function increment_daily_progress($campaign_id)
    {
        $today = date('Y-m-d');
        $this->db->where('campaign_id', $campaign_id);
        $this->db->where('date', $today);
        $progress = $this->db->get(db_prefix() . 'contactcenter_campaign_daily_progress')->row();
        
        if ($progress) {
            $this->db->where('id', $progress->id);
            $this->db->update(db_prefix() . 'contactcenter_campaign_daily_progress', [
                'messages_sent' => $progress->messages_sent + 1
            ]);
        } else {
            $this->db->insert(db_prefix() . 'contactcenter_campaign_daily_progress', [
                'campaign_id' => $campaign_id,
                'date' => $today,
                'messages_sent' => 1,
                'created_at' => date('Y-m-d H:i:s')
            ]);
        }
    }
    
    /**
     * Check if lead is excluded from campaign (kill switch)
     */
    private function is_lead_excluded($campaign_id, $lead_id)
    {
        $this->db->where('campaign_id', $campaign_id);
        $this->db->where('lead_id', $lead_id);
        $excluded = $this->db->get(db_prefix() . 'contactcenter_campaign_excluded_leads')->row();
        return $excluded !== null;
    }
    
    /**
     * Exclude lead from campaign (kill switch)
     */
    private function exclude_lead_from_campaign($campaign_id, $lead_id, $reason = 'reply_received')
    {
        $this->db->insert(db_prefix() . 'contactcenter_campaign_excluded_leads', [
            'campaign_id' => $campaign_id,
            'lead_id' => $lead_id,
            'reason' => $reason,
            'date_excluded' => date('Y-m-d H:i:s')
        ]);
    }
    
    /**
     * Simulate typing indicator before sending message
     */
    private function simulate_typing($device_token, $phonenumber, $message_length)
    {
        // Calculate typing duration: 0.2 seconds per character, minimum 1 second
        $typing_duration = max(1, $message_length * 0.2);
        
        // Send typing indicator via API (if available)
        // This would need to be implemented based on your WhatsApp API provider
        // For now, we'll just sleep to simulate the delay
        usleep((int)($typing_duration * 1000000)); // Convert to microseconds
    }
    
    /**
     * Get random interval with jitter (+/- 20%)
     */
    private function get_random_interval($min, $max)
    {
        $base = rand($min, $max);
        $jitter = $base * 0.2; // 20% jitter
        $variation = rand(-$jitter, $jitter);
        return max(1, (int)($base + $variation)); // Minimum 1 second
    }

    function cron_leads_engine()
    {
        // Load helper for Spintax parsing
        $this->load->helper('contactcenter/contactcenter');

        // buscos os motores ativos - ORDENA POR QUEM ESTÁ MAIS TEMPO SEM RODAR (last_run ASC)
        $this->db->where('status', 1);
        $this->db->order_by('last_run', 'ASC'); 
        $this->db->limit(10);
        $leads_engine = $this->db->get(db_prefix() . 'contactcenter_leads_engine')->result();

        // percorro de forma paralella cada motor
        foreach ($leads_engine as $engine) {


            $currentDateTime = date('Y-m-d H:i:s');
            // Atualiza last_run para este motor ir para o fim da fila no próximo ciclo
            $this->db->where('id', $engine->id);
            $this->db->update(db_prefix() . 'contactcenter_leads_engine', ['last_run' => $currentDateTime]);


            // valido se esta dentro do horario permitido de envio
            $start_time = strtotime($engine->start_time);
            $end_time = strtotime($engine->end_time);
            $current_time = strtotime(date("H:i:s"));

            if ($current_time < $start_time || $current_time > $end_time) {
                continue;
            }


            // Get device
            $this->db->where('dev_id', $engine->device_id);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();

            if ($device == null || $device->dev_engine != 1) {
                continue;
            }

            // Calculate daily limit (warm-up mode)
            $daily_limit = isset($engine->daily_limit) ? (int)$engine->daily_limit : 1000;
            if (isset($engine->is_warmup_active) && $engine->is_warmup_active == 1) {
                $daily_limit = $this->calculate_warmup_limit($engine->warmup_start_date, $daily_limit);
            }

            // Check daily progress
            $messages_sent_today = $this->get_daily_progress($engine->id);
            if ($messages_sent_today >= $daily_limit) {
                continue; // Daily limit reached
            }

            // Get batch settings - LIMITADO A NO MAXIMO 3 PARA EVITAR SOBRECARGA
            $batch_size = isset($engine->batch_size) ? (int)$engine->batch_size : 3;
            if ($batch_size > 3) {
                $batch_size = 3;
            }
            $batch_cooldown = isset($engine->batch_cooldown) ? (int)$engine->batch_cooldown : 5;
            $interval_min = isset($engine->message_interval_min) ? (int)$engine->message_interval_min : 30;
            $interval_max = isset($engine->message_interval_max) ? (int)$engine->message_interval_max : 60;

            // Get messages ordered
            $this->db->where('contactcenter_leads_engine_id', $engine->id);
            $this->db->order_by('ordenation', 'ASC');
            $messages = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->result();

            if (empty($messages)) {
                continue;
            }

            // Build query with optional status and tag filtering
            // Ensure fromMe is cast to integer for proper comparison
            // fromMe = 1 means last message from STAFF, fromMe = 0 means last message from CONTACT
            $fromMe = isset($engine->fromMe) ? intval($engine->fromMe) : 0;
            
            $sql = "
                SELECT c.id, c.session, c.phonenumber, l.name, l.id as leadid, l.is_whatsapp, last_msg.msg_date as last_message_date
                FROM `tblcontactcenter_contact` c
                INNER JOIN tblleads l ON c.phonenumber = l.phonenumber
                INNER JOIN (
                    SELECT m1.msg_conversation_number, m1.msg_session, m1.msg_fromMe, m1.msg_date
                    FROM " . db_prefix() . "contactcenter_message m1
                    INNER JOIN (
                        SELECT msg_conversation_number, msg_session, MAX(msg_date) as max_date
                        FROM " . db_prefix() . "contactcenter_message
                        WHERE msg_session = ?
                        AND msg_isGroupMsg = 0
                        GROUP BY msg_conversation_number, msg_session
                    ) m2 ON m1.msg_conversation_number = m2.msg_conversation_number
                        AND m1.msg_session = m2.msg_session
                        AND m1.msg_date = m2.max_date
                    WHERE m1.msg_isGroupMsg = 0
                ) last_msg ON last_msg.msg_conversation_number = c.phonenumber 
                    AND last_msg.msg_session = c.session
                WHERE last_msg.msg_fromMe = ?
                AND c.is_locked = 0
                AND c.isGroup = 0
                AND TIMESTAMPDIFF(HOUR, last_msg.msg_date, ?) >= ?                
                AND c.session = ?
            ";
            
            $params = [
                $device->dev_token,  // For the subquery msg_session filter
                $fromMe,             // Filter by last message sender (1 = staff, 0 = contact)
                $currentDateTime,
                $engine->hours_since_last_contact,
                $device->dev_token   // For the main query c.session filter
            ];
            
            // Add status filtering only if leads_status is set (not NULL/empty)
            if (!empty($engine->leads_status) && $engine->leads_status > 0) {
                $sql .= " AND l.status = ?";
                $params[] = $engine->leads_status;
            }
            
            // Add tag filtering if tags are set
            if (!empty($engine->tags)) {
                $sql .= " AND EXISTS (
                    SELECT 1
                    FROM " . db_prefix() . "taggables AS taggables
                    WHERE taggables.rel_id = l.id
                      AND taggables.rel_type = 'lead'
                      AND taggables.tag_id IN ({$engine->tags})
                )";
            }
            
            $sql .= " ORDER BY last_msg.msg_date ASC LIMIT ?";
            $params[] = $batch_size;
            
            $leads = $this->db->query($sql, $params)->result();

            if (empty($leads)) {
                continue;
            }

            // Process leads in batches
            $leads_processed_today = 0;
            $current_batch_count = 0;

            foreach ($leads as $lead) {
                // Check daily limit
                if ($messages_sent_today + $leads_processed_today >= $daily_limit) {
                    break; // Daily limit reached
                }

                // Check kill switch (stop on reply)
                if (isset($engine->stop_on_reply) && $engine->stop_on_reply == 1) {
                    if ($this->is_lead_excluded($engine->id, $lead->leadid)) {
                        continue; // Lead replied, skip
                    }
                }

                // Lock lead
                $this->db->where('id', $lead->id);
                $this->db->update(db_prefix() . 'contactcenter_contact', ['is_locked' => 1]);

                // Validate WhatsApp number
                $isValidNumber = false;
                if ($device->api_local == 1) {
                    if ($lead->is_whatsapp == "pending") {
                        $this->db->where('id', $lead->id);
                        $this->db->update(db_prefix() . 'contactcenter_contact', ['is_locked' => 0]);
                        continue;
                    } elseif ($lead->is_whatsapp == "registered") {
                        $isValidNumber = true;
                    }
                } else {
                    $data = [
                        "token" => $device->dev_token,
                        "phonenumber" => $lead->phonenumber
                    ];
                    $isValidNumber = $this->verify_Number_Whatsapp($data);
                    if ($isValidNumber["exists"]) {
                        $this->db->where('id', $lead->leadid);
                        $this->db->update(db_prefix() . 'leads', ['is_whatsapp' => 'registered']);
                        $isValidNumber = true;
                    }
                }

                if (!$isValidNumber) {
                    $this->db->where('id', $lead->id);
                    $this->db->update(db_prefix() . 'contactcenter_contact', ['is_locked' => 0]);
                    continue;
                }

                // Check if this is the first message to this lead (for vCard and Inbound Bait)
                $is_first_message = $this->is_first_message_to_lead($lead->phonenumber, $device->dev_token);
                
                // Send Inbound Bait first if enabled and it's the first message
                if ($is_first_message && isset($engine->inbound_bait_enable) && $engine->inbound_bait_enable == 1 && !empty($engine->inbound_bait_message)) {
                    // Load merge fields library
                    if (!class_exists('Leads_merge_fields', false)) {
                        $this->load->library('merge_fields/leads_merge_fields');
                    }
                    
                    // Store original text for logging
                    $original_bait_text = $engine->inbound_bait_message;
                    
                    // Get all merge fields for this lead
                    $merge_fields = $this->leads_merge_fields->format($lead->id);
                    
                    // Add custom variables for backward compatibility
                    $firstName = explode(' ', $lead->name)[0];
                    $merge_fields['{FirstName}'] = $firstName;
                    $merge_fields['{Lead}'] = $lead->name;
                    $merge_fields['{Agente}'] = get_contactcenter_staff_name($device->staffid);
                    
                    // Replace all merge fields (case-insensitive)
                    $bait_text = $original_bait_text;
                    $replaced_fields = [];
                    $unreplaced_fields = [];
                    
                    foreach ($merge_fields as $key => $val) {
                        if (stripos($bait_text, $key) !== false) {
                            $bait_text = str_ireplace($key, $val, $bait_text);
                            $replaced_fields[$key] = $val;
                        }
                    }
                    
                    // Check for unreplaced fields
                    preg_match_all('/\{[^}]+\}/', $bait_text, $matches);
                    if (!empty($matches[0])) {
                        $unreplaced_fields = array_unique($matches[0]);
                    }
                    
                    // Parse spintax if needed
                    $bait_text_before_spintax = $bait_text;
                    $bait_text = parse_spintax($bait_text);
                    
                    // Log merge field replacement for inbound bait
                    $log_message = "Leads Engine Inbound Bait Sent - Engine ID: {$engine->id}, Lead ID: {$lead->leadid}\n";
                    $log_message .= "Original Text: " . substr($original_bait_text, 0, 200) . (strlen($original_bait_text) > 200 ? '...' : '') . "\n";
                    $log_message .= "After Merge Fields: " . substr($bait_text_before_spintax, 0, 200) . (strlen($bait_text_before_spintax) > 200 ? '...' : '') . "\n";
                    $log_message .= "Final Text: " . substr($bait_text, 0, 200) . (strlen($bait_text) > 200 ? '...' : '') . "\n";
                    $log_message .= "Replaced Fields (" . count($replaced_fields) . "): " . implode(', ', array_keys($replaced_fields)) . "\n";
                    if (!empty($unreplaced_fields)) {
                        $log_message .= "WARNING - Unreplaced Fields (" . count($unreplaced_fields) . "): " . implode(', ', $unreplaced_fields) . "\n";
                    }
                    
                    log_activity($log_message, $device->staffid);
                    
                    // Simulate typing
                    $this->simulate_typing($device->dev_token, $lead->phonenumber, strlen($bait_text));
                    
                    // Send bait message
                    $this->send_text(strval($lead->phonenumber), $bait_text, $device->staffid, null, null, true, 'crm');
                    
                    // Increment progress
                    $this->increment_daily_progress($engine->id);
                    $leads_processed_today++;
                    
                    // Wait before sending actual pitch (give time for reply)
                    sleep(rand(30, 60)); // Wait 30-60 seconds for potential reply
                    
                    // Check if lead replied (if they did, skip the pitch due to kill switch)
                    if (isset($engine->stop_on_reply) && $engine->stop_on_reply == 1) {
                        if ($this->has_lead_replied($lead->phonenumber, $device->dev_token)) {
                            // Lead replied, skip pitch
                            $this->db->where('id', $lead->id);
                            $this->db->update(db_prefix() . 'contactcenter_contact', ['is_locked' => 0]);
                            continue;
                        }
                    }
                }
                
                // Send vCard if enabled and it's the first message
                if ($is_first_message && isset($engine->vcard_enable) && $engine->vcard_enable == 1 && !empty($engine->vcard_name) && !empty($engine->vcard_phone)) {
                    // Load merge fields library
                    if (!class_exists('Leads_merge_fields', false)) {
                        $this->load->library('merge_fields/leads_merge_fields');
                    }
                    
                    // Store original vCard text for logging
                    $original_vcard_text = "Clique no cartão abaixo e salve meu contato para receber as promoções.";
                    
                    // Get all merge fields for this lead
                    $merge_fields = $this->leads_merge_fields->format($lead->id);
                    
                    // Add custom variables for backward compatibility
                    $firstName = explode(' ', $lead->name)[0];
                    $merge_fields['{FirstName}'] = $firstName;
                    $merge_fields['{Lead}'] = $lead->name;
                    $merge_fields['{Agente}'] = get_contactcenter_staff_name($device->staffid);
                    
                    $vcard_text = $original_vcard_text;
                    $replaced_fields = [];
                    $unreplaced_fields = [];
                    
                    // Replace all merge fields (case-insensitive)
                    foreach ($merge_fields as $key => $val) {
                        if (stripos($vcard_text, $key) !== false) {
                            $vcard_text = str_ireplace($key, $val, $vcard_text);
                            $replaced_fields[$key] = $val;
                        }
                    }
                    
                    // Check for unreplaced fields
                    preg_match_all('/\{[^}]+\}/', $vcard_text, $matches);
                    if (!empty($matches[0])) {
                        $unreplaced_fields = array_unique($matches[0]);
                    }
                    
                    // Parse spintax if needed
                    $vcard_text_before_spintax = $vcard_text;
                    $vcard_text = parse_spintax($vcard_text);
                    
                    // Log merge field replacement for vCard
                    $log_message = "Leads Engine vCard Sent - Engine ID: {$engine->id}, Lead ID: {$lead->leadid}\n";
                    $log_message .= "Original Text: " . substr($original_vcard_text, 0, 200) . "\n";
                    $log_message .= "After Merge Fields: " . substr($vcard_text_before_spintax, 0, 200) . "\n";
                    $log_message .= "Final Text: " . substr($vcard_text, 0, 200) . "\n";
                    $log_message .= "Replaced Fields (" . count($replaced_fields) . "): " . implode(', ', array_keys($replaced_fields)) . "\n";
                    if (!empty($unreplaced_fields)) {
                        $log_message .= "WARNING - Unreplaced Fields (" . count($unreplaced_fields) . "): " . implode(', ', $unreplaced_fields) . "\n";
                    }
                    
                    log_activity($log_message, $device->staffid);
                    
                    // Send vCard
                    $this->send_vcard(strval($lead->phonenumber), $engine->vcard_name, $engine->vcard_phone, $device->staffid, $vcard_text);
                    
                    // Increment progress
                    $this->increment_daily_progress($engine->id);
                    $leads_processed_today++;
                    
                    // Wait a bit before sending campaign messages
                  //  sleep(rand(1, 10));
                }

                // Process messages for this lead
                foreach ($messages as $message_engine) {
                    // Check daily limit before each message
                    if ($messages_sent_today + $leads_processed_today >= $daily_limit) {
                        break 2; // Break both loops
                    }

                    $text = "";
                    if ($message_engine->text != null && $message_engine->text != "") {
                        // Store original text for logging
                        $original_text = $message_engine->text;
                        
                        // First, replace merge fields before spintax parsing to avoid conflicts
                        // Load merge fields library
                        if (!class_exists('Leads_merge_fields', false)) {
                            $this->load->library('merge_fields/leads_merge_fields');
                        }
                        
                        // Get all merge fields for this lead
                        $merge_fields = $this->leads_merge_fields->format($lead->id);
                        
                        // Add custom variables for backward compatibility
                        $firstName = explode(' ', $lead->name)[0];
                        $merge_fields['{FirstName}'] = $firstName;
                        $merge_fields['{Lead}'] = $lead->name;
                        $merge_fields['{Agente}'] = get_contactcenter_staff_name($device->staffid);
                        
                        // Replace all merge fields (case-insensitive)
                        $text = $original_text;
                        $replaced_fields = [];
                        $unreplaced_fields = [];
                        
                        foreach ($merge_fields as $key => $val) {
                            // Check if field exists in text (case-insensitive)
                            if (stripos($text, $key) !== false) {
                                $text = str_ireplace($key, $val, $text);
                                $replaced_fields[$key] = $val;
                            }
                        }
                        
                        // Check for any unreplaced merge fields (still contain {})
                        preg_match_all('/\{[^}]+\}/', $text, $matches);
                        if (!empty($matches[0])) {
                            $unreplaced_fields = array_unique($matches[0]);
                        }
                        
                        // Now parse spintax after merge fields are replaced
                        $text_before_spintax = $text;
                        $text = parse_spintax($text);
                        
                        // Log merge field replacement details
                        $log_message = "Leads Engine Message Sent - Engine ID: {$engine->id}, Lead ID: {$lead->leadid}, Message ID: {$message_engine->id}\n";
                        $log_message .= "Original Text: " . substr($original_text, 0, 200) . (strlen($original_text) > 200 ? '...' : '') . "\n";
                        $log_message .= "After Merge Fields: " . substr($text_before_spintax, 0, 200) . (strlen($text_before_spintax) > 200 ? '...' : '') . "\n";
                        $log_message .= "Final Text: " . substr($text, 0, 200) . (strlen($text) > 200 ? '...' : '') . "\n";
                        $log_message .= "Replaced Fields (" . count($replaced_fields) . "): " . implode(', ', array_keys($replaced_fields)) . "\n";
                        if (!empty($unreplaced_fields)) {
                            $log_message .= "WARNING - Unreplaced Fields (" . count($unreplaced_fields) . "): " . implode(', ', $unreplaced_fields) . "\n";
                        }
                        $log_message .= "Available Merge Fields: " . implode(', ', array_keys($merge_fields));
                        
                        log_activity($log_message, $device->staffid);
                    }

                    $texto = $text;

                    // Simulate typing before sending
                    $this->simulate_typing($device->dev_token, $lead->phonenumber, strlen($texto));

                    $response = null;
                    if ($message_engine->image != null && $message_engine->media_type == 'image') {
                        $img = site_url("uploads/{$message_engine->image}");
                        $name = explode('/', $message_engine->image);
                        $fileName = end($name);
                        $response = $this->send_file(strval($lead->phonenumber), $texto, $img, $message_engine->media_type, $device->staffid, $fileName);
                    } else if ($message_engine->image != null && $message_engine->media_type == 'video') {
                        $img = site_url("uploads/{$message_engine->image}");
                        $name = explode('/', $message_engine->image);
                        $fileName = end($name);
                        $response = $this->send_file(strval($lead->phonenumber), $texto, $img, $message_engine->media_type, $device->staffid, $fileName);
                    } else if ($message_engine->image != null && $message_engine->media_type == 'audio') {
                        $img = site_url("uploads/{$message_engine->image}");
                        $response = $this->send_audio(strval($lead->phonenumber), $img, $device->staffid);
                    } else {
                        if ($message_engine->text == null) {
                            continue;
                        }
                        $response = $this->send_text(strval($lead->phonenumber), $texto, $device->staffid, $reply_id = null, $edit_id = null, $queue = true, $type_source = 'crm');
                    }

                    // Increment daily progress
                    $this->increment_daily_progress($engine->id);
                    $leads_processed_today++;

                    // Wait between messages (with jitter)
                    if ($message_engine !== end($messages)) { // Don't wait after last message
                        $wait_seconds = $this->get_random_interval($interval_min, $interval_max);
                        sleep($wait_seconds);
                    }
                }

                // Update lead status
                $this->db->where('id', $lead->id);
                $this->db->update(db_prefix() . 'contactcenter_contact', ['date' => date('Y-m-d H:i:s')]);

                $this->db->where('id', $lead->leadid);
                $this->db->update(db_prefix() . 'leads', ['status' => $engine->leads_status_final]);
                
                // Add follow-up tag to lead if configured
                if (isset($engine->campaign_tag_id) && !empty($engine->campaign_tag_id)) {
                    $campaign_tag_id = intval($engine->campaign_tag_id);
                    if ($campaign_tag_id > 0) {
                        // Check if tag exists
                        $this->db->where('id', $campaign_tag_id);
                        $tag = $this->db->get(db_prefix() . 'tags')->row();
                        
                        if ($tag) {
                            // Check if tag is already assigned to this lead
                            $this->db->where('tag_id', $campaign_tag_id);
                            $this->db->where('rel_id', $lead->leadid);
                            $this->db->where('rel_type', 'lead');
                            $existing = $this->db->get(db_prefix() . 'taggables')->row();
                            
                            if (!$existing) {
                                // Get max order for this lead
                                $this->db->select_max('tag_order');
                                $this->db->where('rel_id', $lead->leadid);
                                $this->db->where('rel_type', 'lead');
                                $max_order_result = $this->db->get(db_prefix() . 'taggables')->row();
                                $max_order = $max_order_result && $max_order_result->tag_order ? ($max_order_result->tag_order + 1) : 1;
                                
                                // Insert tag relationship
                                $this->db->insert(db_prefix() . 'taggables', [
                                    'tag_id' => $campaign_tag_id,
                                    'rel_id' => $lead->leadid,
                                    'rel_type' => 'lead',
                                    'tag_order' => $max_order
                                ]);
                                
                                log_activity("Follow-up tag added - Engine ID: {$engine->id}, Lead ID: {$lead->leadid}, Tag ID: {$campaign_tag_id}, Tag Name: {$tag->name}", $device->staffid);
                            }
                        }
                    }
                }

                // Unlock lead
                $this->db->where('id', $lead->id);
                $this->db->update(db_prefix() . 'contactcenter_contact', ['is_locked' => 0]);

                $current_batch_count++;

                // Batch cooldown (respite) after batch is complete
                if ($current_batch_count >= $batch_size) {
                    // REMOVIDO SLEEP QUE TRAVA APACHE
                    // O proximo ciclo do cron cuidará do intervalo
                    $current_batch_count = 0;
                    break; // Sai do loop de leads deste motor para dar vez a outro motor
                }
            }
        }
    }


    public function show_leads_engine($id)
    {
        // busco o motor
        $this->db->where('id', $id);
        $engine = $this->db->get(db_prefix() . 'contactcenter_leads_engine')->row();

        if ($engine) {

            $currentDateTime = date('Y-m-d H:i:s');

            // busco o device pela sessao do lead
            $this->db->where('dev_id', $engine->device_id);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();


            $leads = $this->db->query("
                 SELECT c.id, c.session, c.phonenumber, l.name , l.id as leadid
                FROM `tblcontactcenter_contact` c
                INNER JOIN tblleads l ON c.phonenumber = l.phonenumber
                WHERE l.status = ? 
                AND c.msg_fromMe = 1
                AND c.is_locked = 0
                AND TIMESTAMPDIFF(HOUR, c.date, ?) >= ?                
                AND c.session = ?
                ORDER BY c.date ASC            
           ", [$engine->leads_status, $currentDateTime, $engine->hours_since_last_contact, $device->dev_token])->result();

            return $leads;
        }

        return null;
    }

    public function get_leads_engine_conversation($id = null, $filters = [])
    {
        if ($id) {
            $this->db->where('id', $id);
            return $this->db->get(db_prefix() . 'contactcenter_leads_engine')->row();
        } else {
            // Apply filters
            if (isset($filters['con_status'])) {
                // For leads_engine table, use 'status' column instead of 'con_status'
                $this->db->where('status', $filters['con_status']);
            }
            
            // Apply ordering
            if (isset($filters['order_by'])) {
                $this->db->order_by($filters['order_by']);
            } else {
                $this->db->order_by('id', 'DESC');
            }
            
            return $this->db->get(db_prefix() . 'contactcenter_leads_engine')->result();
        }
    }

    public function add_leads_engine($data)
    {
        $data['date'] = date("Y-m-d H:i:s");

        // Handle tags (convert array to comma-separated string, same as conversation_engine)
        if (isset($data['tags']) && is_array($data['tags']) && count($data['tags']) > 0) {
            $data['tags'] = implode(",", $data['tags']);
        } else {
            $data['tags'] = isset($data['tags']) ? $data['tags'] : "";
        }
        
        // Handle optional status fields - set to NULL if empty
        if (isset($data['leads_status']) && ($data['leads_status'] === '' || $data['leads_status'] === null)) {
            $data['leads_status'] = null;
        }
        if (isset($data['leads_status_final']) && ($data['leads_status_final'] === '' || $data['leads_status_final'] === null)) {
            $data['leads_status_final'] = null;
        }

        if ($data['id'] != "") {
            $id = $data['id'];
            unset($data['id']);

            $this->db->where('id', $id);
            $this->db->update(db_prefix() . 'contactcenter_leads_engine', $data);
            if ($this->db->affected_rows() > 0) {
                return true;
            }
        } else {
            $this->db->insert(db_prefix() . 'contactcenter_leads_engine', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                return true;
            }
        }
    }


    public function add_leads_engine_messages($data)
    {

        if ($data) {
            // Verifica se $data["list_text"] está em branco
            if (empty($data["text"])) {
                // Verifica se o $_FILES["file"] não existe
                if (!isset($_FILES["file"]) || empty($_FILES["file"]["name"])) {
                    return false;
                }
            }

            if ($_FILES["file"] && $_FILES['file']['name']) {
                $file_extension = pathinfo($_FILES['file']['name'], PATHINFO_EXTENSION);

                // Define o tipo de mídia com base na extensão do arquivo
                $image_extensions = ['gif', 'jpg', 'jpeg', 'png'];
                $video_extensions = ['mp4', 'avi', 'mov', 'wmv'];
                $auido_extensions = ['mp3'];

                if (in_array(strtolower($file_extension), $image_extensions)) {
                    $mediaType = 'image';
                    $maxSize = 5120; // Tamanho máximo em kilobytes (5MB)
                    $data["media_type"] = 'image';
                } elseif (in_array(strtolower($file_extension), $video_extensions)) {
                    $mediaType = 'video';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'video';
                } elseif (in_array(strtolower($file_extension), $auido_extensions)) {
                    $mediaType = 'audio';
                    $maxSize = 10240; // Tamanho máximo em kilobytes (10MB)
                    $data["media_type"] = 'audio';
                } else {
                    // Tipo de arquivo não suportado
                    return false;
                }

                // Faz o upload da mídia
                $media = $this->uploads_media("contactcenter/{$mediaType}", $maxSize, $mediaType);

                if ($media) {
                    $data["image"] = $media;
                } else {
                    return false;
                }
            }

            $this->db->insert(db_prefix() . 'contactcenter_leads_engine_messages', $data);
            $insert_id = $this->db->insert_id();
            if ($insert_id) {
                return true;
            }
        }
    }


    public function update_leads_engine_messages($message_id, $data)
    {
        if ($message_id && $data) {
            // Verifica se $data["text"] está em branco
            if (empty($data["text"])) {
                // Verifica se o $_FILES["file"] não existe
                if (!isset($_FILES["file"]) || empty($_FILES["file"]["name"])) {
                    // Se não tem texto nem arquivo novo, verifica se já existe mídia
                    $this->db->where('id', $message_id);
                    $existing = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->row();
                    if (!$existing || (!$existing->text && !$existing->image)) {
                        return false;
                    }
                }
            }

            if ($_FILES["file"] && $_FILES['file']['name']) {
                $file_extension = pathinfo($_FILES['file']['name'], PATHINFO_EXTENSION);

                // Define o tipo de mídia com base na extensão do arquivo
                $image_extensions = ['gif', 'jpg', 'jpeg', 'png'];
                $video_extensions = ['mp4', 'avi', 'mov', 'wmv'];
                $audio_extensions = ['mp3'];

                if (in_array(strtolower($file_extension), $image_extensions)) {
                    $mediaType = 'image';
                    $maxSize = 5120; // Tamanho máximo em kilobytes (5MB)
                    $data["media_type"] = 'image';
                } elseif (in_array(strtolower($file_extension), $video_extensions)) {
                    $mediaType = 'video';
                    $maxSize = 65536; // Tamanho máximo em kilobytes (64MB)
                    $data["media_type"] = 'video';
                } elseif (in_array(strtolower($file_extension), $audio_extensions)) {
                    $mediaType = 'audio';
                    $maxSize = 10240; // Tamanho máximo em kilobytes (10MB)
                    $data["media_type"] = 'audio';
                } else {
                    // Tipo de arquivo não suportado
                    return false;
                }

                // Faz o upload da mídia
                $media = $this->uploads_media("contactcenter/{$mediaType}", $maxSize, $mediaType);

                if ($media) {
                    // Delete old media file if exists
                    $this->db->where('id', $message_id);
                    $old_message = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->row();
                    if ($old_message && $old_message->image) {
                        if (file_exists("uploads/{$old_message->image}")) {
                            unlink("uploads/{$old_message->image}");
                        }
                    }
                    $data["image"] = $media;
                } else {
                    return false;
                }
            }

            $this->db->where('id', $message_id);
            $this->db->update(db_prefix() . 'contactcenter_leads_engine_messages', $data);
            return $this->db->affected_rows() > 0;
        }
        return false;
    }

    public function delete_leads_engine_messages($id)
    {

        if ($id) {

            $this->db->where('id', $id);
            $list = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->row();
            if ($list && $list->image) {
                if (file_exists("uploads/{$list->image}")) {
                    unlink("uploads/{$list->image}");
                }
            }

            $this->db->where('id', $id);
            $deleted = $this->db->delete(db_prefix() . 'contactcenter_leads_engine_messages');
            if ($deleted) {

                return true;
            }
        }
    }


