    public function update_leads_status_engine($data)
    {
        $id = $data['id'];

        // busco as mensagens
        $canSave = false;
        $this->db->where('contactcenter_leads_engine_id', $id);
        $mensagens = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->result();

        if ($mensagens) {
            foreach ($mensagens as $mensagem) {

                if ($mensagem->text != null || $mensagem->image != null) {
                    $canSave = true;
                    break;
                }
            }
        }

        if (!$canSave) {
            return false;
        }


        unset($data['id']);
        $this->db->where('id', $id);
        $this->db->update(db_prefix() . 'contactcenter_leads_engine', $data);
        if ($this->db->affected_rows() > 0) {
            return true;
        }
    }

    public function replicate_leads_engine($engine_id, $device_ids)
    {
        try {
            // Get the original engine
            $this->db->where('id', $engine_id);
            $original_engine = $this->db->get(db_prefix() . 'contactcenter_leads_engine')->row();
            
            if (!$original_engine) {
                return ['success' => false, 'message' => 'Engine not found', 'count' => 0];
            }
            
            // Get the engine list (messages)
            $this->db->where('contactcenter_leads_engine_id', $engine_id);
            $engine_list = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->result();
            
            $created_count = 0;
            $errors = [];
            
            foreach ($device_ids as $device_id) {
                // Verify device exists
                $device = $this->get_device($device_id);
                if (!$device) {
                    $errors[] = "Device ID {$device_id} not found";
                    continue;
                }
                
                // Convert object to array for insertion
                $new_engine = (array) $original_engine;
                
                // Remove the ID so it creates a new record
                unset($new_engine['id']);
                
                // Update fields for the new campaign
                $new_engine['title'] = $original_engine->title . " - " . $device->dev_name;
                $new_engine['status'] = 0; // Set as inactive by default
                $new_engine['date'] = date('Y-m-d H:i:s');
                $new_engine['device_id'] = $device_id;
                
                // Insert the new engine
                $this->db->insert(db_prefix() . 'contactcenter_leads_engine', $new_engine);
                $new_engine_id = $this->db->insert_id();
                
                if ($new_engine_id) {
                    // Copy the engine list (messages)
                    if ($engine_list) {
                        foreach ($engine_list as $list_item) {
                            $new_list_item = (array) $list_item;
                            unset($new_list_item['id']);
                            $new_list_item['contactcenter_leads_engine_id'] = $new_engine_id;
                            $this->db->insert(db_prefix() . 'contactcenter_leads_engine_messages', $new_list_item);
                        }
                    }
                    
                    $created_count++;
                    
                    // Log activity
                    log_activity('Replicated Leads Engine [' . $original_engine->title . '] to Device [' . $device->dev_name . ']', get_staff_user_id());
                } else {
                    $errors[] = "Failed to create engine for device ID {$device_id}";
                }
            }
            
            if ($created_count > 0) {
                return ['success' => true, 'count' => $created_count, 'errors' => $errors];
            } else {
                return ['success' => false, 'message' => 'No engines created. Errors: ' . implode(', ', $errors), 'count' => 0];
            }
        } catch (Exception $e) {
            return ['success' => false, 'message' => $e->getMessage(), 'count' => 0];
        }
    }

    public function duplicate_leads_engine($data)
    {
        $this->db->where('id', $data['id']);
        $engine = $this->db->get(db_prefix() . 'contactcenter_leads_engine')->row();

        if (!$engine) {
            return false;
        }

        // Convert object to array for insertion
        $new_engine = (array) $engine;
        
        // Remove the ID so it creates a new record
        unset($new_engine['id']);
        
        // Update fields for the duplicate
        $new_engine['title'] = $engine->title . " - Duplicado";
        $new_engine['status'] = 0;
        $new_engine['date'] = date('Y-m-d H:i:s');
        
        // Ensure hours_since_last_contact has a default value if not set
        if (!isset($new_engine['hours_since_last_contact']) || empty($new_engine['hours_since_last_contact'])) {
            $new_engine['hours_since_last_contact'] = 24;
        }

        // Insert the new engine
        $this->db->insert(db_prefix() . 'contactcenter_leads_engine', $new_engine);
        $id = $this->db->insert_id();

        if (!$id) {
            return false;
        }

        // Copy the engine list (messages)
        $this->db->where('contactcenter_leads_engine_id', $data['id']);
        $engine_list = $this->db->get(db_prefix() . 'contactcenter_leads_engine_messages')->result();

        if ($engine_list) {
            foreach ($engine_list as $list) {
                $new_list_item = (array) $list;
                unset($new_list_item['id']);
                $new_list_item['contactcenter_leads_engine_id'] = $id;
                $this->db->insert(db_prefix() . 'contactcenter_leads_engine_messages', $new_list_item);
            }
        }

        log_activity('Leads Engine duplicated - Original ID: ' . $data['id'] . ', New ID: ' . $id, get_staff_user_id());

        return true;
    }

