    public function send_last_message_to_ia()
    {

        // busco os contatos onde msg_fromMe é 0 e a data é de hoje, mas uma hora atras
        $currentDateTime = date('Y-m-d H:i:s', strtotime('-1 hour'));
        $this->db->where('msg_fromMe', 0);
        $this->db->where('date', $currentDateTime);

        $contacts = $this->db->get(db_prefix() . 'contactcenter_contact')->result();

        // percorro os contatos
        foreach ($contacts as $contact) {
            // busco o device
            $this->db->where('dev_token', $contact->session);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();

            // busco lead
            $this->db->where('id', $contact->leadid);
            $lead = $this->db->get(db_prefix() . 'leads')->row();

            if ($lead->gpt_status == 1) {
                continue;
            }

            // busco a ultima mensagem que seja do usuario, to tipo text
            $this->db->where('msg_session', $contact->session);
            $this->db->where('msg_conversation_number', $contact->phonenumber);
            $this->db->where('msg_fromMe', 0);
            $this->db->where('msg_type', 'text');
            $this->db->order_by('date', 'DESC');
            $lastMessage = $this->db->get(db_prefix() . 'contactcenter_message')->row();


            // valido se ja existe registro na ia antes de salvar
            $this->db->where('ia_to', $contact->phonenumber);
            $this->db->where('ia_session', $contact->session);
            $this->db->where('msg_id', $lastMessage->msg_id);
            $this->db->where('ia_content', $lastMessage->msg_content);
            $this->db->where('ia_type', 0);
            $exists = $this->db->get(db_prefix() . 'contactcenter_message_ia')->row();

            if ($exists) {
                continue;
            }

            // salvo na ia
            $Crear = array(
                "ia_to" => $contact->phonenumber,
                "staffid" => $device->staffid,
                "leadid" => $contact->leadid,
                "msg_id" => $lastMessage->msg_id,
                "ia_content" => $lastMessage->msg_content,
                "ia_session" => $contact->session,
                "ia_date" => date("Y-m-d H:i:s"),
                "ia_type" => 0,
            );
            $this->db->insert(db_prefix() . 'contactcenter_message_ia', $Crear);
            $insert_id = $this->db->insert_id();
        }
    }

    /**
     * get_meta_analytics
     * @param array $filters Optional filters: date_from, date_to, status, source, assigned
     */
    public function get_meta_analytics($filters = [])
    {
        // Use a simpler approach: get distinct sourceIds first, then get latest record for each
        $this->db->select('sourceId');
        $this->db->from(db_prefix() . 'contactcenter_meta');
        $this->db->join(db_prefix() . 'leads', db_prefix() . 'contactcenter_meta.lead_id = ' . db_prefix() . 'leads.id', 'left');
        
        $this->db->where(db_prefix() . 'contactcenter_meta.conversionSource !=', 'ORGANIC');
        
        // Apply filters
        if (!empty($filters['date_from'])) {
            $this->db->where(db_prefix() . 'leads.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where(db_prefix() . 'leads.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $this->db->where(db_prefix() . 'leads.status', $filters['status']);
        }
        if (!empty($filters['source'])) {
            $this->db->where(db_prefix() . 'leads.source', $filters['source']);
        }
        if (!empty($filters['assigned'])) {
            $this->db->where(db_prefix() . 'leads.assigned', $filters['assigned']);
        }
        
        $this->db->group_by('sourceId');
        $sourceIds = $this->db->get()->result();
        
        if (!$sourceIds) {
            return [];
        }
        
        // Reset query builder
        $this->db->reset_query();
        
        // Get latest meta record for each sourceId and calculate filtered lead count
        $meta = [];
        foreach ($sourceIds as $row) {
            $this->db->select('*');
            $this->db->from(db_prefix() . 'contactcenter_meta');
            $this->db->where('sourceId', $row->sourceId);
            $this->db->order_by('meta_id', 'DESC');
            $this->db->limit(1);
            $result = $this->db->get()->row();
            if ($result) {
                // Calculate filtered lead count for this sourceId
                $this->db->select('COUNT(DISTINCT ' . db_prefix() . 'contactcenter_meta.lead_id) as filtered_leads', false);
                $this->db->from(db_prefix() . 'contactcenter_meta');
                $this->db->join(db_prefix() . 'leads', db_prefix() . 'contactcenter_meta.lead_id = ' . db_prefix() . 'leads.id', 'left');
                $this->db->where(db_prefix() . 'contactcenter_meta.sourceId', $row->sourceId);
                $this->db->where(db_prefix() . 'contactcenter_meta.conversionSource !=', 'ORGANIC');
                
                // Apply the same filters
                if (!empty($filters['date_from'])) {
                    $this->db->where(db_prefix() . 'leads.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
                }
                if (!empty($filters['date_to'])) {
                    $this->db->where(db_prefix() . 'leads.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
                }
                if (!empty($filters['status'])) {
                    $this->db->where(db_prefix() . 'leads.status', $filters['status']);
                }
                if (!empty($filters['source'])) {
                    $this->db->where(db_prefix() . 'leads.source', $filters['source']);
                }
                if (!empty($filters['assigned'])) {
                    $this->db->where(db_prefix() . 'leads.assigned', $filters['assigned']);
                }
                
                $count_result = $this->db->get()->row();
                $result->filtered_leads = $count_result ? (int)$count_result->filtered_leads : 0;
                
                $meta[] = $result;
            }
        }
        
        // Sort by meta_id DESC
        usort($meta, function($a, $b) {
            return $b->meta_id - $a->meta_id;
        });
        
        return $meta;
    }

    /**
     * get_leads_meta_analytics
     * @param string $sourceId Source ID
     * @param array $filters Optional filters: date_from, date_to, status, source, assigned
     */
    public function get_leads_meta_analytics($sourceId = '', $filters = [])
    {
        $meta_table = db_prefix() . 'contactcenter_meta';
        $leads_table = db_prefix() . 'leads';
        
        $this->db->select($meta_table . '.*, ' . $leads_table . '.*, ' . $meta_table . '.source as meta_source');
        $this->db->from($meta_table);
        $this->db->join($leads_table, $meta_table . '.lead_id = ' . $leads_table . '.id');

        // Verificar se $sourceId está vazio ou não
        if (!empty($sourceId)) {
            $this->db->where($meta_table . '.sourceId', $sourceId);
        } else {
            $this->db->where($meta_table . '.sourceId IS NULL');
        }
        
        // Apply filters
        if (!empty($filters['date_from'])) {
            $this->db->where($leads_table . '.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where($leads_table . '.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $this->db->where($leads_table . '.status', $filters['status']);
        }
        if (!empty($filters['source'])) {
            $this->db->where($leads_table . '.source', $filters['source']);
        }
        if (!empty($filters['assigned'])) {
            $this->db->where($leads_table . '.assigned', $filters['assigned']);
        }

        $this->db->order_by($meta_table . '.date', 'DESC');
        $meta = $this->db->get()->result();

        if ($meta) {
            return $meta;
        }

        return null;
    }


    /**
     * conta quantos leads por dia foram enviados
     */
    public function conta_meta_por_dia($sourceId, $filters = [])
    {
        $meta_table = db_prefix() . 'contactcenter_meta';
        $leads_table = db_prefix() . 'leads';
        
        $this->db->select('DATE(' . $meta_table . '.date) as lead_date, COUNT(*) as total_leads');
        $this->db->from($meta_table);
        $this->db->join($leads_table, $meta_table . '.lead_id = ' . $leads_table . '.id', 'left');

        // Verificar se $sourceId está vazio ou não
        if (!empty($sourceId)) {
            $this->db->where($meta_table . '.sourceId', $sourceId);
        } else {
            $this->db->where($meta_table . '.sourceId IS NULL');
        }
        
        // Apply filters
        if (!empty($filters['date_from'])) {
            $this->db->where($leads_table . '.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where($leads_table . '.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $this->db->where($leads_table . '.status', $filters['status']);
        }
        if (!empty($filters['source'])) {
            $this->db->where($leads_table . '.source', $filters['source']);
        }
        if (!empty($filters['assigned'])) {
            $this->db->where($leads_table . '.assigned', $filters['assigned']);
        }

        $this->db->group_by('DATE(' . $meta_table . '.date)');
        $this->db->order_by('lead_date', 'ASC');
        $result = $this->db->get()->result();

        if ($result) {
            $leads_por_dia = [];
            foreach ($result as $row) {
                $leads_por_dia[] = [
                    'date' => $row->lead_date,
                    'quantity' => $row->total_leads
                ];
            }

            return $leads_por_dia;
        }
        return 0;
    }

