    /**
     * insert_links_custom
     */
    public function insert_links_custom($data)
    {

        if (empty($data["phonenumber"]) || empty($data["source"])) {
            return false;
        }

        $clean_phonenumber = preg_replace('/\D/', '', $data["phonenumber"]);

        $base_url = 'https://api.whatsapp.com/send';

        $header = json_encode(['alg' => 'HS256', 'typ' => 'JWT']);
        $hash = md5("inx" . date("Y-m-d") . time());


        $payload = json_encode([
            'exp' => time() + 3600,
            'phone' => $clean_phonenumber,
            'text' => $data["msg"] ?? 'Olá! Tenho interesse e queria mais informações, por favor.',
            'source_url' => site_url("?inxid={$hash}"),
            'icebreaker' => $data["msg"] ?? 'Olá! Tenho interesse e queria mais informações, por favor.',
            'app' => 'AXIOM',
            'entry_point' => $hash,
            'jid' => $clean_phonenumber . '@s.whatsapp.net',
            'show_keyboard' => 1,
            'show_ad_attribution' => 1,
            'source' => $hash,
            'source_id' => $hash
        ]);

        // Codificando header e payload em Base64 URL safe
        $base64UrlHeader = $this->base64UrlEncode($header);
        $base64UrlPayload = $this->base64UrlEncode($payload);

        // Criando uma chave secreta (mesma chave usada para assinar o token original)


        // Gerando a assinatura usando HS256
        $signature = hash_hmac('sha256', $base64UrlHeader . '.' . $base64UrlPayload, $hash, true);
        $base64UrlSignature = $this->base64UrlEncode($signature);

        // Criando o token JWT
        $jwt = $base64UrlHeader . '.' . $base64UrlPayload . '.' . $base64UrlSignature;

        // Parâmetros
        $params = [
            'phone' => $clean_phonenumber,
            'text' => $data["msg"] ?? 'Olá! Tenho interesse e queria mais informações, por favor.',
            'source_url' =>  site_url("?inxid={$hash}"),
            'icebreaker' => $data["msg"] ?? 'Olá! Tenho interesse e queria mais informações, por favor.',
            'app' => 'AXIOM',
            'entry_point' => $hash,
            'jid' => $clean_phonenumber . '@s.whatsapp.net',
            'show_keyboard' => '1',
            'show_ad_attribution' => '1',
            'source' => $hash,
            'token' => $jwt,
            'context' => $jwt,
        ];



        // Gerar a URL completa
        $url = $base_url . '?' . http_build_query($params);

        // Array para inserir no banco de dados
        $crear = [
            "phonenumber" => $clean_phonenumber,
            "msg" => $data["msg"] ?? '',
            "source" => $data["source"],
            "hash" => $hash,
            "date" => date("Y-m-d H:i:s"),
            "link" => $url,
        ];

        // Inserir no banco de dados
        $this->db->insert(db_prefix() . 'contactcenter_links_custom', $crear);;
        $insert_id = $this->db->insert_id();

        return $insert_id ? true : false;
    }



    public function base64UrlEncode($data)
    {
        return rtrim(strtr(base64_encode($data), '+/', '-_'), '=');
    }


    public function delete_links_custom($data)
    {

        //verifica se existe o link
        $this->db->where('link_id', $data["id"]);
        $link = $this->db->get(db_prefix() . 'contactcenter_links_custom')->row();
        if ($link) {
            $this->db->where('link_id', $data["id"]);
            $this->db->delete(db_prefix() . 'contactcenter_links_custom');

            $this->db->where('sourceId', $link->hash);
            $this->db->delete(db_prefix() . 'contactcenter_meta');

            return true;
        } else {
            return false;
        }
    }

    /**
