            // deleta as threads
            $this->db->where('lead_id', $id);
            $this->db->delete(db_prefix() . 'contactcenter_thread');

            // deleta as conversas chatWeb
            $this->db->where('leadid', $id);
            $this->db->delete(db_prefix() . 'contactcenter_chat_web');

            // deleta as conversas do atendimento transferidos
            $this->db->where('lead_id', $id);
            $this->db->delete(db_prefix() . 'contactcenter_atendimento_trans');
        }
    }


