    /**
     * cron notification reminders whatsapp leads
     */
    public function cron_notification_reminders_whatsapp_leads()
    {
        $this->db->where('notify_by_whatsapp', 1);
        $this->db->where('rel_type', 'lead');
        $this->db->where('isnotify_whatsapp', 0);
        $reminders = $this->db->get(db_prefix() . 'reminders')->result();
        if ($reminders) {
            foreach ($reminders as $reminder) {
                if (date("Y-m-d H:i:s") >= $reminder->date) {
                    $this->db->where('id', $reminder->id);
                    $this->db->update(db_prefix() . 'reminders', ['isnotify_whatsapp' => 1]);

                    $lead = $this->get_leads($reminder->rel_id);
                    $device = $this->get_device_staff($reminder->staff);
                    if ($device) {
                        $staffid = $device->staffid;
                    } else {
                        $staffid = null;
                    }
                    $this->send_text($lead->phonenumber, $reminder->description, $staffid);
                }
            }
        }
    }


    public function restart_device($request)
    {

        $id = $request['id'];
        // busco o device
        $device = $this->get_device($id);

        if ($device) {

            $host = site_url();

            // busco o server
            $server = $this->get_server($device->server_id);

            // // busco algum servidor diferente do server do device
            // $this->db->where('id !=', $device->server_id);
            // $servers = $this->db->get(db_prefix() . 'contactcenter_server')->result();

            // // busco aleatoriamente um servidor
            // $servers = $servers[array_rand($servers)];

            // Agora vamos buscar o novo servidor
            // Pega qualquer servidor diferente do atual
            $this->db->where('id !=', $device->server_id);
            $servers = $this->db->get(db_prefix() . 'contactcenter_server')->result();

            if (empty($servers)) {
                return false; // Sem servidores disponíveis, encerra
            }

            // AXIOM: Escolhe servidor aleatoriamente
            $servers = $servers[array_rand($servers)];


            $data = [
                "dev_instance_name" => $device->dev_instance_name,
                "dev_token" => $device->dev_token,
            ];



            // logout first
            $ApiUrl = $server->url . 'instance/logout/' . $device->dev_instance_name;
            $this->axiom_evolution->logout($ApiUrl, $device->dev_token);

            $this->axiom_evolution->delete_instance($server, $host, $device->dev_instance_name);


            if ($servers->version == 1) {
                $this->axiom_evolution->create_instance_v1($servers, $host, $data);
            } else {
                $this->axiom_evolution->create_instance_v2($servers, $host, $data);
            }



            // atualizo device pro novo server
            $this->db->where('dev_id', $id);
            $this->db->update(db_prefix() . 'contactcenter_device', ['server_id' => $servers->id]);

            return true;
        }

        return false;
    }

    /**
     * Restart device with sequential server change
     */
    public function restart_device_sequential($request)
    {
        $id = $request['id'];
        $device = $this->get_device($id);

        if (!$device) {
            return false;
        }

        $host = site_url();
        $server = $this->get_server($device->server_id);

        // Get all servers except current one, ordered by ID for sequential selection
        if (false // AXIOM: verificação de domínio do parceiro removida) {
            // AXIOM: servidor local configurado pelo usuário
            $this->db->where('id !=', $device->server_id);
        } else {
            $this->db->where('id !=', $device->server_id);
        }
        $this->db->order_by('id', 'ASC');
        $available_servers = $this->db->get(db_prefix() . 'contactcenter_server')->result();

        if (empty($available_servers)) {
            return false;
        }

        // Find current server index and get next one sequentially
        $current_index = -1;
        foreach ($available_servers as $index => $srv) {
            if ($srv->id > $device->server_id) {
                $current_index = $index;
                break;
            }
        }

        // If no server found with higher ID, wrap around to first
        if ($current_index === -1) {
            $new_server = $available_servers[0];
        } else {
            $new_server = $available_servers[$current_index];
        }

        $data = [
            "dev_instance_name" => $device->dev_instance_name,
            "dev_token" => $device->dev_token,
        ];

        // Logout first
        $ApiUrl = $server->url . 'instance/logout/' . $device->dev_instance_name;
        $this->axiom_evolution->logout($ApiUrl, $device->dev_token);

        $this->axiom_evolution->delete_instance($server, $host, $device->dev_instance_name);

        if ($new_server->version == 1) {
            $this->axiom_evolution->create_instance_v1($new_server, $host, $data);
        } else {
            $this->axiom_evolution->create_instance_v2($new_server, $host, $data);
        }

        // Update device to new server
        $this->db->where('dev_id', $id);
        $this->db->update(db_prefix() . 'contactcenter_device', [
            'server_id' => $new_server->id,
            'status' => 'connecting',
            'last_status' => date('Y-m-d H:i:s')
        ]);

        return true;
    }

    public function send_chat($data)
    {
        //uploads_image();    
        $action = $data["action"];

        switch ($action) {
            case 'text':
                $Send = $this->send_text($data["phonenumber"], $data["msg"], $data["staffid"], $data["reply_id"], $data["edit_id"], $queue = true, $type_source = 'crm_user');
                if ($Send["error"]) {
                    log_activity("Error ao enviar text: " . $Send["response"]["message"][0]);
                }

                //atualiza a mensagem editada
                if (!$Send["error"] && $data["edit_id"]) {
                    $this->db->where('msg_send_id', $data["edit_id"]);
                    $this->db->update(db_prefix() . 'contactcenter_message', ['msg_content' => $data["msg"], 'msg_status' => 'MESSAGE_EDIT']);
                }


                return true;
                break;
            case 'image':
                $path = $this->uploads_media("chat", $maxSize = null, $mediaType = 'image');
                if ($path == false) {
                    return false;
                }
                $url = site_url("uploads/{$path}");
                $name = explode('/', $path);
                $fileName = end($name);
                $Send = $this->send_file($data["phonenumber"], $data["msg"], $url, $media_type = "image", $data["staffid"], $fileName, $reply_id = null, $queue = true, $type_source = 'crm_user');
                if ($Send) {
                    if ($Send["error"]) {
                        log_activity("Error ao enviar image: " . $Send["response"]["message"][0]);
                    } else {
                        //depos que envia apagar o arquivo
                        unlink(FCPATH . "/uploads/" . $path);
                    }
                    return true;
                }
                break;
            case 'video':
                $path = $this->uploads_media("chat", $maxSize = null, $mediaType = 'video');
                if ($path == false) {
                    return false;
                }
                $url = site_url("uploads/{$path}");
                $name = explode('/', $path);
                $fileName = end($name);
                $Send = $this->send_file($data["phonenumber"], $data["msg"], $url, $media_type = "video", $data["staffid"], $fileName, $reply_id = null, $queue = true, $type_source = 'crm_user');
                if ($Send) {
                    //depos que envia apagar o arquivo
                    if ($Send["error"]) {
                        log_activity("Error ao enviar video: " . $Send["response"]["message"][0]);
                    } else {
                        unlink(FCPATH . "/uploads/" . $path);
                    }

                    return true;
                }
                break;
            case 'document':
                $path = $this->uploads_media_php("chat", $maxSize = null, $mediaType = 'document');
                if ($path == false) {
                    return false;
                }

                $url = site_url("uploads/{$path}");
                $name = explode('/', $path);
                $fileName = end($name);
                $Send = $this->send_file($data["phonenumber"], $data["msg"], $url, $media_type = "document", $data["staffid"], $fileName, $reply_id = null, $queue = true, $type_source = 'crm_user');
                if ($Send) {
                    //depos que envia apagar o arquivo
                    if ($Send["error"]) {
                        log_activity("Error ao enviar document: " . $Send["response"]["message"][0]);
                    } else {
                        unlink(FCPATH . "/uploads/" . $path);
                    }

                    return true;
                }
                break;
            case 'xlsx':
                $path = $this->uploads_media("chat", $maxSize = null, $mediaType = 'document');
                if ($path == false) {
                    return false;
                }
                $url = site_url("uploads/{$path}");
                $name = explode('/', $path);
                $fileName = end($name);
                $Send = $this->send_file($data["phonenumber"], $data["msg"], $url, $media_type = "document", $data["staffid"], $fileName, $reply_id = null, $queue = true, $type_source = 'crm_user');

                if ($Send) {
                    if ($Send["error"]) {
                        log_activity("Error ao enviar xlsx: " . $Send["response"]["message"][0]);
                    } else {
                        unlink(FCPATH . "/uploads/" . $path);
                    }
                    return true;
                }
                break;
            case 'zip':
                $path = $this->uploads_media("chat", $maxSize = null, $mediaType = 'zip');
                if ($path == false) {
                    return false;
                }
                $url = site_url("uploads/{$path}");
                $name = explode('/', $path);
                $fileName = end($name);
                $Send = $this->send_file($data["phonenumber"], $data["msg"], $url, $media_type = "document", $data["staffid"], $fileName, $reply_id = null, $queue = true, $type_source = 'crm_user');
                if ($Send) {
                    //depos que envia apagar o arquivo
                    if ($Send["error"]) {
                        log_activity("Error ao enviar zip: " . $Send["response"]["message"][0]);
                    } else {
                        unlink(FCPATH . "/uploads/" . $path);
                    }
                    return true;
                }
                break;
            default:
                return false;
                break;
        }
    }

    public function update_web_socket()
    {
        // busco todos os devices
        $devices = $this->db->get(db_prefix() . 'contactcenter_device')->result();

        foreach ($devices as $device) {
            try {

                // busco o server
                $server = $this->get_server($device->server_id);

                if ($server->version == 1) {
                    $this->axiom_evolution->update_web_socket_v1($server, $device->dev_instance_name);
                    $this->axiom_evolution->update_webhook_v1($server, $device->dev_instance_name);
                } else {
                    $this->axiom_evolution->update_web_socket_v2($server, $device->dev_instance_name);
                    $this->axiom_evolution->update_webhook_v2($server, $device->dev_instance_name);
                }
            } catch (\Throwable $th) {
                continue;
            }
        }
    }
