    public function ajax_time_ia($data)
    {
        $dias_da_semana = dias_semanas();
        $horarios = [];

        foreach ($dias_da_semana as $num => $dia) {
            $start = $data["start_$num"];
            $end = $data["end_$num"];
            $horarios[$num] = [
                'day' => $dia,
                'start' => $start,
                'end' => $end
            ];
        }

        // faz o update na tabela device 
        $this->db->where('dev_id', $data["device_id"]);
        $this->db->update(db_prefix() . 'contactcenter_device', [
            'timer_ia' => json_encode($horarios)
        ]);
        if ($this->db->affected_rows() > 0) {
            return true;
        } else {
            return false;
        }
    }

