                $logData = [
                    'log_type' => 'error',
                    'log_data' => json_encode($data),
                    'log_date' => date('Y-m-d H:i:s'),
                    'log_user' => get_staff_user_id(),
                    'log_ip' => $this->input->ip_address(),
                    'log_description' => 'Error ao enviar mensagem: Device não encontrado',
                ];

                log_activity("Error on api: " . json_encode($logData));

                $result = [
                    'error' => true,
                    'response' => 'Device not found'
                ];

                return $result;
            }

            $server = $this->get_server($device->server_id);

            switch ($type) {
                case 'text':
                    return $this->send_api_message_text($device, $server, $data);
                    break;
                case 'media':
                    return $this->send_api_message_media($device, $server, $data);
                    break;
                default: {
                        $result = [
                            'error' => true,
                            'response' => 'Type not found'
                        ];
                        return $result;
                        break;
                    }
            }
        } catch (\Throwable $th) {
            $logData = [
                'log_type' => 'error',
                'log_data' => json_encode($data),
                'log_date' => date('Y-m-d H:i:s'),
                'log_user' => get_staff_user_id(),
                'log_ip' => $this->input->ip_address(),
                'log_description' => 'Error ao enviar mensagem: ' . $th->getMessage(),
            ];

            log_activity("Error on api: " . json_encode($logData));

            $result = [
                'error' => true,
                'response' => 'Error on send message: ' . $th->getMessage()
            ];

            return $result;
        }
    }


    public function send_api_message_text($device, $server, $data)
    {
        if (!empty($data['phonenumber'])) {
            $this->update_lead_lastcontact_by_phone($data['phonenumber']);
        }

        $result = [
            'error' => false,
            'response' => null
        ];

        if ($device->status != "inChat" && $device->status != "CONNECTED" && $device->status != "open") {
            $result["error"] = true;
            $result["response"] = 'Device is not connected';
            return $result;
        }

        if ($device->status == "inChat" || $device->status == "CONNECTED" || $device->status == "open") {

            $text = str_replace("<br />", "", $data["message"]);
            $text = str_replace("<strong>", "**", $text);
            $text = str_replace("</strong>", "**", $text);

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {

                $data = array(
                    'number' => $data["phonenumber"],
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'composing',
                        'linkPreview' => false
                    ),
                    'textMessage' => array(
                        'text' => $text
                    )
                );
            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {

                $data = array(
                    'number' => $data["phonenumber"],
                    'text' => $text,
                    'options' => array(
                        'delay' => 2000,
                        'presence' => 'composing',
                        'linkPreview' => false
                    )
                );
            }

            $prefixUrl = "{$server->url}message/sendText/{$device->dev_instance_name}";

            $response = $this->axiom_evolution->send($data, $prefixUrl, $device->dev_token);
            if ($response["error"]) {
                $result["error"] = true;
                $result["response"] = 'Erro on sent the message';

                $log_data = [
                    'log_type' => 'error',
                    'log_data' => json_encode($response),
                    'log_date' => date('Y-m-d H:i:s'),
                    'log_user' => get_staff_user_id(),
                    'log_ip' => $this->input->ip_address(),
                    'log_description' => 'Error ao enviar mensagem pela API'
                ];
                log_activity("Error on api: " . json_encode($log_data));

                return $result;
            }

            $result["error"] = false;
            $result["response"] = "Message sent successfully";
            return $result;
        }
    }

    public function send_api_message_media($device, $server, $data)
    {
        if (!empty($data['phonenumber'])) {
            $this->update_lead_lastcontact_by_phone($data['phonenumber']);
        }

        $result = [
            'error' => false,
            'response' => null
        ];

        if ($device->status != "inChat" && $device->status != "CONNECTED" && $device->status != "open") {
            $result["error"] = true;
            $result["response"] = 'Device is not connected';
            return $result;
        }

        if ($device->status == "inChat" || $device->status == "CONNECTED" || $device->status == "open") {

            if ($server->api_type == "axiom_evolution" && $server->version == 1) {

                $data = array(
                    'number' => $data["phonenumber"],
                    'options' => array(
                        'delay' => 1200,
                        'presence' => 'composing',
                    ),
                    'mediaMessage' => array(
                        'mediatype' => $data["mediatype"],
                        'caption' => $data["caption"],
                        'media' => $data["url"]
                    )
                );
            } else if ($server->api_type == "axiom_evolution" && $server->version == 2) {
                $data = array(
                    'number' => $data["phonenumber"],
                    'mediatype' => $data["mediatype"],
                    'caption' => $data["caption"],
                    'media' => $data["url"],
                    'options' => array(
                        'delay' => 0,
                        'presence' => 'composing'
                    )
                );
            }

            $prefixUrl = "{$server->url}message/sendMedia/{$device->dev_instance_name}";

            $response = $this->axiom_evolution->send($data, $prefixUrl, $device->dev_token);
            if ($response["error"]) {
                $result["error"] = true;
                $result["response"] = 'Erro on sent the media';

                $log_data = [
                    'log_type' => 'error',
                    'log_data' => json_encode($response),
                    'log_date' => date('Y-m-d H:i:s'),
                    'log_user' => get_staff_user_id(),
                    'log_ip' => $this->input->ip_address(),
                    'log_description' => 'Error ao enviar midia pela API'
                ];
                log_activity("Error on api: " . json_encode($log_data));

                return $result;
            }

            $result["error"] = false;
            $result["response"] = "Media sent successfully";
            return $result;
        }
    }

    public function get_dados_leads_sender_id($sender_id)
    {
        if ($sender_id) {
            $this->db->where('lead_messenger_id', $sender_id);
            return $this->db->get(db_prefix() . 'leads')->row();
        }
    }

    public function get_messages_meta($data, $isRead = false)
    {
        $pageId = $data["page_id"];
        $sender_id = $data["sender_id"];
        $paginadorId = $data["paginadorId"];
        if ($data) {
            if ($paginadorId) {
                $this->db->where('messenger_id <', $paginadorId);
            }
            $this->db->where('page_id', $pageId);
            $this->db->where('sender_id', $sender_id);
            $this->db->order_by("messenger_id", "DESC");
            $this->db->limit(8);
            $Result = $this->db->get(db_prefix() . 'facebookleadsintegration_messenger')->result();
            if ($isRead) {
                // Atualiza a msg_isread com true, marcando que foi lido
                $read = [
                    "from_read" => 1
                ];
                $this->db->where('page_id', $pageId);
                $this->db->where('sender_id', $sender_id);
                $this->db->update(db_prefix() . 'facebookleadsintegration_messenger', $read);

                $this->db->where('page_id', $pageId);
                $this->db->where('sender_id', $sender_id);
                $this->db->update(db_prefix() . 'facebookleadsintegration_messenger_contact', ['count' => 0]);
            }
            return array_reverse($Result);
        }
    }

    public function ajax_send_msg_messenger($data)
    {

        $active_facebookleadsintegration = $this->app_modules->is_inactive("facebookleadsintegration");
        if (!$active_facebookleadsintegration) {
            $this->load->model('facebookleadsintegration/facebookleadsintegration_model');
            $action = $data["action"];

            $pages = json_decode(get_option('facebook_pages'), true);
            foreach ($pages as $page) {
                if ($page['id'] == $data["page_id"]) {
                    $pageAccessToken = $page['access_token_long'];
                }
            }

            switch ($action):
                case 'text':
                    $send = $this->facebookleadsintegration_model->send_messenger($data["page_id"], $data["sender_id"], $data["msg"], $pageAccessToken);
                    if (isset($send['error']) && $send['error']) {
                        return [
                            'status' => 'error',
                            'message' => $send['message'],
                            'code' => $send['code'],
                        ];
                    }
                    if ($send) {
                        return [
                            'status' => 'success',
                            'data' => $send,
                        ];
                    } else {
                        return [
                            'status' => 'error',
                            'message' => 'Mensagem não enviada.',
                        ];
                    }
                    break;
                case 'image':
                    //pega o tipo de midia se é imagem, video ou audio
                    if ($_FILES['file']['type'] == 'image/jpeg' || $_FILES['file']['type'] == 'image/png' || $_FILES['file']['type'] == 'image/jpg') {
                        $mediaType = 'image';
                        $maxSize = 8 * 1024;
                    } elseif ($_FILES['file']['type'] == 'video/mp4' || $_FILES['file']['type'] == 'video/avi' || $_FILES['file']['type'] == 'video/mov' || $_FILES['file']['type'] == 'video/wmv') {
                        $mediaType = 'video';
                        $maxSize = 25 * 1024;
                    }

                    $path = $this->uploads_media("chatMessenger", $maxSize, $mediaType);
                    if ($path == false) {
                        return false;
                    }
                    $url = site_url("uploads/{$path}");
                    $send = $this->facebookleadsintegration_model->send_messenger_image_video($data["page_id"], $data["sender_id"], $url, $pageAccessToken, $mediaType);
                    if (isset($send['error']) && $send['error']) {
                        return [
                            'status' => 'error',
                            'message' => $send['message'],
                            'code' => $send['code'],
                        ];
                    }
                    if ($send) {
                        return [
                            'status' => 'success',
                            'data' => $send,
                        ];
                    } else {
                        return [
                            'status' => 'error',
                            'message' => 'Mensagem não enviada.',
                        ];
                    }
                    break;
                case 'audio':

                    $audio = $this->upload_audio("contactcenter/audio");
                    $audioUrl = site_url("/uploads/" . $audio);
                    $send =  $this->facebookleadsintegration_model->send_messenger_audio($data["page_id"], $data["sender_id"], $audioUrl, $pageAccessToken, "audio");
                    if (isset($send['error']) && $send['error']) {
                        return [
                            'status' => 'error',
                            'message' => $send['message'],
                            'code' => $send['code'],
                        ];
                    }
                    if ($send) {
                        return [
                            'status' => 'success',
                            'data' => $send,
                        ];
                    } else {
                        return [
                            'status' => 'error',
                            'message' => 'Mensagem não enviada.',
                        ];
                    }


                    break;
                default:
                    return false;
                    break;
            endswitch;
        } else {
            return false;
        }
    }



    public function get_departments_staff_device()
    {
        // Pega os departamentos
        $this->db->where('staffid', get_staff_user_id());
        $this->db->group_by('departmentid');
        $Departments = $this->db->get(db_prefix() . 'staff_departments')->result();

        if ($Departments) {
            $departmentIds = [];

            // Coleta os IDs dos departamentos em um array
            foreach ($Departments as $dep) {
                $departmentIds[] = $dep->departmentid;
            }

            if (!empty($departmentIds)) {

                $this->db->where_in('departmentid', $departmentIds);
                $this->db->group_by('staffid');
                $Members = $this->db->get(db_prefix() . 'staff_departments')->result();
                if ($Members) {
                    $staffIds = [];
                    foreach ($Members as $member) {
                        $staffIds[] = $member->staffid;
                    }

                    $this->db->where_in('staffid', $staffIds);
                    // Only get active devices
                    $this->db->where('is_active', 1);
                    $Devices = $this->db->get(db_prefix() . 'contactcenter_device')->result();
                    return $Devices;
                }
            }
        }

        return []; // Retorna um array vazio se não encontrar nenhum dado
    }

    /**
     * Pega os departamentos do staff
     */
    public function get_staff_members($staffid)
    {
        $this->db->select('departmentid');
        $this->db->where('staffid', $staffid);
        $this->db->group_by('departmentid');
        $Departments = $this->db->get(db_prefix() . 'staff_departments')->result();
        if ($Departments) {
            $departmentIds = [];

            // Coleta os IDs dos departamentos em um array
            foreach ($Departments as $dep) {
                $departmentIds[] = $dep->departmentid;
            }
            return $departmentIds;
        }
        return [];
    }

