    public function ajax_create_variacoe_openai($data)
    {
        // Recuperar a chave da API
        $apiKey = get_option("tokenopenai_contactcenter");
        $url = 'https://api.openai.com/v1/chat/completions';

        // Construir o payload corretamente sem sobrescrever $messages
        $data = [
            "model" => "gpt-4o",
            "messages" => array_merge(
                [["role" => "system", "content" => "Crie exatamente {$data["quantidade"]} variações da seguinte mensagem. Separe cada variação com o caractere '|'. Não adicione numeração ou quebras de linha."]],
                [["role" => "user", "content" => $data["text"]]]
            ),
        ];

        $headers = [
            "Content-Type: application/json",
            "Authorization: Bearer $apiKey",
            "OpenAI-Beta: assistants=v2"
        ];

        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));

        $response = curl_exec($ch);
        $err = curl_error($ch);

        curl_close($ch);

        if ($err) {
            log_activity("cURL Error #:" . $err);
        } else {
            $result = json_decode($response, true);

            if (isset($result["choices"][0]["message"]["content"])) {
                return $result["choices"][0]["message"]["content"];
            } else {
                log_activity("Error ao criar variações: " . json_encode($result));
                return false;
            }
        }
    }


