    /**
     * pega as mensagens de rapidas shearch
     */
    public function get_msgspeed_search($data)
    {
        $this->db->group_start(); // Inicia um grupo de condições
        $this->db->where('device_id', $data["device_id"]);
        $this->db->like('title', $data["search"], 'both');
        $this->db->group_end(); // Fecha o primeiro grupo

        $this->db->or_group_start(); // Inicia o segundo grupo para o OR
        $this->db->where('restrict', 0);
        $this->db->like('title', $data["search"], 'both');
        $this->db->group_end(); // Fecha o segundo grupo

        return $this->db->get(db_prefix() . 'contactcenter_message_speed')->result();
    }

    public function ajax_delete_msg_whats($data)
    {

        //pega dados da mensagem
        $this->db->where('msg_send_id', $data["msg_id"]);
        $msg = $this->db->get(db_prefix() . 'contactcenter_message')->row();
        if (!$msg) {
            return false;
        }

        $device = $this->get_device_token($msg->msg_session);

        $server = $this->get_server($device->server_id);
        $url = "{$server->url}chat/deleteMessageForEveryone/{$device->dev_instance_name}";

        $jSON = [
            "id" => $msg->msg_send_id,
            "remoteJid" => $msg->remoteJid,
            "fromMe" => true,
        ];

        $json_data = json_encode($jSON);

        $curl = curl_init();

        curl_setopt_array($curl, array(
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_ENCODING => '',
            CURLOPT_MAXREDIRS => 10,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
            CURLOPT_CUSTOMREQUEST => 'DELETE',
            CURLOPT_POSTFIELDS => $json_data,
            CURLOPT_HTTPHEADER => array(
                'Content-Type: application/json',
                'ApiKey: ' . $server->value_key . ' '
            ),
        ));

        $response = curl_exec($curl);
        curl_close($curl);

        $retorno = json_decode($response, true);
        if ($retorno["status"] == "PENDING") {
            //faz update na mensagem
            $this->db->where('msg_send_id', $data["msg_id"]);
            $this->db->update(db_prefix() . 'contactcenter_message', ["msg_status" => "DELIVERY_DELETE"]);

            log_activity("Mensagem deletada com sucesso ID: {$msg->msg_send_id} Phone: {$msg->remoteJid}", get_staff_user_id());

            return true;
        } else {
            return false;
        }
    }


