    /**
     * Converte mensagens com base64 para arquivos
     */
    public function cron_file_message_base64()
    {
        // Pega mensagens com base64 mas sem URL gerada, excluindo tipos não arquivos
        $this->db->where('msg_base64 IS NOT NULL');
        $this->db->where('msg_base64 !=', '');

        $this->db->group_start()
            ->where('msg_url IS NULL')
            ->or_where('msg_url', '')
            ->group_end();

        $this->db->where_not_in('msg_type', ['ptt', 'text', 'video']);
        $this->db->order_by('msg_id', 'DESC');
        $this->db->limit(100);
        $messages = $this->db->get(db_prefix() . 'contactcenter_message')->result();
        foreach ($messages as $msg) {
            $file_url = contactcenter_base64ToFile($msg->msg_base64, "contactcenter/messages");

            if ($file_url) {
                $this->db->where('msg_id', $msg->msg_id);
                $this->db->update(db_prefix() . 'contactcenter_message', ['msg_url' => $file_url]);
            }
        }
    }


