    public function reload_device($device_id)
    {
        $this->db->where('dev_id', $device_id["id"]);
        $device =  $this->db->get(db_prefix() . 'contactcenter_device')->row();
        if (!$device) {
            return false;
        }
        //pega o servidor 
        $server = $this->get_server($device->server_id);
        $url = "{$server->url}instance/restart/{$device->dev_instance_name}";

        if($server->version == 1){
            $method = 'PUT';
        }else{
            $method = 'POST';
        }

        $response = $this->axiom_evolution->reload_instance_evolution($url, $server->value_key, $method);

        return $response;

    }

    /**
     * Get devices with health data
     */
    public function get_devices_with_health()
    {
        $devices = $this->get_device();
        
        foreach ($devices as $device) {
            // Get messages sent in last 24 hours
            $this->db->where('msg_session', $device->dev_token);
            $this->db->where('msg_fromMe', 1);
            $this->db->where('msg_date >=', date('Y-m-d H:i:s', strtotime('-24 hours')));
            $sent_count = $this->db->count_all_results(db_prefix() . 'contactcenter_message');
            
            // Get messages received in last 24 hours
            $this->db->where('msg_session', $device->dev_token);
            $this->db->where('msg_fromMe', 0);
            $this->db->where('msg_date >=', date('Y-m-d H:i:s', strtotime('-24 hours')));
            $received_count = $this->db->count_all_results(db_prefix() . 'contactcenter_message');
            
            // Update device with counts
            $device->msgs_sent_24h = $sent_count;
            $device->msgs_received_24h = $received_count;
            
            // Calculate health score (ratio)
            if ($received_count > 0) {
                $device->health_score = $sent_count / $received_count;
            } else {
                $device->health_score = $sent_count > 0 ? 999 : 0;
            }
        }
        
        return $devices;
    }

    /**
     * Update health scores for all devices
     */
    public function update_device_health_scores()
    {
        $devices = $this->get_device();
        
        foreach ($devices as $device) {
            // Get messages sent in last 24 hours
            $this->db->where('msg_session', $device->dev_token);
            $this->db->where('msg_fromMe', 1);
            $this->db->where('msg_date >=', date('Y-m-d H:i:s', strtotime('-24 hours')));
            $sent_count = $this->db->count_all_results(db_prefix() . 'contactcenter_message');
            
            // Get messages received in last 24 hours
            $this->db->where('msg_session', $device->dev_token);
            $this->db->where('msg_fromMe', 0);
            $this->db->where('msg_date >=', date('Y-m-d H:i:s', strtotime('-24 hours')));
            $received_count = $this->db->count_all_results(db_prefix() . 'contactcenter_message');
            
            // Calculate health score (ratio)
            $health_score = 0;
            if ($received_count > 0) {
                $health_score = $sent_count / $received_count;
            } else {
                $health_score = $sent_count > 0 ? 999 : 0;
            }
            
            // Determine status mode based on health score
            $status_mode = 'active';
            if ($health_score >= 10.0) {
                $status_mode = 'cooldown'; // Critical - pause campaigns
            } elseif ($health_score >= 5.0) {
                $status_mode = 'warming_up'; // Warning - activate maturation
            }
            
            // Update device
            $this->db->where('dev_id', $device->dev_id);
            $this->db->update(db_prefix() . 'contactcenter_device', [
                'msgs_sent_24h' => $sent_count,
                'msgs_received_24h' => $received_count,
                'health_score' => $health_score,
                'status_mode' => $status_mode
            ]);
        }
        
        return true;
    }

