    /**
     * Quick Warm-up - Easy way to warm up a device with pre-setup scripts
     */
    public function quick_warmup_device($device_id)
    {
        // Get device
        $device = $this->get_device($device_id);
        if (!$device) {
            return ['success' => false, 'message' => 'Dispositivo não encontrado'];
        }

        $actions_taken = [];

        // 1. Create default maturation scripts if they don't exist
        $existing_scripts = $this->get_maturation_scripts();
        if (empty($existing_scripts)) {
            $this->create_default_maturation_scripts();
            $actions_taken[] = '✓ Scripts de maturação criados (6 scripts pré-configurados)';
        } else {
            $actions_taken[] = '✓ Scripts de maturação já existem (' . count($existing_scripts) . ' scripts)';
        }

        // 2. Set device to warming_up mode
        $this->db->where('dev_id', $device_id);
        $this->db->update(db_prefix() . 'contactcenter_device', [
            'status_mode' => 'warming_up'
        ]);
        $actions_taken[] = '✓ Modo de aquecimento ativado para: ' . $device->dev_name;

        // 3. Reset health counters to start fresh
        $this->db->where('dev_id', $device_id);
        $this->db->update(db_prefix() . 'contactcenter_device', [
            'msgs_sent_24h' => 0,
            'msgs_received_24h' => 0,
            'health_score' => 0.00
        ]);
        $actions_taken[] = '✓ Contadores de saúde resetados';
        
        $message = implode("\n", $actions_taken);
        $message .= "\n\n🔥 O dispositivo está agora em modo de aquecimento!";
        $message .= "\n\nO sistema irá automaticamente:";
        $message .= "\n• Enviar mensagens de maturação entre dispositivos";
        $message .= "\n• Monitorar a saúde do número em tempo real";
        $message .= "\n• Ajustar o status conforme a saúde melhora";
        $message .= "\n• Voltar ao modo 'ativo' quando a saúde estiver saudável (< 3.0)";

        return ['success' => true, 'message' => $message];
    }

    /**
     * Internal Maturation (Auto-Chat) - Bot-to-bot conversations
     * This function pairs devices that need health improvement and makes them chat
     */
    public function cron_internal_maturation()
    {
        // Get devices that need maturation (status_mode = 'warming_up' or health_score > 5.0)
        $this->db->where_in('status_mode', ['warming_up', 'cooldown']);
        $this->db->or_where('health_score >', 5.0);
        $devices_needing_help = $this->db->get(db_prefix() . 'contactcenter_device')->result();

        if (empty($devices_needing_help)) {
            return;
        }

        // Get maturation scripts
        $scripts = $this->get_maturation_scripts();
        if (empty($scripts)) {
            // Create default scripts if none exist
            $this->create_default_maturation_scripts();
            $scripts = $this->get_maturation_scripts();
        }

        // Get configured device pairs (prioritized)
        $this->db->where('is_active', 1);
        $this->db->order_by('priority', 'DESC');
        $this->db->order_by('date_created', 'ASC');
        $configured_pairs = $this->db->get(db_prefix() . 'contactcenter_device_pairs')->result();

        // If pairs are configured, use them
        if (!empty($configured_pairs)) {
            foreach ($configured_pairs as $pair_config) {
                // Get both devices
                $device_a = $this->get_device($pair_config->device_a_id);
                $device_b = $this->get_device($pair_config->device_b_id);
                
                if (!$device_a || !$device_b) {
                    continue;
                }
                
                // Check if at least one needs help
                $a_needs_help = in_array($device_a->status_mode, ['warming_up', 'cooldown']) || (isset($device_a->health_score) && $device_a->health_score > 5.0);
                $b_needs_help = in_array($device_b->status_mode, ['warming_up', 'cooldown']) || (isset($device_b->health_score) && $device_b->health_score > 5.0);
                
                if (!$a_needs_help && !$b_needs_help) {
                    continue; // Both are healthy, skip
                }
                
                // Get a random script
                $script = $scripts[array_rand($scripts)];
                $dialogue = json_decode($script->dialogue_json, true);
                
                if (!is_array($dialogue) || empty($dialogue)) {
                    continue;
                }
                
                // Execute the dialogue
                $this->execute_dialogue($device_a, $device_b, $dialogue);
            }
        } else {
            // Fallback to automatic pairing (original behavior)
            // Get devices in "Safe Pool" (active devices with good health)
            $this->db->where('status_mode', 'active');
            $this->db->where('health_score <', 3.0);
            $this->db->where('status', 'CONNECTED');
            $safe_pool_devices = $this->db->get(db_prefix() . 'contactcenter_device')->result();

            if (empty($safe_pool_devices)) {
                return;
            }

            foreach ($devices_needing_help as $device_a) {
                // Find a partner device from safe pool
                $device_b = $safe_pool_devices[array_rand($safe_pool_devices)];
                
                // Get a random script
                $script = $scripts[array_rand($scripts)];
                $dialogue = json_decode($script->dialogue_json, true);
                
                if (!is_array($dialogue) || empty($dialogue)) {
                    continue;
                }
                
                // Execute the dialogue
                $this->execute_dialogue($device_a, $device_b, $dialogue);
            }
        }
    }

    /**
     * Execute dialogue between two devices
     */
    private function execute_dialogue($device_a, $device_b, $dialogue)
    {
        foreach ($dialogue as $message) {
            $sender = $message['sender'];
            $text = $message['text'];
            
            // Determine which device sends this message
            $sender_device = ($sender == 'A') ? $device_a : $device_b;
            $receiver_device = ($sender == 'A') ? $device_b : $device_a;
            
            // Simulate typing (3-10 seconds)
            $typing_duration = rand(3, 10);
            sleep($typing_duration);
            
            // Send message (silently, without notifications)
            $response = $this->send_text(
                $receiver_device->dev_number,
                $text,
                $sender_device->staffid,
                null, // reply_id
                null, // edit_id
                true, // queue
                'maturation' // type_source - special type for maturation messages
            );
            
            // Archive messages automatically (mark as read and archive)
            if ($response && isset($response['key']) && isset($response['key']['id'])) {
                $this->archive_maturation_message($response['key']['id'], $receiver_device->dev_token);
            }
            
            // Small delay between messages
            sleep(rand(2, 5));
        }
    }

    /**
     * Archive maturation message (mark as read and archive)
     */
    private function archive_maturation_message($message_id, $device_token)
    {
        // Get device
        $this->db->where('dev_token', $device_token);
        $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
        
        if (!$device) {
            return false;
        }
        
        // Get server
        $server = $this->get_server($device->server_id);
        
        if ($server->api_type == "axiom_evolution") {
            // Mark as read
            $readUrl = "{$server->url}chat/markMessageAsRead/{$device->dev_instance_name}";
            $readData = [
                'messageId' => $message_id
            ];
            $this->axiom_evolution->send($readData, $readUrl, $device->dev_token);
            
            // Archive conversation (if API supports it)
            // Note: Archive functionality depends on Evolution API version
            // This is a placeholder - adjust based on your API version
        }
        
        return true;
    }

    /**
     * Safe Groups - Send periodic messages to groups
     * This function sends messages to configured safe groups to improve reputation
     */
    public function cron_safe_groups()
    {
        // Get all active safe groups
        $this->db->where('is_active', 1);
        $safe_groups = $this->db->get(db_prefix() . 'contactcenter_safe_groups')->result();
        
        if (empty($safe_groups)) {
            return;
        }
        
        // Messages to send (neutral, human-like)
        $group_messages = [
            "Bom dia pessoal!",
            "Boa tarde!",
            "Boa noite!",
            "Ok",
            "👍",
            "👋",
            "Tudo bem?",
            "Alguém aí?",
            "Bom final de semana!"
        ];
        
        foreach ($safe_groups as $group) {
            // Get device
            $this->db->where('dev_id', $group->device_id);
            $device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
            
            if (!$device || $device->status != 'CONNECTED') {
                continue;
            }
            
            // Check last message sent to this group (avoid spamming)
            $this->db->where('msg_conversation_number', $group->group_id);
            $this->db->where('msg_session', $device->dev_token);
            $this->db->where('msg_fromMe', 1);
            $this->db->order_by('msg_date', 'DESC');
            $this->db->limit(1);
            $last_message = $this->db->get(db_prefix() . 'contactcenter_message')->row();
            
            // Only send if last message was more than 2 hours ago
            if ($last_message) {
                $last_message_time = strtotime($last_message->msg_date);
                $two_hours_ago = strtotime('-2 hours');
                
                if ($last_message_time > $two_hours_ago) {
                    continue; // Too soon, skip
                }
            }
            
            // Send random message
            $random_message = $group_messages[array_rand($group_messages)];
            
            // Simulate typing
            $this->simulate_typing($device->dev_token, $group->group_id, strlen($random_message));
            
            // Send message to group
            $this->send_text(
                $group->group_id,
                $random_message,
                $device->staffid,
                null,
                null,
                true,
                'safe_groups'
            );
        }
    }

