                'dialogue_json' => json_encode([
                    ['sender' => 'A', 'text' => 'Oi, como vai?'],
                    ['sender' => 'B', 'text' => 'Oi! Tudo bem, obrigado'],
                    ['sender' => 'A', 'text' => 'Que bom!']
                ], JSON_UNESCAPED_UNICODE)
            ],
            [
                'category' => 'business',
                'dialogue_json' => json_encode([
                    ['sender' => 'A', 'text' => 'Boa tarde'],
                    ['sender' => 'B', 'text' => 'Boa tarde, posso ajudar?'],
                    ['sender' => 'A', 'text' => 'Sim, obrigado'],
                    ['sender' => 'B', 'text' => 'Perfeito!']
                ], JSON_UNESCAPED_UNICODE)
            ],
            [
                'category' => 'casual',
                'dialogue_json' => json_encode([
                    ['sender' => 'A', 'text' => 'E aí, beleza?'],
                    ['sender' => 'B', 'text' => 'Tudo certo!'],
                    ['sender' => 'A', 'text' => 'Ótimo!']
                ], JSON_UNESCAPED_UNICODE)
            ],
            [
                'category' => 'greetings',
                'dialogue_json' => json_encode([
                    ['sender' => 'A', 'text' => 'Olá'],
                    ['sender' => 'B', 'text' => 'Olá, tudo bem?'],
                    ['sender' => 'A', 'text' => 'Sim, e você?'],
                    ['sender' => 'B', 'text' => 'Também!']
                ], JSON_UNESCAPED_UNICODE)
            ]
        ];

        foreach ($default_scripts as $script) {
            $script['date_created'] = date('Y-m-d H:i:s');
            $this->db->insert(db_prefix() . 'contactcenter_maturation_scripts', $script);
        }
    }

    /**
     * Message Triggers Methods
     */
    public function get_message_triggers()
    {
        $this->db->order_by('datecreated', 'DESC');
        return $this->db->get(db_prefix() . 'contactcenter_message_triggers')->result();
    }

    public function get_message_trigger($id)
    {
        $this->db->where('id', $id);
        return $this->db->get(db_prefix() . 'contactcenter_message_triggers')->row();
    }

    public function add_message_trigger($data)
    {
        // Convert arrays to comma-separated strings
        if (isset($data['action_add_tag']) && is_array($data['action_add_tag'])) {
            $data['action_add_tag'] = implode(',', $data['action_add_tag']);
        }
        
        // Convert trigger words array to comma-separated string
        if (isset($data['trigger_words']) && is_array($data['trigger_words'])) {
            $data['trigger_words'] = implode(',', array_map('trim', $data['trigger_words']));
        }
        
        // Set default values
        if (!isset($data['is_active'])) {
            $data['is_active'] = 1;
        }
        if (!isset($data['case_sensitive'])) {
            $data['case_sensitive'] = 0;
        }
        if (!isset($data['message_sender_type'])) {
            $data['message_sender_type'] = 'contact'; // Default to contact for backward compatibility
        }
        if (!isset($data['action_disable_ai'])) {
            $data['action_disable_ai'] = 0;
        }
        if (!isset($data['action_send_notification'])) {
            $data['action_send_notification'] = 0;
        }
        
        $this->db->insert(db_prefix() . 'contactcenter_message_triggers', $data);
        return $this->db->insert_id();
    }

    public function update_message_trigger($id, $data)
    {
        // Convert arrays to comma-separated strings
        if (isset($data['action_add_tag']) && is_array($data['action_add_tag'])) {
            $data['action_add_tag'] = implode(',', $data['action_add_tag']);
        }
        
        // Convert trigger words array to comma-separated string
        if (isset($data['trigger_words']) && is_array($data['trigger_words'])) {
            $data['trigger_words'] = implode(',', array_map('trim', $data['trigger_words']));
        }
        
        $this->db->where('id', $id);
        $this->db->update(db_prefix() . 'contactcenter_message_triggers', $data);
        return $this->db->affected_rows() > 0;
    }

    public function delete_message_trigger($id)
    {
        $this->db->where('id', $id);
        $this->db->delete(db_prefix() . 'contactcenter_message_triggers');
        return $this->db->affected_rows() > 0;
    }

    public function toggle_message_trigger($id)
    {
        $trigger = $this->get_message_trigger($id);
        if ($trigger) {
            $new_status = $trigger->is_active ? 0 : 1;
            $this->db->where('id', $id);
            $this->db->update(db_prefix() . 'contactcenter_message_triggers', ['is_active' => $new_status]);
            return $this->db->affected_rows() > 0;
        }
        return false;
    }

    /**
     * Check and execute triggers for a message
     * @param int $lead_id Lead ID
     * @param string $message_content Message content
     * @param bool $is_first_message Whether this is the first message from the lead
     * @param bool $is_from_staff Whether the message is from staff (msg_fromMe = 1) or contact (msg_fromMe = 0)
     * @return array Array of executed triggers
     */
    public function check_and_execute_triggers($lead_id, $message_content, $is_first_message = false, $is_from_staff = false)
    {
        $executed_triggers = [];
        
        // Log trigger check start
        log_activity("TRIGGER CHECK START - Lead ID: {$lead_id}, Message length: " . strlen($message_content) . ", Is first message: " . ($is_first_message ? 'yes' : 'no') . ", Is from staff: " . ($is_from_staff ? 'yes' : 'no'), get_staff_user_id());
        
        // Get active triggers
        $this->db->where('is_active', 1);
        $triggers = $this->db->get(db_prefix() . 'contactcenter_message_triggers')->result();
        
        log_activity("TRIGGER CHECK - Found " . count($triggers) . " active trigger(s)", get_staff_user_id());
        
        foreach ($triggers as $trigger) {
            // Check message sender type filter
            $sender_type = isset($trigger->message_sender_type) ? $trigger->message_sender_type : 'contact';
            
            log_activity("TRIGGER CHECK - Trigger ID: {$trigger->id}, Name: {$trigger->name}, Sender type: {$sender_type}, Trigger type: {$trigger->trigger_type}", get_staff_user_id());
            
            if ($sender_type != 'both') {
                // If trigger is set to 'contact' but message is from staff, skip
                if ($sender_type == 'contact' && $is_from_staff) {
                    log_activity("TRIGGER SKIPPED - Trigger ID: {$trigger->id}, Reason: Sender type mismatch (trigger: contact, message: staff)", get_staff_user_id());
                    continue;
                }
                // If trigger is set to 'staff' but message is from contact, skip
                if ($sender_type == 'staff' && !$is_from_staff) {
                    log_activity("TRIGGER SKIPPED - Trigger ID: {$trigger->id}, Reason: Sender type mismatch (trigger: staff, message: contact)", get_staff_user_id());
                    continue;
                }
            }
            
            // Check trigger type
            if ($trigger->trigger_type == 'first_message' && !$is_first_message) {
                log_activity("TRIGGER SKIPPED - Trigger ID: {$trigger->id}, Reason: Not first message (trigger type: first_message)", get_staff_user_id());
                continue; // Skip if not first message
            }
            
            // Check if message contains trigger words
            $trigger_words = explode(',', $trigger->trigger_words);
            $message_lower = $trigger->case_sensitive ? $message_content : strtolower($message_content);
            $matched = false;
            
            foreach ($trigger_words as $word) {
                $word = trim($word);
                if (empty($word)) continue;
                
                $word_check = $trigger->case_sensitive ? $word : strtolower($word);
                if (strpos($message_lower, $word_check) !== false) {
                    $matched = true;
                    break;
                }
            }
            
            if (!$matched) {
                continue; // No match, skip this trigger
            }
            
            // Execute trigger actions
            $this->execute_trigger_actions($trigger, $lead_id);
            $executed_triggers[] = $trigger->id;
            
            log_activity("Message trigger executed - Trigger ID: {$trigger->id}, Lead ID: {$lead_id}, Message: " . substr($message_content, 0, 100));
        }
        
        return $executed_triggers;
    }

    /**
     * Execute actions for a trigger
     * @param object $trigger Trigger object
     * @param int $lead_id Lead ID
     */
    private function execute_trigger_actions($trigger, $lead_id)
    {
        $this->load->model('leads_model');
        $lead = $this->leads_model->get($lead_id);
        
        if (!$lead) {
            return;
        }
        
        $update_data = [];
        
        // Add tags (merge with existing tags instead of replacing)
        if (!empty($trigger->action_add_tag)) {
            // Get new tags from trigger
            $new_tags = explode(',', $trigger->action_add_tag);
            $new_tags = array_filter(array_map('trim', $new_tags));
            
            if (!empty($new_tags)) {
                // Get existing tags for the lead
                $existing_tags = get_tags_in($lead_id, 'lead');
                
                // Merge existing tags with new tags (avoid duplicates)
                $all_tags = array_merge($existing_tags ? $existing_tags : [], $new_tags);
                $all_tags = array_unique(array_map('trim', $all_tags));
                $all_tags = array_filter($all_tags); // Remove empty values
                
                // Save merged tags (this will keep existing tags and add new ones)
                handle_tags_save($all_tags, $lead_id, 'lead');
                
                log_activity("Trigger tag added - Trigger ID: {$trigger->id}, Lead ID: {$lead_id}, New tags: " . implode(', ', $new_tags) . ", Total tags: " . implode(', ', $all_tags), get_staff_user_id());
            }
        }
        
        // Change status
        if (!empty($trigger->action_change_status)) {
            $update_data['status'] = $trigger->action_change_status;
        }
        
        // Change source
        if (!empty($trigger->action_change_source)) {
            $update_data['source'] = $trigger->action_change_source;
        }
        
        // Update field
        if (!empty($trigger->action_update_field) && !empty($trigger->action_update_field_value)) {
            $field_name = $trigger->action_update_field;
            if (property_exists($lead, $field_name)) {
                $update_data[$field_name] = $trigger->action_update_field_value;
            }
        }
        
        // Update custom field
        if (!empty($trigger->action_update_custom_field) && !empty($trigger->action_update_custom_field_value)) {
            $custom_fields = [$trigger->action_update_custom_field => $trigger->action_update_custom_field_value];
            handle_custom_fields_post($lead_id, $custom_fields);
        }
        
        // Update description
        if (!empty($trigger->action_update_description)) {
            $current_description = $lead->description ?? '';
            $update_data['description'] = $current_description . "\n" . $trigger->action_update_description;
        }
        
        // Disable AI
        if ($trigger->action_disable_ai) {
            // CRITICAL: Only disable AI for THIS specific lead, NOT the device
            // Get device info for logging
            $this->db->where('id', $lead_id);
            $lead_for_device = $this->db->get(db_prefix() . 'leads')->row();
            
            $device_info = null;
            if ($lead_for_device && !empty($lead_for_device->phonenumber)) {
                // Try to find device by phone number or other means
                // This is just for logging purposes
            }
            
            log_activity("TRIGGER DISABLE_AI - Trigger ID: {$trigger->id}, Lead ID: {$lead_id}, Phone: " . ($lead_for_device->phonenumber ?? 'N/A') . " - Apenas atualizando gpt_status do lead, NÃO alterando device", get_staff_user_id());
            
            $this->db->where('id', $lead_id);
            $this->db->update(db_prefix() . 'leads', ['gpt_status' => 1]);
            
            // Verify update
            $this->db->where('id', $lead_id);
            $lead_after = $this->db->get(db_prefix() . 'leads')->row();
            log_activity("TRIGGER DISABLE_AI VERIFICATION - Lead ID: {$lead_id}, gpt_status after update: " . ($lead_after->gpt_status ?? 'null'), get_staff_user_id());
        }
        
        // Change owner
        if (!empty($trigger->action_change_owner)) {
            $update_data['assigned'] = $trigger->action_change_owner;
        }
        
        // Update lead if there are changes
        if (!empty($update_data)) {
            $this->leads_model->update($update_data, $lead_id);
        }
        
        // Send notification
        if ($trigger->action_send_notification && !empty($trigger->action_notification_staff)) {
            $notification_message = !empty($trigger->action_notification_message) 
                ? $trigger->action_notification_message 
                : "Trigger activated for lead #{$lead_id}";
            
            $this->load->model('notifications_model');
            add_notification([
                'description' => $notification_message,
                'touserid' => $trigger->action_notification_staff,
                'fromuserid' => get_staff_user_id(),
                'link' => admin_url('contactcenter/chatsingle/' . $lead->phonenumber),
            ]);
        }
    }

    /**
     * Check if this is the first message from a lead
     * @param int $lead_id Lead ID
     * @param string $phonenumber Phone number
     * @return bool
     */
    public function is_first_message_from_lead($lead_id, $phonenumber)
    {
        // Check if there are any previous messages from this phone number (not from us)
        // We check by phone number because the current message might not have leadid set yet
        // Note: This is called AFTER the current message is inserted, so we check if count == 1
        $this->db->where('msg_from', $phonenumber);
        $this->db->where('msg_fromMe', 0);
        $this->db->where('msg_isGroupMsg', 0);
        $count = $this->db->count_all_results(db_prefix() . 'contactcenter_message');
        
        // If count is 1, this is the first message (the one just inserted), so return true
        // If count > 1, this is not the first message, so return false
        return $count == 1;
    }

    /**
     * Generate group chat name based on configured format
     * @param object $lead Lead object
     * @param string|null $meeting_date Optional meeting date in YYYY-MM-DD format
     * @param string|null $custom_name Optional custom name to add
     * @return string Generated group name
     */
    /**
     * Manual group creation - reusable method that can be called from AJAX or assistants
     */
    public function manual_create_group_chat($lead_id, $phonenumber, $device_id, $meeting_date = null, $custom_name = null)
    {
        try {
            log_activity("manual_create_group_chat INICIADO - Lead ID: {$lead_id}, Device ID: {$device_id}, Phone: {$phonenumber}", get_staff_user_id());
            
            // Get lead information
            $lead = $this->get_leads($lead_id);
            if (!$lead) {
                log_activity("manual_create_group_chat ERRO - Lead não encontrado. Lead ID: {$lead_id}", get_staff_user_id());
                return [
                    "success" => false,
                    "message" => "Lead not found"
                ];
            }
            
            // Get device information
            $device = $this->get_device($device_id);
            if (!$device) {
                log_activity("manual_create_group_chat ERRO - Device não encontrado. Device ID: {$device_id}", get_staff_user_id());
                return [
                    "success" => false,
                    "message" => "Device not found"
                ];
            }
            
            // Generate group name using existing helper method
            $group_name = $this->generate_group_chat_name($lead, $meeting_date, $custom_name);
            
            log_activity("manual_create_group_chat NOME GERADO - Group Name: {$group_name}, Lead: {$lead->name}, Meeting Date: " . ($meeting_date ?? 'null'), get_staff_user_id());
            
            // Start with lead phone number
            $participants = [$phonenumber];
            
            // Get configured staff members to auto-add to group
            $auto_add_staff_ids = get_option('contactcenter_group_chat_auto_add_staff');
            log_activity("manual_create_group_chat AUTO ADD STAFF CONFIG - Raw config value: " . ($auto_add_staff_ids ?: 'empty'), get_staff_user_id());
            
            if (!empty($auto_add_staff_ids)) {
                // Handle both array and comma-separated string formats
                if (is_array($auto_add_staff_ids)) {
                    $staff_ids_array = array_filter($auto_add_staff_ids, function($val) {
                        return !empty(trim($val));
                    });
                } else {
                    $staff_ids_array = array_filter(explode(',', $auto_add_staff_ids), function($val) {
                        return !empty(trim($val));
                    });
                }
                
                log_activity("manual_create_group_chat AUTO ADD STAFF - Processing " . count($staff_ids_array) . " staff IDs", get_staff_user_id());
                
                foreach ($staff_ids_array as $staff_id) {
                    $staff_id = trim($staff_id);
                    if (empty($staff_id)) continue;
                    
                    // Get staff member info
                    $staff_info = $this->staff_model->get($staff_id);
                    $staff_name = $staff_info ? ($staff_info->firstname . ' ' . $staff_info->lastname) : "Unknown (ID: {$staff_id})";
                    
                    // Get phone number from staff profile
                    $staff_phone = null;
                    if ($staff_info && !empty($staff_info->phonenumber)) {
                        $staff_phone = preg_replace('/\D/', '', $staff_info->phonenumber);
                    }
                    
                    // If no phone in profile, try to get from device as fallback
                    if (empty($staff_phone)) {
                        $staff_devices = $this->get_device(null, $staff_id);
                        if (!empty($staff_devices)) {
                            $devices_list = is_array($staff_devices) ? $staff_devices : [$staff_devices];
                            foreach ($devices_list as $staff_device) {
                                $phone_field = !empty($staff_device->dev_number) ? $staff_device->dev_number : null;
                                if ($phone_field) {
                                    $staff_phone = preg_replace('/\D/', '', $phone_field);
                                    break;
                                }
                            }
                        }
                    }
                    
                    // Add staff phone to participants if found
                    if (!empty($staff_phone) && !in_array($staff_phone, $participants)) {
                        $participants[] = $staff_phone;
                        log_activity("manual_create_group_chat STAFF ADDED - Staff ID: {$staff_id}, Name: {$staff_name}, Phone: {$staff_phone}", get_staff_user_id());
                    }
                }
            }
            
            log_activity("manual_create_group_chat PARTICIPANTS FINAL - Total participants: " . count($participants), get_staff_user_id());
            
            // Get server information
            $server = $this->get_server($device->server_id);
            if (!$server) {
                log_activity("manual_create_group_chat ERRO - Server não encontrado. Server ID: " . ($device->server_id ?? 'null'), get_staff_user_id());
                return [
                    "success" => false,
                    "message" => "Server not found"
                ];
            }
            
            // Create group using Evolution API
            if ($server->api_type == "axiom_evolution") {
                $response = $this->axiom_evolution->create_group_evolution(
                    $server->url,
                    $device->dev_instance_name,
                    $device->dev_token,
                    $group_name,
                    $participants
                );
                
                // Get group ID from response
                $group_id = null;
                if (isset($response['id']) && !empty($response['id'])) {
                    $group_id = $response['id'];
                } elseif (isset($response['group']['id']) && !empty($response['group']['id'])) {
                    $group_id = $response['group']['id'];
                } elseif (isset($response['groupId']) && !empty($response['groupId'])) {
                    $group_id = $response['groupId'];
                }
                
                // Check for participants that couldn't be added (privacy settings)
                $failed_participants = [];
                if (isset($response['participants']) && is_array($response['participants'])) {
                    // Evolution API might return participant status
                    foreach ($response['participants'] as $participant) {
                        if (isset($participant['status']) && in_array(strtolower($participant['status']), ['error', 'failed', 'rejected', 'blocked'])) {
                            if (isset($participant['jid']) || isset($participant['phoneNumber'])) {
                                $failed_participants[] = isset($participant['phoneNumber']) ? $participant['phoneNumber'] : $participant['jid'];
                            }
                        }
                    }
                }
                
                // Also check response for error messages about specific participants
                if (isset($response['errors']) && is_array($response['errors'])) {
                    foreach ($response['errors'] as $error) {
                        if (isset($error['participant']) && !in_array($error['participant'], $failed_participants)) {
                            $failed_participants[] = $error['participant'];
                        }
                    }
                }
                
                // Check response message for participant errors
                if (isset($response['message']) && preg_match_all('/(\d{10,15})/', $response['message'], $matches)) {
                    foreach ($matches[1] as $phone) {
                        if (!in_array($phone, $failed_participants) && in_array($phone, $participants)) {
                            $failed_participants[] = $phone;
                        }
                    }
                }
                
                if ($group_id) {
                    // Save group to database
                    $group_data = [
                        'group_api_name' => $group_name,
                        'group_api_description' => '',
                        'group_api_id' => $group_id,
                        'device_id' => $device_id,
                        'numbers' => $phonenumber
                    ];
                    // Only add date_created if column exists
                    if ($this->db->field_exists('date_created', db_prefix() . 'contactcenter_group_api')) {
                        $group_data['date_created'] = date('Y-m-d H:i:s');
                    }
                    
                    $this->db->insert(db_prefix() . 'contactcenter_group_api', $group_data);
                    $group_db_id = $this->db->insert_id();
                    
                    log_activity("manual_create_group_chat SUCESSO - Group criado. Group ID (API): {$group_id}, Group DB ID: {$group_db_id}, Lead ID: {$lead_id}", get_staff_user_id());
                    
                    // Prepare the meeting message first so it's available when sending invite
                    $final_message = '';
                    $default_message = get_option('contactcenter_group_chat_default_message');
                    if (!empty($default_message)) {
                        // Prepare merge fields
                        $replacements = [
                            '{lead_name}' => $lead->name ?? '',
                            '{lead_email}' => $lead->email ?? '',
                            '{lead_phone}' => $lead->phonenumber ?? '',
                            '{date}' => '',
                            '{date_iso}' => '',
                            '{google_meet_link}' => ''
                        ];
                        
                        // Format meeting date if provided
                        if (!empty($meeting_date)) {
                            try {
                                $date_obj = new DateTime($meeting_date);
                                $replacements['{date}'] = $date_obj->format('d/m/Y');
                                $replacements['{date_iso}'] = $date_obj->format('Y-m-d');
                            } catch (Exception $e) {
                                // Invalid date, leave empty
                            }
                        }
                        
                        // Get Google Meet link from the last meeting/event for this lead
                        $google_meet_link = '';
                        
                        // First, try to get from the last meeting in events table
                        $this->db->where('rel_type', 'lead');
                        $this->db->where('rel_id', $lead_id);
                        $this->db->where('meetLink IS NOT NULL');
                        $this->db->where('meetLink !=', '');
                        $this->db->where('meetLink !=', '0');
                        $this->db->where('meetLink !=', '1');
                        $this->db->order_by('start', 'DESC');
                        $this->db->limit(1);
                        $last_meeting = $this->db->get(db_prefix() . 'events')->row();
                        
                        if ($last_meeting && !empty($last_meeting->meetLink)) {
                            // Validate it's a URL
                            if (filter_var($last_meeting->meetLink, FILTER_VALIDATE_URL) || strpos($last_meeting->meetLink, 'http://') === 0 || strpos($last_meeting->meetLink, 'https://') === 0) {
                                $google_meet_link = $last_meeting->meetLink;
                                log_activity("manual_create_group_chat GOOGLE MEET FOUND - Found in last meeting (Event ID: {$last_meeting->eventid}, Start: {$last_meeting->start}): {$google_meet_link}", get_staff_user_id());
                            } else {
                                log_activity("manual_create_group_chat GOOGLE MEET INVALID - Last meeting has meetLink but it's not a valid URL: {$last_meeting->meetLink}", get_staff_user_id());
                            }
                        } else {
                            log_activity("manual_create_group_chat GOOGLE MEET NOT FOUND - No meeting with valid meetLink found for Lead ID: {$lead_id}", get_staff_user_id());
                            
                            // Fallback: Check custom fields
                            $custom_fields = get_custom_fields('leads');
                            foreach ($custom_fields as $field) {
                                $field_value = get_custom_field_value($lead->id, $field['id'], 'leads');
                                if (!empty($field_value) && preg_match('/meet\.google\.com|meet\.google|meet\?|meet\/[a-z-]+/i', $field_value)) {
                                    $google_meet_link = $field_value;
                                    log_activity("manual_create_group_chat GOOGLE MEET FOUND - Found in custom field '{$field['name']}': {$google_meet_link}", get_staff_user_id());
                                    break;
                                }
                            }
                            
                            // If still not found, check lead description
                            if (empty($google_meet_link) && !empty($lead->description)) {
                                if (preg_match('/(https?:\/\/meet\.google\.com\/[a-z-]+|https?:\/\/meet\.google\.com\/[a-z]+-[a-z]+-[a-z]+)/i', $lead->description, $matches)) {
                                    $google_meet_link = $matches[1];
                                    log_activity("manual_create_group_chat GOOGLE MEET FOUND - Found in lead description: {$google_meet_link}", get_staff_user_id());
                                }
                            }
                        }
                        
                        $replacements['{google_meet_link}'] = $google_meet_link;
                        
                        // Replace placeholders in message
                        $final_message = str_replace(array_keys($replacements), array_values($replacements), $default_message);
                        $final_message = preg_replace('/\{[^}]+\}/', '', $final_message);
                        $final_message = trim($final_message);
                        
                        log_activity("manual_create_group_chat MEETING MESSAGE PREPARED - Final message length: " . strlen($final_message), get_staff_user_id());
                    }
                    
                    // Always generate and send invite link to the lead
                    log_activity("manual_create_group_chat GENERATING INVITE LINK - Generating invite link for group {$group_id}", get_staff_user_id());
                    
                    // Generate group invite link
                    $invite_response = $this->axiom_evolution->generate_group_invite_link_evolution(
                        $server->url,
                        $device->dev_instance_name,
                        $device->dev_token,
                        $group_id
                    );
                    
                    $invite_link = null;
                    if (isset($invite_response['inviteUrl']) && !empty($invite_response['inviteUrl'])) {
                        // Evolution API returns full invite URL
                        $invite_link = $invite_response['inviteUrl'];
                        log_activity("manual_create_group_chat INVITE LINK FOUND - InviteUrl: {$invite_link}", get_staff_user_id());
                    } elseif (isset($invite_response['code']) && !empty($invite_response['code'])) {
                        // Evolution API returns invite code, format as WhatsApp invite link
                        $invite_link = "https://chat.whatsapp.com/" . $invite_response['code'];
                        log_activity("manual_create_group_chat INVITE CODE FOUND - Code: {$invite_response['code']}, Full response: " . json_encode($invite_response), get_staff_user_id());
                    } elseif (isset($invite_response['inviteCode']) && !empty($invite_response['inviteCode'])) {
                        // Evolution API returns inviteCode, format as WhatsApp invite link
                        $invite_link = "https://chat.whatsapp.com/" . $invite_response['inviteCode'];
                        log_activity("manual_create_group_chat INVITE CODE FOUND - InviteCode: {$invite_response['inviteCode']}, Full response: " . json_encode($invite_response), get_staff_user_id());
                    } elseif (isset($invite_response['inviteLink']) && !empty($invite_response['inviteLink'])) {
                        $invite_link = $invite_response['inviteLink'];
                        log_activity("manual_create_group_chat INVITE LINK FOUND - InviteLink: {$invite_link}", get_staff_user_id());
                    } elseif (isset($invite_response['link']) && !empty($invite_response['link'])) {
                        $invite_link = $invite_response['link'];
                        log_activity("manual_create_group_chat INVITE LINK FOUND - Link: {$invite_link}", get_staff_user_id());
                    } else {
                        log_activity("manual_create_group_chat INVITE LINK NOT FOUND - Response keys: " . implode(', ', array_keys($invite_response ?: [])), get_staff_user_id());
                        log_activity("manual_create_group_chat INVITE RESPONSE FULL - " . json_encode($invite_response), get_staff_user_id());
                    }
                    
                    if ($invite_link) {
                        log_activity("manual_create_group_chat INVITE LINK GENERATED - Link: {$invite_link}", get_staff_user_id());
                        
                        // Get invite message template
                        $invite_message_template = get_option('contactcenter_group_chat_invite_message');
                        if (empty($invite_message_template)) {
                            $invite_message_template = "Olá! Você foi convidado para participar do grupo *{group_name}*.\n\nClique no link abaixo para entrar:\n{invite_link}";
                        }
                        
                        // Prepare merge fields for invite message
                        $invite_replacements = [
                            '{group_name}' => $group_name,
                            '{invite_link}' => $invite_link,
                            '{lead_name}' => $lead->name ?? ''
                        ];
                        
                        $invite_message = str_replace(array_keys($invite_replacements), array_values($invite_replacements), $invite_message_template);
                        
                        // Send invite link to the lead
                        $clean_lead_phone = preg_replace('/\D/', '', $phonenumber);
                        if (!empty($clean_lead_phone)) {
                            log_activity("manual_create_group_chat PREPARING TO SEND INVITE - Phone: {$clean_lead_phone}, Device ID: {$device_id}, Staff ID: " . ($device->staffid ?? 'null'), get_staff_user_id());
                            
                            // Use the same device that created the group to send the invite
                            // Get device by device_id to ensure we use the correct device
                            $this->db->where('dev_id', $device_id);
                            $send_device = $this->db->get(db_prefix() . 'contactcenter_device')->row();
                            
                            if ($send_device && ($send_device->status == "inChat" || $send_device->status == "CONNECTED" || $send_device->status == "open" || $send_device->status == "connecting")) {
                                $send_result = $this->send_text($clean_lead_phone, $invite_message, $send_device->staffid, null, null, true, 'crm');
                                log_activity("manual_create_group_chat INVITE SENT TO LEAD - Invite link sent to {$clean_lead_phone} for group {$group_id}. Send result: " . json_encode($send_result), get_staff_user_id());
                                
                                // Also send the meeting link message to the lead (so they get it even if not added to group)
                                if (!empty($final_message)) {
                                    log_activity("manual_create_group_chat SENDING MEETING MESSAGE TO LEAD - Sending meeting message to {$clean_lead_phone} after invite", get_staff_user_id());
                                    $meeting_message_result = $this->send_text($clean_lead_phone, $final_message, $send_device->staffid, null, null, true, 'crm');
                                    log_activity("manual_create_group_chat MEETING MESSAGE SENT TO LEAD - Meeting message sent to {$clean_lead_phone}. Send result: " . json_encode($meeting_message_result), get_staff_user_id());
                                } else {
                                    log_activity("manual_create_group_chat MEETING MESSAGE SKIPPED - Final message is empty, skipping send to lead", get_staff_user_id());
                                }
                            } else {
                                log_activity("manual_create_group_chat INVITE NOT SENT - Device not connected. Device ID: {$device_id}, Status: " . ($send_device->status ?? 'not found'), get_staff_user_id());
                            }
                        } else {
                            log_activity("manual_create_group_chat INVITE NOT SENT - Lead phone number is empty or invalid: {$phonenumber}", get_staff_user_id());
                        }
                        
                        // Also send to any failed participants if there were any
                        if (!empty($failed_participants)) {
                            log_activity("manual_create_group_chat PARTICIPANTS FAILED - " . count($failed_participants) . " participants couldn't be added: " . implode(', ', $failed_participants), get_staff_user_id());
                            
                            foreach ($failed_participants as $failed_phone) {
                                // Clean phone number
                                $clean_phone = preg_replace('/\D/', '', $failed_phone);
                                
                                if (!empty($clean_phone) && $clean_phone != $clean_lead_phone) {
                                    $this->send_text($clean_phone, $invite_message, $device->staffid, null, null, true, 'crm');
                                    log_activity("manual_create_group_chat INVITE SENT TO FAILED PARTICIPANT - Invite link sent to {$clean_phone} for group {$group_id}", get_staff_user_id());
                                }
                            }
                        }
                    } else {
                        log_activity("manual_create_group_chat INVITE LINK FAILED - Could not generate invite link. Response: " . json_encode($invite_response), get_staff_user_id());
                    }
                    
                    // Set group picture if configured
                    $default_picture = get_option('contactcenter_group_chat_default_picture');
                    if (!empty($default_picture)) {
                        $picture_path = FCPATH . $default_picture;
                        if (file_exists($picture_path)) {
                            $this->axiom_evolution->set_group_picture_evolution(
                                $server->url,
                                $device->dev_instance_name,
                                $device->dev_token,
                                $group_id,
                                $picture_path
                            );
                        }
                    }
                    
                    // Send first message to group if configured
                    $default_message = get_option('contactcenter_group_chat_default_message');
                    if (!empty($default_message)) {
                        // Prepare merge fields
                        $replacements = [
                            '{lead_name}' => $lead->name ?? '',
                            '{lead_email}' => $lead->email ?? '',
                            '{lead_phone}' => $lead->phonenumber ?? '',
                            '{date}' => '',
                            '{date_iso}' => '',
                            '{google_meet_link}' => ''
                        ];
                        
                        // Format meeting date if provided
                        if (!empty($meeting_date)) {
                            try {
                                $date_obj = new DateTime($meeting_date);
                                $replacements['{date}'] = $date_obj->format('d/m/Y');
                                $replacements['{date_iso}'] = $date_obj->format('Y-m-d');
                            } catch (Exception $e) {
                                // Invalid date, leave empty
                            }
                        }
                        
                        // Get Google Meet link from the last meeting/event for this lead
                        $google_meet_link = '';
                        
                        // First, try to get from the last meeting in events table
                        $this->db->where('rel_type', 'lead');
                        $this->db->where('rel_id', $lead_id);
                        $this->db->where('meetLink IS NOT NULL');
                        $this->db->where('meetLink !=', '');
                        $this->db->where('meetLink !=', '0');
                        $this->db->where('meetLink !=', '1');
                        $this->db->order_by('start', 'DESC');
                        $this->db->limit(1);
                        $last_meeting = $this->db->get(db_prefix() . 'events')->row();
                        
                        if ($last_meeting && !empty($last_meeting->meetLink)) {
                            // Validate it's a URL
                            if (filter_var($last_meeting->meetLink, FILTER_VALIDATE_URL) || strpos($last_meeting->meetLink, 'http://') === 0 || strpos($last_meeting->meetLink, 'https://') === 0) {
                                $google_meet_link = $last_meeting->meetLink;
                                log_activity("manual_create_group_chat GOOGLE MEET FOUND - Found in last meeting (Event ID: {$last_meeting->eventid}, Start: {$last_meeting->start}): {$google_meet_link}", get_staff_user_id());
                            } else {
                                log_activity("manual_create_group_chat GOOGLE MEET INVALID - Last meeting has meetLink but it's not a valid URL: {$last_meeting->meetLink}", get_staff_user_id());
                            }
                        } else {
                            log_activity("manual_create_group_chat GOOGLE MEET NOT FOUND - No meeting with valid meetLink found for Lead ID: {$lead_id}", get_staff_user_id());
                            
                            // Fallback: Check custom fields
                            $custom_fields = get_custom_fields('leads');
                            foreach ($custom_fields as $field) {
                                $field_value = get_custom_field_value($lead->id, $field['id'], 'leads');
                                if (!empty($field_value) && preg_match('/meet\.google\.com|meet\.google|meet\?|meet\/[a-z-]+/i', $field_value)) {
                                    $google_meet_link = $field_value;
                                    log_activity("manual_create_group_chat GOOGLE MEET FOUND - Found in custom field '{$field['name']}': {$google_meet_link}", get_staff_user_id());
                                    break;
                                }
                            }
                            
                            // If still not found, check lead description
                            if (empty($google_meet_link) && !empty($lead->description)) {
                                if (preg_match('/(https?:\/\/meet\.google\.com\/[a-z-]+|https?:\/\/meet\.google\.com\/[a-z]+-[a-z]+-[a-z]+)/i', $lead->description, $matches)) {
                                    $google_meet_link = $matches[1];
                                    log_activity("manual_create_group_chat GOOGLE MEET FOUND - Found in lead description: {$google_meet_link}", get_staff_user_id());
                                }
                            }
                        }
                        
                        $replacements['{google_meet_link}'] = $google_meet_link;
                        
                        // Replace placeholders in message
                        $final_message = str_replace(array_keys($replacements), array_values($replacements), $default_message);
                        $final_message = preg_replace('/\{[^}]+\}/', '', $final_message);
                        $final_message = trim($final_message);
                        
                        // Only send if message is not empty
                        if (!empty($final_message)) {
                            $message_response = $this->axiom_evolution->send_group_message_evolution(
                                $server->url,
                                $device->dev_instance_name,
                                $device->dev_token,
                                $group_id,
                                $final_message,
                                $server->version ?? null
                            );
                            
                            if (isset($message_response['error'])) {
                                log_activity("manual_create_group_chat MESSAGE FAILED - Failed to send first message to group. Group ID: {$group_id}, Error: " . json_encode($message_response), get_staff_user_id());
                            } else {
                                log_activity("manual_create_group_chat MESSAGE SENT - First message sent successfully to Group ID: {$group_id}", get_staff_user_id());
                            }
                        }
                    }
                    
                    return [
                        "success" => true,
                        "message" => "Group chat created successfully",
                        "group_name" => $group_name,
                        "group_id" => $group_id
                    ];
                } else {
                    log_activity("manual_create_group_chat ERRO - Resposta da API não contém group ID. Response: " . json_encode($response), get_staff_user_id());
                    return [
                        "success" => false,
                        "message" => "Error creating group: Invalid response from API"
                    ];
                }
            } else {
                log_activity("manual_create_group_chat ERRO - Server não é Evolution API. API Type: " . ($server->api_type ?? 'null'), get_staff_user_id());
                return [
                    "success" => false,
                    "message" => "Group creation is only available for Evolution API servers"
                ];
            }
        } catch (Exception $e) {
            log_activity("manual_create_group_chat EXCEÇÃO - Exceção ao criar grupo: " . $e->getMessage(), get_staff_user_id());
            return [
                "success" => false,
                "message" => "Error creating group: " . $e->getMessage()
            ];
        }
    }

    private function generate_group_chat_name($lead, $meeting_date = null, $custom_name = null)
    {
        // Get the configured format from options, default to: "AXIOM x {Lead Name} ({Date})"
        $format = get_option('contactcenter_group_chat_name_format');
        if (empty($format)) {
            $format = 'AXIOM x {lead_name} ({date})';
        }
        
        // Replace placeholders
        $group_name = $format;
        
        // Replace {lead_name} with actual lead name
        $lead_name = !empty($lead->name) ? $lead->name : 'Lead';
        $group_name = str_replace('{lead_name}', $lead_name, $group_name);
        
        // Replace date placeholders only if meeting_date is provided
        if ($meeting_date) {
            // Validate and format the meeting date
            $date_timestamp = strtotime($meeting_date);
            if ($date_timestamp !== false) {
                // Format date nicely (e.g., "2026-01-15" -> "15/01/2026")
                $formatted_date = date('d/m/Y', $date_timestamp);
                $group_name = str_replace('{date}', $formatted_date, $group_name);
                $group_name = str_replace('{date_iso}', $meeting_date, $group_name);
            } else {
                // Invalid date format, remove date placeholders
                $group_name = str_replace('{date}', '', $group_name);
                $group_name = str_replace('{date_iso}', '', $group_name);
            }
        } else {
            // No meeting date provided, remove date placeholders
            $group_name = str_replace('{date}', '', $group_name);
            $group_name = str_replace('{date_iso}', '', $group_name);
        }
        
        // Add custom name if provided
        if ($custom_name) {
            $group_name .= ' - ' . $custom_name;
        }
        
        // Clean up any remaining placeholders and extra spaces
        $group_name = preg_replace('/\{[^}]+\}/', '', $group_name);
        $group_name = preg_replace('/\s+/', ' ', $group_name); // Remove extra spaces
        $group_name = preg_replace('/\s*\(\s*\)\s*/', '', $group_name); // Remove empty parentheses
        $group_name = trim($group_name);
        
        return $group_name;
    }

    /**
     * ADS ANALYTICS METHODS
     */
    
    /**
     * Get available campaigns from custom field
     */
    public function get_available_campaigns()
    {
        $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
        
        if (empty($custom_fields)) {
            return [];
        }
        
        $this->db->distinct();
        $this->db->select('value');
        $this->db->from(db_prefix() . 'customfieldsvalues');
        $this->db->where('fieldid', $custom_fields[0]['id']);
        $this->db->where('value !=', '');
        $this->db->where('value IS NOT NULL');
        $this->db->order_by('value', 'ASC');
        $result = $this->db->get()->result();
        
        if (!$result) {
            return [];
        }
        
        $campaigns = [];
        foreach ($result as $row) {
            $campaigns[] = $row->value;
        }
        
        return $campaigns;
    }

