    /**
     * Get ads analytics creatives with stats
     */
    public function get_ads_analytics_creatives($filters = [])
    {
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_data_table = db_prefix() . 'leads';
        $media_table = db_prefix() . 'contactcenter_ads_media';
        $custom_fields_values_table = db_prefix() . 'customfieldsvalues';
        
        // Get the custom field ID for leads_unidade (campaign)
        $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
        $campaign_field_id = !empty($custom_fields) ? $custom_fields[0]['id'] : null;
        
        // Get all creatives first
        $this->db->select('c.*, m.file_path, m.file_type, m.file_name, m.thumbnail_path');
        $this->db->from($creatives_table . ' c');
        $this->db->join($media_table . ' m', 'c.media_id = m.id', 'left');
        
        // Apply creative filters
        if (!empty($filters['creative_id'])) {
            $this->db->where('c.id', $filters['creative_id']);
        }
        if (!empty($filters['campaign_name'])) {
            $this->db->where('c.campaign_name', $filters['campaign_name']);
        }
        
        $creatives = $this->db->get()->result();
        
        // For each creative, count leads (explicitly linked OR matching campaign name)
        foreach ($creatives as $creative) {
            $total_leads = 0;
            $converted_leads = 0;
            
            // Count explicitly linked leads
            $this->db->select('COUNT(DISTINCT al.lead_id) as count', false);
            $this->db->from($leads_table . ' al');
            $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
            $this->db->where('al.creative_id', $creative->id);
            
            // Apply filters for explicitly linked leads
            if (!empty($filters['date_from'])) {
                $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
            }
            if (!empty($filters['date_to'])) {
                $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
            }
            if (!empty($filters['status'])) {
                $this->db->where('l.status', $filters['status']);
            }
            if (!empty($filters['source'])) {
                $this->db->where('l.source', $filters['source']);
            }
            if (!empty($filters['assigned'])) {
                $this->db->where('l.assigned', $filters['assigned']);
            }
            
            $explicit_result = $this->db->get()->row();
            $explicit_leads = $explicit_result ? $explicit_result->count : 0;
            
            // Count converted explicitly linked leads
            $this->db->select('COUNT(DISTINCT al.lead_id) as count', false);
            $this->db->from($leads_table . ' al');
            $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
            $this->db->where('al.creative_id', $creative->id);
            $this->db->where('l.status', 1);
            
            // Apply filters
            if (!empty($filters['date_from'])) {
                $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
            }
            if (!empty($filters['date_to'])) {
                $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
            }
            if (!empty($filters['source'])) {
                $this->db->where('l.source', $filters['source']);
            }
            if (!empty($filters['assigned'])) {
                $this->db->where('l.assigned', $filters['assigned']);
            }
            
            $explicit_converted_result = $this->db->get()->row();
            $explicit_converted = $explicit_converted_result ? $explicit_converted_result->count : 0;
            
            // Count leads matching campaign name via custom field (excluding already explicitly linked)
            if ($campaign_field_id) {
                // Get lead IDs that are explicitly linked to avoid double counting
                $this->db->select('al.lead_id');
                $this->db->from($leads_table . ' al');
                $this->db->where('al.creative_id', $creative->id);
                $explicit_lead_ids = $this->db->get()->result_array();
                $explicit_lead_ids_array = array_column($explicit_lead_ids, 'lead_id');
                $explicit_lead_ids_list = !empty($explicit_lead_ids_array) ? implode(',', array_map('intval', $explicit_lead_ids_array)) : '0';
                
                // Count leads matching campaign name (excluding explicitly linked)
                $this->db->select('COUNT(DISTINCT cfv.relid) as count', false);
                $this->db->from($custom_fields_values_table . ' cfv');
                $this->db->join($leads_data_table . ' l', 'cfv.relid = l.id', 'left');
                $this->db->where('cfv.fieldid', $campaign_field_id);
                $this->db->where('cfv.fieldto', 'leads');
                $this->db->where('cfv.value', $creative->campaign_name);
                if (!empty($explicit_lead_ids_array)) {
                    $this->db->where('cfv.relid NOT IN (' . $explicit_lead_ids_list . ')', null, false);
                }
                
                // Apply filters
                if (!empty($filters['date_from'])) {
                    $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
                }
                if (!empty($filters['date_to'])) {
                    $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
                }
                if (!empty($filters['status'])) {
                    $this->db->where('l.status', $filters['status']);
                }
                if (!empty($filters['source'])) {
                    $this->db->where('l.source', $filters['source']);
                }
                if (!empty($filters['assigned'])) {
                    $this->db->where('l.assigned', $filters['assigned']);
                }
                
                $campaign_result = $this->db->get()->row();
                $campaign_leads = $campaign_result ? $campaign_result->count : 0;
                
                // Count converted leads matching campaign name
                $this->db->select('COUNT(DISTINCT cfv.relid) as count', false);
                $this->db->from($custom_fields_values_table . ' cfv');
                $this->db->join($leads_data_table . ' l', 'cfv.relid = l.id', 'left');
                $this->db->where('cfv.fieldid', $campaign_field_id);
                $this->db->where('cfv.fieldto', 'leads');
                $this->db->where('cfv.value', $creative->campaign_name);
                $this->db->where('l.status', 1);
                if (!empty($explicit_lead_ids_array)) {
                    $this->db->where('cfv.relid NOT IN (' . $explicit_lead_ids_list . ')', null, false);
                }
                
                // Apply filters
                if (!empty($filters['date_from'])) {
                    $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
                }
                if (!empty($filters['date_to'])) {
                    $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
                }
                if (!empty($filters['source'])) {
                    $this->db->where('l.source', $filters['source']);
                }
                if (!empty($filters['assigned'])) {
                    $this->db->where('l.assigned', $filters['assigned']);
                }
                
                $campaign_converted_result = $this->db->get()->row();
                $campaign_converted = $campaign_converted_result ? $campaign_converted_result->count : 0;
                
                $total_leads = $explicit_leads + $campaign_leads;
                $converted_leads = $explicit_converted + $campaign_converted;
            } else {
                $total_leads = $explicit_leads;
                $converted_leads = $explicit_converted;
            }
            
            $creative->total_leads = (int)$total_leads;
            $creative->converted_leads = (int)$converted_leads;
        }
        
        return $creatives;
    }

    /**
     * Get leads for a specific creative
     */
    public function get_ads_creative_leads($creative_id, $filters = [])
    {
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_data_table = db_prefix() . 'leads';
        $custom_fields_values_table = db_prefix() . 'customfieldsvalues';
        
        // Get creative to find campaign name
        $creative = $this->db->where('id', $creative_id)->get($creatives_table)->row();
        if (!$creative) {
            return [];
        }
        
        // Get the custom field ID for leads_unidade (campaign)
        $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
        $campaign_field_id = !empty($custom_fields) ? $custom_fields[0]['id'] : null;
        
        // Build query to get leads that are either explicitly linked OR match by campaign name
        $this->db->select('DISTINCT ' . $leads_data_table . '.*', false);
        $this->db->from($leads_data_table);
        
        if ($campaign_field_id) {
            // Use UNION to combine explicitly linked leads and leads matching campaign name
            // First get explicitly linked leads
            $this->db->join($leads_table . ' al', "al.lead_id = {$leads_data_table}.id AND al.creative_id = {$creative_id}", 'left');
            
            // Also get leads matching campaign name via custom field
            $this->db->join($custom_fields_values_table . ' cfv', "cfv.relid = {$leads_data_table}.id AND cfv.fieldid = {$campaign_field_id} AND cfv.fieldto = 'leads' AND cfv.value = " . $this->db->escape($creative->campaign_name), 'left');
            
            // Get leads that are either explicitly linked OR match by campaign name
            $this->db->where("(al.creative_id = {$creative_id} OR (cfv.value = " . $this->db->escape($creative->campaign_name) . " AND cfv.relid IS NOT NULL))", null, false);
        } else {
            // Fallback if custom field not found - only get explicitly linked
            $this->db->join($leads_table . ' al', "al.lead_id = {$leads_data_table}.id", 'left');
            $this->db->where('al.creative_id', $creative_id);
        }
        
        // Apply filters
        if (!empty($filters['date_from'])) {
            $this->db->where($leads_data_table . '.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where($leads_data_table . '.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $this->db->where($leads_data_table . '.status', $filters['status']);
        }
        if (!empty($filters['source'])) {
            $this->db->where($leads_data_table . '.source', $filters['source']);
        }
        if (!empty($filters['assigned'])) {
            $this->db->where($leads_data_table . '.assigned', $filters['assigned']);
        }
        
        $this->db->order_by($leads_data_table . '.dateadded', 'DESC');
        
        return $this->db->get()->result();
    }

    /**
     * Get leads by day for a creative (for chart)
     */
    public function get_ads_leads_by_day($creative_id, $filters = [])
    {
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_data_table = db_prefix() . 'leads';
        $custom_fields_values_table = db_prefix() . 'customfieldsvalues';
        
        // Get creative to find campaign name
        $creative = $this->db->where('id', $creative_id)->get($creatives_table)->row();
        if (!$creative) {
            return [];
        }
        
        // Get the custom field ID for leads_unidade (campaign)
        $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
        $campaign_field_id = !empty($custom_fields) ? $custom_fields[0]['id'] : null;
        
        // Use UNION to get leads from both sources
        $query1 = $this->db->select('DATE(' . $leads_data_table . '.dateadded) as date, COUNT(DISTINCT ' . $leads_data_table . '.id) as count', false)
            ->from($leads_table)
            ->join($leads_data_table, $leads_table . '.lead_id = ' . $leads_data_table . '.id')
            ->where($leads_table . '.creative_id', $creative_id);
        
        // Apply filters to query 1
        if (!empty($filters['date_from'])) {
            $query1->where($leads_data_table . '.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $query1->where($leads_data_table . '.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $query1->where($leads_data_table . '.status', $filters['status']);
        }
        if (!empty($filters['source'])) {
            $query1->where($leads_data_table . '.source', $filters['source']);
        }
        if (!empty($filters['assigned'])) {
            $query1->where($leads_data_table . '.assigned', $filters['assigned']);
        }
        $query1->group_by('DATE(' . $leads_data_table . '.dateadded)', false);
        
        $sql1 = $query1->get_compiled_select();
        
        if ($campaign_field_id) {
            // Query 2: Leads matching campaign name (excluding explicitly linked)
            $this->db->select('al.lead_id');
            $this->db->from($leads_table . ' al');
            $this->db->where('al.creative_id', $creative_id);
            $explicit_lead_ids = $this->db->get()->result_array();
            $explicit_lead_ids_array = array_column($explicit_lead_ids, 'lead_id');
            
            $query2 = $this->db->select('DATE(' . $leads_data_table . '.dateadded) as date, COUNT(DISTINCT ' . $leads_data_table . '.id) as count', false)
                ->from($custom_fields_values_table)
                ->join($leads_data_table, $custom_fields_values_table . '.relid = ' . $leads_data_table . '.id')
                ->where($custom_fields_values_table . '.fieldid', $campaign_field_id)
                ->where($custom_fields_values_table . '.fieldto', 'leads')
                ->where($custom_fields_values_table . '.value', $creative->campaign_name);
            
            if (!empty($explicit_lead_ids_array)) {
                $query2->where($custom_fields_values_table . '.relid NOT IN (' . implode(',', array_map('intval', $explicit_lead_ids_array)) . ')', null, false);
            }
            
            // Apply filters to query 2
            if (!empty($filters['date_from'])) {
                $query2->where($leads_data_table . '.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
            }
            if (!empty($filters['date_to'])) {
                $query2->where($leads_data_table . '.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
            }
            if (!empty($filters['status'])) {
                $query2->where($leads_data_table . '.status', $filters['status']);
            }
            if (!empty($filters['source'])) {
                $query2->where($leads_data_table . '.source', $filters['source']);
            }
            if (!empty($filters['assigned'])) {
                $query2->where($leads_data_table . '.assigned', $filters['assigned']);
            }
            $query2->group_by('DATE(' . $leads_data_table . '.dateadded)', false);
            
            $sql2 = $query2->get_compiled_select();
            
            // Combine with UNION and aggregate
            $sql = "SELECT date, SUM(count) as count FROM (($sql1) UNION ALL ($sql2)) combined GROUP BY date ORDER BY date ASC";
        } else {
            $sql = $sql1 . " ORDER BY date ASC";
        }
        
        return $this->db->query($sql)->result();
    }

    /**
     * Get leads by status for a creative (for chart)
     */
    public function get_ads_leads_by_status($creative_id, $filters = [])
    {
        // Use the get_ads_creative_leads function and aggregate by status
        $leads = $this->get_ads_creative_leads($creative_id, $filters);
        
        // Get status names
        $status_table = db_prefix() . 'leads_status';
        $statuses = $this->db->get($status_table)->result();
        $status_map = [];
        foreach ($statuses as $status) {
            $status_map[$status->id] = $status->name;
        }
        
        // Count leads by status
        $status_counts = [];
        foreach ($leads as $lead) {
            $status_id = $lead->status;
            $status_name = isset($status_map[$status_id]) ? $status_map[$status_id] : 'Unknown';
            
            if (!isset($status_counts[$status_id])) {
                $status_counts[$status_id] = [
                    'status_name' => $status_name,
                    'count' => 0
                ];
            }
            $status_counts[$status_id]['count']++;
        }
        
        // Convert to array and sort by count
        $result = array_values($status_counts);
        usort($result, function($a, $b) {
            return $b['count'] - $a['count'];
        });
        
        // Convert to objects
        $final_result = [];
        foreach ($result as $item) {
            $final_result[] = (object)$item;
        }
        
        return $final_result;
    }

    /**
     * Add ads investment
     */
    public function add_ads_investment($data)
    {
        // Validate required fields
        if (empty($data['budget_type'])) {
            log_message('error', 'add_ads_investment: budget_type is required');
            return false;
        }
        
        if ($data['budget_type'] == 'creative' && empty($data['creative_id'])) {
            log_message('error', 'add_ads_investment: creative_id is required for creative budget type');
            return false;
        }
        
        if ($data['budget_type'] == 'ad_set' && empty($data['ad_set_id'])) {
            log_message('error', 'add_ads_investment: ad_set_id is required for ad_set budget type');
            return false;
        }
        
        if (empty($data['start_date'])) {
            log_message('error', 'add_ads_investment: start_date is required');
            return false;
        }
        
        $this->db->insert(db_prefix() . 'contactcenter_ads_investments', $data);
        
        if ($this->db->error()['code'] != 0) {
            log_message('error', 'add_ads_investment database error: ' . $this->db->error()['message']);
            return false;
        }
        
        return $this->db->insert_id();
    }

    /**
     * Update ads investment
     */
    public function update_ads_investment($id, $data)
    {
        if (empty($id)) {
            log_message('error', 'update_ads_investment: id is required');
            return false;
        }
        
        $this->db->where('id', $id);
        $this->db->update(db_prefix() . 'contactcenter_ads_investments', $data);
        
        if ($this->db->error()['code'] != 0) {
            log_message('error', 'update_ads_investment database error: ' . $this->db->error()['message']);
            return false;
        }
        
        return $this->db->affected_rows() > 0;
    }

