    /**
     * Get total invested for a creative
     * Handles both creative-level and ad set-level budgets
     * For ad set budgets, distributes proportionally based on leads generated
     */
    public function get_ads_total_invested($creative_id, $filters = [])
    {
        $investments_table = db_prefix() . 'contactcenter_ads_investments';
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_main_table = db_prefix() . 'leads';
        
        // First, check for creative-level budgets
        $this->db->select('*');
        $this->db->from($investments_table);
        $this->db->where('budget_type', 'creative');
        $this->db->where('creative_id', $creative_id);
        $this->db->where('is_active', 1);
        
        $creative_investments = $this->db->get()->result();
        
        $total_invested = 0;
        
        // Parse dates - filters should already be in YYYY-MM-DD format from controller
        $date_from = null;
        $date_to = time();
        
        if (!empty($filters['date_from'])) {
            // If already in YYYY-MM-DD format, strtotime will work fine
            $date_from = strtotime($filters['date_from'] . ' 00:00:00');
            if ($date_from === false) {
                $date_from = null;
            }
        }
        
        if (!empty($filters['date_to'])) {
            // Add end of day time to include the full day
            $date_to = strtotime($filters['date_to'] . ' 23:59:59');
            if ($date_to === false) {
                $date_to = time();
            }
        }
        
        // Calculate creative-level budget
        foreach ($creative_investments as $investment) {
            $start_date = strtotime($investment->start_date);
            $end_date = $investment->end_date ? strtotime($investment->end_date . ' 23:59:59') : time();
            
            // Adjust date range based on filters
            $calc_start = $date_from ? max($start_date, $date_from) : $start_date;
            $calc_end = min($end_date, $date_to);
            
            if ($calc_end < $calc_start) {
                continue; // Investment period doesn't overlap with filter period
            }
            
            // Calculate number of days
            $days = ceil(($calc_end - $calc_start) / 86400) + 1;
            
            // Add investment for this period
            $total_invested += $investment->daily_investment * $days;
        }
        
        // Now check for ad set-level budgets
        // Get the creative's ad set
        $this->db->select('ad_set_id');
        $this->db->from($creatives_table);
        $this->db->where('id', $creative_id);
        $creative = $this->db->get()->row();
        
        if ($creative && $creative->ad_set_id) {
            // Get ad set investments
            $this->db->select('*');
            $this->db->from($investments_table);
            $this->db->where('budget_type', 'ad_set');
            $this->db->where('ad_set_id', $creative->ad_set_id);
            $this->db->where('is_active', 1);
            
            $ad_set_investments = $this->db->get()->result();
            
            foreach ($ad_set_investments as $investment) {
                $start_date = strtotime($investment->start_date);
                $end_date = $investment->end_date ? strtotime($investment->end_date . ' 23:59:59') : time();
                
                // Adjust date range based on filters
                $calc_start = $date_from ? max($start_date, $date_from) : $start_date;
                $calc_end = min($end_date, $date_to);
                
                if ($calc_end < $calc_start) {
                    continue; // Investment period doesn't overlap with filter period
                }
                
                // Calculate number of days in this period
                $days = ceil(($calc_end - $calc_start) / 86400) + 1;
                
                // Get all creatives in this ad set
                $this->db->select('id');
                $this->db->from($creatives_table);
                $this->db->where('ad_set_id', $creative->ad_set_id);
                $ad_set_creatives = $this->db->get()->result();
                
                if (empty($ad_set_creatives)) {
                    continue;
                }
                
                $creative_ids = [];
                foreach ($ad_set_creatives as $c) {
                    $creative_ids[] = $c->id;
                }
                
                // Count leads for each creative in the date range
                $creative_lead_counts = [];
                $total_leads_in_ad_set = 0;
                
                foreach ($creative_ids as $c_id) {
                    // Count leads for this creative in the date range
                    $this->db->select('COUNT(*) as lead_count', false);
                    $this->db->from($leads_table . ' al');
                    $this->db->join($leads_main_table . ' l', 'al.lead_id = l.id', 'left');
                    $this->db->where('al.creative_id', $c_id);
                    
                    // Apply date filter if provided
                    if ($date_from) {
                        $this->db->where('DATE(l.dateadded) >=', date('Y-m-d', $calc_start));
                    }
                    if ($date_to) {
                        $this->db->where('DATE(l.dateadded) <=', date('Y-m-d', $calc_end));
                    }
                    
                    // Apply other filters if provided
                    if (!empty($filters['status'])) {
                        $this->db->where('l.status', $filters['status']);
                    }
                    if (!empty($filters['source'])) {
                        $this->db->where('l.source', $filters['source']);
                    }
                    if (!empty($filters['assigned'])) {
                        $this->db->where('l.assigned', $filters['assigned']);
                    }
                    
                    $result = $this->db->get()->row();
                    $lead_count = (int)($result->lead_count ?? 0);
                    
                    $creative_lead_counts[$c_id] = $lead_count;
                    $total_leads_in_ad_set += $lead_count;
                }
                
                // Calculate proportional budget allocation for this creative
                if ($total_leads_in_ad_set > 0) {
                    // Distribute budget proportionally based on leads
                    $creative_lead_count = $creative_lead_counts[$creative_id] ?? 0;
                    $proportional_share = $creative_lead_count / $total_leads_in_ad_set;
                    $allocated_daily_budget = $investment->daily_investment * $proportional_share;
                    $allocated_budget = $allocated_daily_budget * $days;
                    $total_invested += $allocated_budget;
                }
                // If total_leads_in_ad_set == 0, no budget is allocated (no leads, no cost)
            }
        }
        
        return round($total_invested, 2);
    }

    /**
     * Calculate CPL (Cost Per Lead) for a creative
     * 
     * @param int $creative_id
     * @param array $filters
     * @param int|null $total_leads_count Optional: Use pre-calculated lead count to ensure consistency with displayed count
     * @return float|null
     */
    public function calculate_ads_cpl($creative_id, $filters = [], $total_leads_count = null)
    {
        $total_invested = $this->get_ads_total_invested($creative_id, $filters);
        
        // Use provided count if available (for consistency with displayed count), otherwise count leads
        if ($total_leads_count !== null) {
            $total_leads = (int)$total_leads_count;
        } else {
        $leads = $this->get_ads_creative_leads($creative_id, $filters);
        $total_leads = count($leads);
        }
        
        if ($total_leads == 0) {
            return null; // No leads to calculate CPL
        }
        
        if ($total_invested <= 0) {
            return null; // No investment to calculate CPL
        }
        
        return round($total_invested / $total_leads, 2);
    }

    /**
     * Link lead to creative
     */
    public function link_lead_to_creative($creative_id, $lead_id)
    {
        // Check if link already exists
        $this->db->where('creative_id', $creative_id);
        $this->db->where('lead_id', $lead_id);
        $existing = $this->db->get(db_prefix() . 'contactcenter_ads_leads')->row();
        
        if ($existing) {
            return true; // Already linked
        }
        
        $data = [
            'creative_id' => $creative_id,
            'lead_id' => $lead_id
        ];
        
        $this->db->insert(db_prefix() . 'contactcenter_ads_leads', $data);
        return $this->db->insert_id();
    }

