        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_data_table = db_prefix() . 'leads';
        $custom_fields_values_table = db_prefix() . 'customfieldsvalues';
        
        // Get the custom field ID for leads_unidade (campaign)
        $custom_fields = get_custom_fields('leads', ['slug' => 'leads_unidade', 'active' => 1]);
        $campaign_field_id = !empty($custom_fields) ? $custom_fields[0]['id'] : null;
        
        // Get all ad sets
        $this->db->select('*');
        $this->db->from($sets_table);
        $this->db->order_by('name', 'ASC');
        
        $ad_sets = $this->db->get()->result();
        
        // For each ad set, count leads from all creatives in the set
        foreach ($ad_sets as $ad_set) {
            $total_leads = 0;
            $converted_leads = 0;
            
            // Get all creatives in this ad set
            $this->db->select('id, campaign_name');
            $this->db->from($creatives_table);
            $this->db->where('ad_set_id', $ad_set->id);
            $creatives_in_set = $this->db->get()->result();
            
            if (empty($creatives_in_set)) {
                $ad_set->total_leads = 0;
                $ad_set->converted_leads = 0;
                $ad_set->creatives_count = 0;
                continue;
            }
            
            $ad_set->creatives_count = count($creatives_in_set);
            $creative_ids = array_column($creatives_in_set, 'id');
            $campaign_names = array_unique(array_column($creatives_in_set, 'campaign_name'));
            
            // Count leads from explicitly linked creatives
            $this->db->select('COUNT(DISTINCT al.lead_id) as count', false);
            $this->db->from($leads_table . ' al');
            $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
            $this->db->where_in('al.creative_id', $creative_ids);
            
            // Apply filters
            if (!empty($filters['date_from'])) {
                $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
            }
            if (!empty($filters['date_to'])) {
                $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
            }
            if (!empty($filters['status'])) {
                $this->db->where('l.status', $filters['status']);
            }
            if (!empty($filters['source'])) {
                $this->db->where('l.source', $filters['source']);
            }
            if (!empty($filters['assigned'])) {
                $this->db->where('l.assigned', $filters['assigned']);
            }
            
            $explicit_result = $this->db->get()->row();
            $explicit_leads = $explicit_result ? $explicit_result->count : 0;
            
            // Count converted explicitly linked leads
            $this->db->select('COUNT(DISTINCT al.lead_id) as count', false);
            $this->db->from($leads_table . ' al');
            $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
            $this->db->where_in('al.creative_id', $creative_ids);
            $this->db->where('l.status', 1);
            
            // Apply filters
            if (!empty($filters['date_from'])) {
                $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
            }
            if (!empty($filters['date_to'])) {
                $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
            }
            if (!empty($filters['source'])) {
                $this->db->where('l.source', $filters['source']);
            }
            if (!empty($filters['assigned'])) {
                $this->db->where('l.assigned', $filters['assigned']);
            }
            
            $explicit_converted_result = $this->db->get()->row();
            $explicit_converted = $explicit_converted_result ? $explicit_converted_result->count : 0;
            
            // Count leads matching campaign names via custom field (excluding already explicitly linked)
            if ($campaign_field_id && !empty($campaign_names)) {
                // Get lead IDs that are explicitly linked to avoid double counting
                $this->db->select('al.lead_id');
                $this->db->from($leads_table . ' al');
                $this->db->where_in('al.creative_id', $creative_ids);
                $explicit_lead_ids = $this->db->get()->result_array();
                $explicit_lead_ids_array = array_column($explicit_lead_ids, 'lead_id');
                $explicit_lead_ids_list = !empty($explicit_lead_ids_array) ? implode(',', array_map('intval', $explicit_lead_ids_array)) : '0';
                
                // Count leads matching any campaign name in the set (excluding explicitly linked)
                $this->db->select('COUNT(DISTINCT cfv.relid) as count', false);
                $this->db->from($custom_fields_values_table . ' cfv');
                $this->db->join($leads_data_table . ' l', 'cfv.relid = l.id', 'left');
                $this->db->where('cfv.fieldid', $campaign_field_id);
                $this->db->where('cfv.fieldto', 'leads');
                $this->db->where_in('cfv.value', $campaign_names);
                if (!empty($explicit_lead_ids_array)) {
                    $this->db->where('cfv.relid NOT IN (' . $explicit_lead_ids_list . ')', null, false);
                }
                
                // Apply filters
                if (!empty($filters['date_from'])) {
                    $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
                }
                if (!empty($filters['date_to'])) {
                    $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
                }
                if (!empty($filters['status'])) {
                    $this->db->where('l.status', $filters['status']);
                }
                if (!empty($filters['source'])) {
                    $this->db->where('l.source', $filters['source']);
                }
                if (!empty($filters['assigned'])) {
                    $this->db->where('l.assigned', $filters['assigned']);
                }
                
                $campaign_result = $this->db->get()->row();
                $campaign_leads = $campaign_result ? $campaign_result->count : 0;
                
                // Count converted leads matching campaign names
                $this->db->select('COUNT(DISTINCT cfv.relid) as count', false);
                $this->db->from($custom_fields_values_table . ' cfv');
                $this->db->join($leads_data_table . ' l', 'cfv.relid = l.id', 'left');
                $this->db->where('cfv.fieldid', $campaign_field_id);
                $this->db->where('cfv.fieldto', 'leads');
                $this->db->where_in('cfv.value', $campaign_names);
                $this->db->where('l.status', 1);
                if (!empty($explicit_lead_ids_array)) {
                    $this->db->where('cfv.relid NOT IN (' . $explicit_lead_ids_list . ')', null, false);
                }
                
                // Apply filters
                if (!empty($filters['date_from'])) {
                    $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
                }
                if (!empty($filters['date_to'])) {
                    $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
                }
                if (!empty($filters['source'])) {
                    $this->db->where('l.source', $filters['source']);
                }
                if (!empty($filters['assigned'])) {
                    $this->db->where('l.assigned', $filters['assigned']);
                }
                
                $campaign_converted_result = $this->db->get()->row();
                $campaign_converted = $campaign_converted_result ? $campaign_converted_result->count : 0;
                
                $total_leads = $explicit_leads + $campaign_leads;
                $converted_leads = $explicit_converted + $campaign_converted;
            } else {
                $total_leads = $explicit_leads;
                $converted_leads = $explicit_converted;
            }
            
            $ad_set->total_leads = $total_leads;
            $ad_set->converted_leads = $converted_leads;
        }
        
        return $ad_sets;
    }

    /**
     * Get total invested for an ad set
     */
    public function get_ads_set_total_invested($ad_set_id, $filters = [])
    {
        $investments_table = db_prefix() . 'contactcenter_ads_investments';
        
        // Get ad set investments
        $this->db->select('*');
        $this->db->from($investments_table);
        $this->db->where('budget_type', 'ad_set');
        $this->db->where('ad_set_id', $ad_set_id);
        $this->db->where('is_active', 1);
        
        $ad_set_investments = $this->db->get()->result();
        
        $total_invested = 0;
        
        // Parse dates - filters should already be in YYYY-MM-DD format from controller
        $date_from = null;
        $date_to = time();
        
        if (!empty($filters['date_from'])) {
            $date_from = strtotime($filters['date_from'] . ' 00:00:00');
            if ($date_from === false) {
                $date_from = null;
            }
        }
        
        if (!empty($filters['date_to'])) {
            $date_to = strtotime($filters['date_to'] . ' 23:59:59');
            if ($date_to === false) {
                $date_to = time();
            }
        }
        
        foreach ($ad_set_investments as $investment) {
            $start_date = strtotime($investment->start_date);
            $end_date = $investment->end_date ? strtotime($investment->end_date . ' 23:59:59') : time();
            
            // Adjust date range based on filters
            $calc_start = $date_from ? max($start_date, $date_from) : $start_date;
            $calc_end = min($end_date, $date_to);
            
            if ($calc_end < $calc_start) {
                continue; // Investment period doesn't overlap with filter period
            }
            
            // Calculate number of days
            $days = ceil(($calc_end - $calc_start) / 86400) + 1;
            
            // Add investment for this period
            $total_invested += $investment->daily_investment * $days;
        }
        
        return round($total_invested, 2);
    }

    /**
     * Calculate CPL (Cost Per Lead) for an ad set
     */
    public function calculate_ads_set_cpl($ad_set_id, $filters = [], $total_leads_count = null)
    {
        $total_invested = $this->get_ads_set_total_invested($ad_set_id, $filters);
        
        // Use provided count if available (for consistency with displayed count), otherwise count leads
        if ($total_leads_count !== null) {
            $total_leads = (int)$total_leads_count;
        } else {
            // Get ad set analytics to count leads
            $ad_sets = $this->get_ads_analytics_sets($filters);
            $total_leads = 0;
            foreach ($ad_sets as $set) {
                if ($set->id == $ad_set_id) {
                    $total_leads = $set->total_leads ?? 0;
                    break;
                }
            }
        }
        
        if ($total_leads == 0) {
            return null; // No leads to calculate CPL
        }
        
        if ($total_invested <= 0) {
            return null; // No investment to calculate CPL
        }
        
        return round($total_invested / $total_leads, 2);
    }


    public function get_ads_analytics_summary($filters = [])
    {
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_data_table = db_prefix() . 'leads';
        
        $this->db->select('COUNT(DISTINCT al.lead_id) as total_leads', false);
        $this->db->from($leads_table . ' al');
        $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
        
        if (!empty($filters['date_from'])) {
            $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $this->db->where('l.status', $filters['status']);
        }
        if (!empty($filters['assigned'])) {
            $this->db->where('l.assigned', $filters['assigned']);
        }
        
        $total_leads_result = $this->db->get()->row();
        $total_leads = $total_leads_result ? (int)$total_leads_result->total_leads : 0;
        
        $this->db->select('COUNT(DISTINCT al.lead_id) as converted_leads', false);
        $this->db->from($leads_table . ' al');
        $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
        $this->db->where('l.status', 1);
        
        if (!empty($filters['date_from'])) {
            $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['assigned'])) {
            $this->db->where('l.assigned', $filters['assigned']);
        }
        
        $converted_result = $this->db->get()->row();
        $converted_leads = $converted_result ? (int)$converted_result->converted_leads : 0;
        
        $creatives = $this->get_ads_creatives();
        $total_invested = 0;
        foreach ($creatives as $creative) {
            $total_invested += $this->get_ads_total_invested($creative->id, $filters);
        }
        
        $this->db->select('COUNT(*) as creatives_count', false);
        $this->db->from($creatives_table);
        $this->db->where('is_active', 1);
        $creatives_result = $this->db->get()->row();
        $creatives_count = $creatives_result ? (int)$creatives_result->creatives_count : 0;
        
        $conversion_rate = $total_leads > 0 ? ($converted_leads / $total_leads) * 100 : 0;
        $avg_cpl = $total_leads > 0 && $total_invested > 0 ? $total_invested / $total_leads : null;
        $roi = $total_invested > 0 ? (($converted_leads * 100) / $total_invested) : 0;
        
        return [
            'total_leads' => $total_leads,
            'converted_leads' => $converted_leads,
            'conversion_rate' => round($conversion_rate, 2),
            'total_invested' => round($total_invested, 2),
            'creatives_count' => $creatives_count,
            'avg_cpl' => $avg_cpl !== null ? round($avg_cpl, 2) : null,
            'roi' => round($roi, 2)
        ];
    }

