    public function get_ads_performance_by_campaign($filters = [])
    {
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $leads_table = db_prefix() . 'contactcenter_ads_leads';
        $leads_data_table = db_prefix() . 'leads';
        $investments_table = db_prefix() . 'contactcenter_ads_investments';
        
        $this->db->select('c.campaign_name, 
            COUNT(DISTINCT al.lead_id) as total_leads, 
            COUNT(DISTINCT CASE WHEN l.status = 1 THEN al.lead_id END) as converted_leads', false);
        $this->db->from($creatives_table . ' c');
        $this->db->join($leads_table . ' al', 'c.id = al.creative_id', 'left');
        $this->db->join($leads_data_table . ' l', 'al.lead_id = l.id', 'left');
        $this->db->where('c.campaign_name IS NOT NULL');
        $this->db->where('c.campaign_name !=', '');
        $this->db->group_by('c.campaign_name');
        $this->db->order_by('total_leads', 'DESC');
        $this->db->limit(10);
        
        if (!empty($filters['date_from'])) {
            $this->db->where('l.dateadded >=', date('Y-m-d 00:00:00', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where('l.dateadded <=', date('Y-m-d 23:59:59', strtotime($filters['date_to'])));
        }
        if (!empty($filters['status'])) {
            $this->db->where('l.status', $filters['status']);
        }
        if (!empty($filters['assigned'])) {
            $this->db->where('l.assigned', $filters['assigned']);
        }
        
        $results = $this->db->get()->result_array();
        
        // Calculate additional metrics for each campaign
        foreach ($results as &$campaign) {
            $campaign_name = $campaign['campaign_name'];
            $total_leads = (int)$campaign['total_leads'];
            $converted_leads = (int)$campaign['converted_leads'];
            
            // Calculate conversion rate
            $campaign['conversion_rate'] = $total_leads > 0 ? ($converted_leads / $total_leads) * 100 : 0;
            
            // Get total invested for this campaign
            $campaign_filters = array_merge($filters, ['campaign_name' => $campaign_name]);
            $campaign['total_invested'] = $this->get_ads_campaign_total_invested($campaign_name, $filters);
            
            // Calculate CPL
            $campaign['avg_cpl'] = null;
            if ($campaign['total_invested'] > 0 && $total_leads > 0) {
                $campaign['avg_cpl'] = $campaign['total_invested'] / $total_leads;
            }
            
            // Calculate ROI (assuming each converted lead has value of 100)
            $campaign['roi'] = 0;
            if ($campaign['total_invested'] > 0 && $converted_leads > 0) {
                $revenue = $converted_leads * 100; // Assuming 100 per conversion
                $campaign['roi'] = (($revenue - $campaign['total_invested']) / $campaign['total_invested']) * 100;
            }
        }
        
        return $results;
    }
    
    /**
     * Get total invested for a specific campaign
     */
    private function get_ads_campaign_total_invested($campaign_name, $filters = [])
    {
        $creatives_table = db_prefix() . 'contactcenter_ads_creatives';
        $investments_table = db_prefix() . 'contactcenter_ads_investments';
        
        $this->db->select('COALESCE(SUM(i.daily_investment), 0) as total_invested', false);
        $this->db->from($creatives_table . ' c');
        $this->db->join($investments_table . ' i', 'c.id = i.creative_id', 'left');
        $this->db->where('c.campaign_name', $campaign_name);
        
        if (!empty($filters['date_from'])) {
            $this->db->where('i.date >=', date('Y-m-d', strtotime($filters['date_from'])));
        }
        if (!empty($filters['date_to'])) {
            $this->db->where('i.date <=', date('Y-m-d', strtotime($filters['date_to'])));
        }
        
        $result = $this->db->get()->row();
        return $result ? (float)$result->total_invested : 0;
    }

    public function get_ads_cpl_distribution($filters = [])
    {
        $creatives = $this->get_ads_analytics_creatives($filters);
        $distribution = [];
        
        foreach ($creatives as $creative) {
            $cpl = $this->calculate_ads_cpl($creative->id, $filters, $creative->total_leads ?? 0);
            if ($cpl !== null) {
                $distribution[] = [
                    'creative_name' => $creative->name,
                    'cpl' => $cpl,
                    'leads' => $creative->total_leads ?? 0
                ];
            }
        }
        
        return $distribution;
    }

    public function get_ads_top_performers($filters = [], $limit = 5)
    {
        $creatives = $this->get_ads_analytics_creatives($filters);
        $performers = [];
        
        foreach ($creatives as $creative) {
            $cpl = $this->calculate_ads_cpl($creative->id, $filters, $creative->total_leads ?? 0);
            $conversion_rate = ($creative->total_leads ?? 0) > 0 
                ? (($creative->converted_leads ?? 0) / ($creative->total_leads ?? 0)) * 100 
                : 0;
            
            $performers[] = [
                'creative' => $creative,
                'cpl' => $cpl,
                'conversion_rate' => $conversion_rate,
                'score' => $this->_calculate_performance_score($creative, $cpl, $conversion_rate)
            ];
        }
        
        usort($performers, function($a, $b) {
            return $b['score'] <=> $a['score'];
        });
        
        return [
            'top' => array_slice($performers, 0, $limit),
            'worst' => array_slice(array_reverse($performers), 0, $limit)
        ];
    }

    private function _calculate_performance_score($creative, $cpl, $conversion_rate)
    {
        $score = 0;
        $leads = $creative->total_leads ?? 0;
        if ($leads > 0) {
            $score += min(40, $leads / 10);
        }
        $score += min(30, ($conversion_rate / 10) * 3);
        if ($cpl !== null && $cpl > 0) {
            $cpl_score = max(0, 30 - ($cpl / 5));
            $score += min(30, $cpl_score);
        }
        return round(min(100, $score));
    }

    public function get_ads_comparison_data($creative_ids, $filters = [])
    {
        $comparison = [];
        
        foreach ($creative_ids as $creative_id) {
            $creative = $this->get_ads_creative($creative_id);
            if (!$creative) {
                continue;
            }
            
            $analytics = $this->get_ads_analytics_creatives(array_merge($filters, ['creative_id' => $creative_id]));
            if (!empty($analytics)) {
                $creative_data = $analytics[0];
                $cpl = $this->calculate_ads_cpl($creative_id, $filters, $creative_data->total_leads ?? 0);
                $total_invested = $this->get_ads_total_invested($creative_id, $filters);
                $conversion_rate = ($creative_data->total_leads ?? 0) > 0 
                    ? (($creative_data->converted_leads ?? 0) / ($creative_data->total_leads ?? 0)) * 100 
                    : 0;
                
                $comparison[] = [
                    'id' => $creative_id,
                    'name' => $creative->name,
                    'campaign_name' => $creative->campaign_name,
                    'leads' => $creative_data->total_leads ?? 0,
                    'converted' => $creative_data->converted_leads ?? 0,
                    'conversion_rate' => round($conversion_rate, 2),
                    'cpl' => $cpl,
                    'total_invested' => round($total_invested, 2),
                    'roi' => $total_invested > 0 ? round((($creative_data->converted_leads ?? 0) * 100) / $total_invested, 2) : 0
                ];
            }
        }
        
        return $comparison;
    }

    public function get_ads_data_for_ai_analysis($filters = [])
    {
        $summary = $this->get_ads_analytics_summary($filters);
        $performers = $this->get_ads_top_performers($filters, 5);
        $campaign_performance = $this->get_ads_performance_by_campaign($filters);
        $leads_trend = $this->get_ads_leads_trend($filters);
        
        return [
            'total_leads' => $summary['total_leads'],
            'converted_leads' => $summary['converted_leads'],
            'conversion_rate' => $summary['conversion_rate'],
            'total_invested' => $summary['total_invested'],
            'avg_cpl' => $summary['avg_cpl'],
            'roi' => $summary['roi'],
            'creatives_count' => $summary['creatives_count'],
            'top_creatives' => array_map(function($item) {
                return [
                    'name' => $item['creative']->name,
                    'leads' => $item['creative']->total_leads ?? 0,
                    'converted' => $item['creative']->converted_leads ?? 0,
                    'cpl' => $item['cpl'],
                    'conversion_rate' => $item['conversion_rate']
                ];
            }, $performers['top']),
            'worst_creatives' => array_map(function($item) {
                return [
                    'name' => $item['creative']->name,
                    'leads' => $item['creative']->total_leads ?? 0,
                    'converted' => $item['creative']->converted_leads ?? 0,
                    'cpl' => $item['cpl'],
                    'conversion_rate' => $item['conversion_rate']
                ];
            }, $performers['worst']),
            'campaign_performance' => array_map(function($item) {
                return [
                    'campaign_name' => $item->campaign_name,
                    'leads' => (int)$item->leads_count,
                    'converted' => (int)$item->converted_count
                ];
            }, $campaign_performance),
            'trends' => array_map(function($item) {
                return [
                    'date' => $item->date,
                    'leads' => (int)$item->leads_count
                ];
            }, $leads_trend)
        ];
    }

    public function cache_ai_insights($filters, $insights)
    {
        $cache_table = db_prefix() . 'contactcenter_ads_ai_insights_cache';
        
        if (!$this->db->table_exists($cache_table)) {
            $this->db->query("CREATE TABLE IF NOT EXISTS `{$cache_table}` (
                `id` INT(11) NOT NULL AUTO_INCREMENT,
                `filters_hash` VARCHAR(64) NOT NULL,
                `insights` LONGTEXT NOT NULL,
                `created_at` DATETIME NOT NULL,
                `expires_at` DATETIME NOT NULL,
                PRIMARY KEY (`id`),
                UNIQUE KEY `filters_hash` (`filters_hash`),
                KEY `expires_at` (`expires_at`)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;");
        }
        
        // Normalize filters for consistent hashing (only include relevant filter keys)
        $normalized_filters = [
            'date_from' => isset($filters['date_from']) ? $filters['date_from'] : '',
            'date_to' => isset($filters['date_to']) ? $filters['date_to'] : '',
            'status' => isset($filters['status']) ? $filters['status'] : '',
            'assigned' => isset($filters['assigned']) ? $filters['assigned'] : ''
        ];
        
        $filters_hash = md5(json_encode($normalized_filters));
        // Set expiration to 1 year from now (effectively permanent, but allows cleanup of old data)
        $expires_at = date('Y-m-d H:i:s', strtotime('+1 year'));
        
        log_message('debug', 'Saving insights to database with filters: ' . json_encode($normalized_filters));
        log_message('debug', 'Hash: ' . $filters_hash);
        
        // Only clean up entries older than 1 year (very old data)
        $this->db->where('expires_at <', date('Y-m-d H:i:s', strtotime('-1 year')));
        $deleted = $this->db->delete($cache_table);
        if ($deleted > 0) {
            log_message('debug', 'Cleaned up ' . $deleted . ' old cache entries');
        }
        
        $data = [
            'filters_hash' => $filters_hash,
            'insights' => json_encode($insights, JSON_UNESCAPED_UNICODE),
            'created_at' => date('Y-m-d H:i:s'),
            'expires_at' => $expires_at
        ];
        
        $this->db->replace($cache_table, $data);
        log_message('debug', 'Insights saved to database successfully. Created at: ' . $data['created_at']);
    }

    public function get_cached_ai_insights($filters)
    {
        $cache_table = db_prefix() . 'contactcenter_ads_ai_insights_cache';
        
        if (!$this->db->table_exists($cache_table)) {
            log_message('debug', 'Cache table does not exist');
            return null;
        }
        
        // Normalize filters for consistent hashing (same as when saving)
        $normalized_filters = [
            'date_from' => isset($filters['date_from']) ? $filters['date_from'] : '',
            'date_to' => isset($filters['date_to']) ? $filters['date_to'] : '',
            'status' => isset($filters['status']) ? $filters['status'] : '',
            'assigned' => isset($filters['assigned']) ? $filters['assigned'] : ''
        ];
        
        $filters_hash = md5(json_encode($normalized_filters));
        
        log_message('debug', 'Looking up cache with filters: ' . json_encode($normalized_filters));
        log_message('debug', 'Cache hash: ' . $filters_hash);
        
        $this->db->where('filters_hash', $filters_hash);
        // Check if entry exists and hasn't expired (expires_at > now or NULL for permanent)
        $this->db->group_start();
        $this->db->where('expires_at >', date('Y-m-d H:i:s'));
        $this->db->or_where('expires_at IS NULL', null, false);
        $this->db->group_end();
        $cache = $this->db->get($cache_table)->row();
        
        if ($cache) {
            log_message('debug', 'Saved insights found in database. Created: ' . $cache->created_at . ', Expires: ' . ($cache->expires_at ?: 'Never'));
            $decoded = json_decode($cache->insights, true);
            if ($decoded) {
                log_message('debug', 'Insights decoded successfully. Keys: ' . implode(', ', array_keys($decoded ?: [])));
                return $decoded;
            } else {
                log_message('error', 'Failed to decode saved insights. JSON error: ' . json_last_error_msg());
            }
        } else {
            log_message('debug', 'No saved insights found in database for this filter combination');
        }
        
        return null;
    }

    /**
     * Delete cached AI insights for given filters
     */
    public function delete_cached_ai_insights($filters)
    {
        $cache_table = db_prefix() . 'contactcenter_ads_ai_insights_cache';
        
        if (!$this->db->table_exists($cache_table)) {
            return false;
        }
        
        // Normalize filters for consistent hashing (same as when saving)
        $normalized_filters = [
            'date_from' => isset($filters['date_from']) ? $filters['date_from'] : '',
            'date_to' => isset($filters['date_to']) ? $filters['date_to'] : '',
            'status' => isset($filters['status']) ? $filters['status'] : '',
            'assigned' => isset($filters['assigned']) ? $filters['assigned'] : ''
        ];
        
        $filters_hash = md5(json_encode($normalized_filters));
        
        $this->db->where('filters_hash', $filters_hash);
        $deleted = $this->db->delete($cache_table);
        
        log_message('debug', 'Deleted cached insights for hash: ' . $filters_hash . ' (rows deleted: ' . $deleted . ')');
        
        return $deleted > 0;
    }

    /**
     * Search leads using Google Places API (Text Search)
     * Uses real Google Places data similar to AXIOM Studio's Google Custom Search approach
     * 
     * @param array $params Search parameters (location, category, etc.)
     * @return array Array of leads or error
     */
    public function search_leads_ai($params)
    {
        // Get Google Places API key (try Contact Center first, then AXIOM Studio)
        $google_api_key = get_option('contactcenter_google_places_api_key');
        if (empty($google_api_key)) {
            // Try AXIOM Studio Google Search API key as fallback
            $google_api_key = get_option('omniu_studio_google_search_api_key');
        }
        
        // If still empty, try to get from config like AXIOM Studio does
        if (empty($google_api_key)) {
            $config = $this->config->item('omniu_studio_social_media');
            if (!empty($config) && isset($config['google_search_api_key'])) {
                $google_api_key = $config['google_search_api_key'];
            }
        }
        
        if (empty($google_api_key)) {
            return ['error' => 'Google Places API key not configured. Please configure it in Contact Center settings or use AXIOM Studio Google Search API key.'];
        }

        // Build location string
        $location = [];
        if (!empty($params['city'])) {
            $location[] = $params['city'];
        }
        if (!empty($params['state'])) {
            $location[] = $params['state'];
        }
        if (!empty($params['country'])) {
            $location[] = $params['country'];
        }
        $location_str = implode(', ', $location);
        
        $category = !empty($params['category']) ? $params['category'] : 'businesses';
        $quantity = isset($params['quantity']) ? (int)$params['quantity'] : 100;
        
        // Build search query - Google Places API format
        // Google Places API expects: "business_type in city, state, country"
        // For Brazil: "restaurants in São Paulo, SP, Brazil" or "restaurants in São Paulo, São Paulo, Brazil"
        if (!empty($params['country']) && strtolower($params['country']) === 'brazil') {
            // Use state code (e.g., SP) if available, otherwise use state name
            $state_part = !empty($params['state_code']) ? $params['state_code'] : (!empty($params['state']) ? $params['state'] : '');
            $city_part = !empty($params['city']) ? $params['city'] : '';
            
            if ($city_part && $state_part) {
                // Format: "category in city, state_code, Brazil"
                // Try multiple query formats to improve results
                // Format 1: English format (most common)
                $query = $category . ' in ' . $city_part . ', ' . $state_part . ', Brazil';
                
                // Alternative: Try Portuguese format for better Brazil results
                // $query = $category . ' em ' . $city_part . ', ' . $state_part . ', Brasil';
                
                // Log for debugging
                log_message('debug', 'Google Places API search query: ' . $query);
                log_message('debug', 'Location params - City: ' . $city_part . ', State: ' . $state_part . ', Country: Brazil');
            } else {
                $query = $category . ' in ' . $location_str;
                log_message('debug', 'Google Places API search query (fallback): ' . $query);
            }
        } else {
            // For other countries, use standard format
            $query = $category . ' in ' . $location_str;
            log_message('debug', 'Google Places API search query: ' . $query);
        }
        
        log_message('debug', 'Final Google Places API search query: ' . $query);
        log_message('debug', 'Search parameters: ' . json_encode($params));
        
        // Extract requested city for filtering
        $requested_city = !empty($params['city']) ? $params['city'] : '';
        
        // Use Google Places API Text Search
        $leads = $this->search_google_places($google_api_key, $query, $location_str, $quantity, $requested_city);
        
        if (isset($leads['error'])) {
            return $leads;
        }
        
        // Limit to requested batch size
        $batch_size = isset($params['batch_size']) ? (int)$params['batch_size'] : 100;
        if (count($leads) > $batch_size) {
            $leads = array_slice($leads, 0, $batch_size);
        }
        
        // Optional: Enrich leads with Gemini AI if enabled
        $enable_gemini_enrichment = isset($params['enable_gemini_enrichment']) && $params['enable_gemini_enrichment'] === true;
        if ($enable_gemini_enrichment) {
            // Get Gemini API key
            $gemini_api_key = get_option('contactcenter_gemini_api_key');
            if (empty($gemini_api_key)) {
                // Try to get from AXIOM Studio config
                $config_path = APPPATH . 'modules/omniu_studio/config/omniu_studio.php';
                if (file_exists($config_path)) {
                    include($config_path);
                    if (isset($omniu_studio_social_media['gemini_api_key'])) {
                        $gemini_api_key = $omniu_studio_social_media['gemini_api_key'];
                    }
                }
            }
            
            if (!empty($gemini_api_key)) {
                log_message('debug', 'Enriching ' . count($leads) . ' leads with Gemini AI');
                
                $enrichment_stats = [
                    'total' => count($leads),
                    'enriched' => 0,
                    'whatsapp_found' => 0,
                    'social_media_found' => 0
                ];
                
                $total_leads = count($leads);
                $enriched_count = 0;
                
                foreach ($leads as &$lead) {
                    $enriched_count++;
                    
                    // Update progress during enrichment if session_id is provided
                    if ($session_id) {
                        $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_enriching_leads') . ' (' . $enriched_count . '/' . $total_leads . ')');
                    }
                    
                    $enrichment = $this->enrich_lead_with_gemini(
                        $lead['name'],
                        $lead['city'],
                        $lead['phone'],
                        $lead['website'],
                        $gemini_api_key
                    );
                    
                    // Mark that enrichment was attempted
                    $lead['enrichment_attempted'] = true;
                    
                    // Update lead with enrichment data
                    if (!empty($enrichment['whatsapp_number'])) {
                        $lead['whatsapp_number'] = $enrichment['whatsapp_number'];
                        $lead['whatsapp_enriched'] = $enrichment['whatsapp_number'];
                        $enrichment_stats['whatsapp_found']++;
                    }
                    if (!empty($enrichment['social_media'])) {
                        $lead['social_media'] = $enrichment['social_media'];
                        $enrichment_stats['social_media_found']++;
                    }
                    $lead['enrichment_confidence'] = $enrichment['confidence_level'];
                    
                    // Count enriched leads
                    if (!empty($enrichment['whatsapp_number']) || !empty($enrichment['social_media'])) {
                        $enrichment_stats['enriched']++;
                    }
                    
                    // Rate limiting: sleep between AI requests
                    usleep(500000); // 0.5 seconds
                }
                unset($lead); // Break reference
                
                log_message('debug', 'Gemini enrichment completed. Stats: ' . json_encode($enrichment_stats));
                
                // Add enrichment stats to leads array metadata (will be returned separately)
                $leads['_enrichment_stats'] = $enrichment_stats;
            } else {
                log_message('warning', 'Gemini enrichment requested but API key not found');
            }
        }
        
        return $leads;
    }

    /**
     * Search Google Places API (New) using Text Search
     * Uses the NEW Places API with FieldMask for cost optimization
     * Architecture: Places API for finding leads, Gemini for enrichment (optional)
     * 
     * @param string $api_key Google Places API key
     * @param string $query Search query
     * @param string $location Location string for reference
     * @param int $max_results Maximum number of results
     * @param string $requested_city City name to filter results (prevents wrong city results)
     */
    private function search_google_places($api_key, $query, $location, $max_results = 100, $requested_city = '')
    {
        // Use the NEW Places API Text Search endpoint
        $api_url = "https://places.googleapis.com/v1/places:searchText";
        
        // Request body for Places API (New)
        // Note: Google Places API (New) returns up to 20 results per request
        // To get more, we need to use pagination with nextPageToken
        // Use pageSize instead of maxResultCount (maxResultCount is deprecated)
        $data = [
            'textQuery' => $query,
            'pageSize' => 20, // API max is 20 per request - always request max to get nextPageToken
            'languageCode' => 'pt-BR',
            'regionCode' => 'BR' // Brazil region code - this helps bias results to Brazil
        ];
        
        // Add locationBias for better results in the requested city
        // Use a wider radius (50km) to get more results and increase chance of pagination
        if (!empty($requested_city)) {
            // Try to get coordinates for common Brazilian cities
            $city_coords = $this->get_city_coordinates($requested_city);
            if ($city_coords) {
                $data['locationBias'] = [
                    'circle' => [
                        'center' => [
                            'latitude' => $city_coords['lat'],
                            'longitude' => $city_coords['lng']
                        ],
                        'radius' => 50000.0 // Increased to 50km radius to get more results
                    ]
                ];
                log_message('debug', 'Added locationBias for city: ' . $requested_city . ' at ' . $city_coords['lat'] . ', ' . $city_coords['lng'] . ' with 50km radius');
            }
        }
        
        // Log the exact query being sent
        log_message('debug', 'Places API request data: ' . json_encode($data));
        
        // CRITICAL: FieldMask controls costs - only request what we need
        // Without FieldMask, Google charges for ALL data (photos, reviews, etc.)
        $headers = [
            'Content-Type: application/json',
            'X-Goog-Api-Key: ' . $api_key,
            'X-Goog-FieldMask: places.id,places.displayName,places.formattedAddress,places.nationalPhoneNumber,places.internationalPhoneNumber,places.websiteUri,places.rating,places.userRatingCount,places.primaryType,places.types,places.businessStatus'
        ];
        
        log_message('debug', 'Google Places API (New) query: ' . $query);
        
        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $api_url);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, 30);
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);
        
        $response = curl_exec($ch);
        $curl_error = curl_error($ch);
        $http_code = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);
        
        if ($curl_error) {
            log_message('error', 'Google Places API (New) CURL Error: ' . $curl_error);
            return ['error' => 'Connection error: ' . $curl_error];
        }
        
        if ($http_code !== 200) {
            log_message('error', 'Google Places API (New) Error: HTTP ' . $http_code . ' - ' . $response);
            $decoded = json_decode($response, true);
            if (isset($decoded['error']['message'])) {
                return ['error' => 'Google Places API error: ' . $decoded['error']['message']];
            }
            return ['error' => 'HTTP ' . $http_code . ' error connecting to Google Places API'];
        }
        
        $decoded = json_decode($response, true);
        
        if (!isset($decoded['places']) || empty($decoded['places'])) {
            log_message('info', 'Google Places API (New): No results found for query: ' . $query);
            return [];
        }
        
        // Handle pagination if needed (Places API New returns up to 20 per request)
        $all_results = $decoded['places'];
        $next_page_token = isset($decoded['nextPageToken']) ? trim($decoded['nextPageToken']) : null;
        
        // Log response structure for debugging
        $response_keys = array_keys($decoded);
        log_message('debug', 'Places API: First response keys: ' . implode(', ', $response_keys));
        log_message('debug', 'Places API: Places count: ' . count($all_results));
        log_message('debug', 'Places API: nextPageToken present: ' . (isset($decoded['nextPageToken']) ? 'YES' : 'NO'));
        if (isset($decoded['nextPageToken'])) {
            log_message('debug', 'Places API: nextPageToken value: ' . substr($decoded['nextPageToken'], 0, 50) . '...');
        }
        
        // Fetch more results if needed - continue until we reach max_results or no more pages
        $max_pages = ceil($max_results / 20); // Calculate how many pages we need
        $page_count = 1; // We already have the first page
        
        log_message('debug', 'Places API: Starting pagination. Need ' . $max_results . ' results, will fetch up to ' . $max_pages . ' pages. Current results: ' . count($all_results));
        log_message('debug', 'Places API: Pagination will start if: count(' . count($all_results) . ') < max(' . $max_results . ') AND token exists(' . (!empty($next_page_token) ? 'YES' : 'NO') . ') AND page_count(' . $page_count . ') < max_pages(' . $max_pages . ')');
        
        // Continue fetching pages until we have enough results or no more pages
        while (count($all_results) < $max_results && !empty($next_page_token) && $page_count < $max_pages) {
            log_message('debug', 'Places API: Entering pagination loop - page_count: ' . $page_count . ', current results: ' . count($all_results) . ', nextPageToken: ' . ($next_page_token ? 'EXISTS' : 'EMPTY'));
            sleep(2); // Required delay between requests (Google requirement)
            
            // Create new request with pageToken
            // Use pageSize instead of maxResultCount (deprecated)
            $page_data = [
                'textQuery' => $query,
                'pageSize' => 20, // Always request 20 per page
                'languageCode' => 'pt-BR',
                'regionCode' => 'BR',
                'pageToken' => $next_page_token
            ];
            
            // Add locationBias if it was in original request
            if (isset($data['locationBias'])) {
                $page_data['locationBias'] = $data['locationBias'];
            }
            
            $ch = curl_init();
            curl_setopt($ch, CURLOPT_URL, $api_url);
            curl_setopt($ch, CURLOPT_POST, true);
            curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($page_data));
            curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
            curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
            curl_setopt($ch, CURLOPT_TIMEOUT, 30);
            curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);
            
            $page_response = curl_exec($ch);
            $page_http_code = curl_getinfo($ch, CURLINFO_HTTP_CODE);
            curl_close($ch);
            
            if ($page_http_code !== 200) {
                log_message('warning', 'Places API pagination error on page ' . ($page_count + 1) . ': HTTP ' . $page_http_code);
                break;
            }
            
            $page_decoded = json_decode($page_response, true);
            if (isset($page_decoded['places']) && !empty($page_decoded['places'])) {
                $all_results = array_merge($all_results, $page_decoded['places']);
                $next_page_token = isset($page_decoded['nextPageToken']) ? $page_decoded['nextPageToken'] : null;
                $page_count++;
                log_message('debug', 'Places API: Fetched page ' . $page_count . ', total results: ' . count($all_results) . ', nextPageToken: ' . ($next_page_token ? 'EXISTS' : 'NULL/EMPTY'));
            } else {
                log_message('debug', 'Places API: No more results on page ' . ($page_count + 1) . '. Response: ' . substr($page_response, 0, 200));
                $next_page_token = null; // Explicitly set to null to exit loop
                break;
            }
            
            // If no nextPageToken, we've reached the end
            if (empty($next_page_token)) {
                log_message('debug', 'Places API: No nextPageToken returned, reached end of results');
                break;
            }
        }
        
        log_message('debug', 'Places API: Pagination complete. Total results: ' . count($all_results) . ' (requested: ' . $max_results . '). Loop exited because: ' . 
            (count($all_results) >= $max_results ? 'reached max_results' : 
            (empty($next_page_token) ? 'no more pages' : 
            ($page_count >= $max_pages ? 'reached max_pages limit' : 'unknown'))));
        
        // Convert Google Places API (New) results to lead format
        // Filter: Only process businesses with businessStatus = "OPERATIONAL"
        // Also filter by location to ensure results match the requested city
        // Note: The NEW API returns data directly, no need for separate details call
        $leads = [];
        $requested_city_normalized = !empty($requested_city) ? $this->normalize_city_name($requested_city) : '';
        
        foreach ($all_results as $place) {
            // Filter only OPERATIONAL businesses
            if (isset($place['businessStatus']) && $place['businessStatus'] !== 'OPERATIONAL') {
                continue;
            }
            
            $address = $place['formattedAddress'] ?? '';
            $city = $this->extract_city_from_address($address);
            $city_normalized = $this->normalize_city_name($city);
            
            // Filter by city if we have a requested city
            // This prevents results from other cities (like Orlando when searching São José do Rio Preto)
            // Only filter out if clearly wrong (different country or clearly different city)
            if (!empty($requested_city_normalized) && !empty($address)) {
                $address_lower = mb_strtolower($address, 'UTF-8');
                
                // Check if it's wrong country (USA when searching Brazil)
                $is_wrong_country = (
                    stripos($address_lower, 'usa') !== false || 
                    stripos($address_lower, 'united states') !== false || 
                    stripos($address_lower, 'eua') !== false ||
                    stripos($address_lower, 'orlando') !== false ||
                    stripos($address_lower, 'florida') !== false ||
                    stripos($address_lower, 'fl ') !== false
                );
                
                // Check if address contains the requested city (more reliable than extracted city)
                $address_contains_city = stripos($address, $requested_city) !== false;
                
                // Only filter out if clearly wrong country
                // Be lenient with city matching - if address doesn't contain city but also doesn't contain wrong country, include it
                if ($is_wrong_country && !$address_contains_city) {
                    log_message('debug', 'Filtered out result from wrong country/city: ' . $city . ' (requested: ' . $requested_city . ') - Address: ' . $address);
                    continue; // Skip this result - it's clearly from wrong location
                }
            }
            
            $lead = [
                'name' => isset($place['displayName']['text']) ? $place['displayName']['text'] : '',
                'company' => isset($place['displayName']['text']) ? $place['displayName']['text'] : '',
                'phone' => $this->format_phone_number($place['internationalPhoneNumber'] ?? $place['nationalPhoneNumber'] ?? ''),
                'website' => $place['websiteUri'] ?? '',
                'email' => '', // Google Places API doesn't provide email
                'address' => $address,
                'city' => $city,
                'state' => $this->extract_state_from_address($address),
                'country' => $this->extract_country_from_address($address),
                'social_media' => '', // Will be enriched by Gemini if enabled
                'description' => isset($place['primaryType']) ? $place['primaryType'] : (isset($place['types'][0]) ? $place['types'][0] : ''),
                'rating' => $place['rating'] ?? null,
                'user_rating_count' => $place['userRatingCount'] ?? 0,
                'business_status' => $place['businessStatus'] ?? 'UNKNOWN'
            ];
            
            // Add lead if we have at least a name
            if (!empty($lead['name'])) {
                $leads[] = $lead;
            }
        }
        
        // Limit to requested max_results
        if (count($leads) > $max_results) {
            $leads = array_slice($leads, 0, $max_results);
        }
        
        log_message('debug', 'Google Places API (New) found ' . count($leads) . ' operational leads (requested: ' . $max_results . ')');
        
        return $leads;
    }

    /**
     * Enrich lead with Gemini AI using Google Search Retrieval
     * Finds WhatsApp/mobile numbers and social media links
     */
    private function enrich_lead_with_gemini($businessName, $city, $currentPhone, $website, $gemini_api_key)
    {
        if (empty($gemini_api_key)) {
            log_message('warning', 'Gemini API key not provided, skipping enrichment');
            return [
                'whatsapp_number' => null,
                'social_media' => null,
                'confidence_level' => 'low'
            ];
        }
        
        // Use gemini-flash-latest which is available in v1beta API
        // Alternative models: gemini-pro, gemini-1.5-pro, gemini-2.0-flash-exp
        $url = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent?key=' . $gemini_api_key;
        
        // Build research prompt
        $prompt = "Research this business: {$businessName} in {$city}.\n";
        $prompt .= "Current phone: {$currentPhone}\n";
        $prompt .= "Website: {$website}\n\n";
        $prompt .= "Task: Find their official WhatsApp or Mobile number (mobile numbers in Brazil start with '9' after area code).\n";
        $prompt .= "Check Instagram bio, Facebook page, Google My Business, and business directories.\n\n";
        $prompt .= "Return ONLY valid JSON with these exact keys:\n";
        $prompt .= "{\n";
        $prompt .= '  "whatsapp_number": "phone number in format (XX) 9XXXX-XXXX or null",' . "\n";
        $prompt .= '  "social_media": "Instagram or Facebook URL or null",' . "\n";
        $prompt .= '  "confidence_level": "high|medium|low"' . "\n";
        $prompt .= "}\n\n";
        $prompt .= "If no WhatsApp/mobile number found, set whatsapp_number to null. Do not invent numbers.";
        
        // Use googleSearch tool (googleSearchRetrieval is deprecated)
        // Format: tools[0].googleSearch with optional timeRangeFilter
        $payload = [
            'contents' => [
                [
                    'parts' => [
                        ['text' => $prompt]
                    ],
                    'role' => 'user'
                ]
            ],
            'tools' => [
                [
                    'googleSearch' => [
                        'timeRangeFilter' => null // null = search all time
                    ]
                ]
            ],
            'generationConfig' => [
                'temperature' => 0.3,
                // Note: responseMimeType cannot be used with tools (googleSearch)
                // We'll parse JSON from the text response instead
                'maxOutputTokens' => 500
            ]
        ];
        
        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($payload));
        curl_setopt($ch, CURLOPT_HTTPHEADER, ['Content-Type: application/json']);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, 30);
        
        $response = curl_exec($ch);
        $http_code = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);
        
        if ($http_code !== 200) {
            log_message('error', 'Gemini API Error: HTTP ' . $http_code . ' - ' . $response);
            return [
                'whatsapp_number' => null,
                'social_media' => null,
                'confidence_level' => 'low'
            ];
        }
        
        $jsonResponse = json_decode($response, true);
        
        // Extract text from Gemini response
        if (isset($jsonResponse['candidates'][0]['content']['parts'][0]['text'])) {
            $textResponse = $jsonResponse['candidates'][0]['content']['parts'][0]['text'];
            
            // Try to parse JSON from response
            // Sometimes Gemini wraps JSON in markdown code blocks
            $textResponse = preg_replace('/```json\s*/', '', $textResponse);
            $textResponse = preg_replace('/```\s*/', '', $textResponse);
            $textResponse = trim($textResponse);
            
            $enrichment = json_decode($textResponse, true);
            
            if (json_last_error() === JSON_ERROR_NONE && is_array($enrichment)) {
                return [
                    'whatsapp_number' => $enrichment['whatsapp_number'] ?? null,
                    'social_media' => $enrichment['social_media'] ?? null,
                    'confidence_level' => $enrichment['confidence_level'] ?? 'low'
                ];
            }
        }
        
        // Fallback if JSON parsing fails
        log_message('warning', 'Gemini API: Failed to parse JSON response for business: ' . $businessName);
        return [
            'whatsapp_number' => null,
            'social_media' => null,
            'confidence_level' => 'low'
        ];
    }

    /**
     * Format phone number to international format
     * Converts national phone numbers to international format
     */
    private function format_phone_number($phone)
    {
        if (empty($phone)) {
            return '';
        }
        
        // Remove all non-digit characters
        $phone = preg_replace('/\D/', '', $phone);
        
        // If it's already in international format (starts with country code), return as-is
        // Brazilian numbers: if starts with 55, it's already international
        if (strlen($phone) >= 12 && substr($phone, 0, 2) === '55') {
            return $phone;
        }
        
        // If it's a Brazilian national number (10-11 digits), add country code 55
        if (strlen($phone) >= 10 && strlen($phone) <= 11) {
            // Brazilian phone: add country code 55
            return '55' . $phone;
        }
        
        // Return as-is if we can't determine format
        return $phone;
    }

    /**
     * Extract city from formatted address
     */
    private function extract_city_from_address($address)
    {
        if (empty($address)) {
            return '';
        }
        
        // Try to extract city from address (usually before state/country)
        // This is a simple extraction - could be improved
        $parts = explode(',', $address);
        if (count($parts) >= 2) {
            return trim($parts[count($parts) - 2]);
        }
        
        return '';
    }
    
    /**
     * Extract city name from query string
     */
    private function extract_city_from_query($query)
    {
        // Extract city from query like "restaurants in São José do Rio Preto, SP, Brazil"
        // Pattern: "in CITY_NAME,"
        if (preg_match('/\bin\s+([^,]+),/i', $query, $matches)) {
            return trim($matches[1]);
        }
        return '';
    }
    
    /**
     * Normalize city name for comparison (remove accents, lowercase, etc.)
     */
    private function normalize_city_name($city)
    {
        if (empty($city)) {
            return '';
        }
        
        // Remove accents and convert to lowercase
        $city = mb_strtolower($city, 'UTF-8');
        $city = iconv('UTF-8', 'ASCII//TRANSLIT//IGNORE', $city);
        $city = preg_replace('/[^a-z0-9\s]/', '', $city);
        $city = preg_replace('/\s+/', ' ', $city);
        $city = trim($city);
        
        return $city;
    }
    
    /**
     * Get coordinates for a Brazilian city
     * Returns coordinates for common cities, or null if not found
     */
    private function get_city_coordinates($city)
    {
        // Common Brazilian cities coordinates
        $cities_coords = [
            'sao jose do rio preto' => ['lat' => -20.8111, 'lng' => -49.3750],
            'são jose do rio preto' => ['lat' => -20.8111, 'lng' => -49.3750],
            'sao paulo' => ['lat' => -23.5505, 'lng' => -46.6333],
            'são paulo' => ['lat' => -23.5505, 'lng' => -46.6333],
            'rio de janeiro' => ['lat' => -22.9068, 'lng' => -43.1729],
            'belo horizonte' => ['lat' => -19.9167, 'lng' => -43.9345],
            'brasilia' => ['lat' => -15.7942, 'lng' => -47.8822],
            'brasília' => ['lat' => -15.7942, 'lng' => -47.8822],
            'curitiba' => ['lat' => -25.4284, 'lng' => -49.2733],
            'recife' => ['lat' => -8.0476, 'lng' => -34.8770],
            'porto alegre' => ['lat' => -30.0346, 'lng' => -51.2177],
            'salvador' => ['lat' => -12.9714, 'lng' => -38.5014],
            'fortaleza' => ['lat' => -3.7172, 'lng' => -38.5433],
            'campinas' => ['lat' => -22.9056, 'lng' => -47.0608],
            'goiania' => ['lat' => -16.6864, 'lng' => -49.2643],
            'goiânia' => ['lat' => -16.6864, 'lng' => -49.2643],
        ];
        
        $city_normalized = $this->normalize_city_name($city);
        
        // Try exact match first
        if (isset($cities_coords[$city_normalized])) {
            return $cities_coords[$city_normalized];
        }
        
        // Try partial match
        foreach ($cities_coords as $key => $coords) {
            if (stripos($city_normalized, $key) !== false || stripos($key, $city_normalized) !== false) {
                return $coords;
            }
        }
        
        // If not found, return null (will use regionCode only)
        return null;
    }

    /**
     * Extract state from formatted address
     */
    private function extract_state_from_address($address)
    {
        if (empty($address)) {
            return '';
        }
        
        // Try to extract state from address
        $parts = explode(',', $address);
        if (count($parts) >= 3) {
            return trim($parts[count($parts) - 2]);
        }
        
        return '';
    }

    /**
     * Extract country from formatted address
     */
    private function extract_country_from_address($address)
    {
        if (empty($address)) {
            return '';
        }
        
        // Last part is usually country
        $parts = explode(',', $address);
        if (!empty($parts)) {
            return trim(end($parts));
        }
        
        return '';
    }

    /**
     * Build search prompt for Gemini API
     */
    private function build_ai_search_prompt($params)
    {
        $location = [];
        if (!empty($params['country'])) {
            $location[] = $params['country'];
        }
        if (!empty($params['state'])) {
            $location[] = $params['state'];
        }
        if (!empty($params['city'])) {
            $location[] = $params['city'];
        }
        $location_str = implode(', ', $location);
        
        $category = !empty($params['category']) ? $params['category'] : 'businesses';
        $quantity = isset($params['quantity']) ? (int)$params['quantity'] : 100;
        
        $prompt = "You are a business lead finder. Based on your knowledge of businesses and locations, provide realistic business information for the following location: {$location_str}.\n\n";
        $prompt .= "Category/Type: {$category}\n\n";
        $prompt .= "Generate up to {$quantity} realistic business leads and return a JSON array with the following structure for each business:\n";
        $prompt .= "[\n";
        $prompt .= "  {\n";
        $prompt .= "    \"name\": \"Contact person name (if available, otherwise use company name)\",\n";
        $prompt .= "    \"company\": \"Company/Business name\",\n";
        $prompt .= "    \"phone\": \"Phone number in international format (e.g., 5517991198465 for Brazil)\",\n";
        $prompt .= "    \"website\": \"Website URL (if available)\",\n";
        $prompt .= "    \"email\": \"Email address (if available)\",\n";
        $prompt .= "    \"address\": \"Full street address\",\n";
        $prompt .= "    \"city\": \"City name\",\n";
        $prompt .= "    \"state\": \"State/Province name\",\n";
        $prompt .= "    \"country\": \"Country name\",\n";
        $prompt .= "    \"social_media\": \"Social media URLs (Facebook, Instagram, LinkedIn, etc.) separated by commas\",\n";
        $prompt .= "    \"description\": \"Business description or services offered\"\n";
        $prompt .= "  }\n";
        $prompt .= "]\n\n";
        $prompt .= "CRITICAL: You MUST return ONLY a valid JSON array. Do NOT include any markdown formatting, code blocks, explanations, or text before or after the JSON.\n";
        $prompt .= "Start your response directly with [ and end with ]. No ```json tags, no explanations, no other text.\n\n";
        $prompt .= "Important requirements:\n";
        $prompt .= "- Return ONLY valid JSON array starting with [ and ending with ]\n";
        $prompt .= "- NO markdown formatting, NO code blocks, NO explanations\n";
        $prompt .= "- Phone numbers MUST be realistic and varied - NOT sequential or patterned\n";
        $prompt .= "- Phone numbers must be in international format without spaces or special characters\n";
        $prompt .= "- For Brazil (country code 55): Use format 55 + area code (2 digits) + 9 digits (e.g., 5517998765432, 5511987654321, 5511999887766)\n";
        $prompt .= "- Each phone number must be UNIQUE and RANDOM - vary the digits significantly between businesses\n";
        $prompt .= "- DO NOT use sequential patterns like 10001, 20002, 30003 - use random digits\n";
        $prompt .= "- Examples of realistic Brazilian phone numbers: 5517998765432, 5511987654321, 5511999887766, 5511988776655, 5517991122334\n";
        $prompt .= "- Generate realistic business names, addresses, and contact information appropriate for {$location_str}\n";
        $prompt .= "- Use realistic phone numbers with correct country codes and area codes for the location\n";
        $prompt .= "- If information is not available, use empty string \"\" for that field\n";
        $prompt .= "- Focus on businesses that match the category: {$category}\n";
        $prompt .= "- Make ALL data realistic and varied - use different business names, addresses, phone numbers, emails, and contact details\n";
        $prompt .= "- Return at least 10-20 businesses if possible, up to {$quantity}\n\n";
        $prompt .= "Remember: Your response must be ONLY the JSON array, nothing else. Start with [ and end with ].\n";
        $prompt .= "CRITICAL: Phone numbers must look REAL and RANDOM, not sequential or patterned!\n";
        
        return $prompt;
    }

    /**
     * Extract leads array from Gemini API response
     */
    private function extract_leads_from_response($text)
    {
        // Clean the text - remove any leading/trailing whitespace
        $text = trim($text);
        
        // Try to extract JSON from markdown code blocks (most common format)
        // Match ```json [...] ``` or ``` [...] ```
        if (preg_match('/```(?:json)?\s*(\[.*?\])\s*```/s', $text, $matches)) {
            $jsonString = trim($matches[1]);
            $leads = json_decode($jsonString, true);
            if (json_last_error() === JSON_ERROR_NONE && is_array($leads) && count($leads) > 0) {
                log_message('debug', 'Successfully extracted ' . count($leads) . ' leads from markdown code block');
                return $leads;
            }
        }
        
        // Try to find JSON array that starts with [ and ends with ]
        // Use a more robust regex that handles nested structures
        if (preg_match('/\[[\s\S]*\]/', $text, $matches)) {
            $jsonString = trim($matches[0]);
            $leads = json_decode($jsonString, true);
            if (json_last_error() === JSON_ERROR_NONE && is_array($leads) && count($leads) > 0) {
                log_message('debug', 'Successfully extracted ' . count($leads) . ' leads from JSON array pattern');
                return $leads;
            }
        }
        
        // Try to find JSON array by looking for the first [ and matching closing ]
        $startPos = strpos($text, '[');
        if ($startPos !== false) {
            $bracketCount = 0;
            $endPos = $startPos;
            for ($i = $startPos; $i < strlen($text); $i++) {
                if ($text[$i] === '[') {
                    $bracketCount++;
                } elseif ($text[$i] === ']') {
                    $bracketCount--;
                    if ($bracketCount === 0) {
                        $endPos = $i + 1;
                        break;
                    }
                }
            }
            if ($endPos > $startPos) {
                $jsonString = substr($text, $startPos, $endPos - $startPos);
                $leads = json_decode($jsonString, true);
                if (json_last_error() === JSON_ERROR_NONE && is_array($leads) && count($leads) > 0) {
                    log_message('debug', 'Successfully extracted ' . count($leads) . ' leads using bracket matching');
                    return $leads;
                }
            }
        }
        
        // Try to decode the entire text as JSON (in case it's pure JSON)
        $leads = json_decode($text, true);
        if (json_last_error() === JSON_ERROR_NONE && is_array($leads) && count($leads) > 0) {
            log_message('debug', 'Successfully decoded entire text as JSON array with ' . count($leads) . ' leads');
            return $leads;
        }
        
        // Log the error with more context
        $jsonError = json_last_error_msg();
        log_message('error', 'Failed to extract leads from Gemini response. JSON Error: ' . $jsonError);
        log_message('error', 'Response preview (first 1000 chars): ' . substr($text, 0, 1000));
        log_message('error', 'Response preview (last 500 chars): ' . substr($text, -500));
        
        return ['error' => 'Failed to parse leads from AI response. The AI may not have returned valid JSON. Please try again or check the logs for details.'];
    }

    /**
     * Create Omni Pilot session
     */
    public function create_omni_pilot_session($wizard_data)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_sessions')) {
            return false;
        }
        
        $session_data = [
            'staffid' => get_staff_user_id(),
            'device_id' => isset($wizard_data['step_2']['device_id']) ? $wizard_data['step_2']['device_id'] : null,
            'goal_target' => isset($wizard_data['step_0']['goal_target']) ? (int)$wizard_data['step_0']['goal_target'] : 0,
            'goal_status_id' => isset($wizard_data['step_0']['goal_status_id']) ? (int)$wizard_data['step_0']['goal_status_id'] : null,
            'deadline_date' => isset($wizard_data['step_0']['deadline_date']) ? $wizard_data['step_0']['deadline_date'] : null,
            'status' => 'pending',
            'progress_percentage' => 0,
            'created_at' => date('Y-m-d H:i:s'),
            'updated_at' => date('Y-m-d H:i:s')
        ];

        $this->db->insert(db_prefix() . 'contactcenter_omni_pilot_sessions', $session_data);
        $session_id = $this->db->insert_id();

        if ($session_id) {
            // Save step data
            foreach ($wizard_data as $step_key => $step_data) {
                $step_number = (int)str_replace('step_', '', $step_key);
                $this->save_omni_pilot_step($session_id, $step_number, $step_data);
            }
        }

        return $session_id;
    }

    /**
     * Save Omni Pilot step data
     */
    public function save_omni_pilot_step($session_id, $step_number, $step_data)
    {
        // Check if step already exists
        $this->db->where('session_id', $session_id);
        $this->db->where('step_number', $step_number);
        $existing = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_steps')->row();

        $data = [
            'session_id' => $session_id,
            'step_number' => $step_number,
            'step_data' => json_encode($step_data),
            'completed' => 1,
            'updated_at' => date('Y-m-d H:i:s')
        ];

        if ($existing) {
            $this->db->where('id', $existing->id);
            $this->db->update(db_prefix() . 'contactcenter_omni_pilot_steps', $data);
            return $existing->id;
        } else {
            $data['created_at'] = date('Y-m-d H:i:s');
            $this->db->insert(db_prefix() . 'contactcenter_omni_pilot_steps', $data);
            return $this->db->insert_id();
        }
    }

    /**
     * Get active Omni Pilot session for device
     */
    public function get_active_omni_pilot_session($device_id)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_sessions')) {
            return null;
        }
        
        $this->db->where('device_id', $device_id);
        $this->db->where_in('status', ['pending', 'importing', 'creating_campaign', 'scheduling_messages', 'active', 'campaign_setup', 'message_setup', 'followup_setup']);
        $this->db->order_by('created_at', 'DESC');
        $this->db->limit(1);
        return $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
    }

    /**
     * Get Omni Pilot progress
     */
    public function get_omni_pilot_progress($session_id)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_sessions')) {
            return null;
        }
        
        $this->db->where('id', $session_id);
        $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();

        if (!$session) {
            return null;
        }

        // Get goal progress
        $goal_progress = 0;
        if ($session->goal_status_id) {
            $this->db->where('status', $session->goal_status_id);
            if ($session->tag_id) {
                $this->db->where('id IN (SELECT rel_id FROM ' . db_prefix() . 'taggables WHERE tag_id = ' . (int)$session->tag_id . ' AND rel_type = "lead")');
            }
            $goal_progress = $this->db->count_all_results(db_prefix() . 'leads');
        }

        // Campaign and follow-up progress are shown in their respective badges
        // We don't need to track detailed sending progress here
        $campaign_sent = 0;
        $campaign_total = 0;
        $followup_current = 0;
        $followup_total = 0;
        
        // Use updated step_detail if it was changed
        $final_step_detail = isset($session->step_detail) ? $session->step_detail : null;
        
        return [
            'session_id' => $session->id,
            'status' => $session->status,
            'progress_percentage' => $session->progress_percentage,
            'current_phase' => $session->current_phase,
            'current_step' => isset($session->current_step) ? floatval($session->current_step) : null,
            'step_detail' => $final_step_detail,
            'goal_target' => $session->goal_target,
            'goal_progress' => $goal_progress,
            'goal_status_id' => $session->goal_status_id,
            'campaign_id' => $session->campaign_id,
            'leads_engine_id' => $session->leads_engine_id,
            'campaign_sent' => $campaign_sent,
            'campaign_total' => $campaign_total,
            'followup_current' => $followup_current,
            'followup_total' => $followup_total,
            'error_message' => $session->error_message
        ];
    }

    /**
     * Execute Omni Pilot background job
     * Note: This runs synchronously. For true background processing, consider using a queue system.
     */
    public function execute_omni_pilot_background($session_id)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_sessions')) {
            log_activity('Omni Pilot tables do not exist. Please run module install.', get_staff_user_id());
            return;
        }
        
        // Update status to importing
        $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_phase_importing_leads'));
        
        // Set execution time limit for long-running processes
        set_time_limit(300); // 5 minutes

        try {
            // Get session data
            $this->db->where('id', $session_id);
            $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
            
            if (!$session) {
                throw new Exception('Session not found');
            }

            // Get step data
            $steps = [];
            $this->db->where('session_id', $session_id);
            $step_records = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_steps')->result();
            foreach ($step_records as $step) {
                $steps['step_' . $step->step_number] = json_decode($step->step_data, true);
            }

            // Step 1: Import leads
            // Merge step_2 campaign_import_status into step_1 data if available
            $import_step_data = $steps['step_1'] ?? [];
            if (isset($steps['step_2']['campaign_import_status']) && !empty($steps['step_2']['campaign_import_status'])) {
                $import_step_data['campaign_import_status'] = $steps['step_2']['campaign_import_status'];
            }
            $this->update_omni_pilot_status($session_id, 'importing', 10, _l('omni_pilot_phase_importing_leads'));
            $tag_id = $this->import_leads_for_omni_pilot($session_id, $import_step_data);
            if ($tag_id) {
                $this->db->where('id', $session_id);
                $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['tag_id' => $tag_id]);
            }

            // Step 2: Create campaign
            $this->update_omni_pilot_status($session_id, 'campaign_setup', 30, _l('omni_pilot_phase_setting_up_campaign'));
            $campaign_id = $this->create_campaign_for_omni_pilot($session_id, $steps, $tag_id);
            if ($campaign_id) {
                $this->db->where('id', $session_id);
                $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['campaign_id' => $campaign_id]);
                $this->update_omni_pilot_status($session_id, 'campaign_setup', 50, _l('omni_pilot_phase_campaign_created'));
            }

            // Step 3: Create initial message
            $this->update_omni_pilot_status($session_id, 'message_setup', 60, _l('omni_pilot_phase_setting_up_messages'));
            $message_result = $this->create_messages_for_omni_pilot($campaign_id, $steps['step_3'] ?? []);
            if ($message_result) {
                $this->update_omni_pilot_status($session_id, 'message_setup', 70, _l('omni_pilot_phase_messages_configured'));
            }

            // Step 5: Create follow-up
            $this->update_omni_pilot_status($session_id, 'followup_setup', 80, _l('omni_pilot_phase_setting_up_followup'));
            $leads_engine_id = $this->create_followup_for_omni_pilot($session_id, $steps['step_5'] ?? []);
            if ($leads_engine_id) {
                $this->db->where('id', $session_id);
                $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['leads_engine_id' => $leads_engine_id]);
                $this->update_omni_pilot_status($session_id, 'followup_setup', 90, _l('omni_pilot_phase_followup_configured'));
            }

            // Complete
            $this->update_omni_pilot_status($session_id, 'active', 95, _l('omni_pilot_phase_activating'));
            
            // Activate campaign
            if ($campaign_id) {
                $this->db->where('con_id', $campaign_id);
                $this->db->update(db_prefix() . 'contactcenter_conversation_engine', ['con_status' => 1]);
            }

            // Activate follow-up engine
            if ($leads_engine_id) {
                $this->db->where('id', $leads_engine_id);
                $this->db->update(db_prefix() . 'contactcenter_leads_engine', ['status' => 1]);
            }

            // Final update
            $this->update_omni_pilot_status($session_id, 'active', 100, _l('omni_pilot_phase_active_running'));
            
            $this->db->where('id', $session_id);
            $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', [
                'completed_at' => date('Y-m-d H:i:s')
            ]);

        } catch (Exception $e) {
            $this->update_omni_pilot_status($session_id, 'failed', 0, 'Error: ' . $e->getMessage());
            log_activity('Omni Pilot execution failed: ' . $e->getMessage(), get_staff_user_id());
        }
    }

    /**
     * Update Omni Pilot status
     */
    public function update_omni_pilot_status($session_id, $status, $progress, $phase, $step_number = null, $step_detail = null)
    {
        // Check which columns exist in the table
        $columns = $this->db->list_fields(db_prefix() . 'contactcenter_omni_pilot_sessions');
        
        $update_data = [
            'status' => $status,
            'progress_percentage' => $progress,
            'current_phase' => $phase,
            'updated_at' => date('Y-m-d H:i:s')
        ];
        
        // Add step information if provided and column exists
        if ($step_number !== null && in_array('current_step', $columns)) {
            $update_data['current_step'] = $step_number;
        }
        if ($step_detail !== null && in_array('step_detail', $columns)) {
            $update_data['step_detail'] = $step_detail;
        }
        
        $this->db->where('id', $session_id);
        $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', $update_data);
    }

    /**
     * Execute a specific Omni Pilot step
     */
    public function execute_omni_pilot_step($session_id, $step)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_sessions')) {
            throw new Exception('Omni Pilot tables do not exist. Please run module install.');
        }
        
        // Get session data
        $this->db->where('id', $session_id);
        $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
        
        if (!$session) {
            throw new Exception('Session not found');
        }

        // Get step data
        $steps = [];
        $this->db->where('session_id', $session_id);
        $step_records = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_steps')->result();
        foreach ($step_records as $step_record) {
            $steps['step_' . $step_record->step_number] = json_decode($step_record->step_data, true);
        }

        $result = [];

        switch ($step) {
            case 'import':
                // Step 1: Import leads
                // Merge step_2 campaign_import_status into step_1 data if available
                $import_step_data = $steps['step_1'] ?? [];
                if (isset($steps['step_2']['campaign_import_status']) && !empty($steps['step_2']['campaign_import_status'])) {
                    $import_step_data['campaign_import_status'] = $steps['step_2']['campaign_import_status'];
                }
                $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, null);
                
                // If leads are not already searched, search them first
                if (empty($import_step_data['selected_leads']) && ($import_step_data['import_method'] ?? 'ai') === 'ai') {
                    // Search leads using AI with progress updates
                    $search_params = [
                        'country' => $import_step_data['ai_import_country'] ?? '55',
                        'state' => $import_step_data['ai_state'] ?? '',
                        'state_code' => $import_step_data['ai_state'] ?? '',
                        'city' => $import_step_data['ai_city'] ?? '',
                        'category' => $import_step_data['ai_category'] ?? '',
                        'quantity' => $import_step_data['ai_quantity'] ?? 100,
                        'batch_size' => 100,
                        'enable_gemini_enrichment' => ($import_step_data['enable_gemini_enrichment'] ?? 0) == 1,
                        'session_id' => $session_id // Pass session ID for progress updates
                    ];
                    
                    $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_searching_leads'));
                    $leads = $this->search_leads_ai_with_progress($search_params);
                    
                    if (isset($leads['error'])) {
                        throw new Exception('Failed to search leads: ' . $leads['error']);
                    }
                    
                    // Store leads in step data
                    $import_step_data['selected_leads'] = $leads;
                    $steps['step_1']['selected_leads'] = $leads;
                    
                    // Update step data in database
                    $this->db->where('session_id', $session_id);
                    $this->db->where('step_number', 1);
                    $this->db->update(db_prefix() . 'contactcenter_omni_pilot_steps', [
                        'step_data' => json_encode($steps['step_1'], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES)
                    ]);
                }
                
                // Update: Importing leads
                $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_importing_leads'));
                
                // Create progress callback
                $progress_callback = function($current, $total) use ($session_id) {
                    $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_importing_leads') . ' (' . $current . '/' . $total . ')');
                };
                
                try {
                    $tag_id = $this->import_leads_for_omni_pilot($session_id, $import_step_data, $progress_callback);
                    
                    // Check if leads were actually imported by counting them
                    $leads_count = count($steps['step_1']['selected_leads'] ?? []);
                    $imported_leads_count = 0;
                    if ($tag_id && $leads_count > 0) {
                        // Count how many leads have this tag
                        $this->db->select('COUNT(*) as count');
                        $this->db->from(db_prefix() . 'taggables');
                        $this->db->where('tag_id', $tag_id);
                        $this->db->where('rel_type', 'lead');
                        $imported_result = $this->db->get()->row();
                        $imported_leads_count = $imported_result ? $imported_result->count : 0;
                    }
                    
                    // If leads were imported (even if tag_id is false due to DB errors), consider it successful
                    if ($imported_leads_count > 0 || ($tag_id && $tag_id > 0)) {
                        if ($tag_id) {
                            $this->db->where('id', $session_id);
                            $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['tag_id' => $tag_id]);
                        }
                        $result['tag_id'] = $tag_id;
                        $result['imported_count'] = $imported_leads_count;
                        $result['success'] = true; // Explicitly mark as successful
                        $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_completed'));
                    } else {
                        throw new Exception('No leads were imported');
                    }
                } catch (Exception $e) {
                    // Check if leads were actually imported despite the error
                    $leads_count = count($steps['step_1']['selected_leads'] ?? []);
                    $imported_leads_count = 0;
                    $found_tag_id = null;
                    
                    if ($leads_count > 0) {
                        // Try to find the tag that was created
                        $tag_name = 'OmniPilot-' . date('Y-m-d') . '-' . ($steps['step_1']['ai_category'] ?? 'Campaign');
                        $this->db->where('name', $tag_name);
                        $tag = $this->db->get(db_prefix() . 'tags')->row();
                        if ($tag) {
                            $found_tag_id = $tag->id;
                            // Count imported leads
                            $this->db->select('COUNT(*) as count');
                            $this->db->from(db_prefix() . 'taggables');
                            $this->db->where('tag_id', $tag->id);
                            $this->db->where('rel_type', 'lead');
                            $imported_result = $this->db->get()->row();
                            $imported_leads_count = $imported_result ? $imported_result->count : 0;
                        }
                    }
                    
                    // If leads were imported, consider it successful even if there were errors
                    if ($imported_leads_count > 0) {
                        // Leads were imported successfully, update session
                        if ($found_tag_id) {
                            $this->db->where('id', $session_id);
                            $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['tag_id' => $found_tag_id]);
                        }
                        $result['tag_id'] = $found_tag_id;
                        $result['imported_count'] = $imported_leads_count;
                        $result['success'] = true; // Explicitly mark as successful
                        $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_completed'));
                        // Don't throw exception - leads were imported successfully, continue to next step
                        log_activity('Omni Pilot import completed with ' . $imported_leads_count . ' leads despite some errors: ' . $e->getMessage(), get_staff_user_id());
                    } else {
                        // No leads were imported, throw exception
                        log_activity('Omni Pilot import failed: ' . $e->getMessage(), get_staff_user_id());
                        throw new Exception('Failed to import leads: ' . $e->getMessage());
                    }
                }
                
                // Ensure result has success flag
                if (!isset($result['success'])) {
                    // If we got here and result has data, it means import succeeded
                    if (!empty($result) && (isset($result['tag_id']) || isset($result['imported_count']))) {
                        $result['success'] = true;
                        log_activity('Omni Pilot import step completed successfully. Tag ID: ' . ($result['tag_id'] ?? 'null') . ', Imported: ' . ($result['imported_count'] ?? 0), get_staff_user_id());
                    } else {
                        $result['success'] = false;
                        $result['message'] = 'Import step completed but no leads were imported';
                        log_activity('Omni Pilot import step completed but no result data was set', get_staff_user_id());
                    }
                }
                
                // Log final result for debugging
                log_activity('Omni Pilot import step final result: ' . json_encode($result), get_staff_user_id());
                break;

            case 'campaign':
                // Step 2: Create campaign
                // Refresh session data to get latest tag_id from previous step
                $this->db->where('id', $session_id);
                $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
                
                if (!$session) {
                    throw new Exception('Session not found');
                }
                
                $this->update_omni_pilot_status($session_id, 'campaign_setup', 0, _l('omni_pilot_step_2_creating_campaign'), 2, null);
                $campaign_id = $this->create_campaign_for_omni_pilot($session_id, $steps, $session->tag_id);
                if ($campaign_id && $campaign_id > 0) {
                    $this->db->where('id', $session_id);
                    $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['campaign_id' => $campaign_id]);
                    $this->update_omni_pilot_status($session_id, 'campaign_setup', 0, _l('omni_pilot_step_2_creating_campaign'), 2, _l('omni_pilot_completed'));
                    $result['campaign_id'] = $campaign_id;
                    $result['success'] = true; // Explicitly mark as successful
                } else {
                    throw new Exception('Failed to create campaign');
                }
                break;

            case 'message':
                // Step 2.1: Sending Campaign (will be tracked separately via polling)
                // Step 3: Interacting with leads (waiting for first follow-up)
                $this->update_omni_pilot_status($session_id, 'message_setup', 0, _l('omni_pilot_step_3_interacting'), 3, _l('omni_pilot_waiting_first_followup'));
                $message_result = $this->create_messages_for_omni_pilot($session->campaign_id, $steps['step_3'] ?? []);
                if ($message_result) {
                    $result['message_result'] = $message_result;
                    $result['success'] = true; // Explicitly mark as successful
                } else {
                    throw new Exception('Failed to create messages');
                }
                break;

            case 'followup':
                // Step 4: Follow-up (will show progress like "Follow-up 1/5")
                // Refresh session data to get latest tag_id from import step
                $this->db->where('id', $session_id);
                $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
                
                if (!$session) {
                    throw new Exception('Session not found');
                }
                
                // Log tag_id for debugging
                log_activity('Omni Pilot followup step: Session tag_id = ' . ($session->tag_id ?? 'NULL'), get_staff_user_id());
                
                $this->update_omni_pilot_status($session_id, 'followup_setup', 0, _l('omni_pilot_step_4_followup'), 4, null);
                $leads_engine_id = $this->create_followup_for_omni_pilot($session_id, $steps['step_5'] ?? []);
                if ($leads_engine_id && $leads_engine_id > 0) {
                    $this->db->where('id', $session_id);
                    $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['leads_engine_id' => $leads_engine_id]);
                    $this->update_omni_pilot_status($session_id, 'followup_setup', 0, _l('omni_pilot_step_4_followup'), 4, _l('omni_pilot_completed'));
                    $result['leads_engine_id'] = $leads_engine_id;
                    $result['success'] = true; // Explicitly mark as successful
                } else {
                    throw new Exception('Failed to create follow-up');
                }
                break;

            case 'activate':
                // Refresh session to get latest data
                $this->db->where('id', $session_id);
                $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
                
                if (!$session) {
                    throw new Exception('Session not found');
                }
                
                // Update status to show we're activating everything
                $this->update_omni_pilot_status($session_id, 'activating', 0, _l('omni_pilot_step_activating'), 5, null);
                
                // Activate campaign (set to active)
                if ($session->campaign_id) {
                    $this->db->where('con_id', $session->campaign_id);
                    $this->db->update(db_prefix() . 'contactcenter_conversation_engine', ['con_status' => 1]);
                    log_activity('Omni Pilot activated campaign ID: ' . $session->campaign_id, get_staff_user_id());
                }

                // Activate ALL follow-up engines for this Omni Pilot (each follow-up is a separate engine)
                // Find all follow-ups by device_id and title pattern (new pattern: Omni-{user}-{category}-{goal}-{hours}h)
                $this->db->where('device_id', $session->device_id);
                $this->db->like('title', 'Omni-', 'after');
                $this->db->update(db_prefix() . 'contactcenter_leads_engine', ['status' => 1]);
                $activated_count = $this->db->affected_rows();
                log_activity('Omni Pilot activated ' . $activated_count . ' follow-up engines for device ' . $session->device_id, get_staff_user_id());

                // Now everything is created and activated - update status to show sending progress
                // Status will be updated by polling with actual sending progress
                $this->update_omni_pilot_status($session_id, 'active', 0, _l('omni_pilot_step_2_1_sending_campaign'), 2.1, '0/0');
                
                // Mark setup as completed - now showing sending progress
                $this->db->where('id', $session_id);
                $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', [
                    'completed_at' => date('Y-m-d H:i:s')
                ]);
                
                $result['completed'] = true;
                $result['success'] = true; // Explicitly mark as successful
                break;

            default:
                throw new Exception('Unknown step: ' . $step);
        }

        return $result;
    }

    /**
     * Search leads AI with progress updates
     */
    public function search_leads_ai_with_progress($params)
    {
        $session_id = $params['session_id'] ?? null;
        
        // Update: Searching leads
        if ($session_id) {
            $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_searching_leads'));
        }
        
        // Call the original search function
        $leads = $this->search_leads_ai($params);
        
        if (isset($leads['error'])) {
            return $leads;
        }
        
        // Update: Leads found
        $leads_count = count($leads);
        if ($session_id) {
            $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_leads_found') . ': ' . $leads_count);
        }
        
        // Check if enrichment is enabled
        $enable_gemini_enrichment = isset($params['enable_gemini_enrichment']) && $params['enable_gemini_enrichment'] === true;
        if ($enable_gemini_enrichment && $session_id) {
            // Update: Enriching leads
            $this->update_omni_pilot_status($session_id, 'importing', 0, _l('omni_pilot_step_1_creating_leads'), 1, _l('omni_pilot_enriching_leads'));
        }
        
        return $leads;
    }

    /**
     * Import leads for Omni Pilot
     */
    public function import_leads_for_omni_pilot($session_id, $step_data, $progress_callback = null)
    {
        $import_method = $step_data['import_method'] ?? 'ai';
        $tag_name = 'OmniPilot-' . date('Y-m-d') . '-' . ($step_data['ai_category'] ?? 'Campaign');
        
        // Create or get tag
        $this->db->where('name', $tag_name);
        $tag = $this->db->get(db_prefix() . 'tags')->row();
        
        if (!$tag) {
            // Check if color column exists before trying to insert it
            $columns = $this->db->list_fields(db_prefix() . 'tags');
            $tag_data = ['name' => $tag_name];
            if (in_array('color', $columns)) {
                $tag_data['color'] = '#00e09b';
            }
            
            $this->db->insert(db_prefix() . 'tags', $tag_data);
            $tag_id = $this->db->insert_id();
        } else {
            $tag_id = $tag->id;
        }

        if ($import_method == 'ai') {
            // Use existing AI import logic
            $leads = $step_data['selected_leads'] ?? [];
            
            // Get import status - prefer campaign_import_status from step_2 if available, otherwise use ai_import_status from step_1
            // Check if we have step_2 data passed (for backward compatibility, check both)
            $import_status = null;
            if (isset($step_data['campaign_import_status']) && !empty($step_data['campaign_import_status'])) {
                $import_status = $step_data['campaign_import_status'];
            } elseif (isset($step_data['ai_import_status']) && !empty($step_data['ai_import_status'])) {
                $import_status = $step_data['ai_import_status'];
            } else {
                $import_status = get_option('leads_default_status');
            }
            
            $import_data = [
                'status' => $import_status,
                'source' => $step_data['ai_import_source'] ?? get_option('leads_default_source'),
                'staffid' => $step_data['ai_import_staffid'] ?? get_staff_user_id(),
                'country' => $step_data['ai_import_country'] ?? '55',
                'gpt_status' => $step_data['ai_import_gpt_status'] ?? 0
            ];

            $imported_count = 0;
            $total_leads = count($leads);
            foreach ($leads as $index => $lead) {
                // Call progress callback if provided
                if ($progress_callback && is_callable($progress_callback)) {
                    $progress_callback($imported_count + 1, $total_leads);
                }
                $lead_data = [
                    'name' => $lead['name'] ?? ($lead['company'] ?? ''),
                    'company' => $lead['company'] ?? '',
                    'phonenumber' => $lead['phone'] ?? '',
                    'website' => $lead['website'] ?? '',
                    'email' => $lead['email'] ?? '',
                    'city' => $lead['city'] ?? '',
                    'state' => $lead['state'] ?? '',
                    'address' => $lead['address'] ?? '',
                    'country' => $import_data['country'],
                    'status' => $import_data['status'],
                    'source' => $import_data['source'],
                    'assigned' => $import_data['staffid'],
                    'gpt_status' => $import_data['gpt_status'],
                    'dateadded' => date('Y-m-d H:i:s'),
                    'addedfrom' => get_staff_user_id()
                ];

                $lead_id = $this->leads_model->add($lead_data);
                
                if ($lead_id && $tag_id) {
                    // Check if taggable already exists
                    $this->db->where('rel_id', $lead_id);
                    $this->db->where('rel_type', 'lead');
                    $this->db->where('tag_id', $tag_id);
                    $exists = $this->db->get(db_prefix() . 'taggables')->row();
                    
                    if (!$exists) {
                        $this->db->insert(db_prefix() . 'taggables', [
                            'rel_id' => $lead_id,
                            'rel_type' => 'lead',
                            'tag_id' => $tag_id
                        ]);
                    }
                    $imported_count++;
                }
            }
            
            log_activity('Omni Pilot imported ' . $imported_count . ' leads with tag ID: ' . $tag_id, get_staff_user_id());
            
            // Return tag_id even if there were some database errors (leads were still imported)
            // Only return false if no leads were imported at all
            if ($imported_count > 0) {
                return $tag_id;
            } else {
                return false;
            }
        } else {
            // File upload import - reuse existing import logic
            // This would need to be implemented based on existing import_leads functionality
            // For now, create tag even if no file import
            log_activity('Omni Pilot file import not yet implemented', get_staff_user_id());
            return $tag_id; // Return tag_id even for file import (tag was created)
        }
    }

    /**
     * Create campaign for Omni Pilot
     */
    public function create_campaign_for_omni_pilot($session_id, $steps, $tag_id)
    {
        $step_0 = $steps['step_0'] ?? [];
        $step_1 = $steps['step_1'] ?? [];
        $step_2 = $steps['step_2'] ?? [];

        $category = $step_1['ai_category'] ?? 'Campaign';
        $goal_status = $step_0['goal_status_id'] ?? 0;
        
        // Get status name for campaign name
        $this->db->where('id', $goal_status);
        $status = $this->db->get(db_prefix() . 'leads_status')->row();
        $goal_name = $status ? $status->name : 'Goal';

        // Get device to get staffid
        $device_id = $step_2['device_id'] ?? null;
        $device = null;
        if ($device_id) {
            $device = $this->get_device($device_id);
        }
        
        // Get staff user name for title
        $staff_id = $device ? $device->staffid : get_staff_user_id();
        $user_name = get_staff_full_name($staff_id);
        // Clean user name for title (remove extra spaces, limit length)
        $user_name = trim($user_name);
        if (strlen($user_name) > 20) {
            $user_name = substr($user_name, 0, 20);
        }
        
        // Build campaign data - match the working add_conversation_engine method pattern
        // Get list of existing columns to avoid errors
        $columns = $this->db->list_fields(db_prefix() . 'contactcenter_conversation_engine');
        
        // Always use generated name with user name, even if campaign_name is provided
        // This ensures consistency with follow-up naming
        $generated_campaign_name = 'Omni-' . $user_name . '-' . $category . '-' . $goal_name;
        $campaign_data = [
            'con_title' => $generated_campaign_name,
            'device_id' => $device_id,
            'staffid' => $device ? $device->staffid : get_staff_user_id(),
            'con_status' => 0, // Will be activated after all setup is complete
            'con_date' => date('Y-m-d H:i:s'), // Required field - matches working method
            'con_count_send' => 0, // Initialize counters
            'con_count_reply' => 0
        ];
        
        // Add fields that exist in the table (checking column existence to avoid errors)
        // Use campaign_import_status from step_2 for leads_status (where to import leads to)
        if (in_array('leads_status', $columns)) {
            $campaign_data['leads_status'] = $step_2['campaign_import_status'] ?? $step_0['goal_status_id'] ?? null;
        }
        // Use campaign_final_status from step_2 for leads_status_final (final status after campaign sends message)
        if (in_array('leads_status_final', $columns)) {
            $campaign_data['leads_status_final'] = $step_2['campaign_final_status'] ?? $step_0['goal_status_id'] ?? null;
        }
        if (in_array('leads_create_data', $columns)) {
            $campaign_data['leads_create_data'] = date('Y-m-d H:i:s');
        }
        if (in_array('leads_create_data_final', $columns)) {
            $campaign_data['leads_create_data_final'] = $step_0['deadline_date'] ?? date('Y-m-d H:i:s', strtotime('+30 days'));
        }
        if (in_array('start_time', $columns)) {
            $campaign_data['start_time'] = $step_2['start_time'] ?? '08:00';
        }
        if (in_array('end_time', $columns)) {
            $campaign_data['end_time'] = $step_2['end_time'] ?? '18:00';
        }
        if (in_array('leads_day', $columns)) {
            $campaign_data['leads_day'] = 0; // Unlimited
        }
        if (in_array('leads_sleep', $columns)) {
            $campaign_data['leads_sleep'] = 0; // Initialize - matches replicate method
        }
        if (in_array('tags', $columns)) {
            $campaign_data['tags'] = $tag_id ? (string)$tag_id : '';
        }
        if (in_array('date_filter_type', $columns)) {
            $campaign_data['date_filter_type'] = 'creation_date';
        }
        if (in_array('device_rotation_index', $columns)) {
            $campaign_data['device_rotation_index'] = 0; // Initialize - matches replicate method
        }

        $this->db->insert(db_prefix() . 'contactcenter_conversation_engine', $campaign_data);
        $campaign_id = $this->db->insert_id();
        
        log_activity('Omni Pilot created campaign ID: ' . $campaign_id, get_staff_user_id());
        
        return $campaign_id;
    }

    /**
     * Create messages for Omni Pilot
     */
    public function create_messages_for_omni_pilot($campaign_id, $step_data)
    {
        if (!$campaign_id || empty($step_data['selected_message'])) {
            return false;
        }

        $media_path = $step_data['selected_message']['media'] ?? null;
        $media_type = $step_data['selected_message']['media_type'] ?? null;
        
        // Determine media type if not provided
        if ($media_path && !$media_type) {
            $media_type = $this->getMediaTypeFromPath($media_path);
        }
        
        $message_data = [
            'con_id' => $campaign_id,
            'list_text' => $step_data['selected_message']['text'] ?? '',
            'list_image' => $media_path,
            'list_ordem' => 1
        ];
        
        // Add media_type only if column exists
        $columns = $this->db->list_fields(db_prefix() . 'contactcenter_conversation_engine_list');
        if (in_array('media_type', $columns)) {
            $message_data['media_type'] = $media_type;
        }

        $this->db->insert(db_prefix() . 'contactcenter_conversation_engine_list', $message_data);
        return $this->db->insert_id();
    }

    /**
     * Create follow-up for Omni Pilot
     * Creates a separate follow-up engine for each message with its own hours_since_last_contact
     */
    public function create_followup_for_omni_pilot($session_id, $step_data)
    {
        // Get session to get device_id, status, and tag_id
        // Refresh session to ensure we have the latest tag_id from import step
        $this->db->where('id', $session_id);
        $session = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_sessions')->row();
        
        if (!$session) {
            log_activity('Omni Pilot: Session not found when creating follow-up', get_staff_user_id());
            return false;
        }
        
        // Log tag_id for debugging
        log_activity('Omni Pilot: Creating follow-up with tag_id: ' . ($session->tag_id ?? 'NULL'), get_staff_user_id());

        // Get step 0 data for status
        $this->db->where('session_id', $session_id);
        $this->db->where('step_number', 0);
        $step_0_record = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_steps')->row();
        $step_0 = $step_0_record ? json_decode($step_0_record->step_data, true) : [];
        
        // Get step 1 data for category (same as campaign)
        $this->db->where('session_id', $session_id);
        $this->db->where('step_number', 1);
        $step_1_record = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_steps')->row();
        $step_1 = $step_1_record ? json_decode($step_1_record->step_data, true) : [];
        
        $category = $step_1['ai_category'] ?? 'Campaign';
        $goal_status = $step_0['goal_status_id'] ?? 0;
        
        // Get status name for follow-up name (same as campaign)
        $this->db->where('id', $goal_status);
        $status = $this->db->get(db_prefix() . 'leads_status')->row();
        $goal_name = $status ? $status->name : 'Goal';

        // Get device to get staffid
        $device = $this->get_device($session->device_id);
        
        // Get tag_id from session (same tag used for campaign)
        $tag_id = $session->tag_id ?? null;
        
        // If tag_id is not in session, try to find it by tag name pattern
        if (!$tag_id || $tag_id <= 0) {
            // Try to find tag by name pattern (OmniPilot-{date}-{category})
            // First try exact match with category
            $expected_tag_name = 'OmniPilot-' . date('Y-m-d') . '-' . $category;
            $this->db->where('name', $expected_tag_name);
            $tag = $this->db->get(db_prefix() . 'tags')->row();
            
            // If not found, try with date pattern
            if (!$tag) {
                $this->db->like('name', 'OmniPilot-' . date('Y-m-d'), 'after');
                $this->db->order_by('id', 'DESC');
                $tag = $this->db->get(db_prefix() . 'tags')->row();
            }
            
            if ($tag) {
                $tag_id = $tag->id;
                // Update session with found tag_id
                $this->db->where('id', $session_id);
                $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', ['tag_id' => $tag_id]);
                log_activity('Omni Pilot: Found tag_id ' . $tag_id . ' (tag: ' . $tag->name . ') and updated session', get_staff_user_id());
            } else {
                log_activity('Omni Pilot: Could not find tag_id for follow-up. Session tag_id: ' . ($session->tag_id ?? 'NULL') . ', Expected tag name: ' . $expected_tag_name, get_staff_user_id());
            }
        } else {
            log_activity('Omni Pilot: Using tag_id ' . $tag_id . ' from session for follow-up', get_staff_user_id());
        }
        
        // Get staff user name for title (same as campaign)
        $staff_id = $device ? $device->staffid : get_staff_user_id();
        $user_name = get_staff_full_name($staff_id);
        // Clean user name for title (remove extra spaces, limit length)
        $user_name = trim($user_name);
        if (strlen($user_name) > 20) {
            $user_name = substr($user_name, 0, 20);
        }
        
        // Get list of existing columns
        $columns = $this->db->list_fields(db_prefix() . 'contactcenter_leads_engine');
        
        if (empty($step_data['followup_messages']) || !is_array($step_data['followup_messages'])) {
            log_activity('Omni Pilot: No follow-up messages to create', get_staff_user_id());
            return false;
        }
        
        // Create a separate follow-up engine for EACH message
        $first_leads_engine_id = null;
        $created_count = 0;
        
        foreach ($step_data['followup_messages'] as $index => $message) {
            $hours = isset($message['hours']) ? intval($message['hours']) : 24;
            $message_text = $message['text'] ?? '';
            
            if (empty($message_text)) {
                continue; // Skip empty messages
            }
            
            // Build follow-up data for this specific follow-up (same pattern as campaign)
            $followup_data = [
                'title' => 'Omni-' . $user_name . '-' . $category . '-' . $goal_name . '-' . $hours . 'h',
                'staffid' => $device ? $device->staffid : get_staff_user_id(),
                'date' => date('Y-m-d H:i:s'),
                'status' => 0 // Will be activated after all setup is complete
            ];
            
            // Add fields that exist in the table
            if (in_array('device_id', $columns)) {
                $followup_data['device_id'] = $session->device_id;
            }
            if (in_array('leads_status', $columns)) {
                $followup_data['leads_status'] = $step_0['goal_status_id'] ?? null;
            }
            if (in_array('leads_status_final', $columns)) {
                $followup_data['leads_status_final'] = $step_0['goal_status_id'] ?? null;
            }
            if (in_array('start_time', $columns)) {
                $followup_data['start_time'] = '08:00';
            }
            if (in_array('end_time', $columns)) {
                $followup_data['end_time'] = '18:00';
            }
            if (in_array('hours_since_last_contact', $columns)) {
                $followup_data['hours_since_last_contact'] = $hours; // Use the hours from the message
            }
            if (in_array('fromMe', $columns)) {
                $followup_data['fromMe'] = 1;
            }
            // Add tags field (same tag as campaign) - stored as comma-separated string
            if (in_array('tags', $columns)) {
                $followup_data['tags'] = $tag_id ? (string)$tag_id : '';
                log_activity('Omni Pilot: Setting tags for follow-up engine: ' . ($followup_data['tags'] ?: 'EMPTY'), get_staff_user_id());
            } else {
                log_activity('Omni Pilot: Tags column does not exist in contactcenter_leads_engine table', get_staff_user_id());
            }

            // Insert this follow-up engine
            $this->db->insert(db_prefix() . 'contactcenter_leads_engine', $followup_data);
            $leads_engine_id = $this->db->insert_id();
            
            if ($leads_engine_id) {
                // Store the first ID to return (for backward compatibility)
                if ($first_leads_engine_id === null) {
                    $first_leads_engine_id = $leads_engine_id;
                }
                
                // Create ONE message for this follow-up engine
                $message_data = [
                    'contactcenter_leads_engine_id' => $leads_engine_id,
                    'text' => $message_text,
                    'ordenation' => 1 // Always 1 since each follow-up has only one message
                ];
                
                // Add image and media_type if provided
                if (!empty($message['media'])) {
                    $message_data['image'] = $message['media'];
                }
                if (!empty($message['media_type'])) {
                    $message_data['media_type'] = $message['media_type'];
                }
                
                $this->db->insert(db_prefix() . 'contactcenter_leads_engine_messages', $message_data);
                $created_count++;
                
                log_activity('Omni Pilot created follow-up engine ID: ' . $leads_engine_id . ' with ' . $hours . ' hours', get_staff_user_id());
            }
        }
        
        if ($created_count > 0) {
            log_activity('Omni Pilot created ' . $created_count . ' follow-up engines', get_staff_user_id());
            return $first_leads_engine_id; // Return first ID for backward compatibility
        }
        
        return false;
    }

    /**
     * Generate AI messages for Step 3
     */
    public function generate_omni_pilot_messages($category, $context = '', $count = 5, $language = 'pt-BR')
    {
        if (empty($this->tokenOpenai)) {
            return [];
        }

        $messages = [];
        
        // Build comprehensive prompt with all context
        $prompt = "Generate {$count} different WhatsApp greeting messages for a business in the '{$category}' category.";
        
        if (!empty($context)) {
            $prompt .= "\n\nContext:\n{$context}";
        }
        
        // Add language instruction
        $langInstruction = '';
        switch ($language) {
            case 'pt-BR':
                $langInstruction = "Write in Brazilian Portuguese.";
                break;
            case 'en-US':
                $langInstruction = "Write in English.";
                break;
            case 'es-ES':
                $langInstruction = "Write in Spanish.";
                break;
        }
        
        $prompt .= "\n\n{$langInstruction}";
        $prompt .= "\n\nEach message should be:\n";
        $prompt .= "- Professional but friendly\n";
        $prompt .= "- Short (max 2-3 sentences)\n";
        $prompt .= "- Personalized (use {Lead} or {FirstName} placeholders)\n";
        $prompt .= "- Appealing and make the receiver want to know more\n";
        $prompt .= "- Different from the others\n";
        $prompt .= "- Return as JSON array: [\"message1\", \"message2\", ...]";

        try {
            $openai = new Openai_api();
            $url = 'https://api.openai.com/v1/chat/completions';
            
            $data = [
                'model' => 'gpt-4',
                'messages' => [
                    ['role' => 'system', 'content' => 'You are a professional copywriter specializing in WhatsApp business messages.'],
                    ['role' => 'user', 'content' => $prompt]
                ],
                'temperature' => 0.8
            ];
            
            $response = $openai->calApiPost($url, $this->tokenOpenai, 0, 0, '', 'gpt-4', $data);

            if ($response === false) {
                log_activity('AI message generation failed: calApiPost returned false', get_staff_user_id());
            } elseif (!is_array($response)) {
                log_activity('AI message generation failed: Invalid response format: ' . gettype($response), get_staff_user_id());
            } elseif (isset($response['error'])) {
                $errorMsg = isset($response['error']['message']) ? $response['error']['message'] : json_encode($response['error']);
                log_activity('AI message generation failed: API error - ' . $errorMsg, get_staff_user_id());
            } elseif (isset($response['choices'][0]['message']['content'])) {
                $content = $response['choices'][0]['message']['content'];
                $json_messages = json_decode($content, true);
                
                if (json_last_error() !== JSON_ERROR_NONE) {
                    // Se não é JSON válido, trata como texto simples
                    $messages[] = [
                        'text' => $content,
                        'media' => null,
                        'media_type' => null
                    ];
                } elseif (is_array($json_messages)) {
                    foreach ($json_messages as $msg) {
                        if (is_string($msg)) {
                            $messages[] = [
                                'text' => $msg,
                                'media' => null,
                                'media_type' => null
                            ];
                        }
                    }
                }
            } else {
                log_activity('AI message generation failed: Unexpected response structure: ' . json_encode($response), get_staff_user_id());
            }
        } catch (Exception $e) {
            log_activity('AI message generation failed: Exception - ' . $e->getMessage() . ' | Trace: ' . $e->getTraceAsString(), get_staff_user_id());
        }

        // Fallback if AI fails
        if (empty($messages)) {
            $messages = [
                ['text' => 'Olá {Lead}, temos uma oportunidade especial para você!', 'media' => null, 'media_type' => null],
                ['text' => 'Oi {FirstName}, gostaria de apresentar nossa solução.', 'media' => null, 'media_type' => null],
                ['text' => 'Bom dia {Lead}, como podemos ajudar você hoje?', 'media' => null, 'media_type' => null],
                ['text' => 'Olá {FirstName}, temos novidades que podem interessar você.', 'media' => null, 'media_type' => null],
                ['text' => 'Oi {Lead}, que tal conhecermos melhor suas necessidades?', 'media' => null, 'media_type' => null]
            ];
        }

        return array_slice($messages, 0, $count);
    }
    
    /**
     * Get media type from file path
     */
    private function getMediaTypeFromPath($path)
    {
        if (!$path) {
            return null;
        }
        
        $extension = strtolower(pathinfo($path, PATHINFO_EXTENSION));
        
        $image_extensions = ['jpg', 'jpeg', 'png', 'gif', 'webp'];
        $video_extensions = ['mp4', 'mov', 'avi', 'mkv', 'webm'];
        $audio_extensions = ['mp3', 'wav', 'ogg', 'm4a'];
        
        if (in_array($extension, $image_extensions)) {
            return 'image';
        } elseif (in_array($extension, $video_extensions)) {
            return 'video';
        } elseif (in_array($extension, $audio_extensions)) {
            return 'audio';
        } elseif ($extension === 'pdf' || $extension === 'doc' || $extension === 'docx') {
            return 'document';
        }
        
        return 'file';
    }

    /**
     * Generate follow-up messages for Step 5
     */
    public function generate_omni_pilot_followup_messages($initial_message, $category = '', $hours = [1, 8, 24, 48, 168])
    {
        if (empty($this->tokenOpenai)) {
            return $this->generate_default_followup_messages($hours);
        }

        $messages = [];
        $hour_labels = [
            1 => '1 hour',
            8 => '8 hours',
            24 => '1 day',
            48 => '2 days',
            168 => '1 week'
        ];

        foreach ($hours as $hour) {
            $prompt = "Generate a follow-up WhatsApp message for a business in the '{$category}' category.";
            $prompt .= "\n\nInitial message was: {$initial_message}";
            $prompt .= "\nThis follow-up is sent after {$hour_labels[$hour]} with no response.";
            $prompt .= "\n\nMessage should be:\n";
            $prompt .= "- Polite and non-intrusive\n";
            $prompt .= "- Short (1-2 sentences)\n";
            $prompt .= "- Use {Lead} or {FirstName} placeholder\n";
            $prompt .= "- Different from the initial message\n";
            $prompt .= "- Return only the message text, no JSON";

            try {
                $openai = new Openai_api();
                $url = 'https://api.openai.com/v1/chat/completions';
                
                $data = [
                    'model' => 'gpt-4',
                    'messages' => [
                        ['role' => 'system', 'content' => 'You are a professional copywriter specializing in WhatsApp follow-up messages.'],
                        ['role' => 'user', 'content' => $prompt]
                    ],
                    'temperature' => 0.7
                ];
                
                $response = $openai->calApiPost($url, $this->tokenOpenai, 0, 0, '', 'gpt-4', $data);

                if ($response && isset($response['choices'][0]['message']['content'])) {
                    $text = trim($response['choices'][0]['message']['content']);
                    // Remove quotes if present
                    $text = trim($text, '"\'');
                    $messages[] = [
                        'hours' => $hour,
                        'text' => $text,
                        'media' => null,
                        'media_type' => null
                    ];
                } else {
                    $messages[] = [
                        'hours' => $hour,
                        'text' => $this->get_default_followup_message($hour),
                        'media' => null,
                        'media_type' => null
                    ];
                }
            } catch (Exception $e) {
                log_activity('AI follow-up generation failed: ' . $e->getMessage(), get_staff_user_id());
                $messages[] = [
                    'hours' => $hour,
                    'text' => $this->get_default_followup_message($hour),
                    'media' => null,
                    'media_type' => null
                ];
            }
        }

        return $messages;
    }

    /**
     * Get default follow-up message
     */
    private function get_default_followup_message($hours)
    {
        $messages = [
            1 => 'Olá {Lead}, ainda estamos aqui caso precise de algo!',
            8 => 'Oi {FirstName}, não esqueça que estamos à disposição.',
            24 => 'Bom dia {Lead}, gostaria de retomar nossa conversa.',
            48 => 'Olá {FirstName}, ainda temos oportunidades disponíveis.',
            168 => 'Oi {Lead}, que tal darmos uma nova chance?'
        ];

        return $messages[$hours] ?? 'Olá {Lead}, gostaria de retomar nossa conversa.';
    }

    /**
     * Generate default follow-up messages (fallback)
     */
    private function generate_default_followup_messages($hours)
    {
        $messages = [];
        foreach ($hours as $hour) {
            $messages[] = [
                'hours' => $hour,
                'text' => $this->get_default_followup_message($hour),
                'media' => null,
                'media_type' => null
            ];
        }
        return $messages;
    }

    /**
     * Stop/Cancel Omni Pilot session
     */
    public function stop_omni_pilot_session($session_id)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_sessions')) {
            return false;
        }

        $this->db->where('id', $session_id);
        $this->db->where('staffid', get_staff_user_id()); // Ensure user owns the session
        
        // Only allow stopping if status is not completed or failed
        $this->db->where_not_in('status', ['completed', 'failed', 'cancelled']);
        
        $data = [
            'status' => 'cancelled',
            'updated_at' => date('Y-m-d H:i:s'),
            'current_phase' => _l('omni_pilot_phase_cancelled')
        ];
        
        $this->db->update(db_prefix() . 'contactcenter_omni_pilot_sessions', $data);
        
        return $this->db->affected_rows() > 0;
    }

    /**
     * Get Omni Pilot templates for staff member
     */
    public function get_omni_pilot_templates($staffid)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_templates')) {
            return [];
        }

        $this->db->where('staffid', $staffid);
        $this->db->where('is_active', 1);
        $this->db->order_by('created_at', 'DESC');
        $templates = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_templates')->result();

        // Decode wizard_data for each template
        foreach ($templates as $template) {
            if (!empty($template->wizard_data)) {
                $template->wizard_data = json_decode($template->wizard_data, true);
            }
        }

        return $templates;
    }

    /**
     * Get single Omni Pilot template
     */
    public function get_omni_pilot_template($template_id, $staffid)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_templates')) {
            return null;
        }

        $this->db->where('id', $template_id);
        $this->db->where('staffid', $staffid);
        $template = $this->db->get(db_prefix() . 'contactcenter_omni_pilot_templates')->row();

        if ($template && !empty($template->wizard_data)) {
            $template->wizard_data = json_decode($template->wizard_data, true);
        }

        return $template;
    }

    /**
     * Delete Omni Pilot template
     */
    public function delete_omni_pilot_template($template_id, $staffid)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_omni_pilot_templates')) {
            return false;
        }

        $this->db->where('id', $template_id);
        $this->db->where('staffid', $staffid);
        $this->db->delete(db_prefix() . 'contactcenter_omni_pilot_templates');

        return $this->db->affected_rows() > 0;
    }

    /**
     * Log AI interaction to structured table
     */
    public function log_ai_interaction($data)
    {
        if (!$this->db->table_exists(db_prefix() . 'contactcenter_ai_interactions')) {
            return false;
        }
        
        try {
            $insert_data = array(
                'lead_id' => isset($data['lead_id']) ? $data['lead_id'] : null,
                'device_id' => isset($data['device_id']) ? $data['device_id'] : null,
                'thread_id' => isset($data['thread_id']) ? $data['thread_id'] : null,
                'run_id' => isset($data['run_id']) ? $data['run_id'] : null,
                'interaction_type' => isset($data['interaction_type']) ? $data['interaction_type'] : 'message',
                'user_message' => isset($data['user_message']) ? $data['user_message'] : null,
                'ai_response' => isset($data['ai_response']) ? $data['ai_response'] : null,
                'function_name' => isset($data['function_name']) ? $data['function_name'] : null,
                'function_arguments' => isset($data['function_arguments']) ? (is_array($data['function_arguments']) ? json_encode($data['function_arguments']) : $data['function_arguments']) : null,
                'function_result' => isset($data['function_result']) ? (is_array($data['function_result']) ? json_encode($data['function_result']) : $data['function_result']) : null,
                'raw_input' => isset($data['raw_input']) ? (is_array($data['raw_input']) ? json_encode($data['raw_input']) : $data['raw_input']) : null,
                'raw_output' => isset($data['raw_output']) ? (is_array($data['raw_output']) ? json_encode($data['raw_output']) : $data['raw_output']) : null,
                'status' => isset($data['status']) ? $data['status'] : null,
                'error_message' => isset($data['error_message']) ? $data['error_message'] : null,
                'context_data' => isset($data['context_data']) ? (is_array($data['context_data']) ? json_encode($data['context_data']) : $data['context_data']) : null,
                'created_at' => date('Y-m-d H:i:s')
            );
            
            $this->db->insert(db_prefix() . 'contactcenter_ai_interactions', $insert_data);
            return $this->db->insert_id();
        } catch (Exception $e) {
            error_log("Failed to log AI interaction: " . $e->getMessage());
            return false;
        }
    }

