    /**
     * Get chat history for a lead (by phonenumber) - For AXIOM
     * Uses msg_id DESC for fast fetch (primary key); returns chronological order.
     * Phone matching: DB may store 5516898375259, 16898375259, or 16898375259@s.whatsapp.net
     */
    public function get_chat_history_for_lead($phonenumber, $limit = 50)
    {
        if (empty($phonenumber)) {
            return [];
        }

        try {
            $phoneClean = preg_replace('/\D/', '', $phonenumber);
            $variants = array_unique([
                $phonenumber,
                $phoneClean,
                $phoneClean . '@s.whatsapp.net'
            ]);
            if (strlen($phoneClean) >= 10 && strlen($phoneClean) <= 11 && substr($phoneClean, 0, 2) !== '55') {
                $variants[] = '55' . $phoneClean;
            }
            if (strlen($phoneClean) >= 12 && substr($phoneClean, 0, 2) === '55') {
                $variants[] = substr($phoneClean, 2);
            }
            $variants = array_values(array_filter($variants));

            $this->db->select('msg_id, msg_content as text, msg_fromMe as fromMe, msg_date as date');
            $this->db->where('msg_isGroupMsg', 0);
            $this->db->where_in('msg_conversation_number', $variants);
            $this->db->where("(msg_type IN ('text','conversation') OR msg_type IS NULL OR msg_type = '')");
            $this->db->where("msg_content IS NOT NULL AND msg_content != ''");
            $this->db->order_by('msg_id', 'DESC');
            $this->db->limit($limit);
            
            $query = $this->db->get(db_prefix() . 'contactcenter_message');
            if ($query === false) {
                error_log("Failed to get chat history: Query failed");
                return [];
            }
            $messages = array_reverse($query->result_array());
            
            // Format for AXIOM (chronological: oldest first)
            $formatted = [];
            foreach ($messages as $msg) {
                // Ensure fromMe is properly converted (handle both 0/1 and true/false)
                $fromMe = 0;
                if (isset($msg['fromMe'])) {
                    $fromMe = is_bool($msg['fromMe']) ? ($msg['fromMe'] ? 1 : 0) : (int)$msg['fromMe'];
                }
                
                $formatted[] = [
                    'text' => trim($msg['text'] ?? ''),
                    'fromMe' => $fromMe,
                    'date' => $msg['date'] ?? ''
                ];
            }
            
            // Debug: Log last messages retrieved
            if (!empty($formatted)) {
                error_log("Chat History Retrieved - Phonnumber: {$phonenumber}, Count: " . count($formatted));
                error_log("Last 3 messages: " . json_encode(array_slice($formatted, -3)));
            }
            
            return $formatted;
        } catch (Exception $e) {
            error_log("Failed to get chat history: " . $e->getMessage());
            return [];
        }
    }

    /**
     * Get lead data by phonenumber - For AXIOM (Enhanced with status and custom fields)
     */
    public function get_lead_data($phonenumber)
    {
        if (empty($phonenumber)) {
            return null;
        }

        try {
            // Try to get from contactcenter_contact table
            $this->db->where('phonenumber', $phonenumber);
            $this->db->where('isGroup', 0);
            $contact = $this->db->get(db_prefix() . 'contactcenter_contact')->row_array();
            
            $lead_id = null;
            $name = '';
            
            if ($contact) {
                $name = $contact['name'] ?? '';
                $lead_id = $contact['lead_id'] ?? null;
            }
            
            $lead_data = [
                'name' => $name,
                'phonenumber' => $phonenumber,
                'lead_id' => $lead_id,
                'status' => null,
                'source' => null,
                'email' => null,
                'company' => null,
                'address' => null,
                'city' => null,
                'state' => null,
                'country' => null,
                'title' => null,
                'website' => null,
                'description' => null
            ];
            
            // Get detailed lead information if lead_id exists
            if (!empty($lead_id)) {
                $this->load->model('leads_model');
                $lead = $this->leads_model->get($lead_id);
                
                if ($lead) {
                    $lead_data['name'] = $lead->name ?? $lead_data['name'];
                    $lead_data['email'] = $lead->email ?? null;
                    $lead_data['company'] = $lead->company ?? null;
                    $lead_data['address'] = $lead->address ?? null;
                    $lead_data['city'] = $lead->city ?? null;
                    $lead_data['state'] = $lead->state ?? null;
                    $lead_data['country'] = $lead->country ?? null;
                    $lead_data['title'] = $lead->title ?? null;
                    $lead_data['website'] = $lead->website ?? null;
                    $lead_data['description'] = $lead->description ?? null;
                    $lead_data['source'] = $lead->source ?? null;
                    
                    // Get creation date
                    if (!empty($lead->dateadded)) {
                        $lead_data['date_created'] = $lead->dateadded;
                        $lead_data['date_created_formatted'] = date('d/m/Y H:i', strtotime($lead->dateadded));
                    }
                    
                    // Get last contact date
                    if (!empty($lead->lastcontact)) {
                        $lead_data['last_contact'] = $lead->lastcontact;
                        $lead_data['last_contact_formatted'] = date('d/m/Y H:i', strtotime($lead->lastcontact));
                    }
                    
                    // Get assigned to
                    if (!empty($lead->assigned)) {
                        $lead_data['assigned_to'] = $lead->assigned;
                    }
                    
                    // Get lead status
                    if (!empty($lead->status)) {
                        $status = $this->leads_model->get_status($lead->status);
                        if ($status) {
                            $lead_data['status'] = $status->name ?? null;
                            $lead_data['status_id'] = $lead->status;
                        }
                    }
                    
                    // Get source name
                    if (!empty($lead->source)) {
                        $source = $this->leads_model->get_source($lead->source);
                        if ($source) {
                            $lead_data['source_name'] = $source->name ?? null;
                        }
                    }
                    
                    // Get custom fields
                    $custom_fields = [];
                    $this->load->helper('custom_fields');
                    if (function_exists('get_custom_fields') && function_exists('get_custom_field_value')) {
                        $cf_definitions = get_custom_fields('leads');
                        if ($cf_definitions) {
                            foreach ($cf_definitions as $field) {
                                $value = get_custom_field_value($lead_id, $field['id'], 'leads', false);
                                if (!empty($value)) {
                                    $custom_fields[] = [
                                        'name' => $field['name'] ?? 'Campo ' . $field['id'],
                                        'value' => $value
                                    ];
                                }
                            }
                        }
                    }
                    $lead_data['custom_fields'] = $custom_fields;
                    
                    // Get related contacts (other contacts with same email or company)
                    $related_contacts = [];
                    if (!empty($lead->email)) {
                        $this->db->select('id, firstname, lastname, email, phonenumber, title');
                        $this->db->where('email', $lead->email);
                        $this->db->where('id !=', $lead_id); // Exclude current lead
                        $contacts = $this->db->get(db_prefix() . 'contacts')->result_array();
                        if ($contacts) {
                            foreach ($contacts as $contact) {
                                $related_contacts[] = [
                                    'type' => 'contact',
                                    'name' => trim(($contact['firstname'] ?? '') . ' ' . ($contact['lastname'] ?? '')),
                                    'email' => $contact['email'] ?? null,
                                    'phone' => $contact['phonenumber'] ?? null,
                                    'title' => $contact['title'] ?? null
                                ];
                            }
                        }
                    }
                    
                    // Get other leads with same company
                    if (!empty($lead->company)) {
                        $this->db->select('id, name, email, phonenumber');
                        $this->db->where('company', $lead->company);
                        $this->db->where('id !=', $lead_id);
                        $other_leads = $this->db->get(db_prefix() . 'leads')->result_array();
                        if ($other_leads) {
                            foreach ($other_leads as $other_lead) {
                                $related_contacts[] = [
                                    'type' => 'lead',
                                    'name' => $other_lead['name'] ?? null,
                                    'email' => $other_lead['email'] ?? null,
                                    'phone' => $other_lead['phonenumber'] ?? null
                                ];
                            }
                        }
                    }
                    $lead_data['related_contacts'] = $related_contacts;
                }
            }
            
            return $lead_data;
        } catch (Exception $e) {
            error_log("Failed to get lead data: " . $e->getMessage());
            return null;
        }
    }

