    public function add_auto_followup($data)
    {
        $table = db_prefix() . 'contactcenter_auto_followup';

        if (isset($data['tags']) && is_array($data['tags'])) {
            $data['tags'] = implode(',', $data['tags']);
        }
        if (isset($data['lead_statuses']) && is_array($data['lead_statuses'])) {
            $data['lead_statuses'] = implode(',', $data['lead_statuses']);
        }

        $data['hours_equivalent'] = $this->_compute_hours_equivalent(
            isset($data['time_amount']) ? (int)$data['time_amount'] : 24,
            isset($data['time_unit']) ? $data['time_unit'] : 'hours'
        );

        $data['created_at'] = date('Y-m-d H:i:s');

        $this->db->insert($table, $data);
        return $this->db->insert_id();
    }

    public function update_auto_followup($id, $data)
    {
        $table = db_prefix() . 'contactcenter_auto_followup';

        if (isset($data['tags']) && is_array($data['tags'])) {
            $data['tags'] = implode(',', $data['tags']);
        }
        if (isset($data['lead_statuses']) && is_array($data['lead_statuses'])) {
            $data['lead_statuses'] = implode(',', $data['lead_statuses']);
        }

        if (isset($data['time_amount']) || isset($data['time_unit'])) {
            $existing = $this->get_auto_followup($id);
            $amount = isset($data['time_amount']) ? (int)$data['time_amount'] : (int)$existing->time_amount;
            $unit   = isset($data['time_unit']) ? $data['time_unit'] : $existing->time_unit;
            $data['hours_equivalent'] = $this->_compute_hours_equivalent($amount, $unit);
        }

        $data['updated_at'] = date('Y-m-d H:i:s');
        $this->db->where('id', $id);
        $this->db->update($table, $data);
        return $this->db->affected_rows() >= 0;
    }

    public function delete_auto_followup($id)
    {
        $queue_table = db_prefix() . 'contactcenter_auto_followup_queue';
        if ($this->db->table_exists($queue_table)) {
            $this->db->where('followup_id', $id);
            $this->db->where('status', 'pending');
            $this->db->update($queue_table, ['status' => 'cancelled']);
        }

        $this->db->where('id', $id);
        $this->db->delete(db_prefix() . 'contactcenter_auto_followup');
        return $this->db->affected_rows() > 0;
    }

    private function _compute_hours_equivalent($amount, $unit)
    {
        $multipliers = [
            'minutes' => 1 / 60,
            'hours'   => 1,
            'days'    => 24,
            'weeks'   => 168,
            'months'  => 720,
            'years'   => 8760,
        ];
        $m = isset($multipliers[$unit]) ? $multipliers[$unit] : 1;
        return round($amount * $m, 2);
    }

    // -- Queue CRUD --

    public function get_followup_queue($filters = [])
    {
        $table = db_prefix() . 'contactcenter_auto_followup_queue';
        if (!$this->db->table_exists($table)) {
            return [];
        }

        $this->db->select('q.*, f.title as followup_title, f.objective');
        $this->db->from($table . ' q');
        $this->db->join(db_prefix() . 'contactcenter_auto_followup f', 'f.id = q.followup_id', 'left');

        if (!empty($filters['followup_id'])) {
            $this->db->where('q.followup_id', $filters['followup_id']);
        }
        if (!empty($filters['status'])) {
            $this->db->where('q.status', $filters['status']);
        }
        if (!empty($filters['date_from'])) {
            $this->db->where('q.scheduled_at >=', $filters['date_from']);
        }
        if (!empty($filters['date_to'])) {
            $this->db->where('q.scheduled_at <=', $filters['date_to'] . ' 23:59:59');
        }

        $this->db->order_by('q.scheduled_at', 'ASC');

        $limit = isset($filters['limit']) ? (int)$filters['limit'] : 200;
        $this->db->limit($limit);

        return $this->db->get()->result();
    }

