    public function get_queue_stats($followup_id = null)
    {
        $table = db_prefix() . 'contactcenter_auto_followup_queue';
        if (!$this->db->table_exists($table)) {
            return ['pending' => 0, 'sent_today' => 0, 'failed_today' => 0];
        }

        $where_followup = $followup_id ? " AND followup_id = " . (int)$followup_id : '';
        $today = date('Y-m-d');

        $pending = $this->db->query("SELECT COUNT(*) as c FROM {$table} WHERE status='pending'" . $where_followup)->row()->c;
        $sent_today = $this->db->query("SELECT COUNT(*) as c FROM {$table} WHERE status='sent' AND DATE(sent_at) = '{$today}'" . $where_followup)->row()->c;
        $failed_today = $this->db->query("SELECT COUNT(*) as c FROM {$table} WHERE status='failed' AND DATE(updated_at) = '{$today}'" . $where_followup)->row()->c;

        return [
            'pending'      => (int)$pending,
            'sent_today'   => (int)$sent_today,
            'failed_today' => (int)$failed_today,
        ];
    }

