        )->row()->c;
    }

    /**
     * Sync lastcontact for a batch of leads from Contact Center messages.
     * Uses PHP-side matching for performance.
     * Returns ['updated' => N, 'scanned' => N, 'offset' => N, 'total_leads' => N].
     */
    public function sync_leads_lastcontact_batch($offset = 0, $batch_size = 200, $max_leads = 0)
    {
        $msg_table  = db_prefix() . 'contactcenter_message';
        $lead_table = db_prefix() . 'leads';

        if ($max_leads > 0 && ($offset + $batch_size) > $max_leads) {
            $batch_size = max($max_leads - $offset, 0);
        }
        if ($batch_size <= 0) {
            return ['updated' => 0, 'scanned' => 0, 'offset' => $offset, 'done' => true];
        }

        $leads = $this->db->query(
            "SELECT id, phonenumber, lastcontact FROM {$lead_table}
             WHERE phonenumber IS NOT NULL AND phonenumber != ''
             ORDER BY COALESCE(lastcontact, dateadded) DESC
             LIMIT {$batch_size} OFFSET {$offset}"
        )->result();

        if (empty($leads)) {
            return ['updated' => 0, 'scanned' => 0, 'offset' => $offset, 'done' => true];
        }

        $phone_map = [];
        foreach ($leads as $lead) {
            $clean = preg_replace('/\D/', '', $lead->phonenumber);
            if (!empty($clean)) {
                $phone_map[$clean] = $lead;
            }
        }

        if (empty($phone_map)) {
            return ['updated' => 0, 'scanned' => count($leads), 'offset' => $offset + count($leads), 'done' => false];
        }

        $phone_list = implode(',', array_map(function($p) { return $this->db->escape($p); }, array_keys($phone_map)));

        $results = $this->db->query(
            "SELECT msg_conversation_number, MAX(msg_date) as last_msg_date
             FROM {$msg_table}
             WHERE msg_conversation_number IN ({$phone_list})
             GROUP BY msg_conversation_number"
        )->result();

        $updated = 0;
        foreach ($results as $row) {
            $phone_clean = preg_replace('/\D/', '', $row->msg_conversation_number);
            if (isset($phone_map[$phone_clean])) {
                $lead = $phone_map[$phone_clean];
                $current = $lead->lastcontact ?: '1970-01-01 00:00:00';
                if ($row->last_msg_date > $current) {
                    $this->db->where('id', $lead->id);
                    $this->db->update($lead_table, ['lastcontact' => $row->last_msg_date]);
                    $updated++;
                }
            }
        }

        return [
            'updated' => $updated,
            'scanned' => count($leads),
            'offset'  => $offset + count($leads),
            'done'    => count($leads) < $batch_size,
        ];
    }

    public function get_lead_recent_messages($lead_id, $limit = 10)
    {
        $this->db->select('phonenumber, name');
        $this->db->where('id', $lead_id);
        $lead = $this->db->get(db_prefix() . 'leads')->row();
        if (!$lead || empty($lead->phonenumber)) {
            return [];
        }

        $phone = preg_replace('/\D/', '', $lead->phonenumber);

        $msg_table = db_prefix() . 'contactcenter_message';
        $raw  = $this->db->escape($lead->phonenumber);
        $clean = $this->db->escape($phone);
        $jid   = $this->db->escape($phone . '@s.whatsapp.net');

        $sql = "SELECT msg_content, msg_fromMe, msg_date
                FROM {$msg_table}
                WHERE (
                    msg_conversation_number = {$raw}
                    OR msg_conversation_number = {$clean}
                    OR msg_conversation_number LIKE CONCAT('%', {$clean})
                    OR remoteJid = {$jid}
                )
                AND msg_content IS NOT NULL
                AND msg_content != ''
                ORDER BY msg_date DESC
                LIMIT {$limit}";

        $messages = $this->db->query($sql)->result_array();

        return array_reverse($messages);
    }

    // -- Cron: Generator --

    public function cron_auto_followup_generate()
    {
        $config_table = db_prefix() . 'contactcenter_auto_followup';
        $queue_table  = db_prefix() . 'contactcenter_auto_followup_queue';

        if (!$this->db->table_exists($config_table) || !$this->db->table_exists($queue_table)) {
            return;
        }

        $gemini_key = get_option('contactcenter_gemini_api_key');
        if (empty($gemini_key)) {
            log_activity('auto_followup_generate: No Gemini API key configured', 0);
            return;
        }

        $followups = $this->get_auto_followups(['status' => 1]);
        if (empty($followups)) {
            return;
        }

        $objective_labels = [
            'lead_warmer'  => 'Lead Warmer - Re-engage the lead with a warm, friendly message',
            'appointment'  => 'Appointment Booking - Encourage the lead to schedule a meeting',
            'reactivation' => 'Reactivation - Bring back an inactive lead',
            'feedback'     => 'Feedback/Survey - Ask for feedback or satisfaction',
            'upsell'       => 'Upsell/Cross-sell - Present additional products or services',
            'custom'       => '',
        ];

        foreach ($followups as $fu) {
            $hours_eq    = (float)$fu->hours_equivalent;
            $window_h    = (int)$fu->generation_window_hours ?: 2;
            $daily_limit = (int)$fu->daily_limit ?: 50;

            $sent_today = $this->db->query(
                "SELECT COUNT(*) as c FROM {$queue_table}
                 WHERE followup_id = " . (int)$fu->id . "
                 AND status IN ('pending','sending','sent','skipped')
                 AND DATE(created_at) = '" . date('Y-m-d') . "'"
            )->row()->c;

            if ($sent_today >= $daily_limit) {
                continue;
            }

            $remaining = $daily_limit - (int)$sent_today;

            $tag_join = '';
            if (!empty($fu->tags)) {
                $tag_ids = array_map('intval', explode(',', $fu->tags));
                $tag_ids_str = implode(',', $tag_ids);
                $tag_join = " INNER JOIN " . db_prefix() . "taggables tg ON tg.rel_id = l.id AND tg.rel_type = 'lead' AND tg.tag_id IN ({$tag_ids_str})";
            }

            $status_where = '';
            if (!empty($fu->lead_statuses)) {
                $status_ids = array_map('intval', explode(',', $fu->lead_statuses));
                $status_ids_str = implode(',', $status_ids);
                $status_where = " AND l.status IN ({$status_ids_str})";
            }

            $now_ts = time();
            $window_seconds = $window_h * 3600;

            $msg_table = db_prefix() . 'contactcenter_message';

            $sql = "SELECT l.id, l.name, l.phonenumber, l.lastcontact,
                           TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) as scheduled_at
                    FROM " . db_prefix() . "leads l
                    {$tag_join}
                    WHERE l.phonenumber IS NOT NULL
                      AND l.phonenumber != ''
                      {$status_where}
                      AND l.lastcontact IS NOT NULL
                      AND TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) <= DATE_ADD(NOW(), INTERVAL {$window_h} HOUR)
                      AND TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) >= DATE_SUB(NOW(), INTERVAL 1 HOUR)
                      AND EXISTS (
                          SELECT 1 FROM {$msg_table} m
                          WHERE m.msg_conversation_number = l.phonenumber
                          AND m.msg_content IS NOT NULL AND m.msg_content != ''
                          LIMIT 1
                      )
                      AND l.id NOT IN (
                          SELECT lead_id FROM {$queue_table}
                          WHERE followup_id = " . (int)$fu->id . "
                          AND status IN ('pending','sending','sent','skipped')
                      )
                    ORDER BY scheduled_at ASC
                    LIMIT {$remaining}";

            $leads = $this->db->query($sql)->result();

            if (empty($leads)) {
                continue;
            }

            $obj_label = isset($objective_labels[$fu->objective]) ? $objective_labels[$fu->objective] : $fu->objective;
            if ($fu->objective === 'custom' && !empty($fu->custom_objective)) {
                $obj_label = $fu->custom_objective;
            }

            foreach ($leads as $lead) {
                $messages = $this->get_lead_recent_messages($lead->id, 10);

                if (empty($messages)) {
                    $this->add_to_followup_queue([
                        'followup_id' => $fu->id, 'lead_id' => $lead->id,
                        'phone' => $lead->phonenumber, 'lead_name' => $lead->name,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'No conversation history', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $formatted = '';
                foreach ($messages as $msg) {
                    $sender = $msg['msg_fromMe'] ? 'Staff' : 'Customer';
                    $content = trim($msg['msg_content']);
                    if (!empty($content)) {
                        $formatted .= "[{$sender}]: {$content}\n";
                    }
                }

                if (empty(trim($formatted))) {
                    $this->add_to_followup_queue([
                        'followup_id' => $fu->id, 'lead_id' => $lead->id,
                        'phone' => $lead->phonenumber, 'lead_name' => $lead->name,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'No usable content', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $prompt = "You are a sales/customer service assistant. Generate a natural, personalized follow-up WhatsApp message for this contact.\n\n"
                    . "OBJECTIVE: {$obj_label}\n"
                    . "CONTACT NAME: {$lead->name}\n\n"
                    . "RECENT CONVERSATION:\n{$formatted}\n"
                    . "INSTRUCTIONS:\n"
                    . "- Write a single short WhatsApp message (2-4 sentences)\n"
                    . "- Reference specific details from the conversation naturally\n"
                    . "- Match the tone used in previous messages\n"
                    . "- Include a clear call to action aligned with the objective\n"
                    . "- Do NOT use brackets, placeholders, or template variables\n"
                    . "- Write in the same language used in the conversation\n"
                    . "- Be warm but professional\n\n"
                    . "Return ONLY the message text, nothing else.";

                $result = contactcenter_call_gemini_api($gemini_key, $prompt, false);

                if (empty($result) || (is_array($result) && isset($result['error']))) {
                    log_activity("auto_followup_generate: Gemini failed for lead {$lead->id} in followup {$fu->id}", 0);
                    $this->add_to_followup_queue([
                        'followup_id' => $fu->id, 'lead_id' => $lead->id,
                        'phone' => $lead->phonenumber, 'lead_name' => $lead->name,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'AI generation failed', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $message_text = is_string($result) ? trim($result) : '';
                if (empty($message_text)) {
                    $this->add_to_followup_queue([
                        'followup_id' => $fu->id, 'lead_id' => $lead->id,
                        'phone' => $lead->phonenumber, 'lead_name' => $lead->name,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'Empty AI response', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $scheduled_at = $lead->scheduled_at;
                $sched_time = date('H:i:s', strtotime($scheduled_at));
                $start_time = $fu->start_time ?: '08:00:00';
                $end_time   = $fu->end_time ?: '18:00:00';

                if ($sched_time < $start_time) {
                    $scheduled_at = date('Y-m-d', strtotime($scheduled_at)) . ' ' . $start_time;
                } elseif ($sched_time > $end_time) {
                    $scheduled_at = date('Y-m-d', strtotime($scheduled_at . ' +1 day')) . ' ' . $start_time;
                }

                if (strtotime($scheduled_at) < time()) {
                    $scheduled_at = date('Y-m-d H:i:s', time() + 60);
                    $now_time = date('H:i:s');
                    if ($now_time < $start_time || $now_time > $end_time) {
                        $scheduled_at = date('Y-m-d') . ' ' . $start_time;
                        if ($now_time > $end_time) {
                            $scheduled_at = date('Y-m-d', strtotime('+1 day')) . ' ' . $start_time;
                        }
                    }
                }

                $context = mb_substr($formatted, 0, 500);

                $this->add_to_followup_queue([
                    'followup_id'     => $fu->id,
                    'lead_id'         => $lead->id,
                    'phone'           => $lead->phonenumber,
                    'lead_name'       => $lead->name,
                    'scheduled_at'    => $scheduled_at,
                    'message_text'    => $message_text,
                    'context_summary' => $context,
                    'status'          => 'pending',
                ]);
            }
        }
    }

    /**
     * Count eligible leads for a followup rule (not yet queued).
     */
    public function count_followup_eligible_leads($followup_id)
    {
        $fu = $this->get_auto_followup($followup_id);
        if (!$fu) return 0;

        $hours_eq    = (float)$fu->hours_equivalent;
        $queue_table = db_prefix() . 'contactcenter_auto_followup_queue';
        $msg_table   = db_prefix() . 'contactcenter_message';

        $tag_join = '';
        if (!empty($fu->tags)) {
            $tag_ids = array_map('intval', explode(',', $fu->tags));
            $tag_join = " INNER JOIN " . db_prefix() . "taggables tg ON tg.rel_id = l.id AND tg.rel_type = 'lead' AND tg.tag_id IN (" . implode(',', $tag_ids) . ")";
        }

        $status_where = '';
        if (!empty($fu->lead_statuses)) {
            $status_ids = array_map('intval', explode(',', $fu->lead_statuses));
            $status_where = " AND l.status IN (" . implode(',', $status_ids) . ")";
        }

        $sql = "SELECT COUNT(DISTINCT l.id) as total
                FROM " . db_prefix() . "leads l
                {$tag_join}
                WHERE l.phonenumber IS NOT NULL
                  AND l.phonenumber != ''
                  AND l.lastcontact IS NOT NULL
                  {$status_where}
                  AND TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) <= NOW()
                  AND EXISTS (
                      SELECT 1 FROM {$msg_table} m
                      WHERE m.msg_conversation_number = l.phonenumber
                      AND m.msg_content IS NOT NULL AND m.msg_content != ''
                      LIMIT 1
                  )
                  AND l.id NOT IN (
                      SELECT lead_id FROM {$queue_table}
                      WHERE followup_id = " . (int)$fu->id . "
                      AND status IN ('pending','sending','sent','skipped')
                  )";

        return (int)$this->db->query($sql)->row()->total;
    }

    public function debug_followup_lead_distribution($followup_id)
    {
        $fu = $this->get_auto_followup($followup_id);
        if (!$fu) return [];

        $hours_eq    = (float)$fu->hours_equivalent;
        $queue_table = db_prefix() . 'contactcenter_auto_followup_queue';
        $lead_table  = db_prefix() . 'leads';

        $tag_join = '';
        if (!empty($fu->tags)) {
            $tag_ids = array_map('intval', explode(',', $fu->tags));
            $tag_join = " INNER JOIN " . db_prefix() . "taggables tg ON tg.rel_id = l.id AND tg.rel_type = 'lead' AND tg.tag_id IN (" . implode(',', $tag_ids) . ")";
        }

        $status_where = '';
        if (!empty($fu->lead_statuses)) {
            $status_ids = array_map('intval', explode(',', $fu->lead_statuses));
            $status_where = " AND l.status IN (" . implode(',', $status_ids) . ")";
        }

        $msg_table   = db_prefix() . 'contactcenter_message';
        $base_where = "l.phonenumber IS NOT NULL AND l.phonenumber != '' {$status_where}";

        $total_with_phone = (int)$this->db->query(
            "SELECT COUNT(DISTINCT l.id) as c FROM {$lead_table} l {$tag_join} WHERE {$base_where}"
        )->row()->c;

        $with_lastcontact = (int)$this->db->query(
            "SELECT COUNT(DISTINCT l.id) as c FROM {$lead_table} l {$tag_join}
             WHERE {$base_where} AND l.lastcontact IS NOT NULL"
        )->row()->c;

        $null_lastcontact = (int)$this->db->query(
            "SELECT COUNT(DISTINCT l.id) as c FROM {$lead_table} l {$tag_join}
             WHERE {$base_where} AND l.lastcontact IS NULL"
        )->row()->c;

        $match_time = (int)$this->db->query(
            "SELECT COUNT(DISTINCT l.id) as c FROM {$lead_table} l {$tag_join}
             WHERE {$base_where}
             AND l.lastcontact IS NOT NULL
             AND TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) <= NOW()"
        )->row()->c;

        $has_cc_messages = (int)$this->db->query(
            "SELECT COUNT(DISTINCT l.id) as c FROM {$lead_table} l {$tag_join}
             WHERE {$base_where}
             AND l.lastcontact IS NOT NULL
             AND TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) <= NOW()
             AND EXISTS (
                 SELECT 1 FROM {$msg_table} m
                 WHERE m.msg_conversation_number = l.phonenumber
                 AND m.msg_content IS NOT NULL AND m.msg_content != ''
                 LIMIT 1
             )"
        )->row()->c;

        $in_queue = (int)$this->db->query(
            "SELECT COUNT(DISTINCT lead_id) as c FROM {$queue_table}
             WHERE followup_id = " . (int)$fu->id . " AND status IN ('pending','sending','sent','skipped')"
        )->row()->c;

        $cutoff = $this->db->query(
            "SELECT DATE_SUB(NOW(), INTERVAL {$hours_eq} HOUR) as cutoff_date"
        )->row()->cutoff_date;

        return [
            'hours_equivalent'          => $hours_eq,
            'cutoff_date'               => $cutoff,
            'total_leads_with_phone'    => $total_with_phone,
            'has_lastcontact'           => $with_lastcontact,
            'no_lastcontact'            => $null_lastcontact,
            'match_time_filter'         => $match_time,
            'has_cc_messages'           => $has_cc_messages,
            'no_cc_messages'            => $match_time - $has_cc_messages,
            'already_in_queue'          => $in_queue,
            'final_eligible'            => max($has_cc_messages - $in_queue, 0),
        ];
    }

    /**
     * Generate messages for a batch of eligible leads and add to queue.
     * Returns array with 'processed', 'queued', 'skipped', 'remaining'.
     */
    public function generate_followup_batch($followup_id, $batch_size = 20)
    {
        $fu = $this->get_auto_followup($followup_id);
        if (!$fu) return ['error' => 'Rule not found'];

        $queue_table = db_prefix() . 'contactcenter_auto_followup_queue';
        $hours_eq = (float)$fu->hours_equivalent;

        $gemini_key = get_option('contactcenter_gemini_api_key');
        if (empty($gemini_key)) return ['error' => 'No Gemini API key configured'];

        $tag_join = '';
        if (!empty($fu->tags)) {
            $tag_ids = array_map('intval', explode(',', $fu->tags));
            $tag_join = " INNER JOIN " . db_prefix() . "taggables tg ON tg.rel_id = l.id AND tg.rel_type = 'lead' AND tg.tag_id IN (" . implode(',', $tag_ids) . ")";
        }

        $status_where = '';
        if (!empty($fu->lead_statuses)) {
            $status_ids = array_map('intval', explode(',', $fu->lead_statuses));
            $status_where = " AND l.status IN (" . implode(',', $status_ids) . ")";
        }

        $msg_table = db_prefix() . 'contactcenter_message';

        $sql = "SELECT l.id, l.name, l.phonenumber, l.lastcontact,
                       TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) as scheduled_at
                FROM " . db_prefix() . "leads l
                {$tag_join}
                WHERE l.phonenumber IS NOT NULL
                  AND l.phonenumber != ''
                  AND l.lastcontact IS NOT NULL
                  {$status_where}
                  AND TIMESTAMPADD(HOUR, {$hours_eq}, l.lastcontact) <= NOW()
                  AND EXISTS (
                      SELECT 1 FROM {$msg_table} m
                      WHERE m.msg_conversation_number = l.phonenumber
                      AND m.msg_content IS NOT NULL AND m.msg_content != ''
                      LIMIT 1
                  )
                  AND l.id NOT IN (
                      SELECT lead_id FROM {$queue_table}
                      WHERE followup_id = " . (int)$fu->id . "
                      AND status IN ('pending','sending','sent','skipped')
                  )
                ORDER BY l.lastcontact DESC
                LIMIT {$batch_size}";

        $leads = $this->db->query($sql)->result();

        if (empty($leads)) {
            return ['processed' => 0, 'queued' => 0, 'skipped' => 0, 'remaining' => 0];
        }

        $objective_labels = [
            'lead_warmer'  => 'Lead Warmer - Re-engage the lead with a warm, friendly message',
            'appointment'  => 'Appointment Booking - Encourage the lead to schedule a meeting',
            'reactivation' => 'Reactivation - Bring back an inactive lead',
            'feedback'     => 'Feedback/Survey - Ask for feedback or satisfaction',
            'upsell'       => 'Upsell/Cross-sell - Present additional products or services',
            'custom'       => '',
        ];

        $obj_label = isset($objective_labels[$fu->objective]) ? $objective_labels[$fu->objective] : $fu->objective;
        if ($fu->objective === 'custom' && !empty($fu->custom_objective)) {
            $obj_label = $fu->custom_objective;
        }

        $start_time = $fu->start_time ?: '08:00:00';
        $end_time   = $fu->end_time ?: '18:00:00';

        $queued = 0;
        $skipped = 0;
        $samples = [];

        foreach ($leads as $lead) {
            $messages = $this->get_lead_recent_messages($lead->id, 10);
            if (empty($messages)) {
                $this->add_to_followup_queue([
                    'followup_id'     => $fu->id,
                    'lead_id'         => $lead->id,
                    'phone'           => $lead->phonenumber,
                    'lead_name'       => $lead->name,
                    'scheduled_at'    => date('Y-m-d H:i:s'),
                    'message_text'    => '',
                    'context_summary' => 'No conversation history found',
                    'status'          => 'skipped',
                ]);
                $skipped++;
                continue;
            }

            $formatted = '';
            foreach ($messages as $msg) {
                $sender = $msg['msg_fromMe'] ? 'Staff' : 'Customer';
                $content = trim($msg['msg_content']);
                if (!empty($content)) {
                    $formatted .= "[{$sender}]: {$content}\n";
                }
            }

            if (empty(trim($formatted))) {
                $this->add_to_followup_queue([
                    'followup_id'     => $fu->id,
                    'lead_id'         => $lead->id,
                    'phone'           => $lead->phonenumber,
                    'lead_name'       => $lead->name,
                    'scheduled_at'    => date('Y-m-d H:i:s'),
                    'message_text'    => '',
                    'context_summary' => 'No usable message content',
                    'status'          => 'skipped',
                ]);
                $skipped++;
                continue;
            }

            $prompt = "You are a sales/customer service assistant. Generate a natural, personalized follow-up WhatsApp message for this contact.\n\n"
                . "OBJECTIVE: {$obj_label}\n"
                . "CONTACT NAME: {$lead->name}\n\n"
                . "RECENT CONVERSATION:\n{$formatted}\n"
                . "INSTRUCTIONS:\n"
                . "- Write a single short WhatsApp message (2-4 sentences)\n"
                . "- Reference specific details from the conversation naturally\n"
                . "- Match the tone used in previous messages\n"
                . "- Include a clear call to action aligned with the objective\n"
                . "- Do NOT use brackets, placeholders, or template variables\n"
                . "- Write in the same language used in the conversation\n"
                . "- Be warm but professional\n\n"
                . "Return ONLY the message text, nothing else.";

            $result = contactcenter_call_gemini_api($gemini_key, $prompt, false);
            $message_text = is_string($result) ? trim($result) : '';

            if (empty($message_text)) {
                $this->add_to_followup_queue([
                    'followup_id'     => $fu->id,
                    'lead_id'         => $lead->id,
                    'phone'           => $lead->phonenumber,
                    'lead_name'       => $lead->name,
                    'scheduled_at'    => date('Y-m-d H:i:s'),
                    'message_text'    => '',
                    'context_summary' => 'AI generation failed',
                    'status'          => 'skipped',
                ]);
                $skipped++;
                continue;
            }

            $scheduled_at = $lead->scheduled_at;
            $sched_time = date('H:i:s', strtotime($scheduled_at));

            if ($sched_time < $start_time) {
                $scheduled_at = date('Y-m-d', strtotime($scheduled_at)) . ' ' . $start_time;
            } elseif ($sched_time > $end_time) {
                $scheduled_at = date('Y-m-d', strtotime($scheduled_at . ' +1 day')) . ' ' . $start_time;
            }

            if (strtotime($scheduled_at) < time()) {
                $scheduled_at = date('Y-m-d H:i:s', time() + 60);
                $now_time = date('H:i:s');
                if ($now_time < $start_time || $now_time > $end_time) {
                    $scheduled_at = date('Y-m-d') . ' ' . $start_time;
                    if ($now_time > $end_time) {
                        $scheduled_at = date('Y-m-d', strtotime('+1 day')) . ' ' . $start_time;
                    }
                }
            }

            $context = mb_substr($formatted, 0, 500);

            $this->add_to_followup_queue([
                'followup_id'     => $fu->id,
                'lead_id'         => $lead->id,
                'phone'           => $lead->phonenumber,
                'lead_name'       => $lead->name,
                'scheduled_at'    => $scheduled_at,
                'message_text'    => $message_text,
                'context_summary' => $context,
                'status'          => 'pending',
            ]);
            $queued++;

            if (count($samples) < 3) {
                $samples[] = [
                    'lead_name' => $lead->name,
                    'phone'     => $lead->phonenumber,
                    'message'   => mb_substr($message_text, 0, 150),
                    'scheduled' => $scheduled_at,
                ];
            }
        }

        $remaining = $this->count_followup_eligible_leads($followup_id);

        return [
            'processed' => count($leads),
            'queued'    => $queued,
            'skipped'   => $skipped,
            'remaining' => $remaining,
            'samples'   => $samples,
        ];
    }

    // -- Cron: Sender --

    public function cron_auto_followup_send()
    {
        $queue_table  = db_prefix() . 'contactcenter_auto_followup_queue';
        $config_table = db_prefix() . 'contactcenter_auto_followup';

        if (!$this->db->table_exists($queue_table) || !$this->db->table_exists($config_table)) {
            return;
        }

        $this->db->select('q.*, f.device_id, f.staffid, f.daily_limit, f.start_time, f.end_time, f.status as fu_status');
        $this->db->from($queue_table . ' q');
        $this->db->join($config_table . ' f', 'f.id = q.followup_id', 'inner');
        $this->db->where('q.status', 'pending');
        $this->db->where('q.scheduled_at <=', date('Y-m-d H:i:s'));
        $this->db->where('f.status', 1);
        $this->db->order_by('q.scheduled_at', 'ASC');
        $this->db->limit(20);
        $items = $this->db->get()->result();

        if (empty($items)) {
            return;
        }

        $daily_counts = [];
        foreach ($items as $item) {
            $fu_id = $item->followup_id;

            $now_time = date('H:i:s');
            $start = $item->start_time ?: '08:00:00';
            $end   = $item->end_time ?: '18:00:00';
            if ($now_time < $start || $now_time > $end) {
                continue;
            }

            if (!isset($daily_counts[$fu_id])) {
                $daily_counts[$fu_id] = (int)$this->db->query(
                    "SELECT COUNT(*) as c FROM {$queue_table}
                     WHERE followup_id = {$fu_id} AND status = 'sent'
                     AND DATE(sent_at) = '" . date('Y-m-d') . "'"
                )->row()->c;
            }

            $limit = (int)$item->daily_limit ?: 50;
            if ($daily_counts[$fu_id] >= $limit) {
                continue;
            }

            $this->update_queue_item($item->id, ['status' => 'sending']);

            $staffid = $item->staffid ?: null;
            $send_result = $this->send_text($item->phone, $item->message_text, $staffid, null, null, true, 'crm');

            $success = false;
            if ($send_result) {
                if (isset($send_result['key']) || isset($send_result['id']) || isset($send_result['message'])) {
                    $success = true;
                }
            }

            if ($success) {
                $this->update_queue_item($item->id, [
                    'status'  => 'sent',
                    'sent_at' => date('Y-m-d H:i:s'),
                ]);
                $daily_counts[$fu_id]++;
            } else {
                $err = $send_result ? json_encode($send_result) : 'send_text returned false';
                $this->update_queue_item($item->id, [
                    'status'        => 'failed',
                    'error_message' => mb_substr($err, 0, 500),
                ]);
            }
        }
    }

    // =========================================================================
    // INVOICE FOLLOW-UP
    // =========================================================================

    public function get_invoice_followups($where = [])
    {
        $table = db_prefix() . 'contactcenter_invoice_followup';
        if (!$this->db->table_exists($table)) return [];
        if (!empty($where)) $this->db->where($where);
        $this->db->order_by('id', 'DESC');
        return $this->db->get($table)->result();
    }

    public function get_invoice_followup($id)
    {
        $table = db_prefix() . 'contactcenter_invoice_followup';
        if (!$this->db->table_exists($table)) return null;
        $this->db->where('id', $id);
        return $this->db->get($table)->row();
    }

    public function add_invoice_followup($data)
    {
        $table = db_prefix() . 'contactcenter_invoice_followup';

        if (isset($data['invoice_statuses']) && is_array($data['invoice_statuses'])) {
            $data['invoice_statuses'] = implode(',', $data['invoice_statuses']);
        }

        $data['hours_equivalent'] = $this->_compute_hours_equivalent(
            isset($data['time_amount']) ? (int)$data['time_amount'] : 3,
            isset($data['time_unit']) ? $data['time_unit'] : 'days'
        );

        $data['created_at'] = date('Y-m-d H:i:s');
        $this->db->insert($table, $data);
        return $this->db->insert_id();
    }

    public function update_invoice_followup($id, $data)
    {
        $table = db_prefix() . 'contactcenter_invoice_followup';

        if (isset($data['invoice_statuses']) && is_array($data['invoice_statuses'])) {
            $data['invoice_statuses'] = implode(',', $data['invoice_statuses']);
        }

        $existing = $this->get_invoice_followup($id);
        if ($existing) {
            $amount = isset($data['time_amount']) ? (int)$data['time_amount'] : (int)$existing->time_amount;
            $unit   = isset($data['time_unit']) ? $data['time_unit'] : $existing->time_unit;
            $data['hours_equivalent'] = $this->_compute_hours_equivalent($amount, $unit);
        }

        $data['updated_at'] = date('Y-m-d H:i:s');
        $this->db->where('id', $id);
        $this->db->update($table, $data);
        return $this->db->affected_rows() >= 0;
    }

    public function delete_invoice_followup($id)
    {
        $table = db_prefix() . 'contactcenter_invoice_followup';
        $queue = db_prefix() . 'contactcenter_invoice_followup_queue';
        if ($this->db->table_exists($queue)) {
            $this->db->where('followup_id', $id);
            $this->db->where('status', 'pending');
            $this->db->update($queue, ['status' => 'cancelled', 'updated_at' => date('Y-m-d H:i:s')]);
        }
        $this->db->where('id', $id);
        $this->db->delete($table);
        return $this->db->affected_rows() > 0;
    }

    public function add_to_invoice_followup_queue($data)
    {
        $table = db_prefix() . 'contactcenter_invoice_followup_queue';
        $data['created_at'] = date('Y-m-d H:i:s');
        $this->db->insert($table, $data);
        return $this->db->insert_id();
    }

    public function update_invoice_queue_item($id, $data)
    {
        $table = db_prefix() . 'contactcenter_invoice_followup_queue';
        $data['updated_at'] = date('Y-m-d H:i:s');
        $this->db->where('id', $id);
        $this->db->update($table, $data);
        return $this->db->affected_rows() >= 0;
    }

    public function get_invoice_followup_queue_items($followup_id = null, $filters = [])
    {
        $queue  = db_prefix() . 'contactcenter_invoice_followup_queue';
        $config = db_prefix() . 'contactcenter_invoice_followup';
        if (!$this->db->table_exists($queue)) return [];

        $this->db->select('q.*, f.title as rule_title');
        $this->db->from($queue . ' q');
        $this->db->join($config . ' f', 'f.id = q.followup_id', 'left');

        if ($followup_id) {
            $this->db->where('q.followup_id', $followup_id);
        }
        if (!empty($filters['status'])) {
            $this->db->where('q.status', $filters['status']);
        }
        $this->db->order_by('q.scheduled_at', 'DESC');
        $this->db->limit(200);
        return $this->db->get()->result();
    }

    public function get_invoice_followup_queue_stats($followup_id = null)
    {
        $queue = db_prefix() . 'contactcenter_invoice_followup_queue';
        if (!$this->db->table_exists($queue)) {
            return ['pending' => 0, 'sent_today' => 0, 'failed_today' => 0, 'total' => 0];
        }

        $where_fu = $followup_id ? " AND followup_id = " . (int)$followup_id : '';
        $today = date('Y-m-d');

        $pending = (int)$this->db->query("SELECT COUNT(*) as c FROM {$queue} WHERE status = 'pending' {$where_fu}")->row()->c;
        $sent    = (int)$this->db->query("SELECT COUNT(*) as c FROM {$queue} WHERE status = 'sent' AND DATE(sent_at) = '{$today}' {$where_fu}")->row()->c;
        $failed  = (int)$this->db->query("SELECT COUNT(*) as c FROM {$queue} WHERE status = 'failed' AND DATE(updated_at) = '{$today}' {$where_fu}")->row()->c;
        $total   = (int)$this->db->query("SELECT COUNT(*) as c FROM {$queue} WHERE 1=1 {$where_fu}")->row()->c;

        return ['pending' => $pending, 'sent_today' => $sent, 'failed_today' => $failed, 'total' => $total];
    }

    public function get_client_recent_messages($client_id, $limit = 10)
    {
        $this->db->select('phonenumber, company');
        $this->db->where('userid', $client_id);
        $client = $this->db->get(db_prefix() . 'clients')->row();
        if (!$client || empty($client->phonenumber)) return [];

        $phone = preg_replace('/\D/', '', $client->phonenumber);
        $msg_table = db_prefix() . 'contactcenter_message';
        $raw   = $this->db->escape($client->phonenumber);
        $clean = $this->db->escape($phone);
        $jid   = $this->db->escape($phone . '@s.whatsapp.net');

        $sql = "SELECT msg_content, msg_fromMe, msg_date
                FROM {$msg_table}
                WHERE (
                    msg_conversation_number = {$raw}
                    OR msg_conversation_number = {$clean}
                    OR msg_conversation_number LIKE CONCAT('%', {$clean})
                    OR remoteJid = {$jid}
                )
                AND msg_content IS NOT NULL AND msg_content != ''
                ORDER BY msg_date DESC LIMIT {$limit}";

        $messages = $this->db->query($sql)->result_array();
        return array_reverse($messages);
    }

    public function _build_invoice_followup_where($fu)
    {
        $hours_eq    = (float)$fu->hours_equivalent;
        $queue_table = db_prefix() . 'contactcenter_invoice_followup_queue';
        $inv_table   = db_prefix() . 'invoices';
        $cli_table   = db_prefix() . 'clients';
        $msg_table   = db_prefix() . 'contactcenter_message';

        $inv_status_where = '';
        if (!empty($fu->invoice_statuses)) {
            $ids = array_map('intval', explode(',', $fu->invoice_statuses));
            $inv_status_where = " AND i.status IN (" . implode(',', $ids) . ")";
        }

        return [
            'hours_eq'         => $hours_eq,
            'queue_table'      => $queue_table,
            'inv_table'        => $inv_table,
            'cli_table'        => $cli_table,
            'msg_table'        => $msg_table,
            'inv_status_where' => $inv_status_where,
        ];
    }

    public function count_invoice_followup_eligible($followup_id)
    {
        $fu = $this->get_invoice_followup($followup_id);
        if (!$fu) return 0;

        $w = $this->_build_invoice_followup_where($fu);

        $sql = "SELECT COUNT(DISTINCT i.id) as total
                FROM {$w['inv_table']} i
                INNER JOIN {$w['cli_table']} c ON c.userid = i.clientid
                WHERE c.phonenumber IS NOT NULL AND c.phonenumber != ''
                  {$w['inv_status_where']}
                  AND TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) <= NOW()
                  AND EXISTS (
                      SELECT 1 FROM {$w['msg_table']} m
                      WHERE m.msg_conversation_number = c.phonenumber
                      AND m.msg_content IS NOT NULL AND m.msg_content != ''
                      LIMIT 1
                  )
                  AND i.id NOT IN (
                      SELECT invoice_id FROM {$w['queue_table']}
                      WHERE followup_id = " . (int)$fu->id . "
                      AND status IN ('pending','sending','sent','skipped')
                  )";

        return (int)$this->db->query($sql)->row()->total;
    }

    public function debug_invoice_followup_distribution($followup_id)
    {
        $fu = $this->get_invoice_followup($followup_id);
        if (!$fu) return [];

        $w = $this->_build_invoice_followup_where($fu);

        $base = "c.phonenumber IS NOT NULL AND c.phonenumber != '' {$w['inv_status_where']}";

        $total_invoices = (int)$this->db->query(
            "SELECT COUNT(DISTINCT i.id) as c FROM {$w['inv_table']} i
             INNER JOIN {$w['cli_table']} c ON c.userid = i.clientid
             WHERE {$base}"
        )->row()->c;

        $match_time = (int)$this->db->query(
            "SELECT COUNT(DISTINCT i.id) as c FROM {$w['inv_table']} i
             INNER JOIN {$w['cli_table']} c ON c.userid = i.clientid
             WHERE {$base} AND TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) <= NOW()"
        )->row()->c;

        $has_cc = (int)$this->db->query(
            "SELECT COUNT(DISTINCT i.id) as c FROM {$w['inv_table']} i
             INNER JOIN {$w['cli_table']} c ON c.userid = i.clientid
             WHERE {$base} AND TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) <= NOW()
             AND EXISTS (SELECT 1 FROM {$w['msg_table']} m WHERE m.msg_conversation_number = c.phonenumber AND m.msg_content IS NOT NULL AND m.msg_content != '' LIMIT 1)"
        )->row()->c;

        $in_queue = (int)$this->db->query(
            "SELECT COUNT(DISTINCT invoice_id) as c FROM {$w['queue_table']}
             WHERE followup_id = " . (int)$fu->id . " AND status IN ('pending','sending','sent','skipped')"
        )->row()->c;

        $cutoff = $this->db->query("SELECT DATE_SUB(NOW(), INTERVAL {$w['hours_eq']} HOUR) as d")->row()->d;

        return [
            'hours_equivalent'     => $w['hours_eq'],
            'cutoff_date'          => $cutoff,
            'total_invoices'       => $total_invoices,
            'match_time_filter'    => $match_time,
            'has_cc_messages'      => $has_cc,
            'no_cc_messages'       => $match_time - $has_cc,
            'already_in_queue'     => $in_queue,
            'final_eligible'       => max($has_cc - $in_queue, 0),
        ];
    }

    public function generate_invoice_followup_batch($followup_id, $batch_size = 20)
    {
        $fu = $this->get_invoice_followup($followup_id);
        if (!$fu) return ['error' => 'Rule not found'];

        $gemini_key = get_option('contactcenter_gemini_api_key');
        if (empty($gemini_key)) return ['error' => 'No Gemini API key configured'];

        $w = $this->_build_invoice_followup_where($fu);

        $sql = "SELECT i.id as invoice_id, i.number as invoice_number, i.total as invoice_total,
                       i.duedate, i.status as inv_status, i.clientid,
                       c.company as client_name, c.phonenumber,
                       TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) as scheduled_at
                FROM {$w['inv_table']} i
                INNER JOIN {$w['cli_table']} c ON c.userid = i.clientid
                WHERE c.phonenumber IS NOT NULL AND c.phonenumber != ''
                  {$w['inv_status_where']}
                  AND TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) <= NOW()
                  AND EXISTS (
                      SELECT 1 FROM {$w['msg_table']} m
                      WHERE m.msg_conversation_number = c.phonenumber
                      AND m.msg_content IS NOT NULL AND m.msg_content != ''
                      LIMIT 1
                  )
                  AND i.id NOT IN (
                      SELECT invoice_id FROM {$w['queue_table']}
                      WHERE followup_id = " . (int)$fu->id . "
                      AND status IN ('pending','sending','sent','skipped')
                  )
                ORDER BY i.duedate ASC
                LIMIT {$batch_size}";

        $invoices = $this->db->query($sql)->result();
        if (empty($invoices)) {
            return ['processed' => 0, 'queued' => 0, 'skipped' => 0, 'remaining' => 0];
        }

        $objective_labels = [
            'payment_reminder'  => 'Payment Reminder - Friendly reminder that payment is due or overdue',
            'overdue_collection'=> 'Overdue Collection - Firm but professional message about overdue payment',
            'partial_payment'   => 'Partial Payment - Acknowledge partial payment, request the remaining balance',
            'friendly_reminder' => 'Friendly Reminder - Soft, gentle reminder about upcoming/recent payment',
            'final_notice'      => 'Final Notice - Last professional attempt before escalation',
            'custom'            => '',
        ];

        $obj_label = isset($objective_labels[$fu->objective]) ? $objective_labels[$fu->objective] : $fu->objective;
        if ($fu->objective === 'custom' && !empty($fu->custom_objective)) {
            $obj_label = $fu->custom_objective;
        }

        $start_time = $fu->start_time ?: '08:00:00';
        $end_time   = $fu->end_time ?: '18:00:00';
        $queued = 0; $skipped = 0; $samples = [];

        foreach ($invoices as $inv) {
            $messages = $this->get_client_recent_messages($inv->clientid, 10);
            if (empty($messages)) {
                $this->add_to_invoice_followup_queue([
                    'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                    'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                    'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                    'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                    'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                    'context_summary' => 'No conversation history', 'status' => 'skipped',
                ]);
                $skipped++; continue;
            }

            $formatted = '';
            foreach ($messages as $msg) {
                $sender = $msg['msg_fromMe'] ? 'Staff' : 'Customer';
                $content = trim($msg['msg_content']);
                if (!empty($content)) $formatted .= "[{$sender}]: {$content}\n";
            }

            if (empty(trim($formatted))) {
                $this->add_to_invoice_followup_queue([
                    'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                    'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                    'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                    'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                    'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                    'context_summary' => 'No usable content', 'status' => 'skipped',
                ]);
                $skipped++; continue;
            }

            $inv_status_label = '';
            switch ((int)$inv->inv_status) {
                case 1: $inv_status_label = 'Unpaid'; break;
                case 3: $inv_status_label = 'Partially Paid'; break;
                case 4: $inv_status_label = 'Overdue'; break;
                default: $inv_status_label = 'Pending'; break;
            }

            $days_overdue = max(0, (int)floor((time() - strtotime($inv->duedate)) / 86400));

            $prompt = "You are a professional accounts receivable assistant. Generate a natural, personalized WhatsApp message to remind/collect payment for an invoice.\n\n"
                . "OBJECTIVE: {$obj_label}\n"
                . "CLIENT NAME: {$inv->client_name}\n"
                . "INVOICE #: {$inv->invoice_number}\n"
                . "AMOUNT: R$ " . number_format((float)$inv->invoice_total, 2, ',', '.') . "\n"
                . "DUE DATE: " . date('d/m/Y', strtotime($inv->duedate)) . "\n"
                . "STATUS: {$inv_status_label}\n"
                . "DAYS OVERDUE: {$days_overdue}\n\n"
                . "RECENT CONVERSATION WITH CLIENT:\n{$formatted}\n"
                . "INSTRUCTIONS:\n"
                . "- Write a single WhatsApp message (2-4 sentences)\n"
                . "- Reference the specific invoice amount and due date\n"
                . "- Match the tone from the conversation history\n"
                . "- Be professional but empathetic\n"
                . "- Include a clear call to action for payment\n"
                . "- Do NOT use brackets, placeholders, or template variables\n"
                . "- Write in the same language used in the conversation\n\n"
                . "Return ONLY the message text, nothing else.";

            $result = contactcenter_call_gemini_api($gemini_key, $prompt, false);
            $message_text = is_string($result) ? trim($result) : '';

            if (empty($message_text)) {
                $this->add_to_invoice_followup_queue([
                    'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                    'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                    'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                    'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                    'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                    'context_summary' => 'AI generation failed', 'status' => 'skipped',
                ]);
                $skipped++; continue;
            }

            $scheduled_at = $inv->scheduled_at;
            $sched_time = date('H:i:s', strtotime($scheduled_at));
            if ($sched_time < $start_time) {
                $scheduled_at = date('Y-m-d', strtotime($scheduled_at)) . ' ' . $start_time;
            } elseif ($sched_time > $end_time) {
                $scheduled_at = date('Y-m-d', strtotime($scheduled_at . ' +1 day')) . ' ' . $start_time;
            }
            if (strtotime($scheduled_at) < time()) {
                $scheduled_at = date('Y-m-d H:i:s', time() + 60);
                $now_time = date('H:i:s');
                if ($now_time < $start_time || $now_time > $end_time) {
                    $scheduled_at = date('Y-m-d') . ' ' . $start_time;
                    if ($now_time > $end_time) {
                        $scheduled_at = date('Y-m-d', strtotime('+1 day')) . ' ' . $start_time;
                    }
                }
            }

            $this->add_to_invoice_followup_queue([
                'followup_id'     => $fu->id,
                'invoice_id'      => $inv->invoice_id,
                'client_id'       => $inv->clientid,
                'phone'           => $inv->phonenumber,
                'client_name'     => $inv->client_name,
                'invoice_number'  => $inv->invoice_number,
                'invoice_total'   => $inv->invoice_total,
                'invoice_duedate' => $inv->duedate,
                'scheduled_at'    => $scheduled_at,
                'message_text'    => $message_text,
                'context_summary' => mb_substr($formatted, 0, 500),
                'status'          => 'pending',
            ]);
            $queued++;

            if (count($samples) < 3) {
                $samples[] = [
                    'client_name'    => $inv->client_name,
                    'phone'          => $inv->phonenumber,
                    'invoice_number' => $inv->invoice_number,
                    'invoice_total'  => $inv->invoice_total,
                    'message'        => mb_substr($message_text, 0, 150),
                    'scheduled'      => $scheduled_at,
                ];
            }
        }

        $remaining = $this->count_invoice_followup_eligible($followup_id);
        return ['processed' => count($invoices), 'queued' => $queued, 'skipped' => $skipped, 'remaining' => $remaining, 'samples' => $samples];
    }

    public function cron_invoice_followup_generate()
    {
        $config_table = db_prefix() . 'contactcenter_invoice_followup';
        $queue_table  = db_prefix() . 'contactcenter_invoice_followup_queue';
        if (!$this->db->table_exists($config_table) || !$this->db->table_exists($queue_table)) return;

        $gemini_key = get_option('contactcenter_gemini_api_key');
        if (empty($gemini_key)) return;

        $followups = $this->get_invoice_followups(['status' => 1]);
        if (empty($followups)) return;

        $objective_labels = [
            'payment_reminder'  => 'Payment Reminder - Friendly reminder that payment is due or overdue',
            'overdue_collection'=> 'Overdue Collection - Firm but professional message about overdue payment',
            'partial_payment'   => 'Partial Payment - Acknowledge partial payment, request the remaining balance',
            'friendly_reminder' => 'Friendly Reminder - Soft, gentle reminder about upcoming/recent payment',
            'final_notice'      => 'Final Notice - Last professional attempt before escalation',
            'custom'            => '',
        ];

        foreach ($followups as $fu) {
            $w = $this->_build_invoice_followup_where($fu);
            $window_h    = (int)$fu->generation_window_hours ?: 2;
            $daily_limit = (int)$fu->daily_limit ?: 50;

            $sent_today = (int)$this->db->query(
                "SELECT COUNT(*) as c FROM {$queue_table}
                 WHERE followup_id = " . (int)$fu->id . "
                 AND status IN ('pending','sending','sent')
                 AND DATE(created_at) = '" . date('Y-m-d') . "'"
            )->row()->c;
            if ($sent_today >= $daily_limit) continue;
            $remaining = $daily_limit - $sent_today;

            $sql = "SELECT i.id as invoice_id, i.number as invoice_number, i.total as invoice_total,
                           i.duedate, i.status as inv_status, i.clientid,
                           c.company as client_name, c.phonenumber,
                           TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) as scheduled_at
                    FROM {$w['inv_table']} i
                    INNER JOIN {$w['cli_table']} c ON c.userid = i.clientid
                    WHERE c.phonenumber IS NOT NULL AND c.phonenumber != ''
                      {$w['inv_status_where']}
                      AND TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) <= DATE_ADD(NOW(), INTERVAL {$window_h} HOUR)
                      AND TIMESTAMPADD(HOUR, {$w['hours_eq']}, i.duedate) >= DATE_SUB(NOW(), INTERVAL 1 HOUR)
                      AND EXISTS (
                          SELECT 1 FROM {$w['msg_table']} m
                          WHERE m.msg_conversation_number = c.phonenumber
                          AND m.msg_content IS NOT NULL AND m.msg_content != '' LIMIT 1
                      )
                      AND i.id NOT IN (
                          SELECT invoice_id FROM {$queue_table}
                          WHERE followup_id = " . (int)$fu->id . "
                          AND status IN ('pending','sending','sent','skipped')
                      )
                    ORDER BY i.duedate ASC
                    LIMIT {$remaining}";

            $invoices = $this->db->query($sql)->result();
            if (empty($invoices)) continue;

            $obj_label = isset($objective_labels[$fu->objective]) ? $objective_labels[$fu->objective] : $fu->objective;
            if ($fu->objective === 'custom' && !empty($fu->custom_objective)) $obj_label = $fu->custom_objective;

            $start_time = $fu->start_time ?: '08:00:00';
            $end_time   = $fu->end_time ?: '18:00:00';

            foreach ($invoices as $inv) {
                $messages = $this->get_client_recent_messages($inv->clientid, 10);
                if (empty($messages)) {
                    $this->add_to_invoice_followup_queue([
                        'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                        'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                        'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                        'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'No conversation history', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $formatted = '';
                foreach ($messages as $msg) {
                    $sender = $msg['msg_fromMe'] ? 'Staff' : 'Customer';
                    $content = trim($msg['msg_content']);
                    if (!empty($content)) $formatted .= "[{$sender}]: {$content}\n";
                }
                if (empty(trim($formatted))) {
                    $this->add_to_invoice_followup_queue([
                        'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                        'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                        'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                        'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'No usable content', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $inv_status_label = '';
                switch ((int)$inv->inv_status) {
                    case 1: $inv_status_label = 'Unpaid'; break;
                    case 3: $inv_status_label = 'Partially Paid'; break;
                    case 4: $inv_status_label = 'Overdue'; break;
                    default: $inv_status_label = 'Pending'; break;
                }
                $days_overdue = max(0, (int)floor((time() - strtotime($inv->duedate)) / 86400));

                $prompt = "You are a professional accounts receivable assistant. Generate a natural, personalized WhatsApp message to remind/collect payment for an invoice.\n\n"
                    . "OBJECTIVE: {$obj_label}\nCLIENT NAME: {$inv->client_name}\n"
                    . "INVOICE #: {$inv->invoice_number}\nAMOUNT: R$ " . number_format((float)$inv->invoice_total, 2, ',', '.') . "\n"
                    . "DUE DATE: " . date('d/m/Y', strtotime($inv->duedate)) . "\nSTATUS: {$inv_status_label}\nDAYS OVERDUE: {$days_overdue}\n\n"
                    . "RECENT CONVERSATION:\n{$formatted}\n"
                    . "INSTRUCTIONS:\n- Write a single WhatsApp message (2-4 sentences)\n- Reference the invoice amount and due date\n"
                    . "- Be professional but empathetic\n- Include a clear call to action for payment\n"
                    . "- Do NOT use brackets or placeholders\n- Write in the same language as the conversation\n\nReturn ONLY the message text.";

                $result = contactcenter_call_gemini_api($gemini_key, $prompt, false);
                $message_text = is_string($result) ? trim($result) : '';
                if (empty($message_text)) {
                    $this->add_to_invoice_followup_queue([
                        'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                        'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                        'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                        'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                        'scheduled_at' => date('Y-m-d H:i:s'), 'message_text' => '',
                        'context_summary' => 'AI failed', 'status' => 'skipped',
                    ]);
                    continue;
                }

                $scheduled_at = $inv->scheduled_at;
                $sched_time = date('H:i:s', strtotime($scheduled_at));
                if ($sched_time < $start_time) $scheduled_at = date('Y-m-d', strtotime($scheduled_at)) . ' ' . $start_time;
                elseif ($sched_time > $end_time) $scheduled_at = date('Y-m-d', strtotime($scheduled_at . ' +1 day')) . ' ' . $start_time;
                if (strtotime($scheduled_at) < time()) {
                    $scheduled_at = date('Y-m-d H:i:s', time() + 60);
                    $now_time = date('H:i:s');
                    if ($now_time < $start_time || $now_time > $end_time) {
                        $scheduled_at = date('Y-m-d') . ' ' . $start_time;
                        if ($now_time > $end_time) $scheduled_at = date('Y-m-d', strtotime('+1 day')) . ' ' . $start_time;
                    }
                }

                $this->add_to_invoice_followup_queue([
                    'followup_id' => $fu->id, 'invoice_id' => $inv->invoice_id,
                    'client_id' => $inv->clientid, 'phone' => $inv->phonenumber,
                    'client_name' => $inv->client_name, 'invoice_number' => $inv->invoice_number,
                    'invoice_total' => $inv->invoice_total, 'invoice_duedate' => $inv->duedate,
                    'scheduled_at' => $scheduled_at, 'message_text' => $message_text,
                    'context_summary' => mb_substr($formatted, 0, 500), 'status' => 'pending',
                ]);
            }
        }
    }

    public function cron_invoice_followup_send()
    {
        $queue_table  = db_prefix() . 'contactcenter_invoice_followup_queue';
        $config_table = db_prefix() . 'contactcenter_invoice_followup';
        if (!$this->db->table_exists($queue_table) || !$this->db->table_exists($config_table)) return;

        $this->db->select('q.*, f.device_id, f.staffid, f.daily_limit, f.start_time, f.end_time, f.status as fu_status');
        $this->db->from($queue_table . ' q');
        $this->db->join($config_table . ' f', 'f.id = q.followup_id', 'inner');
        $this->db->where('q.status', 'pending');
        $this->db->where('q.scheduled_at <=', date('Y-m-d H:i:s'));
        $this->db->where('f.status', 1);
        $this->db->order_by('q.scheduled_at', 'ASC');
        $this->db->limit(20);
        $items = $this->db->get()->result();

        if (empty($items)) return;
        $daily_counts = [];

        foreach ($items as $item) {
            $fu_id = $item->followup_id;
            $now_time = date('H:i:s');
            $start = $item->start_time ?: '08:00:00';
            $end   = $item->end_time ?: '18:00:00';
            if ($now_time < $start || $now_time > $end) continue;

            if (!isset($daily_counts[$fu_id])) {
                $daily_counts[$fu_id] = (int)$this->db->query(
                    "SELECT COUNT(*) as c FROM {$queue_table}
                     WHERE followup_id = {$fu_id} AND status = 'sent'
                     AND DATE(sent_at) = '" . date('Y-m-d') . "'"
                )->row()->c;
            }
            if ($daily_counts[$fu_id] >= ((int)$item->daily_limit ?: 50)) continue;

            $this->update_invoice_queue_item($item->id, ['status' => 'sending']);
            $staffid = $item->staffid ?: null;
            $send_result = $this->send_text($item->phone, $item->message_text, $staffid, null, null, true, 'crm');

            $success = false;
            if ($send_result && (isset($send_result['key']) || isset($send_result['id']) || isset($send_result['message']))) {
                $success = true;
            }

            if ($success) {
                $this->update_invoice_queue_item($item->id, ['status' => 'sent', 'sent_at' => date('Y-m-d H:i:s')]);
                $daily_counts[$fu_id]++;
            } else {
                $err = $send_result ? json_encode($send_result) : 'send_text returned false';
                $this->update_invoice_queue_item($item->id, ['status' => 'failed', 'error_message' => mb_substr($err, 0, 500)]);
            }
        }
    }

}

